/*
 * contextdata.locals.js  (SC.contextDataLocals) – Arbeits-/Alltags-Kontext für die
 * LOCALS-Lernkarten (Track es-en: Spanisch-Sprecher lernen Englisch). REINE DATEN.
 * Pendant zu contextdata.js, nur in der GEDREHTEN Lernrichtung. Wird in context.js
 * (expandLocals) an die loc-* Karten gehängt – nur im Locals-Track (data.locals.js
 * hat die Karten dann in SC.data.CARDS eingehängt). Schlüssel = Karten-id.
 *
 * Kompakte Schreibweise pro Eintrag:
 *   e   = englischer Beispielsatz – echter, sprechbarer Satz aus dem Arbeitsalltag
 *         (Hostelería/Tourismus, Tag-für-Tag, Job). Die zu lernende Sprache.
 *   t   = spanische Übersetzung des Satzes (Verständnishilfe, LatAm-Spanisch)
 *   s   = situación (Spanisch) – konkrete Situation: wann sagt man das?
 *   sEn = situation (Englisch) – gleiche Aussage auf Englisch
 *   n   = consejo (Spanisch) – kurzer Tipp / Besonderheit / höflichere Variante
 *   nEn = tip (Englisch) – gleiche Aussage auf Englisch
 *
 * Generiert aus den Karten in data.locals.js (ein Eintrag pro Karte) und durch ein
 * adversariales Gegenlesen geprüft. Inhaltsregeln: echter, natürlicher Satz aus dem
 * Arbeitsalltag – nicht schulisch; Englisch idiomatisch, Spanisch natürlich (LatAm).
 * {name} wird zur Laufzeit ersetzt.
 */
(function () {
  "use strict";

  var C = {
    // ===================== At the restaurant (meseros) =====================
    "loc-mes01": { e: "Are you ready to order, or do you need a few more minutes?", t: "¿Están listos para ordenar, o necesitan unos minutos más?", s: "Cuando te acercas a una mesa después de dejar el menú.", sEn: "When you approach a table after dropping off the menu.", n: "Agregar \"or do you need a few more minutes?\" suena más amable y sin presión.", nEn: "Adding \"or do you need a few more minutes?\" sounds friendlier and less pushy." },
    "loc-mes02": { e: "Anything to drink while you look at the menu?", t: "¿Algo de tomar mientras ven el menú?", s: "Apenas sientas a los clientes, antes de tomar el pedido de comida.", sEn: "Right after you seat the guests, before taking the food order.", n: "\"Drink\" lleva una 'i' corta, como en 'sit'; no la alargues a 'dreenk'.", nEn: "\"Drink\" has a short 'i' like in 'sit'; don't stretch it into 'dreenk'." },
    "loc-mes03": { e: "For here or to go?", t: "¿Para comer aquí o para llevar?", s: "En un mostrador de comida rápida cuando el cliente pide.", sEn: "At a fast-food counter when the customer orders.", n: "En el Reino Unido suele decirse \"eat in or take away?\" para lo mismo.", nEn: "In the UK people often say \"eat in or take away?\" for the same thing." },
    "loc-mes04": { e: "Here is the menu, and I'll be right back to take your order.", t: "Aquí tiene el menú, y vuelvo enseguida a tomar su pedido.", s: "Al entregar la carta a una mesa recién sentada.", sEn: "When handing the menu to a freshly seated table.", n: "Para varias personas di \"here are the menus\" en plural.", nEn: "For several people say \"here are the menus\" in the plural." },
    "loc-mes05": { e: "How would you like your steak — rare, medium, or well done?", t: "¿Cómo desea su bistec: poco hecho, término medio o bien cocido?", s: "Cuando el cliente pide un corte de carne.", sEn: "When the customer orders a cut of meat.", n: "Ofrecer las opciones (rare/medium/well done) ayuda al cliente a responder rápido.", nEn: "Offering the options (rare/medium/well done) helps the customer answer quickly." },
    "loc-mes06": { e: "Do you have any allergies I should tell the kitchen about?", t: "¿Tiene alguna alergia que deba avisarle a la cocina?", s: "Antes de enviar un pedido a la cocina, por seguridad.", sEn: "Before sending an order to the kitchen, for safety.", n: "\"Allergies\" lleva el acento en la primera sílaba: A-ller-gies.", nEn: "\"Allergies\" is stressed on the first syllable: A-ller-gies." },
    "loc-mes07": { e: "Today's special is fish, and it comes with rice and vegetables.", t: "El plato del día es pescado, y viene con arroz y verduras.", s: "Cuando recomiendas el plato del día a la mesa.", sEn: "When you recommend the daily special to the table.", n: "También puedes decir \"the special of the day\" sin cambiar el sentido.", nEn: "You can also say \"the special of the day\" with the same meaning." },
    "loc-mes08": { e: "Would you like any dessert? We have cheesecake and ice cream.", t: "¿Desea algún postre? Tenemos cheesecake y helado.", s: "Después de retirar los platos principales.", sEn: "After clearing the main dishes.", n: "\"Dessert\" (postre) lleva doble s; \"desert\" (desierto) lleva una sola.", nEn: "\"Dessert\" (the sweet) has a double s; \"desert\" (the dry place) has one." },
    "loc-mes09": { e: "Of course, I'll bring you the bill right away.", t: "Claro, enseguida le traigo la cuenta.", s: "Cuando el cliente pide la cuenta.", sEn: "When the customer asks for the check.", n: "En EE. UU. se dice \"the check\" en vez de \"the bill\".", nEn: "In the US people say \"the check\" instead of \"the bill\"." },
    "loc-mes10": { e: "Sorry for the wait — your table is ready now.", t: "Disculpe la demora; su mesa ya está lista.", s: "Cuando el cliente esperó más de lo normal.", sEn: "When the customer has waited longer than usual.", n: "\"Sorry for the wait\" suena más cálido que el formal \"we apologize for the delay\".", nEn: "\"Sorry for the wait\" sounds warmer than the formal \"we apologize for the delay\"." },
    "loc-mes11": { e: "Good evening! Table for how many?", t: "¡Buenas noches! ¿Mesa para cuántos?", s: "Al recibir a un grupo en la entrada del restaurante.", sEn: "When greeting a group at the restaurant entrance.", n: "Más completo: \"a table for how many people?\" si quieres sonar más claro.", nEn: "Fuller version: \"a table for how many people?\" if you want to be clearer." },
    "loc-mes12": { e: "The restroom is in the back, just past the bar.", t: "El baño está al fondo, justo pasando la barra.", s: "Cuando un cliente pregunta dónde está el baño.", sEn: "When a customer asks where the bathroom is.", n: "En lugares públicos \"restroom\" suena más educado que \"toilet\".", nEn: "In public places \"restroom\" sounds more polite than \"toilet\"." },
    "loc-mes13": { e: "Is everything okay here? Can I get you anything else?", t: "¿Todo bien por aquí? ¿Les traigo algo más?", s: "Al pasar por la mesa para revisar a mitad de la comida.", sEn: "When you check on the table partway through the meal.", n: "Acompáñalo con una sonrisa; suena como interés genuino, no como apuro.", nEn: "Pair it with a smile so it sounds like genuine care, not rushing them." },
    "loc-mes14": { e: "Shall I heat up your food? It's been sitting for a few minutes.", t: "¿Le caliento la comida? Lleva unos minutos servida.", s: "Cuando notas que el plato del cliente se enfrió.", sEn: "When you notice the customer's plate has gone cold.", n: "\"Shall I...?\" es muy cortés; en EE. UU. también vale \"Want me to heat it up?\".", nEn: "\"Shall I...?\" is very polite; in the US \"Want me to heat it up?\" also works." },
    "loc-mes15": { e: "Would you like the wine list, or shall I bring something while you decide?", t: "¿Desea ver la carta de vinos, o le traigo algo mientras decide?", s: "Después de sentar a los clientes en un restaurante con buena oferta de vinos.", sEn: "After seating guests at a restaurant with a good wine selection.", n: "'wine list' es el término correcto; evita decir 'wine letter'.", nEn: "'Wine list' is the right term; avoid saying 'wine letter'." },
    "loc-mes16": { e: "How was everything? Can I get you anything else before the bill?", t: "¿Cómo estuvo todo? ¿Le traigo algo más antes de la cuenta?", s: "Al recoger los platos vacíos para saber si todo gustó.", sEn: "When clearing the empty plates to check if everything was enjoyed.", n: "Es más natural que 'how was all'; usa siempre 'everything'.", nEn: "It's more natural than 'how was all'; always use 'everything'." },
    // ===================== At reception (recepcion) =====================
    "loc-rec01": { e: "Welcome, do you have a reservation with us tonight?", t: "Bienvenido, ¿tiene una reserva con nosotros esta noche?", s: "En recepción cuando llega un huésped.", sEn: "At the front desk when a guest arrives.", n: "\"Reservation\" es el término de hotel; \"booking\" es más común en el Reino Unido.", nEn: "\"Reservation\" is the hotel term; \"booking\" is more common in the UK." },
    "loc-rec02": { e: "May I see your passport, please, to complete the check-in?", t: "¿Me permite su pasaporte, por favor, para completar el registro?", s: "Durante el registro de un huésped extranjero.", sEn: "During check-in for a foreign guest.", n: "\"May I...\" es más formal y cortés que \"Can I...\" para pedir documentos.", nEn: "\"May I...\" is more formal and polite than \"Can I...\" when asking for documents." },
    "loc-rec03": { e: "Breakfast is from seven to ten in the dining room downstairs.", t: "El desayuno es de siete a diez en el comedor de abajo.", s: "Al explicar los horarios del hotel durante el check-in.", sEn: "When explaining the hotel schedule during check-in.", n: "Para horas usa \"from... to...\"; \"between seven and ten\" también suena natural.", nEn: "For times use \"from... to...\"; \"between seven and ten\" also sounds natural." },
    "loc-rec04": { e: "Your room is on the second floor, and the elevator is on your left.", t: "Su habitación está en el segundo piso, y el ascensor está a su izquierda.", s: "Al entregar la llave y dar indicaciones al huésped.", sEn: "When handing over the key and giving directions to the guest.", n: "Ojo: en EE. UU. \"second floor\" es el primer piso de arriba; en el Reino Unido eso es \"first floor\".", nEn: "Note: in the US \"second floor\" is one up from ground; in the UK that's the \"first floor\"." },
    "loc-rec05": { e: "The wifi is free, and the password is on the back of your key card.", t: "El wifi es gratis, y la contraseña está atrás de su tarjeta llave.", s: "Cuando el huésped pregunta por internet en la recepción.", sEn: "When the guest asks about internet at the front desk.", n: "\"Wifi\" se pronuncia \"uai-fai\", no \"ui-fi\".", nEn: "\"Wifi\" is pronounced \"why-fy\", not \"wee-fee\"." },
    "loc-rec06": { e: "What time is check-out? I'd like to plan my morning.", t: "¿A qué hora es la salida? Quiero organizar mi mañana.", s: "Cuando un huésped pregunta hasta qué hora puede quedarse.", sEn: "When a guest asks how late they can stay.", n: "\"Check-out\" lleva guion como sustantivo; \"to check out\" sin guion es el verbo.", nEn: "\"Check-out\" is hyphenated as a noun; \"to check out\" without a hyphen is the verb." },
    "loc-rec07": { e: "Do you need an extra towel, or anything else for the room?", t: "¿Necesita una toalla extra, o algo más para la habitación?", s: "Cuando un huésped pide algo en recepción y quieres ofrecerle más.", sEn: "When a guest asks for something at reception and you want to offer more.", n: "Usa \"extra\" antes del sustantivo: \"an extra towel\", no \"a towel extra\".", nEn: "Put \"extra\" before the noun: \"an extra towel\", not \"a towel extra\"." },
    "loc-rec08": { e: "I'm happy to help you with that, just give me one moment.", t: "Con gusto le ayudo con eso, deme un momento.", s: "Cuando un huésped te pide un favor y quieres mostrar buena disposición.", sEn: "When a guest asks you for a favor and you want to sound willing.", n: "\"I'm happy to help\" suena más cálido que \"I can help\".", nEn: "\"I'm happy to help\" sounds warmer than \"I can help\"." },
    "loc-rec09": { e: "I'm sorry, we're fully booked tonight, but I can recommend a place nearby.", t: "Lo siento, estamos llenos esta noche, pero puedo recomendarle un lugar cerca.", s: "Cuando alguien quiere una habitación y no hay disponibilidad.", sEn: "When someone wants a room and there's no availability.", n: "\"Fully booked\" es lo natural en hoteles; \"full\" suena a estómago lleno.", nEn: "\"Fully booked\" is natural for hotels; \"full\" sounds like a full stomach." },
    "loc-rec10": { e: "How was your stay with us? I hope everything was comfortable.", t: "¿Qué tal su estadía con nosotros? Espero que todo haya sido cómodo.", s: "Cuando el huésped se va y quieres saber su experiencia.", sEn: "When the guest is leaving and you want to hear about their experience.", n: "\"Stay\" se pronuncia \"stéi\", no \"estéi\"; evita la 'e' al inicio.", nEn: "\"Stay\" sounds like \"stay\", with no extra 'e' at the start." },
    "loc-rec11": { e: "Do you need help with your luggage? I can take it up to your room.", t: "¿Necesita ayuda con el equipaje? Puedo subírselo a la habitación.", s: "Cuando un huésped llega o sale con maletas pesadas.", sEn: "When a guest arrives or leaves with heavy bags.", n: "\"Luggage\" es incontable: di \"your luggage\", nunca \"luggages\".", nEn: "\"Luggage\" is uncountable: say \"your luggage\", never \"luggages\"." },
    "loc-rec12": { e: "Check-in is at three, but you're welcome to leave your bags with us until then.", t: "El registro es a las tres, pero puede dejar sus maletas con nosotros hasta entonces.", s: "Cuando un huésped llega antes de la hora de registro.", sEn: "When a guest arrives before check-in time.", n: "\"Check-in\" lleva guion como sustantivo; \"check in\" separado es el verbo.", nEn: "\"Check-in\" is hyphenated as a noun; \"check in\" apart is the verb." },
    "loc-rec13": { e: "Would you like me to call a taxi for you?", t: "¿Quiere que le pida un taxi?", s: "Cuando un huésped necesita transporte para salir.", sEn: "When a guest needs transport to go out.", n: "\"Would you like me to...\" es más cortés que \"Do you want me to...\".", nEn: "\"Would you like me to...\" is more polite than \"Do you want me to...\"." },
    "loc-rec14": { e: "Your key, please, and I'll have your bill ready in a minute.", t: "Su llave, por favor, y le tengo la cuenta lista en un minuto.", s: "Cuando el huésped hace el check-out y devuelve la llave.", sEn: "When the guest checks out and returns the key.", n: "Agregar \"please\" suaviza la petición y suena profesional.", nEn: "Adding \"please\" softens the request and sounds professional." },
    "loc-rec15": { e: "Would you like me to store your luggage until your room is ready?", t: "¿Desea que le guarde el equipaje hasta que su habitación esté lista?", s: "Cuando un huésped llega antes de la hora de registro.", sEn: "When a guest arrives before check-in time.", n: "'luggage' es incontable; nunca digas 'luggages'.", nEn: "'Luggage' is uncountable; never say 'luggages'." },
    "loc-rec16": { e: "Just so you know, the pool closes at eight, so plan your swim before then.", t: "Para que lo sepa, la piscina cierra a las ocho, así que planee su baño antes.", s: "Al informar a un huésped sobre los horarios de las instalaciones.", sEn: "When informing a guest about facility hours.", n: "'pool' se pronuncia 'pul', con la 'l' clara al final.", nEn: "'Pool' is pronounced 'pool' with a clear 'l' at the end." },
    // ===================== Tours & guides (guias) =====================
    "loc-gui01": { e: "Welcome to the tour, everyone, I'm glad you could join us today.", t: "Bienvenidos al tour, me alegra que hayan podido acompañarnos hoy.", s: "Al inicio del recorrido, para saludar al grupo.", sEn: "At the start of the tour, to greet the group.", n: "\"Welcome to\" lleva \"to\"; no digas \"welcome at the tour\".", nEn: "\"Welcome to\" needs \"to\"; don't say \"welcome at the tour\"." },
    "loc-gui02": { e: "Please follow me, and stay close so no one gets left behind.", t: "Síganme, por favor, y manténganse cerca para que nadie se quede atrás.", s: "Cuando empiezas a caminar y quieres que el grupo te siga.", sEn: "When you start walking and want the group to follow you.", n: "\"Follow me\" no lleva preposición: nunca digas \"follow to me\".", nEn: "\"Follow me\" takes no preposition: never say \"follow to me\"." },
    "loc-gui03": { e: "This way, please, and mind the step on your right.", t: "Por aquí, por favor, y cuidado con el escalón a su derecha.", s: "Cuando guías al grupo por un lugar con un desnivel o peligro.", sEn: "When you lead the group past an uneven spot or hazard.", n: "\"Mind the step\" es muy común en inglés británico; \"watch your step\" también sirve.", nEn: "\"Mind the step\" is common in British English; \"watch your step\" also works." },
    "loc-gui04": { e: "The city was founded in 1533 by Spanish settlers.", t: "La ciudad fue fundada en 1533 por colonos españoles.", s: "Cuando explicas la historia de un lugar durante el tour.", sEn: "When you explain the history of a place during the tour.", n: "1533 se dice \"fifteen thirty-three\", no \"one thousand five hundred...\".", nEn: "Say 1533 as \"fifteen thirty-three\", not \"one thousand five hundred...\"." },
    "loc-gui05": { e: "We have fifteen minutes for photos, then we'll move on.", t: "Tenemos quince minutos para fotos, luego seguimos.", s: "Cuando das una pausa en un punto bonito del recorrido.", sEn: "When you give a break at a scenic spot on the tour.", n: "Cuida \"fifteen\" (15) vs \"fifty\" (50): el acento va al final en \"fifteen\".", nEn: "Mind \"fifteen\" (15) vs \"fifty\" (50): \"fifteen\" is stressed on the last syllable." },
    "loc-gui06": { e: "Please don't stray from the group, it's easy to get lost here.", t: "No se alejen del grupo, es fácil perderse por aquí.", s: "Cuando el grupo está en un lugar grande o concurrido.", sEn: "When the group is in a large or crowded place.", n: "Una alternativa más simple es \"please stay with the group\".", nEn: "A simpler alternative is \"please stay with the group\"." },
    "loc-gui07": { e: "Let's meet at the bus at three, so please don't be late.", t: "Nos vemos en el bus a las tres, así que por favor no se demoren.", s: "Cuando das tiempo libre y fijas un punto de encuentro.", sEn: "When you give free time and set a meeting point.", n: "\"Let's meet at\" para el lugar y \"at three\" para la hora; no mezcles \"in three\".", nEn: "Use \"meet at\" for the place and \"at three\" for the time; not \"in three\"." },
    "loc-gui08": { e: "Do you have any questions before we continue?", t: "¿Tienen alguna pregunta antes de continuar?", s: "Después de explicar algo, para invitar a preguntar.", sEn: "After explaining something, to invite questions.", n: "\"Any questions?\" solo también funciona y suena natural.", nEn: "\"Any questions?\" on its own also works and sounds natural." },
    "loc-gui09": { e: "Keep your belongings safe, especially in the crowded areas.", t: "Cuiden sus pertenencias, sobre todo en las zonas con mucha gente.", s: "Cuando entran a un lugar lleno de gente o turistas.", sEn: "When you enter a crowded or touristy place.", n: "\"Belongings\" siempre va en plural; no digas \"belonging\".", nEn: "\"Belongings\" is always plural; don't say \"belonging\"." },
    "loc-gui10": { e: "I hope you enjoy the visit, and feel free to take lots of photos.", t: "Espero que disfruten la visita, y tomen muchas fotos sin problema.", s: "Al dejar al grupo explorar por su cuenta un sitio.", sEn: "When you let the group explore a site on their own.", n: "\"Enjoy the visit\" sin \"to\"; \"enjoy\" no lleva infinitivo después.", nEn: "\"Enjoy the visit\" with no \"to\"; \"enjoy\" isn't followed by an infinitive." },
    "loc-gui11": { e: "On your left you'll see the cathedral, one of the oldest in the country.", t: "A su izquierda verán la catedral, una de las más antiguas del país.", s: "Cuando señalas un punto de interés mientras caminan o van en bus.", sEn: "When you point out a landmark as you walk or ride the bus.", n: "Usa \"on your left/right\" para indicar el lado desde el punto de vista del turista.", nEn: "Use \"on your left/right\" to point from the tourist's point of view." },
    "loc-gui12": { e: "Take a photo here, the view of the bay is amazing.", t: "Tomen una foto aquí, la vista de la bahía es increíble.", s: "En un mirador o punto fotogénico del recorrido.", sEn: "At a lookout or photogenic spot on the tour.", n: "\"Take a photo\" es lo natural; \"make a photo\" es un error común.", nEn: "\"Take a photo\" is natural; \"make a photo\" is a common mistake." },
    "loc-gui13": { e: "The tour lasts two hours, so we'll be back before lunch.", t: "El recorrido dura dos horas, así que estaremos de vuelta antes del almuerzo.", s: "Cuando empiezas el tour y el grupo quiere saber cuánto tiempo tomará.", sEn: "When you start the tour and the group wants to know how long it will take.", n: "Di 'lasts' (no 'last') para hablar de duración; suena como 'lasts', con la 'a' corta.", nEn: "Use 'lasts' (with the -s) for duration, and keep the 'a' short." },
    "loc-gui14": { e: "Does anyone need water before we head up the hill?", t: "¿Alguien necesita agua antes de subir la colina?", s: "Cuando revisas si alguien del grupo necesita algo antes de seguir caminando.", sEn: "When you check whether anyone in the group needs something before walking on.", n: "'Anyone' es más natural que 'somebody' para preguntas a un grupo.", nEn: "'Anyone' sounds more natural than 'somebody' when asking a whole group." },
    "loc-gui15": { e: "Please stay together so no one gets lost in the crowd.", t: "Manténganse juntos, por favor, para que nadie se pierda entre la gente.", s: "Al guiar a un grupo por un lugar concurrido durante un tour.", sEn: "When leading a group through a busy place during a tour.", n: "Una variante útil es 'please stay close to me'.", nEn: "A useful variant is 'please stay close to me'." },
    "loc-gui16": { e: "Can everyone hear me okay, or should I speak up?", t: "¿Pueden oírme todos bien, o hablo más fuerte?", s: "Al comenzar una explicación con un grupo grande o ruidoso.", sEn: "When starting an explanation with a large or noisy group.", n: "Añadir 'or should I speak up?' muestra que te importa el grupo.", nEn: "Adding 'or should I speak up?' shows you care about the group." },
    // ===================== Taxi & transport (taxi-en) =====================
    "loc-tax01": { e: "Good evening! Where to?", t: "¡Buenas noches! ¿A dónde lo llevo?", s: "Cuando un pasajero se sube al taxi y le preguntas su destino.", sEn: "When a passenger gets in the taxi and you ask their destination.", n: "'Where to?' es la versión corta y natural de 'Where do you want to go?'.", nEn: "'Where to?' is the short, natural version of 'Where do you want to go?'." },
    "loc-tax02": { e: "Hop in, please, I'll put your bag in the back.", t: "Súbase, por favor, le pongo la maleta atrás.", s: "Cuando invitas al pasajero a subir mientras tú te encargas del equipaje.", sEn: "When you invite the passenger to get in while you handle the luggage.", n: "'Hop in' es amistoso e informal; con clientes muy formales mejor 'Please get in'.", nEn: "'Hop in' is friendly and casual; for very formal clients say 'Please get in'." },
    "loc-tax03": { e: "It's twenty thousand pesos, or you can pay by card.", t: "Son veinte mil pesos, o también puede pagar con tarjeta.", s: "Cuando llegas al destino y le dices al pasajero cuánto debe pagar.", sEn: "When you arrive and tell the passenger how much they owe.", n: "Di 'It's' (no 'It are') aunque sean muchos pesos; el precio total va en singular.", nEn: "Say 'It's' (not 'It are') even for big amounts; a total price stays singular." },
    "loc-tax04": { e: "Are you in a hurry? I can take the highway if you like.", t: "¿Tiene afán? Puedo tomar la autopista si quiere.", s: "Cuando quieres saber si el pasajero necesita llegar rápido para elegir la ruta.", sEn: "When you want to know if the passenger needs to get there fast so you can pick the route.", n: "'Hurry' suena 'JÓ-rri', pero con la 'h' suave del inglés (un soplo de aire), no la 'j' fuerte del español.", nEn: "'Hurry' sounds like 'HUH-ree'; the 'h' is a soft breath, not a hard Spanish 'j'." },
    "loc-tax05": { e: "We'll be there in ten minutes if the traffic stays light.", t: "Llegamos en diez minutos si el tráfico sigue tranquilo.", s: "Cuando el pasajero pregunta cuánto falta y le das un estimado.", sEn: "When the passenger asks how long is left and you give an estimate.", n: "'We'll be there' suena más natural que 'We arrive'; usa 'we'll' para el futuro cercano.", nEn: "'We'll be there' sounds more natural than 'We arrive'; use 'we'll' for the near future." },
    "loc-tax06": { e: "Shall I open the trunk for your suitcases?", t: "¿Le abro el baúl para las maletas?", s: "Cuando ofreces guardar el equipaje del pasajero al inicio del viaje.", sEn: "When you offer to store the passenger's luggage at the start of the trip.", n: "En EE. UU. dicen 'trunk' y en el Reino Unido 'boot'; ambos para el baúl.", nEn: "Americans say 'trunk' and Brits say 'boot' for the car's luggage space." },
    "loc-tax07": { e: "Sorry, I don't have change for a fifty.", t: "Disculpe, no tengo cambio para un billete de cincuenta.", s: "Cuando el pasajero paga con un billete grande y no puedes darle el vuelto.", sEn: "When the passenger pays with a big bill and you can't give change.", n: "'Change' aquí significa vuelto/sencillo; no se usa en plural ('changes').", nEn: "Here 'change' means coins or small bills; it has no plural ('changes')." },
    "loc-tax08": { e: "Here we are. Have a good trip!", t: "Llegamos. ¡Buen viaje!", s: "Cuando dejas al pasajero en su destino y te despides amablemente.", sEn: "When you drop the passenger off and say a friendly goodbye.", n: "Para un vuelo o viaje largo también puedes decir 'Have a safe trip'.", nEn: "For a flight or long journey you can also say 'Have a safe trip'." },
    "loc-tax09": { e: "There's a lot of traffic today, so it might take a little longer.", t: "Hay mucho tráfico hoy, así que puede demorar un poco más.", s: "Cuando avisas al pasajero que el viaje será más lento por el tráfico.", sEn: "When you warn the passenger the ride will be slower because of traffic.", n: "'Traffic' es incontable: di 'a lot of traffic', nunca 'many traffics'.", nEn: "'Traffic' is uncountable: say 'a lot of traffic', never 'many traffics'." },
    "loc-tax10": { e: "Can I help with your bags? They look heavy.", t: "¿Le ayudo con las maletas? Se ven pesadas.", s: "Cuando ofreces cargar el equipaje del pasajero al subir o bajar.", sEn: "When you offer to carry the passenger's luggage getting in or out.", n: "'Bags' y 'luggage' sirven; 'luggage' es incontable y no lleva 's'.", nEn: "Both 'bags' and 'luggage' work, but 'luggage' is uncountable and takes no 's'." },
    "loc-tax11": { e: "Please put on your seatbelt, it's the law here.", t: "Póngase el cinturón, por favor, aquí es obligatorio por ley.", s: "Justo antes de arrancar con un pasajero en el taxi.", sEn: "Right before starting to drive with a passenger in the taxi.", n: "Es más cortés que el imperativo seco 'Put your seatbelt on'.", nEn: "It's more polite than the blunt command 'Put your seatbelt on'." },
    "loc-tax12": { e: "Do you mind the air conditioning, or should I turn it down?", t: "¿Le molesta el aire acondicionado, o lo bajo un poco?", s: "Cuando notas que el pasajero podría tener frío en el carro.", sEn: "When you notice the passenger might be cold in the car.", n: "Ojo: 'Do you mind?' significa lo contrario; 'yes' quiere decir que sí molesta.", nEn: "Careful: with 'Do you mind?' a 'yes' means it does bother them." },
    "loc-tax13": { e: "We're almost there, just a couple more blocks.", t: "Ya casi llegamos, solo un par de cuadras más.", s: "Para tranquilizar a un pasajero apurado cuando falta poco.", sEn: "To reassure a passenger in a hurry when you're close.", n: "'almost' suena 'OL-moust', con acento en la primera sílaba y la 'l' pronunciada.", nEn: "'Almost' sounds like 'AWL-most', stress on the first syllable, with the 'l' pronounced." },
    "loc-tax14": { e: "Is here okay for you, or would you like me to go a bit further?", t: "¿Le parece bien por aquí, o prefiere que avance un poco más?", s: "Al acercarte al destino para confirmar dónde dejar al pasajero.", sEn: "When approaching the destination to confirm where to drop off.", n: "Puedes decir 'right here?' como versión más corta y casual.", nEn: "You can say 'right here?' as a shorter, more casual version." },
    // ===================== Sales & market (ventas) =====================
    "loc-ven01": { e: "Hi there! How can I help you today?", t: "¡Hola! ¿En qué le puedo ayudar hoy?", s: "Cuando un cliente entra a tu puesto o tienda y lo saludas.", sEn: "When a customer comes into your stall or shop and you greet them.", n: "'How can I help you?' es más amable que 'What do you want?'.", nEn: "'How can I help you?' sounds warmer than 'What do you want?'." },
    "loc-ven02": { e: "If you take two, I'll give you a discount.", t: "Si lleva dos, le hago un descuento.", s: "Cuando quieres cerrar la venta ofreciendo un mejor precio.", sEn: "When you want to close the sale by offering a better price.", n: "Di 'a discount' con el artículo 'a'; en inglés no se omite.", nEn: "Say 'a discount' with the article 'a'; English doesn't drop it before singular nouns." },
    "loc-ven03": { e: "It's handmade, so each piece is a little different.", t: "Es hecho a mano, por eso cada pieza es un poco diferente.", s: "Cuando explicas a un turista por qué tu producto es especial y vale más.", sEn: "When you explain to a tourist why your product is special and worth more.", n: "'Handmade' es una sola palabra; no digas 'hand made' separado.", nEn: "'Handmade' is one word; don't write it as two ('hand made')." },
    "loc-ven04": { e: "What size are you looking for? We have small to extra large.", t: "¿Qué talla busca? Tenemos desde pequeña hasta extra grande.", s: "Cuando un cliente mira la ropa y le ayudas a encontrar su talla.", sEn: "When a customer is browsing clothes and you help find their size.", n: "Para zapatos usa la misma frase; 'size' sirve para talla y número.", nEn: "Use the same phrase for shoes; 'size' covers clothing and shoe sizes." },
    "loc-ven05": { e: "Cash only, please, the card machine isn't working today.", t: "Solo efectivo, por favor, hoy no funciona la máquina de tarjetas.", s: "Cuando un cliente quiere pagar con tarjeta pero solo aceptas efectivo.", sEn: "When a customer wants to pay by card but you only take cash.", n: "'Cash' suena 'cash'; evita decir 'cesh', la 'a' es abierta como en 'gato'.", nEn: "'Cash' has an open 'a' like in 'cat'; don't say 'cesh'." },
    "loc-ven06": { e: "Shall I wrap it for you? It's a nice gift.", t: "¿Se lo envuelvo? Es un buen regalo.", s: "Cuando el cliente compra algo y le ofreces envolverlo, sobre todo si es regalo.", sEn: "When the customer buys something and you offer to wrap it, especially as a gift.", n: "La 'w' de 'wrap' es muda; se dice 'rap', igual que la música.", nEn: "The 'w' in 'wrap' is silent; it sounds just like 'rap'." },
    "loc-ven07": { e: "It's the last one, so I can't really lower the price.", t: "Es el último que queda, así que no puedo bajar mucho el precio.", s: "Cuando el cliente regatea y tú justificas el precio porque queda solo uno.", sEn: "When a customer haggles and you justify the price because only one is left.", n: "'The last one' lleva 'one' al final; sin él suena incompleto en inglés.", nEn: "'The last one' needs 'one' at the end; leaving it out sounds incomplete." },
    "loc-ven08": { e: "Thank you so much! Come back soon!", t: "¡Muchas gracias! ¡Vuelva pronto!", s: "Cuando te despides de un cliente después de una venta.", sEn: "When you say goodbye to a customer after a sale.", n: "'Come back soon' es cálido e informal; con clientes formales usa 'We hope to see you again'.", nEn: "'Come back soon' is warm and casual; for formal clients use 'We hope to see you again'." },
    "loc-ven09": { e: "Would you like to try it? The fitting room is right behind you.", t: "¿Quiere probarlo? El probador está justo detrás de usted.", s: "Cuando un cliente mira una prenda en tu tienda y dudas si quiere medírsela.", sEn: "When a customer is eyeing a piece of clothing and you want to invite them to try it.", n: "Para comida usa \"try\" igual, pero para ropa también puedes decir \"try it on\".", nEn: "For food just say \"try it,\" but for clothing you can also say \"try it on.\"" },
    "loc-ven10": { e: "We have more colors if that one isn't quite what you want.", t: "Tenemos más colores por si ese no es justo lo que busca.", s: "Cuando el cliente parece dudar del color del producto que tiene en la mano.", sEn: "When a customer seems unsure about the color of the item they're holding.", n: "En inglés \"colors\" no lleva la \"u\" que sí tiene el inglés británico (\"colours\").", nEn: "In US spelling it's \"colors\"; British English adds a \"u\" (\"colours\")." },
    "loc-ven11": { e: "Come in, we're open, feel free to look around.", t: "Pase, está abierto, mire con confianza.", s: "Al invitar a un cliente que duda en la puerta de tu local.", sEn: "When inviting a customer who is hesitating at your shop door.", n: "Añadir 'feel free to look around' quita la presión de comprar.", nEn: "Adding 'feel free to look around' takes the pressure off buying." },
    "loc-ven12": { e: "That looks great on you, the color really suits you.", t: "Le queda muy bien, el color realmente le favorece.", s: "Cuando un cliente se prueba algo y le sienta bien.", sEn: "When a customer tries something on and it fits well.", n: "Para ropa di 'looks great on you', no 'fits you good'.", nEn: "For clothes say 'looks great on you', not 'fits you good'." },
    "loc-ven13": { e: "Is it a gift? I can wrap it nicely for you.", t: "¿Es para regalo? Se lo puedo envolver bonito.", s: "Al cobrar, cuando crees que el artículo puede ser un obsequio.", sEn: "At checkout, when you think the item might be a gift.", n: "Ofrecer envolver después suena atento y aumenta la venta.", nEn: "Offering to wrap it afterward sounds attentive and boosts the sale." },
    "loc-ven14": { e: "We offer home delivery, so we can bring it right to your door.", t: "Tenemos envío a domicilio, así que se lo llevamos hasta la puerta.", s: "Cuando un cliente compra algo grande o pesado.", sEn: "When a customer buys something large or heavy.", n: "'delivery' se pronuncia 'dilíveri', con el acento en la segunda sílaba.", nEn: "'Delivery' is stressed on the second syllable: di-LIV-er-y." },
    // ===================== Greetings & chat (saludos-en) =====================
    "loc-sal01": { e: "Good to see you! How are you today?", t: "¡Qué bueno verte! ¿Cómo estás hoy?", s: "Cuando saludas a un cliente o compañero al empezar la conversación.", sEn: "When you greet a customer or coworker as the conversation begins.", n: "La respuesta corta más natural es \"I'm good, thanks. And you?\"", nEn: "The most natural short reply is \"I'm good, thanks. And you?\"" },
    "loc-sal02": { e: "Nice to meet you, I'm Carlos, your guide for today.", t: "Mucho gusto, soy Carlos, su guía de hoy.", s: "Cuando conoces a alguien por primera vez y te presentas.", sEn: "When you meet someone for the first time and introduce yourself.", n: "Solo se usa la primera vez; al despedirte di \"Nice meeting you.\"", nEn: "Use it only the first time; when saying goodbye say \"Nice meeting you.\"" },
    "loc-sal03": { e: "Where are you from? We get a lot of visitors from Canada.", t: "¿De dónde eres? Recibimos muchos visitantes de Canadá.", s: "Cuando charlas con un turista y quieres conocer su país de origen.", sEn: "When chatting with a tourist and you want to know their home country.", n: "Suena más amable añadir un comentario después en vez de solo preguntar.", nEn: "It sounds friendlier to add a small comment afterward rather than just asking." },
    "loc-sal04": { e: "So what do you do? Are you here for work or vacation?", t: "Y, ¿a qué te dedicas? ¿Estás aquí por trabajo o de vacaciones?", s: "Cuando conversas con un huésped y quieres saber su profesión.", sEn: "When chatting with a guest and you want to know their profession.", n: "\"What do you do?\" significa el trabajo; \"What are you doing?\" es ahora mismo.", nEn: "\"What do you do?\" asks about your job; \"What are you doing?\" means right now." },
    "loc-sal05": { e: "Thanks for stopping by. Have a nice day!", t: "Gracias por venir. ¡Que tengas un buen día!", s: "Cuando un cliente se va y quieres despedirte con calidez.", sEn: "When a customer leaves and you want to send them off warmly.", n: "Variante igual de común y un poco más cálida: \"Have a great day!\"", nEn: "An equally common, slightly warmer variant is \"Have a great day!\"" },
    "loc-sal06": { e: "See you later, take care on the road!", t: "¡Nos vemos luego, cuídate en el camino!", s: "Cuando te despides de alguien que volverás a ver pronto.", sEn: "When saying bye to someone you'll see again soon.", n: "Más informal aún: \"See ya!\"; en lo profesional mejor \"See you soon.\"", nEn: "More casual: \"See ya!\"; in professional settings use \"See you soon.\"" },
    "loc-sal07": { e: "Sorry, can you repeat that, please? It's a little noisy in here.", t: "Perdón, ¿puedes repetir, por favor? Hay un poco de ruido aquí.", s: "Cuando no escuchaste bien y necesitas que el cliente repita.", sEn: "When you didn't catch something and need the customer to repeat it.", n: "Más formal: \"Could you repeat that, please?\"; \"could\" suena más cortés.", nEn: "More formal: \"Could you repeat that, please?\"; \"could\" sounds more polite." },
    "loc-sal08": { e: "I'm sorry, I don't understand. Could you say it another way?", t: "Disculpe, no entiendo. ¿Podría decirlo de otra forma?", s: "Cuando no comprendes lo que pidió el cliente y necesitas aclararlo.", sEn: "When you can't grasp what the customer asked and need it clarified.", n: "Evita \"I don't understand you\"; suena a culpar a la persona.", nEn: "Avoid \"I don't understand you\"; it can sound like you're blaming them." },
    "loc-sal09": { e: "Good morning! Welcome, how can I help you today?", t: "¡Buenos días! Bienvenido, ¿en qué le puedo ayudar hoy?", s: "Cuando saludas a alguien por la mañana al llegar a tu negocio.", sEn: "When you greet someone in the morning as they arrive at your business.", n: "Después del mediodía usa \"Good afternoon\" y tras las seis \"Good evening.\"", nEn: "After noon say \"Good afternoon,\" and after six say \"Good evening.\"" },
    "loc-sal10": { e: "Hi again! How's your day going so far?", t: "¡Hola de nuevo! ¿Qué tal va tu día hasta ahora?", s: "Cuando saludas con confianza a un cliente habitual o compañero.", sEn: "When greeting a regular customer or coworker in a friendly way.", n: "\"How's your day?\" es informal; con clientes nuevos usa \"How are you?\"", nEn: "\"How's your day?\" is casual; with new customers prefer \"How are you?\"" },
    "loc-sal11": { e: "Pleased to meet you, I've heard great things about your work.", t: "Encantado de conocerte, he oído cosas muy buenas de tu trabajo.", s: "Cuando conoces a alguien en un contexto formal o de negocios.", sEn: "When meeting someone in a formal or business setting.", n: "\"Pleased to meet you\" es más formal que \"Nice to meet you.\"", nEn: "\"Pleased to meet you\" is more formal than \"Nice to meet you.\"" },
    "loc-sal12": { e: "Thanks for everything. Take care, and travel safe!", t: "Gracias por todo. ¡Cuídate y buen viaje!", s: "Cuando te despides de alguien deseándole bienestar.", sEn: "When you say goodbye and wish someone well.", n: "Cuida la pronunciación: \"care\" suena \"ker\", no \"car\".", nEn: "Watch the pronunciation: \"care\" sounds like \"ker,\" not \"car.\"" },
    "loc-sal13": { e: "Hi, what's your name? I'll be your guide today.", t: "Hola, ¿cómo te llamas? Seré tu guía hoy.", s: "Cuando conoces a un cliente o compañero nuevo y quieres presentarte.", sEn: "When you meet a new customer or coworker and want to introduce yourself.", n: "\"What's your name?\" es informal; en contextos muy formales di \"May I have your name?\".", nEn: "\"What's your name?\" is informal; in very formal contexts say \"May I have your name?\"" },
    "loc-sal14": { e: "Nice to meet you too. Likewise!", t: "Mucho gusto a ti también. ¡Igualmente!", s: "Cuando respondes a alguien que acaba de decir que le da gusto conocerte.", sEn: "When you reply to someone who just said it was nice to meet you.", n: "\"Likewise\" es una forma corta y educada de decir \"igualmente\" en un saludo.", nEn: "\"Likewise\" is a short, polite way to say \"same to you\" in a greeting." },
    // ===================== On the phone (telefono) =====================
    "loc-tel01": { e: "Good morning, may I ask who's calling?", t: "Buenos días, ¿me permite saber quién habla?", s: "Cuando contestas el teléfono y quieres saber quién es la persona.", sEn: "When you answer the phone and want to know who is on the line.", n: "Más cortés: \"May I ask who's calling?\" en vez de solo \"Who's calling?\"", nEn: "More polite: \"May I ask who's calling?\" instead of just \"Who's calling?\"" },
    "loc-tel02": { e: "One moment, please, I'll check that for you.", t: "Un momento, por favor, se lo reviso.", s: "Cuando necesitas que el cliente espere mientras buscas algo.", sEn: "When you need the caller to wait while you look something up.", n: "Equivalente natural: \"Just a moment\" o \"Hold on a second, please.\"", nEn: "Natural equivalents: \"Just a moment\" or \"Hold on a second, please.\"" },
    "loc-tel03": { e: "She's not in right now. Can I leave a message?", t: "Ella no está ahora. ¿Puedo dejar un mensaje?", s: "Cuando la persona que buscas no está y quieres dejarle un recado.", sEn: "When the person you want isn't available and you'd like to leave a note.", n: "Si tú recibes la llamada, ofrece: \"Would you like to leave a message?\"", nEn: "If you're the one answering, offer: \"Would you like to leave a message?\"" },
    "loc-tel04": { e: "I'll call you back in ten minutes with the details.", t: "Le devuelvo la llamada en diez minutos con los detalles.", s: "Cuando no puedes atender ahora pero prometes volver a llamar.", sEn: "When you can't deal with it now but promise to phone again.", n: "\"Call back\" es por teléfono; para escribir di \"I'll get back to you.\"", nEn: "\"Call back\" is by phone; for writing say \"I'll get back to you.\"" },
    "loc-tel05": { e: "Can you hear me okay? The line sounds a little weak.", t: "¿Me escucha bien? La línea suena un poco débil.", s: "Cuando la llamada se oye mal y quieres confirmar que te escuchan.", sEn: "When the call sounds bad and you want to confirm they can hear you.", n: "\"Hear\" suena \"hir\"; es homófono de \"here\" (suenan igual) aunque significa escuchar.", nEn: "\"Hear\" sounds like \"hir\"; it's a homophone of \"here\" but means to listen." },
    "loc-tel06": { e: "I'm sorry, I think you have the wrong number.", t: "Disculpe, creo que marcó el número equivocado.", s: "Cuando alguien llama buscando a una persona o lugar que no es.", sEn: "When someone calls asking for a person or place that isn't yours.", n: "Suaviza con \"I think\" antes para no sonar brusco al corregir.", nEn: "Soften it with \"I think\" first so the correction doesn't sound blunt." },
    "loc-tel07": { e: "Good morning, thank you for calling. Who would you like to speak to?", t: "Buenos días, gracias por llamar. ¿Con quién desea hablar?", s: "Cuando contestas el teléfono y necesitas saber a qué persona busca quien llama.", sEn: "When you answer the phone and need to know which person the caller is looking for.", n: "Más formal: \"May I ask who you'd like to speak to?\"; evita el directo \"Who do you want?\".", nEn: "More formal: \"May I ask who you'd like to speak to?\"; avoid the blunt \"Who do you want?\"" },
    "loc-tel08": { e: "Thanks for calling, and please don't hesitate to reach out again.", t: "Gracias por llamar, y no dude en contactarnos de nuevo.", s: "Al cerrar una llamada con un cliente para despedirte de forma amable.", sEn: "When closing a call with a customer to say goodbye politely.", n: "Puedes añadir \"have a great day\" al final para sonar más cálido.", nEn: "You can add \"have a great day\" at the end to sound warmer." },
    "loc-tel09": { e: "I'm sorry, could you speak more slowly? The line isn't very clear.", t: "Disculpe, ¿puede hablar más despacio? La línea no está muy clara.", s: "Cuando la persona habla rápido por teléfono y no logras entender.", sEn: "When the person is speaking fast on the phone and you can't follow.", n: "Pronuncia \"slowly\" como \"SLOU-li\"; empieza con \"sorry\" para sonar cortés.", nEn: "Pronounce \"slowly\" as \"SLOH-lee\"; start with \"sorry\" to sound polite." },
    "loc-tel10": { e: "One moment, please. I'll put you through to a colleague who can help.", t: "Un momento, por favor. Le paso con un compañero que puede ayudarle.", s: "Cuando no puedes resolver tú la consulta y transfieres la llamada a otra persona.", sEn: "When you can't handle the request yourself and transfer the call to someone else.", n: "\"Put through\" es muy británico; en EE. UU. se dice más \"transfer you to\".", nEn: "\"Put through\" is very British; in the US people more often say \"transfer you to\"." },
    "loc-tel11": { e: "Can I have your name, please, so I can pull up your booking?", t: "¿Me puede dar su nombre, por favor, para buscar su reserva?", s: "Cuando contestas el teléfono y necesitas identificar al cliente antes de ayudarlo.", sEn: "When you answer the phone and need to identify the caller before helping them.", n: "Agregar \"please\" suena más cortés que solo \"Can I have your name?\".", nEn: "Adding \"please\" sounds more polite than just \"Can I have your name?\"." },
    "loc-tel12": { e: "Please hold the line while I check that for you.", t: "Por favor, espere en línea mientras lo reviso.", s: "Cuando necesitas dejar al cliente en espera para buscar información.", sEn: "When you need to put the caller on hold to look something up.", n: "También puedes decir \"Can you hold for a moment?\" para sonar más suave.", nEn: "You can also say \"Can you hold for a moment?\" to sound softer." },
    "loc-tel13": { e: "I'll connect you now; please stay on the line.", t: "Lo comunico ahora mismo; por favor, no cuelgue.", s: "Cuando vas a pasar la llamada del cliente a la persona correcta.", sEn: "When you're about to transfer the caller to the right person.", n: "\"Put you through\" es una variante muy común: \"I'll put you through now.\"", nEn: "\"Put you through\" is a very common variant: \"I'll put you through now.\"" },
    "loc-tel14": { e: "Can you leave your number and I'll call you back?", t: "¿Me deja su número y yo le devuelvo la llamada?", s: "Cuando la persona que buscan no está y quieres tomar un recado.", sEn: "When the person they want isn't available and you want to take a message.", n: "Repite el número en voz alta para confirmarlo y evitar errores.", nEn: "Repeat the number back out loud to confirm it and avoid mistakes." },
    // ===================== Giving directions (direcciones) =====================
    "loc-dir01": { e: "Go straight ahead for two blocks and you'll see it on your right.", t: "Siga derecho dos cuadras y lo verá a su derecha.", s: "Cuando alguien te pregunta por una dirección y el lugar está de frente.", sEn: "When someone asks you for directions and the place is straight ahead.", n: "\"Straight\" suena \"streit\", no \"es-traight\"; no le pongas la \"e\" al inicio.", nEn: "\"Straight\" sounds like \"strayt\", not \"es-traight\"; don't add an \"e\" at the start." },
    "loc-dir02": { e: "Turn left at the traffic light and the hotel is right there.", t: "Gire a la izquierda en el semáforo y el hotel está justo ahí.", s: "Cuando indicas a alguien que doble a la izquierda para llegar a un lugar.", sEn: "When you tell someone to turn left to reach a place.", n: "Acompaña la frase con un gesto de la mano; ayuda mucho si hay duda.", nEn: "Pair the phrase with a hand gesture; it helps a lot if there's any doubt." },
    "loc-dir03": { e: "Turn right after the bank and the entrance is just ahead.", t: "Gire a la derecha después del banco y la entrada está justo adelante.", s: "Cuando le explicas a alguien que debe doblar a la derecha en su recorrido.", sEn: "When you explain to someone that they need to turn right on their way.", n: "No confundas \"right\" (derecha) con \"left\"; señala con la mano para evitar errores.", nEn: "Don't mix up \"right\" with \"left\"; point with your hand to avoid mistakes." },
    "loc-dir04": { e: "Don't worry, it's only two blocks away, a five-minute walk.", t: "No se preocupe, está a solo dos cuadras, una caminata de cinco minutos.", s: "Cuando indicas qué tan cerca está un lugar contando cuadras.", sEn: "When you indicate how close a place is by counting blocks.", n: "En inglés británico se dice \"two streets away\"; \"blocks\" es más de EE. UU.", nEn: "In British English people say \"two streets away\"; \"blocks\" is more American." },
    "loc-dir05": { e: "The pharmacy is next to the bank, you can't miss it.", t: "La farmacia está al lado del banco, no tiene pérdida.", s: "Cuando ubicas un sitio usando un negocio conocido como referencia.", sEn: "When you locate a place using a well-known business as a reference.", n: "\"You can't miss it\" es la coletilla natural para decir que es fácil de encontrar.", nEn: "\"You can't miss it\" is the natural tag to say it's easy to find." },
    "loc-dir06": { e: "Excuse me, is the market far from here, or can I walk?", t: "Disculpe, ¿está lejos el mercado de aquí, o puedo ir caminando?", s: "Cuando preguntas por la distancia a un lugar antes de decidir cómo llegar.", sEn: "When you ask how far a place is before deciding how to get there.", n: "Para responder corto: \"Not really\" (no mucho) o \"Yes, quite far\".", nEn: "For a short reply: \"Not really\" (not much) or \"Yes, quite far\"." },
    "loc-dir07": { e: "Cross the street here and the bus stop is on the other side.", t: "Cruce la calle aquí y el paradero está al otro lado.", s: "Cuando le dices a alguien que pase al otro lado de la calle para continuar.", sEn: "When you tell someone to go to the other side of the street to continue.", n: "\"Cross\" lleva una sola sílaba; no digas \"croses\" para el imperativo.", nEn: "\"Cross\" is one syllable; don't say \"croses\" for the command form." },
    "loc-dir08": { e: "The café is on the corner, right where those two streets meet.", t: "El café está en la esquina, justo donde se cruzan esas dos calles.", s: "Cuando señalas que un lugar queda exactamente en una esquina.", sEn: "When you point out that a place is exactly on a corner.", n: "Se dice \"on the corner\", no \"in the corner\" (eso es un rincón cerrado).", nEn: "Say \"on the corner\", not \"in the corner\" (that means an inside nook)." },
    "loc-dir09": { e: "Good news, it's nearby, just around the corner from the plaza.", t: "Buena noticia, está cerca, a la vuelta de la esquina de la plaza.", s: "Cuando tranquilizas a alguien diciéndole que el destino está cerca.", sEn: "When you reassure someone that the destination is close.", n: "\"Nearby\" y \"close by\" significan lo mismo; ambos suenan naturales.", nEn: "\"Nearby\" and \"close by\" mean the same thing; both sound natural." },
    "loc-dir10": { e: "Take the second turn on your left and the parking is right there.", t: "Tome el segundo giro a su izquierda y el parqueadero está justo ahí.", s: "Cuando guías a un conductor o peatón a tomar un giro específico.", sEn: "When you guide a driver or pedestrian to take a specific turn.", n: "Más común para autos: \"take the second left\"; \"turn\" sirve también a pie.", nEn: "More common for cars: \"take the second left\"; \"turn\" also works on foot." },
    "loc-dir11": { e: "The pharmacy is right across from the church, you can't miss it.", t: "La farmacia está justo frente a la iglesia, no tiene pierde.", s: "Cuando un turista te pregunta dónde queda un lugar cercano.", sEn: "When a tourist asks you where a nearby place is.", n: "\"Across from\" es lo mismo que \"opposite\"; ambos sirven para \"frente a\".", nEn: "\"Across from\" means the same as \"opposite\"; both work for \"frente a\"." },
    "loc-dir12": { e: "Just walk for five minutes and it'll be on your right.", t: "Solo camine cinco minutos y lo verá a su derecha.", s: "Cuando indicas cuánto debe caminar la persona para llegar.", sEn: "When you tell someone how long to walk to get there.", n: "Puedes decir \"a five-minute walk\" como forma corta: \"It's a five-minute walk.\"", nEn: "You can say \"a five-minute walk\" as a short form: \"It's a five-minute walk.\"" },
    "loc-dir13": { e: "Go up this street and turn left at the corner.", t: "Suba por esta calle y gire a la izquierda en la esquina.", s: "Cuando das direcciones e indicas seguir por una calle en subida.", sEn: "When giving directions and telling someone to head up a street.", n: "Si la calle no sube, usa mejor \"go down this street\" o \"go along this street\".", nEn: "If the street doesn't go uphill, use \"go down this street\" or \"go along this street\" instead." },
    "loc-dir14": { e: "It's right there, just past the blue door.", t: "Está justo ahí, pasando la puerta azul.", s: "Cuando el lugar está muy cerca y casi puedes señalarlo.", sEn: "When the place is very close and you can almost point at it.", n: "\"Right\" aquí significa \"justo\", no \"derecha\"; el contexto lo aclara.", nEn: "\"Right\" here means \"exactly/just\", not the direction; context makes it clear." },
    // ===================== Job interview (entrevista) =====================
    "loc-ent01": { e: "I have experience in customer service, mostly at hotels and restaurants.", t: "Tengo experiencia en servicio al cliente, sobre todo en hoteles y restaurantes.", s: "Cuando te presentas en una entrevista y resaltas tu experiencia.", sEn: "When you introduce yourself in an interview and highlight your experience.", n: "Se usa \"experience in\" + un campo (customer service, sales); suena natural y profesional.", nEn: "Use \"experience in\" + a field (customer service, sales); it sounds natural and professional." },
    "loc-ent02": { e: "I speak basic English, but I'm practicing every day to improve.", t: "Hablo inglés básico, pero practico todos los días para mejorar.", s: "Cuando el entrevistador pregunta por tu nivel de inglés y eres honesto.", sEn: "When the interviewer asks about your English level and you're honest.", n: "Agregar \"but I'm improving\" da una impresión positiva y proactiva.", nEn: "Adding \"but I'm improving\" gives a positive, proactive impression." },
    "loc-ent03": { e: "I'm punctual and responsible, and I always show up on time.", t: "Soy puntual y responsable, y siempre llego a tiempo.", s: "Cuando describes tus cualidades personales en una entrevista de trabajo.", sEn: "When you describe your personal qualities in a job interview.", n: "\"Punctual\" se pronuncia \"PUNK-chual\"; respáldalo con un ejemplo concreto.", nEn: "\"Punctual\" is pronounced \"PUNK-chual\"; back it up with a concrete example." },
    "loc-ent04": { e: "Could you tell me what the hours are for this position?", t: "¿Me podría decir cuál es el horario para este puesto?", s: "Cuando preguntas en la entrevista por la jornada laboral del puesto.", sEn: "When you ask in the interview about the work schedule for the job.", n: "\"Hours\" en plural es lo natural para el horario; \"schedule\" también sirve.", nEn: "Plural \"hours\" is natural for the schedule; \"schedule\" also works." },
    "loc-ent05": { e: "If you choose me, I can start right away, even this week.", t: "Si me eligen, puedo empezar de inmediato, incluso esta semana.", s: "Cuando muestras disponibilidad inmediata al final de la entrevista.", sEn: "When you show immediate availability at the end of the interview.", n: "\"Right away\" y \"immediately\" sirven igual; el primero suena más natural.", nEn: "\"Right away\" and \"immediately\" work the same; the first sounds more natural." },
    "loc-ent06": { e: "I worked at a hotel for two years, mainly at the front desk.", t: "Trabajé dos años en un hotel, principalmente en la recepción.", s: "Cuando cuentas tu experiencia laboral previa en una entrevista.", sEn: "When you describe your previous work experience in an interview.", n: "Usa \"worked\" (pasado) para empleos terminados; \"work\" sería el presente.", nEn: "Use \"worked\" (past) for finished jobs; \"work\" would be the present." },
    "loc-ent07": { e: "Thank you for the opportunity, I really enjoyed meeting the team today.", t: "Gracias por la oportunidad, de verdad disfruté conocer al equipo hoy.", s: "Al terminar la entrevista, cuando te despides del entrevistador.", sEn: "At the end of the interview, when you say goodbye to the interviewer.", n: "Da un apretón de manos firme y sonríe al decirlo para dejar buena impresión.", nEn: "Give a firm handshake and smile as you say it to leave a good impression." },
    "loc-ent08": { e: "Thank you so much, when will I hear back about the position?", t: "Muchas gracias, ¿cuándo me darían respuesta sobre el puesto?", s: "Al cerrar la entrevista, cuando quieres saber los próximos pasos.", sEn: "When wrapping up the interview and you want to know the next steps.", n: "\"Hear back\" suena más natural que \"have an answer\"; pronuncia la 'h' de \"hear\".", nEn: "\"Hear back\" sounds more natural than \"have an answer\"; pronounce the 'h' in \"hear\"." },
    "loc-ent09": { e: "I like working in a team and I think I get along well with people.", t: "Me gusta trabajar en equipo y creo que me llevo bien con la gente.", s: "Cuando te preguntan por tus fortalezas o tu estilo de trabajo.", sEn: "When they ask about your strengths or your work style.", n: "Se dice \"in a team\", no \"in team\"; no olvides el artículo \"a\".", nEn: "Say \"in a team\", not \"in team\"; don't drop the article \"a\"." },
    "loc-ent10": { e: "Don't worry, I learn quickly and I'm not afraid to ask questions.", t: "No se preocupe, aprendo rápido y no me da miedo preguntar.", s: "Cuando el puesto requiere algo nuevo que aún no dominas.", sEn: "When the job needs something new that you haven't mastered yet.", n: "También puedes decir \"I'm a fast learner\", que suena muy natural en inglés.", nEn: "You can also say \"I'm a fast learner\", which sounds very natural in English." },
    "loc-ent11": { e: "I'm available on weekends and I can also cover evening shifts.", t: "Estoy disponible los fines de semana y también puedo cubrir turnos de noche.", s: "Cuando hablan de horarios y quieres mostrar flexibilidad.", sEn: "When they discuss the schedule and you want to show flexibility.", n: "Se usa \"on weekends\", con \"on\", no \"in weekends\".", nEn: "Use \"on weekends\", with \"on\", not \"in weekends\"." },
    "loc-ent12": { e: "That sounds great, so when do I start?", t: "Suena genial, entonces ¿cuándo empiezo?", s: "Cuando ya te ofrecieron el trabajo y quieres confirmar la fecha.", sEn: "When they've already offered you the job and you want to confirm the date.", n: "Usa \"start\", no \"begin\", que suena más formal y menos común aquí.", nEn: "Use \"start\", not \"begin\", which sounds more formal and less common here." },
    "loc-ent13": { e: "May I ask what the salary is for this position?", t: "¿Puedo preguntar cuál es el salario de este puesto?", s: "Cuando en una entrevista quieres saber cuánto pagan por el trabajo.", sEn: "When in an interview you want to know how much the job pays.", n: "Suena más profesional empezar con \"May I ask...\" en vez de preguntar directo.", nEn: "Starting with \"May I ask...\" sounds more professional than asking bluntly." },
    "loc-ent14": { e: "I have good references from my last two jobs.", t: "Tengo buenas referencias de mis dos últimos trabajos.", s: "Cuando en la entrevista mencionas que otros pueden recomendarte.", sEn: "When in the interview you mention that others can vouch for you.", n: "Ofrece: \"I can provide their contact details\" para sonar más seguro.", nEn: "Offer: \"I can provide their contact details\" to sound more confident." },
    // ===================== Office & emails (oficina) =====================
    "loc-ofi01": { e: "No problem, I'll send you the email right away with all the details.", t: "No hay problema, le envío el correo enseguida con todos los detalles.", s: "Cuando un cliente o colega te pide información por correo.", sEn: "When a client or colleague asks you for information by email.", n: "\"Right away\" significa \"enseguida\"; también sirve \"right now\".", nEn: "\"Right away\" means \"enseguida\"; \"right now\" works too." },
    "loc-ofi02": { e: "Thank you for your time; I look forward to your reply.", t: "Gracias por su tiempo; quedo atento a su respuesta.", s: "Para cerrar un correo formal de manera cortés.", sEn: "To close a formal email politely.", n: "Después de \"look forward to\" siempre va sustantivo o verbo en -ing, no infinitivo.", nEn: "After \"look forward to\" always use a noun or -ing verb, never the infinitive." },
    "loc-ofi03": { e: "Can we schedule a meeting for sometime next week?", t: "¿Podemos agendar una reunión para algún día de la próxima semana?", s: "Cuando necesitas coordinar una cita de trabajo con alguien.", sEn: "When you need to arrange a work appointment with someone.", n: "\"Schedule\" se pronuncia \"SKE-dyul\" (US) o \"SHE-dyul\" (UK), no \"esquedule\".", nEn: "\"Schedule\" is pronounced \"SKE-dyul\" (US) or \"SHE-dyul\" (UK), not \"esquedule\"." },
    "loc-ofi04": { e: "I'm attaching the document so you can review it before the call.", t: "Adjunto el documento para que lo pueda revisar antes de la llamada.", s: "Cuando envías un archivo junto con un correo.", sEn: "When you send a file along with an email.", n: "Se dice \"attaching\", no \"attaching to\"; el archivo es el objeto directo.", nEn: "Say \"attaching the document\", not \"attaching to\"; the file is the direct object." },
    "loc-ofi05": { e: "Sorry for the late reply, things have been very busy this week.", t: "Disculpe la demora en responder, ha sido una semana muy ocupada.", s: "Cuando respondes un correo varios días después de recibirlo.", sEn: "When you answer an email several days after receiving it.", n: "Más formal: \"I apologize for the delayed response\".", nEn: "More formal: \"I apologize for the delayed response\"." },
    "loc-ofi06": { e: "I agree, I think that's the best way to handle it.", t: "Estoy de acuerdo, creo que esa es la mejor manera de manejarlo.", s: "Cuando apoyas la propuesta de un colega en una conversación.", sEn: "When you support a colleague's proposal in a conversation.", n: "Se dice \"I agree\", nunca \"I am agree\"; es un verbo, no un adjetivo.", nEn: "Say \"I agree\", never \"I am agree\"; it's a verb, not an adjective." },
    "loc-ofi07": { e: "Sorry, could you explain that again? I didn't quite catch it.", t: "Disculpe, ¿me puede explicar de nuevo? No lo capté bien.", s: "Cuando no entendiste una instrucción y necesitas aclaración.", sEn: "When you didn't understand an instruction and need clarification.", n: "\"Could you\" es más cortés que \"can you\" para pedir algo.", nEn: "\"Could you\" is more polite than \"can you\" when asking for something." },
    "loc-ofi08": { e: "It's getting late, let's talk tomorrow when we're both fresh.", t: "Se está haciendo tarde, hablamos mañana que estemos descansados.", s: "Para terminar una conversación de trabajo y posponerla un día.", sEn: "To end a work conversation and put it off until the next day.", n: "También puedes decir \"let's catch up tomorrow\" en un tono más relajado.", nEn: "You can also say \"let's catch up tomorrow\" for a more relaxed tone." },
    "loc-ofi09": { e: "Hi, just checking, did you get my email from this morning?", t: "Hola, solo confirmando, ¿recibió mi correo de esta mañana?", s: "Cuando das seguimiento a un correo que aún no te responden.", sEn: "When you follow up on an email that hasn't been answered yet.", n: "\"Did you get\" es más natural que \"did you receive\" en el día a día.", nEn: "\"Did you get\" is more natural than \"did you receive\" in everyday use." },
    "loc-ofi10": { e: "I'll copy you on the email so you stay in the loop.", t: "Lo copio en el correo para que esté al tanto.", s: "Cuando vas a incluir a alguien en un correo dirigido a otra persona.", sEn: "When you're going to include someone on an email sent to another person.", n: "También se dice \"I'll CC you\", muy común en oficinas.", nEn: "You can also say \"I'll CC you\", very common in offices." },
    "loc-ofi11": { e: "What's the deadline for sending the report?", t: "¿Cuál es la fecha límite para enviar el reporte?", s: "Cuando necesitas saber para cuándo debes entregar una tarea o documento.", sEn: "When you need to know by when a task or document is due.", n: "\"Deadline\" suena \"déd-lain\"; la \"ea\" se pronuncia como \"e\" corta.", nEn: "\"Deadline\" sounds like \"ded-line\"; the \"ea\" is a short \"e\"." },
    "loc-ofi12": { e: "I'll check and let you know by the end of the day.", t: "Lo reviso y le aviso antes de que termine el día.", s: "Cuando alguien pregunta algo y necesitas verificar antes de responder.", sEn: "When someone asks something and you need to verify before answering.", n: "Útil agregar un plazo (\"by tomorrow\") para que la otra persona sepa qué esperar.", nEn: "It helps to add a time frame (\"by tomorrow\") so the other person knows what to expect." },
    "loc-ofi13": { e: "Could you please forward me the email from the client?", t: "¿Podría reenviarme el correo del cliente, por favor?", s: "Cuando le pides a un colega que te reenvíe un correo que no recibiste.", sEn: "When you ask a colleague to forward you an email you didn't get.", n: "\"Forward\" como verbo significa reenviar; no lo confundas con \"send\" (enviar nuevo).", nEn: "\"Forward\" as a verb means to re-send a received email; don't mix it up with \"send\" (a new one)." },
    "loc-ofi14": { e: "I'm on a call right now, can I get back to you in five minutes?", t: "Estoy en una llamada ahora mismo, ¿le puedo responder en cinco minutos?", s: "Cuando alguien te interrumpe y estás hablando por teléfono.", sEn: "When someone interrupts you while you're on the phone.", n: "\"On a call\" es más natural en oficina que \"talking on the phone\".", nEn: "\"On a call\" sounds more natural at work than \"talking on the phone\"." },
    // ===================== Basic grammar (gramatica-en) =====================
    "loc-gra01": { e: "I am the new receptionist; it's my first day today.", t: "Yo soy la nueva recepcionista; hoy es mi primer día.", s: "Cuando te presentas a un compañero o cliente.", sEn: "When you introduce yourself to a coworker or customer.", n: "En el habla se contrae a \"I'm\"; suena más natural que \"I am\".", nEn: "In speech it contracts to \"I'm\"; it sounds more natural than \"I am\"." },
    "loc-gra02": { e: "You are next in line, sir; I'll be right with you.", t: "Usted es el siguiente, señor; lo atiendo enseguida.", s: "Cuando le indicas a un cliente que es su turno.", sEn: "When you tell a customer it's their turn.", n: "Se contrae a \"you're\", que suena igual que \"your\"; cuidado al escribir.", nEn: "It contracts to \"you're\", which sounds like \"your\"; be careful when writing." },
    "loc-gra03": { e: "He is the manager; he can help you with the refund.", t: "Él es el gerente; él le puede ayudar con el reembolso.", s: "Cuando señalas a otra persona que puede atender al cliente.", sEn: "When you point out another person who can help the customer.", n: "Se contrae a \"he's\"; recuerda la 's' final que en español no existe.", nEn: "It contracts to \"he's\"; remember the final 's' that doesn't exist in Spanish." },
    "loc-gra04": { e: "We are open until ten, so there's plenty of time.", t: "Estamos abiertos hasta las diez, así que hay tiempo de sobra.", s: "Cuando le informas a un cliente el horario del negocio.", sEn: "When you tell a customer the business hours.", n: "Se contrae a \"we're\"; pronúncialo como \"wir\", no como \"güi-ar\".", nEn: "It contracts to \"we're\"; pronounce it like \"wir\", not \"güi-ar\"." },
    "loc-gra05": { e: "What time does the restaurant open?", t: "¿A qué hora abre el restaurante?", s: "Cuando preguntas por una cosa o un dato que no sabes.", sEn: "When you ask about a thing or a piece of information you don't know.", n: "\"What\" suena \"uot\", no \"juat\"; la 'h' es muda.", nEn: "\"What\" sounds like \"wot\", not \"hwat\"; the 'h' is silent." },
    "loc-gra06": { e: "Where is the nearest pharmacy?", t: "¿Dónde está la farmacia más cercana?", s: "Cuando preguntas por la ubicación de un lugar o una cosa.", sEn: "When you ask about the location of a place or a thing.", n: "Recuerda usar \"is/are\" después: \"Where is...?\" o \"Where are...?\".", nEn: "Remember to add \"is/are\" after it: \"Where is...?\" or \"Where are...?\"." },
    "loc-gra07": { e: "When does the tour start?", t: "¿Cuándo empieza el tour?", s: "Cuando preguntas por el momento o la hora de algo.", sEn: "When you ask about the time or moment of something.", n: "Para horas exactas también puedes decir \"What time...?\".", nEn: "For exact times you can also say \"What time...?\"." },
    "loc-gra08": { e: "Why is the bill so high?", t: "¿Por qué la cuenta es tan alta?", s: "Cuando preguntas por la razón o el motivo de algo.", sEn: "When you ask for the reason or motive behind something.", n: "No confundas \"why\" (por qué) con \"because\" (porque), que es la respuesta.", nEn: "Don't mix up \"why\" (the question) with \"because\" (the answer)." },
    "loc-gra09": { e: "I called you yesterday but you didn't answer.", t: "Te llamé ayer pero no contestaste.", s: "Cuando hablas de algo que pasó el día anterior.", sEn: "When you talk about something that happened the day before.", n: "Con \"yesterday\" el verbo va en pasado: \"I worked\", no \"I work\".", nEn: "With \"yesterday\" the verb goes in the past: \"I worked\", not \"I work\"." },
    "loc-gra10": { e: "See you tomorrow at nine.", t: "Nos vemos mañana a las nueve.", s: "Cuando hablas de algo que pasará el día siguiente.", sEn: "When you talk about something happening the next day.", n: "Ojo: \"tomorrow\" es el día futuro; \"morning\" es la mañana del día.", nEn: "Note: \"tomorrow\" is the future day; \"morning\" is the early part of the day." },
    "loc-gra11": { e: "How do you say \"gracias\" in English?", t: "¿Cómo se dice \"gracias\" en inglés?", s: "Cuando no sabes una palabra en inglés y quieres aprenderla.", sEn: "When you don't know a word in English and want to learn it.", n: "Frase clave para salir de apuros; añade \"in English\" al final.", nEn: "A key phrase to get unstuck; add \"in English\" at the end." },
    "loc-gra12": { e: "What does \"sold out\" mean?", t: "¿Qué significa \"sold out\"?", s: "Cuando oyes o lees una palabra y no sabes qué quiere decir.", sEn: "When you hear or read a word and don't know what it means.", n: "Pon la palabra en el espacio: \"What does X mean?\".", nEn: "Put the word in the gap: \"What does X mean?\"." },
    "loc-gra13": { e: "How do you get to the bus station from here?", t: "¿Cómo se llega a la estación de buses desde aquí?", s: "Cuando preguntas la manera de hacer algo o de llegar a un lugar.", sEn: "When you ask the way to do something or to get somewhere.", n: "'How' se pronuncia 'jáu' con 'h' aspirada suave, no como 'ou' en español.", nEn: "'How' is said 'how' with a light breathy 'h', not a hard sound." },
    "loc-gra14": { e: "How much is the room for one night?", t: "¿Cuánto cuesta la habitación por una noche?", s: "Cuando preguntas el precio de algo incontable o de un servicio.", sEn: "When you ask the price of something uncountable or a service.", n: "Usa 'how much' para incontables y 'how many' para cosas contables (how many nights).", nEn: "Use 'how much' for uncountable things and 'how many' for countable ones (how many nights)." },
    // ===================== In class (examen) =====================
    "loc-exa01": { e: "Raise your hand if you have a question.", t: "Levanta la mano si tienes una pregunta.", s: "Cuando un profesor pide a los estudiantes que levanten la mano.", sEn: "When a teacher asks students to raise their hand.", n: "\"Raise\" significa levantar algo; no lo confundas con \"rise\" (subir por sí solo).", nEn: "\"Raise\" means to lift something; don't confuse it with \"rise\" (to go up by itself)." },
    "loc-exa02": { e: "Please read out loud so everyone can hear you.", t: "Por favor lee en voz alta para que todos te escuchen.", s: "Cuando le pides a alguien que lea con voz para el grupo.", sEn: "When you ask someone to read aloud for the group.", n: "También puedes decir \"read aloud\"; significan lo mismo.", nEn: "You can also say \"read aloud\"; they mean the same thing." },
    "loc-exa03": { e: "Hand in your homework before Friday.", t: "Entrega la tarea antes del viernes.", s: "Cuando un profesor pide que se entregue un trabajo.", sEn: "When a teacher asks for work to be turned in.", n: "\"Hand in\" es entregar; \"hand out\" es repartir, no los mezcles.", nEn: "\"Hand in\" means submit; \"hand out\" means distribute, don't mix them up." },
    "loc-exa04": { e: "Excuse me, may I go to the restroom?", t: "Disculpe, ¿puedo ir al baño?", s: "Cuando pides permiso para ir al baño en clase o el trabajo.", sEn: "When you ask permission to go to the bathroom in class or at work.", n: "\"May I\" es más educado que \"Can I\" para pedir permiso.", nEn: "\"May I\" is more polite than \"Can I\" when asking permission." },
    "loc-exa05": { e: "Sorry, I didn't understand the question. Could you repeat it?", t: "Disculpe, no entendí la pregunta. ¿Podría repetirla?", s: "Cuando no captaste lo que te preguntaron y necesitas aclararlo.", sEn: "When you didn't catch what was asked and need it clarified.", n: "Es \"didn't understand\", no \"don't understood\"; el pasado va en \"did\".", nEn: "It's \"didn't understand\", not \"don't understood\"; the past goes in \"did\"." },
    "loc-exa06": { e: "How do you spell it? Letter by letter, please.", t: "¿Cómo se escribe? Letra por letra, por favor.", s: "Cuando necesitas que alguien deletree una palabra o un nombre.", sEn: "When you need someone to spell a word or name out.", n: "Sirve mucho para tomar nombres por teléfono o en recepción.", nEn: "Very useful for taking down names on the phone or at reception." },
    "loc-exa07": { e: "Sorry, could you say it again, please?", t: "Disculpe, ¿podría repetirlo, por favor?", s: "Cuando no escuchaste bien y necesitas que repitan.", sEn: "When you didn't hear well and need it repeated.", n: "Suaviza la frase con \"sorry\" o \"please\" para sonar más amable.", nEn: "Soften it with \"sorry\" or \"please\" to sound more polite." },
    "loc-exa08": { e: "I'm done with the exercise, what should I do now?", t: "Ya terminé el ejercicio, ¿qué hago ahora?", s: "Cuando avisas que acabaste una tarea o actividad.", sEn: "When you let someone know you've finished a task or activity.", n: "\"I'm done\" suena natural; \"I finished\" también sirve.", nEn: "\"I'm done\" sounds natural; \"I finished\" works too." },
    "loc-exa09": { e: "I'm not sure, but I think it's at three o'clock.", t: "No estoy seguro, pero creo que es a las tres.", s: "Cuando das una respuesta de la que no tienes certeza.", sEn: "When you give an answer you're not certain about.", n: "Añade \"but I think...\" para igual dar tu mejor respuesta.", nEn: "Add \"but I think...\" to still offer your best guess." },
    "loc-exa10": { e: "Can you help me with this, please?", t: "¿Me puedes ayudar con esto, por favor?", s: "Cuando necesitas asistencia con algo que no entiendes o no puedes hacer solo.", sEn: "When you need assistance with something you can't do alone.", n: "\"Could you help me?\" suena un poco más formal y educado.", nEn: "\"Could you help me?\" sounds a bit more formal and polite." },
    "loc-exa11": { e: "Open your books to page twenty, please.", t: "Abran el libro en la página veinte, por favor.", s: "Cuando el profesor indica a la clase empezar a leer una página.", sEn: "When the teacher tells the class to start on a certain page.", n: "En clase se usa el plural 'your books' aunque sea un libro por alumno.", nEn: "In class the plural 'your books' is used even though each student has one book." },
    "loc-exa12": { e: "Work in pairs and practice the dialogue together.", t: "Trabajen en parejas y practiquen el diálogo juntos.", s: "Cuando el profesor organiza una actividad de a dos.", sEn: "When the teacher sets up a two-person activity.", n: "'Pairs' se pronuncia 'pers', igual que 'pears'; significa parejas de dos.", nEn: "'Pairs' sounds like 'pers', the same as 'pears'; it means groups of two." },
    "loc-exa13": { e: "Write your name at the top of the page.", t: "Escriban su nombre en la parte de arriba de la hoja.", s: "Cuando el profesor pide identificar el trabajo antes de entregarlo.", sEn: "When the teacher asks students to label their work before handing it in.", n: "La 'w' de 'write' es muda; se dice 'rait', no 'uu-rait'.", nEn: "The 'w' in 'write' is silent; it's said 'rite', not 'wuh-rite'." },
    "loc-exa14": { e: "Can you give me an example so I understand better?", t: "¿Puede darme un ejemplo para que entienda mejor?", s: "Cuando no comprendes una explicación y pides una muestra concreta.", sEn: "When you don't grasp an explanation and ask for a concrete sample.", n: "'Example' se pronuncia 'ig-ZÁM-pol', con la sílaba fuerte en el medio.", nEn: "'Example' is said 'ig-ZAM-pul', with the stress on the middle syllable." },
    // ===================== At the bar (bar-en) =====================
    "loc-bar01": { e: "Hi there, what can I get you tonight?", t: "Hola, ¿qué le sirvo esta noche?", s: "Cuando atiendes a un cliente que llega a la barra.", sEn: "When you greet a customer who comes up to the bar.", n: "Es más casual que \"What would you like?\", perfecto para un bar.", nEn: "It's more casual than \"What would you like?\", perfect for a bar." },
    "loc-bar02": { e: "Would you like that with ice or without?", t: "¿Lo quiere con hielo o sin hielo?", s: "Cuando preguntas al cliente cómo prefiere su bebida.", sEn: "When you ask the customer how they want their drink.", n: "\"Ice\" se dice \"ais\"; lo contrario es \"no ice\" o \"without ice\".", nEn: "\"Ice\" sounds like \"ais\"; the opposite is \"no ice\" or \"without ice\"." },
    "loc-bar03": { e: "One or two beers, or should I bring a pitcher for the table?", t: "¿Una o dos cervezas, o les traigo una jarra para la mesa?", s: "Cuando un grupo llega al bar y tomas el primer pedido de bebidas.", sEn: "When a group arrives at the bar and you take the first drink order.", n: "Para sonar más natural di 'a couple of beers' cuando quieren dos.", nEn: "To sound more natural, say 'a couple of beers' when they want two." },
    "loc-bar04": { e: "Happy hour is until seven, so the second drink is half price.", t: "La hora feliz es hasta las siete, así que la segunda bebida es a mitad de precio.", s: "Cuando un cliente pregunta por las promociones de bebidas en la tarde.", sEn: "When a customer asks about drink deals in the afternoon.", n: "Se dice 'happy hour', no 'happy hours', aunque dure varias horas.", nEn: "Say 'happy hour', not 'happy hours', even if it lasts several hours." },
    "loc-bar05": { e: "Would you like the cocktail menu, or are you in the mood for a beer?", t: "¿Quiere ver la carta de cócteles, o tiene ganas de una cerveza?", s: "Cuando un cliente se sienta en la barra y aún no decide qué tomar.", sEn: "When a customer sits at the bar and hasn't decided what to drink.", n: "'Cocktail' se pronuncia 'COK-teil', con el acento en la primera sílaba.", nEn: "'Cocktail' is pronounced 'COCK-tayl', with the stress on the first syllable." },
    "loc-bar06": { e: "Anything else, or shall I close out your tab?", t: "¿Algo más, o le cierro la cuenta?", s: "Cuando el cliente parece terminar y revisas si quiere pedir más.", sEn: "When the customer seems finished and you check if they want more.", n: "Más cálido suena 'Can I get you anything else?'.", nEn: "It sounds warmer to say 'Can I get you anything else?'." },
    "loc-bar07": { e: "That's ten thousand, please, and you can pay at the counter.", t: "Son diez mil, por favor, y puede pagar en la caja.", s: "Cuando le dices el total de la cuenta a un cliente en el bar.", sEn: "When you tell a customer the total of their bill at the bar.", n: "Para mayor cortesía agrega 'whenever you're ready' sin presionar.", nEn: "For extra politeness add 'whenever you're ready' to avoid pressure." },
    "loc-bar08": { e: "Cheers, everyone, and welcome to your first night here!", t: "¡Salud a todos, y bienvenidos a su primera noche aquí!", s: "Cuando brindas con un grupo o entregas las bebidas para celebrar.", sEn: "When you toast with a group or hand over drinks to celebrate.", n: "En inglés 'Cheers!' también significa 'gracias' de manera informal.", nEn: "In English 'Cheers!' can also informally mean 'thanks'." },
    "loc-bar09": { e: "Last call is at one, so let me know if you'd like one more.", t: "La última ronda es a la una, así que avíseme si quiere una más.", s: "Cuando el bar está por cerrar y avisas a los clientes que pidan ya.", sEn: "When the bar is about to close and you warn customers to order now.", n: "'Last call' es la frase fija; evita traducir literal como 'last round'.", nEn: "'Last call' is the set phrase; avoid the literal 'last round'." },
    "loc-bar10": { e: "Still or sparkling water? We have both chilled and ready.", t: "¿Agua con o sin gas? Tenemos ambas frías y listas.", s: "Cuando un cliente pide agua y debes saber qué tipo quiere.", sEn: "When a customer asks for water and you need to know which kind.", n: "'Sparkling' es 'con gas' y 'still' es 'sin gas'; no uses 'with gas'.", nEn: "'Sparkling' means fizzy and 'still' means flat; never say 'with gas'." },
    "loc-bar11": { e: "Would you like to see the menu, or do you know what you'd like?", t: "¿Quiere ver el menú, o ya sabe qué desea?", s: "Al atender a alguien que acaba de sentarse en la barra.", sEn: "When serving someone who just sat down at the bar.", n: "'Would you like' es más cortés que 'Do you want' con clientes.", nEn: "'Would you like' is more polite than 'Do you want' with customers." },
    "loc-bar12": { e: "I recommend our house cocktail, it's the most popular one.", t: "Le recomiendo nuestro cóctel de la casa, es el más pedido.", s: "Cuando un cliente no sabe qué pedir y quiere una sugerencia.", sEn: "When a customer is unsure and wants a suggestion.", n: "'cocktail' se pronuncia 'COC-teil', con la 'a' como en 'tail'; no lo digas como el español 'cóctel'.", nEn: "'Cocktail' sounds like 'COCK-tail'; mind the English stress." },
    "loc-bar13": { e: "Would you like to open a tab, or are you paying as you go?", t: "¿Le abro una cuenta, o paga cada consumo?", s: "Cuando un cliente planea quedarse y pedir varias bebidas.", sEn: "When a customer plans to stay and order several drinks.", n: "'a tab' es la cuenta abierta en el bar; no confundas con 'bill'.", nEn: "'A tab' is a running bar account, different from the final 'bill'." },
    "loc-bar14": { e: "I'll bring it right over, just give me a second.", t: "Enseguida se lo traigo, deme un segundo.", s: "Justo después de que un cliente hace su pedido en el bar.", sEn: "Right after a customer places their order at the bar.", n: "'right over' suena más natural que 'right now' al llevar algo.", nEn: "'Right over' sounds more natural than 'right now' when bringing something." },
    // ===================== Shopping (compras-en) =====================
    "loc-com01": { e: "Excuse me, how much is this? I don't see a price tag.", t: "Disculpe, ¿cuánto cuesta esto? No veo la etiqueta de precio.", s: "Cuando estás comprando y un artículo no tiene precio marcado.", sEn: "When you're shopping and an item has no marked price.", n: "También puedes decir 'How much does this cost?' con el mismo sentido.", nEn: "You can also say 'How much does this cost?' with the same meaning." },
    "loc-com02": { e: "Do you have a bigger size? This one is a little tight on me.", t: "¿Tienen una talla más grande? Esta me queda un poco ajustada.", s: "Cuando te pruebas una prenda y necesitas una talla mayor.", sEn: "When you try on clothing and need a larger size.", n: "Di 'a bigger size', no 'a more big size', que es incorrecto.", nEn: "Say 'a bigger size', not 'a more big size', which is wrong." },
    "loc-com03": { e: "I'm just looking, thanks, but I'll ask if I need anything.", t: "Solo estoy mirando, gracias, pero pregunto si necesito algo.", s: "Cuando un vendedor se acerca y aún no quieres comprar nada.", sEn: "When a salesperson approaches and you don't want to buy yet.", n: "Es una frase muy cortés para que no te sigan; suena natural y amable.", nEn: "It's a very polite way to ask for space; it sounds natural and kind." },
    "loc-com04": { e: "Can I try it on? Where's the fitting room?", t: "¿Puedo probármelo? ¿Dónde está el probador?", s: "Cuando quieres probarte ropa antes de decidir comprarla.", sEn: "When you want to try on clothes before deciding to buy.", n: "Con ropa di 'try it on' con 'on' al final; 'try it' sin 'on' suena incompleto al hablar de prendas.", nEn: "With clothes say 'try it on' with the particle 'on'; 'try it' without 'on' sounds incomplete for garments." },
    "loc-com05": { e: "Do you take card, or is it cash only?", t: "¿Aceptan tarjeta, o es solo efectivo?", s: "Cuando vas a pagar y no sabes qué métodos acepta el negocio.", sEn: "When you're about to pay and don't know which methods they accept.", n: "'Take card' es coloquial; 'accept cards' es más formal.", nEn: "'Take card' is casual; 'accept cards' is more formal." },
    "loc-com06": { e: "Can I have a bag, please? These won't fit in my pocket.", t: "¿Me da una bolsa, por favor? Esto no cabe en mi bolsillo.", s: "Cuando terminas de pagar y necesitas una bolsa para llevar tus cosas.", sEn: "When you finish paying and need a bag to carry your things.", n: "Más suave aún suena 'Could I get a bag, please?'.", nEn: "It sounds even softer to say 'Could I get a bag, please?'." },
    "loc-com07": { e: "Is there a discount if I buy two of them?", t: "¿Hay descuento si compro dos?", s: "Cuando regateas o preguntas por una rebaja al comprar varios.", sEn: "When you bargain or ask for a deal when buying several.", n: "Suena natural decir 'Any discount?' de forma breve e informal.", nEn: "It sounds natural to say 'Any discount?' briefly and informally." },
    "loc-com08": { e: "It's perfect, I'll take it. Can you ring it up?", t: "Es perfecto, me lo llevo. ¿Me lo cobra?", s: "Cuando decides comprar algo y se lo dices al vendedor.", sEn: "When you decide to buy something and tell the salesperson.", n: "'I'll take it' es la frase fija para comprar; no digas 'I take it'.", nEn: "'I'll take it' is the set phrase for buying; don't say 'I take it'." },
    "loc-com09": { e: "Where's the fitting room? I'd like to try these on.", t: "¿Dónde está el probador? Quiero probarme estas.", s: "Cuando tienes ropa en la mano y buscas dónde probártela.", sEn: "When you're holding clothes and look for somewhere to try them on.", n: "También se dice 'dressing room'; ambas son correctas y comunes.", nEn: "You can also say 'dressing room'; both are correct and common." },
    "loc-com10": { e: "Do you have another color? I love it, but not in red.", t: "¿Tienen otro color? Me encanta, pero no en rojo.", s: "Cuando te gusta un producto pero quieres verlo en otro color.", sEn: "When you like a product but want to see it in a different color.", n: "En inglés de EE. UU. se escribe 'color' (sin 'u'); en inglés británico es 'colour'.", nEn: "In US spelling it's 'color'; in UK spelling it's 'colour'." },
    "loc-com11": { e: "Excuse me, where do I pay for this?", t: "Disculpe, ¿dónde pago esto?", s: "Cuando ya elegiste algo en una tienda y buscas la caja.", sEn: "When you've picked something in a shop and are looking for the till.", n: "También puedes preguntar \"Where's the checkout?\" o \"Where's the cashier?\".", nEn: "You can also ask \"Where's the checkout?\" or \"Where's the cashier?\"." },
    "loc-com12": { e: "Does it have a warranty in case something breaks?", t: "¿Tiene garantía por si algo se daña?", s: "Cuando vas a comprar un aparato y quieres saber si está cubierto.", sEn: "When buying a device and you want to know if it's covered.", n: "En inglés británico también se usa \"guarantee\"; \"warranty\" es lo más común.", nEn: "British English also uses \"guarantee\"; \"warranty\" is the most common term." },
    "loc-com13": { e: "If it doesn't fit, can I return it?", t: "Si no me queda, ¿puedo devolverlo?", s: "Cuando compras ropa o un producto y preguntas por la política de devolución.", sEn: "When buying clothes or a product and asking about the return policy.", n: "Cuidado: \"return\" es devolver; \"refund\" es el reembolso del dinero.", nEn: "Careful: \"return\" is to give it back; \"refund\" is getting your money back." },
    "loc-com14": { e: "Is it on sale, or is that the full price?", t: "¿Está en oferta, o ese es el precio completo?", s: "Cuando quieres saber si un artículo tiene descuento antes de comprarlo.", sEn: "When you want to know if an item is discounted before buying.", n: "\"On sale\" es en oferta; \"for sale\" significa que está a la venta, no rebajado.", nEn: "\"On sale\" means discounted; \"for sale\" just means it's available to buy." },
    // ===================== Health & pharmacy (salud-en) =====================
    "loc-med01": { e: "I feel sick, I think I need to lie down for a while.", t: "Me siento mal, creo que necesito acostarme un rato.", s: "Cuando le dices a alguien que no te sientes bien físicamente.", sEn: "When you tell someone you're not feeling physically well.", n: "'Sick' es enfermo en general; en EE. UU. también puede ser con náuseas.", nEn: "'Sick' means ill in general; in the US it can also mean nauseous." },
    "loc-med02": { e: "I have a headache, do you have something for it?", t: "Me duele la cabeza, ¿tiene algo para eso?", s: "Cuando pides un analgésico en la farmacia o le avisas a un compañero.", sEn: "When you ask for a painkiller at the pharmacy or tell a coworker.", n: "Se usa 'have a headache', no 'have headache'; el artículo es necesario.", nEn: "Say 'have a headache', not 'have headache'; the article is needed." },
    "loc-med03": { e: "Do you have something for a cough that won't make me drowsy?", t: "¿Tiene algo para la tos que no me dé sueño?", s: "En la farmacia, cuando le pides al farmacéutico un remedio para la tos.", sEn: "At the pharmacy, when you ask the pharmacist for a cough remedy.", n: "Para algo más suave, di \"Could you recommend something for a cough?\".", nEn: "For a softer tone, say \"Could you recommend something for a cough?\"." },
    "loc-med04": { e: "I need a doctor, my daughter has a high fever.", t: "Necesito un médico, mi hija tiene fiebre alta.", s: "Cuando alguien se enferma y pides atención médica urgente.", sEn: "When someone falls ill and you ask for urgent medical care.", n: "En una emergencia real, di \"I need a doctor right now\" para que entiendan la urgencia.", nEn: "In a real emergency, say \"I need a doctor right now\" so they grasp the urgency." },
    "loc-med05": { e: "Please be careful, I'm allergic to penicillin.", t: "Por favor tenga cuidado, soy alérgico a la penicilina.", s: "Cuando te atiende un médico o farmacéutico y debes avisar de tu alergia.", sEn: "When a doctor or pharmacist treats you and you must warn them of your allergy.", n: "Pronuncia \"allergic\" como \"a-LER-yik\", con la g suave, no como en español.", nEn: "Pronounce \"allergic\" as \"uh-LUR-jik\", with a soft g, not the Spanish g." },
    "loc-med06": { e: "Excuse me, where is the pharmacy? My friend isn't feeling well.", t: "Disculpe, ¿dónde está la farmacia? Mi amigo no se siente bien.", s: "Cuando buscas una farmacia en la calle y le preguntas a alguien.", sEn: "When you're looking for a pharmacy on the street and ask someone.", n: "En inglés británico también se dice \"chemist's\" para farmacia.", nEn: "In British English, a pharmacy is also called a \"chemist's\"." },
    "loc-med07": { e: "And how often do I take it, with or without food?", t: "¿Y cada cuánto lo tomo, con o sin comida?", s: "Cuando recibes un medicamento y preguntas por la dosis.", sEn: "When you receive a medication and ask about the dosage.", n: "También puedes preguntar \"How many times a day?\" si es más fácil para ti.", nEn: "You can also ask \"How many times a day?\" if that's easier for you." },
    "loc-med08": { e: "Someone fainted, please call an ambulance!", t: "¡Alguien se desmayó, por favor llamen a una ambulancia!", s: "En una emergencia, cuando necesitas que alguien pida una ambulancia.", sEn: "In an emergency, when you need someone to call an ambulance.", n: "Pronuncia \"ambulance\" como \"AM-byu-lans\", no \"am-bu-LAN-se\".", nEn: "Pronounce \"ambulance\" as \"AM-byuh-lance\", not \"am-boo-LAHN-say\"." },
    "loc-med09": { e: "Take one pill every eight hours with a glass of water.", t: "Tome una pastilla cada ocho horas con un vaso de agua.", s: "Cuando explicas a un cliente o paciente cómo tomar su medicamento.", sEn: "When you explain to a customer or patient how to take their medicine.", n: "\"Pill\" es la pastilla; \"tablet\" o \"capsule\" sirven según la forma.", nEn: "\"Pill\" works for any tablet; use \"tablet\" or \"capsule\" depending on the shape." },
    "loc-med10": { e: "Does it need a prescription, or can I just buy it here?", t: "¿Necesita receta, o lo puedo comprar aquí no más?", s: "En la farmacia, cuando preguntas si requieres receta para un medicamento.", sEn: "At the pharmacy, when you ask if a medicine requires a prescription.", n: "\"Prescription\" se dice \"pre-SKRIP-shun\"; cuidado con no decir \"perscription\".", nEn: "\"Prescription\" is said \"pre-SKRIP-shun\"; avoid saying \"perscription\"." },
    "loc-med11": { e: "I have a stomachache and I feel a bit nauseous.", t: "Me duele el estómago y tengo un poco de náuseas.", s: "Cuando le describes tu malestar al farmacéutico o al médico.", sEn: "When describing your discomfort to the pharmacist or doctor.", n: "Pronuncia \"stomach\" como \"STÓ-mak\" pero con la 'o' relajada (casi 'STÁ-mak'); la \"ch\" suena como \"k\".", nEn: "Pronounce \"stomach\" as \"STUH-muk\"; the \"ch\" sounds like \"k\" and the second syllable is unstressed." },
    "loc-med12": { e: "I have a fever and I've been feeling cold all day.", t: "Tengo fiebre y he tenido frío todo el día.", s: "Cuando explicas tus síntomas en la farmacia o al pedir ayuda.", sEn: "When explaining your symptoms at the pharmacy or asking for help.", n: "Se dice \"I have a fever\", no \"I am fever\"; usa siempre \"have\".", nEn: "Say \"I have a fever\", never \"I am fever\"; always use \"have\"." },
    "loc-med13": { e: "Do you have something for pain that I don't need a prescription for?", t: "¿Tiene algo para el dolor que no necesite receta?", s: "Cuando pides un analgésico de venta libre en la farmacia.", sEn: "When asking for an over-the-counter painkiller at the pharmacy.", n: "Puedes ser específico: \"something for a headache / a toothache / back pain\".", nEn: "You can be specific: \"something for a headache / a toothache / back pain\"." },
    "loc-med14": { e: "I'm not feeling well; I just need to rest for a while.", t: "No me siento bien; solo necesito descansar un rato.", s: "Cuando le avisas a alguien que necesitas parar y recuperarte.", sEn: "When telling someone you need to stop and recover.", n: "\"Rest\" es descansar; \"relax\" es relajarse, no significan exactamente lo mismo.", nEn: "\"Rest\" means to recover; \"relax\" means to unwind, they aren't quite the same." },
    // ===================== Bank & money (dinero-en) =====================
    "loc-din01": { e: "Excuse me, where is an ATM around here?", t: "Disculpe, ¿dónde hay un cajero por aquí?", s: "Cuando necesitas sacar efectivo y preguntas por un cajero automático.", sEn: "When you need cash and ask where to find an ATM.", n: "Di las letras \"A-T-M\" por separado; en inglés británico también es \"cashpoint\".", nEn: "Say the letters \"A-T-M\" separately; in British English it's also a \"cashpoint\"." },
    "loc-din02": { e: "Before I withdraw, is there a fee for using this ATM?", t: "Antes de retirar, ¿cobran comisión por usar este cajero?", s: "Cuando vas a sacar dinero y quieres saber si hay cargo extra.", sEn: "When you're about to take out money and want to know about extra charges.", n: "\"Fee\" es el cargo; \"commission\" suena más a inversiones, evítalo aquí.", nEn: "\"Fee\" means the charge; \"commission\" sounds more like investments, so avoid it here." },
    "loc-din03": { e: "Hi, I want to exchange dollars for local currency, please.", t: "Hola, quiero cambiar dólares a moneda local, por favor.", s: "En una casa de cambio, cuando pides cambiar tu dinero.", sEn: "At a currency exchange, when you ask to change your money.", n: "\"Exchange\" se pronuncia \"iks-CHÉINCH\" (la parte final suena como la \"y\" de \"yo\", una j suave); usa \"change money\" si te sale más natural.", nEn: "\"Exchange\" is said \"iks-CHAYNJ\"; use \"change money\" if it feels more natural." },
    "loc-din04": { e: "What's the exchange rate for dollars today?", t: "¿Cuál es la tasa de cambio del dólar hoy?", s: "Cuando quieres cambiar dinero y preguntas a cuánto está la moneda.", sEn: "When you want to change money and ask what the rate is.", n: "Puedes añadir \"...and is the fee included?\" para evitar sorpresas.", nEn: "You can add \"...and is the fee included?\" to avoid surprises." },
    "loc-din05": { e: "Can I pay in cash, or do you only take card?", t: "¿Puedo pagar en efectivo, o solo aceptan tarjeta?", s: "Al pagar, cuando preguntas si aceptan efectivo.", sEn: "When paying, asking whether they accept cash.", n: "\"In cash\" lleva \"in\"; no digas \"pay cash\" sin la preposición en preguntas formales.", nEn: "Use \"in cash\" with \"in\"; don't drop the preposition in more formal questions." },
    "loc-din06": { e: "I'm sorry, the card was declined. Would you like to try another?", t: "Lo siento, la tarjeta fue rechazada. ¿Quiere probar con otra?", s: "Cuando atiendes a un cliente y su tarjeta no pasa el pago.", sEn: "When you serve a customer and their card doesn't go through.", n: "\"Declined\" suena más amable que \"rejected\" al hablar con el cliente.", nEn: "\"Declined\" sounds gentler than \"rejected\" when speaking to a customer." },
    "loc-din07": { e: "Can I have a receipt, please? I need it for work.", t: "¿Me da un recibo, por favor? Lo necesito para el trabajo.", s: "Después de pagar, cuando pides el comprobante.", sEn: "After paying, when you ask for proof of purchase.", n: "\"Receipt\" se pronuncia \"ri-SIIT\"; la p es muda.", nEn: "\"Receipt\" is pronounced \"ri-SEET\"; the p is silent." },
    "loc-din08": { e: "Here you go, keep the change.", t: "Aquí tiene, quédese con el cambio.", s: "Cuando pagas a un taxista o mesero y le dejas la diferencia de propina.", sEn: "When you pay a taxi driver or waiter and leave the difference as a tip.", n: "\"Change\" aquí es el vuelto, no \"return\"; suena generoso y natural.", nEn: "\"Change\" here means the leftover money, not \"return\"; it sounds generous and natural." },
    "loc-din09": { e: "I need an invoice with my company's name on it.", t: "Necesito una factura con el nombre de mi empresa.", s: "Cuando pides una factura formal para gastos de la empresa.", sEn: "When you ask for a formal invoice for company expenses.", n: "\"Invoice\" es la factura formal; \"receipt\" es el simple comprobante.", nEn: "\"Invoice\" is the formal bill; a \"receipt\" is the simple proof of payment." },
    "loc-din10": { e: "Can I pay with my phone? I have Apple Pay.", t: "¿Puedo pagar con el teléfono? Tengo Apple Pay.", s: "Al pagar, cuando preguntas si aceptan pago sin contacto desde el celular.", sEn: "When paying, asking if they accept contactless payment from your phone.", n: "También puedes decir \"Do you take contactless?\" para pagos sin contacto.", nEn: "You can also say \"Do you take contactless?\" for tap-to-pay." },
    "loc-din11": { e: "This ATM is out of cash; let's try the one across the street.", t: "Este cajero no tiene billetes; probemos el de enfrente.", s: "Cuando el cajero no entrega dinero y le explicas la situación al cliente.", sEn: "When the ATM has no money and you explain the situation to a customer.", n: "\"ATM\" se pronuncia letra por letra: \"ei-ti-em\".", nEn: "\"ATM\" is pronounced letter by letter: \"ay-tee-em\"." },
    "loc-din12": { e: "Can I split the payment between two cards?", t: "¿Puedo dividir el pago entre dos tarjetas?", s: "Cuando quieres pagar una cuenta usando más de un método o tarjeta.", sEn: "When you want to pay a bill using more than one method or card.", n: "Para repartir la cuenta entre amigos se dice \"split the bill\".", nEn: "To divide a bill among friends, say \"split the bill\"." },
    "loc-din13": { e: "Do you exchange currency here, or only at the bank?", t: "¿Hacen cambio de moneda aquí, o solo en el banco?", s: "Cuando un turista pregunta dónde puede cambiar su dinero.", sEn: "When a tourist asks where they can change their money.", n: "\"Currency\" se pronuncia \"KÉR-ren-si\", con el acento en la primera sílaba.", nEn: "\"Currency\" is pronounced \"KUR-ren-see\", with the stress on the first syllable." },
    "loc-din14": { e: "I need to withdraw cash before the shops close.", t: "Necesito sacar efectivo antes de que cierren las tiendas.", s: "Cuando explicas que vas a un cajero a retirar dinero.", sEn: "When explaining that you're going to an ATM to take out money.", n: "\"Withdraw\" es retirar del cajero; \"take out cash\" es una forma más informal.", nEn: "\"Withdraw\" is to take money from an ATM; \"take out cash\" is a more casual version." },
    // ===================== Customer service (cliente-en) =====================
    "loc-cli01": { e: "Good afternoon, how may I help you today?", t: "Buenas tardes, ¿en qué le puedo ayudar hoy?", s: "Al recibir a un cliente en recepción, tienda o por teléfono.", sEn: "When greeting a customer at a desk, store, or on the phone.", n: "\"How may I help you?\" es más formal que \"How can I help you?\".", nEn: "\"How may I help you?\" is more formal than \"How can I help you?\"." },
    "loc-cli02": { e: "Let me check that for you, one moment please.", t: "Permítame revisarlo, un momento por favor.", s: "Cuando un cliente pregunta algo y necesitas verificar la información.", sEn: "When a customer asks something and you need to verify the information.", n: "Añadir \"for you\" suena más atento y profesional.", nEn: "Adding \"for you\" sounds more attentive and professional." },
    "loc-cli03": { e: "I'm so sorry for the inconvenience, let me sort this out for you right now.", t: "Lamento mucho el inconveniente, permítame resolverlo de inmediato.", s: "Cuando un cliente tuvo un problema y quieres disculparte antes de solucionarlo.", sEn: "When a customer had a problem and you want to apologize before fixing it.", n: "Suena más cálido decir 'I'm sorry for the inconvenience' que un seco 'sorry'.", nEn: "Saying 'I'm sorry for the inconvenience' sounds warmer than a flat 'sorry'." },
    "loc-cli04": { e: "Can I have your order number so I can look into this for you?", t: "¿Me da su número de pedido para poder revisarlo?", s: "Cuando necesitas buscar el pedido de un cliente en el sistema.", sEn: "When you need to find a customer's order in the system.", n: "Más formal: 'Could I have your order number, please?' suena aún más cortés.", nEn: "More formal: 'Could I have your order number, please?' sounds even politer." },
    "loc-cli05": { e: "I'll send you the information by email in just a few minutes.", t: "Le envío la información por correo en unos minutos.", s: "Cuando prometes mandarle datos o detalles a un cliente.", sEn: "When you promise to send a customer details or data.", n: "Especifica el medio: 'by email' o 'by text' para que quede claro.", nEn: "Specify the channel: 'by email' or 'by text' so it's clear." },
    "loc-cli06": { e: "Is there anything else I can help with before we finish?", t: "¿Hay algo más en lo que pueda ayudarle antes de terminar?", s: "Al cerrar una atención, para asegurarte de que el cliente quedó conforme.", sEn: "When wrapping up, to make sure the customer is fully satisfied.", n: "También se dice 'anything else I can do for you?', muy común en servicio.", nEn: "You can also say 'anything else I can do for you?', very common in service." },
    "loc-cli07": { e: "Thank you for your patience while I checked that for you.", t: "Gracias por su paciencia mientras lo revisaba.", s: "Cuando un cliente esperó en línea o en el mostrador mientras resolvías algo.", sEn: "When a customer waited on the line or at the counter while you sorted something out.", n: "Pronuncia 'patience' como 'PEY-shens', no 'pa-TIENS'.", nEn: "Pronounce 'patience' like 'PAY-shuns', not 'pa-TIENS'." },
    "loc-cli08": { e: "Thanks for calling, and have a great day!", t: "Gracias por llamar, ¡que tenga un buen día!", s: "Para despedirte cordialmente de un cliente al final de la atención.", sEn: "To say a warm goodbye to a customer at the end of the interaction.", n: "Por la tarde di 'have a great evening' para sonar más natural.", nEn: "In the evening say 'have a great evening' to sound more natural." },
    "loc-cli09": { e: "I'll transfer your call to the right department now, please stay on the line.", t: "Voy a transferir su llamada al área correcta, por favor no cuelgue.", s: "Cuando otra persona o área debe atender la llamada del cliente.", sEn: "When another person or department needs to handle the customer's call.", n: "En el Reino Unido se dice 'put you through' en lugar de 'transfer'.", nEn: "In the UK people say 'put you through' instead of 'transfer'." },
    "loc-cli10": { e: "Good news, your case has been resolved and everything is back to normal.", t: "Buenas noticias, su caso quedó resuelto y todo está en orden.", s: "Cuando le confirmas a un cliente que su problema ya está solucionado.", sEn: "When you confirm to a customer that their problem is now fixed.", n: "Pronuncia 'resolved' como 'ri-ZOLVD', con la z sonora.", nEn: "Pronounce 'resolved' as 'ri-ZOLVD', with a voiced z." },
    "loc-cli11": { e: "I apologize for the mistake, let me fix it right away.", t: "Le pido una disculpa por el error, permítame corregirlo enseguida.", s: "Cuando hubo un error de tu parte y te disculpas con el cliente.", sEn: "When there was a mistake on your side and you apologize to the customer.", n: "\"I apologize\" es más formal que \"I'm sorry\"; ideal para atención al cliente.", nEn: "\"I apologize\" is more formal than \"I'm sorry\"; great for customer service." },
    "loc-cli12": { e: "Give me one moment while I look that up for you.", t: "Permítame un momento mientras le busco eso.", s: "Cuando necesitas una pausa breve para revisar algo para el cliente.", sEn: "When you need a short pause to check something for the customer.", n: "Más cortés: \"Could you give me one moment, please?\"", nEn: "More polite: \"Could you give me one moment, please?\"" },
    "loc-cli13": { e: "I'll follow up with you by email once the order ships.", t: "Le haré seguimiento por correo en cuanto se despache el pedido.", s: "Cuando un cliente deja un asunto pendiente y quieres asegurarle que lo retomarás.", sEn: "When a customer has an open issue and you want to assure them you'll get back to them.", n: "Suena más profesional decir 'follow up with you' que 'call you again'; el 'follow' se pronuncia 'fólou', sin sonido de 'w' fuerte.", nEn: "'Follow up with you' sounds more professional than 'call you again'; 'follow' is said 'FOL-oh', with a soft ending." },
    "loc-cli14": { e: "I'm here if you need anything, just give me a call.", t: "Quedo a sus órdenes, solo llámeme.", s: "Al cerrar una atención, para que el cliente sepa que puede volver a contactarte.", sEn: "When wrapping up service, to let the customer know they can reach you again.", n: "Variante un poco más formal: 'Please let me know if you need anything else.'", nEn: "A slightly more formal variant: 'Please let me know if you need anything else.'" },
    // ===================== Numbers & dates (numeros-en) =====================
    "loc-num01": { e: "Let's count them together: one, two, three, and there's your change.", t: "Contémoslos juntos: uno, dos, tres, y ahí está su vuelto.", s: "Cuando cuentas en voz alta billetes, artículos o personas frente al cliente.", sEn: "When you count bills, items, or people out loud in front of a customer.", n: "La 'th' de 'three' va con la lengua entre los dientes, no como 't'.", nEn: "The 'th' in 'three' uses the tongue between the teeth, not a plain 't'." },
    "loc-num02": { e: "That'll be ten dollars, please.", t: "Son diez dólares, por favor.", s: "Al decir un precio redondo de diez al cobrar.", sEn: "When stating a round price of ten while charging.", n: "No confundas 'ten' (diez) con 'tan'; la 'e' es corta y clara.", nEn: "Don't mix up 'ten' with 'tan'; the 'e' is short and clear." },
    "loc-num03": { e: "The bus leaves in twenty minutes, so we have a little time.", t: "El bus sale en veinte minutos, así que tenemos un poco de tiempo.", s: "Al indicar una cantidad o un tiempo de veinte a un cliente.", sEn: "When telling a customer a quantity or a time of twenty.", n: "Muchos dicen 'twenny'; tu di 'TWEN-ty' marcando ambas sílabas.", nEn: "Many say 'twenny'; you say 'TWEN-ty' marking both syllables." },
    "loc-num04": { e: "The entrance fee is one hundred per person.", t: "La entrada cuesta cien por persona.", s: "Al dar un precio o número de cien a un cliente o turista.", sEn: "When giving a customer or tourist a price or number of one hundred.", n: "Puedes decir solo 'a hundred'; suena natural y más relajado.", nEn: "You can just say 'a hundred'; it sounds natural and more relaxed." },
    "loc-num05": { e: "The room is one thousand a night, breakfast included.", t: "La habitación cuesta mil por noche, con desayuno incluido.", s: "Al decir un precio de mil, por ejemplo una tarifa o total.", sEn: "When stating a price of one thousand, like a rate or total.", n: "Cuidado: 'thousand' lleva 'th'; no lo digas como 'tausan'.", nEn: "Careful: 'thousand' has a 'th'; don't say it like 'tausan'." },
    "loc-num06": { e: "Your room is the first one on the right.", t: "Su habitación es la primera a la derecha.", s: "Al señalar cuál es el primero en una fila, lista o ubicación.", sEn: "When pointing out which is the first in a row, list, or location.", n: "Para fechas se dice 'the first of May'; 'first' también es '1st'.", nEn: "For dates say 'the first of May'; 'first' is also written '1st'." },
    "loc-num07": { e: "We're closed on Sundays, but we open again on Monday.", t: "Cerramos los domingos, pero abrimos de nuevo el lunes.", s: "Al indicar un día de la semana, como horarios o citas.", sEn: "When stating a day of the week, like hours or appointments.", n: "En inglés los días siempre van con mayúscula: 'Monday'.", nEn: "In English the days are always capitalized: 'Monday'." },
    "loc-num08": { e: "Sorry, what's the date today? I need it for the form.", t: "Disculpe, ¿qué fecha es hoy? La necesito para el formulario.", s: "Cuando necesitas saber o confirmar la fecha actual, por ejemplo al registrar.", sEn: "When you need to know or confirm today's date, for example when checking in.", n: "También puedes preguntar 'what's today's date?', igual de común.", nEn: "You can also ask 'what's today's date?', just as common." },
    "loc-num09": { e: "You can pay half now and half when you check out.", t: "Puede pagar la mitad ahora y la mitad al hacer el check-out.", s: "Al hablar de dividir un pago, una porción o una cantidad por la mitad.", sEn: "When talking about splitting a payment, a portion, or an amount in half.", n: "La 'l' de 'half' es muda: se dice 'haf', no 'jalf'.", nEn: "The 'l' in 'half' is silent: say 'haf', not 'half' with the l." },
    "loc-num10": { e: "How much is it in total, including the drinks?", t: "¿Cuánto es en total, incluyendo las bebidas?", s: "Al preguntar o confirmar la suma final de una cuenta.", sEn: "When asking or confirming the final sum of a bill.", n: "También se usa 'how much is it altogether?', muy natural.", nEn: "You can also use 'how much is it altogether?', very natural." },
    "loc-num11": { e: "That'll be fifty pesos for the two coffees.", t: "Son cincuenta pesos por los dos cafés.", s: "Cuando le dices a un cliente cuánto debe pagar y la cifra incluye el número cincuenta.", sEn: "When you tell a customer the total and the amount involves the number fifty.", n: "Cuidado: \"fifty\" (50) suena distinto a \"fifteen\" (15); en fifty el acento va al inicio (FIF-ty).", nEn: "Careful: \"fifty\" (50) sounds different from \"fifteen\" (15); in fifty the stress is at the start (FIF-ty)." },
    "loc-num12": { e: "The room is on the second floor, room two hundred and four.", t: "La habitación está en el segundo piso, cuarto doscientos cuatro.", s: "Cuando indicas a un huésped el número de su habitación o una cantidad alrededor de doscientos.", sEn: "When you give a guest their room number or an amount around two hundred.", n: "En inglés americano puedes decir \"two hundred four\", pero \"two hundred and four\" también es correcto y común.", nEn: "In American English you can say \"two hundred four\", but \"two hundred and four\" is also correct and common." },
    "loc-num13": { e: "Your taxi will pick you up at half past three.", t: "Su taxi lo recogerá a las tres y media.", s: "Cuando confirmas una hora exacta para un servicio, tour o reserva.", sEn: "When you confirm an exact time for a service, tour, or booking.", n: "También es muy común decir \"three thirty\", que suena más casual y rápido.", nEn: "It's also very common to say \"three thirty\", which sounds more casual and quick." },
    "loc-num14": { e: "Your reservation is for May fifteenth, is that right?", t: "Su reserva es para el quince de mayo, ¿es correcto?", s: "Cuando confirmas una fecha de reserva, viaje o cita con un cliente.", sEn: "When you confirm a booking, trip, or appointment date with a customer.", n: "En inglés se dice el mes antes del día: \"May fifteenth\", no \"fifteen May\".", nEn: "In English you say the month before the day: \"May fifteenth\", not \"fifteen May\"." },
    // ===================== At the beach (playa-en) =====================
    "loc-pla01": { e: "Would you like to rent a chair for the afternoon? It's very comfortable.", t: "¿Le gustaría rentar una silla por la tarde? Es muy cómoda.", s: "Cuando ofreces sillas de playa a un turista que llega a la orilla.", sEn: "When you offer beach chairs to a tourist arriving at the shore.", n: "En inglés británico es más común 'hire' que 'rent' para alquilar.", nEn: "In British English 'hire' is more common than 'rent' for renting." },
    "loc-pla02": { e: "Would you like an umbrella? The sun is really strong right now.", t: "¿Quiere una sombrilla? El sol está muy fuerte ahorita.", s: "Cuando ofreces una sombrilla a un cliente bajo el sol en la playa.", sEn: "When you offer an umbrella to a customer under the sun at the beach.", n: "Pronuncia 'umbrella' como 'om-BRE-la', con el acento en el medio.", nEn: "Pronounce 'umbrella' as 'om-BREL-uh', with the stress in the middle." },
    "loc-pla03": { e: "Watch out for the waves, they can knock you over near the rocks.", t: "Cuidado con las olas, lo pueden tumbar cerca de las rocas.", s: "Cuando un turista entra al mar y quieres advertirle que el oleaje está fuerte.", sEn: "When a tourist walks into the sea and you want to warn them the surf is strong.", n: "También puedes decir \"Be careful with the waves\", pero \"watch out\" suena más natural como aviso rápido.", nEn: "You can also say \"Be careful with the waves\", but \"watch out\" sounds more natural as a quick warning." },
    "loc-pla04": { e: "The sun is strong today, so don't forget to put on sunscreen.", t: "El sol está fuerte hoy, así que no olvides ponerte protector solar.", s: "Cuando un cliente está en la playa al mediodía y quieres recomendarle protegerse.", sEn: "When a guest is at the beach at midday and you want to suggest they protect themselves.", n: "Di \"strong\" sin agregar una 'e' al inicio: es \"strong\", no \"estrong\".", nEn: "Say \"strong\" without adding an 'e' at the start that Spanish speakers tend to put before s+consonant." },
    "loc-pla05": { e: "Can I offer you a massage right here under the umbrella?", t: "¿Le puedo ofrecer un masaje aquí mismo bajo la sombrilla?", s: "Cuando vendes servicios en la playa y te acercas a ofrecer un masaje a un turista que descansa.", sEn: "When you sell beach services and approach a resting tourist to offer a massage.", n: "\"Can I offer you...?\" es muy cortés para vender sin presionar; evita \"Do you want a massage?\" que suena brusco.", nEn: "\"Can I offer you...?\" is polite for selling without pressure; avoid the blunt \"Do you want a massage?\"" },
    "loc-pla06": { e: "A cold coconut? It's really refreshing in this heat.", t: "¿Un coco frío? Es muy refrescante con este calor.", s: "Cuando vendes cocos en la playa y le ofreces uno a alguien que pasa caminando.", sEn: "When you sell coconuts on the beach and offer one to someone walking by.", n: "Pronuncia \"coconut\" como \"CO-co-nut\", con el acento en la primera sílaba.", nEn: "Stress \"coconut\" on the first syllable: \"CO-co-nut\"." },
    "loc-pla07": { e: "Please don't leave your things unattended; the beach gets busy.", t: "Por favor no deje sus cosas solas; la playa se llena mucho.", s: "Cuando avisas a un turista que va a meterse al mar y deja sus pertenencias en la arena.", sEn: "When you warn a tourist heading into the water who is leaving belongings on the sand.", n: "\"Unattended\" es la palabra exacta para \"sin vigilancia\"; agregar \"please\" lo hace más amable.", nEn: "\"Unattended\" is the precise word for \"with no one watching\"; adding \"please\" softens it." },
    "loc-pla08": { e: "The boat leaves in ten minutes, so please make your way to the dock.", t: "El bote sale en diez minutos, así que por favor diríjanse al muelle.", s: "Cuando avisas a los pasajeros que el bote del tour está por zarpar.", sEn: "When you let passengers know the tour boat is about to depart.", n: "\"Leaves\" en presente simple sirve para horarios fijos; también vale \"is leaving\" para algo inminente.", nEn: "Use \"leaves\" (simple present) for schedules; \"is leaving\" also works for something imminent." },
    "loc-pla09": { e: "Shall I watch your things while you go for a swim?", t: "¿Le cuido sus cosas mientras se da un chapuzón?", s: "Cuando un cliente en la playa quiere meterse al mar y deja sus pertenencias en la silla.", sEn: "When a beach customer wants to go in the water and is leaving their belongings on the chair.", n: "\"Shall I\" suena más formal y educado que \"Should I\" para ofrecer un servicio.", nEn: "\"Shall I\" sounds more formal and polite than \"Should I\" when offering a service." },
    "loc-pla10": { e: "Sunscreen helps a lot, especially around noon when the sun is strongest.", t: "El protector solar ayuda mucho, sobre todo al mediodía cuando el sol está más fuerte.", s: "Cuando aconsejas a un turista que se está poniendo rojo bajo el sol.", sEn: "When you advise a tourist who is getting sunburned in the sun.", n: "\"Sunscreen\" y \"sunblock\" son intercambiables; evita decir \"solar protector\" (calco del español).", nEn: "\"Sunscreen\" and \"sunblock\" are interchangeable; avoid saying \"solar protector\" (a Spanish calque)." },
    "loc-pla11": { e: "Would you like coconut water? It's nice and cold.", t: "¿Quiere agua de coco? Está bien fría.", s: "Cuando ofreces bebidas a los clientes que toman sol en la playa.", sEn: "When you offer drinks to customers sunbathing on the beach.", n: "\"Would you like...?\" es la forma más cortés de ofrecer algo, mejor que \"Do you want...?\".", nEn: "\"Would you like...?\" is the most polite way to offer something, better than \"Do you want...?\"." },
    "loc-pla12": { e: "The tide is coming in, so let's move your chairs back a bit.", t: "La marea está subiendo, así que movamos sus sillas un poco hacia atrás.", s: "Cuando el mar empieza a acercarse y avisas a los clientes en la orilla.", sEn: "When the sea starts moving up and you warn customers near the shore.", n: "Lo contrario es \"the tide is going out\" (la marea está bajando).", nEn: "The opposite is \"the tide is going out\" (la marea está bajando)." },
    "loc-pla13": { e: "I offer fresh fruit if you'd like a snack on the beach.", t: "Ofrezco frutas frescas por si quiere algo para picar en la playa.", s: "Cuando eres vendedor ambulante y ofreces fruta a la gente en la arena.", sEn: "When you're a beach vendor offering fruit to people on the sand.", n: "\"Fruit\" suele ser incontable: di \"fresh fruit\", no \"fresh fruits\".", nEn: "\"Fruit\" is usually uncountable: say \"fresh fruit,\" not \"fresh fruits.\"" },
    "loc-pla14": { e: "Here's your change, and thank you so much.", t: "Aquí tiene su vuelto, y muchas gracias.", s: "Cuando le devuelves el dinero sobrante a un cliente después de un pago.", sEn: "When you give back the leftover money to a customer after a payment.", n: "En inglés \"change\" es incontable; nunca digas \"a change\" para referirte al vuelto.", nEn: "In English \"change\" is uncountable; never say \"a change\" to mean the money returned." },
    // ===================== Public transport (transporte-en) =====================
    "loc-tra01": { e: "Excuse me, does this bus go downtown?", t: "Disculpe, ¿este bus va al centro?", s: "Cuando estás en la parada y le preguntas al conductor si el bus llega al centro.", sEn: "When you are at the stop and ask the driver if the bus reaches the center.", n: "En inglés \"downtown\" es \"el centro\"; agregar \"Excuse me\" al inicio suena más educado.", nEn: "\"Downtown\" means the city center; starting with \"Excuse me\" sounds more polite." },
    "loc-tra02": { e: "How much is the fare to the city center?", t: "¿Cuánto cuesta el pasaje al centro de la ciudad?", s: "Cuando subes al bus o taxi y quieres saber el precio del pasaje.", sEn: "When you board a bus or taxi and want to know the ticket price.", n: "\"Fare\" es el precio del transporte; no confundas con \"fee\" (cargo) ni \"fair\" (justo/feria).", nEn: "\"Fare\" is the transport price; don't confuse it with \"fee\" or \"fair\"." },
    "loc-tra03": { e: "Could you tell me where I get off for the museum?", t: "¿Me podría decir dónde me bajo para el museo?", s: "Cuando vas en el bus y no sabes en qué parada bajarte para tu destino.", sEn: "When you are on the bus and don't know which stop to get off at.", n: "\"Get off\" es bajarse de un bus o tren; para un carro pequeño se usa \"get out\".", nEn: "\"Get off\" is for buses and trains; for a small car you say \"get out\"." },
    "loc-tra04": { e: "Next stop, please, I'm getting off here.", t: "La próxima parada, por favor, me bajo aquí.", s: "Cuando le avisas al conductor que quieres bajarte en la siguiente parada.", sEn: "When you signal the driver that you want off at the next stop.", n: "Un \"please\" al final lo hace cortés; también puedes decir \"This is my stop\".", nEn: "Adding \"please\" keeps it polite; you can also say \"This is my stop\"." },
    "loc-tra05": { e: "I just missed it, what time is the next one?", t: "Acabo de perderlo, ¿a qué hora sale el próximo?", s: "Cuando se te fue el bus o el tren y preguntas cuándo viene el siguiente.", sEn: "When you missed the bus or train and ask when the next comes.", n: "\"The next one\" evita repetir \"bus\"; \"one\" reemplaza el sustantivo ya mencionado.", nEn: "\"The next one\" avoids repeating \"bus\"; \"one\" stands in for the noun already mentioned." },
    "loc-tra06": { e: "Do you have change for a twenty? I only have a big bill.", t: "¿Tiene cambio de veinte? Solo tengo un billete grande.", s: "Cuando vas a pagar el pasaje y necesitas que te cambien un billete grande.", sEn: "When you pay the fare and need a big bill broken into smaller money.", n: "\"Change\" aquí significa sencillo o vuelto; no lleva 's' aunque sean varias monedas.", nEn: "\"Change\" means coins or smaller money here, and never takes an 's'." },
    "loc-tra07": { e: "I'm going to the airport, could you take me there?", t: "Voy al aeropuerto, ¿me podría llevar?", s: "Cuando paras un taxi o subes al bus y dices tu destino.", sEn: "When you flag a taxi or board a bus and state your destination.", n: "\"I'm going to\" es para planes en curso; di \"airport\" con el acento en \"AIR\".", nEn: "Use \"I'm going to\" for current plans; stress \"airport\" on \"AIR\"." },
    "loc-tra08": { e: "Is it far on foot, or should I take a taxi?", t: "¿Está muy lejos a pie, o mejor tomo un taxi?", s: "Cuando preguntas si conviene caminar al lugar o tomar transporte.", sEn: "When you ask whether to walk to the place or take a ride.", n: "\"On foot\" significa caminando; no digas \"by foot\", que es un error común.", nEn: "\"On foot\" means walking; avoid the common mistake \"by foot\"." },
    "loc-tra09": { e: "How often does the bus come on Sundays?", t: "¿Cada cuánto pasa el bus los domingos?", s: "Cuando esperas en la parada y quieres saber la frecuencia del bus.", sEn: "When you're waiting at the stop and want to know how often the bus runs.", n: "Para horarios fijos puedes decir \"What time does the bus come?\" en vez de \"how often\".", nEn: "For a fixed timetable, ask \"What time does the bus come?\" instead of \"how often\"." },
    "loc-tra10": { e: "Excuse me, does it stop at the market?", t: "Disculpe, ¿para en el mercado?", s: "Cuando subes a un bus y quieres confirmar que pasa por tu parada.", sEn: "When you get on a bus and want to confirm it goes to your stop.", n: "El \"stop\" suena \"stáp\"; no agregues una \"e\" al inicio como en español.", nEn: "\"Stop\" sounds like \"stahp\"; don't add an \"e\" sound at the start." },
    "loc-tra11": { e: "I need a taxi to the airport, my flight is at noon.", t: "Necesito un taxi al aeropuerto, mi vuelo es al mediodía.", s: "Cuando pides en recepción o por teléfono un taxi para llegar al aeropuerto.", sEn: "When you ask at reception or by phone for a taxi to the airport.", n: "Más cortés: \"Could I get a taxi to the airport, please?\"", nEn: "More polite: \"Could I get a taxi to the airport, please?\"" },
    "loc-tra12": { e: "Excuse me, where is the station? I think I'm lost.", t: "Disculpe, ¿dónde está la estación? Creo que estoy perdido.", s: "Cuando le preguntas a alguien en la calle cómo llegar a la estación.", sEn: "When you ask someone on the street how to get to the station.", n: "Especifica si hace falta: \"the bus station\" o \"the train station\".", nEn: "Specify if needed: \"the bus station\" or \"the train station\"." },
    "loc-tra13": { e: "The metro is faster than the bus at this hour.", t: "El metro es más rápido que el bus a esta hora.", s: "Cuando le recomiendas a alguien la mejor forma de moverse por la ciudad.", sEn: "When you suggest the best way to get around the city.", n: "En inglés británico se dice \"the underground\" o \"the tube\" en vez de \"the metro\".", nEn: "In British English people say \"the underground\" or \"the tube\" instead of \"the metro\"." },
    "loc-tra14": { e: "I bought a ticket online, do I still need to validate it?", t: "Compré un tiquete en línea, ¿igual tengo que validarlo?", s: "Cuando ya tienes tu boleto y preguntas qué hacer al subir.", sEn: "When you already have your ticket and ask what to do when boarding.", n: "\"Bought\" suena \"bot\"; la \"gh\" es muda en esta palabra.", nEn: "\"Bought\" sounds like \"bot\"; the \"gh\" is silent here." },
    // ===================== In the meeting (reunion-en) =====================
    "loc-reu01": { e: "Okay everyone, let's get started, we have a lot to cover.", t: "Bien a todos, empecemos, tenemos mucho que ver.", s: "Cuando abres una reunión y quieres que el equipo arranque.", sEn: "When you open a meeting and want the team to begin.", n: "\"Let's get started\" es más cálido que \"Let's start\"; perfecto para reuniones.", nEn: "\"Let's get started\" sounds warmer than \"Let's start\"; great for meetings." },
    "loc-reu02": { e: "Can you see my screen, or should I share it again?", t: "¿Pueden ver mi pantalla, o la comparto de nuevo?", s: "Cuando compartes pantalla en una videollamada y quieres confirmar que se ve.", sEn: "When you share your screen on a call and want to confirm it's visible.", n: "En llamadas se dice \"share my screen\"; \"screen\" rima con \"green\", con e larga.", nEn: "On calls say \"share my screen\"; \"screen\" rhymes with \"green\", long e sound." },
    "loc-reu03": { e: "Sorry, you cut out for a second, could you say that again?", t: "Perdón, se cortó un momento, ¿podría repetir eso?", s: "Cuando en una videollamada el audio del otro se entrecortó y no entendiste.", sEn: "When someone's audio froze on a video call and you missed it.", n: "\"You cut out\" es la frase exacta para audio entrecortado; no digas \"you cut\".", nEn: "\"You cut out\" is the set phrase for choppy audio; \"you cut\" doesn't mean this." },
    "loc-reu04": { e: "Could you repeat that? I didn't quite catch the last part.", t: "¿Podría repetir eso? No alcancé a entender la última parte.", s: "Cuando no entendiste algo en la reunión y pides que lo repitan.", sEn: "When you missed something in the meeting and ask for a repeat.", n: "\"Could you\" es más cortés que \"Can you\"; agregar el motivo suena natural y amable.", nEn: "\"Could you\" is more polite than \"Can you\"; adding the reason sounds natural and kind." },
    "loc-reu05": { e: "I agree with that, I think it's the best option for the team.", t: "Estoy de acuerdo con eso, creo que es la mejor opción para el equipo.", s: "Cuando apoyas una idea o propuesta que alguien acaba de plantear en la reunión.", sEn: "When you support an idea someone just raised in the meeting.", n: "\"Agree\" ya es el verbo; no digas \"I am agree\", eso es un error muy común.", nEn: "\"Agree\" is already the verb; never say \"I am agree\", a very common mistake." },
    "loc-reu06": { e: "Let's leave it for later and move on to the budget.", t: "Dejémoslo para después y pasemos al presupuesto.", s: "Cuando un tema se está alargando y prefieres posponerlo en la reunión.", sEn: "When a topic is dragging and you choose to postpone it in the meeting.", n: "Una variante común es \"Let's table that for now\" en reuniones formales.", nEn: "A common variant in formal meetings is \"Let's table that for now\"." },
    "loc-reu07": { e: "That covers the agenda. Any questions before we wrap up?", t: "Con eso cubrimos la agenda. ¿Alguna pregunta antes de terminar?", s: "Cuando terminas de explicar algo en una reunión y quieres dar espacio para dudas.", sEn: "When you finish explaining something in a meeting and want to open the floor for doubts.", n: "Suena más cálido decir \"Any questions so far?\" para invitar a participar.", nEn: "It sounds warmer to say \"Any questions so far?\" to invite people in." },
    "loc-reu08": { e: "That's all from me. Thanks, everyone, and have a great rest of your day.", t: "Eso es todo de mi parte. Gracias a todos, y que tengan un buen resto del día.", s: "Al cerrar una reunión o llamada para despedirte del grupo.", sEn: "When closing a meeting or call to say goodbye to the group.", n: "Evita \"thanks to everyone\"; lo natural es solo \"thanks, everyone\".", nEn: "Avoid \"thanks to everyone\"; the natural form is just \"thanks, everyone.\"" },
    "loc-reu09": { e: "Can you hear me okay, or should I move closer to the mic?", t: "¿Pueden escucharme bien, o me acerco al micrófono?", s: "Al inicio de una videollamada, para confirmar que tu audio funciona.", sEn: "At the start of a video call, to confirm your audio is working.", n: "No confundas 'hear' (oír) con 'listen' (escuchar con atención); aquí siempre se usa 'hear'.", nEn: "Don't confuse 'hear' (perceive sound) with 'listen' (pay attention); use 'hear' here." },
    "loc-reu10": { e: "Let me share my screen so we can go through this together.", t: "Déjenme compartir la pantalla para que lo veamos juntos.", s: "En una reunión, cuando vas a mostrar un documento o presentación.", sEn: "In a meeting, when you're about to show a document or slides.", n: "Se dice 'share my screen', no 'share the screen of me'; 'screen' suena 'skriin'.", nEn: "Say 'share my screen', not 'share the screen of me'; 'screen' sounds like 'skreen'." },
    "loc-reu11": { e: "Give me a second, I'm pulling up the file.", t: "Permítanme un segundo, estoy abriendo el archivo.", s: "Cuando necesitas una breve pausa para buscar algo durante la reunión.", sEn: "When you need a brief pause to find something during the meeting.", n: "'Give me a second' es informal y amable; en contextos muy formales usa 'One moment, please.'", nEn: "'Give me a second' is casual and friendly; in very formal settings use 'One moment, please.'" },
    "loc-reu12": { e: "Let's move to the next point on the agenda.", t: "Pasemos al siguiente punto de la agenda.", s: "Cuando terminan un tema y quieres avanzar la reunión.", sEn: "When you finish one topic and want to move the meeting forward.", n: "También puedes decir 'Let's move on to...'; ambas son naturales.", nEn: "You can also say 'Let's move on to...'; both are natural." },
    "loc-reu13": { e: "Is that clear, or would you like me to go over it again?", t: "¿Quedó claro, o quieren que lo repase de nuevo?", s: "Después de explicar algo, para comprobar que todos entendieron.", sEn: "After explaining something, to check that everyone understood.", n: "Suena más amable agregar 'or do you have any questions?' al final.", nEn: "It sounds friendlier to add 'or do you have any questions?' at the end." },
    "loc-reu14": { e: "I'll send the summary later today so everyone has the notes.", t: "Les envío el resumen más tarde para que todos tengan las notas.", s: "Al cerrar la reunión, prometiendo enviar un resumen por escrito.", sEn: "When closing the meeting, promising to send a written summary.", n: "Cuida el acento de 'summary'; se dice 'SÁ-ma-ri', no 'su-MA-ri'.", nEn: "Mind the stress in 'summary'; it's 'SUM-uh-ree', not 'su-MA-ree'." },
    // ===================== Useful connectors (conectores-en) =====================
    "loc-con01": { e: "I'd love to help, but the kitchen is already closed.", t: "Me encantaría ayudar, pero la cocina ya está cerrada.", s: "Cuando quieres decir que sí pero hay un obstáculo o una excepción.", sEn: "When you want to agree but add an obstacle or exception.", n: "En inglés se pone una coma antes de \"but\" cuando une dos ideas completas.", nEn: "In English you put a comma before \"but\" when it joins two full ideas." },
    "loc-con02": { e: "We're a little behind because the order was very large.", t: "Estamos un poco atrasados porque el pedido era muy grande.", s: "Cuando das la razón o el motivo de algo.", sEn: "When you give the reason or cause for something.", n: "\"Because\" explica el porqué; \"so\" explica el resultado, no los confundas.", nEn: "\"Because\" gives the reason; \"so\" gives the result, don't mix them up." },
    "loc-con03": { e: "We have rooms with a sea view, and we also offer airport pickup.", t: "Tenemos habitaciones con vista al mar, y también ofrecemos traslado al aeropuerto.", s: "Cuando agregas otra cosa más a lo que acabas de decir.", sEn: "When you add one more thing to what you just said.", n: "\"Also\" suele ir antes del verbo principal: \"we also offer\", no \"we offer also\".", nEn: "\"Also\" usually goes before the main verb: \"we also offer,\" not \"we offer also.\"" },
    "loc-con04": { e: "We have many local dishes, for example the ceviche and the arepa.", t: "Tenemos muchos platos típicos, por ejemplo el ceviche y la arepa.", s: "Cuando das un caso concreto para aclarar lo que dices.", sEn: "When you give a concrete case to make your point clear.", n: "En conversación puedes decir \"like\" en vez de \"for example\" para sonar más casual.", nEn: "In conversation you can say \"like\" instead of \"for example\" to sound more casual." },
    "loc-con05": { e: "The bus was late, so we'll start the tour ten minutes later.", t: "El bus llegó tarde, entonces empezaremos el tour diez minutos más tarde.", s: "Cuando explicas el resultado o la consecuencia de algo.", sEn: "When you state the result or consequence of something.", n: "Aquí \"so\" significa \"por eso\"; al inicio de frase \"So,...\" sirve para retomar el tema.", nEn: "Here \"so\" means \"therefore\"; at the start, \"So,...\" works to resume the topic." },
    "loc-con06": { e: "The price includes breakfast; besides, the wifi is completely free.", t: "El precio incluye desayuno; además, el wifi es completamente gratis.", s: "Cuando añades un punto extra que refuerza lo que dijiste.", sEn: "When you add an extra point that reinforces what you said.", n: "No confundas \"besides\" (además) con \"beside\" (al lado de), son distintos.", nEn: "Don't confuse \"besides\" (in addition) with \"beside\" (next to); they differ." },
    "loc-con07": { e: "The room is small; however, it has a beautiful view of the city.", t: "La habitación es pequeña; sin embargo, tiene una vista hermosa de la ciudad.", s: "Cuando das un contraste o algo positivo que compensa lo negativo.", sEn: "When you give a contrast or a positive that offsets the negative.", n: "\"However\" suele llevar coma después: \"However, ...\"; es más formal que \"but\".", nEn: "\"However\" usually takes a comma after it; it's more formal than \"but.\"" },
    "loc-con08": { e: "We had a few delays, but in the end the guests were very happy.", t: "Tuvimos algunos retrasos, pero al final los huéspedes quedaron muy contentos.", s: "Cuando resumes cómo resultó algo después de varios pasos.", sEn: "When you sum up how something turned out after several steps.", n: "\"In the end\" es el resultado final; \"at the end\" es un lugar o momento, no los mezcles.", nEn: "\"In the end\" is the final outcome; \"at the end\" is a place or moment, don't mix them." },
    "loc-con09": { e: "Your room has a bed and a private bathroom.", t: "Su habitación tiene una cama y un baño privado.", s: "Cuando enlazas dos cosas en una frase para describir o explicar algo.", sEn: "When you link two things in a sentence to describe or explain something.", n: "En habla rápida \"and\" suena casi como \"an\"; no hace falta pronunciar fuerte la d.", nEn: "In fast speech \"and\" sounds almost like \"an\"; you don't need to pronounce the d strongly." },
    "loc-con10": { e: "Would you like still or sparkling water?", t: "¿Quiere agua sin gas o con gas?", s: "Cuando ofreces dos opciones al cliente para que elija una.", sEn: "When you offer the customer two options to choose from.", n: "Para una sola pregunta de dos opciones, sube la voz en la primera y bájala en la segunda.", nEn: "For a single two-option question, raise your voice on the first and lower it on the second." },
    "loc-con11": { e: "First, I'll take your order, then I'll bring some bread.", t: "Primero tomo su orden, luego le traigo pan.", s: "Cuando explicas el orden de los pasos de un proceso o servicio.", sEn: "When you explain the order of steps in a process or service.", n: "\"First\" al inicio de la frase organiza tus ideas y suena profesional; sepárala con una pausa.", nEn: "\"First\" at the start of a sentence organizes your ideas and sounds professional; set it off with a pause." },
    "loc-con12": { e: "We'll visit the museum, and then we'll have lunch.", t: "Visitaremos el museo y luego almorzaremos.", s: "Cuando, como guía o anfitrión, anuncias lo que sigue después de algo.", sEn: "When, as a guide or host, you announce what comes after something.", n: "No confundas \"then\" (luego) con \"than\" (que, en comparaciones); se escriben casi igual.", nEn: "Don't confuse \"then\" (luego) with \"than\" (used in comparisons); they look almost the same." },
    "loc-con13": { e: "The tour is great, although it can get a little hot at noon.", t: "El tour es genial, aunque puede hacer un poco de calor al mediodía.", s: "Cuando admites algo positivo pero agregas una pequeña salvedad o advertencia.", sEn: "When you admit something positive but add a small caveat or warning.", n: "En conversación informal puedes usar \"though\" al final: \"It's great, it gets hot though.\"", nEn: "In casual conversation you can use \"though\" at the end: \"It's great, it gets hot though.\"" },
    "loc-con14": { e: "It's a sweet drink, kind of like lemonade.", t: "Es una bebida dulce, algo así como limonada.", s: "Cuando comparas algo desconocido para el cliente con algo que sí conoce.", sEn: "When you compare something unfamiliar to the customer with something they know.", n: "\"Like\" para comparar es muy útil al describir comida local: \"It tastes like...\".", nEn: "\"Like\" for comparing is very useful when describing local food: \"It tastes like...\"." },
    // ===================== Complaints & apologies (quejas-en) =====================
    "loc-que01": { e: "I'm very sorry about the wait; let me bring your food right now.", t: "Lamento mucho la espera; permítame traerle su comida ahora mismo.", s: "Cuando te disculpas con un cliente por un error o una molestia.", sEn: "When you apologize to a customer for a mistake or inconvenience.", n: "Di \"I'm sorry about\" + el problema; \"I'm sorry for\" + lo que tú hiciste.", nEn: "Say \"I'm sorry about\" + the problem; \"I'm sorry for\" + what you did." },
    "loc-que02": { e: "Don't worry, I'll fix it right away and bring you a new plate.", t: "No se preocupe, lo soluciono enseguida y le traigo un plato nuevo.", s: "Cuando un cliente reporta un problema y le aseguras una solución inmediata.", sEn: "When a customer reports a problem and you promise an immediate fix.", n: "\"Right away\" suena más natural que \"immediately\" en el trato con clientes.", nEn: "\"Right away\" sounds more natural than \"immediately\" when dealing with customers." },
    "loc-que03": { e: "I'm sorry to hear that. What's the problem, exactly?", t: "Lamento escuchar eso. ¿Cuál es el problema, exactamente?", s: "Cuando un cliente se queja y necesitas entender qué pasó.", sEn: "When a customer complains and you need to understand what happened.", n: "Suaviza con \"May I ask what the problem is?\" para sonar más cortés.", nEn: "Soften it with \"May I ask what the problem is?\" to sound more polite." },
    "loc-que04": { e: "This one is cold, isn't it? I'll bring you another one right away.", t: "Este está frío, ¿verdad? Le traigo otro enseguida.", s: "Cuando algo salió mal con un producto o plato y ofreces reemplazarlo.", sEn: "When something is wrong with a product or dish and you offer a replacement.", n: "Para varios, di \"some more\"; para uno solo, \"another one\".", nEn: "For several, say \"some more\"; for just one, \"another one.\"" },
    "loc-que05": { e: "Please don't worry about it, there's no charge for the dessert.", t: "Por favor no se preocupe, no se le cobrará el postre.", s: "Cuando decides no cobrar algo como gesto por una molestia.", sEn: "When you decide not to charge for something as a gesture for the trouble.", n: "También puedes decir \"it's on the house\" para invitar algo gratis.", nEn: "You can also say \"it's on the house\" to offer something for free." },
    "loc-que06": { e: "I understand. Let me call the manager so we can sort this out.", t: "Entiendo. Permítame llamar al gerente para resolver esto.", s: "Cuando un problema necesita a alguien con más autoridad.", sEn: "When a problem needs someone with more authority.", n: "\"Manager\" se pronuncia \"MA-na-yer\" con la G como la J inglesa de \"jump\", no como una G en español.", nEn: "\"Manager\" is said \"MA-na-jer,\" with a soft G like the English J in \"jump.\"" },
    "loc-que07": { e: "Thanks for letting us know; we'll make sure it doesn't happen again.", t: "Gracias por avisarnos; nos aseguraremos de que no vuelva a pasar.", s: "Cuando un cliente reporta algo y agradeces que lo haya comentado.", sEn: "When a customer reports something and you thank them for mentioning it.", n: "Esto convierte una queja en algo positivo; úsalo siempre antes de disculparte.", nEn: "This turns a complaint into something positive; use it right before apologizing." },
    "loc-que08": { e: "I've turned up the air conditioning. Is this better for you?", t: "Subí el aire acondicionado. ¿Está mejor así para usted?", s: "Después de ajustar algo, para confirmar que el cliente quedó satisfecho.", sEn: "After adjusting something, to confirm the customer is now satisfied.", n: "Agregar \"for you\" al final lo hace sonar más atento y personal.", nEn: "Adding \"for you\" at the end makes it sound more attentive and personal." },
    "loc-que09": { e: "I understand your frustration, and I'll do my best to fix this.", t: "Entiendo su molestia, y haré todo lo posible por solucionarlo.", s: "Cuando un cliente está enojado por un error y quieres mostrarle empatía.", sEn: "When a customer is upset about a mistake and you want to show empathy.", n: "Validar primero con \"I understand...\" calma al cliente antes de explicar la solución.", nEn: "Validating first with \"I understand...\" calms the customer before you explain the fix." },
    "loc-que10": { e: "Let me make it right for you right now.", t: "Permítame corregirlo ahora mismo.", s: "Cuando algo salió mal y quieres asegurarle al cliente que lo vas a arreglar.", sEn: "When something went wrong and you want to assure the customer you'll fix it.", n: "\"Make it right\" es una expresión común y cálida; más natural que \"correct it\".", nEn: "\"Make it right\" is a common, warm phrase; more natural than \"correct it.\"" },
    "loc-que11": { e: "I'll offer you a discount for the trouble, it's the least I can do.", t: "Le ofrezco un descuento por las molestias, es lo menos que puedo hacer.", s: "Cuando quieres compensar a un cliente por un problema con su pedido o servicio.", sEn: "When you want to make up to a customer for a problem with their order or service.", n: "\"For the trouble\" o \"for the inconvenience\" son las frases típicas para disculparse.", nEn: "\"For the trouble\" or \"for the inconvenience\" are the typical phrases for apologizing." },
    "loc-que12": { e: "I'm really sorry, it won't happen again.", t: "Lo siento mucho, no volverá a pasar.", s: "Cuando te disculpas con un cliente y prometes que el error no se repetirá.", sEn: "When you apologize to a customer and promise the mistake won't be repeated.", n: "Pronuncia \"won't\" como /wont/, no como \"want\", para no confundir el sentido.", nEn: "Pronounce \"won't\" as /wohnt/, not like \"want,\" so the meaning stays clear." },
    "loc-que13": { e: "How can I make it up to you?", t: "¿Cómo puedo compensarlo?", s: "Cuando preguntas a un cliente molesto qué puedes hacer para resarcir el error.", sEn: "When you ask an upset customer what you can do to make up for the mistake.", n: "\"Make it up to you\" significa compensar; no lo confundas con \"make up\" (maquillaje/inventar).", nEn: "\"Make it up to you\" means to compensate; don't confuse it with \"make up\" (makeup/invent)." },
    "loc-que14": { e: "Thank you for understanding, we really appreciate it.", t: "Gracias por su comprensión, de verdad lo apreciamos.", s: "Cuando un cliente acepta tu disculpa o solución con paciencia.", sEn: "When a customer accepts your apology or solution patiently.", n: "Tras \"for\" usa el gerundio: \"for understanding\", nunca \"for understand\".", nEn: "After \"for\" use the -ing form: \"for understanding,\" never \"for understand.\"" },
    // ===================== Local food (platos-en) =====================
    "loc-pla-t01": { e: "I'd recommend the bandeja paisa; it's a local dish you can't miss.", t: "Le recomiendo la bandeja paisa; es un plato típico que no se puede perder.", s: "Cuando un turista pregunta qué probar de la comida de la región.", sEn: "When a tourist asks what to try from the regional food.", n: "\"Local\" se pronuncia \"LOU-cal\"; evita decir \"typical dish\", suena raro en inglés.", nEn: "\"Local\" is said \"LOH-cul\"; avoid \"typical dish,\" it sounds odd in English." },
    "loc-pla-t02": { e: "It comes with rice and fish, and a small salad on the side.", t: "Viene con arroz y pescado, y una pequeña ensalada al lado.", s: "Cuando describes qué incluye un plato del menú.", sEn: "When you describe what a dish includes.", n: "Usa \"comes with\" para acompañamientos incluidos; \"on the side\" es \"aparte\".", nEn: "Use \"comes with\" for included sides; \"on the side\" means served separately." },
    "loc-pla-t03": { e: "It's a little spicy, but you can ask the kitchen to make it milder.", t: "Es un poco picante, pero puede pedirle a la cocina que lo haga más suave.", s: "Cuando un cliente pregunta por un plato y quieres advertirle del picante.", sEn: "When a customer asks about a dish and you want to warn them it's hot.", n: "Para algo muy picante di \"It's quite spicy\"; \"a little\" suaviza el aviso.", nEn: "For something very hot say \"It's quite spicy\"; \"a little\" softens the warning." },
    "loc-pla-t04": { e: "The arepa is made of corn, so it's naturally gluten-free.", t: "La arepa es de maíz, así que es naturalmente sin gluten.", s: "Cuando explicas a un turista de qué está hecho un plato típico.", sEn: "When you explain to a tourist what a local dish is made of.", n: "Pronuncia \"corn\" con la o larga (corn), no como \"con\".", nEn: "Pronounce \"corn\" with a long o (corn), not like \"con\"." },
    "loc-pla-t05": { e: "The ceviche has lime, fresh fish, and a bit of onion.", t: "El ceviche lleva limón, pescado fresco y un poco de cebolla.", s: "Cuando describes los ingredientes de un plato a un comensal.", sEn: "When you describe a dish's ingredients to a diner.", n: "En inglés \"lime\" es el limón verde; \"lemon\" es el amarillo.", nEn: "In English \"lime\" is the green one; \"lemon\" is the yellow one." },
    "loc-pla-t06": { e: "Is it vegetarian, or does it have any meat or fish?", t: "¿Es vegetariano, o lleva algo de carne o pescado?", s: "Cuando un cliente quiere saber si un plato no tiene carne.", sEn: "When a customer wants to know if a dish has no meat.", n: "Para algo sin nada de origen animal di \"vegan\" en vez de \"vegetarian\".", nEn: "For something with no animal products say \"vegan\" instead of \"vegetarian\"." },
    "loc-pla-t07": { e: "I recommend it, it's our most popular dish.", t: "Se lo recomiendo, es nuestro plato más popular.", s: "Cuando un cliente duda y quieres sugerirle un plato.", sEn: "When a customer hesitates and you want to suggest a dish.", n: "Suena más cálido si añades por qué: \"I recommend it, it's really fresh.\"", nEn: "It sounds warmer if you add why: \"I recommend it, it's really fresh.\"" },
    "loc-pla-t08": { e: "Here's your food, enjoy your meal!", t: "Aquí tiene su comida, ¡buen provecho!", s: "Cuando sirves el plato en la mesa.", sEn: "When you serve the dish at the table.", n: "En inglés no hay un \"buen provecho\" fijo; \"Enjoy your meal\" o solo \"Enjoy!\" es lo natural.", nEn: "English has no fixed \"buen provecho\"; \"Enjoy your meal\" or just \"Enjoy!\" is natural." },
    "loc-pla-t09": { e: "You eat it with your hands, no fork needed.", t: "Se come con la mano, no hace falta tenedor.", s: "Cuando explicas a un turista cómo se come un plato típico local.", sEn: "When you explain to a tourist how to eat a typical local dish.", n: "En inglés se dice \"with your hands\" (en plural), aunque uses solo una.", nEn: "In English you say \"with your hands\" (plural), even if you use just one." },
    "loc-pla-t10": { e: "It has coconut milk, which gives it a creamy flavor.", t: "Lleva leche de coco, que le da un sabor cremoso.", s: "Cuando describes los ingredientes de un plato a un comensal curioso.", sEn: "When you describe the ingredients of a dish to a curious diner.", n: "\"Coconut milk\" (leche de coco) es distinto de \"coconut water\" (agua de coco).", nEn: "\"Coconut milk\" is different from \"coconut water.\"" },
    "loc-pla-t11": { e: "It's very fresh, we caught the fish this morning.", t: "Es muy fresco, el pescado lo pescamos esta mañana.", s: "Cuando recomiendas un plato y resaltas que los ingredientes son del día.", sEn: "When you recommend a dish and highlight that the ingredients are same-day.", n: "\"Fresh\" se pronuncia /fresh/; no agregues una \"e\" inicial (\"efresh\").", nEn: "\"Fresh\" is pronounced /fresh/; don't add an initial \"e\" sound (\"efresh\")." },
    "loc-pla-t12": { e: "The patacón is fried plantain, and it goes great with everything.", t: "El patacón es plátano frito, y combina muy bien con todo.", s: "Cuando un turista pregunta qué es ese acompañamiento en su plato.", sEn: "When a tourist asks what that side on their plate is.", n: "Plátano para freír es \"plantain\"; \"banana\" es el de comer crudo.", nEn: "Cooking plantain is \"plantain\"; \"banana\" is the kind you eat raw." },
    "loc-pla-t13": { e: "Would you like a taste first? It's our most popular dish.", t: "¿Quiere una prueba primero? Es nuestro plato más popular.", s: "Cuando ofreces una muestra antes de que el cliente pida.", sEn: "When you offer a sample before the customer orders.", n: "\"A taste\" es una probadita; \"a try\" suena más a probarse ropa.", nEn: "\"A taste\" is a small sample; \"a try\" sounds more like trying on clothes." },
    "loc-pla-t14": { e: "It goes well with fresh juice, would you like one?", t: "Va bien con jugo natural, ¿quiere uno?", s: "Cuando sugieres una bebida que combina con el plato que pidió el cliente.", sEn: "When you suggest a drink that pairs with the dish the customer ordered.", n: "Jugo natural en inglés es \"fresh juice\"; \"natural juice\" suena raro a oídos nativos.", nEn: "Fresh-squeezed juice is \"fresh juice\"; \"natural juice\" sounds odd to native ears." },
    // ===================== Emergencies & safety (emergencias-en) =====================
    "loc-eme01": { e: "Are you okay? Do you need me to call someone?", t: "¿Está bien? ¿Necesita que llame a alguien?", s: "Cuando ves a alguien que se cayó o se ve mal y quieres ayudar.", sEn: "When you see someone who fell or looks unwell and want to help.", n: "\"Okay\" suena con dos sílabas (o-key); evita decir solo \"oh-kay\" muy corto.", nEn: "\"Okay\" sounds like two syllables (o-key); don't clip it too short." },
    "loc-eme02": { e: "Call the police, someone just took her bag!", t: "¡Llame a la policía, alguien acaba de quitarle el bolso!", s: "Cuando presencias un robo o un peligro y necesitas ayuda urgente.", sEn: "When you witness a robbery or danger and need urgent help.", n: "\"Police\" lleva el acento en la segunda sílaba: po-LEECE.", nEn: "\"Police\" stresses the second syllable: po-LEECE." },
    "loc-eme03": { e: "I need help, my friend isn't feeling well.", t: "Necesito ayuda, mi amigo no se siente bien.", s: "Cuando pides ayuda a alguien en una emergencia.", sEn: "When you ask someone for help in an emergency.", n: "Para pedir ayuda urgente grita \"Help!\" solo; la frase completa es para explicar.", nEn: "For urgent help just shout \"Help!\"; the full sentence is for explaining." },
    "loc-eme04": { e: "You look pale, should I call an ambulance?", t: "Se ve pálido, ¿llamo a una ambulancia?", s: "Cuando alguien se siente muy mal y ofreces llamar ayuda médica.", sEn: "When someone feels very ill and you offer to call medical help.", n: "\"Ambulance\" se dice AM-byu-lance, sin pronunciar la u como en español.", nEn: "\"Ambulance\" is said AM-byu-lance, not with a Spanish u." },
    "loc-eme05": { e: "Be careful, the floor is wet over there.", t: "Tenga cuidado, el piso está mojado por allá.", s: "Cuando adviertes a alguien de un peligro cercano.", sEn: "When you warn someone about a nearby hazard.", n: "Para un peligro inmediato di \"Watch out!\"; \"Be careful\" es un aviso más general.", nEn: "For an immediate danger say \"Watch out!\"; \"Be careful\" is a more general warning." },
    "loc-eme06": { e: "I lost my passport, where can I report it?", t: "Perdí mi pasaporte, ¿dónde puedo reportarlo?", s: "Cuando se te extravía un documento y buscas ayuda.", sEn: "When you've misplaced a document and are looking for help.", n: "Si te lo robaron, di \"My passport was stolen\", que es más fuerte que \"lost\".", nEn: "If it was stolen, say \"My passport was stolen\", which is stronger than \"lost\"." },
    "loc-eme07": { e: "I was robbed near the market and they took my phone.", t: "Me robaron cerca del mercado y se llevaron mi teléfono.", s: "Cuando reportas un robo a la policía o pides ayuda.", sEn: "When you report a robbery to the police or ask for help.", n: "Usa \"robbed\" cuando te roban a ti; \"stolen\" para la cosa robada: \"My phone was stolen.\"", nEn: "Use \"robbed\" for the person; \"stolen\" for the item: \"My phone was stolen.\"" },
    "loc-eme08": { e: "Stay calm, help is on the way.", t: "Quédese tranquilo, la ayuda está en camino.", s: "Cuando tranquilizas a alguien asustado durante una emergencia.", sEn: "When you reassure a frightened person during an emergency.", n: "\"Stay calm\" y \"Keep calm\" significan lo mismo; ambos funcionan igual.", nEn: "\"Stay calm\" and \"Keep calm\" mean the same thing; both work equally." },
    "loc-eme09": { e: "There's an accident on the main road, please send help.", t: "Hay un accidente en la vía principal, por favor manden ayuda.", s: "Cuando llamas a emergencias o avisas que ocurrió un choque.", sEn: "When you call emergency services or report a crash.", n: "Recuerda contraer: \"There's\" es más natural que \"There is\" al hablar.", nEn: "Remember to contract: \"There's\" sounds more natural than \"There is\" when speaking." },
    "loc-eme10": { e: "Where is the hospital? It's an emergency.", t: "¿Dónde está el hospital? Es una emergencia.", s: "Cuando necesitas atención médica urgente y preguntas la ubicación.", sEn: "When you need urgent medical care and ask for the location.", n: "La \"h\" de \"hospital\" sí se pronuncia, a diferencia del español.", nEn: "The \"h\" in \"hospital\" is pronounced, unlike in Spanish." },
    "loc-eme11": { e: "He feels dizzy and he needs to sit down.", t: "Él se siente mareado y necesita sentarse.", s: "Cuando le explicas a alguien que un compañero o cliente está mal.", sEn: "When you explain to someone that a coworker or guest is unwell.", n: "Para ti mismo di \"I feel dizzy\"; \"dizzy\" suena \"dísi\".", nEn: "For yourself say \"I feel dizzy\"; \"dizzy\" sounds like \"dizz-ee\"." },
    "loc-eme12": { e: "Don't move, help is on the way.", t: "No se mueva, la ayuda viene en camino.", s: "Cuando alguien se cayó o se lastimó y quieres que se quede quieto.", sEn: "When someone has fallen or is hurt and you want them to stay still.", n: "Más suave: \"Try not to move\" suena menos brusco en una emergencia.", nEn: "Softer option: \"Try not to move\" sounds gentler in an emergency." },
    "loc-eme13": { e: "Call the fire department, there's smoke in the kitchen!", t: "¡Llamen a los bomberos, hay humo en la cocina!", s: "Cuando hay un incendio o emergencia y pides que llamen a los bomberos.", sEn: "When there's a fire or emergency and you ask someone to call the firefighters.", n: "En inglés británico se dice \"the fire brigade\" en vez de \"fire department\".", nEn: "In British English people say \"the fire brigade\" instead of \"fire department\"." },
    "loc-eme14": { e: "Please keep calm, everyone, and follow me to the exit.", t: "Por favor mantengan la calma todos, y síganme a la salida.", s: "Cuando guías a un grupo durante una emergencia o evacuación.", sEn: "When you guide a group during an emergency or evacuation.", n: "Variante común: \"Stay calm\" es más corta y se usa igual.", nEn: "Common variant: \"Stay calm\" is shorter and used the same way." },
    // ===================== Reviews & social (resenas-en) =====================
    "loc-res01": { e: "If you enjoyed your visit, could you leave us a review online?", t: "Si disfrutó su visita, ¿nos podría dejar una reseña en internet?", s: "Cuando un cliente satisfecho se va y quieres pedirle una reseña.", sEn: "When a happy customer is leaving and you want to ask for a review.", n: "\"Could you\" es más cortés que \"Can you\" para pedir un favor.", nEn: "\"Could you\" is more polite than \"Can you\" for asking a favor." },
    "loc-res02": { e: "Follow us on Instagram for our daily specials.", t: "Síganos en Instagram para ver nuestras promociones del día.", s: "Cuando invitas a un cliente a seguir el negocio en redes.", sEn: "When you invite a customer to follow the business on social media.", n: "Di el nombre del usuario después: \"Follow us on Instagram, @ourcafe.\"", nEn: "Add the handle after: \"Follow us on Instagram, @ourcafe.\"" },
    "loc-res03": { e: "Tag us in your photos so we can share them too!", t: "Etiquétenos en sus fotos para que también las compartamos.", s: "Cuando animas a los clientes a mencionarte en sus publicaciones.", sEn: "When you encourage customers to mention you in their posts.", n: "\"Tag\" se pronuncia \"tag\" (con 'a' abierta); no lo confundas con \"take\".", nEn: "\"Tag\" is pronounced \"tag\" (open 'a'); don't mix it up with \"take\"." },
    "loc-res04": { e: "Thanks for visiting, we hope to see you again soon!", t: "Gracias por su visita, ¡esperamos verlo pronto de nuevo!", s: "Cuando te despides de un cliente que se va.", sEn: "When you say goodbye to a customer who is leaving.", n: "Suena más cálido con \"again soon\" al final que solo \"Thanks for visiting.\"", nEn: "It sounds warmer with \"again soon\" added than just \"Thanks for visiting.\"" },
    "loc-res05": { e: "Did you enjoy the service today? We'd love your feedback.", t: "¿Le gustó el servicio de hoy? Nos encantaría su opinión.", s: "Cuando preguntas a un cliente si quedó satisfecho.", sEn: "When you ask a customer if they were satisfied.", n: "\"Enjoy\" se dice en-JOY, con el acento en la segunda sílaba.", nEn: "\"Enjoy\" is said en-JOY, with the stress on the second syllable." },
    "loc-res06": { e: "If you liked it, share it with your friends!", t: "Si le gustó, ¡compártalo con sus amigos!", s: "Cuando pides al cliente que recomiende el negocio a otros.", sEn: "When you ask the customer to recommend the business to others.", n: "\"Share\" rima con \"care\"; no lo pronuncies como \"shar\".", nEn: "\"Share\" rhymes with \"care\"; don't pronounce it like \"shar\"." },
    "loc-res07": { e: "We're on Google Maps, so just search our name and you'll find directions.", t: "Estamos en Google Maps, así que solo busque nuestro nombre y encontrará cómo llegar.", s: "Cuando un cliente pregunta cómo encontrarlos o llegar al lugar.", sEn: "When a customer asks how to find you or get to the place.", n: "Puedes añadir 'just search our name' para que sea más útil.", nEn: "You can add 'just search our name' to make it more helpful." },
    "loc-res08": { e: "Thanks again for coming, and come back anytime, we'd love to see you.", t: "Gracias de nuevo por venir, y vuelva cuando quiera, nos encantaría verle.", s: "Al despedir a un cliente que se va contento.", sEn: "When saying goodbye to a happy customer who is leaving.", n: "Suena más cálido si añades 'we'd love to see you' al final.", nEn: "It sounds warmer if you add 'we'd love to see you' at the end." },
    "loc-res09": { e: "Your feedback helps us a lot, so thank you for sharing it.", t: "Su opinión nos ayuda mucho, así que gracias por compartirla.", s: "Cuando un cliente te da un comentario sobre el servicio.", sEn: "When a customer gives you a comment about the service.", n: "'Feedback' es incontable: no digas 'feedbacks'; se pronuncia 'FÍD-bak'.", nEn: "'Feedback' is uncountable: never say 'feedbacks'; it's said 'FEED-back'." },
    "loc-res10": { e: "Tell us what you think, we'd love to hear your honest opinion.", t: "Cuéntenos qué le pareció, nos encantaría conocer su opinión sincera.", s: "Invitando al cliente a dejar un comentario o reseña.", sEn: "Inviting the customer to leave a comment or review.", n: "'What you think' va sin 'do' aquí porque es una frase afirmativa incrustada, no una pregunta directa.", nEn: "'What you think' takes no 'do' here because it's an embedded statement, not a direct question." },
    "loc-res11": { e: "If you enjoyed your visit, you can rate us five stars on the app.", t: "Si disfrutó su visita, puede calificarnos con cinco estrellas en la app.", s: "Pidiendo amablemente una buena calificación al despedir al cliente.", sEn: "Politely asking for a good rating as you say goodbye to the customer.", n: "Se dice 'rate us', no 'qualify us'; 'qualify' significa otra cosa en inglés.", nEn: "Say 'rate us', not 'qualify us'; 'qualify' means something different in English." },
    "loc-res12": { e: "Post your photo and tag us, we love seeing your pictures!", t: "Suba su foto y etiquétenos, ¡nos encanta ver sus fotos!", s: "Animando a los clientes a compartir su experiencia en redes sociales.", sEn: "Encouraging customers to share their experience on social media.", n: "En redes se dice 'post' para subir y 'tag' para etiquetar; no uses 'upload' al hablar de redes.", nEn: "On social media use 'post' to upload and 'tag' to mention; avoid 'upload' in that context." },
    "loc-res13": { e: "We'll reply to your comment as soon as we can.", t: "Responderemos su comentario lo antes posible.", s: "Cuando alguien deja una pregunta o reseña en línea y aseguras una respuesta.", sEn: "When someone leaves a question or review online and you promise a response.", n: "Se dice 'reply to your comment', con 'to'; nunca 'reply your comment'.", nEn: "Say 'reply to your comment', with 'to'; never 'reply your comment'." },
    "loc-res14": { e: "Thanks for recommending us to your friends, it means a lot!", t: "¡Gracias por recomendarnos a sus amigos, significa mucho!", s: "Cuando un cliente dice que habló bien de tu negocio a otras personas.", sEn: "When a customer says they spoke well of your business to others.", n: "'Recommend' lleva una sola 'c' y doble 'm'; se pronuncia 're-co-MÉND'.", nEn: "'Recommend' has one 'c' and double 'm'; it's said 're-kuh-MEND'." },
    // ===================== Housekeeping (limpieza) =====================
    "loc-lim01": { e: "Housekeeping, may I come in to clean your room?", t: "Servicio de limpieza, ¿puedo pasar a limpiar su cuarto?", s: "Cuando tocas la puerta de un huésped antes de entrar a hacer el aseo.", sEn: "When you knock on a guest's door before entering to clean.", n: "Toca primero, espera unos segundos y di la frase antes de abrir; nunca entres en silencio.", nEn: "Knock first, wait a few seconds, and say the phrase before opening; never enter silently." },
    "loc-lim02": { e: "Shall I clean your room now, or would you prefer later?", t: "¿Le hago el cuarto ahora o prefiere más tarde?", s: "Cuando le preguntas al huésped el mejor momento para hacer la limpieza.", sEn: "When you ask the guest the best moment to do the cleaning.", n: "\"Shall I...?\" suena muy cortés para ofrecer un servicio; es más amable que \"Do you want...?\".", nEn: "\"Shall I...?\" sounds very polite for offering a service; it's softer than \"Do you want...?\"." },
    "loc-lim03": { e: "I'll bring fresh towels and leave them in the bathroom.", t: "Le traigo toallas limpias y las dejo en el baño.", s: "Cuando avisas al huésped que vas a reponer las toallas.", sEn: "When you tell the guest you're going to replace the towels.", n: "\"Fresh\" aquí significa limpias/nuevas, no frías; es la palabra natural para toallas y sábanas.", nEn: "\"Fresh\" here means clean/new, not cold; it's the natural word for towels and sheets." },
    "loc-lim04": { e: "Do you need more soap or shampoo for the bathroom?", t: "¿Necesita más jabón o champú para el baño?", s: "Cuando ofreces reponer los artículos de aseo del huésped.", sEn: "When you offer to restock the guest's toiletries.", n: "\"Shampoo\" se pronuncia \"sham-PÚ\", con el acento en la segunda sílaba.", nEn: "\"Shampoo\" is pronounced \"sham-POO\", with the stress on the second syllable." },
    "loc-lim05": { e: "I've changed the sheets, so the bed is all fresh for you.", t: "Ya cambié las sábanas, así que la cama quedó fresquita para usted.", s: "Cuando le confirmas al huésped que ya pusiste sábanas limpias.", sEn: "When you confirm to the guest that you've put on clean sheets.", n: "\"I've changed\" (present perfect) indica que ya está hecho; suena mejor que \"I changed\" aquí.", nEn: "\"I've changed\" (present perfect) shows it's already done; it sounds better than \"I changed\" here." },
    "loc-lim06": { e: "What time works best for cleaning, morning or afternoon?", t: "¿A qué hora le viene mejor la limpieza, mañana o tarde?", s: "Cuando coordinas con el huésped un horario que no lo moleste.", sEn: "When you arrange with the guest a time that won't disturb them.", n: "\"Works best\" es una forma natural y amable de decir \"le conviene más\".", nEn: "\"Works best\" is a natural, polite way to say \"is most convenient for you\"." },
    "loc-lim07": { e: "No problem, I'll come back later when it's convenient.", t: "No hay problema, vuelvo más tarde cuando le quede bien.", s: "Cuando el huésped está ocupado o descansando y decides regresar después.", sEn: "When the guest is busy or resting and you decide to return afterward.", n: "Acompáñalo de una sonrisa y \"no problem\" para que no suene como molestia.", nEn: "Pair it with a smile and \"no problem\" so it doesn't sound like an inconvenience." },
    "loc-lim08": { e: "Hang the sign on the door if you don't want to be disturbed.", t: "Cuelgue el letrero en la puerta si no desea que lo molesten.", s: "Cuando le explicas al huésped cómo pedir privacidad con el letrero.", sEn: "When you explain to the guest how to ask for privacy with the sign.", n: "\"Do not disturb\" es el texto exacto del letrero; puedes señalarlo al decirlo.", nEn: "\"Do not disturb\" is the exact wording on the sign; you can point to it as you say it." },
    "loc-lim09": { e: "Here is some toilet paper, I'll leave extra under the sink.", t: "Aquí tiene papel higiénico, le dejo más debajo del lavamanos.", s: "Cuando repones el papel higiénico en el baño del huésped.", sEn: "When you restock the toilet paper in the guest's bathroom.", n: "\"Toilet paper\" es incontable, por eso se dice \"some\" y no \"a toilet paper\".", nEn: "\"Toilet paper\" is uncountable, so you say \"some\" and not \"a toilet paper\"." },
    "loc-lim10": { e: "Shall I restock the minibar while I'm here?", t: "¿Le repongo el minibar ya que estoy aquí?", s: "Cuando ofreces rellenar las bebidas y snacks del minibar durante la limpieza.", sEn: "When you offer to refill the minibar drinks and snacks during cleaning.", n: "\"Restock\" se pronuncia \"ri-STOK\"; significa volver a llenar las existencias.", nEn: "\"Restock\" is pronounced \"ree-STOCK\"; it means to fill the supplies back up." },
    "loc-lim11": { e: "I found this in your room when I was cleaning, is it yours?", t: "Encontré esto en su cuarto cuando estaba limpiando, ¿es suyo?", s: "Cuando, limpiando, encuentras un objeto olvidado por el huésped.", sEn: "When, while cleaning, you find an item the guest left behind.", n: "Suena más amable si agregas 'I think' al inicio: 'I think I found this in your room.'", nEn: "It sounds gentler if you add 'I think' at the start: 'I think I found this in your room.'" },
    "loc-lim12": { e: "Everything is ready for you, have a good rest.", t: "Todo está listo para usted, que descanse.", s: "Al salir del cuarto después de limpiarlo, te despides del huésped.", sEn: "As you leave the room after cleaning, you say goodbye to the guest.", n: "También puedes decir 'Enjoy your rest' o, de noche, 'Sleep well.'", nEn: "You can also say 'Enjoy your rest' or, at night, 'Sleep well.'" },
    // ===================== Spa & massage (spa-en) =====================
    "loc-spa01": { e: "Welcome, would you like a massage to start your treatment?", t: "Bienvenido, ¿le gustaría un masaje para comenzar su tratamiento?", s: "Al recibir al cliente en el spa y ofrecerle un servicio.", sEn: "When greeting the client at the spa and offering a service.", n: "'Would you like' es más cortés que 'Do you want'; úsalo con clientes.", nEn: "'Would you like' is more polite than 'Do you want'; use it with clients." },
    "loc-spa02": { e: "Before we begin, do you prefer soft or firm pressure?", t: "Antes de empezar, ¿prefiere presión suave o fuerte?", s: "Antes de iniciar el masaje, para ajustarlo al gusto del cliente.", sEn: "Before starting the massage, to tailor it to the client's preference.", n: "'Firm' se usa más que 'strong' para presión de masaje; 'strong' suena a fuerza bruta.", nEn: "'Firm' is more common than 'strong' for massage pressure; 'strong' sounds like brute force." },
    "loc-spa03": { e: "Please lie face down and rest your head in the cradle.", t: "Por favor acuéstese boca abajo y apoye la cabeza en el soporte.", s: "Cuando indicas al cliente cómo posicionarse en la camilla.", sEn: "When you tell the client how to position themselves on the table.", n: "El opuesto es 'face up'; di 'face down' despacio y marca bien la 'd' de 'down'.", nEn: "The opposite is 'face up'; say 'face down' slowly and pronounce the 'd' in 'down' clearly." },
    "loc-spa04": { e: "Just relax and let your shoulders drop.", t: "Solo relájese y deje caer los hombros.", s: "Al empezar el masaje, para que el cliente suelte la tensión.", sEn: "At the start of the massage, to help the client release tension.", n: "Pronuncia 'relax' con acento en la segunda sílaba: re-LAX, no RE-lax.", nEn: "Stress 'relax' on the second syllable: re-LAX, not RE-lax." },
    "loc-spa05": { e: "Let me know if anything bothers you or feels too strong.", t: "Avíseme si le molesta algo o si lo siente muy fuerte.", s: "Durante el masaje, para que el cliente avise sobre incomodidad.", sEn: "During the massage, so the client can flag any discomfort.", n: "'Let me know' es más natural que 'tell me' para invitaciones amables.", nEn: "'Let me know' sounds more natural than 'tell me' for polite invitations." },
    "loc-spa06": { e: "The massage lasts one hour, so we have plenty of time.", t: "El masaje dura una hora, así que tenemos bastante tiempo.", s: "Cuando informas al cliente cuánto durará el servicio.", sEn: "When you tell the client how long the service will take.", n: "Cuidado: 'lasts' no es 'last week'; aquí significa 'dura'.", nEn: "Note: 'lasts' here means 'has a duration of', not 'last week'." },
    "loc-spa07": { e: "Do you have any injuries I should know about before we start?", t: "¿Tiene alguna lesión que deba saber antes de empezar?", s: "En la consulta inicial, para evitar lastimar al cliente.", sEn: "During the initial check, to avoid hurting the client.", n: "'Injury' se dice 'IN-lle-ri' (la 'j' suena como en 'jeep', no como una 'y' española); no confundir con 'pain' (dolor).", nEn: "'Injury' is said 'IN-juh-ree'; don't confuse it with 'pain'." },
    "loc-spa08": { e: "Breathe deeply and slowly, it will help you relax.", t: "Respire profundo y despacio, le ayudará a relajarse.", s: "Durante el masaje, para guiar la relajación del cliente.", sEn: "During the massage, to guide the client into relaxation.", n: "'Breathe' es el verbo; 'breath' (sin e final) es el sustantivo.", nEn: "'Breathe' is the verb; 'breath' (no final e) is the noun." },
    "loc-spa09": { e: "Is the temperature okay, or would you like a blanket?", t: "¿La temperatura está bien, o le gustaría una manta?", s: "Cuando revisas si el cliente está cómodo en la sala.", sEn: "When you check whether the client is comfortable in the room.", n: "'Temperature' se pronuncia 'TEM-pruh-cher', con tres sílabas, no cuatro.", nEn: "'Temperature' is said 'TEM-pruh-cher', in three syllables, not four." },
    "loc-spa10": { e: "There's no rush, take your time getting up.", t: "No hay prisa, tómese su tiempo para levantarse.", s: "Al terminar el masaje, para que el cliente se levante con calma.", sEn: "After the massage, so the client can get up at their own pace.", n: "'Take your time' suena amable; evita 'go slow', que puede sonar tosco.", nEn: "'Take your time' sounds kind; avoid 'go slow', which can sound blunt." },
    "loc-spa11": { e: "I recommend drinking water after the massage to feel refreshed.", t: "Le recomiendo tomar agua después del masaje para sentirse renovado.", s: "Al despedir al cliente, dándole un consejo de cuidado.", sEn: "When seeing the client off, giving an aftercare tip.", n: "Después de 'recommend' usa el verbo en -ing: 'recommend drinking', no 'to drink'.", nEn: "After 'recommend' use the -ing form: 'recommend drinking', not 'to drink'." },
    "loc-spa12": { e: "Thank you for coming, I hope you feel better soon.", t: "Gracias por venir, espero que se sienta mejor pronto.", s: "Al despedir a un cliente que llegó con dolor o tensión.", sEn: "When saying goodbye to a client who came in with pain or tension.", n: "'I hope you feel better' es la frase fija; no digas 'I hope you feel good'.", nEn: "'I hope you feel better' is the set phrase; don't say 'I hope you feel good'." },
    // ===================== Boat & islands (lancha-en) =====================
    "loc-lan01": { e: "Welcome aboard, everyone, please find a seat.", t: "Bienvenidos a bordo, por favor busquen un asiento.", s: "Al recibir a los pasajeros cuando suben al bote.", sEn: "When greeting passengers as they board the boat.", n: "'Aboard' se usa en barcos y aviones; en tierra di 'Welcome' a secas.", nEn: "'Aboard' is for boats and planes; on land just say 'Welcome'." },
    "loc-lan02": { e: "For your safety, please put on your life jacket now.", t: "Por su seguridad, pónganse el chaleco salvavidas ahora.", s: "Antes de zarpar, cuando das las instrucciones de seguridad.", sEn: "Before setting off, when you give the safety instructions.", n: "'Put on' es ponerse; no lo confundas con 'wear', que es ya tenerlo puesto.", nEn: "'Put on' means to don it; don't confuse it with 'wear', which means already having it on." },
    "loc-lan03": { e: "We leave at nine sharp, so please be on time.", t: "Salimos a las nueve en punto, así que por favor sean puntuales.", s: "Cuando informas la hora exacta de salida a los pasajeros.", sEn: "When telling passengers the exact departure time.", n: "'Nine sharp' significa 'nueve en punto, ni un minuto más'; muy útil con turistas.", nEn: "'Nine sharp' means 'nine o'clock exactly, not a minute later'; handy with tourists." },
    "loc-lan04": { e: "Snorkeling is included in the tour, so bring your swimsuit.", t: "El esnórquel está incluido en el tour, así que traigan su traje de baño.", s: "Al explicar qué actividades cubre el paseo en bote.", sEn: "When explaining what activities the boat trip covers.", n: "Se escribe 'snorkeling' y se dice 'SNOR-kuh-ling'; no 'esnorkel'.", nEn: "It's spelled 'snorkeling' and said 'SNOR-kuh-ling'; not 'esnorkel'." },
    "loc-lan05": { e: "The sea is a bit rough today, so please hold on tight.", t: "El mar está un poco picado hoy, así que agárrense bien.", s: "Cuando hay oleaje y debes advertir a los pasajeros.", sEn: "When the water is choppy and you need to warn passengers.", n: "'Rough sea' es mar picado; 'a bit' suaviza y evita asustar a la gente.", nEn: "'Rough sea' means choppy water; 'a bit' softens it so you don't scare people." },
    "loc-lan06": { e: "Please sit down and hold on, we're picking up speed.", t: "Por favor siéntense y agárrense, vamos a acelerar.", s: "Justo antes de que el bote acelere o haya olas.", sEn: "Right before the boat speeds up or hits waves.", n: "'Hold on' solo o 'hold on tight' para enfatizar; ambos suenan naturales.", nEn: "Use 'hold on' alone or 'hold on tight' for emphasis; both sound natural." },
    "loc-lan07": { e: "We return to the dock at three, so please be back at the boat by ten to three.", t: "Volvemos al muelle a las tres, así que por favor estén de vuelta en el bote diez para las tres.", s: "Cuando, como guía o capitán, le dices al grupo a qué hora termina el paseo en lancha.", sEn: "When, as a guide or skipper, you tell the group what time the boat trip ends.", n: "'Dock' suena 'dok' con la 'o' corta; se pronuncia igual que 'doc' (doctor), así que el contexto te dirá cuál es.", nEn: "'Dock' sounds like 'dok' with a short 'o'; it's pronounced the same as 'doc' (doctor), so context tells them apart." },
    "loc-lan08": { e: "Don't forget your sunscreen, the sun gets really strong out on the water.", t: "No olviden el protector solar, el sol se pone muy fuerte allá en el agua.", s: "Cuando recuerdas a los pasajeros llevar protección solar antes de salir al mar.", sEn: "When you remind passengers to bring sun protection before heading out to sea.", n: "También puedes decir 'sunblock'; 'sunscreen' es lo más común a nivel internacional.", nEn: "You can also say 'sunblock'; 'sunscreen' is the most internationally common word." },
    "loc-lan09": { e: "You can swim here, it's safe, but please stay close to the boat.", t: "Pueden nadar aquí, es seguro, pero por favor quédense cerca del bote.", s: "Cuando das permiso al grupo para meterse al agua en una parada del paseo.", sEn: "When you give the group the go-ahead to get in the water at a stop on the trip.", n: "'Safe' suena 'seif'; evita pronunciar la 'e' final, que es muda.", nEn: "'Safe' sounds like 'seif'; don't pronounce the final 'e', it's silent." },
    "loc-lan10": { e: "Careful getting off the boat, the step is wet and slippery.", t: "Cuidado al bajar del bote, el escalón está mojado y resbaloso.", s: "Cuando ayudas a los pasajeros a descender de la lancha de forma segura.", sEn: "When you help passengers step down from the boat safely.", n: "Para sonar más amable agrega 'please': 'Please be careful getting off the boat'.", nEn: "To sound friendlier add 'please': 'Please be careful getting off the boat'." },
    "loc-lan11": { e: "Lunch is served on the island around noon, and it's already included in the tour.", t: "El almuerzo se sirve en la isla alrededor del mediodía, y ya está incluido en el tour.", s: "Cuando explicas al grupo dónde y cuándo comerán durante el paseo.", sEn: "When you explain to the group where and when they'll eat during the trip.", n: "Usa 'is served' (voz pasiva) para sonar profesional; 'we serve lunch' también vale.", nEn: "Use 'is served' (passive) to sound professional; 'we serve lunch' also works." },
    "loc-lan12": { e: "Everyone aboard? Great, enjoy the ride!", t: "¿Todos a bordo? Perfecto, ¡disfruten el paseo!", s: "Cuando, justo antes de arrancar, animas al grupo a disfrutar el recorrido.", sEn: "When, right before setting off, you tell the group to enjoy the trip.", n: "'Ride' sirve para lancha, bus o cualquier paseo; 'enjoy the trip' es la versión más formal.", nEn: "'Ride' works for a boat, bus, or any trip; 'enjoy the trip' is the more formal version." },
    // ===================== Check-out (checkout-en) =====================
    "loc-cko01": { e: "Good morning! Are you ready to check out?", t: "¡Buenos días! ¿Está listo para hacer el check-out?", s: "Cuando un huésped llega a recepción para dejar el hotel.", sEn: "When a guest comes to the front desk to leave the hotel.", n: "'Check out' como verbo va separado; 'check-out' con guion es el sustantivo.", nEn: "'Check out' as a verb is two words; 'check-out' with a hyphen is the noun." },
    "loc-cko02": { e: "Did you enjoy your stay with us?", t: "¿Disfrutó su estadía con nosotros?", s: "Cuando preguntas al huésped cómo le fue justo antes de que se vaya.", sEn: "When you ask the guest how things went just before they leave.", n: "Agregar 'with us' suena más cálido y personal que solo 'your stay'.", nEn: "Adding 'with us' sounds warmer and more personal than just 'your stay'." },
    "loc-cko03": { e: "Here is your bill, please take a moment to look it over.", t: "Aquí tiene su cuenta, tómese un momento para revisarla.", s: "Cuando entregas la factura al huésped al momento de pagar.", sEn: "When you hand the guest the invoice at the moment of payment.", n: "En hotel/restaurante se usa 'bill'; 'check' es más típico de EE. UU. en restaurantes.", nEn: "In a hotel/restaurant use 'bill'; 'check' is more typical in US restaurants." },
    "loc-cko04": { e: "Did you use anything from the minibar during your stay?", t: "¿Usó algo del minibar durante su estadía?", s: "Cuando verificas consumos antes de cerrar la cuenta del huésped.", sEn: "When you check for charges before closing out the guest's bill.", n: "'Anything' es para preguntas; en afirmativo usarías 'something'.", nEn: "'Anything' is for questions; in a statement you'd use 'something'." },
    "loc-cko05": { e: "How would you like to pay, by card or in cash?", t: "¿Cómo desea pagar, con tarjeta o en efectivo?", s: "Cuando le preguntas al huésped su método de pago al hacer el check-out.", sEn: "When you ask the guest their payment method at check-out.", n: "'Would you like' es más cortés que 'How do you want to pay?'.", nEn: "'Would you like' is more polite than 'How do you want to pay?'." },
    "loc-cko06": { e: "Do you need a taxi to the airport? I can call one for you.", t: "¿Necesita un taxi al aeropuerto? Puedo pedirle uno.", s: "Cuando ofreces ayuda con el transporte después de que el huésped paga.", sEn: "When you offer transport help after the guest has paid.", n: "Ofrecer un extra ('I can call one for you') deja una buena última impresión.", nEn: "Offering an extra ('I can call one for you') leaves a good final impression." },
    "loc-cko07": { e: "Shall I store your luggage until your flight this evening?", t: "¿Le guardo el equipaje hasta su vuelo de esta tarde?", s: "Cuando el huésped ya hizo check-out pero su transporte sale más tarde.", sEn: "When the guest has checked out but their ride leaves later.", n: "'Shall I…?' suena muy profesional para ofrecer un servicio; 'Should I…?' también vale.", nEn: "'Shall I…?' sounds very professional when offering a service; 'Should I…?' also works." },
    "loc-cko08": { e: "Just a reminder, check-out is by noon, but we can hold your bags after that.", t: "Solo un recordatorio, la salida es hasta el mediodía, pero podemos guardar sus maletas después de eso.", s: "Cuando informas al huésped el límite de hora para desocupar la habitación.", sEn: "When you tell the guest the deadline to vacate the room.", n: "'By noon' significa 'a más tardar al mediodía'; no confundir con 'at noon' (exactamente).", nEn: "'By noon' means 'no later than noon'; don't confuse it with 'at noon' (exactly then)." },
    "loc-cko09": { e: "Thank you for staying with us, it was a pleasure having you.", t: "Gracias por hospedarse con nosotros, fue un placer tenerlo aquí.", s: "Cuando te despides del huésped al terminar el check-out.", sEn: "When you say goodbye to the guest as check-out finishes.", n: "Añadir 'it was a pleasure having you' suena cálido y muy hospitalario.", nEn: "Adding 'it was a pleasure having you' sounds warm and very hospitable." },
    "loc-cko10": { e: "Safe travels, and we hope to see you again soon!", t: "Buen viaje, ¡y esperamos verlo de nuevo pronto!", s: "Cuando deseas al huésped un buen regreso y lo invitas a volver.", sEn: "When you wish the guest a good trip back and invite them to return.", n: "'We hope to see you again' es estándar; agregar 'soon' lo hace más cercano.", nEn: "'We hope to see you again' is standard; adding 'soon' makes it warmer." },
    "loc-cko11": { e: "Did you forget anything in the room? I can have someone check for you.", t: "¿Olvidó algo en el cuarto? Puedo pedir que alguien lo revise.", s: "Cuando confirmas que el huésped no dejó pertenencias antes de irse.", sEn: "When you confirm the guest didn't leave belongings before leaving.", n: "'Forget' en pasado es 'forgot'; aquí la pregunta usa 'Did you forget…?'.", nEn: "The past of 'forget' is 'forgot'; here the question uses 'Did you forget…?'." },
    "loc-cko12": { e: "Have a safe trip back, and take care!", t: "Buen viaje de regreso, ¡y que le vaya bien!", s: "Cuando das la despedida final al huésped que sale del hotel.", sEn: "When you give the final goodbye to a guest leaving the hotel.", n: "Una variante muy natural es 'Safe travels back home!'.", nEn: "A very natural variant is 'Safe travels back home!'." },
    // ===================== Hair & barber (peluqueria) =====================
    "loc-pel01": { e: "Have a seat. How would you like your haircut today?", t: "Tome asiento. ¿Cómo desea el corte hoy?", s: "Cuando el cliente se sienta y le preguntas qué estilo de corte quiere.", sEn: "When the client sits down and you ask what style of cut they want.", n: "También puedes decir 'What are we doing today?', muy común en barberías.", nEn: "You can also say 'What are we doing today?', very common in barbershops." },
    "loc-pel02": { e: "A little shorter on the sides? I'll leave the top as it is.", t: "¿Un poco más corto a los lados? Dejo la parte de arriba como está.", s: "Cuando confirmas con el cliente cuánto cortar antes de empezar.", sEn: "When you confirm with the client how much to cut before starting.", n: "'Sides' rima con 'tides' (suena 'saidz', con la 'i' larga); para arriba di 'the top' y para atrás 'the back'.", nEn: "'Sides' rhymes with 'tides' (the long 'i' sound); use 'the top' for the top and 'the back' for the back." },
    "loc-pel03": { e: "Before we start, shall I wash your hair, or would you prefer it dry?", t: "Antes de empezar, ¿le lavo el cabello o lo prefiere seco?", s: "Cuando el cliente se sienta en la silla y quieres saber si lava antes de cortar.", sEn: "When the client sits down and you want to know whether to wash before cutting.", n: "\"Shall I...?\" suena formal y amable para ofrecer un servicio; también puedes decir \"Would you like me to wash your hair?\".", nEn: "\"Shall I...?\" sounds polite and professional for offering a service; you can also say \"Would you like me to wash your hair?\"." },
    "loc-pel04": { e: "Would you like a beard trim while you're here, or just the haircut today?", t: "¿Quiere que le recorte la barba mientras está aquí, o solo el corte hoy?", s: "Cuando ofreces un servicio extra a un cliente que vino por un corte.", sEn: "When you offer an extra service to a client who came in for a haircut.", n: "\"Trim\" se pronuncia con una sola sílaba corta, no \"ti-rim\"; significa recortar, no rapar.", nEn: "\"Trim\" is one short syllable, not \"ti-rim\"; it means to neaten, not to shave off." },
    "loc-pel05": { e: "I've finished the sides, is this okay or would you like it shorter?", t: "Ya terminé los lados, ¿así está bien o lo quiere más corto?", s: "Cuando muestras tu avance y confirmas si al cliente le gusta.", sEn: "When you show your progress and confirm whether the client likes it.", n: "Para sonar más natural puedes decir \"Is this okay for you?\" o, más casual, \"Looks good?\".", nEn: "To sound more natural you can say \"Is this okay for you?\" or, more casually, \"Looks good?\"." },
    "loc-pel06": { e: "Shall I blow-dry your hair, or do you prefer to leave it air-dry?", t: "¿Le seco el cabello, o prefiere dejarlo secar al aire?", s: "Al terminar el corte, cuando ofreces secar el cabello antes de que se vaya.", sEn: "After the cut, when you offer to dry the hair before they leave.", n: "\"Blow-dry\" es el término correcto; evita \"dry with the machine\", que suena raro en inglés.", nEn: "\"Blow-dry\" is the correct term; avoid \"dry with the machine,\" which sounds odd in English." },
    "loc-pel07": { e: "Have a seat, please, and I'll be right with you.", t: "Siéntese, por favor, y en un momento lo atiendo.", s: "Cuando un cliente llega y le indicas dónde sentarse para empezar.", sEn: "When a client arrives and you direct them where to sit to begin.", n: "\"Have a seat\" es más cálido que \"Sit down\", que puede sonar como una orden.", nEn: "\"Have a seat\" is warmer than \"Sit down,\" which can sound like a command." },
    "loc-pel08": { e: "Would you like to see the back before I take the cape off?", t: "¿Quiere ver la parte de atrás antes de que le quite la capa?", s: "Al terminar, cuando le ofreces el espejo para que revise la nuca.", sEn: "When you finish and offer the mirror so they can check the back.", n: "Puedes acompañarlo con un gesto del espejo y añadir \"...in the mirror?\" para que quede claro.", nEn: "You can pair it with the mirror and add \"...in the mirror?\" to make it clear." },
    "loc-pel09": { e: "The haircut is twenty thousand, and a beard trim would be five thousand more.", t: "El corte cuesta veinte mil, y el recorte de barba serían cinco mil más.", s: "Cuando le dices el precio al cliente antes de cobrar.", sEn: "When you tell the client the price before charging.", n: "En inglés se dice \"twenty thousand\" sin \"of pesos\"; el contexto ya indica la moneda.", nEn: "In English say \"twenty thousand\" without \"of pesos\"; context already implies the currency." },
    "loc-pel10": { e: "Do you like the length, or should I take off a bit more?", t: "¿Le gusta el largo, o le quito un poquito más?", s: "Cuando confirmas con el cliente si está conforme con cuánto cortaste.", sEn: "When you confirm with the client whether they're happy with how much you cut.", n: "\"Length\" termina en el sonido 'th' sordo de 'think' (leng-th), no en 'z'; no lo digas como \"leng\".", nEn: "\"Length\" ends with the voiceless 'th' sound of 'think' (leng-th), not a 'z'; don't drop it and say \"leng\"." },
    "loc-pel11": { e: "Please don't move for a second, I'm doing the edges around your ear.", t: "Por favor, no se mueva un segundo, estoy haciendo los bordes alrededor de la oreja.", s: "Cuando haces un detalle delicado y necesitas que el cliente se quede quieto.", sEn: "When you're doing a delicate detail and need the client to stay still.", n: "Añadir \"for a second\" lo hace sonar más amable que un seco \"Don't move\".", nEn: "Adding \"for a second\" sounds friendlier than a blunt \"Don't move\"." },
    "loc-pel12": { e: "Looking sharp! See you in a month for a touch-up?", t: "¡Se ve muy bien! ¿Nos vemos en un mes para un retoque?", s: "Cuando te despides del cliente e invitas a que vuelva pronto.", sEn: "When you say goodbye and invite the client to come back soon.", n: "\"See you in a month?\" suena amistoso; \"touch-up\" es la palabra para un retoque rápido.", nEn: "\"See you in a month?\" sounds friendly; \"touch-up\" is the word for a quick retouch." },
    // ===================== Renting & home (vivienda) =====================
    "loc-viv01": { e: "Welcome to the apartment, let me show you around real quick.", t: "Bienvenido al apartamento, déjeme mostrarle todo rapidito.", s: "Cuando recibes a un inquilino o huésped que llega por primera vez.", sEn: "When you welcome a tenant or guest arriving for the first time.", n: "\"Show you around\" significa enseñar el lugar; es la frase natural para una visita guiada de la casa.", nEn: "\"Show you around\" means to give a tour; it's the natural phrase for walking through the home." },
    "loc-viv02": { e: "Just a reminder: the rent is due on the first of each month.", t: "Solo un recordatorio: el arriendo se paga el día uno de cada mes.", s: "Cuando le explicas al inquilino cuándo debe pagar.", sEn: "When you explain to the tenant when payment is due.", n: "\"Due\" se pronuncia \"diu\" y significa \"que se debe pagar\"; no lo confundas con \"do\".", nEn: "\"Due\" sounds like \"dyoo\" and means \"owed/payable\"; don't confuse it with \"do\"." },
    "loc-viv03": { e: "Here are the keys, this big one is for the front door.", t: "Aquí están las llaves, esta grande es de la puerta principal.", s: "Cuando entregas las llaves y explicas para qué es cada una.", sEn: "When you hand over the keys and explain what each one is for.", n: "\"Keys\" siempre lleva la 's' al final cuando hay más de una; \"key\" es solo una.", nEn: "\"Keys\" needs the final 's' when there's more than one; \"key\" is just one." },
    "loc-viv04": { e: "Good news: wifi and water are included in the rent.", t: "Buena noticia: el wifi y el agua están incluidos en el arriendo.", s: "Cuando aclaras qué servicios no se pagan aparte.", sEn: "When you clarify which utilities aren't paid separately.", n: "\"Included\" lleva el acento en la segunda sílaba: in-CLU-ded.", nEn: "\"Included\" is stressed on the second syllable: in-CLU-ded." },
    "loc-viv05": { e: "The AC controls are here on the wall, just press this button to turn it on.", t: "El aire acondicionado se controla aquí en la pared, solo presione este botón para encenderlo.", s: "Cuando le muestras al inquilino cómo usar el aire acondicionado.", sEn: "When you show the tenant how to use the air conditioning.", n: "\"AC\" es la forma corta y común de \"air conditioning\"; se dice \"ei-si\".", nEn: "\"AC\" is the short, common form of \"air conditioning,\" pronounced \"ay-see\"." },
    "loc-viv06": { e: "Please don't smoke inside, but you're welcome to use the balcony.", t: "Por favor, no fume adentro, pero puede usar el balcón.", s: "Cuando explicas las reglas de la casa a un inquilino o huésped.", sEn: "When you explain the house rules to a tenant or guest.", n: "Ofrecer una alternativa (\"but you're welcome to...\") suaviza la regla y suena más amable.", nEn: "Offering an alternative (\"but you're welcome to...\") softens the rule and sounds friendlier." },
    "loc-viv07": { e: "The trash goes out on Tuesdays, just leave the bag by the gate.", t: "La basura se saca los martes, solo deje la bolsa junto a la reja.", s: "Cuando le explicas al inquilino el día de recolección de basura.", sEn: "When you tell the tenant which day the trash is collected.", n: "\"Trash\" es común en EE.UU. y \"rubbish\" en el Reino Unido, pero ambos te entenderán.", nEn: "\"Trash\" is common in the US and \"rubbish\" in the UK, but both will understand you." },
    "loc-viv08": { e: "If anything breaks, let me know and I'll send someone to fix it.", t: "Si algo se daña, avíseme y mando a alguien a arreglarlo.", s: "Cuando le pides al inquilino que reporte cualquier problema en la casa.", sEn: "When you ask the tenant to report any problem in the home.", n: "\"Let me know\" es la forma natural de decir \"avíseme\"; suena mejor que \"tell me\".", nEn: "\"Let me know\" is the natural way to say \"avíseme\"; it sounds better than \"tell me\"." },
    "loc-viv09": { e: "Sorry about the heat, I'll fix the AC tomorrow morning.", t: "Disculpe el calor, mañana en la mañana arreglo el aire.", s: "Cuando le prometes al inquilino reparar algo al día siguiente.", sEn: "When you promise the tenant to repair something the next day.", n: "\"I'll fix\" usa \"will\" para promesas hechas en el momento; suena seguro y profesional.", nEn: "\"I'll fix\" uses \"will\" for on-the-spot promises; it sounds confident and professional." },
    "loc-viv10": { e: "The deposit is returned at the end if there's no damage.", t: "El depósito se devuelve al final si no hay daños.", s: "Cuando explicas las condiciones para recuperar el depósito.", sEn: "When you explain the conditions for getting the deposit back.", n: "\"Deposit\" lleva el acento en la segunda sílaba: de-PO-sit.", nEn: "\"Deposit\" is stressed on the second syllable: de-PO-sit." },
    "loc-viv11": { e: "Text me if you need anything, day or night.", t: "Escríbame si necesita algo, de día o de noche.", s: "Cuando le entregas el apartamento al inquilino y le dejas tu contacto.", sEn: "When you hand over the apartment to a tenant and give them your contact.", n: "\"Text me\" suena casual; con un cliente formal di \"Just message me\" o \"Feel free to reach out.\"", nEn: "\"Text me\" sounds casual; for a formal guest say \"Just message me\" or \"Feel free to reach out.\"" },
    "loc-viv12": { e: "Please lock the door when you leave, even for a few minutes.", t: "Por favor cierre bien la puerta al salir, aunque sea por unos minutos.", s: "Cuando le explicas al huésped las reglas de seguridad de la vivienda.", sEn: "When you explain the home's safety rules to the guest.", n: "\"Lock\" se pronuncia \"lok\", no confundas con \"look\" (mirar), que suena \"luk\".", nEn: "\"Lock\" sounds like \"lok\"; don't confuse it with \"look\", which sounds like \"luk\"." },
    // ===================== The weather (clima-en) =====================
    "loc-clm01": { e: "It's really hot today, so let me bring you some cold water.", t: "Hace mucho calor hoy, así que déjeme traerle agua fría.", s: "Cuando hace conversación con un cliente mientras lo atiendes en un día caluroso.", sEn: "When you make small talk with a guest while serving them on a hot day.", n: "Para el clima siempre usa \"it's\" (it is), no \"have\" como en español (\"hace calor\").", nEn: "For weather always use \"it's\" (it is), not \"have\" like in Spanish (\"hace calor\")." },
    "loc-clm02": { e: "It's cloudy this morning, but it should clear up by noon.", t: "Está nublado esta mañana, pero debería despejarse al mediodía.", s: "Cuando un turista te pregunta si vale la pena salir y comentas el cielo.", sEn: "When a tourist asks if it's worth going out and you comment on the sky.", n: "\"Cloudy\" termina en sonido \"di\"; otra opción útil es \"overcast\" para un cielo muy gris.", nEn: "\"Cloudy\" ends in a \"dee\" sound; another useful option is \"overcast\" for a very grey sky." },
    "loc-clm03": { e: "It looks like rain, so you might want to take a jacket.", t: "Parece que va a llover, así que quizá quiera llevar una chaqueta.", s: "Cuando aconsejas a un huésped antes de que salga a pasear.", sEn: "When you advise a guest before they head out for a walk.", n: "También puedes decir \"It looks like it's going to rain\"; ambas son naturales.", nEn: "You can also say \"It looks like it's going to rain\"; both sound natural." },
    "loc-clm04": { e: "It's very humid today, so take it easy and stay hydrated.", t: "Hay mucha humedad hoy, así que tómelo con calma y manténgase hidratado.", s: "Cuando un visitante siente el calor pegajoso y le explicas el clima de la zona.", sEn: "When a visitor feels the sticky heat and you explain the area's climate.", n: "\"Humid\" se pronuncia \"JIÚ-mid\"; el sonido de la h sí se oye (como una j suave), no la dejes muda como en español.", nEn: "\"Humid\" is pronounced \"HYOO-mid\"; the h IS pronounced here, don't drop it like in Spanish." },
    "loc-clm05": { e: "Take an umbrella just in case, the weather changes fast here.", t: "Lleve un paraguas por si acaso, el clima cambia rápido aquí.", s: "Cuando recomiendas a un turista qué llevar antes de un tour.", sEn: "When you recommend to a tourist what to bring before a tour.", n: "\"Just in case\" es la frase clave para \"por si acaso\"; memorízala como bloque.", nEn: "\"Just in case\" is the key phrase for \"por si acaso\"; memorize it as a chunk." },
    "loc-clm06": { e: "It's cool at night, so you'll want a light sweater.", t: "Hace fresco en la noche, así que va a querer un suéter ligero.", s: "Cuando le adviertes a un huésped sobre el cambio de temperatura en la tarde.", sEn: "When you warn a guest about the temperature drop in the evening.", n: "\"Cool\" es fresco (agradable); \"cold\" es frío de verdad; no los mezcles.", nEn: "\"Cool\" means pleasantly fresh; \"cold\" means truly cold; don't mix them up." },
    "loc-clm07": { e: "The sun rises early here, so the beach is beautiful at dawn.", t: "El sol sale temprano aquí, así que la playa es hermosa al amanecer.", s: "Cuando recomiendas a un turista madrugar para ver el amanecer.", sEn: "When you suggest a tourist get up early to see the sunrise.", n: "Se dice \"the sun rises\" (sale) y \"the sun sets\" (se pone); no uses \"goes out.\"", nEn: "Say \"the sun rises\" and \"the sun sets\"; don't use \"goes out.\"" },
    "loc-clm08": { e: "What a nice day, it's perfect for a walk by the water.", t: "Qué día tan bonito, está perfecto para caminar junto al agua.", s: "Cuando saludas a un cliente y comentas el buen tiempo para romper el hielo.", sEn: "When you greet a guest and comment on the good weather to break the ice.", n: "\"What a nice day!\" lleva \"a\"; nunca digas \"What nice day\" sin el artículo.", nEn: "\"What a nice day!\" needs \"a\"; never say \"What nice day\" without the article." },
    "loc-clm09": { e: "Rain is expected in the afternoon, so let's do the tour this morning.", t: "Se espera lluvia en la tarde, así que hagamos el tour esta mañana.", s: "Cuando reorganizas el plan del día con base en el pronóstico.", sEn: "When you rearrange the day's plan based on the forecast.", n: "\"Rain is expected\" es voz pasiva, ideal para sonar profesional al dar el pronóstico.", nEn: "\"Rain is expected\" is passive voice, ideal to sound professional when giving the forecast." },
    "loc-clm10": { e: "It's windy down by the dock, so hold on to your hat.", t: "Hace viento allá en el muelle, así que sujete su sombrero.", s: "Cuando avisas a los pasajeros del viento antes de subir al bote.", sEn: "When you warn passengers about the wind before boarding the boat.", n: "\"Windy\" se pronuncia \"UÍN-di\"; la w en inglés no suena como \"gu\" del español.", nEn: "\"Windy\" is pronounced \"WIN-dee\"; the English w isn't the Spanish \"gu\" sound." },
    "loc-clm11": { e: "The rainy season starts soon, so prices go down after July.", t: "La temporada de lluvias empieza pronto, así que los precios bajan después de julio.", s: "Cuando le explicas a un turista cuándo conviene viajar a la zona.", sEn: "When you explain to a tourist the best time to visit the area.", n: "Lo opuesto es \"the dry season\"; ambas frases son muy útiles en turismo.", nEn: "The opposite is \"the dry season\"; both phrases are very useful in tourism." },
    "loc-clm12": { e: "It's clear today, so you'll get a great view from the top.", t: "Hoy está despejado, así que tendrá una vista increíble desde la cima.", s: "Cuando animas a un visitante a subir a un mirador por el buen cielo.", sEn: "When you encourage a visitor to go up to a lookout thanks to the clear sky.", n: "\"Clear\" sirve para el cielo y también para \"quedó claro\"; cuida el contexto.", nEn: "\"Clear\" works for the sky and also for \"understood\"; mind the context." },
    // ===================== CV & cover letter (cv-en) =====================
    "loc-cv01": { e: "I'm applying for the position of front desk receptionist.", t: "Me postulo para el puesto de recepcionista.", s: "Cuando escribes la primera línea de tu carta de presentación o correo.", sEn: "When you write the opening line of your cover letter or email.", n: "Di \"apply for\" un puesto, nunca \"apply to\" el puesto; \"to\" se usa con empresas.", nEn: "Say \"apply for\" a position, never \"apply to\" the position; \"to\" is used with companies." },
    "loc-cv02": { e: "I'm attaching my CV and references for your review.", t: "Adjunto mi hoja de vida y referencias para su revisión.", s: "Cuando envías un correo de postulación con tus documentos.", sEn: "When you send a job application email with your documents.", n: "En EE. UU. se usa \"resume\"; \"CV\" es más común en UK y LatAm, ambos se entienden.", nEn: "In the US people say \"resume\"; \"CV\" is more common in the UK and LatAm, both are understood." },
    "loc-cv03": { e: "I have five years of experience in customer service.", t: "Tengo cinco años de experiencia en servicio al cliente.", s: "Cuando resumes tu trayectoria en una entrevista o carta.", sEn: "When you summarize your background in an interview or letter.", n: "Di \"years of experience\", con \"of\"; omitirlo (\"years experience\") suena incorrecto.", nEn: "Say \"years of experience\", with \"of\"; dropping it (\"years experience\") sounds wrong." },
    "loc-cv04": { e: "My strengths are punctuality and organization.", t: "Mis fortalezas son la puntualidad y el orden.", s: "Cuando el entrevistador te pregunta por tus puntos fuertes.", sEn: "When the interviewer asks about your strong points.", n: "\"Strengths\" es difícil; practica el grupo final \"-ngths\" lentamente: streng-ths.", nEn: "\"Strengths\" is hard; practice the final cluster \"-ngths\" slowly: streng-ths." },
    "loc-cv05": { e: "I studied business administration at the university.", t: "Estudié administración de empresas en la universidad.", s: "Cuando hablas de tu formación académica en una entrevista.", sEn: "When you talk about your academic background in an interview.", n: "Solo \"administration\" puede sonar a gobierno; añade \"business\" para que quede claro.", nEn: "Just \"administration\" can sound like government; add \"business\" to make it clear." },
    "loc-cv06": { e: "I speak Spanish and English, and I'm learning a little Portuguese.", t: "Hablo español e inglés, y estoy aprendiendo un poco de portugués.", s: "Cuando mencionas tus idiomas como ventaja para un puesto en turismo.", sEn: "When you mention your languages as an asset for a tourism job.", n: "Los idiomas van con mayúscula en inglés: \"Spanish\", \"English\", siempre.", nEn: "Languages are capitalized in English: \"Spanish\", \"English\", always." },
    "loc-cv07": { e: "I'm looking for a job in the hospitality sector, ideally at a hotel.", t: "Estoy buscando trabajo en el sector de hospitalidad, idealmente en un hotel.", s: "Cuando te presentas en un negocio o le cuentas a alguien que estás en busca de empleo.", sEn: "When you walk into a business or tell someone you're searching for work.", n: "Suena más profesional decir \"I'm currently looking for a job\" que solo \"I want a job\".", nEn: "It sounds more professional to say \"I'm currently looking for a job\" than just \"I want a job\"." },
    "loc-cv08": { e: "I can provide references from my previous managers if you'd like.", t: "Puedo dar referencias de mis jefes anteriores si lo desea.", s: "En una entrevista o al final de tu carta, cuando ofreces respaldo de empleadores pasados.", sEn: "In an interview or at the end of your letter, when you offer backup from past employers.", n: "Di \"references\" (con S al final); en singular \"a reference\" suena raro al ofrecer varias.", nEn: "Say \"references\" with the final S; the singular sounds odd when you're offering several." },
    "loc-cv09": { e: "I'm hardworking and honest, and I always show up on time.", t: "Soy trabajador y honesto, y siempre llego a tiempo.", s: "Cuando describes tus cualidades en una entrevista o carta de presentación.", sEn: "When you describe your qualities in an interview or cover letter.", n: "\"Hardworking\" es una sola palabra; evita \"hard worker\" como adjetivo.", nEn: "\"Hardworking\" is one word as an adjective; don't say \"a hard worker\" in that slot." },
    "loc-cv10": { e: "I'd like to grow with the company and take on more responsibility over time.", t: "Me gustaría crecer en la empresa y asumir más responsabilidades con el tiempo.", s: "Cuando te preguntan sobre tus metas o por qué quieres el puesto.", sEn: "When you're asked about your goals or why you want the position.", n: "\"Grow with the company\" suena más comprometido que \"grow in the company\".", nEn: "\"Grow with the company\" sounds more committed than \"grow in the company\"." },
    "loc-cv11": { e: "Who should I address this to, the hiring manager or HR?", t: "¿A quién debo dirigir esto, al encargado de contratación o a Recursos Humanos?", s: "Cuando vas a escribir una carta o correo y no sabes el nombre del destinatario.", sEn: "When you're about to write a letter or email and don't know the recipient's name.", n: "Si no sabes el nombre, usa \"Dear Hiring Manager\" en la carta.", nEn: "If you don't know the name, use \"Dear Hiring Manager\" in the letter." },
    "loc-cv12": { e: "Thank you for your consideration; I'd welcome the chance to interview.", t: "Agradezco su consideración; me encantaría tener la oportunidad de entrevistarme.", s: "Cierre de una carta de presentación.", sEn: "Closing line of a cover letter.", n: "Fórmula estándar para cerrar una carta formal.", nEn: "A standard way to close a formal letter." },
    // ===================== Negotiating (negociacion) =====================
    "loc-neg01": { e: "Can we talk about the price? I'm buying a few of these.", t: "¿Podemos hablar del precio? Voy a llevar varios de estos.", s: "En un mercado o tienda, cuando quieres abrir una negociación con educación.", sEn: "At a market or shop, when you want to politely open a negotiation.", n: "Empezar con \"Can we talk about...\" suena más amable que decir directo \"too expensive\".", nEn: "Starting with \"Can we talk about...\" sounds friendlier than bluntly saying \"too expensive\"." },
    "loc-neg02": { e: "I was hoping for a bit more, to be honest.", t: "Esperaba un poco más, la verdad.", s: "Cuando te ofrecen un precio o cantidad por debajo de lo que querías.", sEn: "When you're offered a price or amount below what you wanted.", n: "\"I was hoping\" (pasado) suena más suave y educado que \"I want more\".", nEn: "\"I was hoping\" in the past tense sounds softer and more polite than \"I want more\"." },
    "loc-neg03": { e: "What's your best offer if I pay in cash today?", t: "¿Cuál es su mejor oferta si pago en efectivo hoy?", s: "Cuando quieres que la otra persona baje el precio al máximo.", sEn: "When you want the other person to give you their lowest price.", n: "Añadir \"if I pay in cash\" suele conseguir mejores ofertas.", nEn: "Adding \"if I pay in cash\" often gets you a better offer." },
    "loc-neg04": { e: "I'm sure we can reach an agreement that works for both of us.", t: "Estoy seguro de que podemos llegar a un acuerdo que sirva para ambos.", s: "Cuando quieres mantener un tono positivo en medio de una negociación.", sEn: "When you want to keep a positive tone in the middle of a negotiation.", n: "Es \"reach an agreement\", no \"arrive to an agreement\".", nEn: "It's \"reach an agreement\", not \"arrive to an agreement\"." },
    "loc-neg05": { e: "Let me think about it and I'll come back to you tomorrow.", t: "Déjeme pensarlo y le respondo mañana.", s: "Cuando no quieres decidir en el momento sin parecer descortés.", sEn: "When you don't want to decide on the spot without seeming rude.", n: "\"Let me think about it\" es una forma educada de decir no sin cerrar la puerta.", nEn: "\"Let me think about it\" is a polite way to say no without closing the door." },
    "loc-neg06": { e: "If you buy more, I'll lower the price for you.", t: "Si compra más, le bajo el precio.", s: "Como vendedor, cuando ofreces un descuento por comprar en cantidad.", sEn: "As a seller, when you offer a discount for buying in larger quantity.", n: "\"Lower the price\" suena natural; \"make a discount\" es incorrecto, usa \"give a discount\".", nEn: "\"Lower the price\" sounds natural; \"make a discount\" is wrong, use \"give a discount\"." },
    "loc-neg07": { e: "It's a fair price for handmade work, honestly.", t: "Es un precio justo por un trabajo hecho a mano, de verdad.", s: "Cuando defiendes tu precio porque el cliente regatea demasiado.", sEn: "When you defend your price because the customer is haggling too hard.", n: "\"Fair\" se pronuncia como \"fer\", no separes las dos vocales.", nEn: "\"Fair\" sounds like \"fer\"; don't split it into two vowels." },
    "loc-neg08": { e: "Is there any flexibility on the price?", t: "¿Hay algo de flexibilidad en el precio?", s: "Una forma elegante de preguntar si pueden hacerte rebaja.", sEn: "An elegant way to ask whether they can come down on the price.", n: "Más formal y suave que \"can you go cheaper?\"; ideal en tiendas o tratos serios.", nEn: "More formal and gentle than \"can you go cheaper?\"; great for shops or serious deals." },
    "loc-neg09": { e: "Okay, it's a deal. Let's shake on it.", t: "Listo, trato hecho. Démonos la mano.", s: "Cuando ambos aceptan las condiciones y cierran el acuerdo.", sEn: "When both sides accept the terms and close the agreement.", n: "\"It's a deal\" o solo \"Deal!\" sirven; significan que ya aceptaste.", nEn: "\"It's a deal\" or just \"Deal!\" both work; they mean you've accepted." },
    "loc-neg10": { e: "I need to check with my boss before I can confirm.", t: "Necesito consultarlo con mi jefe antes de confirmar.", s: "Cuando no tienes la autoridad para cerrar el trato tú solo.", sEn: "When you don't have the authority to close the deal on your own.", n: "Es \"check with\" (consultar a una persona), distinto de \"check on\".", nEn: "It's \"check with\" a person, which is different from \"check on\"." },
    "loc-neg11": { e: "Does it include shipping, or is that extra?", t: "¿Incluye el envío, o se cobra aparte?", s: "Antes de cerrar una compra, para saber si el precio cubre el envío.", sEn: "Before finalizing a purchase, to know if the price covers delivery.", n: "En inglés es \"shipping\" o \"delivery\"; no uses \"the send\".", nEn: "In English it's \"shipping\" or \"delivery\"; don't say \"the send\"." },
    "loc-neg12": { e: "Let's close the deal today and I'll throw in free delivery.", t: "Cerremos el negocio hoy y le incluyo el envío gratis.", s: "Cuando quieres animar al cliente a decidir en el momento.", sEn: "When you want to encourage the customer to decide right now.", n: "\"Close the deal\" es la frase fija; evita \"close the business\".", nEn: "\"Close the deal\" is the set phrase; avoid \"close the business\"." },
    // ===================== Verb tenses (tiempos-en) =====================
    "loc-tie01": { e: "I work at the front desk from Monday to Friday.", t: "Yo trabajo en la recepción de lunes a viernes.", s: "Cuando hablas de tu rutina o lo que haces normalmente en tu empleo.", sEn: "When you talk about your routine or what you usually do at your job.", n: "En él/ella se agrega S: \"he works\"; pero con I/you/we es \"work\" sin S.", nEn: "For he/she add an S: \"he works\"; but with I/you/we it's \"work\" with no S." },
    "loc-tie02": { e: "I worked at a beach hotel last summer.", t: "Yo trabajé en un hotel de playa el verano pasado.", s: "Cuando cuentas algo que hiciste en el pasado, en una entrevista o charla.", sEn: "When you describe something you did in the past, in an interview or chat.", n: "\"Worked\" termina en /t/, suena \"workt\", no \"work-ed\" con dos sílabas.", nEn: "\"Worked\" ends in a /t/ sound, like \"workt\", not \"work-ed\" with two syllables." },
    "loc-tie03": { e: "I will work the morning shift tomorrow, so I'll see you early.", t: "Mañana trabajaré el turno de la mañana, así que te veo temprano.", s: "Cuando le cuentas a un compañero o jefe tu horario o plan de trabajo a futuro.", sEn: "When you tell a coworker or boss your future schedule or work plan.", n: "En el habla casual casi siempre se dice \"I'll work\" en vez de \"I will work\".", nEn: "In casual speech people almost always say \"I'll work\" instead of \"I will work\"." },
    "loc-tie04": { e: "Sorry, I can't talk right now, I'm working.", t: "Disculpa, no puedo hablar ahorita, estoy trabajando.", s: "Cuando alguien te interrumpe y quieres decir que estás ocupado en este momento.", sEn: "When someone interrupts you and you want to say you're busy right now.", n: "Usa la forma -ing solo para algo que pasa ahora mismo, no para tu trabajo en general.", nEn: "Use the -ing form only for something happening right now, not for your job in general." },
    "loc-tie05": { e: "I have worked here for two years, so I know the menu well.", t: "He trabajado aquí dos años, así que conozco bien el menú.", s: "En una entrevista o con un cliente, cuando hablas de tu experiencia que sigue hasta hoy.", sEn: "In an interview or with a customer, when you talk about experience that continues today.", n: "Di \"for two years\" (duración) y no \"since two years\"; \"since\" va con un punto de inicio como \"since 2024\".", nEn: "Say \"for two years\" (duration), not \"since two years\"; \"since\" goes with a starting point like \"since 2024\"." },
    "loc-tie06": { e: "Yesterday I went to the market to buy fresh fish for the special.", t: "Ayer fui al mercado a comprar pescado fresco para el plato del día.", s: "Cuando cuentas algo que ya hiciste en un momento pasado terminado.", sEn: "When you tell about something you already did at a finished past time.", n: "\"Went\" es el pasado irregular de \"go\"; nunca digas \"goed\".", nEn: "\"Went\" is the irregular past of \"go\"; never say \"goed\"." },
    "loc-tie07": { e: "Tomorrow I'm going to travel to the coast for a few days.", t: "Mañana voy a viajar a la costa por unos días.", s: "Cuando anuncias un plan que ya decidiste para el futuro cercano.", sEn: "When you announce a plan you've already decided for the near future.", n: "En el habla rápida \"going to\" suena como \"gonna\", pero escríbelo completo.", nEn: "In fast speech \"going to\" sounds like \"gonna\", but write it out in full." },
    "loc-tie08": { e: "I eat lunch at noon, but yesterday I ate at the restaurant.", t: "Almuerzo al mediodía, pero ayer comí en el restaurante.", s: "Cuando comparas algo que haces normalmente con algo que hiciste una vez en el pasado.", sEn: "When you compare something you usually do with something you did once in the past.", n: "\"Ate\" se pronuncia como \"eit\", no como se ve escrito.", nEn: "\"Ate\" is pronounced like \"eit\", not the way it looks written." },
    "loc-tie09": { e: "Have you been here before, or is this your first time?", t: "¿Has estado aquí antes, o es tu primera vez?", s: "Cuando un cliente o turista llega y quieres saber si ya conocía el lugar.", sEn: "When a customer or tourist arrives and you want to know if they already knew the place.", n: "Una variante más suave y común es \"Is this your first visit?\".", nEn: "A softer, common variant is \"Is this your first visit?\"." },
    "loc-tie10": { e: "I go to work by bus, but last week I went by taxi.", t: "Voy al trabajo en bus, pero la semana pasada fui en taxi.", s: "Cuando hablas de un hábito y luego de una vez puntual en el pasado.", sEn: "When you talk about a habit and then a one-time event in the past.", n: "Recuerda el par irregular: presente \"go\", pasado \"went\".", nEn: "Remember the irregular pair: present \"go\", past \"went\"." },
    "loc-tie11": { e: "It was raining hard when the tour group arrived.", t: "Estaba lloviendo fuerte cuando llegó el grupo del tour.", s: "Cuando describes lo que estaba pasando de fondo mientras ocurrió otra cosa.", sEn: "When you describe what was happening in the background while something else occurred.", n: "Usa \"was/were + -ing\" para una acción en progreso en el pasado.", nEn: "Use \"was/were + -ing\" for an action in progress in the past." },
    "loc-tie12": { e: "Don't worry, I'll do it tomorrow first thing in the morning.", t: "No se preocupe, lo haré mañana a primera hora.", s: "Cuando prometes a un cliente o jefe encargarte de algo más tarde.", sEn: "When you promise a customer or boss you'll handle something later.", n: "\"I'll\" suena como \"ail\"; junta bien la \"l\" final para que se entienda.", nEn: "\"I'll\" sounds like \"ail\"; pronounce the final \"l\" clearly so it's understood." },
    // ===================== Prepositions (preposiciones) =====================
    "loc-pre01": { e: "I'll meet you at the airport near the main exit.", t: "Nos vemos en el aeropuerto cerca de la salida principal.", s: "Cuando coordinas dónde encontrarte con alguien en una terminal o aeropuerto.", sEn: "When you arrange where to meet someone at a terminal or airport.", n: "Usa \"at the airport\" para el punto; \"in the airport\" suena raro en este caso.", nEn: "Use \"at the airport\" for the location; \"in the airport\" sounds odd here." },
    "loc-pre02": { e: "The tour leaves on Monday at eight in the morning.", t: "El tour sale el lunes a las ocho de la mañana.", s: "Cuando le dices a un cliente el día exacto de una actividad o reserva.", sEn: "When you tell a customer the exact day of an activity or booking.", n: "Con días se usa \"on\": \"on Monday\", \"on Friday\".", nEn: "With days you use \"on\": \"on Monday\", \"on Friday\"." },
    "loc-pre03": { e: "High season starts in July, so book your room early.", t: "La temporada alta empieza en julio, así que reserve su habitación temprano.", s: "Cuando hablas de un mes o una época del año con un cliente.", sEn: "When you talk about a month or time of year with a customer.", n: "Con meses y años se usa \"in\": \"in July\", \"in 2026\".", nEn: "With months and years you use \"in\": \"in July\", \"in 2026\"." },
    "loc-pre04": { e: "Your table is ready at three o'clock, just ask for me.", t: "Su mesa está lista a las tres, solo pregunte por mí.", s: "Cuando confirmas una hora exacta para una reserva o cita.", sEn: "When you confirm an exact time for a reservation or appointment.", n: "Con horas exactas se usa \"at\": \"at three\", \"at noon\".", nEn: "With exact times you use \"at\": \"at three\", \"at noon\"." },
    "loc-pre05": { e: "She isn't here right now, she's at home today.", t: "Ella no está ahora, hoy está en casa.", s: "Cuando explicas que alguien no está en el trabajo porque está en su casa.", sEn: "When you explain that someone isn't at work because they're at home.", n: "Se dice \"at home\" sin \"the\"; \"at the home\" suena mal.", nEn: "Say \"at home\" without \"the\"; \"at the home\" sounds wrong." },
    "loc-pre06": { e: "I left the menu on the table by the window.", t: "Dejé el menú en la mesa junto a la ventana.", s: "Cuando indicas dónde pusiste algo sobre una superficie.", sEn: "When you point out where you put something on a surface.", n: "Usa \"on\" para algo encima de una superficie; \"in the table\" estaría mal.", nEn: "Use \"on\" for something on top of a surface; \"in the table\" would be wrong." },
    "loc-pre07": { e: "Please wait here, your bags are still in the car.", t: "Espere aquí, por favor, sus maletas todavía están en el carro.", s: "Cuando le dices a un cliente dónde están sus cosas dentro del vehículo.", sEn: "When you tell a customer where their things are inside the vehicle.", n: "Con carros y taxis se usa \"in the car\"; con bus o avión se usa \"on\".", nEn: "With cars and taxis you use \"in the car\"; with bus or plane you use \"on\"." },
    "loc-pre08": { e: "The pharmacy is next to the bank, just two minutes away.", t: "La farmacia está al lado del banco, a solo dos minutos.", s: "Cuando das indicaciones y un lugar queda justo a un costado de otro.", sEn: "When you give directions and one place is right beside another.", n: "\"Next to\" siempre lleva \"to\"; no digas solo \"next the bank\".", nEn: "\"Next to\" always keeps \"to\"; don't say just \"next the bank\"." },
    "loc-pre09": { e: "There's a good coffee shop near the hotel entrance.", t: "Hay una buena cafetería cerca de la entrada del hotel.", s: "Cuando recomiendas un lugar que queda a poca distancia de donde están.", sEn: "When you recommend a place that's a short distance from where you are.", n: "\"Near\" no necesita \"to\"; \"near the hotel\" es lo más común (\"near to\" también existe pero suena más formal).", nEn: "\"Near\" doesn't need \"to\"; \"near the hotel\" is the most common form (\"near to\" also exists but sounds more formal)." },
    "loc-pre10": { e: "The ATM is between the pharmacy and the supermarket.", t: "El cajero está entre la farmacia y el supermercado.", s: "Cuando ubicas algo que está en medio de otros dos lugares.", sEn: "When you locate something that sits in the middle of two other places.", n: "\"Between\" se usa con dos cosas y normalmente con \"and\": \"between A and B\".", nEn: "\"Between\" is used with two things and usually with \"and\": \"between A and B\"." },
    "loc-pre11": { e: "I saved this table for you, right by the window.", t: "Te guardé esta mesa, justo al lado de la ventana.", s: "Cuando le ofreces algo a un cliente como un detalle o cortesía.", sEn: "When you offer something to a customer as a courtesy.", n: "\"For you\" suena cálido; agrégalo al final para que el cliente se sienta atendido.", nEn: "\"For you\" sounds warm; add it at the end to make the customer feel cared for." },
    "loc-pre12": { e: "I'm here on vacation with my family.", t: "Estoy aquí de vacaciones con mi familia.", s: "Cuando platicas con un huésped o cliente sobre con quién viajas o vives.", sEn: "When chatting with a guest about who you travel or live with.", n: "Se dice \"with my family\", no \"with my familiar\"; \"familiar\" en inglés significa conocido.", nEn: "Say \"with my family,\" not \"familiar,\" which in English means well-known." },
    // ===================== Asking questions (preguntas-en) =====================
    "loc-prg01": { e: "Excuse me, what time is it? My tour starts soon.", t: "Disculpe, ¿qué hora es? Mi tour empieza pronto.", s: "Cuando necesitas saber la hora porque tienes algo programado.", sEn: "When you need the time because you have something scheduled.", n: "Suena casi \"wha-taim-izit\"; las palabras se unen, no las separes demasiado.", nEn: "It sounds like \"wha-taim-izit\"; the words blend, so don't over-separate them." },
    "loc-prg02": { e: "Where do you live? I can recommend a good route home.", t: "¿Dónde vives? Te puedo recomendar una buena ruta a casa.", s: "Cuando conversas con alguien para conocerlo o ubicarlo mejor.", sEn: "When you chat with someone to get to know them or help them.", n: "Es \"live\" (vivir), no \"leave\" (irse); cuida esa diferencia de sonido.", nEn: "It's \"live\" (reside), not \"leave\" (go away); watch that sound difference." },
    "loc-prg03": { e: "How old are you? We have a kids' menu if you'd like.", t: "¿Cuántos años tienes? Tenemos menú infantil si gustas.", s: "Cuando preguntas la edad, por ejemplo de un niño en el restaurante.", sEn: "When you ask someone's age, for example a child at the restaurant.", n: "En inglés se usa \"are\" (be), no \"have\": \"How old are you?\", no \"how old have you\".", nEn: "English uses \"are\" (be), not \"have\": \"How old are you?\"" },
    "loc-prg04": { e: "Why are you here today, just to relax or for the tour?", t: "¿Por qué estás aquí hoy, solo a relajarte o por el tour?", s: "Cuando preguntas el motivo de la visita de un cliente o huésped.", sEn: "When you ask why a customer or guest is visiting.", n: "\"Why are you here?\" puede sonar brusco; suaviza con \"What brings you here?\".", nEn: "\"Why are you here?\" can sound blunt; soften it with \"What brings you here?\"" },
    "loc-prg05": { e: "It's beautiful, but how much does it cost?", t: "Es hermoso, pero ¿cuánto cuesta?", s: "Cuando preguntas el precio de un producto o servicio.", sEn: "When you ask the price of a product or service.", n: "Para una sola cosa di \"How much is it?\"; \"does it cost\" suena más formal.", nEn: "For one item say \"How much is it?\"; \"does it cost\" sounds more formal." },
    "loc-prg06": { e: "When do you open tomorrow? I'd like to come back.", t: "¿Cuándo abren mañana? Me gustaría volver.", s: "Cuando preguntas el horario de apertura de un negocio.", sEn: "When you ask a business's opening hours.", n: "También puedes decir \"What time do you open?\" para preguntar la hora exacta.", nEn: "You can also say \"What time do you open?\" for the exact hour." },
    "loc-prg07": { e: "Someone's at the door, who is it?", t: "Alguien está en la puerta, ¿quién es?", s: "Cuando preguntas quién llama a la puerta o al teléfono.", sEn: "When you ask who is at the door or on the phone.", n: "En el teléfono se prefiere \"Who's calling?\" en vez de \"Who is it?\".", nEn: "On the phone, \"Who's calling?\" is preferred over \"Who is it?\"" },
    "loc-prg08": { e: "We have red and white wine, which one do you prefer?", t: "Tenemos vino tinto y blanco, ¿cuál prefieres?", s: "Cuando le das opciones a un cliente y le pides que elija.", sEn: "When you give a customer options and ask them to choose.", n: "\"Which one\" es para opciones limitadas; \"what\" es más abierto y general.", nEn: "\"Which one\" is for limited options; \"what\" is more open and general." },
    "loc-prg09": { e: "Excuse me, where is the restroom?", t: "Disculpe, ¿dónde está el baño?", s: "Cuando necesitas o te preguntan por el baño en un lugar público.", sEn: "When you need or are asked about the restroom in a public place.", n: "\"Restroom\" es más educado que \"toilet\" en EE.UU.; en el Reino Unido usan \"toilet\".", nEn: "\"Restroom\" is more polite than \"toilet\" in the US; the UK uses \"toilet.\"" },
    "loc-prg10": { e: "Do you speak English? I have a quick question.", t: "¿Hablas inglés? Tengo una pregunta rápida.", s: "Cuando quieres confirmar si la persona te puede entender en inglés.", sEn: "When you want to confirm if the person can understand English.", n: "No olvides el \"Do\" al inicio; \"You speak English?\" suena incompleto.", nEn: "Don't drop the \"Do\" at the start; \"You speak English?\" sounds incomplete." },
    "loc-prg11": { e: "What is this on the plate? It looks delicious.", t: "¿Qué es esto en el plato? Se ve delicioso.", s: "Cuando preguntas qué es un objeto o platillo que no conoces.", sEn: "When you ask what an unfamiliar object or dish is.", n: "Para algo lejos di \"What is that?\"; \"this\" es para algo cercano.", nEn: "For something far away say \"What is that?\"; \"this\" is for something near." },
    "loc-prg12": { e: "What time do you close? I might be a little late.", t: "¿A qué hora cierran? Puede que llegue un poco tarde.", s: "Cuando preguntas la hora de cierre de un negocio.", sEn: "When you ask a business's closing time.", n: "\"Close\" se pronuncia con z suave al final, no \"clós\" con s fuerte.", nEn: "\"Close\" ends with a soft z sound, not a hard s." },
    // ===================== Call center / BPO (bpo-en) =====================
    "loc-bpo01": { e: "Thank you for calling TechSupport, how can I help you today?", t: "Gracias por llamar a TechSupport, ¿en qué puedo ayudarle hoy?", s: "Cuando contestas una llamada entrante en un call center.", sEn: "When you answer an incoming call at a call center.", n: "Agregar \"today\" al final suena natural y profesional en inglés.", nEn: "Adding \"today\" at the end sounds natural and professional in English." },
    "loc-bpo02": { e: "For security, can you confirm your full name, please?", t: "Por seguridad, ¿me confirma su nombre completo, por favor?", s: "Cuando verificas la identidad del cliente al inicio de la llamada.", sEn: "When you verify the customer's identity at the start of the call.", n: "Anteponer \"For security\" explica por qué pides los datos y suena más amable.", nEn: "Starting with \"For security\" explains why you're asking and sounds kinder." },
    "loc-bpo03": { e: "Can I have your account number to pull up your details?", t: "¿Me da su número de cuenta para ver sus datos?", s: "Cuando necesitas el número de cuenta para buscar al cliente en el sistema.", sEn: "When you need the account number to find the customer in the system.", n: "\"Can I have\" es educado; \"Give me\" suena exigente, evítalo con clientes.", nEn: "\"Can I have\" is polite; \"Give me\" sounds demanding, so avoid it with customers." },
    "loc-bpo04": { e: "One moment while I check that for you.", t: "Un momento mientras reviso eso por usted.", s: "Cuando haces una pausa para buscar información durante la llamada.", sEn: "When you pause to look up information during the call.", n: "Cerrar con \"for you\" hace que la espera se sienta como un servicio.", nEn: "Ending with \"for you\" makes the wait feel like a service." },
    "loc-bpo05": { e: "Thank you for holding, I have your information now.", t: "Gracias por esperar, ya tengo su información.", s: "Cuando retomas la llamada después de poner al cliente en espera.", sEn: "When you return to the call after putting the customer on hold.", n: "\"Holding\" aquí significa esperar en línea, no sostener algo.", nEn: "\"Holding\" here means waiting on the line, not gripping something." },
    "loc-bpo06": { e: "Let me put you on hold for just a moment, please.", t: "Permítame ponerlo en espera solo un momento, por favor.", s: "Cuando vas a dejar al cliente en espera para consultar algo.", sEn: "When you're about to put the customer on hold to check something.", n: "Siempre pide permiso antes; agregar \"just a moment\" tranquiliza al cliente.", nEn: "Always ask first; adding \"just a moment\" reassures the customer." },
    "loc-bpo07": { e: "I'll transfer you to the right department, please stay on the line.", t: "Lo transfiero con el área correspondiente, por favor no cuelgue.", s: "Cuando la consulta del cliente no es de tu área y debes pasarlo con otro equipo.", sEn: "When the customer's issue isn't yours to handle and you pass them to another team.", n: "Suena más cálido si agregas 'please stay on the line' o 'one moment, please' antes de transferir.", nEn: "It sounds warmer if you add 'please stay on the line' or 'one moment, please' before transferring." },
    "loc-bpo08": { e: "Let me make sure I understand: you'd like to cancel the order placed yesterday, correct?", t: "Permítame confirmar lo que entendí: usted quiere cancelar el pedido de ayer, ¿correcto?", s: "Cuando repites lo que pidió el cliente para confirmar que entendiste bien.", sEn: "When you repeat the customer's request to confirm you understood correctly.", n: "Cerrar con 'correct?' o 'is that right?' invita al cliente a confirmar y evita errores.", nEn: "Closing with 'correct?' or 'is that right?' invites the customer to confirm and avoids mistakes." },
    "loc-bpo09": { e: "I'm sorry for the trouble; let's get this sorted out for you right now.", t: "Lamento la molestia; vamos a resolverle esto ahora mismo.", s: "Cuando el cliente tuvo un problema y quieres disculparte antes de solucionarlo.", sEn: "When the customer had a problem and you apologize before fixing it.", n: "'Trouble' aquí significa molestia, no peligro; pronúncialo 'trá-bol' (la primera vocal suena como 'a'), no 'trú-bol'.", nEn: "Here 'trouble' means inconvenience, not danger; say it 'TRUH-buhl', not 'troo-ble'." },
    "loc-bpo10": { e: "Let me verify your information before I make any changes to the account.", t: "Déjeme verificar su información antes de hacer cambios en la cuenta.", s: "Cuando necesitas confirmar los datos del cliente por seguridad antes de actuar.", sEn: "When you need to confirm the customer's details for security before acting.", n: "Más suave: 'Could I just verify your information?' suena menos brusco que ordenarlo.", nEn: "Softer: 'Could I just verify your information?' sounds less abrupt than ordering it." },
    "loc-bpo11": { e: "Are you still there? I just want to make sure we didn't lose the connection.", t: "¿Sigue en la línea? Solo quiero asegurarme de que no se cortó la llamada.", s: "Cuando hay un silencio largo y no sabes si el cliente sigue al teléfono.", sEn: "When there's a long silence and you're not sure the customer is still on the call.", n: "Más formal: 'Are you still on the line?'; 'still there?' es perfecto para tono amable.", nEn: "More formal: 'Are you still on the line?'; 'still there?' is fine for a friendly tone." },
    "loc-bpo12": { e: "Your case has been logged, so the next agent will see everything we discussed.", t: "Su caso quedó registrado, así el próximo agente verá todo lo que hablamos.", s: "Cuando confirmas al cliente que su reclamo o consulta quedó guardado en el sistema.", sEn: "When you confirm to the customer that their complaint or request is saved in the system.", n: "'Logged' viene de 'log' (registrar); también puedes decir 'has been recorded'.", nEn: "'Logged' comes from 'log' (to record); you can also say 'has been recorded'." },
    "loc-bpo13": { e: "I'll give you a reference number so you can follow up on your case anytime.", t: "Le doy su número de referencia para que pueda hacer seguimiento a su caso cuando quiera.", s: "Cuando entregas un código al cliente para que identifique su caso después.", sEn: "When you give the customer a code to identify their case later.", n: "Al dictar el número, di 'double seven' para '77' y deletrea las letras para evitar errores.", nEn: "When reading the number, say 'double seven' for '77' and spell out letters to avoid mistakes." },
    "loc-bpo14": { e: "Can I help you with anything else today, or are you all set?", t: "¿Puedo ayudarle en algo más hoy, o quedó todo resuelto?", s: "Justo antes de cerrar la llamada, para asegurarte de que no falta nada.", sEn: "Right before closing the call, to make sure nothing is left undone.", n: "'Are you all set?' es una forma natural de preguntar '¿ya quedó todo listo?'.", nEn: "'Are you all set?' is a natural way to ask if everything is taken care of." },
    "loc-bpo15": { e: "Thank you for your time, and thanks for your patience while we looked into it.", t: "Gracias por su tiempo, y gracias por su paciencia mientras lo revisábamos.", s: "Al final de la llamada, para agradecer al cliente antes de despedirte.", sEn: "At the end of the call, to thank the customer before saying goodbye.", n: "Combínalo con 'for your patience' cuando la llamada fue larga; suena muy profesional.", nEn: "Pair it with 'for your patience' when the call was long; it sounds very professional." },
    "loc-bpo16": { e: "Have a wonderful day, and don't hesitate to call us back if you need anything.", t: "Que tenga un excelente día, y no dude en volver a llamarnos si necesita algo.", s: "La frase de despedida final cuando cuelgas con el cliente.", sEn: "The final goodbye line when you hang up with the customer.", n: "Varía con 'Have a great day' o 'Take care' para no sonar siempre igual.", nEn: "Vary it with 'Have a great day' or 'Take care' so you don't always sound the same." },
    // ===================== Tech & software (tech-en) =====================
    "loc-tech01": { e: "I'm blocked by a bug in the login flow, so I can't finish the feature yet.", t: "Estoy bloqueado por un error en el flujo de login, así que aún no puedo terminar la función.", s: "En el standup, cuando explicas que un error no te deja avanzar.", sEn: "In standup, when you explain a bug is stopping your progress.", n: "'Bug' es el término normal para un error de software; 'blocked' significa que no puedes seguir.", nEn: "'Bug' is the normal word for a software error; 'blocked' means you can't move forward." },
    "loc-tech02": { e: "I pushed the change, can you review it when you get a minute?", t: "Subí el cambio, ¿lo revisas cuando tengas un momento?", s: "Cuando terminaste tu código y le pides a un compañero que revise el pull request.", sEn: "When you've finished your code and ask a teammate to review the pull request.", n: "'Push' (subir al repositorio) se pronuncia 'push', no 'pus'; agrega 'PR' si quieres ser exacto.", nEn: "'Push' (to the repo) rhymes with 'bush'; add 'PR' if you want to be precise." },
    "loc-tech03": { e: "I'll deploy it to production today once the tests pass.", t: "Lo despliego a producción hoy, una vez que pasen las pruebas.", s: "Cuando avisas al equipo que vas a poner tu cambio en vivo para los usuarios.", sEn: "When you tell the team you'll release your change live for users.", n: "'Production' (o 'prod') es el ambiente real; cuidado, no es lo mismo que 'staging'.", nEn: "'Production' (or 'prod') is the live environment; don't confuse it with 'staging'." },
    "loc-tech04": { e: "I need more time for this; it's more complicated than we expected.", t: "Necesito más tiempo para esto; es más complicado de lo que esperábamos.", s: "Cuando una tarea va a tardar más de lo planeado y debes avisarlo.", sEn: "When a task will take longer than planned and you need to flag it.", n: "Explicar el porqué ('it's more complicated...') hace que pedir más tiempo suene profesional.", nEn: "Adding the reason ('it's more complicated...') makes asking for more time sound professional." },
    "loc-tech05": { e: "In today's standup I'll share where I am and what's blocking me.", t: "En el standup de hoy voy a contar en qué voy y qué me está bloqueando.", s: "Al empezar tu turno en la reunión diaria del equipo.", sEn: "When starting your turn in the team's daily meeting.", n: "El 'standup' es la reunión rápida diaria; di las tres cosas: ayer, hoy y bloqueos.", nEn: "The 'standup' is the quick daily meeting; cover three things: yesterday, today, and blockers." },
    "loc-tech06": { e: "Yesterday I finished the task and opened a pull request for review.", t: "Ayer terminé la tarea y abrí un pull request para revisión.", s: "En el standup, al contar lo que lograste el día anterior.", sEn: "In standup, when reporting what you accomplished the day before.", n: "Con 'yesterday' usa pasado simple: 'finished', no 'I have finished'.", nEn: "With 'yesterday' use the simple past: 'finished', not 'I have finished'." },
    "loc-tech07": { e: "Today I'm working on the login, and I hope to have it done by lunch.", t: "Hoy trabajo en el login, y espero tenerlo listo para el almuerzo.", s: "En el standup, al contar en qué te vas a enfocar hoy.", sEn: "In standup, when saying what you'll focus on today.", n: "Usa 'I'm working on' (presente continuo) para algo que está en curso ahora.", nEn: "Use 'I'm working on' (present continuous) for something in progress right now." },
    "loc-tech08": { e: "Can you merge my branch once the review is approved?", t: "¿Puedes hacer merge de mi rama cuando se apruebe la revisión?", s: "Cuando tu código ya fue revisado y pides combinarlo con la rama principal.", sEn: "When your code has been reviewed and you ask to combine it into the main branch.", n: "'Merge' rima con 'urge': termina en 'j' suave inglesa (como en 'George'), no en 'ch'; 'branch' es 'rama' (de código), no de árbol literal.", nEn: "'Merge' rhymes with 'urge': it ends in a soft 'j' sound (like 'George'), not the 'ch' of 'merch'; 'branch' here means a code branch, not a tree." },
    "loc-tech09": { e: "I have a meeting at ten, so let's keep this standup short.", t: "Tengo una reunión a las diez, así que hagamos este standup corto.", s: "Cuando avisas que tienes poco tiempo por otro compromiso.", sEn: "When you flag that you're short on time due to another commitment.", n: "Di 'at ten' para la hora; agregar 'a.m.' solo si puede haber confusión.", nEn: "Say 'at ten' for the time; add 'a.m.' only if there could be confusion." },
    "loc-tech10": { e: "The test is failing, so I'm looking into it before I merge anything.", t: "El test está fallando, así que lo estoy revisando antes de hacer merge.", s: "Cuando reportas que una prueba automática no pasa y estás investigando.", sEn: "When you report that an automated test isn't passing and you're investigating.", n: "'Is failing' (continuo) indica que sigue fallando ahora; 'looking into it' = investigando.", nEn: "'Is failing' (continuous) means it's still failing now; 'looking into it' means investigating." },
    "loc-tech11": { e: "Don't worry, I'll fix it and let you know as soon as it's working again.", t: "No te preocupes, lo arreglo y te aviso apenas vuelva a funcionar.", s: "Cuando un compañero reporta un error y tú te haces cargo de resolverlo.", sEn: "When a colleague reports a bug and you take charge of fixing it.", n: "\"Let you know\" suena más natural que \"I will inform you\", que es muy formal.", nEn: "\"Let you know\" sounds more natural than the very formal \"I will inform you\"." },
    "loc-tech12": { e: "Before I start, can you share the documentation so I understand the setup?", t: "Antes de empezar, ¿me compartes la documentación para entender la configuración?", s: "Cuando necesitas las instrucciones o guías técnicas para hacer una tarea.", sEn: "When you need the technical guides or instructions to do a task.", n: "Puedes decir \"share the docs\" de forma informal entre desarrolladores.", nEn: "You can say \"share the docs\" informally among developers." },
    "loc-tech13": { e: "I agree with the plan, but let's add one more day for testing.", t: "Estoy de acuerdo con el plan, pero agreguemos un día más para pruebas.", s: "Cuando aceptas una propuesta en una reunión pero quieres sugerir un ajuste.", sEn: "When you accept a proposal in a meeting but want to suggest a tweak.", n: "\"Agree\" se dice solo (no \"I am agree\"); evita ese error muy común.", nEn: "Say just \"agree\" (not \"I am agree\"); avoid that very common mistake." },
    "loc-tech14": { e: "I need access to the repo before I can push my changes.", t: "Necesito acceso al repositorio para poder subir mis cambios.", s: "Cuando le pides permisos a tu líder para entrar al código del proyecto.", sEn: "When you ask your lead for permission to enter the project's code.", n: "\"Repo\" es la forma corta y normal de decir \"repository\".", nEn: "\"Repo\" is the short, normal way to say \"repository\"." },
    "loc-tech15": { e: "Before we start, what's the priority for this sprint?", t: "Antes de empezar, ¿cuál es la prioridad para este sprint?", s: "Cuando quieres saber qué tarea es la más urgente para enfocarte primero.", sEn: "When you want to know which task is most urgent so you focus on it first.", n: "Pronuncia \"priority\" como \"prai-O-ri-ti\", no \"pri-o-ri-DAD\".", nEn: "Pronounce \"priority\" as \"prai-O-ri-ti\", not Spanish-style." },
    "loc-tech16": { e: "Good job, team, we shipped it on time.", t: "Buen trabajo, equipo, lo entregamos a tiempo.", s: "Cuando felicitas al grupo después de terminar un proyecto o entrega.", sEn: "When you congratulate the group after finishing a project or delivery.", n: "\"Great job\" o \"nice work\" son variantes igual de comunes.", nEn: "\"Great job\" or \"nice work\" are equally common variants." },
    // ===================== Video calls (videocall-en) =====================
    "loc-vc01": { e: "Sorry to interrupt, but you're on mute, we can't hear you.", t: "Perdón por interrumpir, pero tienes el micrófono apagado, no te oímos.", s: "Cuando alguien habla en una videollamada pero su micrófono está silenciado.", sEn: "When someone talks on a video call but their mic is muted.", n: "\"On mute\" es la frase fija; no digas \"your microphone is closed\".", nEn: "\"On mute\" is the fixed phrase; don't say \"your microphone is closed\"." },
    "loc-vc02": { e: "I'm sharing my screen now, let me know when you can see it.", t: "Comparto mi pantalla ahora, avísenme cuando la vean.", s: "Cuando vas a mostrar una presentación o documento en la videollamada.", sEn: "When you're about to show a presentation or document on the video call.", n: "Usa el presente continuo \"I'm sharing\" para algo que pasa justo ahora.", nEn: "Use the present continuous \"I'm sharing\" for something happening right now." },
    "loc-vc03": { e: "Sorry, you're breaking up, could you say that again?", t: "Perdón, se te corta, ¿puedes repetir eso?", s: "Cuando la voz de alguien se escucha entrecortada por mala conexión.", sEn: "When someone's voice sounds choppy because of a bad connection.", n: "\"Breaking up\" es para audio entrecortado; \"dropped\" es cuando se cae del todo.", nEn: "\"Breaking up\" is for choppy audio; \"dropped\" is when it cuts off completely." },
    "loc-vc04": { e: "I think you're muted, we can see you talking but there's no sound.", t: "Creo que estás en silencio, te vemos hablar pero no hay sonido.", s: "Cuando ves a alguien mover la boca pero no se escucha nada.", sEn: "When you see someone's mouth moving but hear nothing.", n: "\"You're muted\" y \"you're on mute\" significan lo mismo.", nEn: "\"You're muted\" and \"you're on mute\" mean the same thing." },
    "loc-vc05": { e: "That's a great point, let's circle back to that after the demo.", t: "Buen punto, lo retomamos luego, después de la demo.", s: "Cuando quieres posponer un tema para tratarlo más adelante en la reunión.", sEn: "When you want to postpone a topic to discuss it later in the meeting.", n: "\"Circle back\" es muy usado en oficinas; \"come back to it\" es más simple.", nEn: "\"Circle back\" is very common in offices; \"come back to it\" is simpler." },
    "loc-vc06": { e: "Turn off your camera if you like, the connection might improve.", t: "Apaga la cámara si quieres, puede mejorar la conexión.", s: "Cuando sugieres apagar el video para que la llamada vaya más fluida.", sEn: "When you suggest turning off video so the call runs smoother.", n: "\"If you like\" suena más amable que dar la orden directa \"turn it off\".", nEn: "\"If you like\" sounds kinder than the direct order \"turn it off\"." },
    "loc-vc07": { e: "Sorry, my connection dropped, what did I miss?", t: "Disculpen, se cayó mi conexión, ¿qué me perdí?", s: "Cuando vuelves a la llamada después de quedarte sin internet.", sEn: "When you rejoin the call after losing your internet.", n: "\"Dropped\" es el verbo natural para una conexión que se cae.", nEn: "\"Dropped\" is the natural verb for a connection that cuts out." },
    "loc-vc08": { e: "I had some issues earlier, can you hear me okay now?", t: "Tuve problemas antes, ¿me oyen bien ahora?", s: "Cuando regresas a la llamada y quieres confirmar que tu audio funciona.", sEn: "When you return to the call and want to confirm your audio works.", n: "\"Okay\" aquí significa \"bien\"; también puedes decir \"can you hear me now?\".", nEn: "\"Okay\" here means \"fine\"; you can also just say \"can you hear me now?\"." },
    "loc-vc09": { e: "To cut the background noise, let's mute when we're not talking.", t: "Para reducir el ruido de fondo, pongámonos en silencio cuando no hablemos.", s: "Cuando hay mucho ruido y propones silenciar los micrófonos.", sEn: "When there's a lot of noise and you suggest muting the mics.", n: "\"Let's\" (let us) sirve para hacer una sugerencia grupal amable.", nEn: "\"Let's\" (let us) is used to make a friendly group suggestion." },
    "loc-vc10": { e: "Please turn up the volume, you sound very quiet on my end.", t: "Sube el volumen, por favor, te escuchas muy bajito de mi lado.", s: "Cuando alguien se oye muy bajo y le pides que suba su micrófono o volumen.", sEn: "When someone is too quiet and you ask them to raise their volume.", n: "Lo contrario es \"turn down the volume\" (bajar el volumen).", nEn: "The opposite is \"turn down the volume\" (lower the volume)." },
    "loc-vc11": { e: "I'll drop the link in the chat so everyone can open it.", t: "Comparto el enlace en el chat para que todos puedan abrirlo.", s: "Cuando pones un enlace en el chat de la videollamada para el grupo.", sEn: "When you put a link in the video call chat for the group.", n: "\"Drop the link\" es informal y muy usado; \"share the link\" es neutral.", nEn: "\"Drop the link\" is informal and very common; \"share the link\" is neutral." },
    "loc-vc12": { e: "Thanks everyone, see you at the next call.", t: "Gracias a todos, nos vemos en la próxima llamada.", s: "Cuando cierras una reunión virtual y te despides del grupo.", sEn: "When you close a virtual meeting and say goodbye to the group.", n: "\"See you\" suena más cálido que un \"goodbye\" seco al terminar.", nEn: "\"See you\" sounds warmer than a flat \"goodbye\" at the end." },
    // ===================== Sales & pitch (ventas-pro) =====================
    "loc-vp01": { e: "Our product saves you time by automating the boring tasks.", t: "Nuestro producto le ahorra tiempo al automatizar las tareas aburridas.", s: "Cuando presentas tu producto y destacas su principal beneficio al cliente.", sEn: "When you pitch your product and highlight its main benefit to the client.", n: "\"Saves you time\" pone al cliente en el centro; suena más persuasivo.", nEn: "\"Saves you time\" puts the client at the center; it sounds more persuasive." },
    "loc-vp02": { e: "Can I show you a demo? It only takes five minutes.", t: "¿Le muestro una demostración? Solo toma cinco minutos.", s: "Cuando ofreces una demostración rápida para convencer a un cliente potencial.", sEn: "When you offer a quick demo to convince a potential client.", n: "\"Demo\" es la forma corta y normal de \"demonstration\" en ventas.", nEn: "\"Demo\" is the short, normal form of \"demonstration\" in sales." },
    "loc-vp03": { e: "I'll follow up tomorrow with a quote and a couple of options.", t: "Le hago seguimiento mañana con una cotización y un par de opciones.", s: "Cuando cierras una llamada de ventas y prometes contactar al cliente al día siguiente.", sEn: "When you end a sales call and promise to contact the customer the next day.", n: "\"Follow up\" se pronuncia \"fólou-ap\" y suena más profesional que \"I'll contact you\".", nEn: "\"Follow up\" is pronounced \"FOL-oh-up\" and sounds more professional than \"I'll contact you.\"" },
    "loc-vp04": { e: "This solves your problem because it cuts your waiting time in half.", t: "Esto resuelve su problema porque reduce a la mitad su tiempo de espera.", s: "Cuando presentas un producto y quieres mostrar el beneficio directo para el cliente.", sEn: "When you present a product and want to show the direct benefit to the customer.", n: "Di \"this solves\" y no \"this resolves\"; en ventas \"solve\" suena más natural.", nEn: "Say \"this solves,\" not \"this resolves\"; \"solve\" sounds more natural in sales." },
    "loc-vp05": { e: "What's your budget so I can recommend the right option for you?", t: "¿Cuál es su presupuesto para poder recomendarle la opción adecuada?", s: "Cuando necesitas saber cuánto puede gastar el cliente antes de ofrecerle algo.", sEn: "When you need to know how much the customer can spend before offering something.", n: "\"Budget\" se dice \"BÁ-yet\" con sonido de 'y' fuerte (como la j inglesa de \"jam\"); para sonar más suave agrega \"if you don't mind me asking\".", nEn: "\"Budget\" is said \"BUH-jit\" with a soft 'g' (like the English j in \"jam\"); to soften the question, add \"if you don't mind me asking.\"" },
    "loc-vp06": { e: "I'll send you a proposal by email this afternoon.", t: "Le envío una propuesta por correo esta tarde.", s: "Cuando acuerdas con el cliente mandarle una oferta formal por escrito.", sEn: "When you agree to send the customer a formal written offer.", n: "\"Proposal\" lleva el acento en la segunda sílaba: \"pro-PÓU-zal\".", nEn: "\"Proposal\" is stressed on the second syllable: \"pro-POH-zal.\"" },
    "loc-vp07": { e: "We have a special offer this week if you order today.", t: "Tenemos una oferta especial esta semana si ordena hoy.", s: "Cuando quieres animar al cliente a comprar con una promoción por tiempo limitado.", sEn: "When you want to encourage the customer to buy with a limited-time promotion.", n: "\"Offer\" se dice \"ófer\", no \"ofér\"; añadir \"this week\" crea sensación de urgencia.", nEn: "\"Offer\" is stressed on the first syllable, \"OF-er,\" not \"of-ER\"; adding \"this week\" creates a sense of urgency." },
    "loc-vp08": { e: "Want to give it a try for free for a week, no commitment?", t: "¿Le interesa probarlo gratis por una semana, sin compromiso?", s: "Al ofrecer una prueba gratuita de un producto o servicio.", sEn: "When offering a free trial of a product or service.", n: "\"Give it a try\" suena cercano y sin presión.", nEn: "\"Give it a try\" sounds friendly and low-pressure." },
    "loc-vp09": { e: "I'd be happy to explain the plans and help you pick the best one.", t: "Con gusto le explico los planes y le ayudo a elegir el mejor.", s: "Cuando el cliente duda entre varias opciones y te ofreces a aclararlas.", sEn: "When the customer hesitates between options and you offer to clarify them.", n: "\"I'd be happy to\" es la forma cortés estándar; evita el literal \"with pleasure\".", nEn: "\"I'd be happy to\" is the standard polite phrase; avoid the literal \"with pleasure.\"" },
    "loc-vp10": { e: "It's cheaper in the long run because you save on repairs.", t: "Es más barato a largo plazo porque ahorra en reparaciones.", s: "Cuando justificas un precio más alto explicando el ahorro futuro.", sEn: "When you justify a higher price by explaining future savings.", n: "\"In the long run\" es la frase fija; no digas \"in the long term\" en conversación de ventas.", nEn: "\"In the long run\" is the set phrase; \"in the long term\" is stiffer in sales talk." },
    "loc-vp11": { e: "Thank you for your interest; I'll be in touch soon.", t: "Gracias por su interés; estaré en contacto pronto.", s: "Cuando cierras la conversación con un cliente potencial de forma amable.", sEn: "When you politely close a conversation with a potential customer.", n: "\"Interest\" se dice \"ÍN-trest\", con dos sílabas, no tres.", nEn: "\"Interest\" is said \"IN-trest,\" two syllables, not three." },
    "loc-vp12": { e: "Shall we move forward with the contract today?", t: "¿Avanzamos con el contrato hoy?", s: "Cuando el cliente está convencido y quieres cerrar el trato.", sEn: "When the customer is convinced and you want to close the deal.", n: "\"Shall we\" suena formal y profesional; en EE. UU. también sirve \"Should we move forward\".", nEn: "\"Shall we\" sounds professional; in the US \"Should we move forward\" also works." },
    // ===================== Finance & billing (finanzas-en) =====================
    "loc-fin01": { e: "The invoice is due on Friday, so please pay before then.", t: "La factura vence el viernes, así que por favor pague antes.", s: "Cuando le recuerdas a un cliente o colega la fecha de pago de una factura.", sEn: "When you remind a client or colleague of an invoice payment date.", n: "\"Due\" se dice \"diú\"; \"invoice\" es la factura comercial, distinta de \"receipt\" (recibo).", nEn: "\"Due\" is pronounced \"doo/dyoo\"; \"invoice\" is the bill you send; \"receipt\" is the proof after payment." },
    "loc-fin02": { e: "The budget is tight this month, so let's keep costs down.", t: "El presupuesto es limitado este mes, así que bajemos los costos.", s: "Cuando explicas en el trabajo que hay poco dinero disponible.", sEn: "When you explain at work that there's little money available.", n: "\"Tight\" (apretado) es lo natural para \"limitado\"; evita el literal \"limited budget\".", nEn: "\"Tight\" is the natural word here; \"limited budget\" sounds stiffer." },
    "loc-fin03": { e: "The payment is still pending, so I'll check with accounting.", t: "El pago aún está pendiente, así que reviso con contabilidad.", s: "Cuando un pago no se ha procesado y avisas que vas a verificarlo.", sEn: "When a payment hasn't gone through and you say you'll verify it.", n: "\"Pending\" se pronuncia \"PEN-ding\"; agregar \"still\" enfatiza que sigue sin resolverse.", nEn: "\"Pending\" is pronounced \"PEN-ding\"; adding \"still\" emphasizes that it remains unresolved." },
    "loc-fin04": { e: "I'll send the receipt to your email right away.", t: "Le envío el comprobante a su correo enseguida.", s: "Cuando el cliente ya pagó y le confirmas que recibirá el comprobante.", sEn: "When the customer has paid and you confirm they'll get the receipt.", n: "\"Receipt\" se dice \"ri-SÍIT\"; la 'p' es muda.", nEn: "In \"receipt\" the 'p' is silent: \"ri-SEET.\"" },
    "loc-fin05": { e: "Can we pay by transfer instead of cash?", t: "¿Podemos pagar por transferencia en lugar de efectivo?", s: "Cuando preguntas si se acepta pago por transferencia bancaria.", sEn: "When you ask whether bank transfer payment is accepted.", n: "Se dice \"pay by transfer\", con \"by\", no \"pay for transfer\".", nEn: "Say \"pay by transfer,\" with \"by,\" not \"pay for transfer.\"" },
    "loc-fin06": { e: "I need the invoice with tax included for my company.", t: "Necesito la factura con impuestos incluidos para mi empresa.", s: "Cuando pides una factura formal que detalle los impuestos.", sEn: "When you request a formal invoice that itemizes the tax.", n: "En EE. UU. se dice \"tax\"; en otros países \"VAT\"; \"with tax\" cubre ambos casos.", nEn: "Say \"tax\" in the US or \"VAT\" elsewhere; \"with tax\" works generally." },
    "loc-fin07": { e: "We close the month on the thirtieth, so send your expenses by then.", t: "Cerramos el mes el día treinta, así que manda tus gastos antes.", s: "Cuando informas a colegas hasta qué día se reciben gastos del mes.", sEn: "When you tell colleagues the cutoff day for the month's expenses.", n: "\"Thirtieth\" se dice \"THÉR-ti-eth\"; practica el sonido 'th' para no decir \"tirty\".", nEn: "Practice the 'th' in \"thirtieth\" so it doesn't sound like \"tirty.\"" },
    "loc-fin08": { e: "How much do we owe you for last month?", t: "¿Cuánto le debemos del mes pasado?", s: "Cuando preguntas a un proveedor el monto pendiente por pagar.", sEn: "When you ask a supplier the outstanding amount to pay.", n: "\"Owe\" se pronuncia igual que \"oh\"; la 'w' es muda.", nEn: "\"Owe\" sounds just like \"oh\"; the 'w' is silent." },
    "loc-fin09": { e: "It's within budget, so we can go ahead and order it.", t: "Está dentro del presupuesto, así que podemos seguir y pedirlo.", s: "Cuando confirmas que un gasto cabe en el dinero disponible.", sEn: "When you confirm that a cost fits the available money.", n: "\"Within budget\" es la frase fija; no digas \"inside the budget\".", nEn: "\"Within budget\" is the set phrase; don't say \"inside the budget.\"" },
    "loc-fin10": { e: "Let's review the expenses before we close the report.", t: "Revisemos los gastos antes de cerrar el informe.", s: "Cuando propones a tu equipo revisar juntos los gastos.", sEn: "When you suggest the team go over the expenses together.", n: "\"Let's review\" suena más colaborativo que \"check\".", nEn: "\"Let's review\" sounds more collaborative than \"check.\"" },
    "loc-fin11": { e: "The report is ready, I'll send it over before lunch.", t: "El reporte está listo, te lo envío antes del almuerzo.", s: "Cuando le avisas a tu jefe o cliente que terminaste un informe.", sEn: "When you tell your boss or client that you've finished a report.", n: "Para sonar más formal en correos di \"The report is now ready for your review\".", nEn: "To sound more formal in emails, say \"The report is now ready for your review\"." },
    "loc-fin12": { e: "Good news, the payment was approved, so we can ship right away.", t: "Buenas noticias, el pago fue aprobado, así que podemos enviar de inmediato.", s: "Cuando confirmas que un cobro o transacción pasó sin problema.", sEn: "When you confirm that a charge or transaction went through without issues.", n: "\"Approved\" se pronuncia \"aPRUVD\", con la d final suave, no \"aprobed\".", nEn: "\"Approved\" sounds like \"aPRUVD\", with a soft final d, not \"aprobed\"." },
    // ===================== Logistics & shipping (logistica-en) =====================
    "loc-log01": { e: "Don't worry, the order ships today and you'll have it by Friday.", t: "No se preocupe, el pedido sale hoy y lo tendrá para el viernes.", s: "Cuando le confirmas a un cliente que su pedido se despacha el mismo día.", sEn: "When you confirm to a customer that their order goes out the same day.", n: "También puedes decir \"the order is going out today\" para sonar más natural.", nEn: "You can also say \"the order is going out today\" to sound more natural." },
    "loc-log02": { e: "Here's the tracking number so you can follow your package online.", t: "Aquí está el número de rastreo para que siga su paquete en línea.", s: "Cuando le das al cliente el código para seguir su envío.", sEn: "When you give the customer the code to track their shipment.", n: "\"Tracking\" se dice \"TRA-king\"; evita pronunciar la c como en español.", nEn: "\"Tracking\" is said \"TRA-king\"; avoid pronouncing the c the Spanish way." },
    "loc-log03": { e: "Good news, it cleared customs this morning, so it should arrive soon.", t: "Buenas noticias, pasó por la aduana esta mañana, así que debería llegar pronto.", s: "Cuando informas que un envío internacional ya salió de la aduana.", sEn: "When you report that an international shipment has left customs.", n: "Se dice \"cleared customs\", no \"passed customs\"; \"customs\" siempre va en plural.", nEn: "Say \"cleared customs\", not \"passed customs\"; \"customs\" is always plural." },
    "loc-log04": { e: "Delivery takes three days, but it's usually a bit faster.", t: "La entrega tarda tres días, pero normalmente es un poco más rápido.", s: "Cuando le explicas al cliente cuánto demora recibir su pedido.", sEn: "When you explain to the customer how long their order takes to arrive.", n: "También suena natural \"it takes three days to deliver\".", nEn: "It also sounds natural to say \"it takes three days to deliver\"." },
    "loc-log05": { e: "The package is on its way and should reach you tomorrow.", t: "El paquete está en camino y debería llegarle mañana.", s: "Cuando tranquilizas a un cliente que pregunta dónde está su pedido.", sEn: "When you reassure a customer asking where their order is.", n: "Cuidado: es \"on its way\" (sin apóstrofo), no \"on it's way\".", nEn: "Careful: it's \"on its way\" (no apostrophe), not \"on it's way\"." },
    "loc-log06": { e: "I need the shipping address before I can send this out.", t: "Necesito la dirección de envío antes de poder despachar esto.", s: "Cuando le pides al cliente a dónde debe llegar el paquete.", sEn: "When you ask the customer where the package should be delivered.", n: "Para ser más cortés di \"Could you give me the shipping address?\".", nEn: "To be more polite, say \"Could you give me the shipping address?\"." },
    "loc-log07": { e: "I'm sorry, the shipment was delayed and will arrive a day late.", t: "Lo siento, el embarque se retrasó y llegará un día tarde.", s: "Cuando avisas que un envío llegará más tarde de lo previsto.", sEn: "When you let someone know a shipment will arrive later than planned.", n: "\"Delayed\" se pronuncia \"di-LEID\"; no olvides la d final.", nEn: "\"Delayed\" is said \"di-LEID\"; don't drop the final d." },
    "loc-log08": { e: "Please confirm the quantity so we don't ship the wrong amount.", t: "Confirme la cantidad, por favor, para no enviar la cantidad equivocada.", s: "Cuando necesitas que el cliente verifique cuántas unidades quiere.", sEn: "When you need the customer to verify how many units they want.", n: "\"Quantity\" se dice \"KUAN-ti-ti\"; ojo con no decir \"cuantity\".", nEn: "\"Quantity\" is said \"KUAN-ti-ti\"; don't say \"cuantity\"." },
    "loc-log09": { e: "The container arrives on Monday, so let's plan the unloading.", t: "El contenedor llega el lunes, así que organicemos la descarga.", s: "Cuando coordinas con tu equipo la llegada de un cargamento grande.", sEn: "When you coordinate with your team about a large shipment arriving.", n: "En inglés se usa \"on\" con días: \"on Monday\", no \"the Monday\".", nEn: "In English use \"on\" with days: \"on Monday\", not \"the Monday\"." },
    "loc-log10": { e: "What's the total weight? I need it to calculate the freight cost.", t: "¿Cuál es el peso total? Lo necesito para calcular el costo de flete.", s: "Cuando preguntas cuánto pesa todo el envío para cotizar.", sEn: "When you ask how much the whole shipment weighs in order to quote.", n: "\"Weight\" suena como \"ueit\"; la w no se pronuncia como gu.", nEn: "\"Weight\" sounds like \"ueit\"; the w isn't a hard g sound." },
    "loc-log11": { e: "I'm attaching the shipping invoice for your records.", t: "Adjunto la factura de envío para sus registros.", s: "Cuando mandas por correo la factura del transporte al cliente.", sEn: "When you email the shipping invoice to the customer.", n: "En correos también se usa \"Please find attached the shipping invoice\".", nEn: "In emails you can also use \"Please find attached the shipping invoice\"." },
    "loc-log12": { e: "Shipping is free on all orders over fifty dollars.", t: "El envío es gratis en todos los pedidos de más de cincuenta dólares.", s: "Cuando le dices al cliente que no paga costo de envío.", sEn: "When you tell the customer there's no delivery charge.", n: "También se dice \"free shipping\". En inglés suena más natural decir \"free\" que \"no charge\".", nEn: "You can also say \"free shipping\". In English \"free\" sounds more natural than \"no charge\"." },
    // ===================== HR & feedback (feedback-en) =====================
    "loc-fb01": { e: "Great job this week, the whole team noticed your effort.", t: "Buen trabajo esta semana, todo el equipo notó tu esfuerzo.", s: "Cuando reconoces el buen desempeño de un compañero o empleado.", sEn: "When you acknowledge a coworker's or employee's good performance.", n: "Variantes naturales: \"Nice work\" o \"Well done this week\".", nEn: "Natural variants: \"Nice work\" or \"Well done this week\"." },
    "loc-fb02": { e: "Let's set a goal for next month and check in on it weekly.", t: "Pongámonos una meta para el próximo mes y revisémosla cada semana.", s: "Cuando propones un objetivo en una reunión con tu equipo o jefe.", sEn: "When you propose an objective in a meeting with your team or boss.", n: "\"Goal\" se pronuncia \"goul\", con una sola sílaba.", nEn: "\"Goal\" is pronounced \"goul\", as one syllable." },
    "loc-fb03": { e: "How do you feel about your workload? I want to make sure it's manageable.", t: "¿Cómo te sientes con tu carga de trabajo? Quiero asegurarme de que sea manejable.", s: "Cuando preguntas a un empleado si tiene demasiadas tareas.", sEn: "When you ask an employee whether they have too much on their plate.", n: "\"Workload\" significa carga de trabajo; no la confundas con \"workplace\".", nEn: "\"Workload\" means amount of work; don't confuse it with \"workplace\"." },
    "loc-fb04": { e: "You're doing really well, so keep it up!", t: "Lo estás haciendo muy bien, ¡así que sigue así!", s: "Cuando animas a alguien a mantener su buen rendimiento.", sEn: "When you encourage someone to maintain their good performance.", n: "\"Keep it up\" es informal y cálido; en un correo formal usa \"keep up the good work\".", nEn: "\"Keep it up\" is informal and warm; in a formal email use \"keep up the good work\"." },
    "loc-fb05": { e: "You did great overall, but here's something to improve for next time.", t: "En general lo hiciste muy bien, pero aquí hay algo que mejorar para la próxima.", s: "Cuando das una crítica constructiva sin desmotivar a la persona.", sEn: "When you give constructive criticism without discouraging the person.", n: "Suaviza la crítica empezando con algo positivo antes del \"but\".", nEn: "Soften the criticism by starting with something positive before \"but\"." },
    "loc-fb06": { e: "I appreciate your effort, especially during such a busy week.", t: "Valoro tu esfuerzo, sobre todo en una semana tan ocupada.", s: "Cuando agradeces sinceramente la dedicación de alguien.", sEn: "When you sincerely thank someone for their dedication.", n: "\"Appreciate\" se pronuncia \"a-PRI-shi-eit\"; no digas \"apreciate\".", nEn: "\"Appreciate\" is said \"a-PRI-shi-eit\"; don't say \"apreciate\"." },
    "loc-fb07": { e: "Before we wrap up, do you have any concerns about the new schedule?", t: "Antes de terminar, ¿tienes alguna inquietud sobre el nuevo horario?", s: "Cuando cierras una reunión con un empleado y quieres darle espacio para hablar.", sEn: "When you close a meeting with an employee and want to give them room to speak up.", n: "\"Concerns\" suena más profesional que \"problems\"; usa \"problems\" solo para algo ya roto.", nEn: "\"Concerns\" sounds more professional than \"problems\"; save \"problems\" for things already broken." },
    "loc-fb08": { e: "Let's talk about your goals for the next six months.", t: "Hablemos de tus objetivos para los próximos seis meses.", s: "Al iniciar una evaluación de desempeño con alguien de tu equipo.", sEn: "When starting a performance review with someone on your team.", n: "\"Goals\" se pronuncia \"gols\", con la G dura de \"go\", no como la J española.", nEn: "\"Goals\" is pronounced \"gols\" with a hard G like in \"go\", not like the Spanish J." },
    "loc-fb09": { e: "Thank you for your work this month, the team really noticed it.", t: "Gracias por tu trabajo este mes, el equipo de verdad lo notó.", s: "Cuando reconoces el esfuerzo de un empleado al final de un periodo.", sEn: "When you recognize an employee's effort at the end of a period.", n: "Añadir un detalle concreto (\"this month\") hace que el agradecimiento se sienta sincero.", nEn: "Adding a concrete detail (\"this month\") makes the thanks feel genuine." },
    "loc-fb10": { e: "If anything comes up, just let me know, you have my support.", t: "Si surge cualquier cosa, solo avísame, cuentas con mi apoyo.", s: "Cuando tranquilizas a un miembro del equipo que enfrenta un reto.", sEn: "When reassuring a team member facing a challenge.", n: "También puedes decir \"I've got your back\", más cercano y de uso diario.", nEn: "You can also say \"I've got your back,\" which is warmer and very common." },
    // ===================== Networking (networking-en) =====================
    "loc-net01": { e: "Nice to meet you, what company do you work for?", t: "Mucho gusto, ¿en qué empresa trabajas?", s: "Al conocer a alguien en un evento de negocios y querer saber más.", sEn: "When meeting someone at a business event and wanting to know more.", n: "Di \"work for\", no \"work in\", cuando hablas del nombre de la empresa.", nEn: "Say \"work for,\" not \"work in,\" when naming the company." },
    "loc-net02": { e: "I'd love to stay in touch, let's connect on LinkedIn.", t: "Me encantaría seguir en contacto, conectemos en LinkedIn.", s: "Al despedirte de un contacto profesional que acabas de conocer.", sEn: "When saying goodbye to a professional contact you just met.", n: "\"Connect\" lleva el acento en la segunda sílaba: con-NECT.", nEn: "\"Connect\" is stressed on the second syllable: con-NECT." },
    "loc-net03": { e: "Here's my card, feel free to reach out anytime.", t: "Aquí tienes mi tarjeta, escríbeme cuando quieras.", s: "Al entregar tu tarjeta de presentación tras una buena charla.", sEn: "When handing over your business card after a good chat.", n: "\"Here's my card\" suena natural; evita el literal \"This is my card\".", nEn: "\"Here's my card\" sounds natural; avoid the literal \"This is my card.\"" },
    "loc-net04": { e: "Glad to run into you here, it's been ages!", t: "Me alegra coincidir contigo aquí, ¡hacía mucho!", s: "Cuando te encuentras por casualidad con un conocido en un evento.", sEn: "When you bump into an acquaintance by chance at an event.", n: "\"Run into\" significa encontrarse por casualidad, no correr hacia algo.", nEn: "\"Run into\" means to meet by chance, not to run toward something." },
    "loc-net05": { e: "That sounds interesting, what does your job involve?", t: "Suena interesante, ¿de qué se trata tu trabajo?", s: "Cuando quieres que alguien te explique en qué consiste su puesto.", sEn: "When you want someone to explain what their role actually consists of.", n: "\"What does your job involve?\" es más rica que \"What is your job?\".", nEn: "\"What does your job involve?\" is richer than \"What is your job?\"" },
    "loc-net06": { e: "Do you come to these events often, or is this your first one?", t: "¿Vienes seguido a estos eventos, o es el primero?", s: "Para romper el hielo con alguien en una conferencia o feria.", sEn: "To break the ice with someone at a conference or fair.", n: "\"Often\" se puede pronunciar con la T muda: \"o-fen\".", nEn: "\"Often\" can be pronounced with a silent T: \"o-fen.\"" },
    "loc-net07": { e: "Your project is great, we should work together sometime.", t: "Tu proyecto está genial, deberíamos colaborar algún día.", s: "Cuando ves potencial para una alianza con otro profesional.", sEn: "When you see potential for a partnership with another professional.", n: "Agrega \"sometime\" para que suene a propuesta abierta, no a compromiso firme.", nEn: "Add \"sometime\" so it sounds like an open suggestion, not a firm commitment." },
    "loc-net08": { e: "Great talking with you, I'll message you next week with the details.", t: "Qué bueno hablar contigo, te escribo la próxima semana con los detalles.", s: "Al cerrar una conversación prometiendo dar seguimiento.", sEn: "When closing a conversation by promising to follow up.", n: "Cumple lo que prometes: enviar el mensaje fortalece la red de contactos.", nEn: "Follow through: actually sending the message is what builds your network." },
    "loc-net09": { e: "I loved your talk, especially the part about remote teams.", t: "Me encantó tu presentación, sobre todo la parte de los equipos remotos.", s: "Cuando te acercas a un ponente para felicitarlo después de su charla.", sEn: "When you approach a speaker to congratulate them after their talk.", n: "\"Talk\" aquí significa charla o presentación, no solo \"hablar\".", nEn: "Here \"talk\" means a presentation or speech, not just \"to talk.\"" },
    "loc-net10": { e: "It was great meeting you, let's keep in touch.", t: "Fue un gusto conocerte, mantengámonos en contacto.", s: "Al despedirte de alguien con quien quieres seguir en contacto.", sEn: "When parting from someone you'd like to stay connected with.", n: "Es \"keep in touch\", no \"keep in contact\", aunque ambos se entienden.", nEn: "It's \"keep in touch,\" not \"keep in contact,\" though both are understood." },
    // ===================== Healthcare staff (salud-pro-en) =====================
    "loc-hc01": { e: "Good morning, how are you feeling today?", t: "Buenos días, ¿cómo se siente hoy?", s: "Cuando un enfermero o médico saluda a un paciente al entrar.", sEn: "When a nurse or doctor greets a patient on coming in.", n: "Usa \"feeling\" para la salud; \"How are you?\" es solo un saludo general.", nEn: "Use \"feeling\" for health; \"How are you?\" is just a general greeting." },
    "loc-hc02": { e: "Can you show me where it hurts?", t: "¿Me puede mostrar dónde le duele?", s: "Cuando examinas a un paciente y necesitas ubicar el dolor.", sEn: "When examining a patient and you need to locate the pain.", n: "\"Hurt\" se pronuncia corto: \"hert\", con la R suave americana.", nEn: "\"Hurt\" is short: \"hert,\" with the soft American R." },
    "loc-hc03": { e: "How long have you had these symptoms, a few days or longer?", t: "¿Desde cuándo tiene estos síntomas, unos días o más?", s: "Al hacer la historia clínica de un paciente nuevo.", sEn: "When taking the medical history of a new patient.", n: "\"Symptoms\" se pronuncia \"SIMP-toms\"; la P sí suena.", nEn: "\"Symptoms\" is pronounced \"SIMP-tuhmz\"; the P is sounded." },
    "loc-hc04": { e: "Take a deep breath, please, and hold it for a second.", t: "Respire profundo, por favor, y sosténgalo un segundo.", s: "Cuando auscultas a un paciente con el estetoscopio.", sEn: "When listening to a patient's chest with a stethoscope.", n: "\"Breath\" (sustantivo) suena \"brez\"; \"breathe\" (verbo) suena \"briid\", con sonido suave de 'th' al final (como una 'd' suave), no 'z' ni 'v'.", nEn: "\"Breath\" (noun) sounds like \"breth\"; \"breathe\" (verb) sounds like \"breeth.\"" },
    "loc-hc05": { e: "Before I prescribe anything, are you allergic to any medication?", t: "Antes de recetar algo, ¿es alérgico a algún medicamento?", s: "Antes de dar un tratamiento o medicina a un paciente.", sEn: "Before giving a treatment or medicine to a patient.", n: "\"Allergic\" se pronuncia \"a-LER-yik\", con la G suave.", nEn: "\"Allergic\" is pronounced \"a-LER-jik,\" with a soft G." },
    "loc-hc06": { e: "I'm going to take your blood pressure, just relax your arm.", t: "Le voy a tomar la presión, solo relaje el brazo.", s: "Cuando un enfermero coloca el brazalete para medir la presión.", sEn: "When a nurse puts on the cuff to measure blood pressure.", n: "En inglés es \"take your blood pressure\", no \"measure\" en el habla diaria.", nEn: "In English it's \"take your blood pressure,\" not \"measure,\" in everyday speech." },
    "loc-hc07": { e: "You need some blood tests, so please don't eat anything before tomorrow morning.", t: "Necesita unos análisis de sangre, así que por favor no coma nada antes de mañana en la mañana.", s: "Cuando, como personal de salud, le explicas a un paciente que debe hacerse exámenes de laboratorio.", sEn: "When, as healthcare staff, you tell a patient they need lab work done.", n: "Se dice 'blood tests' en plural; pronuncia 'tests' con el sonido final '-ts' claro, no 'tes'.", nEn: "Say 'blood tests' in the plural, and pronounce the final '-ts' clearly, not just 'tes'." },
    "loc-hc08": { e: "Take this medicine twice a day, once in the morning and once at night.", t: "Tome este medicamento dos veces al día, una en la mañana y una en la noche.", s: "Cuando le indicas a un paciente cómo y cuándo debe tomar su tratamiento.", sEn: "When you tell a patient how and when to take their medication.", n: "Para otras frecuencias usa 'once a day' (una vez) o 'three times a day' (tres veces).", nEn: "For other frequencies use 'once a day' or 'three times a day'." },
    "loc-hc09": { e: "Don't worry, it's nothing serious, just a mild infection.", t: "No se preocupe, no es nada grave, solo una infección leve.", s: "Cuando tranquilizas a un paciente preocupado tras revisar su caso.", sEn: "When you reassure a worried patient after looking at their case.", n: "'Serious' aquí significa 'grave', no 'serio/formal'; acompáñalo con 'Don't worry' para calmar.", nEn: "Here 'serious' means 'grave', not 'formal'; pair it with 'Don't worry' to reassure." },
    "loc-hc10": { e: "Do you have health insurance, or will you be paying out of pocket?", t: "¿Tiene seguro médico, o va a pagar de su bolsillo?", s: "Cuando, en recepción o consulta, preguntas cómo se cubrirá la atención.", sEn: "When, at the front desk or in consultation, you ask how the care will be covered.", n: "'Health insurance' es lo más común; 'medical insurance' también es válido. 'Out of pocket' significa pagar uno mismo.", nEn: "'Health insurance' is the most common; 'medical insurance' is also valid. 'Out of pocket' means paying yourself." },
    "loc-hc11": { e: "I'll prescribe an antibiotic, and you should finish the whole course.", t: "Le voy a recetar un antibiótico, y debe terminar todo el tratamiento.", s: "Cuando decides recetar un medicamento y le explicas al paciente.", sEn: "When you decide to prescribe a medication and explain it to the patient.", n: "'Prescribe' (recetar) no es lo mismo que 'subscribe'; 'a course' es el ciclo completo del tratamiento.", nEn: "'Prescribe' is not 'subscribe', and 'a course' means the full treatment cycle." },
    "loc-hc12": { e: "Rest and drink fluids, and you'll feel better in a couple of days.", t: "Descanse y tome líquidos, y se sentirá mejor en un par de días.", s: "Cuando das recomendaciones sencillas para que el paciente se recupere en casa.", sEn: "When you give simple advice so the patient recovers at home.", n: "'Fluids' suena más profesional que 'liquids' al hablar de salud.", nEn: "'Fluids' sounds more professional than 'liquids' when talking about health." },
    "loc-hc13": { e: "If it gets worse, come back right away or go to the emergency room.", t: "Si empeora, vuelva de inmediato o vaya a urgencias.", s: "Cuando, al dar de alta a un paciente, le adviertes qué hacer si su estado empeora.", sEn: "When discharging a patient, you warn them what to do if their condition worsens.", n: "'Gets worse' es el comparativo correcto; evita decir 'gets more bad'.", nEn: "'Gets worse' is the correct comparative; avoid saying 'gets more bad'." },
    "loc-hc14": { e: "Take care of yourself, and get well soon.", t: "Cuídese, y que se mejore pronto.", s: "Cuando te despides de un paciente al final de la consulta.", sEn: "When you say goodbye to a patient at the end of the visit.", n: "'Get well soon' es para alguien que ya está enfermo; suena cálido y se usa mucho en tarjetas.", nEn: "'Get well soon' is for someone already ill; it sounds warm and is common on cards." },
    // ===================== False friends (falsos-amigos) =====================
    "loc-fa01": { e: "Congratulations, I heard your sister is pregnant!", t: "¡Felicidades, escuché que tu hermana está embarazada!", s: "Cuando comentas que alguien va a tener un bebé.", sEn: "When you mention that someone is going to have a baby.", n: "Cuidado: 'pregnant' es 'embarazada'; 'embarrassed' significa 'avergonzado', no lo confundas.", nEn: "Careful: 'pregnant' means 'embarazada'; 'embarrassed' means 'ashamed', don't mix them up." },
    "loc-fa02": { e: "I'm currently working at a hotel downtown.", t: "Actualmente estoy trabajando en un hotel en el centro.", s: "Cuando cuentas en qué trabajas o qué haces en este momento de tu vida.", sEn: "When you say what you do or where you are in life right now.", n: "'Currently' es 'actualmente'; 'actually' significa 'de hecho/en realidad', es un falso amigo clásico.", nEn: "'Currently' means 'actualmente'; 'actually' means 'in fact', a classic false friend." },
    "loc-fa03": { e: "I can't attend the meeting tomorrow, I have a doctor's appointment.", t: "No puedo asistir a la reunión mañana, tengo una cita médica.", s: "Cuando avisas que irás o no podrás ir a un evento o reunión.", sEn: "When you let someone know whether you'll be at an event or meeting.", n: "'Attend' es 'asistir a'; 'assist' significa 'ayudar', no lo uses para decir que vas a un lugar.", nEn: "'Attend' means 'to go to'; 'assist' means 'to help', don't use it for showing up somewhere." },
    "loc-fa04": { e: "There's a great bookstore around the corner if you're looking for a novel.", t: "Hay una librería muy buena a la vuelta de la esquina si busca una novela.", s: "Cuando le indicas a alguien dónde puede comprar libros.", sEn: "When you tell someone where they can buy books.", n: "'Bookstore' es donde compras libros; 'library' es la biblioteca donde los prestan, no los confundas.", nEn: "'Bookstore' is where you buy books; 'library' is where you borrow them, don't confuse them." },
    "loc-fa05": { e: "You can study quietly at the library; it's free and open all day.", t: "Puede estudiar tranquilo en la biblioteca; es gratis y abre todo el día.", s: "Cuando recomiendas un lugar tranquilo para estudiar o leer.", sEn: "When you recommend a quiet place to study or read.", n: "'Library' es la biblioteca; para comprar libros di 'bookstore', no 'library'.", nEn: "'Library' is the place that lends books; to buy books say 'bookstore', not 'library'." },
    "loc-fa06": { e: "Please be gentle, my skin is very sensitive to the sun.", t: "Por favor con cuidado, mi piel es muy sensible al sol.", s: "Cuando explicas que algo te afecta fácilmente, como la piel o las emociones.", sEn: "When you explain that something affects you easily, like your skin or feelings.", n: "'Sensitive' es 'sensible' (que se afecta); 'sensible' en inglés significa 'sensato', cuidado.", nEn: "'Sensitive' means easily affected; English 'sensible' means level-headed, beware." },
    "loc-fa07": { e: "That's a sensible decision; saving a little each month really adds up.", t: "Esa es una decisión sensata; ahorrar un poco cada mes de verdad suma.", s: "Cuando dices que algo o alguien es razonable y práctico.", sEn: "When you say something or someone is reasonable and practical.", n: "'Sensible' en inglés es 'sensato/razonable'; para 'sensible' del español usa 'sensitive'.", nEn: "English 'sensible' means reasonable; for Spanish 'sensible' use 'sensitive'." },
    "loc-fa08": { e: "I saved the report in a folder on the desktop.", t: "Guardé el informe en una carpeta en el escritorio.", s: "Cuando hablas de organizar archivos o documentos en la computadora o físicamente.", sEn: "When you talk about organizing files or documents on the computer or physically.", n: "'Folder' es 'carpeta'; 'carpet' significa 'alfombra', no lo confundas en la oficina.", nEn: "'Folder' means 'carpeta'; 'carpet' means 'alfombra', don't mix them up at the office." },
    "loc-fa09": { e: "Please take off your shoes; we just cleaned the carpet.", t: "Por favor quítese los zapatos; acabamos de limpiar la alfombra.", s: "Cuando hablas de la alfombra del piso, por ejemplo en una casa u hotel.", sEn: "When you talk about the floor carpet, for example in a home or hotel.", n: "'Carpet' es 'alfombra'; para 'carpeta' di 'folder', es un falso amigo muy común.", nEn: "'Carpet' means 'alfombra'; for 'carpeta' say 'folder', a very common false friend." },
    "loc-fa10": { e: "The new tour was a huge success; every spot sold out.", t: "El nuevo tour fue todo un éxito; se agotaron todos los cupos.", s: "Cuando cuentas que algo salió muy bien o tuvo buenos resultados.", sEn: "When you say that something went very well or got great results.", n: "'Success' es 'éxito'; 'exit' significa 'salida', no lo confundas al leer letreros.", nEn: "'Success' means 'éxito'; 'exit' means 'salida', don't confuse them when reading signs." },
    "loc-fa11": { e: "The exit is at the end of the hallway, on your right.", t: "La salida está al final del pasillo, a su derecha.", s: "Cuando le indicas a alguien por dónde salir de un edificio o lugar.", sEn: "When you tell someone how to leave a building or place.", n: "'Exit' es 'salida'; para 'éxito' (logro) di 'success', cuidado con este falso amigo.", nEn: "'Exit' means 'salida'; for 'éxito' (achievement) say 'success', beware this false friend." },
    "loc-fa12": { e: "My uncle works at a coffee factory just outside the city.", t: "Mi tío trabaja en una fábrica de café a las afueras de la ciudad.", s: "Cuando hablas del lugar donde se fabrican o producen productos.", sEn: "When you talk about the place where products are made or produced.", n: "'Factory' es 'fábrica'; 'fabric' significa 'tela', no lo confundas al hablar de manufactura.", nEn: "'Factory' means 'fábrica'; 'fabric' means 'cloth', don't confuse them when talking manufacturing." },
    "loc-fa13": { e: "This bag is made of a really soft fabric.", t: "Este bolso está hecho de una tela muy suave.", s: "Cuando le explicas a un cliente de qué material está hecho un producto.", sEn: "When you tell a customer what material a product is made of.", n: "Cuidado: 'fabric' significa tela, no fábrica; fábrica se dice 'factory'.", nEn: "Careful: 'fabric' means cloth, not a building; a building where things are made is a 'factory'." },
    "loc-fa14": { e: "I'll remember to bring your receipt next time.", t: "Voy a recordar traerle su recibo la próxima vez.", s: "Cuando le aseguras a alguien que no olvidarás algo.", sEn: "When you assure someone you won't forget something.", n: "'Remember' es recordar; no lo confundas con 'record' (grabar) ni con 'remind' (recordarle a otra persona).", nEn: "'Remember' is to recall; don't confuse it with 'record' (to tape) or 'remind' (to make someone else remember)." },
    "loc-fa15": { e: "Sorry to bother you, but could I see your ticket?", t: "Disculpe que lo moleste, pero ¿podría ver su boleto?", s: "Cuando interrumpes a un cliente con educación para pedirle algo.", sEn: "When you politely interrupt a customer to ask for something.", n: "'Bother' es molestar en el sentido de incomodar; nunca uses 'molest', que en inglés significa abuso sexual.", nEn: "'Bother' means to disturb; never say 'molest', which in English means sexual abuse." },
    "loc-fa16": { e: "I can't work today because I have a cold.", t: "Hoy no puedo trabajar porque estoy resfriado.", s: "Cuando avisas que estás resfriado y no te sientes bien.", sEn: "When you let someone know you have a cold and feel unwell.", n: "'Have a cold' es estar resfriado; 'constipated' en inglés significa estreñido, no resfriado.", nEn: "'Have a cold' means to have the sniffles; 'constipated' in English means blocked bowels, not a cold." },
    // ===================== Pronunciation (pronunciacion-en) =====================
    "loc-pron01": { e: "You can see the ship from the dock.", t: "Puede ver el barco desde el muelle.", s: "Cuando le muestras a un turista una embarcación grande en el puerto.", sEn: "When you point out a large vessel at the port to a tourist.", n: "La 'i' de 'ship' es corta, casi como 'shep'; si la alargas suena 'sheep' (oveja).", nEn: "The 'i' in 'ship' is short, almost 'shep'; stretching it turns it into 'sheep'." },
    "loc-pron02": { e: "We saw a sheep on the way up the mountain.", t: "Vimos una oveja subiendo la montaña.", s: "Cuando describes a los visitantes los animales del recorrido.", sEn: "When you describe the animals seen along the tour.", n: "'Sheep' lleva la 'i' larga (shiip); no la cortes o sonará 'ship' (barco).", nEn: "'Sheep' has a long 'ee' (sheep); cut it short and it becomes 'ship'." },
    "loc-pron03": { e: "I live near the beach, just ten minutes away.", t: "Vivo cerca de la playa, a solo diez minutos.", s: "Cuando le cuentas a un cliente dónde vives durante una charla.", sEn: "When you tell a customer where you live during small talk.", n: "'Live' (vivir) lleva 'i' corta; 'leave' (irse) lleva 'i' larga, no las mezcles.", nEn: "'Live' (reside) has a short 'i'; 'leave' (go away) has a long 'ee'; keep them apart." },
    "loc-pron04": { e: "The bus is about to leave, please hurry.", t: "El bus está a punto de salir, por favor apúrese.", s: "Cuando apuras a los pasajeros porque el transporte va a partir.", sEn: "When you rush passengers because the transport is about to depart.", n: "'Leave' suena 'liiv' con 'i' larga; 'live' con 'i' corta significa vivir.", nEn: "'Leave' sounds like 'leev' with a long vowel; short 'live' means to reside." },
    "loc-pron05": { e: "Would you like some chips with your sandwich?", t: "¿Quiere papitas con su sándwich?", s: "Cuando le ofreces un acompañamiento a un cliente en el restaurante.", sEn: "When you offer a customer a side with their meal.", n: "La 'i' de 'chip' es corta; si la alargas suena 'cheap' (barato).", nEn: "The 'i' in 'chip' is short; stretch it and it becomes 'cheap'." },
    "loc-pron06": { e: "The market is cheaper than the shops downtown.", t: "El mercado es más barato que las tiendas del centro.", s: "Cuando le explicas a un turista dónde conviene comprar.", sEn: "When you tell a tourist where the better deals are.", n: "'Cheap' lleva 'i' larga (chiip); con 'i' corta suena 'chip' (papita).", nEn: "'Cheap' has a long 'ee'; with a short 'i' it sounds like 'chip'." },
    "loc-pron07": { e: "It's right here on the table.", t: "Está justo aquí sobre la mesa.", s: "Cuando le indicas a alguien dónde está un objeto.", sEn: "When you point out where an object is.", n: "La 'i' de 'it' es corta; si la alargas suena 'eat' (comer), que es muy distinto.", nEn: "The 'i' in 'it' is short; lengthen it and you say 'eat', which means something quite different." },
    "loc-pron08": { e: "Where would you like to eat tonight?", t: "¿Dónde le gustaría comer esta noche?", s: "Cuando le sugieres planes de comida a un huésped.", sEn: "When you suggest dining plans to a guest.", n: "'Eat' lleva 'i' larga (iit); con 'i' corta suena 'it', que es el pronombre 'lo/ello'.", nEn: "'Eat' has a long 'ee'; with a short 'i' it sounds like 'it', the pronoun." },
    "loc-pron09": { e: "The restaurant is full tonight, sorry.", t: "El restaurante está lleno esta noche, lo siento.", s: "Cuando le dices a un cliente que no hay mesas disponibles.", sEn: "When you tell a customer there are no tables available.", n: "La 'u' de 'full' es corta y relajada (ful); no suena como 'fool' (tonto) con 'u' larga.", nEn: "The 'u' in 'full' is short and relaxed; it doesn't sound like 'fool' with a long 'oo'." },
    "loc-pron10": { e: "Don't be a fool, always wear your seatbelt.", t: "No sea tonto, póngase siempre el cinturón.", s: "Cuando bromeas o aconsejas a alguien sobre seguridad.", sEn: "When you joke or advise someone about safety.", n: "'Fool' lleva 'u' larga (fuul); con 'u' corta suena 'full' (lleno).", nEn: "'Fool' has a long 'oo'; with a short 'u' it sounds like 'full'." },
    "loc-pron11": { e: "The weather is bad today, take an umbrella.", t: "El clima está malo hoy, lleve un paraguas.", s: "Cuando le adviertes a un huésped sobre el mal tiempo.", sEn: "When you warn a guest about poor weather.", n: "La 'a' de 'bad' es abierta y plana; no la pronuncies como 'bed' (cama).", nEn: "The 'a' in 'bad' is open and flat; don't pronounce it like 'bed'." },
    "loc-pron12": { e: "There's an extra bed in the room for the child.", t: "Hay una cama extra en el cuarto para el niño.", s: "Cuando explicas las camas que tiene la habitación.", sEn: "When you explain the beds available in the room.", n: "'Bed' lleva 'e' como en 'mesa'; si la abres demasiado suena 'bad' (malo).", nEn: "'Bed' uses the 'e' sound; open it too much and it sounds like 'bad'." },
    "loc-pron13": { e: "A man at the door is asking for you.", t: "Un hombre en la puerta pregunta por usted.", s: "Cuando avisas a un colega que alguien lo busca.", sEn: "When you tell a coworker that someone is asking for them.", n: "'Man' (singular) lleva 'a' plana; 'men' (plural) lleva 'e', cuida la diferencia.", nEn: "'Man' (singular) uses a flat 'a'; 'men' (plural) uses 'e', so mind the difference." },
    "loc-pron14": { e: "Two men are waiting at the reception desk.", t: "Dos hombres están esperando en recepción.", s: "Cuando reportas que varias personas esperan ser atendidas.", sEn: "When you report that several people are waiting to be served.", n: "'Men' suena con 'e' como 'men' de mentira; 'man' lleva 'a' y es singular.", nEn: "'Men' uses the 'e' sound; 'man' uses 'a' and is singular." },
    // ===================== Present perfect (perfecto-en) =====================
    "loc-perf01": { e: "I have lived here for three years, so I know the area well.", t: "He vivido aquí tres años, así que conozco bien la zona.", s: "Cuando le cuentas a un turista cuánto tiempo llevas viviendo en el lugar.", sEn: "When you tell a tourist how long you have lived in the area.", n: "Usa el present perfect ('have lived') para algo que empezó en el pasado y sigue hasta hoy.", nEn: "Use the present perfect ('have lived') for something that started in the past and continues today." },
    "loc-perf02": { e: "I lived there in 2019, but I moved away after that.", t: "Viví allí en 2019, pero después me mudé.", s: "Cuando hablas de algo que ya terminó en un momento pasado.", sEn: "When you talk about something that finished at a specific past time.", n: "Con una fecha terminada (in 2019) usa el pasado simple 'lived', no 'have lived'.", nEn: "With a finished time marker (in 2019) use the simple past 'lived', not 'have lived'." },
    "loc-perf03": { e: "Have you ever traveled to South America before?", t: "¿Alguna vez has viajado a Sudamérica antes?", s: "Cuando charlas con un huésped o cliente y quieres preguntar sobre su experiencia de vida.", sEn: "When chatting with a guest or customer and you want to ask about their life experience.", n: "Usa 'ever' para preguntar por experiencias en cualquier momento de la vida, no por algo reciente.", nEn: "Use 'ever' to ask about experiences at any point in life, not about something recent." },
    "loc-perf04": { e: "I have never eaten that, but it looks delicious.", t: "Nunca he comido eso, pero se ve delicioso.", s: "Cuando un cliente te ofrece o menciona un plato que no has probado.", sEn: "When a customer offers or mentions a dish you haven't tried.", n: "Con 'never' ya va la negación, así que no digas 'I have never not eaten'.", nEn: "'Never' already makes it negative, so don't add another 'not'." },
    "loc-perf05": { e: "I have finished the homework, so I can rest now.", t: "He terminado la tarea, así que ya puedo descansar.", s: "Para decir que completaste algo con resultado en el presente.", sEn: "To say you have completed something, with a result now.", n: "Present perfect: have + participio (finished).", nEn: "Present perfect: have + past participle (finished)." },
    "loc-perf06": { e: "I have just arrived, give me a minute to get ready.", t: "Acabo de llegar, deme un minuto para alistarme.", s: "Cuando llegas al trabajo o a un punto de encuentro y avisas que recién llegaste.", sEn: "When you get to work or a meeting point and let someone know you just got there.", n: "'Just' va entre 'have' y el verbo: 'have just arrived', no al final.", nEn: "'Just' goes between 'have' and the verb: 'have just arrived', not at the end." },
    "loc-perf07": { e: "I worked yesterday, so today is my day off.", t: "Trabajé ayer, así que hoy es mi día libre.", s: "Cuando cuentas algo que pasó en un momento pasado y terminado.", sEn: "When you mention something that happened at a finished moment in the past.", n: "Con 'yesterday' usa el pasado simple ('worked'), nunca el present perfect.", nEn: "With 'yesterday' use the simple past ('worked'), never the present perfect." },
    "loc-perf08": { e: "I have worked a lot today, I'm really tired.", t: "He trabajado mucho hoy, estoy muy cansado.", s: "Cuando hablas de tu esfuerzo durante un día que aún no termina.", sEn: "When you talk about your effort during a day that isn't over yet.", n: "Como 'today' aún no acaba, va el present perfect; si ya pasó el día, di 'I worked'.", nEn: "Since 'today' isn't over, use the present perfect; once the day is past, say 'I worked'." },
    "loc-perf09": { e: "Have you eaten yet, or shall I bring the menu?", t: "¿Ya comiste, o te traigo el menú?", s: "Cuando atiendes a un cliente y quieres saber si ya comió.", sEn: "When serving a customer and you want to know if they've eaten already.", n: "'Yet' va al final en preguntas y negaciones; suena como 'iet'.", nEn: "'Yet' goes at the end in questions and negatives; it sounds like 'yet' rhyming with 'net'." },
    "loc-perf10": { e: "I haven't done it yet, but I'll have it ready soon.", t: "Todavía no lo he hecho, pero lo tendré listo pronto.", s: "Cuando un jefe o cliente pregunta por una tarea pendiente.", sEn: "When a boss or customer asks about a task you haven't finished.", n: "Recuerda el irregular: 'do, did, done'; aquí va 'done', no 'did'.", nEn: "Remember the irregular: 'do, did, done'; here it's 'done', not 'did'." },
    "loc-perf11": { e: "I saw her last week at the market.", t: "La vi la semana pasada en el mercado.", s: "Cuando cuentas que viste a alguien en un momento pasado específico.", sEn: "When you mention seeing someone at a specific past moment.", n: "Con 'last week' va el pasado simple 'saw'; el present perfect no acepta tiempos terminados.", nEn: "With 'last week' use the simple past 'saw'; the present perfect can't take finished time markers." },
    "loc-perf12": { e: "I have seen it before, it's a great show.", t: "Lo he visto antes, es un gran espectáculo.", s: "Cuando recomiendas algo que ya conoces sin decir cuándo exactamente.", sEn: "When recommending something you already know, without saying exactly when.", n: "Usa 'seen' (no 'saw') después de 'have'; es el irregular 'see, saw, seen'.", nEn: "Use 'seen' (not 'saw') after 'have'; it's the irregular 'see, saw, seen'." },
    // ===================== Articles a/an/the (articulos-en) =====================
    "loc-art01": { e: "I am a teacher at a local school.", t: "Soy profesor en una escuela de la zona.", s: "Cuando te presentas y dices a qué te dedicas.", sEn: "When you introduce yourself and say what you do.", n: "En inglés siempre va 'a' antes de la profesión: 'a teacher', no solo 'teacher'.", nEn: "In English you always need 'a' before a job: 'a teacher', not just 'teacher'." },
    "loc-art02": { e: "She is a doctor at the hospital downtown.", t: "Ella es médica en el hospital del centro.", s: "Cuando hablas del trabajo de otra persona.", sEn: "When you talk about someone else's job.", n: "Igual que con tu profesión, di 'a doctor'; el artículo nunca se omite.", nEn: "Just like with your own job, say 'a doctor'; the article is never dropped." },
    "loc-art03": { e: "The tour starts in an hour, so we have time for coffee.", t: "El tour empieza en una hora, así que hay tiempo para un café.", s: "Cuando informas cuánto falta para una actividad.", sEn: "When you tell someone how long until an activity starts.", n: "Se usa 'an hour' porque la 'h' es muda y suena como vocal ('an our').", nEn: "Use 'an hour' because the 'h' is silent and it sounds like a vowel ('an our')." },
    "loc-art04": { e: "She studies at a university in the capital.", t: "Ella estudia en una universidad de la capital.", s: "Cuando mencionas dónde estudia alguien.", sEn: "When you mention where someone studies.", n: "Es 'a university' porque empieza con sonido 'yu', como consonante, no 'an'.", nEn: "It's 'a university' because it starts with a 'yu' sound, treated as a consonant, not 'an'." },
    "loc-art05": { e: "The sun is strong today, don't forget your sunscreen.", t: "El sol está fuerte hoy, no olvide su protector solar.", s: "Cuando le adviertes a un cliente sobre el clima en la playa o el tour.", sEn: "When you warn a customer about the weather at the beach or on a tour.", n: "Cosas únicas llevan 'the': 'the sun', 'the moon', 'the sky'.", nEn: "Unique things take 'the': 'the sun', 'the moon', 'the sky'." },
    "loc-art06": { e: "I like coffee, especially in the morning.", t: "Me gusta el café, sobre todo en la mañana.", s: "Cuando hablas de algo en general, como tus gustos.", sEn: "When you talk about something in general, like your preferences.", n: "Para gustos generales NO uses 'the': 'I like coffee', no 'I like the coffee'.", nEn: "For general likes don't use 'the': 'I like coffee', not 'I like the coffee'." },
    "loc-art07": { e: "I play the guitar at the bar on weekends.", t: "Toco la guitarra en el bar los fines de semana.", s: "Cuando cuentas un pasatiempo o talento musical.", sEn: "When you mention a hobby or musical talent.", n: "Los instrumentos llevan 'the': 'play the guitar', 'play the piano'.", nEn: "Instruments take 'the': 'play the guitar', 'play the piano'." },
    "loc-art08": { e: "I go to school in the morning and work in the afternoon.", t: "Voy a la escuela en la mañana y trabajo en la tarde.", s: "Cuando hablas de tu rutina diaria de estudio.", sEn: "When you talk about your daily study routine.", n: "Con su propósito normal NO va 'the': 'go to school', 'go to work'.", nEn: "For its usual purpose, drop 'the': 'go to school', 'go to work'." },
    "loc-art09": { e: "Would you like an egg with your breakfast?", t: "¿Desea un huevo con su desayuno?", s: "Cuando ofreces comida a un huésped en el desayuno.", sEn: "When you offer food to a guest at breakfast.", n: "Va 'an egg' porque empieza con sonido de vocal; usa 'an' antes de a, e, i, o, u.", nEn: "It's 'an egg' because it starts with a vowel sound; use 'an' before a, e, i, o, u sounds." },
    "loc-art10": { e: "This is the best restaurant in town, you have to try it.", t: "Este es el mejor restaurante del pueblo, tiene que probarlo.", s: "Cuando recomiendas un lugar y lo destacas como el número uno.", sEn: "When you recommend a place and highlight it as number one.", n: "Los superlativos siempre llevan 'the': 'the best', 'the biggest', 'the cheapest'.", nEn: "Superlatives always take 'the': 'the best', 'the biggest', 'the cheapest'." },
    "loc-art11": { e: "I have a dog at home, so I always have a smile on my face when I get there.", t: "Tengo un perro en casa, así que siempre llego con una sonrisa en la cara.", s: "Cuando hablas de algo tuyo en una charla casual con un cliente o compañero.", sEn: "When you mention something you own in casual chat with a guest or coworker.", n: "Usa \"a\" antes de sustantivo contable singular: \"a dog\", no \"a dogs\".", nEn: "Use \"a\" before a singular countable noun: \"a dog\", not \"a dogs\"." },
    "loc-art12": { e: "Cats are cute, but they don't like the noise here in the lobby.", t: "Los gatos son lindos, pero no les gusta el ruido aquí en el lobby.", s: "Cuando hablas de algo en general, sin artículo, en una conversación.", sEn: "When you talk about something in general, with no article, in conversation.", n: "Para hablar en general usa el plural sin \"the\": \"Cats are cute\", no \"The cats are cute\".", nEn: "To speak in general use the plural without \"the\": \"Cats are cute\", not \"The cats are cute\"." },
    // ===================== Quantities (cantidades-en) =====================
    "loc-cant01": { e: "How much money do you have on you, just in cash?", t: "¿Cuánto dinero traes contigo, solo en efectivo?", s: "Cuando preguntas por una cantidad de algo incontable, como dinero.", sEn: "When you ask about an amount of something uncountable, like money.", n: "Usa \"how much\" con incontables (money, water) y \"how many\" con contables (coins).", nEn: "Use \"how much\" with uncountables (money, water) and \"how many\" with countables (coins)." },
    "loc-cant02": { e: "How many people are in your group today?", t: "¿Cuántas personas hay en su grupo hoy?", s: "Cuando preguntas el número de personas para una mesa, tour o reserva.", sEn: "When you ask the number of people for a table, tour, or booking.", n: "\"People\" ya es plural; di \"how many people\", nunca \"how many peoples\".", nEn: "\"People\" is already plural; say \"how many people\", never \"how many peoples\"." },
    "loc-cant03": { e: "Would you like some water while you look at the menu?", t: "¿Le gustaría algo de agua mientras mira el menú?", s: "Cuando ofreces una cantidad indefinida de algo a un cliente.", sEn: "When you offer an indefinite amount of something to a guest.", n: "En ofertas y preguntas amables se usa \"some\", no \"any\": \"Would you like some water?\".", nEn: "In polite offers and questions use \"some\", not \"any\": \"Would you like some water?\"." },
    "loc-cant04": { e: "Are there any questions before we start the tour?", t: "¿Hay alguna pregunta antes de empezar el tour?", s: "Cuando preguntas si existe algo, esperando que pueda no haber nada.", sEn: "When you ask whether something exists, open to the answer being none.", n: "\"Any\" se usa en preguntas y frases negativas; en afirmaciones usa \"some\".", nEn: "\"Any\" is used in questions and negatives; in positive statements use \"some\"." },
    "loc-cant05": { e: "There's a lot of work today, so let's split the tables.", t: "Hay mucho trabajo hoy, así que dividamos las mesas.", s: "Cuando comentas que hay gran cantidad de algo, en el trabajo.", sEn: "When you note there's a large amount of something at work.", n: "\"A lot of\" sirve para contables e incontables; es más natural que \"much\" en frases afirmativas.", nEn: "\"A lot of\" works for both countable and uncountable, and is more natural than \"much\" in positive sentences." },
    "loc-cant06": { e: "We have few options left in your size, sorry.", t: "Nos quedan pocas opciones en su talla, lo siento.", s: "Cuando avisas a un cliente que casi no hay disponibilidad.", sEn: "When you tell a customer there's almost nothing available.", n: "\"Few\" suena negativo (casi nada); \"a few\" suena positivo (algunos disponibles).", nEn: "\"Few\" sounds negative (almost none); \"a few\" sounds positive (some available)." },
    "loc-cant07": { e: "Would you like a little sugar in your coffee?", t: "¿Le gustaría un poco de azúcar en el café?", s: "Cuando ofreces una pequeña cantidad de algo incontable.", sEn: "When you offer a small amount of something uncountable.", n: "Usa \"a little\" con incontables (sugar, milk) y \"a few\" con contables (cookies).", nEn: "Use \"a little\" with uncountables (sugar, milk) and \"a few\" with countables (cookies)." },
    "loc-cant08": { e: "I'll send you all the information by email this afternoon.", t: "Le enviaré toda la información por correo esta tarde.", s: "Cuando hablas de datos o detalles que vas a compartir.", sEn: "When you talk about details you're going to share.", n: "\"Information\" es incontable: nunca \"informations\", y di \"some information\".", nEn: "\"Information\" is uncountable: never \"informations\", and say \"some information\"." },
    "loc-cant09": { e: "Many tourists come here in July, so we get really busy.", t: "Muchos turistas vienen aquí en julio, así que nos llenamos.", s: "Cuando comentas que hay gran número de personas o cosas contables.", sEn: "When you mention a large number of people or countable things.", n: "\"Many\" va con contables en plural; con incontables usa \"much\" o \"a lot of\".", nEn: "\"Many\" goes with plural countables; with uncountables use \"much\" or \"a lot of\"." },
    "loc-cant10": { e: "Sorry, there's too much noise here. Let me find you a quieter table.", t: "Disculpe, hay demasiado ruido aquí. Le busco una mesa más tranquila.", s: "Cuando reconoces que algo molesto es excesivo y ofreces solución.", sEn: "When you acknowledge something bothersome is excessive and offer a fix.", n: "\"Too much\" tiene tono negativo (más de lo bueno); no es lo mismo que \"a lot of\".", nEn: "\"Too much\" has a negative tone (more than is good); it's not the same as \"a lot of\"." },
    "loc-cant11": { e: "Take your time, we have enough time before the bus leaves.", t: "Tómese su tiempo, tenemos suficiente tiempo antes de que salga el bus.", s: "Cuando tranquilizas a alguien diciendo que no hay prisa.", sEn: "When you reassure someone there's no rush.", n: "\"Enough\" va antes del sustantivo: \"enough time\", no \"time enough\".", nEn: "\"Enough\" comes before the noun: \"enough time\", not \"time enough\"." },
    "loc-cant12": { e: "I'm sorry, we're out of the red ones. I don't have any right now.", t: "Lo siento, se nos acabaron los rojos. No tengo ninguno ahora.", s: "Cuando le dices a un cliente que no queda nada de lo que pidió.", sEn: "When you tell a customer there's none left of what they asked for.", n: "En negativas usa \"any\": \"I don't have any\", no \"I don't have no\".", nEn: "In negatives use \"any\": \"I don't have any\", not \"I don't have no\"." },
    // ===================== Modal verbs (modales-en) =====================
    "loc-mod01": { e: "Excuse me, could you help me carry these bags upstairs?", t: "Disculpe, ¿podría ayudarme a subir estas maletas?", s: "Cuando pides un favor de forma educada a un cliente o compañero.", sEn: "When you politely ask a guest or coworker for a favor.", n: "\"Could you\" es más cortés que \"can you\" para pedir favores.", nEn: "\"Could you\" is more polite than \"can you\" for asking favors." },
    "loc-mod02": { e: "You should rest a bit; you look really tired today.", t: "Deberías descansar un poco; te ves muy cansado hoy.", s: "Cuando das un consejo amable a un compañero o cliente.", sEn: "When you give friendly advice to a coworker or guest.", n: "\"Should\" es un consejo, no una orden; el verbo va sin \"to\": \"should rest\".", nEn: "\"Should\" is advice, not an order; the verb has no \"to\": \"should rest\"." },
    "loc-mod03": { e: "I'm sorry, I must go now, but my colleague will help you.", t: "Lo siento, debo irme ahora, pero mi compañero le ayudará.", s: "Cuando te despides porque tienes una obligación que cumplir.", sEn: "When you excuse yourself because you have an obligation.", n: "\"Must\" suena fuerte; para algo menos formal di \"I have to go\".", nEn: "\"Must\" sounds strong; for something softer say \"I have to go\"." },
    "loc-mod04": { e: "May I come in? I have your fresh towels.", t: "¿Puedo pasar? Le traigo toallas limpias.", s: "Cuando pides permiso para entrar a la habitación de un huésped.", sEn: "When you ask permission to enter a guest's room.", n: "\"May I\" es la forma más educada de pedir permiso; \"Can I\" es más informal.", nEn: "\"May I\" is the most polite way to ask permission; \"Can I\" is more informal." },
    "loc-mod05": { e: "Can I borrow your phone for a second to call the office?", t: "¿Me prestas tu teléfono un segundo para llamar a la oficina?", s: "Cuando pides usar algo de alguien por un momento.", sEn: "When you ask to use something of someone's for a moment.", n: "\"Borrow\" es recibir prestado; \"lend\" es dar prestado, no los confundas.", nEn: "\"Borrow\" is to receive on loan; \"lend\" is to give on loan, don't mix them up." },
    "loc-mod06": { e: "We could try the other route if there's too much traffic.", t: "Podríamos intentar la otra ruta si hay demasiado tráfico.", s: "Cuando sugieres una opción con suavidad, sin imponerla.", sEn: "When you gently suggest an option without imposing it.", n: "\"Could\" suaviza la sugerencia; suena menos directo que \"we will try\".", nEn: "\"Could\" softens the suggestion; it sounds less direct than \"we will try\"." },
    "loc-mod07": { e: "You shouldn't worry, your room will be ready in a few minutes.", t: "No deberías preocuparte, tu habitación estará lista en unos minutos.", s: "Cuando tranquilizas a un cliente que está ansioso por algo.", sEn: "When you reassure a customer who is anxious about something.", n: "\"Shouldn't\" suena como \"shudnt\", sin pronunciar la L; para más formal di \"there's no need to worry\".", nEn: "\"Shouldn't\" sounds like \"shudnt\" with a silent L; for something more formal say \"there's no need to worry\"." },
    "loc-mod08": { e: "Would you mind waiting a moment while I check the availability?", t: "¿Te importaría esperar un momento mientras reviso la disponibilidad?", s: "Cuando necesitas que el cliente espere y quieres pedirlo con cortesía.", sEn: "When you need the customer to wait and want to ask politely.", n: "Ojo: la respuesta amable a \"Would you mind?\" es \"No, not at all\" (no, no importa), aunque suene raro en español.", nEn: "Note: the polite answer to \"Would you mind?\" is \"No, not at all,\" even though it sounds odd in Spanish." },
    "loc-mod09": { e: "You have to sign here at the bottom and write today's date.", t: "Tienes que firmar aquí abajo y escribir la fecha de hoy.", s: "Cuando le indicas a un cliente dónde firmar un formulario o registro.", sEn: "When you tell a customer where to sign a form or register.", n: "\"Have to\" expresa obligación; para suavizarlo usa \"I'll just need you to sign here\".", nEn: "\"Have to\" expresses obligation; to soften it use \"I'll just need you to sign here\"." },
    "loc-mod10": { e: "It might rain this afternoon, so I'd bring an umbrella for the tour.", t: "Quizás llueva esta tarde, así que yo llevaría un paraguas para el tour.", s: "Cuando adviertes sobre el clima a turistas antes de salir.", sEn: "When you warn tourists about the weather before heading out.", n: "\"Might\" y \"may\" son casi iguales para posibilidad; \"might\" suena un poco más informal.", nEn: "\"Might\" and \"may\" are nearly the same for possibility; \"might\" sounds slightly more casual." },
    "loc-mod11": { e: "Can I help you find something on the menu?", t: "¿Puedo ayudarte a encontrar algo en el menú?", s: "Cuando te acercas a un cliente que parece indeciso o perdido.", sEn: "When you approach a customer who looks unsure or lost.", n: "Para sonar más formal con clientes usa \"May I help you?\" en lugar de \"Can I help?\".", nEn: "To sound more formal with customers, use \"May I help you?\" instead of \"Can I help?\"." },
    "loc-mod12": { e: "We should go now if we want to catch the boat on time.", t: "Deberíamos irnos ya si queremos alcanzar el bote a tiempo.", s: "Cuando, como guía, apuras amablemente al grupo para no llegar tarde.", sEn: "When, as a guide, you gently rush the group so you won't be late.", n: "\"Should\" da una sugerencia, no una orden; para más urgencia di \"we really need to go now\".", nEn: "\"Should\" gives a suggestion, not an order; for more urgency say \"we really need to go now\"." },
    // ===================== Phrasal verbs (phrasal-en) =====================
    "loc-phr01": { e: "You can check in any time after three this afternoon.", t: "Puede registrarse a cualquier hora después de las tres de la tarde.", s: "Cuando le explicas a un huésped a qué hora puede hacer el registro.", sEn: "When you explain to a guest what time they can check in.", n: "El verbo va separado (\"check in\"), pero el sustantivo lleva guion: \"check-in is at three\".", nEn: "The verb is two words (\"check in\"), but the noun is hyphenated: \"check-in is at three\"." },
    "loc-phr02": { e: "What time would you like to check out tomorrow?", t: "¿A qué hora le gustaría salir mañana?", s: "Cuando coordinas con el huésped la hora de salida del hotel.", sEn: "When you arrange the guest's hotel departure time.", n: "\"Check out\" también significa \"echar un vistazo\": \"check out our menu\" (mira nuestro menú).", nEn: "\"Check out\" also means \"take a look\": \"check out our menu\"." },
    "loc-phr03": { e: "Let me turn on the air conditioning for you.", t: "Déjeme encenderle el aire acondicionado.", s: "Cuando enciendes un aparato para la comodidad del cliente.", sEn: "When you switch on a device for the customer's comfort.", n: "Puedes separarlo con el objeto: \"turn the lights on\" o \"turn on the lights\", ambos correctos.", nEn: "You can split it with the object: \"turn the lights on\" or \"turn on the lights,\" both correct." },
    "loc-phr04": { e: "Please remember to turn off the lights when you leave the room.", t: "Por favor recuerde apagar las luces cuando salga de la habitación.", s: "Cuando le pides a un huésped que apague algo al salir.", sEn: "When you ask a guest to switch something off when leaving.", n: "Lo opuesto de \"turn off\" es \"turn on\"; con el pronombre va siempre en medio: \"turn it off\".", nEn: "The opposite of \"turn off\" is \"turn on\"; with a pronoun it always goes in the middle: \"turn it off\"." },
    "loc-phr05": { e: "I can pick you up at the airport at eight if you'd like.", t: "Puedo recogerlo en el aeropuerto a las ocho si gusta.", s: "Cuando ofreces transporte y vas a buscar al cliente en un lugar.", sEn: "When you offer transport and will collect the customer somewhere.", n: "\"Pick up\" también sirve para objetos: \"pick up your order\" (recoger tu pedido).", nEn: "\"Pick up\" also works for objects: \"pick up your order\"." },
    "loc-phr06": { e: "Sorry, the elevator broke down, so please use the stairs for now.", t: "Disculpe, el ascensor se averió, así que use las escaleras por ahora.", s: "Cuando avisas que una máquina o vehículo dejó de funcionar.", sEn: "When you warn that a machine or vehicle has stopped working.", n: "\"Break down\" es para máquinas o vehículos; para una persona que llora, también significa derrumbarse emocionalmente.", nEn: "\"Break down\" is for machines or vehicles; for a person it can also mean to break down emotionally." },
    "loc-phr07": { e: "Let me look up the bus schedule for you on my phone.", t: "Déjeme buscarle el horario del bus en mi teléfono.", s: "Cuando buscas información para un cliente en internet o una lista.", sEn: "When you look up information for a customer online or in a list.", n: "\"Look up\" es buscar un dato; \"look for\" es buscar algo físico que perdiste, no los confundas.", nEn: "\"Look up\" is to find information; \"look for\" is to search for a lost object, don't mix them up." },
    "loc-phr08": { e: "I usually get up at five to open the bakery before sunrise.", t: "Normalmente me levanto a las cinco para abrir la panadería antes del amanecer.", s: "Cuando hablas de tu rutina diaria o tus horarios de trabajo.", sEn: "When you talk about your daily routine or work schedule.", n: "\"Get up\" es salir de la cama; \"wake up\" es despertarse, aunque sigas acostado.", nEn: "\"Get up\" is to leave the bed; \"wake up\" is to stop sleeping, even while still lying down." },
    "loc-phr09": { e: "Please go on, I'm listening to everything you're telling me.", t: "Continúe, por favor, estoy escuchando todo lo que me dice.", s: "Cuando animas a un cliente a seguir hablando o explicando.", sEn: "When you encourage a customer to keep talking or explaining.", n: "\"Go on\" también puede significar suceder: \"What's going on?\" es \"¿Qué está pasando?\".", nEn: "\"Go on\" can also mean to happen: \"What's going on?\" means \"What's happening?\"." },
    "loc-phr10": { e: "Could you fill out this form with your name and contact details?", t: "¿Podría rellenar este formulario con su nombre y datos de contacto?", s: "Cuando le pides a un cliente que complete un formulario.", sEn: "When you ask a customer to complete a form.", n: "\"Fill out\" (US) y \"fill in\" (UK) significan lo mismo; ambos se entienden en cualquier lado.", nEn: "\"Fill out\" (US) and \"fill in\" (UK) mean the same thing; both are understood everywhere." },
    "loc-phr11": { e: "Hold on a second, I'll connect you with my manager.", t: "Espere un segundo, lo comunico con mi gerente.", s: "Cuando, por teléfono, le pides al cliente que espere en línea.", sEn: "When, on the phone, you ask the customer to wait on the line.", n: "\"Hold on\" también significa agarrarse fuerte: \"hold on tight\" en un bote o bus.", nEn: "\"Hold on\" also means to grip tightly: \"hold on tight\" on a boat or bus." },
    "loc-phr12": { e: "We need to hurry up or we'll miss the start of the tour.", t: "Tenemos que darnos prisa o nos perderemos el inicio del tour.", s: "Cuando apuras a alguien porque van con el tiempo justo.", sEn: "When you rush someone because time is running short.", n: "Para sonar amable con clientes, suaviza con \"if you don't mind, we should hurry a little\".", nEn: "To sound polite with customers, soften it with \"if you don't mind, we should hurry a little\"." },
    "loc-phr13": { e: "Please give back the key card at reception before you leave.", t: "Por favor devuelva la tarjeta llave en recepción antes de irse.", s: "Cuando pides que te regresen algo prestado, como una llave.", sEn: "When you ask for something borrowed to be returned, like a key.", n: "Con pronombre, separa el verbo: \"give it back\", nunca \"give back it\".", nEn: "With a pronoun, split the verb: \"give it back,\" never \"give back it\"." },
    "loc-phr14": { e: "You'll need to put on your life jacket before we leave the dock.", t: "Tendrá que ponerse el chaleco salvavidas antes de salir del muelle.", s: "Cuando indicas que se pongan una prenda por seguridad o normas.", sEn: "When you tell someone to put on a garment for safety or rules.", n: "\"Put on\" es la acción de ponerse algo; \"wear\" es tenerlo puesto, no los confundas.", nEn: "\"Put on\" is the action of dressing; \"wear\" is having it on, don't confuse them." },
    // ===================== Comparatives (comparar-en) =====================
    "loc-comp01": { e: "This room is bigger and has a nice view of the sea.", t: "Esta habitación es más grande y tiene una linda vista al mar.", s: "Cuando ofreces una opción mejor a un huésped o cliente comparando tamaños.", sEn: "When you offer a guest or customer a better option by comparing sizes.", n: "Usa 'bigger', no 'more big'; los adjetivos cortos llevan '-er'.", nEn: "Say 'bigger', not 'more big'; short adjectives take '-er'." },
    "loc-comp02": { e: "If you'd like, I can bring you a smaller portion.", t: "Si quiere, le puedo traer una porción más pequeña.", s: "Cuando le ofreces al cliente una versión más chica de algo.", sEn: "When you offer the customer a smaller version of something.", n: "La 'a' de 'smaller' suena como 'o' abierta ('aw'), no como la 'a' del español.", nEn: "The 'a' in 'smaller' sounds like 'aw', not the Spanish 'a'." },
    "loc-comp03": { e: "Our ceviche is the best dish on the menu, I promise.", t: "Nuestro ceviche es el mejor plato del menú, se lo aseguro.", s: "Cuando recomiendas con seguridad lo más destacado de tu negocio.", sEn: "When you confidently recommend the standout of your business.", n: "Siempre 'the best', nunca 'the most good'.", nEn: "Always 'the best', never 'the most good'." },
    "loc-comp04": { e: "Monday traffic is the worst, so let's leave a bit earlier.", t: "El tráfico del lunes es el peor, así que salgamos un poco antes.", s: "Cuando explicas por qué algo conviene evitar o adelantar.", sEn: "When you explain why something is best avoided or done earlier.", n: "'Worst' rima con 'first'; no lo confundas con 'worse' (peor que).", nEn: "'Worst' rhymes with 'first'; don't mix it up with 'worse' (worse than)." },
    "loc-comp05": { e: "This handmade bag is as expensive as the leather one, but it lasts longer.", t: "Este bolso hecho a mano es tan caro como el de cuero, pero dura más.", s: "Cuando comparas dos productos que cuestan parecido para vender.", sEn: "When you compare two similarly priced products to make a sale.", n: "La estructura es 'as ... as'; no olvides el segundo 'as'.", nEn: "The structure is 'as ... as'; don't drop the second 'as'." },
    "loc-comp06": { e: "The market is cheaper than the mall if you want souvenirs.", t: "El mercado es más barato que el centro comercial si quiere recuerdos.", s: "Cuando le aconsejas a un turista dónde ahorrar dinero.", sEn: "When you advise a tourist where to save money.", n: "'Cheaper' está bien, pero 'a better deal' suena más positivo al vender.", nEn: "'Cheaper' is fine, but 'a better deal' sounds more positive when selling." },
    "loc-comp07": { e: "The metro is faster than the bus at this time of day.", t: "El metro es más rápido que el bus a esta hora del día.", s: "Cuando recomiendas la mejor forma de moverse por la ciudad.", sEn: "When you recommend the best way to get around the city.", n: "Pronuncia 'faster' con 'a' abierta; no digas 'fas-ter' cortado.", nEn: "Pronounce 'faster' with an open 'a'; don't clip it." },
    "loc-comp08": { e: "The fresh juice is better than the soda, and it's local.", t: "El jugo natural es mejor que la gaseosa, y es de la región.", s: "Cuando sugieres una opción más sana o de mayor calidad.", sEn: "When you suggest a healthier or higher-quality option.", n: "Recuerda 'better than', no 'more better'.", nEn: "Remember 'better than', not 'more better'." },
    "loc-comp09": { e: "This is the prettiest beach on the whole tour.", t: "Esta es la playa más bonita de todo el tour.", s: "Cuando como guía destacas el lugar más lindo del recorrido.", sEn: "When, as a guide, you highlight the most beautiful spot of the tour.", n: "Adjetivos que terminan en 'y' cambian a '-iest': pretty, prettiest.", nEn: "Adjectives ending in 'y' become '-iest': pretty, prettiest." },
    "loc-comp10": { e: "Taking the elevator is easier with all that luggage.", t: "Tomar el ascensor es más fácil con todo ese equipaje.", s: "Cuando le sugieres al huésped la opción más cómoda.", sEn: "When you suggest the more convenient option to a guest.", n: "'Easier' se dice 'II-zi-er'; la primera sílaba es larga.", nEn: "'Easier' is said 'EE-zee-er'; the first syllable is long." },
    // ===================== Diving & snorkel (buceo-en) =====================
    "loc-buc01": { e: "Before we get in, put on your mask and fins and let me check the strap.", t: "Antes de entrar, pónganse la máscara y las aletas y déjenme revisar la correa.", s: "Cuando preparas al grupo justo antes de entrar al agua.", sEn: "When you get the group ready right before entering the water.", n: "'Put on' lleva el objeto en medio: 'put it on'.", nEn: "'Put on' takes the object in the middle: 'put it on'." },
    "loc-buc02": { e: "While snorkeling, don't hold your breath, just relax and breathe.", t: "Mientras hacen esnórquel, no contengan la respiración, solo relájense y respiren.", s: "Cuando das una regla de seguridad clave antes de bucear.", sEn: "When you give a key safety rule before diving.", n: "'Breath' (sustantivo) suena distinto a 'breathe' (verbo, con 'th' suave).", nEn: "'Breath' (noun) sounds different from 'breathe' (verb, with soft 'th')." },
    "loc-buc03": { e: "Stay calm and breathe slowly, there's no rush down here.", t: "Mantengan la calma y respiren despacio, no hay prisa aquí abajo.", s: "Cuando tranquilizas a un cliente nervioso bajo el agua.", sEn: "When you reassure a nervous customer underwater.", n: "'Slowly' es adverbio; di 'breathe slowly', no 'breathe slow'.", nEn: "'Slowly' is an adverb; say 'breathe slowly', not 'breathe slow'." },
    "loc-buc04": { e: "Follow me and stay close so I can keep an eye on everyone.", t: "Síganme y manténganse cerca para que pueda cuidar a todos.", s: "Cuando guías al grupo en el agua y quieres mantenerlos unidos.", sEn: "When you lead the group in the water and want to keep them together.", n: "'Stay close' es más natural que 'stay near' en este contexto.", nEn: "'Stay close' sounds more natural than 'stay near' here." },
    "loc-buc05": { e: "As we go down, equalize your ears by pinching your nose and blowing gently.", t: "Mientras bajamos, igualen la presión de sus oídos tapándose la nariz y soplando suave.", s: "Cuando explicas cómo evitar el dolor de oídos al descender.", sEn: "When you explain how to avoid ear pain while descending.", n: "'Equalize' lleva el acento al inicio: 'II-kwa-laiz'.", nEn: "'Equalize' is stressed on the first syllable: 'EE-kwa-lize'." },
    "loc-buc06": { e: "Please don't touch the coral, it's very fragile and protected.", t: "Por favor no toquen el coral, es muy frágil y está protegido.", s: "Cuando proteges el arrecife y pides cuidado al grupo.", sEn: "When you protect the reef and ask the group to be careful.", n: "Agregar 'please' suaviza la orden y suena más amable.", nEn: "Adding 'please' softens the command and sounds friendlier." },
    "loc-buc07": { e: "Have you dived before, or is this your first time?", t: "¿Han buceado antes, o es su primera vez?", s: "Cuando preguntas la experiencia del cliente antes de empezar.", sEn: "When you ask about a customer's experience before starting.", n: "El participio es 'dived' o 'dove'; ambos se usan, 'dived' es más seguro.", nEn: "The past participle is 'dived' or 'dove'; both work, 'dived' is safest." },
    "loc-buc08": { e: "This is the signal to go up, a thumbs-up means we surface.", t: "Esta es la señal de subir; el pulgar arriba significa que salimos.", s: "Cuando enseñas las señas de mano antes de la inmersión.", sEn: "When you teach the hand signals before the dive.", n: "'Go up' es subir; 'surface' es un verbo más técnico para salir a flote.", nEn: "'Go up' means ascend; 'surface' is a more technical verb for coming up." },
    "loc-buc09": { e: "Stay with your buddy at all times and never swim off alone.", t: "Quédense con su compañero en todo momento y nunca naden solos.", s: "Cuando recuerdas la regla del compañero de buceo por seguridad.", sEn: "When you remind divers of the buddy rule for safety.", n: "'Buddy' es el término estándar de buceo para 'compañero'.", nEn: "'Buddy' is the standard diving term for your partner." },
    "loc-buc10": { e: "You're lucky, visibility is good today, you'll see lots of fish.", t: "Tienen suerte, la visibilidad es buena hoy, verán muchos peces.", s: "Cuando animas al grupo comentando lo bien que se ve el agua.", sEn: "When you excite the group by noting how clear the water is.", n: "'Visibility' tiene el acento en 'bil': 'vi-zi-BI-li-ti'.", nEn: "'Visibility' is stressed on 'bil': 'vi-zi-BI-li-ty'." },
    "loc-buc11": { e: "Tell me if something is wrong with your mask or you feel uncomfortable underwater.", t: "Avísenme si algo está mal con su máscara o si se sienten incómodos bajo el agua.", s: "Cuando das instrucciones de seguridad a los buzos antes de entrar al agua.", sEn: "When you give safety instructions to divers before they go in the water.", n: "Un toque más amable: 'Just let me know if something's wrong' suena menos brusco.", nEn: "A softer touch: 'Just let me know if something's wrong' sounds less abrupt." },
    "loc-buc12": { e: "We saw a turtle right next to the reef on our last dive!", t: "¡Vimos una tortuga justo al lado del arrecife en nuestro último buceo!", s: "Cuando comentas con emoción lo que vieron durante la inmersión.", sEn: "When you excitedly share what the group saw during the dive.", n: "Cuidado: 'turtle' se dice 'TUR-tl', no 'tur-TEL'; la L final es suave.", nEn: "Careful: 'turtle' is said 'TUR-tl', not 'tur-TEL'; the final L is soft." },
    // ===================== Trekking (trekking-en) =====================
    "loc-trk01": { e: "Drink water, we're at altitude and it's easy to get dehydrated up here.", t: "Tomen agua, estamos en altura y es fácil deshidratarse aquí arriba.", s: "Cuando recuerdas al grupo hidratarse durante una caminata en zona alta.", sEn: "When you remind the group to stay hydrated on a high-altitude hike.", n: "Variante natural: 'Keep drinking water' funciona bien como recordatorio constante.", nEn: "Natural variant: 'Keep drinking water' works well as an ongoing reminder." },
    "loc-trk02": { e: "Let's take it slow on this part, there's no rush to reach the top.", t: "Vamos despacio en esta parte, no hay prisa por llegar a la cima.", s: "Cuando el grupo va cansado y propones bajar el ritmo.", sEn: "When the group is tired and you suggest slowing the pace.", n: "'Take it slow' es muy idiomático; 'Let's go slow' también sirve y es más simple.", nEn: "'Take it slow' is very idiomatic; 'Let's go slow' also works and is simpler." },
    "loc-trk03": { e: "Did you bring a rain jacket? The weather can change fast in the mountains.", t: "¿Trajeron impermeable? El clima puede cambiar rápido en la montaña.", s: "Cuando revisas que los caminantes vayan preparados antes de empezar.", sEn: "When you check that hikers are prepared before setting off.", n: "'Rain jacket' es lo común; 'raincoat' también se entiende perfectamente.", nEn: "'Rain jacket' is the common term; 'raincoat' is also perfectly understood." },
    "loc-trk04": { e: "Careful, the trail is slippery here after the rain, so watch your step.", t: "Cuidado, el camino está resbaloso aquí después de la lluvia, miren dónde pisan.", s: "Cuando adviertes de un tramo peligroso en el sendero.", sEn: "When you warn about a dangerous stretch of the trail.", n: "'Slippery' lleva doble P; pronuncia 'SLÍ-pe-ri' (la 'e' es relajada, casi muda), no olvides la R suave.", nEn: "'Slippery' has a double P; say 'SLI-puh-ree' with a soft R." },
    "loc-trk05": { e: "We'll rest in ten minutes once we reach the lookout point.", t: "Descansamos en diez minutos cuando lleguemos al mirador.", s: "Cuando avisas al grupo que pronto habrá una pausa.", sEn: "When you let the group know a break is coming soon.", n: "'We'll' es contracción de 'we will'; suena más natural que decir 'we will rest'.", nEn: "'We'll' is short for 'we will'; it sounds more natural than 'we will rest'." },
    "loc-trk06": { e: "Wear comfortable shoes, we'll be walking on uneven ground all day.", t: "Usen calzado cómodo, vamos a caminar sobre terreno irregular todo el día.", s: "Cuando das recomendaciones antes de iniciar la caminata.", sEn: "When you give recommendations before starting the hike.", n: "Para senderos duros di 'hiking boots'; 'shoes' sirve para caminatas fáciles.", nEn: "For tough trails say 'hiking boots'; 'shoes' is fine for easy walks." },
    "loc-trk07": { e: "The hike takes four hours, so we'll be back by early afternoon.", t: "La caminata dura cuatro horas, así que estaremos de vuelta a primera hora de la tarde.", s: "Cuando explicas cuánto tiempo durará la actividad.", sEn: "When you explain how long the activity will last.", n: "Usa 'takes' para duración de una actividad; 'lasts' también vale: 'The hike lasts four hours'.", nEn: "Use 'takes' for an activity's duration; 'lasts' also works: 'The hike lasts four hours'." },
    "loc-trk08": { e: "How are you feeling? Let me know if anyone needs to slow down.", t: "¿Cómo se sienten? Avísenme si alguien necesita ir más despacio.", s: "Cuando revisas el estado del grupo a mitad del recorrido.", sEn: "When you check on the group's condition midway through.", n: "'How are you feeling?' pregunta por el estado físico ahora; 'How are you?' es solo un saludo.", nEn: "'How are you feeling?' asks about physical state now; 'How are you?' is just a greeting." },
    "loc-trk09": { e: "Watch the edge over here, the drop is steep so stay close to the wall.", t: "Cuidado con el borde por aquí, la caída es muy inclinada, pegúense a la pared.", s: "Cuando adviertes de un precipicio cerca del sendero.", sEn: "When you warn about a cliff edge near the trail.", n: "'Watch the edge' es una orden corta y clara; 'Be careful near the edge' suena más suave.", nEn: "'Watch the edge' is a short, clear command; 'Be careful near the edge' sounds gentler." },
    "loc-trk10": { e: "We're almost at the top, just a few more minutes and the view is worth it.", t: "Casi llegamos a la cima, solo unos minutos más y la vista vale la pena.", s: "Cuando animas al grupo en el último tramo de subida.", sEn: "When you encourage the group on the final stretch up.", n: "'Almost at the top' anima; evita 'we arrive soon', mejor 'we're almost there'.", nEn: "'Almost at the top' is encouraging; avoid 'we arrive soon', use 'we're almost there'." },
    "loc-trk11": { e: "Protect yourselves from the sun, the rays are stronger at this altitude.", t: "Protéjanse del sol, los rayos son más fuertes a esta altura.", s: "Cuando recomiendas usar gorra y protector solar en la montaña.", sEn: "When you recommend hats and sunscreen on the mountain.", n: "Para un grupo usa 'yourselves'; también puedes reforzar con 'Make sure you protect yourselves from the sun'.", nEn: "For a group use 'yourselves'; you can also reinforce it with 'Make sure you protect yourselves from the sun'." },
    "loc-trk12": { e: "What an amazing view! Take all the photos you want, we have time.", t: "¡Qué vista tan increíble! Tomen todas las fotos que quieran, tenemos tiempo.", s: "Cuando llegan a un mirador con un paisaje espectacular.", sEn: "When you reach a lookout with a spectacular landscape.", n: "'What a + adjetivo + sustantivo' expresa asombro; también 'What a view!' a secas.", nEn: "'What a + adjective + noun' expresses awe; you can also just say 'What a view!'" },
    // ===================== Airport (aeropuerto-en) =====================
    "loc-air01": { e: "How many bags are you checking today, or is it just carry-on?", t: "¿Cuántas maletas registra hoy, o solo lleva equipaje de mano?", s: "Cuando atiendes a un pasajero en el mostrador de la aerolínea.", sEn: "When you assist a passenger at the airline check-in counter.", n: "'Check a bag' es facturar; 'carry-on' es el equipaje de mano que va a la cabina.", nEn: "'Check a bag' means to send it in the hold; 'carry-on' is the bag you take onboard." },
    "loc-air02": { e: "Your flight leaves from gate twelve, which is just past security on the left.", t: "Su vuelo sale por la puerta doce, que está justo pasando seguridad a la izquierda.", s: "Cuando le indicas al pasajero por dónde abordar.", sEn: "When you tell the passenger where to board.", n: "'Gate' es la puerta de embarque; 'door' seria la puerta de una casa, no la confundas.", nEn: "'Gate' is the boarding gate; 'door' is a house door, don't mix them up." },
    "loc-air03": { e: "Window or aisle? We still have a few window seats left for this flight.", t: "¿Ventana o pasillo? Todavía nos quedan algunos asientos de ventana para este vuelo.", s: "Cuando asignas asiento a un pasajero en el check-in.", sEn: "When you assign a seat to a passenger at check-in.", n: "'Aisle' suena como 'I' (la letra) o 'isle'; rima con 'mile' y la S y la E son mudas; no la pronuncies como 'a-isle'.", nEn: "'Aisle' sounds like 'I' or 'isle'; it rhymes with 'mile', and the S and E are silent." },
    "loc-air04": { e: "I'm sorry, the flight is delayed by about an hour due to weather.", t: "Lo siento, el vuelo está retrasado alrededor de una hora por el clima.", s: "Cuando informas a un pasajero que su vuelo saldrá tarde.", sEn: "When you inform a passenger their flight will leave late.", n: "'Delayed' es retrasado; si se cancela del todo es 'cancelled', no lo mezcles.", nEn: "'Delayed' means late; if it's called off entirely it's 'cancelled', don't mix them." },
    "loc-air05": { e: "I'm afraid your bag is overweight, so there will be an extra charge.", t: "Me temo que su maleta excede el peso, así que habrá un cargo adicional.", s: "Cuando la maleta del pasajero pasa el límite permitido en la báscula.", sEn: "When the passenger's bag is over the weight limit on the scale.", n: "'I'm afraid' antes de una mala noticia suena cortés y profesional.", nEn: "'I'm afraid' before bad news sounds polite and professional." },
    "loc-air06": { e: "Here's your boarding pass, and boarding starts about thirty minutes before departure.", t: "Aquí tiene su pase de abordar, y el embarque comienza unos treinta minutos antes de la salida.", s: "Cuando entregas el pase de abordar tras hacer el check-in.", sEn: "When you hand over the boarding pass after check-in.", n: "'Here's' es 'here is'; suena más natural al entregar algo que 'here is your...'.", nEn: "'Here's' is 'here is'; it sounds more natural when handing something over." },
    "loc-air07": { e: "Boarding starts at two, so please be at the gate by one forty-five.", t: "El embarque empieza a las dos, así que por favor esté en la puerta a la una y cuarenta y cinco.", s: "Cuando le informas a un pasajero a qué hora comienza a abordar su vuelo.", sEn: "When you tell a passenger what time their flight starts boarding.", n: "Di \"boarding\" como \"BOR-ding\", sin pronunciar la \"a\" extra que tiene en español.", nEn: "Say \"boarding\" as \"BOR-ding\", without adding the extra vowel Spanish speakers tend to insert." },
    "loc-air08": { e: "Have your passport ready, the agent will check it at the gate.", t: "Tenga su pasaporte listo, el agente lo revisará en la puerta.", s: "Cuando le pides a un pasajero que prepare su pasaporte antes de un control.", sEn: "When you ask a passenger to get their passport out before a checkpoint.", n: "\"Have it ready\" es más natural y amable que \"prepare it\" en este contexto.", nEn: "\"Have it ready\" sounds more natural and friendly than \"prepare it\" here." },
    "loc-air09": { e: "Your connection is in Bogotá, and you'll have about two hours between flights.", t: "Su conexión es en Bogotá, y tendrá unas dos horas entre vuelos.", s: "Cuando le explicas a un pasajero dónde hace escala para tomar su siguiente vuelo.", sEn: "When you explain to a passenger where they change planes for their next flight.", n: "\"Connection\" es la escala; no la confundas con \"layover\", que es el tiempo de espera.", nEn: "\"Connection\" is the transfer; don't confuse it with \"layover\", which is the waiting time." },
    "loc-air10": { e: "Please proceed to security; the line is just to your right.", t: "Pase a seguridad, por favor; la fila está justo a su derecha.", s: "Cuando diriges a un pasajero hacia el control de seguridad del aeropuerto.", sEn: "When you direct a passenger toward the airport security checkpoint.", n: "\"Proceed to\" suena formal y educado; en el día a día también puedes decir \"go ahead to security\".", nEn: "\"Proceed to\" sounds formal and polite; casually you can also say \"go ahead to security\"." },
    "loc-air11": { e: "I'm sorry, but you can't bring liquids over 100 milliliters through security.", t: "Lo siento, pero no puede llevar líquidos de más de 100 mililitros por el control de seguridad.", s: "Cuando le informas a un pasajero que un líquido no está permitido en el control.", sEn: "When you tell a passenger that a liquid isn't allowed through the checkpoint.", n: "\"Can't\" se pronuncia corto; cuida no decir \"can\" porque cambia totalmente el sentido.", nEn: "\"Can't\" is pronounced short; be careful not to say \"can\", which flips the meaning." },
    "loc-air12": { e: "Here's your boarding pass, have a good flight!", t: "Aquí tiene su pase de abordar, ¡buen vuelo!", s: "Cuando te despides de un pasajero justo antes de que aborde su avión.", sEn: "When you say goodbye to a passenger right before they board their plane.", n: "También puedes decir \"safe flight\" o \"enjoy your flight\" para variar.", nEn: "You can also say \"safe flight\" or \"enjoy your flight\" for variety." },
    // ===================== Car rental (alquiler-auto-en) =====================
    "loc-aut01": { e: "How many days do you need it for? Our weekly rate is cheaper.", t: "¿Por cuántos días lo necesita? Nuestra tarifa semanal sale más barata.", s: "Cuando un cliente quiere rentar un auto y le preguntas la duración.", sEn: "When a customer wants to rent a car and you ask how long for.", n: "Es más natural agregar \"for\" al final: \"How many days do you need it for?\".", nEn: "It sounds more natural to add \"for\" at the end: \"How many days do you need it for?\"." },
    "loc-aut02": { e: "Does it include insurance, or is that an extra charge?", t: "¿Incluye seguro, o es un cargo adicional?", s: "Cuando un cliente pregunta si el seguro viene incluido en el precio del alquiler.", sEn: "When a customer asks whether insurance is included in the rental price.", n: "\"Insurance\" se acentúa en la segunda sílaba: in-SUR-ance.", nEn: "\"Insurance\" is stressed on the second syllable: in-SUR-ance." },
    "loc-aut03": { e: "Please return it with a full tank, or we'll charge you for the fuel.", t: "Por favor devuélvalo con el tanque lleno, o le cobraremos el combustible.", s: "Cuando le explicas al cliente la política de combustible al devolver el auto.", sEn: "When you explain the fuel policy to a customer returning the car.", n: "\"Full tank\" es la frase fija; \"tank full\" suena incorrecto en inglés.", nEn: "\"Full tank\" is the fixed phrase; \"tank full\" sounds wrong in English." },
    "loc-aut04": { e: "Everything looks good, just sign here, please.", t: "Todo se ve bien, solo firme aquí, por favor.", s: "Cuando le pides al cliente que firme el contrato de alquiler.", sEn: "When you ask the customer to sign the rental contract.", n: "\"Sign\" se pronuncia \"sain\", con la g muda.", nEn: "\"Sign\" is pronounced \"sain\", with a silent g." },
    "loc-aut05": { e: "I need your driver's license and a credit card to complete the rental.", t: "Necesito su licencia de conducir y una tarjeta de crédito para completar el alquiler.", s: "Cuando le pides al cliente los documentos requeridos para rentar.", sEn: "When you ask the customer for the documents required to rent.", n: "Nota el apóstrofo: \"driver's license\", no \"drivers license\".", nEn: "Note the apostrophe: \"driver's license\", not \"drivers license\"." },
    "loc-aut06": { e: "Don't worry, the car is automatic, so you won't need to shift gears.", t: "No se preocupe, el auto es automático, así que no tendrá que cambiar marchas.", s: "Cuando tranquilizas a un cliente diciéndole que el auto no es manual.", sEn: "When you reassure a customer that the car isn't a manual.", n: "En EE. UU. un auto manual se llama \"stick shift\"; útil saberlo si preguntan.", nEn: "In the US a manual car is called a \"stick shift\"; handy to know if they ask." },
    "loc-aut07": { e: "There's a security deposit of two hundred dollars, refunded when you return the car.", t: "Hay un depósito de garantía de doscientos dólares, que se devuelve al regresar el auto.", s: "Cuando le explicas al cliente que debe dejar un depósito reembolsable.", sEn: "When you explain to the customer that there's a refundable deposit.", n: "\"Deposit\" se acentúa en la segunda sílaba: de-PO-sit.", nEn: "\"Deposit\" is stressed on the second syllable: de-PO-sit." },
    "loc-aut08": { e: "Before you drive off, check the car for any damage and let me know.", t: "Antes de salir, revise el auto por si hay daños y avíseme.", s: "Cuando le pides al cliente que inspeccione el auto antes de llevarlo.", sEn: "When you ask the customer to inspect the car before taking it.", n: "\"Damage\" es incontable: no digas \"damages\" para los golpes del auto.", nEn: "\"Damage\" is uncountable: don't say \"damages\" for dents on the car." },
    "loc-aut09": { e: "Drop-off is at the airport branch, and it's open until midnight.", t: "La devolución es en la sucursal del aeropuerto, y abre hasta la medianoche.", s: "Cuando le indicas al cliente dónde debe entregar el auto al final.", sEn: "When you tell the customer where to return the car at the end.", n: "\"Drop-off\" es el sustantivo; el verbo es \"to drop off\" (the car).", nEn: "\"Drop-off\" is the noun; the verb is \"to drop off\" (the car)." },
    "loc-aut10": { e: "Here are your keys, enjoy the trip and drive safely!", t: "Aquí tiene sus llaves, ¡disfrute el viaje y maneje con cuidado!", s: "Cuando te despides del cliente justo después de entregarle el auto.", sEn: "When you say goodbye to the customer right after handing over the car.", n: "\"Drive safely\" (adverbio) es lo correcto; \"drive safe\" se oye informal pero menos cuidado.", nEn: "\"Drive safely\" (adverb) is correct; \"drive safe\" is casual but less polished." },
    // ===================== Museum & tickets (museo-en) =====================
    "loc-mus01": { e: "Admission is twenty thousand, but it's free for children under six.", t: "La entrada cuesta veinte mil, pero es gratis para niños menores de seis.", s: "Cuando le dices a un visitante cuánto cuesta entrar al museo.", sEn: "When you tell a visitor how much it costs to enter the museum.", n: "\"Admission\" es la entrada al lugar; \"ticket\" es el papel que compras.", nEn: "\"Admission\" is entry to the place; \"ticket\" is the paper you buy." },
    "loc-mus02": { e: "You're welcome to take pictures, but no flash photography, please.", t: "Puede tomar fotos, pero no fotos con flash, por favor.", s: "Cuando le recuerdas a un visitante que no use el flash dentro del museo.", sEn: "When you remind a visitor not to use flash inside the museum.", n: "\"Photography\" se acentúa en la segunda sílaba: pho-TO-gra-phy.", nEn: "\"Photography\" is stressed on the second syllable: pho-TO-gra-phy." },
    "loc-mus03": { e: "Just so you know, the museum closes at five, so you have about an hour.", t: "Para que sepa, el museo cierra a las cinco, así que tiene como una hora.", s: "Cuando le informas a un visitante el horario de cierre del museo.", sEn: "When you tell a visitor what time the museum closes.", n: "\"Closes at\" lleva \"at\" para horas exactas; recuérdalo: at five, at noon.", nEn: "\"Closes at\" uses \"at\" for exact times; remember: at five, at noon." },
    "loc-mus04": { e: "The guided tour starts now, please follow me to the main hall.", t: "La visita guiada empieza ahora, por favor síganme a la sala principal.", s: "Cuando anuncias a un grupo que el recorrido con guía va a comenzar.", sEn: "When you announce to a group that the guided tour is about to begin.", n: "También puedes decir \"is starting now\" para sonar un poco más natural.", nEn: "You can also say \"is starting now\" to sound a touch more natural." },
    "loc-mus05": { e: "Please don't touch the artwork, but feel free to take photos without flash.", t: "Por favor, no toque las obras, pero puede tomar fotos sin flash.", s: "Cuando un visitante se acerca demasiado a una pintura o escultura en el museo.", sEn: "When a visitor gets too close to a painting or sculpture in the museum.", n: "Suena más amable si agregas 'please' al inicio y ofreces una alternativa, como tomar fotos.", nEn: "It sounds friendlier if you add 'please' at the start and offer an alternative, like taking photos." },
    "loc-mus06": { e: "The cloakroom is on the left, just past the ticket desk, if you'd like to leave your coat.", t: "El guardarropa está a la izquierda, justo pasando la taquilla, si quiere dejar su abrigo.", s: "Cuando un visitante llega con abrigo, maleta o mochila grande y busca dónde dejarlos.", sEn: "When a visitor arrives with a coat, suitcase, or large backpack and is looking for a place to leave it.", n: "'Cloakroom' se pronuncia 'clouk-rum'; en EE.UU. también puedes decir 'coat check'.", nEn: "'Cloakroom' is pronounced 'klohk-room'; in the US you can also say 'coat check'." },
    "loc-mus07": { e: "There's a student discount, so just show me your ID and you'll pay less.", t: "Hay descuento para estudiantes, así que solo muéstreme su carné y pagará menos.", s: "Cuando un cliente joven pregunta por el precio de la entrada en la taquilla.", sEn: "When a young customer asks about the ticket price at the box office.", n: "Usa 'a student discount' con 'a'; pedir la identificación con 'show me your ID' es lo natural.", nEn: "Use 'a student discount' with 'a'; asking for ID with 'show me your ID' sounds natural." },
    "loc-mus08": { e: "Just follow the arrows on the floor and they'll take you through the whole exhibition.", t: "Solo siga las flechas en el piso y lo llevarán por toda la exposición.", s: "Cuando un visitante no sabe por dónde empezar el recorrido del museo.", sEn: "When a visitor doesn't know where to start the museum route.", n: "'Arrows' se pronuncia 'ÉR-ous' (la 'a' suena como en 'cat', similar a 'air'); el acento va en la primera sílaba.", nEn: "'Arrows' is pronounced 'AIR-ohz'; the stress is on the first syllable." },
    "loc-mus09": { e: "The exhibition is temporary, so it's only here until the end of the month.", t: "La exposición es temporal, así que solo está aquí hasta fin de mes.", s: "Cuando un visitante pregunta si una muestra estará disponible más adelante.", sEn: "When a visitor asks whether a display will still be available later on.", n: "'Temporary' se pronuncia 'tém-po-re-ri'; el opuesto útil es 'permanent' (permanente).", nEn: "'Temporary' is pronounced 'TEM-puh-rair-ee'; the useful opposite is 'permanent'." },
    "loc-mus10": { e: "Here's your ticket and a map. Enjoy your visit!", t: "Aquí tiene su entrada y un mapa. ¡Disfrute su visita!", s: "Cuando entregas la entrada al visitante y se va a recorrer el museo.", sEn: "When you hand the visitor their ticket and they head off to explore the museum.", n: "Dilo con una sonrisa al final; una variante más corta es solo 'Enjoy!'", nEn: "Say it with a smile at the end; a shorter variant is just 'Enjoy!'" },
    // ===================== Deliveries (delivery-en) =====================
    "loc-del01": { e: "Hi, I have your order here from the restaurant.", t: "Hola, tengo su pedido aquí del restaurante.", s: "Cuando llegas a la puerta del cliente para entregar la comida o el paquete.", sEn: "When you arrive at the customer's door to hand over the food or package.", n: "'I have your order' suena más natural que 'I bring your order'; evita 'I bring'.", nEn: "'I have your order' sounds more natural than 'I bring your order'; avoid 'I bring'." },
    "loc-del02": { e: "Can you open the gate? I have a delivery for apartment 3B.", t: "¿Me abre el portón? Traigo una entrega para el apartamento 3B.", s: "Cuando llegas a un edificio cerrado y necesitas que te dejen entrar.", sEn: "When you arrive at a locked building and need someone to let you in.", n: "Para sonar más cortés puedes decir 'Could you open the gate, please?'", nEn: "To sound more polite you can say 'Could you open the gate, please?'" },
    "loc-del03": { e: "Which floor is it? I'll bring it right up.", t: "¿En qué piso es? Se lo subo enseguida.", s: "Cuando entras a un edificio con varios pisos y no sabes a cuál subir.", sEn: "When you enter a multi-floor building and aren't sure which one to go up to.", n: "En EE.UU. el primer piso es 'first floor' (planta baja); en el Reino Unido es 'ground floor'.", nEn: "In the US the first floor is the ground level; in the UK that's the 'ground floor'." },
    "loc-del04": { e: "Here's your order, still hot. Enjoy your order!", t: "Aquí tiene su pedido, todavía caliente. ¡Que disfrute su pedido!", s: "Al entregar el pedido al cliente.", sEn: "When handing the order to the customer.", n: "\"Order\" (pedido) aplica a comida para llevar o domicilio.", nEn: "\"Order\" works for takeout or delivery food." },
    "loc-del05": { e: "Can you sign here, please? Just on the screen with your finger.", t: "¿Me firma aquí, por favor? Solo en la pantalla con el dedo.", s: "Cuando el cliente debe firmar para confirmar que recibió el pedido.", sEn: "When the customer needs to sign to confirm they received the order.", n: "Agregar 'please' lo hace más cortés; 'sign' se pronuncia 'sain', la g es muda.", nEn: "Adding 'please' makes it more polite; 'sign' is pronounced 'sine', the g is silent." },
    "loc-del06": { e: "Your order arrives in ten minutes; the driver is on the way.", t: "Su pedido llega en diez minutos; el repartidor va en camino.", s: "Cuando informas al cliente por teléfono o app cuánto falta para la entrega.", sEn: "When you tell the customer by phone or app how long until delivery.", n: "También puedes decir 'will arrive in ten minutes'; 'in' indica tiempo que falta.", nEn: "You can also say 'will arrive in ten minutes'; 'in' marks the time remaining." },
    "loc-del07": { e: "That'll be fifteen dollars. Cash or card?", t: "Son quince dólares. ¿Efectivo o tarjeta?", s: "Cuando el cliente recibe el pedido y debe pagar al repartidor.", sEn: "When the customer receives the order and needs to pay the delivery person.", n: "Es una frase fija y corta; di 'card' (no 'credit card') para ir más rápido.", nEn: "It's a fixed, short phrase; say 'card' (not 'credit card') to keep it quick." },
    "loc-del08": { e: "No problem, I'll leave it at the door and text you.", t: "Sin problema, lo dejo en la puerta y le escribo.", s: "Cuando el cliente pide entrega sin contacto y no quiere abrir la puerta.", sEn: "When the customer asks for contactless delivery and doesn't want to open the door.", n: "'At the door' es lo común; 'text you' significa mandar un mensaje de texto.", nEn: "'At the door' is common; 'text you' means to send a text message." },
    "loc-del09": { e: "I'm downstairs by the entrance whenever you're ready.", t: "Estoy abajo en la entrada cuando esté listo.", s: "Cuando llegas y avisas al cliente que esperas en la planta baja del edificio.", sEn: "When you arrive and let the customer know you're waiting on the ground level.", n: "'Downstairs' es una sola palabra; lo opuesto es 'upstairs' (arriba).", nEn: "'Downstairs' is one word; the opposite is 'upstairs'." },
    "loc-del10": { e: "Thanks for your order, and have a great day!", t: "Gracias por su pedido, ¡y que tenga un buen día!", s: "Cuando terminas la entrega y te despides del cliente.", sEn: "When you finish the delivery and say goodbye to the customer.", n: "Cerrar con 'have a great day' deja buena impresión y suma para una buena reseña.", nEn: "Closing with 'have a great day' leaves a good impression and helps earn a good review." },
    // ===================== Gym & fitness (gym-en) =====================
    "loc-gym01": { e: "Come on, ten more reps and then we'll rest.", t: "Vamos, diez repeticiones más y luego descansamos.", s: "Cuando como entrenador animas a alguien a terminar una serie de ejercicios.", sEn: "When, as a trainer, you push someone to finish a set of exercises.", n: "'Reps' es la forma corta de 'repetitions', muy usada en el gimnasio.", nEn: "'Reps' is the short form of 'repetitions', very common at the gym." },
    "loc-gym02": { e: "Keep your back straight so you don't hurt yourself.", t: "Mantenga la espalda recta para no lastimarse.", s: "Cuando corriges la postura de alguien que levanta peso en el gimnasio.", sEn: "When you correct the posture of someone lifting weights at the gym.", n: "'Straight' se pronuncia 'streit'; no la confundas con 'strait'.", nEn: "'Straight' is pronounced 'strayt'; don't confuse it with 'strait'." },
    "loc-gym03": { e: "Great job, keep it up, you're almost there!", t: "¡Buen trabajo, siga así, ya casi lo logra!", s: "Cuando felicitas a alguien que se está esforzando durante el entrenamiento.", sEn: "When you praise someone who is pushing hard during their workout.", n: "'Keep it up' significa 'siga así'; es muy motivador y se usa mucho en el gimnasio.", nEn: "'Keep it up' means to keep going; it's very motivating and common at the gym." },
    "loc-gym04": { e: "Breathe out as you lift, and breathe in as you go down.", t: "Exhale al subir, e inhale al bajar.", s: "Cuando enseñas la técnica de respiración correcta durante un ejercicio.", sEn: "When you teach the correct breathing technique during an exercise.", n: "'Breathe' (verbo) suena 'briid'; 'breath' (sustantivo) suena 'bréth' con th suave, son distintos.", nEn: "'Breathe' (verb) sounds like 'breeth'; 'breath' (noun) sounds like 'breth', they differ." },
    "loc-gym05": { e: "Good work, now rest for thirty seconds before the next set.", t: "Buen trabajo, ahora descanse treinta segundos antes de la siguiente serie.", s: "Cuando guías a un cliente entre series y quieres darle una pausa corta.", sEn: "When you coach a client between sets and want to give a short pause.", n: "Puedes decir \"take thirty seconds\" como variante más casual.", nEn: "You can say \"take thirty seconds\" as a more casual variant." },
    "loc-gym06": { e: "Before you lift anything, don't forget to warm up for five minutes.", t: "Antes de levantar peso, no olvide calentar cinco minutos.", s: "Cuando un cliente quiere empezar a entrenar de inmediato sin preparación.", sEn: "When a client wants to start training right away without preparation.", n: "\"Warm up\" es verbo separado; el sustantivo es \"a warm-up\" con guion.", nEn: "\"Warm up\" is a two-word verb; the noun is \"a warm-up\" with a hyphen." },
    "loc-gym07": { e: "You look tired, drink some water and take a quick break.", t: "Se ve cansado, tome agua y descanse un momento.", s: "Cuando ves a alguien sofocado durante el entrenamiento.", sEn: "When you see someone overheated during a workout.", n: "\"Drink some water\" suena más natural que \"drink water\" para una sugerencia.", nEn: "\"Drink some water\" sounds more natural than \"drink water\" for a suggestion." },
    "loc-gym08": { e: "Control the movement and lower it slowly, don't drop the weight.", t: "Controle el movimiento y baje despacio, no suelte el peso.", s: "Cuando corriges la técnica de alguien que baja la pesa muy rápido.", sEn: "When you correct someone's form as they drop the weight too fast.", n: "Para personas, di \"go down slowly\"; \"lower it\" es para objetos o pesas.", nEn: "For people say \"go down slowly\"; \"lower it\" is for objects or weights." },
    "loc-gym09": { e: "Come on, one more set and then we're done for today.", t: "Vamos, una serie más y terminamos por hoy.", s: "Cuando animas a un cliente a completar la última ronda del ejercicio.", sEn: "When you encourage a client to finish the last round of the exercise.", n: "\"Set\" es una serie de repeticiones; \"rep\" es cada repetición individual.", nEn: "A \"set\" is a series of reps; a \"rep\" is each individual repetition." },
    "loc-gym10": { e: "Great session today, just stretch when you finish to avoid soreness.", t: "Excelente sesión hoy, solo estire al terminar para evitar dolores.", s: "Cuando cierras el entrenamiento y recomiendas estiramientos finales.", sEn: "When you wrap up the workout and recommend final stretches.", n: "\"Stretch\" suena la 'tch' como en \"church\", no como una 's' suave.", nEn: "In \"stretch\" the 'tch' sounds like in \"church,\" not a soft 's.'" },
    // ===================== Home & helpers (hogar-en) =====================
    "loc-hog01": { e: "Don't worry, it's fixed now and the faucet isn't leaking anymore.", t: "No se preocupe, ya está arreglado y la llave ya no gotea.", s: "Cuando le avisas al dueño de casa que terminaste una reparación.", sEn: "When you tell the homeowner you finished a repair.", n: "\"It's fixed\" describe el resultado; \"I fixed it\" enfatiza que tú lo hiciste.", nEn: "\"It's fixed\" describes the result; \"I fixed it\" stresses that you did it." },
    "loc-hog02": { e: "Just to confirm, what time do I pick up the kids from school?", t: "Solo para confirmar, ¿a qué hora recojo a los niños de la escuela?", s: "Cuando organizas el día con la familia y necesitas la hora exacta.", sEn: "When you plan the day with the family and need the exact time.", n: "\"Pick up\" para personas; di \"drop off\" cuando los llevas y los dejas.", nEn: "\"Pick up\" is for getting people; use \"drop off\" when you leave them." },
    "loc-hog03": { e: "I can't open this, I need a tool, do you have a screwdriver?", t: "No puedo abrir esto, necesito una herramienta, ¿tiene un destornillador?", s: "Cuando una tarea requiere algo que no tienes a mano en la casa.", sEn: "When a task needs something you don't have on hand at the house.", n: "\"Tool\" se pronuncia con 'u' larga y termina en L: suena 'tuul', no 'tul' con u corta.", nEn: "\"Tool\" has a long 'oo' and ends in an L sound: say 'toool', not a short 'tull'." },
    "loc-hog04": { e: "The food is ready, should I serve it now or keep it warm?", t: "La comida está lista, ¿la sirvo ahora o la mantengo caliente?", s: "Cuando terminas de cocinar y avisas a la familia.", sEn: "When you finish cooking and let the family know.", n: "\"Food\" es incontable, así que no digas \"the foods are ready\".", nEn: "\"Food\" is uncountable, so don't say \"the foods are ready.\"" },
    "loc-hog05": { e: "Once everyone's done eating, I'll clean the kitchen.", t: "Cuando todos terminen de comer, voy a limpiar la cocina.", s: "Cuando organizas tus tareas y avisas qué harás después.", sEn: "When you plan your tasks and say what you'll do next.", n: "\"I'll\" suena \"ail\"; junta las palabras para sonar más fluido y natural.", nEn: "\"I'll\" sounds like \"ail\"; blend the words to sound more fluent." },
    "loc-hog06": { e: "I finished the laundry, where do I put this clean towel?", t: "Terminé la ropa, ¿dónde guardo esta toalla limpia?", s: "Cuando no sabes el lugar correcto para algo en la casa.", sEn: "When you don't know the right place for something in the house.", n: "\"Where do I put this?\" es para guardar; \"where does this go?\" es otra variante.", nEn: "\"Where do I put this?\" is for storing; \"where does this go?\" is a variant." },
    "loc-hog07": { e: "The kids already ate, so they just need a bath before bed.", t: "Los niños ya comieron, así que solo falta bañarlos antes de dormir.", s: "Cuando informas el estado de los niños al volver el papá o la mamá.", sEn: "When you update the parent on the kids when they get home.", n: "\"Already\" va antes del verbo principal: \"already ate\", no \"ate already\".", nEn: "\"Already\" goes before the main verb: \"already ate,\" not \"ate already.\"" },
    "loc-hog08": { e: "I'm running to the store, I'll be back in an hour.", t: "Voy corriendo a la tienda, vuelvo en una hora.", s: "Cuando sales un momento y avisas cuándo regresas.", sEn: "When you step out briefly and say when you'll return.", n: "Se dice \"in an hour\" para una hora aproximada; \"in one hour\" enfatiza exactamente una hora.", nEn: "Say \"in an hour\" for roughly one hour; \"in one hour\" stresses exactly one hour." },
    "loc-hog09": { e: "Just so you know, we're out of soap, can I buy more?", t: "Para que sepa, se acabó el jabón, ¿puedo comprar más?", s: "Cuando notas que falta un producto de limpieza en la casa.", sEn: "When you notice a cleaning product has run out at the house.", n: "\"We're out of\" significa que se acabó algo; muy común en casa y trabajo.", nEn: "\"We're out of\" means something has run out; very common at home and work." },
    "loc-hog10": { e: "The internet seems slow, should I check the Wi-Fi router?", t: "El internet parece lento, ¿reviso el router del wifi?", s: "Cuando la conexión falla y ofreces revisarla antes de actuar.", sEn: "When the connection fails and you offer to check before acting.", n: "\"Wi-Fi\" se dice \"wai-fai\"; ofrecer con \"Should I...?\" suena servicial.", nEn: "\"Wi-Fi\" is said \"wai-fai\"; offering with \"Should I...?\" sounds helpful." },
    "loc-hog11": { e: "To save energy, please turn off the light when you leave the room.", t: "Para ahorrar energía, por favor apague la luz al salir del cuarto.", s: "Cuando recuerdas a alguien apagar las luces al salir.", sEn: "When you remind someone to switch off the lights as they leave.", n: "\"Turn off\" para luces o aparatos; \"switch off\" es un sinónimo común.", nEn: "\"Turn off\" works for lights or devices; \"switch off\" is a common synonym." },
    "loc-hog12": { e: "The mixer broke, I need a spare part to fix it properly.", t: "La batidora se dañó, necesito un repuesto para arreglarla bien.", s: "Cuando algo se descompone y hace falta una pieza de reemplazo.", sEn: "When something breaks and a replacement piece is needed.", n: "\"Spare part\" es el repuesto; \"replacement\" también sirve en este contexto.", nEn: "\"Spare part\" means the replacement piece; \"replacement\" also works here." },
    // ============== VOCABULARIO TEMÁTICO (loc-voc) — palabras por tema ==============
    "loc-vnum01": { e: "Can I get just one coffee to go, please?", t: "¿Me das solo un café para llevar, por favor?", s: "Cuando pides una sola unidad de algo en un mostrador.", sEn: "When you order a single item at a counter.", n: "\"One\" se pronuncia \"uan\", no \"on\"; rima con \"won\".", nEn: "\"One\" is pronounced \"wun\", not \"on\"; it rhymes with \"won\"." },
    "loc-vnum02": { e: "We need a table for two, please.", t: "Necesitamos una mesa para dos, por favor.", s: "Al pedir mesa para dos personas en un restaurante.", sEn: "When asking for a table for two people at a restaurant.", n: "\"Two\" suena \"tu\"; la 'w' es muda, igual que en \"who\".", nEn: "\"Two\" sounds like \"too\"; the 'w' is silent, like in \"who\"." },
    "loc-vnum03": { e: "I'll be there in three minutes.", t: "Llego en tres minutos.", s: "Cuando avisas cuánto vas a tardar en llegar.", sEn: "When you tell someone how long until you arrive.", n: "\"Three\" lleva el sonido 'th' suave; saca un poco la lengua, no digas \"tri\".", nEn: "\"Three\" has the soft 'th' sound; put your tongue out a little, don't say \"tree\"." },
    "loc-vnum04": { e: "I worked four hours this morning.", t: "Trabajé cuatro horas esta mañana.", s: "Al contar cuántas horas trabajaste o esperaste.", sEn: "When counting how many hours you worked or waited.", n: "\"Four\" (4) y \"for\" (para) suenan casi igual; el contexto los distingue.", nEn: "\"Four\" (4) and \"for\" (for) sound almost the same; context tells them apart." },
    "loc-vnum05": { e: "It costs five dollars.", t: "Cuesta cinco dólares.", s: "Cuando dices el precio de algo barato.", sEn: "When stating the price of something cheap.", n: "\"Five\" termina en sonido 'v', no 'f'; haz vibrar el labio al final.", nEn: "\"Five\" ends in a 'v' sound, not 'f'; let your lip buzz at the end." },
    "loc-vnum06": { e: "Let's meet at six.", t: "Veámonos a las seis.", s: "Al acordar una hora para encontrarse.", sEn: "When agreeing on a time to meet.", n: "\"Six\" lleva una 'i' corta, como en \"sit\"; no la alargues.", nEn: "\"Six\" has a short 'i' like in \"sit\"; don't stretch it." },
    "loc-vnum07": { e: "There are seven people in my family.", t: "Somos siete personas en mi familia.", s: "Al decir cuántas personas son en un grupo o familia.", sEn: "When saying how many people are in a group or family.", n: "Se pronuncia SÉ-ven, con el acento en la primera sílaba.", nEn: "It's pronounced SE-ven, with the stress on the first syllable." },
    "loc-vnum08": { e: "The store opens at eight.", t: "La tienda abre a las ocho.", s: "Al hablar del horario de apertura de un lugar.", sEn: "When talking about a place's opening time.", n: "\"Eight\" suena \"éit\"; el grupo 'gh' es mudo.", nEn: "\"Eight\" sounds like \"ate\"; the 'gh' is silent." },
    "loc-vnum09": { e: "She is nine years old.", t: "Ella tiene nueve años.", s: "Al decir la edad de alguien.", sEn: "When stating someone's age.", n: "\"Nine\" suena \"náin\"; rima con \"mine\" y \"line\".", nEn: "\"Nine\" rhymes with \"mine\" and \"line\"." },
    "loc-vnum10": { e: "I'll be ready in ten minutes.", t: "Estaré listo en diez minutos.", s: "Cuando avisas que tardarás un poco.", sEn: "When you let someone know you'll take a little while.", n: "\"Ten\" rima con \"pen\"; la 'e' es corta y clara.", nEn: "\"Ten\" rhymes with \"pen\"; the 'e' is short and clear." },
    "loc-vnum11": { e: "The bus leaves at eleven.", t: "El autobús sale a las once.", s: "Al hablar de un horario cercano al mediodía o la noche.", sEn: "When talking about a time near noon or late evening.", n: "Se pronuncia i-LÉ-ven, con el acento en la segunda sílaba.", nEn: "It's pronounced i-LE-ven, with the stress on the second syllable." },
    "loc-vnum12": { e: "A dozen eggs is twelve eggs.", t: "Una docena de huevos son doce huevos.", s: "Al contar docenas o ver la hora del mediodía.", sEn: "When counting dozens or telling noon time.", n: "\"Twelve\" termina en sonido 'v'; no digas \"tuelf\".", nEn: "\"Twelve\" ends in a 'v' sound; don't say \"twelf\"." },
    "loc-vnum13": { e: "My brother is thirteen.", t: "Mi hermano tiene trece.", s: "Al decir la edad de un adolescente.", sEn: "When saying a teenager's age.", n: "Ojo: \"thirteen\" (13) se acentúa al final, distinto de \"thirty\" (30).", nEn: "Careful: \"thirteen\" (13) is stressed at the end, unlike \"thirty\" (30)." },
    "loc-vnum14": { e: "She turns fourteen next week.", t: "Ella cumple catorce la próxima semana.", s: "Al hablar de un cumpleaños cercano.", sEn: "When talking about an upcoming birthday.", n: "\"Fourteen\" lleva el acento al final: for-TÍN.", nEn: "\"Fourteen\" is stressed at the end: four-TEEN." },
    "loc-vnum15": { e: "It's a quarter past, so fifteen minutes.", t: "Es y cuarto, o sea quince minutos.", s: "Al hablar de minutos o de un cuarto de hora.", sEn: "When talking about minutes or a quarter hour.", n: "\"Fifteen\" (15) acentúa el final; \"fifty\" (50) acentúa el inicio.", nEn: "\"Fifteen\" (15) stresses the end; \"fifty\" (50) stresses the start." },
    "loc-vnum16": { e: "You can drive at sixteen here.", t: "Aquí puedes manejar a los dieciséis.", s: "Al hablar de la edad para algo permitido.", sEn: "When talking about the age you're allowed to do something.", n: "\"Sixteen\" suena siks-TÍN, con el acento al final.", nEn: "\"Sixteen\" sounds like six-TEEN, stressed at the end." },
    "loc-vnum17": { e: "The room is on the seventeenth floor, room seventeen.", t: "La habitación está en el piso diecisiete, cuarto diecisiete.", s: "Al indicar un número de piso o de habitación.", sEn: "When pointing out a floor or room number.", n: "Se pronuncia se-ven-TÍN, con el acento en la última sílaba.", nEn: "It's pronounced se-ven-TEEN, with the stress on the last syllable." },
    "loc-vnum18": { e: "You have to be eighteen to enter.", t: "Tienes que tener dieciocho para entrar.", s: "Al hablar de la mayoría de edad para entrar a un lugar.", sEn: "When talking about the age limit to enter a place.", n: "\"Eighteen\" suena ei-TÍN; la 'gh' es muda y el acento va al final.", nEn: "\"Eighteen\" sounds like ay-TEEN; the 'gh' is silent and the stress is at the end." },
    "loc-vnum19": { e: "My sister is nineteen now.", t: "Mi hermana ya tiene diecinueve.", s: "Al decir la edad de alguien casi en los veinte.", sEn: "When saying someone's age, almost twenty.", n: "\"Nineteen\" acentúa el final: nain-TÍN.", nEn: "\"Nineteen\" stresses the end: nine-TEEN." },
    "loc-vnum20": { e: "It costs twenty dollars.", t: "Cuesta veinte dólares.", s: "Al decir un precio redondo de algo.", sEn: "When stating a round price for something.", n: "Mucha gente dice \"TUÉ-ni\", casi sin la 't'; ambas formas se aceptan.", nEn: "Many people say \"TWEN-ee\", almost dropping the 't'; both forms are fine." },
    "loc-vnum21": { e: "My father just turned thirty.", t: "Mi papá acaba de cumplir treinta.", s: "Al hablar de una edad o una cantidad redonda.", sEn: "When talking about an age or a round amount.", n: "\"Thirty\" (30) acentúa el inicio; no lo confundas con \"thirteen\" (13).", nEn: "\"Thirty\" (30) stresses the start; don't confuse it with \"thirteen\" (13)." },
    "loc-vnum22": { e: "The trip takes about forty minutes.", t: "El viaje toma unos cuarenta minutos.", s: "Al estimar cuánto dura un trayecto.", sEn: "When estimating how long a trip takes.", n: "\"Forty\" se escribe sin 'u', a diferencia de \"four\".", nEn: "\"Forty\" is spelled without a 'u', unlike \"four\"." },
    "loc-vnum23": { e: "There were about fifty people there.", t: "Había como cincuenta personas ahí.", s: "Al calcular cuánta gente había en un lugar.", sEn: "When estimating how many people were somewhere.", n: "\"Fifty\" (50) acentúa el inicio; \"fifteen\" (15) acentúa el final.", nEn: "\"Fifty\" (50) stresses the start; \"fifteen\" (15) stresses the end." },
    "loc-vnum24": { e: "That'll be one hundred dollars.", t: "Son cien dólares.", s: "Al decir un precio o cantidad de cien.", sEn: "When saying a price or amount of a hundred.", n: "En inglés casi siempre se dice \"a hundred\" o \"one hundred\", no solo \"hundred\".", nEn: "In English you usually say \"a hundred\" or \"one hundred\", not just \"hundred\"." },
    "loc-vnum25": { e: "The rent is one thousand a month.", t: "La renta es de mil al mes.", s: "Al hablar de cantidades grandes como precios o rentas.", sEn: "When talking about large amounts like prices or rent.", n: "\"Thousand\" lleva 'th' suave al inicio; di ZÁU-sand, no \"tausand\".", nEn: "\"Thousand\" starts with the soft 'th'; say THOU-sand, not \"tousand\"." },
    "loc-vnum26": { e: "She won a million dollars.", t: "Ella ganó un millón de dólares.", s: "Al hablar de una cantidad muy grande de dinero.", sEn: "When talking about a very large amount of money.", n: "Se pronuncia MÍ-lion; el plural es \"millions\".", nEn: "It's pronounced MIL-yun; the plural is \"millions\"." },
    "loc-vcol01": { e: "The light is red, so we have to stop.", t: "El semáforo está en rojo, así que hay que parar.", s: "Al hablar de un semáforo o de un color llamativo.", sEn: "When talking about a traffic light or a bold color.", n: "\"Red\" es corto; rima con \"bed\" y \"bread\".", nEn: "\"Red\" is short; it rhymes with \"bed\" and \"bread\"." },
    "loc-vcol02": { e: "I love your blue jacket.", t: "Me encanta tu chamarra azul.", s: "Al hacerle un cumplido a alguien por su ropa.", sEn: "When complimenting someone on their clothes.", n: "\"Blue\" (azul) y \"blew\" (sopló) suenan igual; los distingue el contexto.", nEn: "\"Blue\" (the color) and \"blew\" (past of blow) sound the same; context tells them apart." },
    "loc-vcol03": { e: "The grass is really green after the rain.", t: "El pasto está bien verde después de la lluvia.", s: "Al describir plantas, pasto o algo de color verde.", sEn: "When describing plants, grass, or something green.", n: "\"Green\" lleva una 'i' larga, como en \"see\"; di grin con la vocal estirada.", nEn: "\"Green\" has a long 'i' like in \"see\"; stretch the vowel." },
    "loc-vcol04": { e: "She's wearing a bright yellow dress.", t: "Ella lleva un vestido amarillo brillante.", s: "Al describir ropa o un objeto de color llamativo.", sEn: "When describing clothing or a bright-colored object.", n: "Se pronuncia YÉ-lou; la 'y' inicial suena como la 'y' suave del español, y la 'll' suena como una 'l' normal.", nEn: "It's pronounced YEL-low; the initial 'y' sounds like a soft 'y', and the 'll' is a regular 'l' sound." },
    "loc-vcol05": { e: "I'll have the coffee black, please.", t: "Quiero el café solo, por favor.", s: "Al pedir café sin leche o describir algo de color negro.", sEn: "When ordering coffee without milk or describing something black.", n: "\"Black coffee\" es café solo; no significa que el café sea de color literal.", nEn: "\"Black coffee\" means coffee with no milk, not that it's literally black-colored." },
    "loc-vcol06": { e: "He's wearing a white shirt.", t: "Él lleva una camisa blanca.", s: "Al describir ropa o algo de color blanco.", sEn: "When describing clothing or something white.", n: "\"White\" empieza con un sonido de aire suave; di uáit, no \"güait\".", nEn: "\"White\" starts with a soft breathy sound; say wite, not \"gwite\"." },
    "loc-vcol07": { e: "Can I have an orange juice?", t: "¿Me das un jugo de naranja?", s: "Al pedir una bebida o nombrar la fruta y el color.", sEn: "When ordering a drink or naming the fruit and color.", n: "\"Orange\" sirve para la fruta y el color; se pronuncia Ó-rinch.", nEn: "\"Orange\" works for both the fruit and the color; it's said OR-inj." },
    "loc-vcol08": { e: "She painted her nails purple.", t: "Se pintó las uñas de morado.", s: "Al describir un color morado en ropa, uñas u objetos.", sEn: "When describing a purple color on clothes, nails, or objects.", n: "Se pronuncia PÉR-pol; cuidado, no es \"purpol\" con 'o' clara.", nEn: "It's pronounced PUR-pul; watch the second vowel, it's a soft 'uh'." },
    "loc-vcol09": { e: "The baby's room is pink.", t: "El cuarto del bebé es rosa.", s: "Al describir un color rosado en una habitación u objeto.", sEn: "When describing a pink color in a room or object.", n: "\"Pink\" lleva una 'i' corta; no la confundas con \"think\".", nEn: "\"Pink\" has a short 'i'; don't mix it up with \"think\"." },
    "loc-vcol10": { e: "The sky is gray today.", t: "El cielo está gris hoy.", s: "Al describir el clima nublado o un color apagado.", sEn: "When describing cloudy weather or a dull color.", n: "Se escribe \"gray\" (EE. UU.) o \"grey\" (Reino Unido); suenan igual.", nEn: "It's spelled \"gray\" (US) or \"grey\" (UK); both sound the same." },
    "loc-vcol11": { e: "I'd like the brown shoes, please.", t: "Quiero los zapatos marrones, por favor.", s: "Al describir el color café de ropa, zapatos o cabello.", sEn: "When describing the brown color of clothes, shoes, or hair.", n: "\"Brown\" rima con \"down\" y \"town\"; di bráun.", nEn: "\"Brown\" rhymes with \"down\" and \"town\"; say brown." },
    "loc-vcol12": { e: "She has a gold ring.", t: "Ella tiene un anillo dorado.", s: "Al describir joyas o algo de color dorado.", sEn: "When describing jewelry or something gold-colored.", n: "\"Gold\" sirve para el metal y el color; se pronuncia góuld.", nEn: "\"Gold\" works for both the metal and the color; it's said gohld." },
    "loc-vcol13": { e: "I prefer the silver phone.", t: "Prefiero el teléfono plateado.", s: "Al elegir un objeto por su color plateado.", sEn: "When choosing an object for its silver color.", n: "Se pronuncia SÍL-ver; vale para el metal y el color.", nEn: "It's pronounced SIL-ver; it works for the metal and the color." },
    "loc-vcol14": { e: "I'd like a light blue shirt.", t: "Quiero una camisa azul claro.", s: "Al pedir un tono claro de un color.", sEn: "When asking for a light shade of a color.", n: "\"Light\" antes de un color significa \"claro\"; \"light blue\" es azul claro.", nEn: "\"Light\" before a color means pale; \"light blue\" is pale blue." },
    "loc-vcol15": { e: "He has dark hair.", t: "Él tiene el pelo oscuro.", s: "Al describir un tono oscuro de color o de cabello.", sEn: "When describing a dark shade of color or hair.", n: "\"Dark\" antes de un color lo hace más intenso; \"dark green\" es verde oscuro.", nEn: "\"Dark\" before a color makes it deeper; \"dark green\" is deep green." },
    "loc-vcol16": { e: "The market is so colorful.", t: "El mercado es muy colorido.", s: "Al describir un lugar lleno de colores vivos.", sEn: "When describing a place full of bright colors.", n: "Se escribe \"colorful\" (EE. UU.) o \"colourful\" (Reino Unido).", nEn: "It's spelled \"colorful\" (US) or \"colourful\" (UK)." },
    "loc-vfam01": { e: "My mother lives nearby.", t: "Mi madre vive cerca.", s: "Al hablar de tu mamá en una conversación.", sEn: "When talking about your mom in conversation.", n: "\"Mother\" es formal; en el día a día se dice más \"mom\".", nEn: "\"Mother\" is formal; in everyday speech people say \"mom\" more." },
    "loc-vfam02": { e: "My father works at a hospital.", t: "Mi padre trabaja en un hospital.", s: "Al hablar de tu papá y su trabajo.", sEn: "When talking about your dad and his job.", n: "\"Father\" es formal; en lo cotidiano se usa más \"dad\".", nEn: "\"Father\" is formal; everyday speech uses \"dad\" more." },
    "loc-vfam03": { e: "Their son is starting school this year.", t: "Su hijo empieza la escuela este año.", s: "Al hablar del hijo varón de alguien.", sEn: "When talking about someone's male child.", n: "\"Son\" (hijo) y \"sun\" (sol) suenan igual; los distingue el contexto.", nEn: "\"Son\" and \"sun\" sound the same; context tells them apart." },
    "loc-vfam04": { e: "My daughter loves to draw.", t: "A mi hija le encanta dibujar.", s: "Al hablar de tu hija en una conversación.", sEn: "When talking about your daughter in conversation.", n: "\"Daughter\" suena DÓ-ter; el grupo 'gh' es mudo.", nEn: "\"Daughter\" sounds like DAW-ter; the 'gh' is silent." },
    "loc-vfam05": { e: "My brother is older than me.", t: "Mi hermano es mayor que yo.", s: "Al hablar de tu hermano en una conversación.", sEn: "When talking about your brother in conversation.", n: "Se pronuncia BRÁ-der, con 'th' suave en el medio.", nEn: "It's pronounced BRUH-ther, with a soft 'th' in the middle." },
    "loc-vfam06": { e: "My sister is a nurse.", t: "Mi hermana es enfermera.", s: "Al hablar de tu hermana y su trabajo.", sEn: "When talking about your sister and her job.", n: "Se pronuncia SÍS-ter, con 'i' corta al inicio.", nEn: "It's pronounced SIS-ter, with a short 'i' at the start." },
    "loc-vfam07": { e: "My grandfather tells great stories.", t: "Mi abuelo cuenta muy buenas historias.", s: "Al hablar del papá de tu papá o de tu mamá.", sEn: "When talking about your parent's father.", n: "Cariñosamente se dice \"grandpa\" en vez de \"grandfather\".", nEn: "Affectionately people say \"grandpa\" instead of \"grandfather\"." },
    "loc-vfam08": { e: "My grandmother makes the best soup.", t: "Mi abuela hace la mejor sopa.", s: "Al hablar de la mamá de tu papá o de tu mamá.", sEn: "When talking about your parent's mother.", n: "Cariñosamente se dice \"grandma\" en vez de \"grandmother\".", nEn: "Affectionately people say \"grandma\" instead of \"grandmother\"." },
    "loc-vfam09": { e: "My uncle is coming for dinner.", t: "Mi tío viene a cenar.", s: "Al hablar del hermano de tu papá o de tu mamá.", sEn: "When talking about your parent's brother.", n: "Se pronuncia ÁN-kol; la 'u' suena como una 'a' suave.", nEn: "It's pronounced UN-kul; the 'u' sounds like a soft 'uh'." },
    "loc-vfam10": { e: "My aunt lives in another city.", t: "Mi tía vive en otra ciudad.", s: "Al hablar de la hermana de tu papá o de tu mamá.", sEn: "When talking about your parent's sister.", n: "\"Aunt\" suele sonar \"ant\", igual que \"ant\" (hormiga); el contexto los separa.", nEn: "\"Aunt\" often sounds like \"ant\" (the insect); context keeps them apart." },
    "loc-vfam11": { e: "My cousin and I grew up together.", t: "Mi primo y yo crecimos juntos.", s: "Al hablar del hijo o la hija de tu tío o tía.", sEn: "When talking about your uncle's or aunt's child.", n: "\"Cousin\" sirve para primo y prima; se pronuncia KÁ-sin.", nEn: "\"Cousin\" works for both male and female; it's said KUH-zin." },
    "loc-vfam12": { e: "My nephew just learned to walk.", t: "Mi sobrino acaba de aprender a caminar.", s: "Al hablar del hijo de tu hermano o hermana.", sEn: "When talking about your sibling's son.", n: "\"Nephew\" es sobrino (varón); \"niece\" es sobrina.", nEn: "\"Nephew\" is your brother/sister's son; \"niece\" is the daughter." },
    "loc-vfam13": { e: "My niece is turning five.", t: "Mi sobrina va a cumplir cinco.", s: "Al hablar de la hija de tu hermano o hermana.", sEn: "When talking about your sibling's daughter.", n: "\"Niece\" se pronuncia nis, con 'i' larga, como \"piece\".", nEn: "\"Niece\" is pronounced neece, with a long 'i', like \"piece\"." },
    "loc-vfam14": { e: "Her husband cooks every night.", t: "Su esposo cocina todas las noches.", s: "Al hablar del marido de una mujer.", sEn: "When talking about a woman's husband.", n: "Se pronuncia JÁS-band; la primera sílaba lleva el acento.", nEn: "It's pronounced HUZ-band; the first syllable is stressed." },
    "loc-vfam15": { e: "His wife is a teacher.", t: "Su esposa es maestra.", s: "Al hablar de la mujer casada con un hombre.", sEn: "When talking about a man's wife.", n: "El plural es \"wives\"; cambia la 'f' por 'v'.", nEn: "The plural is \"wives\"; the 'f' changes to a 'v'." },
    "loc-vfam16": { e: "They have three children.", t: "Tienen tres hijos.", s: "Al hablar de los hijos de una familia.", sEn: "When talking about a family's kids.", n: "\"Children\" es el plural irregular de \"child\"; no se dice \"childs\".", nEn: "\"Children\" is the irregular plural of \"child\"; never \"childs\"." },
    "loc-vfam17": { e: "The baby is sleeping.", t: "El bebé está durmiendo.", s: "Al hablar de un recién nacido o un niño muy pequeño.", sEn: "When talking about a newborn or very small child.", n: "El plural es \"babies\"; la 'y' cambia a 'ies'.", nEn: "The plural is \"babies\"; the 'y' changes to 'ies'." },
    "loc-vfam18": { e: "My parents are visiting this weekend.", t: "Mis padres vienen de visita este fin de semana.", s: "Al hablar de tu mamá y tu papá juntos.", sEn: "When talking about your mom and dad together.", n: "\"Parents\" (padres) no es lo mismo que \"relatives\" (parientes).", nEn: "\"Parents\" means mom and dad, not \"relatives\" in general." },
    "loc-vcue01": { e: "I have a headache; my head really hurts.", t: "Tengo dolor de cabeza; me duele mucho la cabeza.", s: "Al hablar de un dolor de cabeza con el médico o un amigo.", sEn: "When talking about a headache with a doctor or friend.", n: "\"Head\" lleva una 'e' corta; di jed, no \"jid\".", nEn: "\"Head\" has a short 'e'; say hed, not \"heed\"." },
    "loc-vcue02": { e: "Wash your face before bed.", t: "Lávate la cara antes de dormir.", s: "Al hablar de higiene o de lavarse la cara.", sEn: "When talking about hygiene or washing your face.", n: "Se pronuncia féis; rima con \"place\" y \"space\".", nEn: "It's pronounced face; it rhymes with \"place\" and \"space\"." },
    "loc-vcue03": { e: "I got something in my eye.", t: "Se me metió algo en el ojo.", s: "Al avisar de una molestia en el ojo.", sEn: "When mentioning an irritation in your eye.", n: "\"Eye\" (ojo) suena igual que \"I\" (yo); el contexto los separa.", nEn: "\"Eye\" sounds exactly like \"I\"; context keeps them apart." },
    "loc-vcue04": { e: "My nose is stuffy because of a cold.", t: "Tengo la nariz tapada por un resfriado.", s: "Al hablar de un resfriado o congestión nasal.", sEn: "When talking about a cold or a stuffy nose.", n: "\"Nose\" (nariz) y \"knows\" (sabe) suenan igual; la 'k' es muda.", nEn: "\"Nose\" and \"knows\" sound the same; the 'k' in \"knows\" is silent." },
    "loc-vcue05": { e: "Cover your mouth when you cough.", t: "Tápate la boca cuando tosas.", s: "Al pedir buenos modales al toser o estornudar.", sEn: "When asking for good manners while coughing or sneezing.", n: "\"Mouth\" termina en 'th'; di máuz con la lengua suave, no \"maus\".", nEn: "\"Mouth\" ends in 'th'; say mowth with a soft tongue, not \"mouse\"." },
    "loc-vcue06": { e: "My right ear hurts a little.", t: "Me duele un poco el oído derecho.", s: "Al describir un dolor de oído.", sEn: "When describing an earache.", n: "\"Ear\" es oreja u oído; se pronuncia ir, como en \"hear\".", nEn: "\"Ear\" means both the outer ear and hearing; it's said \"ear\", like in \"hear\"." },
    "loc-vcue07": { e: "I need to cut my hair.", t: "Necesito cortarme el pelo.", s: "Al hablar de ir a la peluquería o del cabello.", sEn: "When talking about getting a haircut or about hair.", n: "\"Hair\" es incontable; se dice \"my hair is long\", no \"hairs\".", nEn: "\"Hair\" is uncountable; say \"my hair is long\", not \"hairs\"." },
    "loc-vcue08": { e: "My neck is stiff this morning.", t: "Tengo el cuello tieso esta mañana.", s: "Al describir una molestia o tortícolis en el cuello.", sEn: "When describing neck stiffness or soreness.", n: "\"Neck\" rima con \"check\"; la 'e' es corta.", nEn: "\"Neck\" rhymes with \"check\"; the 'e' is short." },
    "loc-vcue09": { e: "I carry my bag on my shoulder.", t: "Llevo el bolso en el hombro.", s: "Al hablar de cargar algo o de un dolor de hombro.", sEn: "When talking about carrying something or a sore shoulder.", n: "Se pronuncia SHÓUL-der; la 'l' sí se pronuncia con claridad.", nEn: "It's pronounced SHOHL-der; the 'l' is clearly pronounced." },
    "loc-vcue10": { e: "I hurt my arm at work.", t: "Me lastimé el brazo en el trabajo.", s: "Al describir una lesión en el brazo.", sEn: "When describing an injury to your arm.", n: "\"Arm\" se pronuncia con la 'a' abierta; el plural es \"arms\".", nEn: "\"Arm\" is pronounced with an open 'a'; the plural is \"arms\"." },
    "loc-vcue11": { e: "Give me a hand with this box.", t: "Échame una mano con esta caja.", s: "Al pedir ayuda para mover algo.", sEn: "When asking for help moving something.", n: "\"Give me a hand\" es un modismo: significa \"ayúdame\".", nEn: "\"Give me a hand\" is an idiom meaning \"help me\"." },
    "loc-vcue12": { e: "I cut my finger while cooking.", t: "Me corté el dedo cocinando.", s: "Al describir una herida pequeña en la mano.", sEn: "When describing a small cut on your hand.", n: "\"Finger\" es dedo de la mano; el del pie es \"toe\".", nEn: "\"Finger\" is a hand digit; a foot digit is a \"toe\"." },
    "loc-vcue13": { e: "My leg hurts after the run.", t: "Me duele la pierna después de correr.", s: "Al hablar de cansancio o dolor en las piernas.", sEn: "When talking about tired or sore legs.", n: "\"Leg\" rima con \"egg\"; la 'e' es corta.", nEn: "\"Leg\" rhymes with \"egg\"; the 'e' is short." },
    "loc-vcue14": { e: "My foot is sore from walking all day.", t: "Me duele el pie de tanto caminar.", s: "Al describir cansancio en los pies.", sEn: "When describing tired or sore feet.", n: "El plural de \"foot\" es \"feet\", no \"foots\".", nEn: "The plural of \"foot\" is \"feet\", not \"foots\"." },
    "loc-vcue15": { e: "I scraped my knee when I fell.", t: "Me raspé la rodilla cuando me caí.", s: "Al describir una caída o un raspón en la rodilla.", sEn: "When describing a fall or a scraped knee.", n: "\"Knee\" se pronuncia ni; la 'k' inicial es muda.", nEn: "\"Knee\" is pronounced nee; the initial 'k' is silent." },
    "loc-vcue16": { e: "My back hurts from sitting all day.", t: "Me duele la espalda de estar sentado todo el día.", s: "Al quejarte de dolor de espalda.", sEn: "When complaining about back pain.", n: "\"Back\" también significa \"atrás\"; el contexto aclara cuál es.", nEn: "\"Back\" also means \"behind/return\"; context makes it clear." },
    "loc-vcue17": { e: "I feel a tightness in my chest.", t: "Siento una opresión en el pecho.", s: "Al describir un síntoma en el pecho ante el médico.", sEn: "When describing a chest symptom to a doctor.", n: "\"Chest\" empieza con sonido 'ch', como en \"check\".", nEn: "\"Chest\" starts with the 'ch' sound, as in \"check\"." },
    "loc-vcue18": { e: "I have a stomachache.", t: "Tengo dolor de estómago.", s: "Al describir un malestar estomacal.", sEn: "When describing a stomach upset.", n: "\"Stomach\" suena STÁ-mak; la 'ch' final suena como 'k'.", nEn: "\"Stomach\" sounds like STUH-muck; the final 'ch' sounds like 'k'." },
    "loc-vcue19": { e: "I have a toothache; one tooth really hurts.", t: "Tengo dolor de muela; me duele mucho un diente.", s: "Al describir un dolor de muela con el dentista.", sEn: "When describing a toothache to the dentist.", n: "El plural de \"tooth\" es \"teeth\", no \"tooths\".", nEn: "The plural of \"tooth\" is \"teeth\", not \"tooths\"." },
    "loc-vcue20": { e: "She has a good heart.", t: "Ella tiene buen corazón.", s: "Al hablar del corazón, literal o como símbolo de bondad.", sEn: "When talking about the heart, literally or as a symbol of kindness.", n: "\"Heart\" se pronuncia jart; cuidado, no es \"hurt\" (lastimar).", nEn: "\"Heart\" is pronounced hart; careful, it's not \"hurt\" (to injure)." },
    "loc-vcmd01": { e: "Could I get some fresh bread with the soup, please?", t: "¿Me puede dar pan fresco con la sopa, por favor?", s: "En un restaurante, al pedir algo para acompañar la comida.", sEn: "At a restaurant, when asking for something to go with the meal.", n: "\"Bread\" es incontable; di \"some bread\" o \"a loaf of bread\", no \"a bread\".", nEn: "\"Bread\" is uncountable; say \"some bread\" or \"a loaf of bread\", not \"a bread\"." },
    "loc-vcmd02": { e: "Can I get a glass of water while I look at the menu?", t: "¿Me puede traer un vaso de agua mientras veo el menú?", s: "Al sentarte en un restaurante o pedir en la barra.", sEn: "When you sit down at a restaurant or order at the counter.", n: "\"Water\" en EE. UU. suena casi como \"UÓ-rer\"; la 't' se vuelve suave.", nEn: "In US English \"water\" sounds almost like \"wadder\"; the 't' goes soft." },
    "loc-vcmd03": { e: "Do you want some milk in your coffee?", t: "¿Quieres un poco de leche en el café?", s: "Al preparar el desayuno o servir café a alguien.", sEn: "When making breakfast or serving someone coffee.", n: "\"Milk\" es incontable: di \"some milk\", nunca \"a milk\".", nEn: "\"Milk\" is uncountable: say \"some milk\", never \"a milk\"." },
    "loc-vcmd04": { e: "I usually have a cup of coffee before work.", t: "Normalmente me tomo una taza de café antes del trabajo.", s: "Hablando de tu rutina de la mañana.", sEn: "Talking about your morning routine.", n: "Lleva el acento en la primera sílaba: KÓ-fi, no \"co-FÍ\".", nEn: "Stress the first syllable: KÓ-fi, not \"co-FEE\"." },
    "loc-vcmd05": { e: "Would you like a cup of tea or coffee?", t: "¿Quieres una taza de té o de café?", s: "Al ofrecerle algo de tomar a una visita.", sEn: "When offering a guest something to drink.", n: "\"Tea\" suena \"ti\" con la 'i' larga, como en \"see\".", nEn: "\"Tea\" sounds like \"tee\" with a long 'i', as in \"see\"." },
    "loc-vcmd06": { e: "I'd like a large orange juice, please.", t: "Quiero un jugo de naranja grande, por favor.", s: "Al pedir el desayuno en una cafetería.", sEn: "When ordering breakfast at a café.", n: "\"Juice\" se dice \"yus\"; la 'j' suena como en \"jeans\".", nEn: "\"Juice\" sounds like \"joos\"; the 'j' is like in \"jeans\"." },
    "loc-vcmd07": { e: "How would you like your egg — fried or scrambled?", t: "¿Cómo quieres el huevo: frito o revuelto?", s: "Al preparar el desayuno para alguien.", sEn: "When making breakfast for someone.", n: "El plural es \"eggs\"; di \"two eggs\" para más de uno.", nEn: "The plural is \"eggs\"; say \"two eggs\" for more than one." },
    "loc-vcmd08": { e: "This sandwich has ham and cheese inside.", t: "Este sándwich lleva jamón y queso adentro.", s: "Al describir un platillo o pedir en un café.", sEn: "When describing a dish or ordering at a café.", n: "\"Cheese\" se dice con la \"i\" larga, como en \"see\"; alarga la vocal.", nEn: "\"Cheese\" has a long 'i'; don't clip it short." },
    "loc-vcmd09": { e: "I don't eat meat, so I'll have the salad instead.", t: "No como carne, así que mejor pido la ensalada.", s: "Al explicar una preferencia o dieta en un restaurante.", sEn: "When explaining a preference or diet at a restaurant.", n: "\"Meat\" (carne) suena igual que \"meet\" (conocer); el contexto lo aclara.", nEn: "\"Meat\" (food) sounds just like \"meet\" (to encounter); context tells them apart." },
    "loc-vcmd10": { e: "I'll have the grilled chicken with rice.", t: "Voy a pedir el pollo a la parrilla con arroz.", s: "Al ordenar tu plato principal en un restaurante.", sEn: "When ordering your main dish at a restaurant.", n: "\"Chicken\" lleva 'i' corta: CHÍ-ken, no \"chí-keen\".", nEn: "\"Chicken\" has a short 'i': CHÍ-ken, not \"chee-keen\"." },
    "loc-vcmd11": { e: "The fish here is really fresh and tastes great.", t: "El pescado aquí es muy fresco y sabe riquísimo.", s: "Al recomendar un platillo o hablar de la comida.", sEn: "When recommending a dish or talking about the food.", n: "\"Fish\" es igual en singular y plural; no digas \"fishes\" para comida.", nEn: "\"Fish\" stays the same in singular and plural; don't say \"fishes\" for food." },
    "loc-vcmd12": { e: "Can I have some rice with the chicken, please?", t: "¿Me puede dar arroz con el pollo, por favor?", s: "Al elegir un acompañamiento en un restaurante.", sEn: "When picking a side dish at a restaurant.", n: "\"Rice\" es incontable: di \"some rice\", nunca \"a rice\".", nEn: "\"Rice\" is uncountable: say \"some rice\", never \"a rice\"." },
    "loc-vcmd13": { e: "I'd love a bowl of hot soup on a cold day.", t: "Me encantaría un plato de sopa caliente en un día frío.", s: "Al pedir algo caliente cuando hace frío.", sEn: "When ordering something warm on a cold day.", n: "\"Soup\" se dice \"sup\"; no la confundas con \"soap\" (jabón).", nEn: "\"Soup\" sounds like \"soop\"; don't mix it up with \"soap\"." },
    "loc-vcmd14": { e: "I'll just have a green salad to start.", t: "Voy a pedir solo una ensalada verde para empezar.", s: "Al elegir una entrada ligera en un restaurante.", sEn: "When choosing a light starter at a restaurant.", n: "\"Salad\" lleva el acento en la primera sílaba: SÁ-lad.", nEn: "\"Salad\" is stressed on the first syllable: SÁ-lad." },
    "loc-vcmd15": { e: "Do you take sugar in your coffee?", t: "¿Le pones azúcar al café?", s: "Al servirle café o té a alguien.", sEn: "When serving someone coffee or tea.", n: "\"Sugar\" empieza con sonido \"sh\": SHÚ-gar, no \"sú-gar\".", nEn: "\"Sugar\" starts with a \"sh\" sound: SHÚ-gar, not \"soo-gar\"." },
    "loc-vcmd16": { e: "Could you pass me the salt, please?", t: "¿Me pasas la sal, por favor?", s: "En la mesa, al pedir el salero.", sEn: "At the table, when asking for the salt shaker.", n: "\"Salt\" rima con \"fault\"; la 'a' suena como 'o' suave: solt.", nEn: "\"Salt\" rhymes with \"fault\"; the 'a' sounds like a soft 'o'." },
    "loc-vcmd17": { e: "Can I have some butter for my bread?", t: "¿Me da un poco de mantequilla para el pan?", s: "En el desayuno, al pedir algo para untar el pan.", sEn: "At breakfast, when asking for something to spread on the bread.", n: "En EE. UU. la 'tt' suena suave: BÁ-rer, casi como una 'r'.", nEn: "In US English the 'tt' goes soft: BÁ-rer, almost like an 'r'." },
    "loc-vcmd18": { e: "I'll have a cold beer, please.", t: "Quiero una cerveza fría, por favor.", s: "Al pedir algo de tomar en un bar o restaurante.", sEn: "When ordering a drink at a bar or restaurant.", n: "\"Beer\" se dice \"bir\"; no la confundas con \"bear\" (oso), que es \"ber\".", nEn: "\"Beer\" has a long \"ee\" sound; don't mix it up with \"bear\" (the animal)." },
    "loc-vcmd19": { e: "Would you like a glass of red or white wine?", t: "¿Quieres una copa de vino tinto o blanco?", s: "Al ofrecer vino a un cliente o invitado.", sEn: "When offering wine to a guest or customer.", n: "\"Wine\" empieza con sonido 'u': uáin, no \"vain\".", nEn: "\"Wine\" starts with a 'w' sound: wine, not \"vine\"." },
    "loc-vcmd20": { e: "Would you like to see the dessert menu?", t: "¿Quieren ver la carta de postres?", s: "Al ofrecer postres después del plato principal.", sEn: "When offering desserts after the main course.", n: "\"Dessert\" (postre) lleva doble s y acento al final: di-SÉRT; \"desert\" (desierto) lleva una sola.", nEn: "\"Dessert\" (the sweet) has a double s and end stress; \"desert\" (dry land) has one s." },
    "loc-vfru01": { e: "An apple a day is a healthy snack.", t: "Una manzana al día es un bocadillo saludable.", s: "Al hablar de comida sana o elegir una fruta.", sEn: "When talking about healthy food or picking a fruit.", n: "\"Apple\" lleva el acento al inicio: Á-pol; el plural es \"apples\".", nEn: "\"Apple\" is stressed at the start: Á-pol; the plural is \"apples\"." },
    "loc-vfru02": { e: "I always put a banana in my morning smoothie.", t: "Siempre le pongo un banano a mi licuado de la mañana.", s: "Al hablar del desayuno o de batidos de fruta.", sEn: "When talking about breakfast or fruit smoothies.", n: "\"Banana\" lleva el acento en la sílaba del medio: ba-NÁ-na.", nEn: "\"Banana\" is stressed on the middle syllable: ba-NÁ-na." },
    "loc-vfru03": { e: "I peel an orange every morning for breakfast.", t: "Pelo una naranja cada mañana para el desayuno.", s: "Al hablar de frutas o del desayuno.", sEn: "When talking about fruit or breakfast.", n: "\"Orange\" nombra la fruta y el color; el acento va al inicio: Ó-rinch.", nEn: "\"Orange\" is both the fruit and the color; stress goes at the start: Ó-rinch." },
    "loc-vfru04": { e: "These grapes are sweet and seedless.", t: "Estas uvas son dulces y sin semilla.", s: "Al elegir fruta en el mercado o servir un postre.", sEn: "When picking fruit at the market or serving a dessert.", n: "\"Grape\" (uva) suena \"gréip\"; no la confundas con \"grapefruit\" (toronja).", nEn: "\"Grape\" sounds like \"grayp\"; don't confuse it with \"grapefruit\"." },
    "loc-vfru05": { e: "I'd like a strawberry milkshake, please.", t: "Quiero una malteada de fresa, por favor.", s: "Al pedir un postre o una bebida con sabor.", sEn: "When ordering a dessert or a flavored drink.", n: "\"Strawberry\" es larga; el acento va al inicio: STRÓ-be-ri.", nEn: "\"Strawberry\" is long; stress goes at the start: STRÓ-be-ri." },
    "loc-vfru06": { e: "Do you want some pineapple on your pizza?", t: "¿Quieres piña en tu pizza?", s: "Al elegir ingredientes para un platillo.", sEn: "When choosing toppings for a dish.", n: "\"Pineapple\" junta \"pine\" + \"apple\"; el acento va al inicio: PÁIN-a-pol.", nEn: "\"Pineapple\" joins \"pine\" + \"apple\"; stress goes at the start: PÁIN-a-pol." },
    "loc-vfru07": { e: "Can I get a slice of lemon with my water?", t: "¿Me da una rodaja de limón con el agua?", s: "Al pedir algo para darle sabor a la bebida.", sEn: "When asking for something to flavor your drink.", n: "\"Lemon\" es el limón amarillo; el verde se llama \"lime\".", nEn: "\"Lemon\" is the yellow one; the green one is called \"lime\"." },
    "loc-vfru08": { e: "Watermelon is perfect on a hot summer day.", t: "La sandía es perfecta en un día caluroso de verano.", s: "Al hablar de frutas de verano o algo refrescante.", sEn: "When talking about summer fruit or something refreshing.", n: "\"Watermelon\" empieza igual que \"water\": UÓ-rer-me-lon.", nEn: "\"Watermelon\" starts like \"water\": UÓ-rer-me-lon." },
    "loc-vfru09": { e: "Add some chopped tomato to the salad.", t: "Agrégale tomate picado a la ensalada.", s: "Al cocinar o preparar una ensalada.", sEn: "When cooking or making a salad.", n: "En EE. UU. se dice to-MÉI-tou; el plural lleva 'es': \"tomatoes\".", nEn: "In the US it's to-MAY-toe; the plural adds 'es': \"tomatoes\"." },
    "loc-vfru10": { e: "Would you like rice or potato with that?", t: "¿Quiere arroz o papa con eso?", s: "Al ofrecer un acompañamiento en un restaurante.", sEn: "When offering a side dish at a restaurant.", n: "El plural lleva 'es': \"potatoes\"; \"French fries\" son las papas fritas.", nEn: "The plural adds 'es': \"potatoes\"; \"French fries\" are the fried ones." },
    "loc-vfru11": { e: "Rabbits love to eat fresh carrots.", t: "A los conejos les encanta comer zanahorias frescas.", s: "Al hablar de verduras o de lo que come una mascota.", sEn: "When talking about vegetables or what a pet eats.", n: "\"Carrot\" lleva el acento al inicio: KÉ-rot; el plural es \"carrots\".", nEn: "\"Carrot\" is stressed at the start: KÉ-rot; the plural is \"carrots\"." },
    "loc-vfru12": { e: "Chopping an onion always makes me cry.", t: "Picar una cebolla siempre me hace llorar.", s: "Al cocinar o preparar comida.", sEn: "When cooking or preparing food.", n: "\"Onion\" empieza con sonido 'a': Á-nion, no \"o-nion\".", nEn: "\"Onion\" starts with an 'uh' sound: Á-nion, not \"oh-nion\"." },
    "loc-vfru13": { e: "Add some lettuce and tomato to the sandwich.", t: "Agrégale lechuga y tomate al sándwich.", s: "Al preparar un sándwich o una ensalada.", sEn: "When making a sandwich or a salad.", n: "\"Lettuce\" suena LÉ-tis, casi como \"let us\".", nEn: "\"Lettuce\" sounds like LÉ-tis, almost like \"let us\"." },
    "loc-vfru14": { e: "This sauce has too much garlic for me.", t: "Esta salsa tiene demasiado ajo para mi gusto.", s: "Al hablar del sabor de un platillo.", sEn: "When talking about the flavor of a dish.", n: "\"Garlic\" es incontable; di \"some garlic\", no \"a garlic\".", nEn: "\"Garlic\" is uncountable; say \"some garlic\", not \"a garlic\"." },
    "loc-vfru15": { e: "We grilled some corn for the barbecue.", t: "Asamos algo de maíz para la parrillada.", s: "Al hablar de una comida al aire libre o una parrillada.", sEn: "When talking about a cookout or barbecue.", n: "\"Corn\" es incontable en general; una mazorca es \"an ear of corn\".", nEn: "\"Corn\" is usually uncountable; one cob is \"an ear of corn\"." },
    "loc-vfru16": { e: "This dish comes with rice and beans.", t: "Este platillo viene con arroz y frijoles.", s: "Al describir un platillo típico en un restaurante.", sEn: "When describing a typical dish at a restaurant.", n: "Casi siempre se usa el plural \"beans\" para los frijoles del plato.", nEn: "You almost always use the plural \"beans\" for the ones on your plate." },
    "loc-vfru17": { e: "I love avocado on my toast in the morning.", t: "Me encanta el aguacate en mi tostada por la mañana.", s: "Al hablar del desayuno o pedir un platillo.", sEn: "When talking about breakfast or ordering a dish.", n: "\"Avocado\" lleva el acento en KÁ: a-vo-KÁ-dou.", nEn: "\"Avocado\" is stressed on KÁ: a-vo-KÁ-dou." },
    "loc-vfru18": { e: "A ripe mango is really sweet and juicy.", t: "Un mango maduro es muy dulce y jugoso.", s: "Al elegir o describir fruta tropical.", sEn: "When picking or describing tropical fruit.", n: "\"Mango\" lleva el acento al inicio: MÁN-gou; el plural es \"mangoes\".", nEn: "\"Mango\" is stressed at the start: MÁN-gou; the plural is \"mangoes\"." },
    "loc-vani01": { e: "My dog loves to play in the park.", t: "A mi perro le encanta jugar en el parque.", s: "Al hablar de tu mascota o de animales.", sEn: "When talking about your pet or animals.", n: "\"Dog\" suena con 'o' abierta: dog; el plural es \"dogs\".", nEn: "\"Dog\" has an open 'o' sound; the plural is \"dogs\"." },
    "loc-vani02": { e: "The cat is sleeping on the sofa again.", t: "El gato está durmiendo en el sofá otra vez.", s: "Al hablar de tu mascota en casa.", sEn: "When talking about your pet at home.", n: "\"Cat\" lleva la 'a' bien abierta: kat; el plural es \"cats\".", nEn: "\"Cat\" has a wide-open 'a'; the plural is \"cats\"." },
    "loc-vani03": { e: "A little bird is singing outside my window.", t: "Un pajarito está cantando afuera de mi ventana.", s: "Al describir lo que ves o escuchas afuera.", sEn: "When describing what you see or hear outside.", n: "\"Bird\" lleva el sonido 'er': berd; el plural es \"birds\".", nEn: "\"Bird\" has an 'er' sound: berd; the plural is \"birds\"." },
    "loc-vani04": { e: "We saw a big fish in the river.", t: "Vimos un pez grande en el río.", s: "Al hablar de animales que viste en la naturaleza.", sEn: "When talking about animals you saw in nature.", n: "\"Fish\" es igual en singular y plural; varios peces son \"fish\".", nEn: "\"Fish\" stays the same in singular and plural; several are still \"fish\"." },
    "loc-vani05": { e: "She rides a horse every weekend.", t: "Ella monta a caballo cada fin de semana.", s: "Al hablar de un pasatiempo o de animales de granja.", sEn: "When talking about a hobby or farm animals.", n: "\"Horse\" suena \"jors\"; no la confundas con \"hoarse\" (ronco).", nEn: "\"Horse\" sounds like \"horss\"; don't confuse it with \"hoarse\" (raspy voice)." },
    "loc-vani06": { e: "The cow gives us fresh milk every day.", t: "La vaca nos da leche fresca cada día.", s: "Al hablar de animales de granja o de dónde viene la leche.", sEn: "When talking about farm animals or where milk comes from.", n: "\"Cow\" rima con \"now\": kau; el plural es \"cows\".", nEn: "\"Cow\" rhymes with \"now\": kau; the plural is \"cows\"." },
    "loc-vani07": { e: "The pig is rolling around in the mud.", t: "El cerdo está revolcándose en el lodo.", s: "Al describir animales de granja.", sEn: "When describing farm animals.", n: "\"Pig\" lleva 'i' corta: pig; la carne de cerdo es \"pork\".", nEn: "\"Pig\" has a short 'i'; the meat from it is \"pork\"." },
    "loc-vani08": { e: "The hen laid three eggs this morning.", t: "La gallina puso tres huevos esta mañana.", s: "Al hablar de animales de granja o de dónde vienen los huevos.", sEn: "When talking about farm animals or where eggs come from.", n: "\"Hen\" es la hembra; el gallo es \"rooster\".", nEn: "\"Hen\" is the female; the male is a \"rooster\"." },
    "loc-vani09": { e: "There are many sheep on that green hill.", t: "Hay muchas ovejas en esa colina verde.", s: "Al describir un paisaje rural o animales de granja.", sEn: "When describing a rural landscape or farm animals.", n: "\"Sheep\" es igual en singular y plural; di \"many sheep\", no \"sheeps\".", nEn: "\"Sheep\" stays the same in singular and plural; say \"many sheep\", not \"sheeps\"." },
    "loc-vani10": { e: "The duck is swimming across the pond.", t: "El pato está nadando por el estanque.", s: "Al describir animales en un parque o lago.", sEn: "When describing animals at a park or lake.", n: "\"Duck\" lleva sonido 'a': dak; el plural es \"ducks\".", nEn: "\"Duck\" has an 'uh' sound: dak; the plural is \"ducks\"." },
    "loc-vani11": { e: "The kids have a pet rabbit at home.", t: "Los niños tienen un conejo de mascota en casa.", s: "Al hablar de mascotas o de animales pequeños.", sEn: "When talking about pets or small animals.", n: "\"Rabbit\" lleva el acento al inicio: RÁ-bit; el plural es \"rabbits\".", nEn: "\"Rabbit\" is stressed at the start: RÁ-bit; the plural is \"rabbits\"." },
    "loc-vani12": { e: "There's a little mouse behind the fridge.", t: "Hay un ratoncito detrás del refrigerador.", s: "Al hablar de un animal pequeño en la casa.", sEn: "When talking about a small animal in the house.", n: "El plural de \"mouse\" es irregular: \"mice\", no \"mouses\".", nEn: "The plural of \"mouse\" is irregular: \"mice\", not \"mouses\"." },
    "loc-vani13": { e: "The lion is the strongest animal at the zoo.", t: "El león es el animal más fuerte del zoológico.", s: "Al hablar de animales salvajes o del zoológico.", sEn: "When talking about wild animals or the zoo.", n: "\"Lion\" lleva el acento al inicio: LÁI-on; el plural es \"lions\".", nEn: "\"Lion\" is stressed at the start: LÁI-on; the plural is \"lions\"." },
    "loc-vani14": { e: "We saw a brown bear in the forest.", t: "Vimos un oso pardo en el bosque.", s: "Al contar algo que viste en la naturaleza.", sEn: "When telling about something you saw in nature.", n: "\"Bear\" (oso) suena \"ber\", igual que \"bare\" (desnudo).", nEn: "\"Bear\" (the animal) sounds like \"bare\" (uncovered)." },
    "loc-vani15": { e: "The monkey is climbing up the tree.", t: "El mono está trepando por el árbol.", s: "Al describir animales en el zoológico o la selva.", sEn: "When describing animals at the zoo or jungle.", n: "\"Monkey\" lleva el acento al inicio: MÁN-ki; el plural es \"monkeys\".", nEn: "\"Monkey\" is stressed at the start: MÁN-ki; the plural is \"monkeys\"." },
    "loc-vani16": { e: "An elephant is the biggest animal I've ever seen.", t: "Un elefante es el animal más grande que he visto.", s: "Al hablar de animales grandes o del zoológico.", sEn: "When talking about big animals or the zoo.", n: "\"Elephant\" lleva el acento al inicio: É-le-fant; la 'ph' suena 'f'.", nEn: "\"Elephant\" is stressed at the start: É-le-fant; the 'ph' sounds like 'f'." },
    "loc-vani17": { e: "Be careful, there's a snake in the grass.", t: "Ten cuidado, hay una serpiente en el pasto.", s: "Al advertir sobre un animal peligroso afuera.", sEn: "When warning about a dangerous animal outside.", n: "\"Snake\" suena \"snéik\"; el plural es \"snakes\".", nEn: "\"Snake\" sounds like \"snayk\"; the plural is \"snakes\"." },
    "loc-vani18": { e: "There's a big spider in the corner of the room.", t: "Hay una araña grande en la esquina del cuarto.", s: "Al señalar un insecto en la casa.", sEn: "When pointing out a bug in the house.", n: "\"Spider\" lleva el acento al inicio: SPÁI-der; el plural es \"spiders\".", nEn: "\"Spider\" is stressed at the start: SPÁI-der; the plural is \"spiders\"." },
    "loc-vani19": { e: "A bee landed on the flower next to me.", t: "Una abeja se posó en la flor junto a mí.", s: "Al hablar de insectos en el jardín o el parque.", sEn: "When talking about insects in the garden or park.", n: "\"Bee\" suena \"bi\" con 'i' larga; no la confundas con \"be\" (ser/estar).", nEn: "\"Bee\" sounds like \"bee\" with a long 'i'; it's a homophone of \"be\"." },
    "loc-vani20": { e: "A colorful butterfly flew past the window.", t: "Una mariposa colorida pasó volando por la ventana.", s: "Al describir algo bonito que viste afuera.", sEn: "When describing something pretty you saw outside.", n: "\"Butterfly\" lleva el acento al inicio: BÁ-ter-flai; el plural es \"butterflies\".", nEn: "\"Butterfly\" is stressed at the start: BÁ-ter-flai; the plural is \"butterflies\"." },
    "loc-vrop01": { e: "I need to iron my shirt before the meeting.", t: "Necesito planchar mi camisa antes de la reunión.", s: "Al prepararte para el trabajo o una ocasión formal.", sEn: "When getting ready for work or a formal occasion.", n: "\"Shirt\" lleva el sonido 'er': shert; el plural es \"shirts\".", nEn: "\"Shirt\" has an 'er' sound: shert; the plural is \"shirts\"." },
    "loc-vrop02": { e: "These pants are a little too tight for me.", t: "Este pantalón me queda un poco apretado.", s: "Al probarte ropa en una tienda.", sEn: "When trying on clothes in a store.", n: "\"Pants\" siempre va en plural; di \"a pair of pants\" para uno.", nEn: "\"Pants\" is always plural; say \"a pair of pants\" for one." },
    "loc-vrop03": { e: "Take off your shoes before you come inside.", t: "Quítate los zapatos antes de entrar.", s: "Al pedirle a alguien que se descalce en casa.", sEn: "When asking someone to take their shoes off at home.", n: "\"Shoes\" casi siempre va en plural; un solo zapato es \"a shoe\".", nEn: "\"Shoes\" is almost always plural; a single one is \"a shoe\"." },
    "loc-vrop04": { e: "She's wearing a beautiful red dress tonight.", t: "Ella lleva un hermoso vestido rojo esta noche.", s: "Al describir la ropa de alguien en una ocasión especial.", sEn: "When describing someone's outfit on a special occasion.", n: "\"Dress\" (vestido) lleva doble s; no la confundas con \"to dress\" (vestirse).", nEn: "\"Dress\" (the garment) has a double s; it can also mean \"to get dressed\"." },
    "loc-vrop05": { e: "That skirt goes really well with your blouse.", t: "Esa falda combina muy bien con tu blusa.", s: "Al opinar sobre la ropa de alguien.", sEn: "When giving an opinion about someone's clothes.", n: "\"Skirt\" lleva el sonido 'er': skert; el plural es \"skirts\".", nEn: "\"Skirt\" has an 'er' sound: skert; the plural is \"skirts\"." },
    "loc-vrop06": { e: "Take a jacket; it gets cold at night.", t: "Lleva una chaqueta; por la noche hace frío.", s: "Al aconsejar a alguien qué ponerse antes de salir.", sEn: "When advising someone what to wear before going out.", n: "\"Jacket\" lleva el acento al inicio: YÁ-ket; el plural es \"jackets\".", nEn: "\"Jacket\" is stressed at the start: YÁ-ket; the plural is \"jackets\"." },
    "loc-vrop07": { e: "Put on your coat, it's snowing outside.", t: "Ponte el abrigo, está nevando afuera.", s: "Al salir cuando hace mucho frío.", sEn: "When going out in very cold weather.", n: "\"Coat\" suena \"kóut\"; un \"coat\" es más abrigador que un \"jacket\".", nEn: "\"Coat\" sounds like \"coat\"; a coat is warmer than a jacket." },
    "loc-vrop08": { e: "He always wears a hat in the sun.", t: "Él siempre usa sombrero cuando hay sol.", s: "Al hablar de protegerse del sol o de un accesorio.", sEn: "When talking about sun protection or an accessory.", n: "\"Hat\" cubre la cabeza con ala; \"cap\" es la gorra con visera.", nEn: "\"Hat\" has a brim all around; a \"cap\" has a front visor." },
    "loc-vrop09": { e: "I can't find a matching pair of socks.", t: "No encuentro un par de calcetines que combinen.", s: "Al vestirte por la mañana.", sEn: "When getting dressed in the morning.", n: "\"Socks\" suele ir en plural; un par es \"a pair of socks\".", nEn: "\"Socks\" usually comes in the plural; one set is \"a pair of socks\"." },
    "loc-vrop10": { e: "Wear gloves so your hands stay warm.", t: "Usa guantes para que las manos no se te enfríen.", s: "Al abrigarte para el frío.", sEn: "When bundling up against the cold.", n: "\"Gloves\" tiene la 'o' con sonido de 'a': glavs; casi siempre va en plural.", nEn: "\"Gloves\" has an 'uh' sound (like 'a'): glavs; it's almost always plural." },
    "loc-vrop11": { e: "Wrap a scarf around your neck before you go.", t: "Ponte una bufanda en el cuello antes de salir.", s: "Al abrigarte el cuello en invierno.", sEn: "When keeping your neck warm in winter.", n: "El plural de \"scarf\" puede ser \"scarves\" o \"scarfs\".", nEn: "The plural of \"scarf\" can be \"scarves\" or \"scarfs\"." },
    "loc-vrop12": { e: "I need a belt to hold up these pants.", t: "Necesito un cinturón para que no se me caiga el pantalón.", s: "Al vestirte o ajustar tu ropa.", sEn: "When getting dressed or adjusting your clothes.", n: "\"Belt\" se dice tal cual: belt; el plural es \"belts\".", nEn: "\"Belt\" is said just as it looks; the plural is \"belts\"." },
    "loc-vrop13": { e: "He's wearing a blue tie with his suit.", t: "Él lleva una corbata azul con su traje.", s: "Al describir ropa formal para el trabajo o un evento.", sEn: "When describing formal wear for work or an event.", n: "\"Tie\" suena \"tai\"; también es el verbo \"atar\".", nEn: "\"Tie\" sounds like \"tie\"; it's also the verb \"to fasten\"." },
    "loc-vrop14": { e: "I just need a clean T-shirt and jeans.", t: "Solo necesito una camiseta limpia y unos jeans.", s: "Al hablar de ropa casual de diario.", sEn: "When talking about everyday casual clothes.", n: "Se escribe con guion: \"T-shirt\"; el plural es \"T-shirts\".", nEn: "It's written with a hyphen: \"T-shirt\"; the plural is \"T-shirts\"." },
    "loc-vrop15": { e: "Put on a sweater, it's chilly in here.", t: "Ponte un suéter, hace fresco aquí adentro.", s: "Al aconsejar abrigarse en un lugar fresco.", sEn: "When suggesting someone bundle up in a cool place.", n: "\"Sweater\" se dice SUÉ-ter; en el Reino Unido también dicen \"jumper\".", nEn: "\"Sweater\" is said SUÉ-ter; in the UK they also say \"jumper\"." },
    "loc-vrop16": { e: "You'll need boots for all this mud.", t: "Vas a necesitar botas para todo este lodo.", s: "Al elegir calzado para el clima o el terreno.", sEn: "When choosing footwear for the weather or terrain.", n: "\"Boots\" casi siempre va en plural; un par es \"a pair of boots\".", nEn: "\"Boots\" is almost always plural; one set is \"a pair of boots\"." },
    "loc-vrop17": { e: "Pack some clean underwear for the trip.", t: "Empaca ropa interior limpia para el viaje.", s: "Al preparar una maleta para un viaje.", sEn: "When packing a suitcase for a trip.", n: "\"Underwear\" es incontable; no digas \"underwears\".", nEn: "\"Underwear\" is uncountable; don't say \"underwears\"." },
    "loc-vrop18": { e: "He wears a baseball cap everywhere he goes.", t: "Él usa una gorra de béisbol a todos lados.", s: "Al describir un accesorio casual.", sEn: "When describing a casual accessory.", n: "\"Cap\" es la gorra con visera; \"hat\" es el sombrero con ala.", nEn: "\"Cap\" has a front visor; a \"hat\" has a brim all around." },
    "loc-vcas01": { e: "We just bought a small house near the beach.", t: "Acabamos de comprar una casa pequeña cerca de la playa.", s: "Cuando hablas de dónde vives o de una propiedad.", sEn: "When you talk about where you live or about a property.", n: "\"House\" lleva una 'h' aspirada al inicio; no la dejes muda como en español.", nEn: "\"House\" has a breathy 'h' at the start; don't leave it silent like in Spanish." },
    "loc-vcas02": { e: "This room is too small for a king-size bed.", t: "Este cuarto es muy pequeño para una cama king.", s: "Al describir o reservar un espacio dentro de una casa u hotel.", sEn: "When describing or booking a space inside a house or hotel.", n: "\"Room\" sirve tanto para 'cuarto' como para 'espacio'; el contexto lo aclara.", nEn: "\"Room\" means both 'a room' and 'space'; context makes it clear." },
    "loc-vcas03": { e: "Please close the door when you leave.", t: "Por favor cierra la puerta cuando salgas.", s: "Al pedir que alguien abra o cierre la entrada de un lugar.", sEn: "When asking someone to open or close the entrance to a place.", n: "El plural es \"doors\"; la 'oo' suena como una 'o' larga, no como 'u'.", nEn: "The plural is \"doors\"; the 'oo' sounds like a long 'o', not a 'u'." },
    "loc-vcas04": { e: "Could you open the window? It's hot in here.", t: "¿Podrías abrir la ventana? Hace calor aquí.", s: "Cuando quieres ventilar una habitación o mirar afuera.", sEn: "When you want to air out a room or look outside.", n: "El acento va en la primera sílaba: UÍN-dou, no win-DÓU.", nEn: "Stress the first syllable: WIN-dow, not win-DOW." },
    "loc-vcas05": { e: "There's a big painting on the wall.", t: "Hay un cuadro grande en la pared.", s: "Al hablar de las paredes de una habitación o edificio.", sEn: "When talking about the walls of a room or building.", n: "\"Wall\" se pronuncia 'uol'; no lo confundas con \"well\" (pozo/bien).", nEn: "\"Wall\" sounds like 'wol'; don't mix it up with \"well\"." },
    "loc-vcas06": { e: "Be careful, the floor is wet.", t: "Ten cuidado, el piso está mojado.", s: "Cuando avisas sobre el suelo o señalas un nivel del edificio.", sEn: "When warning about the ground or pointing out a building level.", n: "\"Floor\" también significa 'planta' de un edificio: \"the third floor\".", nEn: "\"Floor\" also means a building level: \"the third floor\"." },
    "loc-vcas07": { e: "The rain is coming through the roof.", t: "La lluvia está entrando por el techo.", s: "Al hablar de la parte superior de una casa o edificio.", sEn: "When talking about the top of a house or building.", n: "Para el techo interior de una habitación se usa \"ceiling\", no \"roof\".", nEn: "For the inner ceiling of a room use \"ceiling\", not \"roof\"." },
    "loc-vcas08": { e: "Take the stairs; the elevator is broken.", t: "Toma las escaleras; el ascensor está descompuesto.", s: "Cuando indicas cómo subir o bajar entre pisos.", sEn: "When telling someone how to go up or down between floors.", n: "\"Stairs\" casi siempre va en plural; una sola es \"a step\".", nEn: "\"Stairs\" is almost always plural; a single one is \"a step\"." },
    "loc-vcas09": { e: "She's cooking dinner in the kitchen.", t: "Ella está cocinando la cena en la cocina.", s: "Al referirte al lugar de la casa donde se prepara la comida.", sEn: "When referring to the room where food is prepared.", n: "\"Kitchen\" es solo el cuarto; el aparato de cocinar es \"stove\".", nEn: "\"Kitchen\" is only the room; the cooking appliance is \"stove\"." },
    "loc-vcas10": { e: "The bathroom is upstairs, second door on the left.", t: "El baño está arriba, la segunda puerta a la izquierda.", s: "Cuando alguien pregunta dónde está el baño en una casa.", sEn: "When someone asks where the bathroom is in a house.", n: "En lugares públicos suena más educado decir \"restroom\".", nEn: "In public places \"restroom\" sounds more polite." },
    "loc-vcas11": { e: "The kids share a bedroom upstairs.", t: "Los niños comparten un dormitorio arriba.", s: "Al describir el cuarto donde se duerme.", sEn: "When describing the room where people sleep.", n: "Es una sola palabra: \"bedroom\", con el acento en \"bed\".", nEn: "It's one word: \"bedroom\", stressed on \"bed\"." },
    "loc-vcas12": { e: "We watch TV together in the living room.", t: "Vemos televisión juntos en la sala.", s: "Al hablar del cuarto principal para estar y recibir visitas.", sEn: "When talking about the main room for relaxing and guests.", n: "Son dos palabras: \"living room\"; en el Reino Unido también \"lounge\".", nEn: "It's two words: \"living room\"; in the UK also \"lounge\"." },
    "loc-vcas13": { e: "Can you set the table for dinner?", t: "¿Puedes poner la mesa para la cena?", s: "Al referirte al mueble donde se come o se trabaja.", sEn: "When referring to the piece of furniture for eating or working.", n: "\"Table\" termina en sonido '-bol'; la 'a' suena 'éi'.", nEn: "\"Table\" ends in a '-bul' sound and the 'a' sounds like 'ay'." },
    "loc-vcas14": { e: "Please have a seat; take any chair you like.", t: "Por favor siéntate; toma la silla que quieras.", s: "Cuando ofreces asiento o señalas un mueble para sentarse.", sEn: "When offering a seat or pointing to something to sit on.", n: "\"Chair\" empieza con sonido 'ch', no con 'sh'.", nEn: "\"Chair\" starts with a 'ch' sound, not 'sh'." },
    "loc-vcas15": { e: "I'm tired; I'm going to bed.", t: "Estoy cansado; me voy a la cama.", s: "Al hablar del mueble para dormir o de irse a dormir.", sEn: "When talking about the bed or about going to sleep.", n: "\"Go to bed\" significa 'acostarse', sin artículo.", nEn: "\"Go to bed\" means 'go to sleep', with no article." },
    "loc-vcas16": { e: "Just relax on the couch and put your feet up.", t: "Solo relájate en el sofá y pon los pies en alto.", s: "Al referirte al mueble largo de la sala.", sEn: "When referring to the long seat in the living room.", n: "\"Couch\" y \"sofa\" son lo mismo; \"couch\" suena más coloquial.", nEn: "\"Couch\" and \"sofa\" mean the same; \"couch\" is more casual." },
    "loc-vcas17": { e: "I lost my house key again.", t: "Perdí la llave de la casa otra vez.", s: "Cuando hablas de abrir una puerta o cerradura.", sEn: "When talking about opening a door or lock.", n: "\"Key\" (llave) y \"key\" (tecla) se escriben igual; el contexto decide.", nEn: "\"Key\" can mean both a door key and a keyboard key; context decides." },
    "loc-vcas18": { e: "We grow tomatoes in the garden.", t: "Cultivamos tomates en el jardín.", s: "Al hablar del espacio verde alrededor o detrás de la casa.", sEn: "When talking about the green space around or behind the house.", n: "En EE. UU. el patio trasero suele ser \"backyard\"; \"garden\" enfatiza las plantas.", nEn: "In the US the back area is often \"backyard\"; \"garden\" stresses the plants." },
    "loc-vcoc01": { e: "Could you pass me a clean plate?", t: "¿Me pasas un plato limpio?", s: "Al poner la mesa o servir comida.", sEn: "When setting the table or serving food.", n: "\"Plate\" es el plato físico; el plato de comida (platillo) es \"dish\".", nEn: "\"Plate\" is the physical plate; a prepared dish is \"dish\"." },
    "loc-vcoc02": { e: "Can I get a glass of water, please?", t: "¿Me das un vaso de agua, por favor?", s: "Cuando pides o sirves una bebida.", sEn: "When asking for or serving a drink.", n: "\"Glass\" también significa 'vidrio'; el plural es \"glasses\" (también 'gafas').", nEn: "\"Glass\" also means the material; the plural \"glasses\" can mean eyeglasses." },
    "loc-vcoc03": { e: "She poured me a hot cup of coffee.", t: "Me sirvió una taza de café caliente.", s: "Al hablar de bebidas calientes como café o té.", sEn: "When talking about hot drinks like coffee or tea.", n: "\"Cup\" suena 'kap', con 'a' corta; no lo digas como 'cop'.", nEn: "\"Cup\" sounds like 'kup' with a short vowel; don't say it like 'cop'." },
    "loc-vcoc04": { e: "You eat the salad with the small fork.", t: "La ensalada se come con el tenedor pequeño.", s: "Al poner la mesa o explicar los cubiertos.", sEn: "When setting the table or explaining the cutlery.", n: "\"Fork\" es corta; no la alargues. El plural es \"forks\".", nEn: "\"Fork\" is short; don't stretch it. The plural is \"forks\"." },
    "loc-vcoc05": { e: "Be careful, that knife is very sharp.", t: "Ten cuidado, ese cuchillo está muy afilado.", s: "Al cortar comida o advertir sobre un cubierto filoso.", sEn: "When cutting food or warning about a sharp utensil.", n: "La 'k' de \"knife\" es muda: se dice 'náif'.", nEn: "The 'k' in \"knife\" is silent: say 'nyfe' (rhymes with 'life')." },
    "loc-vcoc06": { e: "Stir the soup with a wooden spoon.", t: "Revuelve la sopa con una cuchara de madera.", s: "Al cocinar o servir algo líquido.", sEn: "When cooking or serving something liquid.", n: "\"Spoon\" lleva 'oo' larga como 'u'; no la cortes.", nEn: "\"Spoon\" has a long 'oo' sound like 'oo' in 'moon'." },
    "loc-vcoc07": { e: "The soup is boiling in the big pot.", t: "La sopa está hirviendo en la olla grande.", s: "Al cocinar sopas, guisos o pasta.", sEn: "When cooking soups, stews, or pasta.", n: "\"Pot\" es para líquidos; la sartén plana es \"pan\".", nEn: "\"Pot\" is for liquids; the flat frying one is \"pan\"." },
    "loc-vcoc08": { e: "Heat some oil in the pan before frying.", t: "Calienta un poco de aceite en la sartén antes de freír.", s: "Al freír o saltear alimentos.", sEn: "When frying or sautéing food.", n: "\"Pan\" no significa 'pan' (bread); es un falso amigo.", nEn: "\"Pan\" is not bread; it's a false friend with Spanish 'pan'." },
    "loc-vcoc09": { e: "Turn off the stove when the water boils.", t: "Apaga la estufa cuando el agua hierva.", s: "Al referirte al aparato donde se cocina con fuego o calor.", sEn: "When referring to the appliance you cook on.", n: "En el Reino Unido suele decirse \"cooker\" o \"hob\" en vez de \"stove\".", nEn: "In the UK people often say \"cooker\" or \"hob\" instead of \"stove\"." },
    "loc-vcoc10": { e: "Put the chicken in the oven for an hour.", t: "Mete el pollo al horno por una hora.", s: "Al hornear o asar comida.", sEn: "When baking or roasting food.", n: "\"Oven\" se dice 'A-ven', no 'ó-ven'; la 'o' suena como 'a' corta.", nEn: "\"Oven\" sounds like 'UH-ven', not 'oh-ven'." },
    "loc-vcoc11": { e: "Put the milk back in the fridge.", t: "Vuelve a meter la leche a la nevera.", s: "Al guardar o sacar comida fría.", sEn: "When storing or taking out cold food.", n: "\"Fridge\" es la forma corta y común de \"refrigerator\".", nEn: "\"Fridge\" is the short, everyday form of \"refrigerator\"." },
    "loc-vcoc12": { e: "Here's a napkin in case you spill something.", t: "Aquí tienes una servilleta por si se te cae algo.", s: "Al poner la mesa o atender a un comensal.", sEn: "When setting the table or serving a guest.", n: "En el Reino Unido la servilleta de tela suele llamarse \"serviette\".", nEn: "In the UK a cloth napkin is often called a \"serviette\"." },
    "loc-vcoc13": { e: "Can you open this bottle of wine?", t: "¿Puedes abrir esta botella de vino?", s: "Al servir bebidas o referirte a un envase.", sEn: "When serving drinks or referring to a container.", n: "En EE. UU. la 'tt' suena como 'd' suave: 'BÁ-rol'.", nEn: "In the US the 'tt' sounds like a soft 'd': 'BAH-dul'." },
    "loc-vcoc14": { e: "The chef always wears a white apron.", t: "El chef siempre usa un delantal blanco.", s: "Al hablar de la ropa de protección en la cocina.", sEn: "When talking about protective clothing in the kitchen.", n: "La 'a' inicial suena 'éi': ÉI-pron.", nEn: "The first 'a' sounds like 'ay': AY-pron." },
    "loc-vcoc15": { e: "She carried the drinks on a tray.", t: "Llevó las bebidas en una bandeja.", s: "Al servir o transportar varios platos o vasos.", sEn: "When serving or carrying several dishes or glasses.", n: "\"Tray\" rima con 'day'; el plural es \"trays\".", nEn: "\"Tray\" rhymes with 'day'; the plural is \"trays\"." },
    "loc-vcoc16": { e: "Chop the onions on the cutting board.", t: "Pica las cebollas sobre la tabla de cortar.", s: "Al preparar y cortar ingredientes.", sEn: "When preparing and cutting ingredients.", n: "En el Reino Unido se dice \"chopping board\".", nEn: "In the UK people say \"chopping board\"." },
    "loc-vciu01": { e: "The store is just down the street.", t: "La tienda está justo más abajo en la calle.", s: "Al dar o pedir direcciones en la ciudad.", sEn: "When giving or asking for directions in the city.", n: "La 'st-' va junta, sin 'e' delante: 'strit', no 'estrit'.", nEn: "Say 'str-' together, no 'e' before it: 'street', not 'estreet'." },
    "loc-vciu02": { e: "Let's take the kids to the park.", t: "Llevemos a los niños al parque.", s: "Al planear un paseo o sugerir un lugar al aire libre.", sEn: "When planning an outing or suggesting an outdoor spot.", n: "\"Park\" también es verbo: 'estacionar' (to park the car).", nEn: "\"Park\" is also a verb meaning 'to park a car'." },
    "loc-vciu03": { e: "I need to go to the bank before it closes.", t: "Necesito ir al banco antes de que cierre.", s: "Al hablar de trámites de dinero o cuentas.", sEn: "When talking about money matters or accounts.", n: "\"Bank\" es el banco de dinero; el asiento para sentarse es \"bench\".", nEn: "\"Bank\" is the money bank; the seat to sit on is \"bench\"." },
    "loc-vciu04": { e: "They took him to the hospital after the accident.", t: "Lo llevaron al hospital después del accidente.", s: "Al hablar de emergencias o atención médica.", sEn: "When talking about emergencies or medical care.", n: "La 'h' se aspira en inglés y el acento va en la primera sílaba.", nEn: "The 'h' is pronounced and the stress falls on the first syllable." },
    "loc-vciu05": { e: "The children walk to school every morning.", t: "Los niños caminan a la escuela cada mañana.", s: "Al hablar de educación o de la rutina de los niños.", sEn: "When talking about education or kids' routines.", n: "\"School\" lleva 'sk', no 'sh': se dice 'skul'.", nEn: "\"School\" starts with 'sk', not 'sh': say 'skool'." },
    "loc-vciu06": { e: "I'm going to the store to buy some milk.", t: "Voy a la tienda a comprar leche.", s: "Al hablar de hacer compras pequeñas.", sEn: "When talking about doing small shopping.", n: "En el Reino Unido se usa más \"shop\" que \"store\".", nEn: "In the UK people use \"shop\" more than \"store\"." },
    "loc-vciu07": { e: "We buy fresh fruit at the market on Saturdays.", t: "Compramos fruta fresca en el mercado los sábados.", s: "Al hablar de comprar comida fresca al aire libre.", sEn: "When talking about buying fresh food in an open-air spot.", n: "El acento va en la primera sílaba: MAR-ket.", nEn: "The stress falls on the first syllable: MAR-ket." },
    "loc-vciu08": { e: "There's a great restaurant around the corner.", t: "Hay un restaurante buenísimo a la vuelta de la esquina.", s: "Al recomendar un lugar para comer.", sEn: "When recommending a place to eat.", n: "Se pronuncia 'RÉS-to-rant'; la segunda 'au' casi no suena.", nEn: "Say 'RES-tuh-rant'; the middle vowels almost disappear." },
    "loc-vciu09": { e: "The old church is right in the center of town.", t: "La iglesia antigua está justo en el centro del pueblo.", s: "Al señalar un punto de referencia o un edificio histórico.", sEn: "When pointing out a landmark or a historic building.", n: "\"Church\" lleva dos sonidos 'ch'; cuida ambos.", nEn: "\"Church\" has two 'ch' sounds; mind both of them." },
    "loc-vciu10": { e: "You can borrow these books at the library.", t: "Puedes pedir prestados estos libros en la biblioteca.", s: "Al hablar de pedir libros prestados o estudiar.", sEn: "When talking about borrowing books or studying.", n: "Falso amigo: \"library\" es biblioteca; la librería es \"bookstore\".", nEn: "False friend: \"library\" is not a bookshop; that's a \"bookstore\"." },
    "loc-vciu11": { e: "The museum is free on Sundays.", t: "El museo es gratis los domingos.", s: "Al planear una visita cultural o turística.", sEn: "When planning a cultural or tourist visit.", n: "Se pronuncia 'miu-SÍ-om', con el acento en la segunda sílaba.", nEn: "Say 'myoo-ZEE-um', with the stress on the second syllable." },
    "loc-vciu12": { e: "I'll meet you at the train station at noon.", t: "Te veo en la estación del tren al mediodía.", s: "Al dar un punto de encuentro o usar transporte.", sEn: "When giving a meeting point or using transport.", n: "El '-tion' suena 'shon'; el acento va en STÉI.", nEn: "The '-tion' sounds like 'shun'; stress goes on STAY." },
    "loc-vciu13": { e: "Our flight leaves from the airport at eight.", t: "Nuestro vuelo sale del aeropuerto a las ocho.", s: "Al hablar de viajes en avión.", sEn: "When talking about air travel.", n: "Es una sola palabra: \"airport\", con el acento en \"air\".", nEn: "It's one word: \"airport\", stressed on \"air\"." },
    "loc-vciu14": { e: "We're staying at a hotel near the beach.", t: "Nos vamos a quedar en un hotel cerca de la playa.", s: "Al hablar de alojamiento durante un viaje.", sEn: "When talking about lodging during a trip.", n: "El acento va en la segunda sílaba: jou-TÉL.", nEn: "The stress falls on the second syllable: ho-TEL." },
    "loc-vciu15": { e: "You can buy aspirin at any pharmacy.", t: "Puedes comprar aspirina en cualquier farmacia.", s: "Al buscar medicinas o productos de salud.", sEn: "When looking for medicine or health products.", n: "En EE. UU. también se dice \"drugstore\".", nEn: "In the US people also say \"drugstore\"." },
    "loc-vciu16": { e: "We walked across the bridge over the river.", t: "Cruzamos el puente sobre el río.", s: "Al dar direcciones o describir el paisaje urbano.", sEn: "When giving directions or describing the cityscape.", n: "\"Bridge\" termina con sonido 'ch' suave: 'brich'.", nEn: "\"Bridge\" ends with a soft 'j' sound: 'brij'." },
    "loc-vciu17": { e: "The market is held in the town square.", t: "El mercado se pone en la plaza del pueblo.", s: "Al hablar del espacio abierto central de una ciudad.", sEn: "When talking about a city's central open space.", n: "\"Square\" también significa 'cuadrado'; el contexto aclara.", nEn: "\"Square\" also means the shape; context makes it clear." },
    "loc-vciu18": { e: "Turn left at the next traffic light.", t: "Da vuelta a la izquierda en el siguiente semáforo.", s: "Al dar direcciones para manejar o caminar.", sEn: "When giving directions for driving or walking.", n: "En el Reino Unido se dice \"traffic lights\" en plural.", nEn: "In the UK people say \"traffic lights\" in the plural." },
    "loc-vciu19": { e: "The café is on the corner of Main Street.", t: "El café está en la esquina de la calle Main.", s: "Al ubicar un lugar o dar direcciones.", sEn: "When locating a place or giving directions.", n: "\"On the corner\" para la esquina exterior; \"in the corner\" para un rincón interior.", nEn: "\"On the corner\" is the outside corner; \"in the corner\" is an inside nook." },
    "loc-vciu20": { e: "She works in that tall office building.", t: "Ella trabaja en ese edificio de oficinas alto.", s: "Al describir o señalar una construcción grande.", sEn: "When describing or pointing out a large structure.", n: "Se dice 'BÍL-ding'; la 'u' suena como 'i' corta.", nEn: "Say 'BIL-ding'; the 'u' sounds like a short 'i'." },
    "loc-vtrn01": { e: "We went there by car.", t: "Fuimos allá en carro.", s: "Al hablar de cómo te trasladas.", sEn: "When talking about how you get around.", n: "\"By car\" para el medio de transporte, sin artículo.", nEn: "\"By car\" for the means of transport, with no article." },
    "loc-vtrn02": { e: "I take the bus to work every day.", t: "Tomo el autobús al trabajo todos los días.", s: "Al hablar de transporte público.", sEn: "When talking about public transport.", n: "El plural es \"buses\"; cuida que no suene como 'boss'.", nEn: "The plural is \"buses\"; make sure it doesn't sound like 'boss'." },
    "loc-vtrn03": { e: "The train to the city leaves in ten minutes.", t: "El tren a la ciudad sale en diez minutos.", s: "Al viajar o coordinar horarios.", sEn: "When traveling or coordinating schedules.", n: "La 'tr-' va junta y la 'ai' suena 'éi': 'tréin'.", nEn: "Say 'tr-' together and 'ai' like 'ay': 'trayn'." },
    "loc-vtrn04": { e: "Our plane lands at six in the evening.", t: "Nuestro avión aterriza a las seis de la tarde.", s: "Al hablar de vuelos y viajes en avión.", sEn: "When talking about flights and air travel.", n: "\"Plane\" (avión) suena igual que \"plain\" (sencillo); son homófonos.", nEn: "\"Plane\" sounds exactly like \"plain\"; they're homophones." },
    "loc-vtrn05": { e: "I ride my bike to the office.", t: "Voy en bicicleta a la oficina.", s: "Al hablar de moverte en bicicleta.", sEn: "When talking about getting around by bicycle.", n: "\"Bike\" es la forma corta y común de \"bicycle\".", nEn: "\"Bike\" is the short, everyday form of \"bicycle\"." },
    "loc-vtrn06": { e: "He rides a motorcycle to work.", t: "Él va al trabajo en moto.", s: "Al hablar de vehículos de dos ruedas con motor.", sEn: "When talking about powered two-wheeled vehicles.", n: "La forma corta y coloquial es \"motorbike\" o \"bike\".", nEn: "The short, casual form is \"motorbike\" or just \"bike\"." },
    "loc-vtrn07": { e: "Let's take a taxi; it's faster.", t: "Tomemos un taxi; es más rápido.", s: "Al elegir transporte rápido en la ciudad.", sEn: "When choosing fast transport in the city.", n: "El acento va en la primera sílaba: TÁK-si.", nEn: "The stress falls on the first syllable: TAK-si." },
    "loc-vtrn08": { e: "We crossed the lake by boat.", t: "Cruzamos el lago en barco.", s: "Al hablar de viajes por agua.", sEn: "When talking about travel over water.", n: "Un barco grande es \"ship\"; \"boat\" suele ser más pequeño.", nEn: "A large vessel is a \"ship\"; a \"boat\" is usually smaller." },
    "loc-vtrn09": { e: "The truck is delivering the supplies now.", t: "El camión está entregando los suministros ahora.", s: "Al hablar de transporte de carga o entregas.", sEn: "When talking about freight transport or deliveries.", n: "En el Reino Unido se dice \"lorry\" en vez de \"truck\".", nEn: "In the UK people say \"lorry\" instead of \"truck\"." },
    "loc-vtrn10": { e: "It's quicker to take the subway downtown.", t: "Es más rápido tomar el metro al centro.", s: "Al hablar del tren subterráneo de la ciudad.", sEn: "When talking about the city's underground train.", n: "En el Reino Unido es \"underground\" o \"the tube\", no \"subway\".", nEn: "In the UK it's the \"underground\" or \"the tube\", not \"subway\"." },
    "loc-vtrn11": { e: "I bought a one-way ticket to the coast.", t: "Compré un boleto de ida a la costa.", s: "Al comprar pasajes o entradas.", sEn: "When buying travel passes or admission tickets.", n: "\"Ticket\" sirve para boleto de viaje y para entrada de evento.", nEn: "\"Ticket\" works for both a travel ticket and event admission." },
    "loc-vtrn12": { e: "We need to stop for gas before the highway.", t: "Tenemos que parar por gasolina antes de la carretera.", s: "Al hablar de llenar el tanque del carro.", sEn: "When talking about filling up the car's tank.", n: "En el Reino Unido se dice \"petrol\"; \"gas\" allá es el gas doméstico.", nEn: "In the UK it's \"petrol\"; \"gas\" there means household gas." },
    "loc-vtrn13": { e: "One of the wheels on the cart is loose.", t: "Una de las ruedas del carrito está floja.", s: "Al hablar de las ruedas de un vehículo u objeto.", sEn: "When talking about the wheels of a vehicle or object.", n: "La 'wh-' suena como 'u': 'uil'; no la confundas con \"will\".", nEn: "The 'wh-' sounds like 'w': 'weel'; don't mix it up with \"will\"." },
    "loc-vtrn14": { e: "Please take your seat; the show is starting.", t: "Por favor toma tu asiento; el espectáculo va a empezar.", s: "Al indicar dónde sentarse en un transporte o evento.", sEn: "When telling someone where to sit on transport or at an event.", n: "\"Seat\" lleva 'i' larga; no lo confundas con \"sit\" (sentarse).", nEn: "\"Seat\" has a long 'ee'; don't mix it up with \"sit\" (to sit down)." },
    "loc-vtrn15": { e: "Always wear a helmet when you ride.", t: "Usa siempre casco cuando manejes.", s: "Al hablar de seguridad en moto o bicicleta.", sEn: "When talking about safety on a bike or motorcycle.", n: "El acento va en la primera sílaba: JÉL-met.", nEn: "The stress falls on the first syllable: HEL-met." },
    "loc-vtrn16": { e: "This road leads straight to the beach.", t: "Este camino lleva directo a la playa.", s: "Al dar direcciones o describir una vía.", sEn: "When giving directions or describing a route.", n: "Una carretera grande es \"highway\"; \"road\" es más general.", nEn: "A large road is a \"highway\"; \"road\" is more general." },
    "loc-vdia01": { e: "We have a staff meeting every Monday morning.", t: "Tenemos una reunión de equipo todos los lunes por la mañana.", s: "Al hablar de planes o rutinas al inicio de la semana.", sEn: "When talking about plans or routines at the start of the week.", n: "En inglés los días siempre van con mayúscula: \"Monday\".", nEn: "In English, weekdays are always capitalized: \"Monday\"." },
    "loc-vdia02": { e: "The new guests check in on Tuesday afternoon.", t: "Los nuevos huéspedes se registran el martes por la tarde.", s: "Al confirmar fechas de llegada o citas.", sEn: "When confirming arrival dates or appointments.", n: "\"Tuesday\" empieza con \"TIÚS\"; no lo confundas con \"Thursday\".", nEn: "\"Tuesday\" starts with \"TUES\"; don't mix it up with \"Thursday\"." },
    "loc-vdia03": { e: "The pool is closed for cleaning on Wednesday.", t: "La piscina está cerrada por limpieza el miércoles.", s: "Al avisar de horarios o cierres a mitad de semana.", sEn: "When announcing schedules or closures midweek.", n: "Ojo: la primera \"d\" en \"Wednesday\" es muda: \"UÉNS-dei\".", nEn: "Note: the first \"d\" in \"Wednesday\" is silent: \"WENS-day\"." },
    "loc-vdia04": { e: "We get a big delivery of supplies every Thursday.", t: "Recibimos una gran entrega de suministros todos los jueves.", s: "Al hablar de entregas o tareas semanales.", sEn: "When talking about deliveries or weekly tasks.", n: "El \"Th\" suena suave, con la lengua entre los dientes.", nEn: "The \"Th\" is soft, with the tongue between the teeth." },
    "loc-vdia05": { e: "The restaurant gets very busy on Friday night.", t: "El restaurante se llena mucho el viernes por la noche.", s: "Al hablar de los días de más trabajo.", sEn: "When talking about the busiest workdays.", n: "\"Friday\" se pronuncia \"FRÁI-dei\", con \"ai\" como en \"hi\".", nEn: "\"Friday\" is pronounced \"FRY-day\", with \"ai\" like in \"hi\"." },
    "loc-vdia06": { e: "I usually have Saturday off this season.", t: "Normalmente tengo libre el sábado esta temporada.", s: "Al hablar de los días libres o el fin de semana.", sEn: "When talking about days off or the weekend.", n: "\"Saturday\" tiene tres sílabas: SÁ-ter-dei.", nEn: "\"Saturday\" has three syllables: SA-tur-day." },
    "loc-vdia07": { e: "Brunch is served until noon on Sunday.", t: "El brunch se sirve hasta el mediodía el domingo.", s: "Al informar de horarios especiales del fin de semana.", sEn: "When informing about special weekend hours.", n: "No confundas \"Sunday\" (SÁN-dei) con \"Sundae\" (el helado).", nEn: "Don't confuse \"Sunday\" (the day) with \"sundae\" (the ice cream)." },
    "loc-vdia08": { e: "The high season starts in January.", t: "La temporada alta empieza en enero.", s: "Al hablar de meses y fechas con clientes.", sEn: "When talking about months and dates with customers.", n: "\"January\" lleva el acento al inicio: YÁ-niu-e-ri.", nEn: "\"January\" is stressed at the start: JAN-u-ar-y." },
    "loc-vdia09": { e: "We are fully booked for the whole of February.", t: "Estamos completamente llenos durante todo febrero.", s: "Al confirmar disponibilidad por mes.", sEn: "When confirming availability by month.", n: "La primera \"r\" en \"February\" suele omitirse: \"FÉ-bru-e-ri\".", nEn: "The first \"r\" in \"February\" is often dropped: \"FEB-yoo-ary\"." },
    "loc-vdia10": { e: "The weather gets warmer in March.", t: "El clima se vuelve más cálido en marzo.", s: "Al hablar del clima por temporada con los huéspedes.", sEn: "When talking about seasonal weather with guests.", n: "\"March\" se pronuncia tal cual se escribe, como el mes.", nEn: "\"March\" is pronounced just as it's written." },
    "loc-vdia11": { e: "Our busiest tours run in April.", t: "Nuestros tours con más demanda son en abril.", s: "Al planear actividades por mes.", sEn: "When planning activities by month.", n: "\"April\" se pronuncia \"ÉI-pril\", con \"ei\" al inicio.", nEn: "\"April\" is pronounced \"AY-pril\", with \"ay\" at the start." },
    "loc-vdia12": { e: "We open the rooftop bar in May.", t: "Abrimos el bar de la azotea en mayo.", s: "Al anunciar aperturas de temporada.", sEn: "When announcing seasonal openings.", n: "\"May\" suena igual que el verbo \"may\" (poder): \"méi\".", nEn: "\"May\" sounds like the verb \"may\": \"may\"." },
    "loc-vdia13": { e: "Most families travel here in June.", t: "La mayoría de las familias viajan aquí en junio.", s: "Al hablar de cuándo vienen los turistas.", sEn: "When talking about when tourists come.", n: "\"June\" se pronuncia \"yun\"; no la separes en sílabas.", nEn: "\"June\" is pronounced \"joon\"; don't split it into syllables." },
    "loc-vdia14": { e: "The festival takes place in July.", t: "El festival se realiza en julio.", s: "Al mencionar eventos o fechas importantes.", sEn: "When mentioning events or important dates.", n: "El acento de \"July\" va al final: yu-LÁI.", nEn: "The stress in \"July\" falls on the end: ju-LY." },
    "loc-vdia15": { e: "It can be very hot here in August.", t: "Aquí puede hacer mucho calor en agosto.", s: "Al avisar a los huéspedes sobre el calor de verano.", sEn: "When warning guests about the summer heat.", n: "\"August\" lleva el acento al inicio: Ó-gost.", nEn: "\"August\" is stressed at the start: AU-gust." },
    "loc-vdia16": { e: "The crowds get smaller in September.", t: "Hay menos gente en septiembre.", s: "Al hablar de temporada baja o menos clientes.", sEn: "When talking about low season or fewer customers.", n: "\"September\" lleva el acento en la sílaba del medio: sep-TÉM-ber.", nEn: "\"September\" is stressed on the middle syllable: sep-TEM-ber." },
    "loc-vdia17": { e: "The leaves change color in October.", t: "Las hojas cambian de color en octubre.", s: "Al describir el ambiente o el paisaje a los turistas.", sEn: "When describing the setting or scenery to tourists.", n: "\"October\" lleva el acento en \"TÓU\": ok-TÓU-ber.", nEn: "\"October\" is stressed on \"TO\": oc-TO-ber." },
    "loc-vdia18": { e: "We decorate the lobby in November.", t: "Decoramos el lobby en noviembre.", s: "Al hablar de preparativos por temporada.", sEn: "When talking about seasonal preparations.", n: "\"November\" lleva el acento en el medio: no-VÉM-ber.", nEn: "\"November\" is stressed in the middle: no-VEM-ber." },
    "loc-vdia19": { e: "The hotel is fully booked in December.", t: "El hotel está totalmente reservado en diciembre.", s: "Al hablar de las fechas más concurridas del año.", sEn: "When talking about the busiest dates of the year.", n: "\"December\" lleva el acento en \"SÉM\": di-SÉM-ber.", nEn: "\"December\" is stressed on \"CEM\": de-CEM-ber." },
    "loc-vcli01": { e: "There's plenty of sun today, perfect for the pool.", t: "Hay mucho sol hoy, perfecto para la piscina.", s: "Al comentar el buen clima con los huéspedes.", sEn: "When commenting on the nice weather with guests.", n: "\"Sun\" (sol) y \"son\" (hijo) suenan igual: \"san\".", nEn: "\"Sun\" and \"son\" sound the same: \"san\"." },
    "loc-vcli02": { e: "Bring an umbrella, there's rain in the forecast.", t: "Trae un paraguas, hay lluvia en el pronóstico.", s: "Al aconsejar a un turista antes de salir.", sEn: "When advising a tourist before going out.", n: "\"Rain\" se pronuncia \"réin\"; no añadas una \"e\" inicial.", nEn: "\"Rain\" is pronounced \"rain\"; don't add an extra \"e\" at the start." },
    "loc-vcli03": { e: "There's not a single cloud in the sky.", t: "No hay ni una sola nube en el cielo.", s: "Al describir el clima al planear una actividad.", sEn: "When describing the weather while planning an activity.", n: "\"Cloud\" rima con \"loud\": \"kláud\".", nEn: "\"Cloud\" rhymes with \"loud\": \"kloud\"." },
    "loc-vcli04": { e: "The wind is strong by the coast today.", t: "El viento está fuerte cerca de la costa hoy.", s: "Al avisar sobre las condiciones del clima.", sEn: "When warning about weather conditions.", n: "\"Wind\" (viento) lleva \"i\" corta; \"wind\" (enrollar) suena \"uáind\".", nEn: "\"Wind\" (the air) has a short \"i\"; \"wind\" (to coil) sounds like \"wined\"." },
    "loc-vcli05": { e: "We get a lot of snow up in the mountains.", t: "Cae mucha nieve allá en las montañas.", s: "Al describir el clima de la zona a los huéspedes.", sEn: "When describing the area's weather to guests.", n: "La \"w\" en \"snow\" es muda: se dice \"snóu\".", nEn: "The \"w\" in \"snow\" is silent: it's said \"snow\"." },
    "loc-vcli06": { e: "A big storm is coming tonight, so stay inside.", t: "Viene una gran tormenta esta noche, así que quédese adentro.", s: "Al advertir a los turistas de mal clima.", sEn: "When warning tourists about bad weather.", n: "\"Storm\" se pronuncia con \"or\" claro, sin \"e\" al inicio.", nEn: "\"Storm\" is pronounced with a clear \"or\", no \"e\" at the start." },
    "loc-vcli07": { e: "It's really hot out, would you like some cold water?", t: "Hace mucho calor afuera, ¿le gustaría un poco de agua fría?", s: "Al ofrecer algo refrescante a un cliente.", sEn: "When offering something refreshing to a customer.", n: "\"Hot\" describe el calor; para una persona usa \"I'm hot\", no \"I have heat\".", nEn: "\"Hot\" describes heat; for a person say \"I'm hot\", not \"I have heat\"." },
    "loc-vcli08": { e: "It gets cold here at night, so bring a jacket.", t: "Aquí hace frío de noche, así que trae una chaqueta.", s: "Al aconsejar qué ropa llevar a un turista.", sEn: "When advising a tourist what to wear.", n: "Para una persona di \"I'm cold\", no \"I have cold\".", nEn: "For a person say \"I'm cold\", not \"I have cold\"." },
    "loc-vcli09": { e: "The water is warm enough for swimming.", t: "El agua está lo bastante templada para nadar.", s: "Al describir las condiciones de la playa o piscina.", sEn: "When describing beach or pool conditions.", n: "\"Warm\" lleva \"or\": \"uorm\"; no lo confundas con \"worm\" (gusano).", nEn: "\"Warm\" has an \"or\" sound; don't confuse it with \"worm\"." },
    "loc-vcli10": { e: "The air feels very humid this afternoon.", t: "El aire se siente muy húmedo esta tarde.", s: "Al comentar el clima pegajoso del trópico.", sEn: "When commenting on the sticky tropical weather.", n: "\"Humid\" lleva el acento al inicio: JIÚ-mid.", nEn: "\"Humid\" is stressed at the start: HU-mid." },
    "loc-vcli11": { e: "The weather stays dry all summer here.", t: "El clima se mantiene seco todo el verano aquí.", s: "Al describir el clima de la región a los huéspedes.", sEn: "When describing the region's climate to guests.", n: "\"Dry\" se pronuncia \"drai\", con la misma \"ai\" de \"my\".", nEn: "\"Dry\" is pronounced \"dry\", with the \"ai\" of \"my\"." },
    "loc-vcli12": { e: "It's sunny today, a great day for the beach.", t: "Está soleado hoy, un gran día para la playa.", s: "Al sugerir planes según el buen clima.", sEn: "When suggesting plans based on the nice weather.", n: "\"Sunny\" (soleado) lleva doble \"n\"; \"sunny\", no \"suny\".", nEn: "\"Sunny\" has a double \"n\"; \"sunny\", not \"suny\"." },
    "loc-vcli13": { e: "It looks cloudy, but it probably won't rain.", t: "Se ve nublado, pero probablemente no lloverá.", s: "Al comentar el cielo antes de una salida.", sEn: "When commenting on the sky before an outing.", n: "\"Cloudy\" lleva el acento al inicio: KLÁU-di.", nEn: "\"Cloudy\" is stressed at the start: CLOUD-y." },
    "loc-vcli14": { e: "It's a rainy day, perfect for staying in the café.", t: "Es un día lluvioso, perfecto para quedarse en el café.", s: "Al sugerir un plan bajo techo por la lluvia.", sEn: "When suggesting an indoor plan because of the rain.", n: "\"Rainy\" describe el día; \"rain\" es el sustantivo (la lluvia).", nEn: "\"Rainy\" describes the day; \"rain\" is the noun (the rain itself)." },
    "loc-vcli15": { e: "There's thick fog on the road this morning.", t: "Hay neblina densa en la carretera esta mañana.", s: "Al avisar de condiciones difíciles para manejar o caminar.", sEn: "When warning about tricky driving or walking conditions.", n: "\"Fog\" se pronuncia corto, \"fog\"; el adjetivo es \"foggy\".", nEn: "\"Fog\" is pronounced short, \"fog\"; the adjective is \"foggy\"." },
    "loc-vcli16": { e: "We saw lightning out over the ocean.", t: "Vimos relámpagos sobre el océano.", s: "Al describir una tormenta a los huéspedes.", sEn: "When describing a storm to guests.", n: "\"Lightning\" (relámpago) no lleva \"e\"; \"lightening\" significa aclarar.", nEn: "\"Lightning\" (the flash) has no \"e\"; \"lightening\" means making lighter." },
    "loc-vcli17": { e: "There's a beautiful rainbow after the storm.", t: "Hay un hermoso arcoíris después de la tormenta.", s: "Al señalar algo bonito del paisaje a los turistas.", sEn: "When pointing out something nice in the scenery to tourists.", n: "\"Rainbow\" es una sola palabra: RÉIN-bou.", nEn: "\"Rainbow\" is one word: RAIN-bow." },
    "loc-vver01": { e: "I am the new receptionist on the morning shift.", t: "Soy la nueva recepcionista del turno de la mañana.", s: "Al presentarte o describir tu puesto.", sEn: "When introducing yourself or describing your role.", n: "\"To be\" es irregular: I am, you are, he is.", nEn: "\"To be\" is irregular: I am, you are, he is." },
    "loc-vver02": { e: "We have a table available for two at eight.", t: "Tenemos una mesa disponible para dos a las ocho.", s: "Al confirmar disponibilidad a un cliente.", sEn: "When confirming availability to a customer.", n: "En tercera persona cambia: \"he has\", no \"he haves\".", nEn: "In the third person it changes: \"he has\", not \"he haves\"." },
    "loc-vver03": { e: "I'll do my best to get you an early check-in.", t: "Haré lo posible por conseguirle un registro temprano.", s: "Al ofrecer ayuda a un huésped.", sEn: "When offering help to a guest.", n: "\"Do\" sirve también para preguntas: \"Do you need anything?\".", nEn: "\"Do\" also forms questions: \"Do you need anything?\"." },
    "loc-vver04": { e: "I go to the market early to buy fresh fish.", t: "Voy temprano al mercado a comprar pescado fresco.", s: "Al hablar de tu rutina o tareas del trabajo.", sEn: "When talking about your routine or work tasks.", n: "En tercera persona se añade \"es\": \"she goes\".", nEn: "In the third person you add \"es\": \"she goes\"." },
    "loc-vver05": { e: "Our guests usually eat dinner around eight.", t: "Nuestros huéspedes suelen cenar alrededor de las ocho.", s: "Al describir los horarios de comida del hotel.", sEn: "When describing the hotel's meal times.", n: "El pasado es irregular: \"ate\", no \"eated\".", nEn: "The past tense is irregular: \"ate\", not \"eated\"." },
    "loc-vver06": { e: "What would you like to drink with your meal?", t: "¿Qué le gustaría tomar con su comida?", s: "Al tomar el pedido de bebidas a una mesa.", sEn: "When taking a table's drink order.", n: "\"Drink\" lleva \"i\" corta, como en \"sit\".", nEn: "\"Drink\" has a short \"i\" like in \"sit\"." },
    "loc-vver07": { e: "Most guests sleep late after a long flight.", t: "La mayoría de los huéspedes duermen hasta tarde tras un vuelo largo.", s: "Al explicar por qué pides no molestar por la mañana.", sEn: "When explaining why you ask not to disturb in the morning.", n: "\"Sleep\" lleva la \"i\" larga (como en \"see\"); no la acortes a \"slip\".", nEn: "\"Sleep\" has a long \"ee\": \"sleep\"; don't shorten it." },
    "loc-vver08": { e: "I speak a little English and some Portuguese.", t: "Hablo un poco de inglés y algo de portugués.", s: "Al decirle a un cliente qué idiomas manejas.", sEn: "When telling a customer which languages you can use.", n: "Usa \"speak\" para idiomas: \"I speak English\".", nEn: "Use \"speak\" for languages: \"I speak English\"." },
    "loc-vver09": { e: "From here you can see the whole bay.", t: "Desde aquí se puede ver toda la bahía.", s: "Al señalar una vista a los turistas en un tour.", sEn: "When pointing out a view to tourists on a tour.", n: "\"See\" (ver) suena igual que \"sea\" (mar): \"si\".", nEn: "\"See\" (to look) sounds like \"sea\" (the ocean): \"see\"." },
    "loc-vver10": { e: "I can hear the music from the bar downstairs.", t: "Puedo oír la música del bar de abajo.", s: "Al comentar ruidos o sonidos con un huésped.", sEn: "When commenting on noises or sounds with a guest.", n: "\"Hear\" (oír) suena igual que \"here\" (aquí): \"jir\".", nEn: "\"Hear\" (to listen) sounds like \"here\" (this place): \"heer\"." },
    "loc-vver11": { e: "Please come this way, your table is ready.", t: "Por favor venga por aquí, su mesa está lista.", s: "Al guiar a un cliente a su mesa o habitación.", sEn: "When leading a customer to their table or room.", n: "El pasado es irregular: \"came\", no \"comed\".", nEn: "The past tense is irregular: \"came\", not \"comed\"." },
    "loc-vver12": { e: "Let me give you a map of the area.", t: "Permítame darle un mapa de la zona.", s: "Al entregar algo útil a un huésped.", sEn: "When handing something useful to a guest.", n: "El pasado es irregular: \"gave\", no \"gived\".", nEn: "The past tense is irregular: \"gave\", not \"gived\"." },
    "loc-vver13": { e: "I'll take your bags up to the room.", t: "Le subo las maletas a la habitación.", s: "Al ofrecer ayuda con el equipaje.", sEn: "When offering help with luggage.", n: "El pasado es irregular: \"took\", no \"taked\".", nEn: "The past tense is irregular: \"took\", not \"taked\"." },
    "loc-vver14": { e: "Do you know what time the tour starts?", t: "¿Sabe a qué hora empieza el tour?", s: "Al preguntar o confirmar información con alguien.", sEn: "When asking or confirming information with someone.", n: "La \"k\" en \"know\" es muda: se dice \"nóu\".", nEn: "The \"k\" in \"know\" is silent: it's said \"no\"." },
    "loc-vver15": { e: "I think the blue room has a better view.", t: "Creo que la habitación azul tiene mejor vista.", s: "Al dar tu opinión o una recomendación.", sEn: "When giving your opinion or a recommendation.", n: "El \"th\" en \"think\" es suave, con la lengua entre los dientes.", nEn: "The \"th\" in \"think\" is soft, with the tongue between the teeth." },
    "loc-vver16": { e: "Do you want me to book a taxi for you?", t: "¿Quiere que le reserve un taxi?", s: "Al ofrecer un servicio extra a un huésped.", sEn: "When offering an extra service to a guest.", n: "Para ser más cortés usa \"would you like\" en vez de \"do you want\".", nEn: "To be more polite, use \"would you like\" instead of \"do you want\"." },
    "loc-vver17": { e: "I work at the front desk on weekends.", t: "Trabajo en la recepción los fines de semana.", s: "Al hablar de tu horario o tu puesto.", sEn: "When talking about your schedule or your role.", n: "\"Work\" lleva el sonido \"er\" (como en \"her\"): suena \"uerk\", no \"uork\" con \"o\" clara.", nEn: "\"Work\" has the \"er\" sound (like in \"her\"): \"werk\", not \"work\" with a clear \"o\"." },
    "loc-vver18": { e: "The kids can play in the garden by the pool.", t: "Los niños pueden jugar en el jardín junto a la piscina.", s: "Al señalar zonas para los huéspedes con familia.", sEn: "When pointing out areas for guests with family.", n: "\"Play\" sirve para juegos y para instrumentos: \"play the guitar\".", nEn: "\"Play\" works for games and instruments: \"play the guitar\"." },
    "loc-vver19": { e: "You can read the menu while I bring some water.", t: "Puede leer el menú mientras le traigo un poco de agua.", s: "Al dar tiempo a un cliente para decidir.", sEn: "When giving a customer time to decide.", n: "\"Read\" en presente suena \"rid\"; en pasado suena \"red\".", nEn: "\"Read\" in the present sounds \"reed\"; in the past it sounds \"red\"." },
    "loc-vver20": { e: "Please write your name here on the form.", t: "Por favor escriba su nombre aquí en el formulario.", s: "Al pedirle datos a un huésped en el registro.", sEn: "When asking a guest for details at check-in.", n: "La \"w\" en \"write\" es muda: se dice \"ráit\".", nEn: "The \"w\" in \"write\" is silent: it's said \"rite\"." },
    "loc-vver21": { e: "You can walk to the beach in five minutes.", t: "Puede caminar a la playa en cinco minutos.", s: "Al dar indicaciones a pie a un turista.", sEn: "When giving walking directions to a tourist.", n: "La \"l\" en \"walk\" es muda: se dice \"uok\".", nEn: "The \"l\" in \"walk\" is silent: it's said \"wok\"." },
    "loc-vver22": { e: "I have to run to the kitchen for a moment.", t: "Tengo que correr a la cocina un momento.", s: "Al excusarte por salir rápido durante el servicio.", sEn: "When excusing yourself to step away quickly during service.", n: "El pasado es irregular: \"ran\", no \"runned\".", nEn: "The past tense is irregular: \"ran\", not \"runned\"." },
    "loc-vver23": { e: "You can buy souvenirs at the shop next door.", t: "Puede comprar recuerdos en la tienda de al lado.", s: "Al recomendar dónde comprar algo a un turista.", sEn: "When recommending where to buy something to a tourist.", n: "\"Buy\" (comprar) suena igual que \"by\" y \"bye\": \"bai\".", nEn: "\"Buy\" sounds the same as \"by\" and \"bye\": \"bye\"." },
    "loc-vver24": { e: "How would you like to pay, cash or card?", t: "¿Cómo desea pagar, en efectivo o con tarjeta?", s: "Al cerrar la cuenta con un cliente.", sEn: "When settling the bill with a customer.", n: "\"Pay for\" lleva \"for\": \"pay for the room\".", nEn: "\"Pay for\" takes \"for\": \"pay for the room\"." },
    "loc-vadj01": { e: "We have a big room with a balcony available.", t: "Tenemos una habitación grande con balcón disponible.", s: "Al describir las opciones de habitación a un huésped.", sEn: "When describing room options to a guest.", n: "\"Big\" es informal; \"large\" suena un poco más formal.", nEn: "\"Big\" is casual; \"large\" sounds a bit more formal." },
    "loc-vadj02": { e: "It's a small table by the window, is that okay?", t: "Es una mesa pequeña junto a la ventana, ¿está bien?", s: "Al ofrecer una mesa concreta a los clientes.", sEn: "When offering a specific table to customers.", n: "\"Small\" se pronuncia \"smol\", con la \"l\" suave al final.", nEn: "\"Small\" is pronounced \"smol\", with a soft \"l\" at the end." },
    "loc-vadj03": { e: "This is a good time to visit the old town.", t: "Este es un buen momento para visitar el casco antiguo.", s: "Al dar una recomendación a un turista.", sEn: "When giving a recommendation to a tourist.", n: "El comparativo de \"good\" es irregular: \"better\", no \"gooder\".", nEn: "The comparative of \"good\" is irregular: \"better\", not \"gooder\"." },
    "loc-vadj04": { e: "I'm sorry the weather is so bad today.", t: "Lamento que el clima esté tan malo hoy.", s: "Al disculparte por algo fuera de tu control.", sEn: "When apologizing for something out of your control.", n: "El comparativo de \"bad\" es irregular: \"worse\", no \"badder\".", nEn: "The comparative of \"bad\" is irregular: \"worse\", not \"badder\"." },
    "loc-vadj05": { e: "We just opened a new spa on the top floor.", t: "Acabamos de abrir un nuevo spa en el último piso.", s: "Al promocionar un servicio reciente al huésped.", sEn: "When promoting a recent service to the guest.", n: "\"New\" se pronuncia \"niu\"; no lo confundas con \"knew\" (pasado de know).", nEn: "\"New\" is pronounced \"new\"; don't confuse it with \"knew\" (past of know)." },
    "loc-vadj06": { e: "The old part of the city is worth a visit.", t: "La parte antigua de la ciudad vale la pena visitar.", s: "Al recomendar un lugar histórico a un turista.", sEn: "When recommending a historic place to a tourist.", n: "\"Old\" se pronuncia \"óuld\", con la \"o\" como diptongo.", nEn: "\"Old\" is pronounced \"old\", with the \"o\" as a diphthong." },
    "loc-vadj07": { e: "The tall building over there is our hotel.", t: "El edificio alto de allá es nuestro hotel.", s: "Al señalar una referencia a un turista.", sEn: "When pointing out a landmark to a tourist.", n: "Usa \"tall\" para personas y edificios; \"high\" para alturas o montañas.", nEn: "Use \"tall\" for people and buildings; \"high\" for heights or mountains." },
    "loc-vadj08": { e: "It's only a short walk from here to the beach.", t: "Es solo una caminata corta de aquí a la playa.", s: "Al indicar distancias a pie a un huésped.", sEn: "When indicating walking distances to a guest.", n: "\"Short\" sirve para distancia y para estatura baja.", nEn: "\"Short\" works for distance and for being not tall." },
    "loc-vadj09": { e: "It's a long drive to the airport, about an hour.", t: "Es un trayecto largo al aeropuerto, como una hora.", s: "Al avisar de tiempos o distancias a un huésped.", sEn: "When warning about times or distances to a guest.", n: "\"Long\" sirve para distancia y para tiempo: \"a long time\".", nEn: "\"Long\" works for distance and for time: \"a long time\"." },
    "loc-vadj10": { e: "The seafood here is excellent but a bit expensive.", t: "Los mariscos aquí son excelentes pero un poco caros.", s: "Al describir un lugar o plato con su precio a un turista.", sEn: "When describing a place or dish and its price to a tourist.", n: "\"Expensive\" lleva el acento en el medio: eks-PÉN-siv.", nEn: "\"Expensive\" is stressed in the middle: ex-PEN-sive." },
    "loc-vadj11": { e: "The bus is a cheap way to get downtown.", t: "El autobús es una forma barata de llegar al centro.", s: "Al sugerir una opción económica a un turista.", sEn: "When suggesting a budget option to a tourist.", n: "\"Cheap\" lleva \"i\" larga, como en \"sheep\"; no la acortes como en \"ship\".", nEn: "\"Cheap\" has a long \"ee\": \"cheap\"; don't shorten it." },
    "loc-vadj12": { e: "The wifi here is fast, so you can stream easily.", t: "El wifi aquí es rápido, así que puede ver videos sin problema.", s: "Al destacar un servicio del hotel.", sEn: "When highlighting a hotel service.", n: "\"Fast\" es adjetivo y adverbio: \"a fast car\", \"run fast\".", nEn: "\"Fast\" is both adjective and adverb: \"a fast car\", \"run fast\"." },
    "loc-vadj13": { e: "Service is a little slow tonight, sorry for the wait.", t: "El servicio está un poco lento esta noche, disculpe la espera.", s: "Al disculparte por una demora con un cliente.", sEn: "When apologizing for a delay with a customer.", n: "\"Slow\" se pronuncia \"slóu\", con la \"w\" muda.", nEn: "\"Slow\" is pronounced \"slow\", with a silent \"w\"." },
    "loc-vadj14": { e: "The trail is easy, good for the whole family.", t: "El sendero es fácil, bueno para toda la familia.", s: "Al recomendar una actividad a un turista.", sEn: "When recommending an activity to a tourist.", n: "El opuesto de \"easy\" es \"difficult\" o \"hard\".", nEn: "The opposite of \"easy\" is \"difficult\" or \"hard\"." },
    "loc-vadj15": { e: "The hike is hard, so wear good shoes.", t: "La caminata es difícil, así que use buen calzado.", s: "Al advertir de una actividad exigente a un turista.", sEn: "When warning about a demanding activity to a tourist.", n: "\"Hard\" significa difícil y también duro al tacto.", nEn: "\"Hard\" means both difficult and firm to the touch." },
    "loc-vadj16": { e: "We're happy to have you stay with us.", t: "Estamos felices de tenerlo hospedado con nosotros.", s: "Al dar la bienvenida o despedir a un huésped.", sEn: "When welcoming or seeing off a guest.", n: "\"Happy\" lleva el acento al inicio: JÁ-pi.", nEn: "\"Happy\" is stressed at the start: HAP-py." },
    "loc-vadj17": { e: "I'm sad to hear you're leaving so soon.", t: "Me da pena saber que se va tan pronto.", s: "Al despedir a un huésped que se va antes de lo esperado.", sEn: "When seeing off a guest who is leaving sooner than expected.", n: "\"Sad\" se pronuncia con \"a\" abierta, como en \"cat\".", nEn: "\"Sad\" is pronounced with an open \"a\", like in \"cat\"." },
    "loc-vadj18": { e: "The garden looks really pretty in the evening.", t: "El jardín se ve muy bonito al atardecer.", s: "Al describir algo agradable del lugar a un huésped.", sEn: "When describing something pleasant about the place to a guest.", n: "\"Pretty\" también significa \"bastante\": \"pretty good\".", nEn: "\"Pretty\" also means \"quite\": \"pretty good\"." },
    "loc-vadj19": { e: "The coffee here is strong, just so you know.", t: "El café aquí es fuerte, para que lo sepa.", s: "Al avisar a un cliente sobre el sabor o la intensidad.", sEn: "When warning a customer about flavor or intensity.", n: "\"Strong\" sirve para sabor, personas y cosas resistentes.", nEn: "\"Strong\" works for flavor, people, and sturdy things." },
    "loc-vadj20": { e: "Your room is clean and ready for you now.", t: "Su habitación está limpia y lista para usted ahora.", s: "Al confirmar a un huésped que su cuarto está listo.", sEn: "When confirming to a guest that their room is ready.", n: "\"Clean\" lleva \"i\" larga: \"klin\"; el verbo \"to clean\" es igual.", nEn: "\"Clean\" has a long \"ee\": \"clean\"; the verb \"to clean\" is the same." },
    "loc-vpro01": { e: "My sister is a teacher at the local elementary school.", t: "Mi hermana es maestra en la escuela primaria del barrio.", s: "Cuando hablas de alguien que enseña en una escuela.", sEn: "When you talk about someone who teaches at a school.", n: "\"Teacher\" se pronuncia \"TÍ-cher\", con la 'ch' suave como en \"chair\".", nEn: "\"Teacher\" is said \"TEE-cher\", with a soft 'ch' like in \"chair\"." },
    "loc-vpro02": { e: "You should see a doctor if the pain doesn't go away.", t: "Deberías ver a un médico si el dolor no se te quita.", s: "Cuando recomiendas atención médica a alguien que no se siente bien.", sEn: "When you recommend medical care to someone who feels unwell.", n: "\"Doctor\" sirve para médicos y para títulos de doctorado; el contexto aclara cuál.", nEn: "\"Doctor\" works for medical doctors and for PhD holders; context tells you which." },
    "loc-vpro03": { e: "The nurse checked my blood pressure before the doctor came in.", t: "La enfermera me tomó la presión antes de que entrara el médico.", s: "Cuando describes la atención en un hospital o clínica.", sEn: "When you describe care at a hospital or clinic.", n: "\"Nurse\" vale para hombres y mujeres; no hay una palabra distinta por género.", nEn: "\"Nurse\" works for men and women; there's no separate word by gender." },
    "loc-vpro04": { e: "He works as an engineer at a company that builds bridges.", t: "Él trabaja como ingeniero en una empresa que construye puentes.", s: "Cuando hablas de alguien que diseña o construye cosas técnicas.", sEn: "When you talk about someone who designs or builds technical things.", n: "El acento va al final: \"en-yi-NÍR\", no al principio como en español.", nEn: "The stress falls at the end: \"en-juh-NEER\", not at the start like in Spanish." },
    "loc-vpro05": { e: "We hired a lawyer to help us with the rental contract.", t: "Contratamos a un abogado para que nos ayudara con el contrato de alquiler.", s: "Cuando necesitas ayuda legal con documentos o un caso.", sEn: "When you need legal help with documents or a case.", n: "\"Lawyer\" se dice \"LÓ-yer\"; en inglés británico también se oye \"solicitor\".", nEn: "\"Lawyer\" is said \"LOY-er\"; in British English you also hear \"solicitor\"." },
    "loc-vpro06": { e: "The cook prepared a special dish for the birthday party.", t: "El cocinero preparó un platillo especial para la fiesta de cumpleaños.", s: "Cuando hablas de quien prepara la comida en una cocina.", sEn: "When you talk about the person who prepares food in a kitchen.", n: "\"Cook\" es general; \"chef\" se reserva para el jefe de cocina profesional.", nEn: "\"Cook\" is general; \"chef\" is kept for the professional head of the kitchen." },
    "loc-vpro07": { e: "The waiter brought us the menu and a jug of water.", t: "El mesero nos trajo el menú y una jarra de agua.", s: "Cuando describes el servicio en un restaurante.", sEn: "When you describe the service at a restaurant.", n: "Para una mujer puedes decir \"waitress\", aunque \"server\" sirve para ambos.", nEn: "For a woman you can say \"waitress\", though \"server\" works for both." },
    "loc-vpro08": { e: "A police officer stopped the traffic so the kids could cross.", t: "Un policía detuvo el tráfico para que los niños pudieran cruzar.", s: "Cuando hablas de seguridad pública o de pedir ayuda en la calle.", sEn: "When you talk about public safety or asking for help on the street.", n: "Di \"police officer\", no solo \"police\", para referirte a una persona.", nEn: "Say \"police officer\", not just \"police\", to refer to one person." },
    "loc-vpro09": { e: "The firefighter carried the dog out of the burning house.", t: "El bombero sacó al perro de la casa en llamas.", s: "Cuando hablas de emergencias con fuego o rescates.", sEn: "When you talk about fire emergencies or rescues.", n: "Es una sola palabra: \"firefighter\"; \"fireman\" suena anticuado hoy.", nEn: "It's one word: \"firefighter\"; \"fireman\" sounds dated today." },
    "loc-vpro10": { e: "The bus driver waited a moment so I could get on.", t: "El conductor del autobús esperó un momento para que me subiera.", s: "Cuando hablas de quien maneja un vehículo o transporte.", sEn: "When you talk about whoever drives a vehicle or transport.", n: "\"Driver\" se usa con muchos vehículos: \"taxi driver\", \"truck driver\".", nEn: "\"Driver\" pairs with many vehicles: \"taxi driver\", \"truck driver\"." },
    "loc-vpro11": { e: "The seller gave me a small discount because I bought two.", t: "El vendedor me dio un pequeño descuento porque compré dos.", s: "Cuando hablas de quien te atiende en una venta.", sEn: "When you talk about the person who serves you in a sale.", n: "En tiendas suele decirse \"salesperson\" o \"shop assistant\" más que \"seller\".", nEn: "In shops people often say \"salesperson\" or \"shop assistant\" rather than \"seller\"." },
    "loc-vpro12": { e: "The cashier asked if I wanted a bag for my groceries.", t: "El cajero me preguntó si quería una bolsa para mis compras.", s: "Cuando pagas en la caja de una tienda o supermercado.", sEn: "When you pay at the checkout of a store or supermarket.", n: "El acento va al final: \"ka-SHÍR\"; cuidado con no decir \"CÁ-shier\".", nEn: "The stress falls at the end: \"ka-SHEER\"; be careful not to say \"CASH-ier\"." },
    "loc-vpro13": { e: "The secretary will email you the meeting details this afternoon.", t: "La secretaria te enviará por correo los detalles de la reunión esta tarde.", s: "Cuando hablas de quien organiza la oficina y la agenda.", sEn: "When you talk about whoever organizes the office and schedule.", n: "Muchas oficinas hoy prefieren \"assistant\" o \"office manager\".", nEn: "Many offices today prefer \"assistant\" or \"office manager\"." },
    "loc-vpro14": { e: "Let me ask the manager if we can change your reservation.", t: "Déjame preguntarle al gerente si podemos cambiar tu reservación.", s: "Cuando un cliente pide algo que necesita aprobación.", sEn: "When a customer asks for something that needs approval.", n: "Se dice \"MÁ-na-yer\"; la 'a' del medio es muy corta, casi se la traga.", nEn: "It's said \"MAN-uh-jer\"; the middle 'a' is very short, almost swallowed." },
    "loc-vpro15": { e: "The receptionist gave me my room key and a map of the hotel.", t: "El recepcionista me dio la llave de mi habitación y un mapa del hotel.", s: "Cuando llegas a un hotel u oficina y te atienden en la entrada.", sEn: "When you arrive at a hotel or office and are helped at the front desk.", n: "Es una palabra larga: \"ri-SÉP-shon-ist\"; practícala por sílabas.", nEn: "It's a long word: \"ri-SEP-shun-ist\"; practice it syllable by syllable." },
    "loc-vpro16": { e: "Our guide showed us the best spot to watch the sunset.", t: "Nuestro guía nos mostró el mejor lugar para ver el atardecer.", s: "Cuando hablas de quien dirige un tour o una excursión.", sEn: "When you talk about whoever leads a tour or excursion.", n: "\"Guide\" rima con \"ride\"; se dice \"gáid\", no \"GUÍ-de\".", nEn: "\"Guide\" rhymes with \"ride\"; it's said \"gyde\", not \"GEE-deh\"." },
    "loc-vpro17": { e: "We called an electrician because the lights kept flickering.", t: "Llamamos a un electricista porque las luces seguían parpadeando.", s: "Cuando hay un problema con la electricidad en casa.", sEn: "When there's a problem with the electricity at home.", n: "Se dice \"i-lek-TRÍ-shan\"; el final \"-cian\" suena como \"shan\".", nEn: "It's said \"i-lek-TRI-shun\"; the ending \"-cian\" sounds like \"shun\"." },
    "loc-vpro18": { e: "The plumber fixed the leak under the kitchen sink.", t: "El plomero arregló la fuga debajo del fregadero de la cocina.", s: "Cuando hay un problema con tuberías o agua en casa.", sEn: "When there's a problem with pipes or water at home.", n: "La 'b' de \"plumber\" es muda: suena \"PLÁ-mer\", no \"PLÁM-ber\".", nEn: "The 'b' in \"plumber\" is silent: it sounds like \"PLUM-er\", not \"PLUMB-ber\"." },
    "loc-vpro19": { e: "My hairdresser always knows exactly how I want my hair cut.", t: "Mi peluquero siempre sabe exactamente cómo quiero el corte de pelo.", s: "Cuando hablas de quien te corta o arregla el cabello.", sEn: "When you talk about whoever cuts or styles your hair.", n: "También se dice \"hairstylist\"; \"barber\" es para cortes de hombre.", nEn: "You can also say \"hairstylist\"; \"barber\" is for men's haircuts." },
    "loc-vpro20": { e: "The farmer wakes up early to feed the animals.", t: "El agricultor se levanta temprano para darle de comer a los animales.", s: "Cuando hablas de quien trabaja la tierra o cría animales.", sEn: "When you talk about whoever works the land or raises animals.", n: "\"Farmer\" cubre tanto al agricultor como al ganadero.", nEn: "\"Farmer\" covers both crop growers and livestock keepers." },
    "loc-vtec01": { e: "My computer is running slow, so I need to restart it.", t: "Mi computadora está lenta, así que necesito reiniciarla.", s: "Cuando hablas del equipo que usas para trabajar o estudiar.", sEn: "When you talk about the device you use to work or study.", n: "El acento va en medio: \"kom-PIÚ-ter\", no al principio.", nEn: "The stress is in the middle: \"kom-PYOO-ter\", not at the start." },
    "loc-vtec02": { e: "Can I borrow your phone to make a quick call?", t: "¿Me prestas tu teléfono para hacer una llamada rápida?", s: "Cuando pides usar el celular de alguien.", sEn: "When you ask to use someone's cell phone.", n: "La 'ph' suena como 'f': se dice \"fóun\", no \"póun\".", nEn: "The 'ph' sounds like 'f': it's said \"fone\", not \"pone\"." },
    "loc-vtec03": { e: "The screen cracked when I dropped my phone on the floor.", t: "La pantalla se rajó cuando se me cayó el teléfono al piso.", s: "Cuando hablas de la parte que muestra la imagen en un dispositivo.", sEn: "When you talk about the part that shows the image on a device.", n: "\"Screen\" empieza con \"scr-\", un grupo difícil; practica \"sk-rin\".", nEn: "\"Screen\" starts with \"scr-\", a tricky cluster; practice \"sk-reen\"." },
    "loc-vtec04": { e: "I spilled coffee on the keyboard and now some keys stick.", t: "Derramé café sobre el teclado y ahora algunas teclas se quedan pegadas.", s: "Cuando hablas de lo que usas para escribir en la computadora.", sEn: "When you talk about what you use to type on the computer.", n: "Es palabra compuesta: \"key\" + \"board\", se dice \"KÍ-bord\".", nEn: "It's a compound word: \"key\" + \"board\", said \"KEY-bord\"." },
    "loc-vtec05": { e: "Click the file with the mouse and then press enter.", t: "Haz clic en el archivo con el ratón y luego presiona enter.", s: "Cuando explicas cómo usar la computadora.", sEn: "When you explain how to use the computer.", n: "El plural del aparato suele ser \"mouses\" o \"mice\"; ambos se oyen.", nEn: "The plural of the device is often \"mouses\" or \"mice\"; both are heard." },
    "loc-vtec06": { e: "The internet went down right in the middle of my video call.", t: "El internet se cayó justo en medio de mi videollamada.", s: "Cuando hablas de la conexión a la red.", sEn: "When you talk about the connection to the network.", n: "El acento va al principio: \"ÍN-ter-net\".", nEn: "The stress is at the start: \"IN-ter-net\"." },
    "loc-vtec07": { e: "I'll send you the details by email this afternoon.", t: "Te enviaré los detalles por correo esta tarde.", s: "Cuando acuerdas mandar información escrita por internet.", sEn: "When you agree to send written information over the internet.", n: "\"Email\" se usa igual para el mensaje y para el sistema; suena \"Í-meil\".", nEn: "\"Email\" works for both the message and the system; it sounds like \"EE-mail\"." },
    "loc-vtec08": { e: "Don't forget to change your password every few months.", t: "No olvides cambiar tu contraseña cada pocos meses.", s: "Cuando hablas de la seguridad de tus cuentas en línea.", sEn: "When you talk about the security of your online accounts.", n: "Es palabra compuesta: \"pass\" + \"word\", se dice \"PÁS-uord\".", nEn: "It's a compound: \"pass\" + \"word\", said \"PASS-word\"." },
    "loc-vtec09": { e: "Please save the file before you close the program.", t: "Por favor guarda el archivo antes de cerrar el programa.", s: "Cuando trabajas con documentos en la computadora.", sEn: "When you work with documents on the computer.", n: "\"File\" rima con \"smile\"; se dice \"fáil\".", nEn: "\"File\" rhymes with \"smile\"; it's said \"fyle\"." },
    "loc-vtec10": { e: "I downloaded a new app to track my running.", t: "Descargué una aplicación nueva para registrar mis carreras.", s: "Cuando hablas de programas en el teléfono.", sEn: "When you talk about programs on your phone.", n: "\"App\" es la forma corta de \"application\"; es muy común en el habla diaria.", nEn: "\"App\" is the short form of \"application\"; it's very common in daily speech." },
    "loc-vtec11": { e: "I left my charger at home, so my phone is almost dead.", t: "Dejé mi cargador en casa, así que mi teléfono está casi descargado.", s: "Cuando necesitas energía para tu teléfono o aparato.", sEn: "When you need power for your phone or device.", n: "Viene de \"charge\" (cargar); se dice \"CHAR-yer\".", nEn: "It comes from \"charge\"; it's said \"CHAR-jer\"." },
    "loc-vtec12": { e: "The battery on this laptop only lasts about two hours.", t: "La batería de esta laptop solo dura unas dos horas.", s: "Cuando hablas de cuánto aguanta un aparato sin cargarse.", sEn: "When you talk about how long a device lasts without charging.", n: "Se dice \"BÁ-te-ri\", con tres sílabas, no \"ba-te-RÍ-a\".", nEn: "It's said \"BAT-ter-y\", three syllables, not \"ba-te-REE-a\"." },
    "loc-vtec13": { e: "The camera on this phone takes really sharp pictures.", t: "La cámara de este teléfono toma fotos muy nítidas.", s: "Cuando hablas de tomar fotos o grabar video.", sEn: "When you talk about taking photos or recording video.", n: "Se dice \"KÁ-me-ra\"; en inglés rápido suena casi como \"KÁ-mra\".", nEn: "It's said \"KAM-er-a\"; in fast English it sounds almost like \"KAM-ra\"." },
    "loc-vtec14": { e: "Turn up the speaker so we can all hear the song.", t: "Sube el altavoz para que todos podamos oír la canción.", s: "Cuando hablas del aparato que reproduce el sonido.", sEn: "When you talk about the device that plays the sound.", n: "\"Speaker\" también significa \"orador\"; el contexto aclara el sentido.", nEn: "\"Speaker\" also means a person who talks; context makes the meaning clear." },
    "loc-vtec15": { e: "I put on my headphones so I wouldn't bother anyone.", t: "Me puse los audífonos para no molestar a nadie.", s: "Cuando escuchas música o llamadas sin molestar a otros.", sEn: "When you listen to music or calls without disturbing others.", n: "Suele ir en plural: \"headphones\"; \"earphones\" es para los pequeños.", nEn: "It's usually plural: \"headphones\"; \"earphones\" are the small in-ear ones." },
    "loc-vtec16": { e: "The network is down, so I can't connect to the printer.", t: "La red está caída, así que no puedo conectarme a la impresora.", s: "Cuando hablas de equipos conectados entre sí.", sEn: "When you talk about devices connected to each other.", n: "Es compuesta: \"net\" + \"work\", se dice \"NÉT-uork\".", nEn: "It's a compound: \"net\" + \"work\", said \"NET-work\"." },
    "loc-vtec17": { e: "Press the green button to start the machine.", t: "Presiona el botón verde para encender la máquina.", s: "Cuando explicas cómo usar un aparato.", sEn: "When you explain how to use a device.", n: "Se dice \"BÁ-ton\"; la 'tt' suena suave, casi como una 'd' rápida.", nEn: "It's said \"BUT-ton\"; the 'tt' is soft, almost like a quick 'd'." },
    "loc-vtec18": { e: "All my photos are backed up in the cloud.", t: "Todas mis fotos están respaldadas en la nube.", s: "Cuando hablas de guardar archivos en internet, no en el aparato.", sEn: "When you talk about storing files online, not on the device.", n: "\"Cloud\" también significa \"nube\" del cielo; el contexto los separa.", nEn: "\"Cloud\" also means a cloud in the sky; context tells them apart." },
    "loc-vnat01": { e: "We sat under a big tree to escape the afternoon heat.", t: "Nos sentamos bajo un árbol grande para escapar del calor de la tarde.", s: "Cuando hablas de la vegetación en un parque o en el campo.", sEn: "When you talk about the plants in a park or in the countryside.", n: "\"Tree\" tiene la 'i' larga: \"tri\"; no la cortes como en \"trip\".", nEn: "\"Tree\" has a long 'ee': \"tree\"; don't shorten it like \"trip\"." },
    "loc-vnat02": { e: "She picked a flower and put it in her hair.", t: "Ella tomó una flor y se la puso en el cabello.", s: "Cuando hablas de plantas con pétalos en un jardín.", sEn: "When you talk about petaled plants in a garden.", n: "\"Flower\" suena igual que \"flour\" (harina); el contexto los distingue.", nEn: "\"Flower\" sounds the same as \"flour\" (for baking); context separates them." },
    "loc-vnat03": { e: "I water the plant every morning before work.", t: "Riego la planta cada mañana antes del trabajo.", s: "Cuando hablas de cuidar la vegetación en casa.", sEn: "When you talk about caring for greenery at home.", n: "\"Plant\" también es verbo: \"to plant\" (plantar/sembrar).", nEn: "\"Plant\" is also a verb: \"to plant\" (to put seeds in the ground)." },
    "loc-vnat04": { e: "A single yellow leaf fell onto the table.", t: "Una sola hoja amarilla cayó sobre la mesa.", s: "Cuando describes árboles o el otoño.", sEn: "When you describe trees or the fall season.", n: "El plural es irregular: \"leaf\" pasa a \"leaves\".", nEn: "The plural is irregular: \"leaf\" becomes \"leaves\"." },
    "loc-vnat05": { e: "We hiked all the way to the top of the mountain.", t: "Caminamos hasta la cima de la montaña.", s: "Cuando hablas de excursiones o paisajes altos.", sEn: "When you talk about hikes or high landscapes.", n: "Se dice \"MÁUN-tin\"; la segunda sílaba es muy débil, casi \"tn\".", nEn: "It's said \"MOUN-tin\"; the second syllable is very weak, almost \"tn\"." },
    "loc-vnat06": { e: "The kids love swimming in the river on hot days.", t: "A los niños les encanta nadar en el río en los días calurosos.", s: "Cuando hablas de un curso de agua que corre por el paisaje.", sEn: "When you talk about a flowing waterway across the landscape.", n: "Se dice \"RÍ-ver\"; la 'i' es corta, como en \"live\".", nEn: "It's said \"RIV-er\"; the 'i' is short, like in \"live\"." },
    "loc-vnat07": { e: "From the hotel window you can see the sea.", t: "Desde la ventana del hotel se puede ver el mar.", s: "Cuando describes una vista o un lugar junto al océano.", sEn: "When you describe a view or a place by the ocean.", n: "\"Sea\" (mar) suena igual que \"see\" (ver); el contexto los separa.", nEn: "\"Sea\" sounds the same as \"see\" (to look); context separates them." },
    "loc-vnat08": { e: "We spent the whole day at the beach building sandcastles.", t: "Pasamos todo el día en la playa haciendo castillos de arena.", s: "Cuando hablas de un día junto al mar.", sEn: "When you talk about a day by the sea.", n: "Se dice \"bich\" con 'i' larga; cuidado de no confundirlo con otra palabra corta.", nEn: "It's said \"beech\" with a long 'ee'; be careful not to confuse it with a short-vowel word." },
    "loc-vnat09": { e: "We rented a small boat to row across the lake.", t: "Rentamos un bote pequeño para remar por el lago.", s: "Cuando hablas de un cuerpo de agua tranquilo y cerrado.", sEn: "When you talk about a calm, enclosed body of water.", n: "\"Lake\" rima con \"cake\"; se dice \"léik\".", nEn: "\"Lake\" rhymes with \"cake\"; it's said \"layk\"." },
    "loc-vnat10": { e: "We got a little lost walking through the forest.", t: "Nos perdimos un poco caminando por el bosque.", s: "Cuando hablas de una zona grande con muchos árboles.", sEn: "When you talk about a large area with many trees.", n: "\"Forest\" es un bosque grande; \"woods\" es más pequeño y cercano.", nEn: "\"Forest\" is a large wood; \"woods\" is smaller and more local." },
    "loc-vnat11": { e: "Almost no rain falls in the desert all year.", t: "Casi no cae lluvia en el desierto en todo el año.", s: "Cuando hablas de una zona seca y árida.", sEn: "When you talk about a dry, arid area.", n: "\"Desert\" (desierto) lleva una sola s; \"dessert\" (postre) lleva doble s.", nEn: "\"Desert\" (the dry place) has one s; \"dessert\" (the sweet) has a double s." },
    "loc-vnat12": { e: "We took a boat to a tiny island off the coast.", t: "Tomamos un bote hacia una pequeña isla frente a la costa.", s: "Cuando hablas de un destino rodeado de agua.", sEn: "When you talk about a spot surrounded by water.", n: "La 's' de \"island\" es muda: se dice \"ÁI-land\".", nEn: "The 's' in \"island\" is silent: it's said \"EYE-land\"." },
    "loc-vnat13": { e: "There wasn't a single cloud in the sky today.", t: "Hoy no había ni una sola nube en el cielo.", s: "Cuando hablas del clima o de mirar hacia arriba.", sEn: "When you talk about the weather or looking up.", n: "\"Sky\" rima con \"my\"; se dice \"skai\".", nEn: "\"Sky\" rhymes with \"my\"; it's said \"sky\"." },
    "loc-vnat14": { e: "We lay on the grass and watched the first star appear.", t: "Nos acostamos en el pasto y vimos aparecer la primera estrella.", s: "Cuando hablas del cielo nocturno.", sEn: "When you talk about the night sky.", n: "\"Star\" sirve también para una celebridad: \"a movie star\".", nEn: "\"Star\" also means a celebrity: \"a movie star\"." },
    "loc-vnat15": { e: "The full moon was so bright we didn't need a flashlight.", t: "La luna llena estaba tan brillante que no necesitamos linterna.", s: "Cuando hablas del cielo de noche o del clima.", sEn: "When you talk about the night sky or the weather.", n: "\"Moon\" tiene la 'u' larga: \"mun\"; no la acortes.", nEn: "\"Moon\" has a long 'oo': \"moon\"; don't shorten it." },
    "loc-vnat16": { e: "He skipped a flat rock across the water.", t: "Él hizo rebotar una piedra plana sobre el agua.", s: "Cuando hablas de piedras en la naturaleza.", sEn: "When you talk about stones in nature.", n: "\"Rock\" también significa un género musical: \"rock music\".", nEn: "\"Rock\" also means a music genre: \"rock music\"." },
    "loc-vnat17": { e: "The sand was so hot we had to run to the water.", t: "La arena estaba tan caliente que tuvimos que correr al agua.", s: "Cuando hablas de la playa o del desierto.", sEn: "When you talk about the beach or the desert.", n: "\"Sand\" es incontable: no se dice \"sands\" para hablar de la arena.", nEn: "\"Sand\" is uncountable: you don't say \"sands\" to talk about it." },
    "loc-vnat18": { e: "Please don't walk on the grass; it was just planted.", t: "Por favor no pises el pasto; lo acaban de sembrar.", s: "Cuando hablas del césped en un parque o jardín.", sEn: "When you talk about the lawn in a park or garden.", n: "\"Grass\" es incontable; para un trozo se dice \"a blade of grass\".", nEn: "\"Grass\" is uncountable; for one piece you say \"a blade of grass\"." },
    "loc-vemo01": { e: "I'm so happy you could make it to the party.", t: "Estoy muy feliz de que hayas podido venir a la fiesta.", s: "Cuando expresas alegría por algo bueno.", sEn: "When you express joy about something good.", n: "Se dice \"JÁ-pi\"; la 'h' inicial sí se pronuncia, con aire suave.", nEn: "It's said \"HAP-py\"; the initial 'h' is pronounced, with a soft breath." },
    "loc-vemo02": { e: "She felt sad after saying goodbye to her friends.", t: "Ella se sintió triste después de despedirse de sus amigos.", s: "Cuando hablas de un sentimiento de tristeza.", sEn: "When you talk about a feeling of sadness.", n: "\"Sad\" tiene la 'a' abierta, como en \"cat\".", nEn: "\"Sad\" has an open 'a', like in \"cat\"." },
    "loc-vemo03": { e: "He got angry when the bus left without him.", t: "Se puso enojado cuando el autobús se fue sin él.", s: "Cuando hablas de molestia o enojo.", sEn: "When you talk about annoyance or anger.", n: "Para enojo fuerte se usa \"mad\" en EE. UU.; \"angry\" es más universal.", nEn: "For strong anger \"mad\" is common in the US; \"angry\" is more universal." },
    "loc-vemo04": { e: "The dog was scared of the loud fireworks.", t: "El perro estaba asustado por los fuegos artificiales tan ruidosos.", s: "Cuando hablas de miedo o susto.", sEn: "When you talk about fear or fright.", n: "\"Scared of\" lleva la preposición \"of\": \"scared of dogs\".", nEn: "\"Scared of\" takes the preposition \"of\": \"scared of dogs\"." },
    "loc-vemo05": { e: "I'm too tired to cook, so let's order something.", t: "Estoy demasiado cansado para cocinar, así que pidamos algo.", s: "Cuando hablas de falta de energía o sueño.", sEn: "When you talk about lack of energy or sleepiness.", n: "Se dice \"TÁI-erd\", dos sílabas; no añadas una 'd' fuerte al final.", nEn: "It's said \"TY-erd\", two syllables; don't add a hard 'd' at the end." },
    "loc-vemo06": { e: "The kids got bored waiting for the train.", t: "Los niños se aburrieron esperando el tren.", s: "Cuando hablas de falta de interés o entretenimiento.", sEn: "When you talk about lack of interest or entertainment.", n: "\"I'm bored\" significa que tú te aburres; \"boring\" describe algo aburrido.", nEn: "\"I'm bored\" means you feel it; \"boring\" describes the dull thing itself." },
    "loc-vemo07": { e: "We're so excited about the trip next week.", t: "Estamos muy emocionados por el viaje de la próxima semana.", s: "Cuando esperas algo con muchas ganas.", sEn: "When you're really looking forward to something.", n: "El acento va en medio: \"ek-SÁI-ted\".", nEn: "The stress is in the middle: \"ek-SY-ted\"." },
    "loc-vemo08": { e: "I always feel nervous before speaking in public.", t: "Siempre me siento nervioso antes de hablar en público.", s: "Cuando hablas de ansiedad antes de algo importante.", sEn: "When you talk about anxiety before something important.", n: "\"Nervous\" no significa \"de los nervios\" como en español; es más bien ansioso.", nEn: "\"Nervous\" doesn't mean \"irritable\" like in Spanish; it's more like anxious." },
    "loc-vemo09": { e: "Try to stay calm and breathe slowly.", t: "Trata de mantenerte tranquilo y respira despacio.", s: "Cuando calmas a alguien o describes un estado relajado.", sEn: "When you calm someone down or describe a relaxed state.", n: "La 'l' de \"calm\" es muda: se dice \"kam\".", nEn: "The 'l' in \"calm\" is silent: it's said \"kahm\"." },
    "loc-vemo10": { e: "I was really surprised to see you here.", t: "Me sorprendió mucho verte aquí.", s: "Cuando algo inesperado te impacta.", sEn: "When something unexpected hits you.", n: "Se dice \"sor-PRÁISD\"; \"surprised\" describe a la persona, \"surprising\" a la cosa.", nEn: "It's said \"sur-PRYZD\"; \"surprised\" describes the person, \"surprising\" the thing." },
    "loc-vemo11": { e: "Her parents are very proud of her.", t: "Sus padres están muy orgullosos de ella.", s: "Cuando expresas satisfacción por un logro.", sEn: "When you express satisfaction about an achievement.", n: "\"Proud of\" lleva \"of\": \"proud of you\".", nEn: "\"Proud of\" takes \"of\": \"proud of you\"." },
    "loc-vemo12": { e: "He gets jealous when she talks to other people.", t: "Él se pone celoso cuando ella habla con otras personas.", s: "Cuando hablas de celos en relaciones o amistades.", sEn: "When you talk about jealousy in relationships or friendships.", n: "Se dice \"YÉ-los\"; la 'j' suena suave, no como la 'j' española.", nEn: "It's said \"JEL-us\"; the 'j' is soft, not like the Spanish 'j'." },
    "loc-vemo13": { e: "I'm a little worried about the exam tomorrow.", t: "Estoy un poco preocupado por el examen de mañana.", s: "Cuando algo te causa inquietud o preocupación.", sEn: "When something makes you anxious or concerned.", n: "Se dice \"UÓ-rid\"; \"worried about\" lleva \"about\".", nEn: "It's said \"WUR-eed\"; \"worried about\" takes \"about\"." },
    "loc-vemo14": { e: "She felt lonely after moving to a new city.", t: "Ella se sintió sola después de mudarse a una ciudad nueva.", s: "Cuando hablas de soledad emocional, no solo de estar solo.", sEn: "When you talk about emotional loneliness, not just being alone.", n: "\"Lonely\" es sentirse solo; \"alone\" es solo estar sin compañía.", nEn: "\"Lonely\" is feeling sad and alone; \"alone\" is just being by yourself." },
    "loc-vemo15": { e: "I'm really grateful for all your help.", t: "Estoy muy agradecido por toda tu ayuda.", s: "Cuando expresas agradecimiento sincero.", sEn: "When you express sincere thanks.", n: "Se dice \"GRÉIT-ful\"; \"grateful for\" lleva \"for\".", nEn: "It's said \"GRATE-ful\"; \"grateful for\" takes \"for\"." },
    "loc-vemo16": { e: "I'm a bit confused about which form to fill out.", t: "Estoy un poco confundido sobre qué formulario llenar.", s: "Cuando no entiendes algo o algo no está claro.", sEn: "When you don't understand something or it isn't clear.", n: "\"Confused\" describe a la persona; \"confusing\" describe lo que confunde.", nEn: "\"Confused\" describes the person; \"confusing\" describes the thing that puzzles you." },
    "loc-vesc01": { e: "I left my book at home, so can I share with you?", t: "Dejé mi libro en casa, ¿puedo compartir contigo?", s: "En clase cuando hablas de los materiales de lectura.", sEn: "In class when you talk about reading materials.", n: "\"Book\" lleva una 'u' corta, como en 'put'; no la alargues a 'búuk'.", nEn: "\"Book\" has a short 'u' like in 'put'; don't stretch it into 'boook'." },
    "loc-vesc02": { e: "Write the new words in your notebook so you don't forget them.", t: "Escribe las palabras nuevas en tu cuaderno para que no se te olviden.", s: "Cuando la maestra te pide tomar apuntes.", sEn: "When the teacher asks you to take notes.", n: "\"Notebook\" es cuaderno; el aparato es \"laptop\", no \"notebook\".", nEn: "\"Notebook\" is the paper one; the device is a \"laptop\", not a \"notebook\"." },
    "loc-vesc03": { e: "Can I borrow a pencil? Mine just broke.", t: "¿Me prestas un lápiz? El mío se acaba de romper.", s: "Cuando necesitas algo para escribir y no traes.", sEn: "When you need something to write with and have none.", n: "La 'c' de \"pencil\" suena como una 's': PÉN-sil.", nEn: "The 'c' in \"pencil\" sounds like an 's': PEN-sil." },
    "loc-vesc04": { e: "This pen ran out of ink in the middle of the exam.", t: "A este bolígrafo se le acabó la tinta a mitad del examen.", s: "Cuando escribes algo importante y se acaba la tinta.", sEn: "When you're writing something important and the ink runs out.", n: "\"Pen\" (bolígrafo) y \"pan\" (sartén) suenan distinto; cuida la vocal.", nEn: "\"Pen\" and \"pan\" sound different; watch the vowel." },
    "loc-vesc05": { e: "Use the eraser at the end of your pencil to fix that mistake.", t: "Usa el borrador al final de tu lápiz para corregir ese error.", s: "Cuando te equivocas y necesitas borrar.", sEn: "When you make a mistake and need to erase.", n: "En EE. UU. es \"eraser\"; en el Reino Unido dicen \"rubber\".", nEn: "In the US it's \"eraser\"; in the UK they say \"rubber\"." },
    "loc-vesc06": { e: "Draw a straight line with a ruler, not freehand.", t: "Traza una línea recta con una regla, no a mano alzada.", s: "En clase de matemáticas o dibujo, al medir o trazar.", sEn: "In math or art class, when measuring or drawing.", n: "\"Ruler\" también significa gobernante; el contexto aclara el sentido.", nEn: "\"Ruler\" also means a leader; context makes the meaning clear." },
    "loc-vesc07": { e: "My backpack is so heavy with all these books.", t: "Mi mochila pesa muchísimo con todos estos libros.", s: "Cuando cargas tus útiles camino a la escuela.", sEn: "When you carry your supplies on the way to school.", n: "Una sola palabra: \"backpack\", con el acento en \"back\".", nEn: "It's one word, \"backpack\", stressed on \"back\"." },
    "loc-vesc08": { e: "The teacher wrote the homework on the board.", t: "La maestra escribió la tarea en la pizarra.", s: "Cuando miras al frente del aula para copiar algo.", sEn: "When you look to the front of the room to copy something.", n: "También se dice \"whiteboard\" o \"blackboard\" según el tipo.", nEn: "You can also say \"whiteboard\" or \"blackboard\" depending on the type." },
    "loc-vesc09": { e: "I have a lot of homework to finish tonight.", t: "Tengo mucha tarea que terminar esta noche.", s: "Cuando hablas de lo que debes hacer en casa.", sEn: "When you talk about what you have to do at home.", n: "\"Homework\" es incontable: no se dice \"homeworks\".", nEn: "\"Homework\" is uncountable: never say \"homeworks\"." },
    "loc-vesc10": { e: "We have a math test on Friday, so I need to study.", t: "Tenemos un examen de matemáticas el viernes, así que necesito estudiar.", s: "Cuando hablas de una evaluación próxima.", sEn: "When you talk about an upcoming evaluation.", n: "\"Test\" es más corto y común que \"exam\" en la escuela.", nEn: "\"Test\" is shorter and more common than \"exam\" at school." },
    "loc-vesc11": { e: "My favorite class is English, right after lunch.", t: "Mi clase favorita es inglés, justo después del almuerzo.", s: "Cuando hablas de tu horario escolar.", sEn: "When you talk about your school schedule.", n: "La 'a' de \"class\" es abierta; no la conviertas en \"e\".", nEn: "The 'a' in \"class\" is open; don't turn it into an \"e\"." },
    "loc-vesc12": { e: "The teacher explained it again because we didn't understand.", t: "El maestro lo explicó otra vez porque no entendimos.", s: "Cuando hablas de quien dirige la clase.", sEn: "When you talk about the person who leads the class.", n: "\"Teacher\" sirve para maestro y maestra; el inglés no marca género.", nEn: "\"Teacher\" works for both genders; English doesn't mark it." },
    "loc-vesc13": { e: "She's a hardworking student who always does her homework.", t: "Ella es una alumna aplicada que siempre hace su tarea.", s: "Cuando hablas de alguien que estudia en una escuela.", sEn: "When you talk about someone who studies at a school.", n: "\"Student\" vale para alumno de cualquier nivel, incluso la universidad.", nEn: "\"Student\" works for any level, even at university." },
    "loc-vesc14": { e: "Does anyone have a question before the test?", t: "¿Alguien tiene una pregunta antes del examen?", s: "Cuando la maestra invita a participar en clase.", sEn: "When the teacher invites the class to participate.", n: "La 'qu' suena 'kw' y la 'ti' suena 'ch': KUÉS-chon.", nEn: "The 'qu' sounds like 'kw' and 'ti' like 'ch': KWES-chun." },
    "loc-vesc15": { e: "I knew the answer but I was too shy to raise my hand.", t: "Sabía la respuesta pero me dio pena levantar la mano.", s: "Cuando respondes a una pregunta en clase.", sEn: "When responding to a question in class.", n: "La 'w' de \"answer\" es muda: se dice ÁN-ser.", nEn: "The 'w' in \"answer\" is silent: say AN-ser." },
    "loc-vesc16": { e: "I got a good grade on my history project.", t: "Saqué una buena nota en mi proyecto de historia.", s: "Cuando te entregan los resultados de un examen.", sEn: "When you get your test results back.", n: "\"Grade\" es la nota; también significa el año escolar (grado).", nEn: "\"Grade\" is the mark; it also means the school year (grade level)." },
    "loc-vdep01": { e: "We play soccer in the park every Sunday morning.", t: "Jugamos fútbol en el parque todos los domingos por la mañana.", s: "Cuando hablas del deporte más popular en LatAm.", sEn: "When you talk about the most popular sport in Latin America.", n: "En EE. UU. es \"soccer\"; \"football\" allá es el fútbol americano.", nEn: "In the US it's \"soccer\"; \"football\" there means American football." },
    "loc-vdep02": { e: "He's really tall, so he's great at basketball.", t: "Es muy alto, así que es buenísimo en el baloncesto.", s: "Cuando hablas de un deporte de canasta y equipos.", sEn: "When you talk about a hoop-and-team sport.", n: "Una sola palabra: \"basketball\", acento en \"bas\".", nEn: "One word, \"basketball\", stressed on \"bas\"." },
    "loc-vdep03": { e: "Do you want to play tennis this weekend?", t: "¿Quieres jugar tenis este fin de semana?", s: "Cuando invitas a alguien a un deporte de raqueta.", sEn: "When you invite someone to a racket sport.", n: "Casi igual al español; el acento va en la primera sílaba: TÉ-nis.", nEn: "Almost like Spanish; stress the first syllable: TE-nis." },
    "loc-vdep04": { e: "My brother plays baseball for his school team.", t: "Mi hermano juega béisbol para el equipo de su escuela.", s: "Cuando hablas del deporte del bate y la pelota.", sEn: "When you talk about the bat-and-ball sport.", n: "Una palabra: \"baseball\"; \"base\" suena \"béis\".", nEn: "One word, \"baseball\"; \"base\" sounds like \"bayss\"." },
    "loc-vdep05": { e: "Swimming is the best exercise for your whole body.", t: "La natación es el mejor ejercicio para todo el cuerpo.", s: "Cuando hablas de hacer ejercicio en la piscina.", sEn: "When you talk about exercising in the pool.", n: "Viene de \"to swim\"; la doble 'm' mantiene la 'i' corta.", nEn: "It comes from \"to swim\"; the double 'm' keeps the 'i' short." },
    "loc-vdep06": { e: "I go running every morning before work.", t: "Salgo a correr todas las mañanas antes del trabajo.", s: "Cuando hablas de tu rutina de ejercicio.", sEn: "When you talk about your exercise routine.", n: "Para un evento se dice \"a run\"; la actividad es \"running\".", nEn: "An event is \"a run\"; the activity is \"running\"." },
    "loc-vdep07": { e: "Cycling is a fun way to get around the city.", t: "El ciclismo es una manera divertida de moverse por la ciudad.", s: "Cuando hablas de andar en bicicleta como deporte.", sEn: "When you talk about riding a bike as a sport.", n: "La 'cy' suena como 'sai': SÁI-kling.", nEn: "The 'cy' sounds like 'sigh': SY-kling." },
    "loc-vdep08": { e: "He trains in boxing three times a week.", t: "Entrena boxeo tres veces por semana.", s: "Cuando hablas del deporte de los guantes.", sEn: "When you talk about the sport with gloves.", n: "Viene de \"to box\" (boxear); el sustantivo es \"boxing\".", nEn: "It comes from \"to box\"; the noun is \"boxing\"." },
    "loc-vdep09": { e: "We played volleyball on the beach all afternoon.", t: "Jugamos voleibol en la playa toda la tarde.", s: "Cuando hablas de un deporte de red y manos.", sEn: "When you talk about a net-and-hands sport.", n: "Una palabra: \"volleyball\", con doble 'l'.", nEn: "One word, \"volleyball\", with a double 'l'." },
    "loc-vdep10": { e: "My grandfather plays golf every Saturday.", t: "Mi abuelo juega golf todos los sábados.", s: "Cuando hablas del deporte de los hoyos y palos.", sEn: "When you talk about the sport with holes and clubs.", n: "Igual que en español, pero la 'l' se pronuncia clara: golf.", nEn: "Like in Spanish, but pronounce the 'l' clearly: golf." },
    "loc-vdep11": { e: "Pass me the ball, I'm open!", t: "¡Pásame la pelota, estoy libre!", s: "Cuando juegas y pides el balón a un compañero.", sEn: "When you're playing and ask a teammate for the ball.", n: "\"Ball\" y \"bowl\" (tazón) suenan parecido; la 'a' es más abierta.", nEn: "\"Ball\" and \"bowl\" sound similar; \"ball\" has a more open vowel." },
    "loc-vdep12": { e: "Our team won the championship last year.", t: "Nuestro equipo ganó el campeonato el año pasado.", s: "Cuando hablas del grupo que juega junto.", sEn: "When you talk about the group that plays together.", n: "\"Team\" es equipo deportivo; en la oficina también vale \"team\".", nEn: "\"Team\" is a sports team; at the office \"team\" works too." },
    "loc-vdep13": { e: "He's the best player on the whole team.", t: "Es el mejor jugador de todo el equipo.", s: "Cuando hablas de quien juega un deporte.", sEn: "When you talk about someone who plays a sport.", n: "Viene de \"to play\"; sirve para jugador y para músico.", nEn: "It comes from \"to play\"; it works for an athlete and a musician." },
    "loc-vdep14": { e: "The game starts at eight, so don't be late.", t: "El partido empieza a las ocho, así que no llegues tarde.", s: "Cuando hablas de un encuentro deportivo.", sEn: "When you talk about a sporting match.", n: "\"Game\" es el partido; \"match\" también se usa, sobre todo en tenis.", nEn: "\"Game\" is the match; \"match\" is also used, especially in tennis." },
    "loc-vdep15": { e: "If we score one more goal, we'll win the game.", t: "Si anotamos un gol más, ganaremos el partido.", s: "Cuando hablas del resultado deseado de un partido.", sEn: "When you talk about the desired result of a match.", n: "\"To win\" (ganar) no lleva objeto de dinero; ganar dinero es \"to earn\".", nEn: "\"To win\" is for games; earning money is \"to earn\"." },
    "loc-vdep16": { e: "Nobody likes to lose, but it's part of the game.", t: "A nadie le gusta perder, pero es parte del juego.", s: "Cuando hablas del resultado negativo de un partido.", sEn: "When you talk about the negative result of a match.", n: "\"Lose\" (perder) lleva una 's'; \"loose\" (suelto) lleva dos.", nEn: "\"Lose\" (the verb) has one 's'; \"loose\" (not tight) has two." },
    "loc-vsal01": { e: "I have a sharp pain in my lower back.", t: "Tengo un dolor agudo en la parte baja de la espalda.", s: "Cuando describes una molestia al doctor.", sEn: "When you describe a discomfort to the doctor.", n: "\"Pain\" es dolor físico; \"ache\" es un dolor sordo y constante.", nEn: "\"Pain\" is sharp; \"ache\" is a dull, ongoing one." },
    "loc-vsal02": { e: "She has a high fever, so she should stay in bed.", t: "Tiene fiebre alta, así que debería quedarse en cama.", s: "Cuando alguien está enfermo y tiene temperatura.", sEn: "When someone is sick and has a temperature.", n: "\"Fever\" lleva la 'v' suave; no la conviertas en 'b'.", nEn: "\"Fever\" has a soft 'v'; don't turn it into a 'b'." },
    "loc-vsal03": { e: "I can't stop coughing, I think I caught a cold.", t: "No puedo dejar de toser, creo que agarré un resfriado.", s: "Cuando tienes los síntomas de una gripe.", sEn: "When you have cold symptoms.", n: "\"Cough\" se pronuncia 'kof'; la 'gh' suena como 'f'.", nEn: "\"Cough\" is said 'kof'; the 'gh' sounds like 'f'." },
    "loc-vsal04": { e: "Half the office is out with the flu this week.", t: "Media oficina está ausente con gripe esta semana.", s: "Cuando hablas de una enfermedad viral común.", sEn: "When you talk about a common viral illness.", n: "\"Flu\" es la forma corta de \"influenza\".", nEn: "\"Flu\" is short for \"influenza\"." },
    "loc-vsal05": { e: "Take this medicine twice a day after meals.", t: "Toma esta medicina dos veces al día después de comer.", s: "Cuando el doctor te da indicaciones de tratamiento.", sEn: "When the doctor gives you treatment instructions.", n: "\"Medicine\" suele decirse en dos sílabas: MED-sin.", nEn: "\"Medicine\" is often said in two syllables: MED-sin." },
    "loc-vsal06": { e: "Don't forget to take your pill before breakfast.", t: "No olvides tomar tu pastilla antes del desayuno.", s: "Cuando hablas de un medicamento sólido.", sEn: "When you talk about a solid medication.", n: "\"Pill\" lleva 'i' corta; no suene como \"peel\" (pelar).", nEn: "\"Pill\" has a short 'i'; don't make it sound like \"peel\"." },
    "loc-vsal07": { e: "You should see a doctor if the pain doesn't go away.", t: "Deberías ver a un doctor si el dolor no se quita.", s: "Cuando recomiendas atención médica a alguien.", sEn: "When you recommend medical care to someone.", n: "\"Doctor\" se escribe igual pero la 'o' final suena floja.", nEn: "\"Doctor\" is spelled the same but the final 'o' is weak." },
    "loc-vsal08": { e: "They took him to the hospital after the accident.", t: "Lo llevaron al hospital después del accidente.", s: "Cuando hablas de una emergencia médica.", sEn: "When you talk about a medical emergency.", n: "La 'h' de \"hospital\" sí se pronuncia, suave: JÓS-pi-tal.", nEn: "The 'h' in \"hospital\" is pronounced, softly." },
    "loc-vsal09": { e: "There's a little blood, but the cut isn't deep.", t: "Hay un poco de sangre, pero el corte no es profundo.", s: "Cuando describes una herida pequeña.", sEn: "When you describe a small injury.", n: "\"Blood\" se pronuncia 'blad', con 'a' corta, no 'blud'.", nEn: "\"Blood\" has a short vowel like in 'flood'; for Spanish speakers it sounds closest to 'blad', not 'blud'." },
    "loc-vsal10": { e: "Clean the wound before you put on a bandage.", t: "Limpia la herida antes de poner una venda.", s: "Cuando hablas de cuidar una lesión.", sEn: "When you talk about caring for an injury.", n: "\"Wound\" (herida) se dice 'uund'; la 'w' inicial es como 'u'.", nEn: "\"Wound\" (injury) is said 'woond'; mind the long vowel." },
    "loc-vsal11": { e: "The nurse put a bandage on my knee.", t: "La enfermera me puso una venda en la rodilla.", s: "Cuando cubres una herida para protegerla.", sEn: "When you cover a wound to protect it.", n: "Una tirita pequeña es \"Band-Aid\"; la venda larga es \"bandage\".", nEn: "A small adhesive strip is a \"Band-Aid\"; the long wrap is a \"bandage\"." },
    "loc-vsal12": { e: "I've got a bad cold, so I'm staying home today.", t: "Tengo un resfriado fuerte, así que me quedo en casa hoy.", s: "Cuando tienes nariz tapada y estornudos.", sEn: "When you have a stuffy nose and sneezing.", n: "\"Cold\" es resfriado y también frío; el artículo \"a\" indica enfermedad.", nEn: "\"Cold\" means both a cold and cold weather; \"a cold\" signals the illness." },
    "loc-vsal13": { e: "I have an allergy to peanuts, so I can't eat those.", t: "Tengo alergia al maní, así que no puedo comer eso.", s: "Cuando avisas de algo que no puedes consumir.", sEn: "When you warn about something you can't consume.", n: "\"Allergy\" acentúa la primera sílaba: Á-ler-yi.", nEn: "\"Allergy\" is stressed on the first syllable: A-ler-gy." },
    "loc-vsal14": { e: "The doctor said I just need some rest.", t: "El doctor dijo que solo necesito descanso.", s: "Cuando hablas de recuperarte de una enfermedad.", sEn: "When you talk about recovering from an illness.", n: "\"Rest\" es descanso y también el resto; el contexto aclara.", nEn: "\"Rest\" means a break and also \"the remainder\"; context tells which." },
    "loc-vsal15": { e: "Eating well is good for your health.", t: "Comer bien es bueno para la salud.", s: "Cuando hablas del bienestar en general.", sEn: "When you talk about wellbeing in general.", n: "\"Health\" termina con sonido 'th'; saca un poco la lengua.", nEn: "\"Health\" ends with a 'th' sound; let the tongue peek out." },
    "loc-vsal16": { e: "I have a doctor's appointment at three o'clock.", t: "Tengo una cita con el doctor a las tres.", s: "Cuando agendas una visita médica.", sEn: "When you schedule a medical visit.", n: "Para el médico es \"appointment\"; una cita romántica es \"a date\".", nEn: "For the doctor it's an \"appointment\"; a romantic one is \"a date\"." },
    "loc-vofi01": { e: "There are too many papers on my desk.", t: "Hay demasiados papeles en mi escritorio.", s: "Cuando hablas de tu lugar de trabajo en la oficina.", sEn: "When you talk about your workspace in the office.", n: "\"Desk\" es el mueble; el ordenador de mesa es \"desktop\".", nEn: "\"Desk\" is the furniture; a desktop is the computer." },
    "loc-vofi02": { e: "This chair isn't very comfortable for long meetings.", t: "Esta silla no es muy cómoda para reuniones largas.", s: "Cuando hablas del mobiliario de oficina.", sEn: "When you talk about office furniture.", n: "\"Chair\" empieza con sonido 'ch', como en \"chico\".", nEn: "\"Chair\" starts with a 'ch' sound, like \"church\"." },
    "loc-vofi03": { e: "Can you hand me that sheet of paper?", t: "¿Me pasas esa hoja de papel?", s: "Cuando pides material para escribir o imprimir.", sEn: "When you ask for material to write or print on.", n: "\"Paper\" es incontable; una hoja es \"a sheet of paper\".", nEn: "\"Paper\" is uncountable; one is \"a sheet of paper\"." },
    "loc-vofi04": { e: "We have a meeting at nine to discuss the project.", t: "Tenemos una reunión a las nueve para hablar del proyecto.", s: "Cuando hablas de juntarte con colegas a tratar temas.", sEn: "When you talk about getting together with coworkers to discuss things.", n: "\"Meeting\" lleva 'i' larga: MÍ-ting, no \"miting\" corto.", nEn: "\"Meeting\" has a long 'ee': MEE-ting." },
    "loc-vofi05": { e: "I need to ask my boss before I can confirm that.", t: "Necesito preguntarle a mi jefe antes de poder confirmar eso.", s: "Cuando hablas de quien dirige tu trabajo.", sEn: "When you talk about the person who runs your work.", n: "\"Boss\" lleva 'o' abierta; no la cierres como en español.", nEn: "\"Boss\" has an open 'o'; keep it relaxed." },
    "loc-vofi06": { e: "My coworker helped me finish the report on time.", t: "Mi colega me ayudó a terminar el informe a tiempo.", s: "Cuando hablas de alguien con quien trabajas.", sEn: "When you talk about someone you work with.", n: "También se escribe \"co-worker\"; significan lo mismo.", nEn: "It's also spelled \"co-worker\"; same meaning." },
    "loc-vofi07": { e: "I'll send you the report by the end of the day.", t: "Te envío el informe al final del día.", s: "Cuando hablas de un documento de trabajo.", sEn: "When you talk about a work document.", n: "El verbo \"to report\" acentúa atrás: ri-PÓRT.", nEn: "The verb \"to report\" stresses the second syllable: ri-PORT." },
    "loc-vofi08": { e: "We're working on a big project this month.", t: "Estamos trabajando en un proyecto grande este mes.", s: "Cuando hablas de un trabajo planificado y con metas.", sEn: "When you talk about a planned piece of work with goals.", n: "El sustantivo acentúa delante: PRÓ-yekt; el verbo, atrás: pro-YÉKT.", nEn: "The noun stresses the front: PRO-ject; the verb, the back: pro-JECT." },
    "loc-vofi09": { e: "The deadline for the report is Friday at noon.", t: "La fecha límite del informe es el viernes al mediodía.", s: "Cuando hablas del último día para entregar algo.", sEn: "When you talk about the last day to deliver something.", n: "Una palabra: \"deadline\"; \"dead\" suena 'ded'.", nEn: "One word, \"deadline\"; \"dead\" sounds like 'ded'." },
    "loc-vofi10": { e: "The client wants to see the new design tomorrow.", t: "El cliente quiere ver el nuevo diseño mañana.", s: "Cuando hablas de a quién le prestas un servicio.", sEn: "When you talk about who you provide a service to.", n: "\"Client\" lleva 'ai' al inicio: KLÁI-ent.", nEn: "\"Client\" starts with an 'eye' sound: CLY-ent." },
    "loc-vofi11": { e: "Please read the contract before you sign it.", t: "Por favor lee el contrato antes de firmarlo.", s: "Cuando hablas de un acuerdo formal por escrito.", sEn: "When you talk about a formal written agreement.", n: "El sustantivo acentúa delante: KÓN-trakt.", nEn: "The noun stresses the front: CON-tract." },
    "loc-vofi12": { e: "Let me check my schedule and get back to you.", t: "Déjame revisar mi horario y te aviso.", s: "Cuando coordinas tiempos o citas.", sEn: "When you coordinate times or appointments.", n: "En EE. UU. se dice SKÉ-yul; en el Reino Unido, SHÉ-yul.", nEn: "In the US it's SKE-jool; in the UK, SHE-jool." },
    "loc-vofi13": { e: "She got a raise, so her salary went up this year.", t: "Le dieron un aumento, así que su sueldo subió este año.", s: "Cuando hablas de cuánto ganas por tu trabajo.", sEn: "When you talk about how much you earn from your job.", n: "\"Salary\" es el sueldo fijo; el pago por hora es \"wage\".", nEn: "\"Salary\" is fixed pay; hourly pay is a \"wage\"." },
    "loc-vofi14": { e: "The printer is out of ink again.", t: "La impresora se quedó otra vez sin tinta.", s: "Cuando hablas del equipo para imprimir documentos.", sEn: "When you talk about the machine for printing documents.", n: "Viene de \"to print\"; el que imprime es el \"printer\".", nEn: "It comes from \"to print\"; the machine is the \"printer\"." },
    "loc-vofi15": { e: "Put those documents in the blue folder.", t: "Pon esos documentos en la carpeta azul.", s: "Cuando organizas papeles o archivos.", sEn: "When you organize papers or files.", n: "\"Folder\" sirve para la carpeta física y la del computador.", nEn: "\"Folder\" works for both a physical and a computer folder." },
    "loc-vofi16": { e: "I'll send you an email with all the details.", t: "Te mando un correo con todos los detalles.", s: "Cuando hablas de comunicación escrita en el trabajo.", sEn: "When you talk about written communication at work.", n: "\"Email\" se usa como sustantivo y como verbo: \"to email someone\".", nEn: "\"Email\" works as both a noun and a verb: \"to email someone\"." },
    "loc-vdin01": { e: "I don't have enough money to buy it right now.", t: "No tengo suficiente dinero para comprarlo ahora.", s: "Cuando hablas de cuánto puedes gastar.", sEn: "When you talk about how much you can spend.", n: "\"Money\" es incontable: no se dice \"moneys\".", nEn: "\"Money\" is uncountable: never say \"moneys\"." },
    "loc-vdin02": { e: "What's the price of this jacket?", t: "¿Cuál es el precio de esta chaqueta?", s: "Cuando preguntas cuánto cuesta algo en una tienda.", sEn: "When you ask how much something costs in a store.", n: "\"Price\" lleva 'ai': práis, no \"pris\".", nEn: "\"Price\" has an 'eye' sound: pryce." },
    "loc-vdin03": { e: "This restaurant is too expensive for me.", t: "Este restaurante es demasiado caro para mí.", s: "Cuando algo cuesta más de lo que quieres pagar.", sEn: "When something costs more than you want to pay.", n: "\"Expensive\" es caro; \"cheap\" es barato. No los confundas.", nEn: "\"Expensive\" is costly; \"cheap\" is the opposite." },
    "loc-vdin04": { e: "These shoes were really cheap, only ten dollars.", t: "Estos zapatos estaban bien baratos, solo diez dólares.", s: "Cuando algo cuesta poco dinero.", sEn: "When something costs little money.", n: "\"Cheap\" lleva 'i' larga: chip, no \"chep\".", nEn: "\"Cheap\" has a long 'ee': cheep." },
    "loc-vdin05": { e: "Is there any discount if I pay in cash?", t: "¿Hay algún descuento si pago en efectivo?", s: "Cuando pides una rebaja en el precio.", sEn: "When you ask for a reduction in price.", n: "El sustantivo acentúa delante: DÍS-kaunt.", nEn: "The noun stresses the front: DIS-count." },
    "loc-vdin06": { e: "These jeans are on sale this week.", t: "Estos jeans están en oferta esta semana.", s: "Cuando una tienda baja los precios por un tiempo.", sEn: "When a store lowers prices for a while.", n: "\"On sale\" es en oferta; \"for sale\" es a la venta.", nEn: "\"On sale\" means discounted; \"for sale\" means available to buy." },
    "loc-vdin07": { e: "Can I pay with a card or do you only take cash?", t: "¿Puedo pagar con tarjeta o solo aceptan efectivo?", s: "Cuando pagas en una caja registradora.", sEn: "When you pay at a checkout.", n: "Para pagar es \"card\" o \"credit card\"; \"card\" también es tarjeta de felicitación.", nEn: "For paying it's \"card\" or \"credit card\"; \"card\" can also mean a greeting card." },
    "loc-vdin08": { e: "I'd rather pay in cash than use my card.", t: "Prefiero pagar en efectivo que usar mi tarjeta.", s: "Cuando hablas de dinero físico, billetes y monedas.", sEn: "When you talk about physical money, bills and coins.", n: "\"Cash\" es incontable; no se dice \"cashes\".", nEn: "\"Cash\" is uncountable: never say \"cashes\"." },
    "loc-vdin09": { e: "Here's your change, thank you for shopping with us.", t: "Aquí tiene su cambio, gracias por comprar con nosotros.", s: "Cuando el cajero te devuelve dinero.", sEn: "When the cashier gives you money back.", n: "\"Change\" es el cambio (vuelto) y también cambiar (verbo).", nEn: "\"Change\" means the money back and also \"to change\"." },
    "loc-vdin10": { e: "Keep the receipt in case you want to return it.", t: "Guarda el recibo por si quieres devolverlo.", s: "Cuando te dan el comprobante de una compra.", sEn: "When you get proof of a purchase.", n: "La 'p' de \"receipt\" es muda: se dice ri-SÍT.", nEn: "The 'p' in \"receipt\" is silent: say ri-SEET." },
    "loc-vdin11": { e: "Can we split the bill, please?", t: "¿Podemos dividir la cuenta, por favor?", s: "Cuando pides lo que debes pagar en un restaurante.", sEn: "When you ask for what you owe at a restaurant.", n: "En EE. UU. la cuenta del restaurante suele ser \"the check\".", nEn: "In the US the restaurant total is often \"the check\"." },
    "loc-vdin12": { e: "My shopping cart is already full.", t: "Mi carrito de compras ya está lleno.", s: "Cuando empujas el carrito en el supermercado.", sEn: "When you push the cart at the supermarket.", n: "En EE. UU. es \"cart\"; en el Reino Unido, \"trolley\".", nEn: "In the US it's \"cart\"; in the UK, \"trolley\"." },
    "loc-vdin13": { e: "Do you need a bag for your groceries?", t: "¿Necesita una bolsa para sus compras?", s: "Cuando empacas lo comprado en la caja.", sEn: "When you pack your purchases at the register.", n: "\"Bag\" lleva 'a' abierta; cuídala para no decir \"beg\" (rogar).", nEn: "\"Bag\" has an open 'a'; mind it so it isn't \"beg\"." },
    "loc-vdin14": { e: "I found a coin under the sofa.", t: "Encontré una moneda debajo del sofá.", s: "Cuando hablas de dinero metálico.", sEn: "When you talk about metal money.", n: "\"Coin\" es la moneda metálica; la divisa de un país es \"currency\".", nEn: "\"Coin\" is the metal piece; a country's currency is \"currency\"." },
    "loc-vdin15": { e: "Do you have anything smaller than a fifty-dollar bill?", t: "¿Tiene algo más pequeño que un billete de cincuenta dólares?", s: "Cuando pagas con papel moneda.", sEn: "When you pay with paper money.", n: "En EE. UU. el billete suele ser \"bill\"; \"note\" es más británico.", nEn: "In the US a banknote is usually a \"bill\"; \"note\" is more British." },
    "loc-vdin16": { e: "I want to buy a gift for my mom.", t: "Quiero comprar un regalo para mi mamá.", s: "Cuando hablas de adquirir algo.", sEn: "When you talk about getting something.", n: "\"Buy\" suena 'bai', igual que \"bye\" (adiós).", nEn: "\"Buy\" sounds like 'bye'." },
    "loc-vvia01": { e: "We're planning a trip to the coast next month.", t: "Estamos planeando un viaje a la costa el próximo mes.", s: "Cuando hablas de un recorrido o salida.", sEn: "When you talk about a journey or outing.", n: "\"Trip\" es un viaje concreto; \"travel\" es viajar en general.", nEn: "\"Trip\" is one specific journey; \"travel\" is traveling in general." },
    "loc-vvia02": { e: "My suitcase is too heavy to lift.", t: "Mi maleta pesa demasiado para levantarla.", s: "Cuando empacas tus cosas para un viaje.", sEn: "When you pack your things for a trip.", n: "Una palabra: \"suitcase\"; \"suit\" suena 'sut'.", nEn: "One word, \"suitcase\"; \"suit\" sounds like 'soot'." },
    "loc-vvia03": { e: "Don't forget your passport at the airport.", t: "No olvides tu pasaporte en el aeropuerto.", s: "Cuando viajas a otro país.", sEn: "When you travel to another country.", n: "Una palabra: \"passport\"; acento delante: PÁS-port.", nEn: "One word, \"passport\", stressed on the front." },
    "loc-vvia04": { e: "I bought a round-trip ticket to Miami.", t: "Compré un boleto de ida y vuelta a Miami.", s: "Cuando reservas transporte o entrada.", sEn: "When you book transport or admission.", n: "\"Ticket\" sirve para boleto de avión, de bus y de evento.", nEn: "\"Ticket\" works for a plane, bus, or event ticket." },
    "loc-vvia05": { e: "Our flight leaves at six in the morning.", t: "Nuestro vuelo sale a las seis de la mañana.", s: "Cuando hablas de un viaje en avión.", sEn: "When you talk about traveling by plane.", n: "La 'gh' de \"flight\" es muda: se dice 'fláit'.", nEn: "The 'gh' in \"flight\" is silent: say 'flite'." },
    "loc-vvia06": { e: "We're staying at a small hotel near the beach.", t: "Nos quedamos en un hotel pequeño cerca de la playa.", s: "Cuando hablas de dónde te hospedas.", sEn: "When you talk about where you're staying.", n: "En inglés \"hotel\" acentúa atrás: jou-TÉL.", nEn: "In English \"hotel\" stresses the second syllable: ho-TEL." },
    "loc-vvia07": { e: "Let me check the map to find the museum.", t: "Déjame ver el mapa para encontrar el museo.", s: "Cuando buscas cómo llegar a un lugar.", sEn: "When you look for how to get somewhere.", n: "\"Map\" lleva 'a' abierta y corta; cuida no decir \"mop\" (trapear).", nEn: "\"Map\" has a short open 'a'; don't say \"mop\"." },
    "loc-vvia08": { e: "You can leave your luggage at the front desk.", t: "Puedes dejar tu equipaje en la recepción.", s: "Cuando hablas de las maletas en conjunto.", sEn: "When you talk about your bags as a whole.", n: "\"Luggage\" es incontable; di \"a piece of luggage\" para una pieza.", nEn: "\"Luggage\" is uncountable; say \"a piece of luggage\" for one." },
    "loc-vvia09": { e: "We spent the whole day at the beach.", t: "Pasamos todo el día en la playa.", s: "Cuando hablas de un destino junto al mar.", sEn: "When you talk about a destination by the sea.", n: "\"Beach\" (playa) y \"bitch\" suenan distinto; usa la 'i' larga: bich.", nEn: "\"Beach\" and \"bitch\" differ; use the long 'ee' in \"beach\"." },
    "loc-vvia10": { e: "I really need a vacation after this busy month.", t: "De verdad necesito unas vacaciones después de este mes tan ocupado.", s: "Cuando hablas de tiempo libre para descansar.", sEn: "When you talk about time off to rest.", n: "En EE. UU. es \"vacation\" (singular); en el Reino Unido, \"holiday\".", nEn: "In the US it's \"vacation\" (singular); in the UK, \"holiday\"." },
    "loc-vvia11": { e: "I made a reservation for two nights.", t: "Hice una reserva por dos noches.", s: "Cuando apartas un cuarto o una mesa.", sEn: "When you book a room or a table.", n: "Para hoteles y vuelos vale \"reservation\" o \"booking\".", nEn: "For hotels and flights both \"reservation\" and \"booking\" work." },
    "loc-vvia12": { e: "We crossed the border early in the morning.", t: "Cruzamos la frontera temprano por la mañana.", s: "Cuando viajas entre dos países.", sEn: "When you travel between two countries.", n: "\"Border\" es frontera; el verbo \"to board\" es abordar un avión.", nEn: "\"Border\" is the boundary; \"to board\" is to get on a plane." },
    "loc-vvia13": { e: "We had to wait in line at customs.", t: "Tuvimos que esperar en fila en la aduana.", s: "Cuando llegas a un país y revisan tu equipaje.", sEn: "When you arrive in a country and they check your luggage.", n: "Siempre en plural: \"customs\"; \"custom\" en singular es costumbre.", nEn: "Always plural: \"customs\"; singular \"custom\" means a habit." },
    "loc-vvia14": { e: "Our guide showed us the best spots in the old town.", t: "Nuestro guía nos mostró los mejores lugares del casco viejo.", s: "Cuando alguien te muestra un lugar turístico.", sEn: "When someone shows you around a tourist site.", n: "\"Guide\" es la persona y también la guía impresa.", nEn: "\"Guide\" is both the person and the printed guidebook." },
    "loc-vvia15": { e: "Don't forget to bring your camera on the trip.", t: "No olvides traer tu cámara al viaje.", s: "Cuando quieres tomar fotos en vacaciones.", sEn: "When you want to take photos on vacation.", n: "\"Camera\" acentúa delante: KÁ-me-ra.", nEn: "\"Camera\" stresses the front: CA-me-ra." },
    "loc-vvia16": { e: "I bought a little souvenir to remember the trip.", t: "Compré un pequeño recuerdo para acordarme del viaje.", s: "Cuando llevas algo de vuelta de un destino.", sEn: "When you bring something back from a destination.", n: "\"Souvenir\" acentúa atrás: su-ve-NÍR; es un préstamo del francés.", nEn: "\"Souvenir\" stresses the end: sou-ve-NIR; it's borrowed from French." },
    "loc-vvia17": { e: "The town is full of tourists in the summer.", t: "El pueblo se llena de turistas en el verano.", s: "Cuando hablas de visitantes de un lugar.", sEn: "When you talk about visitors to a place.", n: "\"Tourist\" acentúa delante: TÚ-rist.", nEn: "\"Tourist\" stresses the front: TOU-rist." },
    "loc-vvia18": { e: "Our hike turned into a real adventure.", t: "Nuestra caminata se convirtió en una verdadera aventura.", s: "Cuando vives una experiencia emocionante de viaje.", sEn: "When you have an exciting travel experience.", n: "\"Adventure\" acentúa en medio: ad-VÉN-cher.", nEn: "\"Adventure\" stresses the middle: ad-VEN-ture." },

    // ============== VOCABULARIO TEMÁTICO (loc-voc) — ampliación 2 ==============
    "loc-vhor01": { e: "The meeting lasted about an hour.", t: "La reunión duró como una hora.", s: "Al hablar de cuánto tiempo dura algo.", sEn: "When talking about how long something lasts.", n: "\"Hour\" tiene la 'h' muda; suena \"áur\", igual que \"our\".", nEn: "\"Hour\" has a silent 'h'; it sounds like \"our\"." },
    "loc-vhor02": { e: "Give me just one minute, please.", t: "Dame solo un minuto, por favor.", s: "Cuando pides un momento breve a alguien.", sEn: "When you ask someone for a brief moment.", n: "Se pronuncia MÍ-nit; no lo confundas con \"minute\" (mai-NIÚT) que significa diminuto.", nEn: "It's pronounced MIN-it; don't confuse it with \"minute\" (my-NUTE) meaning tiny." },
    "loc-vhor03": { e: "Wait a second, I'm almost ready.", t: "Espera un segundo, ya casi estoy listo.", s: "Al pedir que alguien espere un instante muy corto.", sEn: "When asking someone to wait a very short instant.", n: "\"Second\" también significa 'segundo' como número de orden, no solo de tiempo.", nEn: "\"Second\" also means 'second' as in order, not just time." },
    "loc-vhor04": { e: "Let's have lunch at noon.", t: "Almorcemos al mediodía.", s: "Al acordar verse a las doce del día.", sEn: "When arranging to meet at twelve midday.", n: "\"Noon\" se refiere solo a las 12 del día; rima con \"moon\".", nEn: "\"Noon\" means only 12 midday; it rhymes with \"moon\"." },
    "loc-vhor05": { e: "The party went on until midnight.", t: "La fiesta siguió hasta la medianoche.", s: "Al hablar de algo que pasa muy tarde en la noche.", sEn: "When talking about something happening very late at night.", n: "Acento en la primera sílaba: MÍD-nait.", nEn: "Stress the first syllable: MID-night." },
    "loc-vhor06": { e: "Have a nice day!", t: "¡Que tengas un buen día!", s: "Al despedirte amablemente de alguien.", sEn: "When saying goodbye politely to someone.", n: "\"Day\" suena \"déi\"; rima con \"say\" y \"way\".", nEn: "\"Day\" sounds like \"day\"; it rhymes with \"say\" and \"way\"." },
    "loc-vhor07": { e: "I'll see you next week.", t: "Te veo la próxima semana.", s: "Al planear algo para los próximos días.", sEn: "When planning something for the coming days.", n: "\"Week\" (semana) y \"weak\" (débil) suenan igual; el contexto los distingue.", nEn: "\"Week\" (week) and \"weak\" (weak) sound the same; context tells them apart." },
    "loc-vhor08": { e: "I'm really busy today.", t: "Estoy muy ocupado hoy.", s: "Al hablar de lo que pasa en el día actual.", sEn: "When talking about what's happening on the current day.", n: "Acento en la segunda sílaba: tu-DÉI.", nEn: "Stress the second syllable: to-DAY." },
    "loc-vhor09": { e: "Let's talk about it tomorrow.", t: "Hablemos de eso mañana.", s: "Al posponer algo para el día siguiente.", sEn: "When postponing something to the next day.", n: "\"Tomorrow\" es solo 'mañana' como día; para 'la mañana' usa \"morning\".", nEn: "\"Tomorrow\" is 'tomorrow' only; for 'the morning' use \"morning\"." },
    "loc-vhor10": { e: "I saw her yesterday at the store.", t: "La vi ayer en la tienda.", s: "Al contar algo que pasó el día anterior.", sEn: "When telling something that happened the day before.", n: "Acento en la primera sílaba: YÉS-ter-dei.", nEn: "Stress the first syllable: YES-ter-day." },
    "loc-vhor11": { e: "Can you come over now?", t: "¿Puedes venir ahora?", s: "Cuando pides que algo pase en este mismo momento.", sEn: "When you ask for something to happen right at this moment.", n: "\"Now\" suena \"náu\"; rima con \"how\" y \"cow\".", nEn: "\"Now\" sounds like \"now\"; it rhymes with \"how\" and \"cow\"." },
    "loc-vhor12": { e: "I woke up early this morning.", t: "Me desperté temprano esta mañana.", s: "Al hablar de hacer algo antes de la hora habitual.", sEn: "When talking about doing something before the usual time.", n: "Acento en la primera sílaba: ÉR-li; rima con \"pearly\".", nEn: "Stress the first syllable: EAR-ly; it rhymes with \"pearly\"." },
    "loc-vhor13": { e: "Sorry I'm late, traffic was bad.", t: "Perdón por llegar tarde, había mucho tráfico.", s: "Al disculparte por llegar después de la hora.", sEn: "When apologizing for arriving after the time.", n: "\"Late\" suena \"léit\"; ojo, no significa 'tarde' como parte del día.", nEn: "\"Late\" sounds like \"late\"; note it doesn't mean 'afternoon'." },
    "loc-vhor14": { e: "The clock on the wall is ten minutes fast.", t: "El reloj de la pared está diez minutos adelantado.", s: "Al referirte a un reloj de pared o de mesa.", sEn: "When referring to a wall or table clock.", n: "\"Clock\" es reloj fijo; el de pulsera es \"watch\".", nEn: "\"Clock\" is a fixed clock; a wristwatch is \"watch\"." },
    "loc-vhor15": { e: "Let me check my calendar first.", t: "Déjame revisar mi calendario primero.", s: "Al organizar fechas o citas.", sEn: "When organizing dates or appointments.", n: "Acento en la primera sílaba: KÁ-len-dar.", nEn: "Stress the first syllable: CAL-en-dar." },
    "loc-vhor16": { e: "Give me a moment to think.", t: "Dame un momento para pensar.", s: "Cuando pides una pausa breve.", sEn: "When you ask for a brief pause.", n: "\"Moment\" es un cognado fácil; significa lo mismo que 'momento'.", nEn: "\"Moment\" is an easy cognate; it means the same as 'momento'." },
    "loc-vban01": { e: "Wash your hands with soap and water.", t: "Lávate las manos con jabón y agua.", s: "Al hablar de higiene o de lavarse.", sEn: "When talking about hygiene or washing up.", n: "\"Soap\" suena \"sóup\"; no lo confundas con \"soup\" (sopa), que suena \"sup\".", nEn: "\"Soap\" sounds like \"sope\"; don't confuse it with \"soup\", which sounds like \"soop\"." },
    "loc-vban02": { e: "Can I get a clean towel, please?", t: "¿Me das una toalla limpia, por favor?", s: "Al pedir una toalla en un hotel o casa.", sEn: "When asking for a towel at a hotel or home.", n: "Se pronuncia TÁU-el, en dos sílabas.", nEn: "It's pronounced TOW-el, in two syllables." },
    "loc-vban03": { e: "Don't forget to pack your toothbrush.", t: "No olvides empacar tu cepillo de dientes.", s: "Al preparar artículos de aseo para un viaje.", sEn: "When packing toiletries for a trip.", n: "Es una sola palabra: tooth + brush, TÚZ-brash.", nEn: "It's one word: tooth + brush, TOOTH-brush." },
    "loc-vban04": { e: "We're out of toothpaste.", t: "Se nos acabó la pasta dental.", s: "Al notar que falta un producto de higiene.", sEn: "When you notice a hygiene product has run out.", n: "Es incontable; di \"some toothpaste\", no \"a toothpaste\".", nEn: "It's uncountable; say \"some toothpaste\", not \"a toothpaste\"." },
    "loc-vban05": { e: "This shampoo smells like coconut.", t: "Este champú huele a coco.", s: "Al hablar de productos para el cabello.", sEn: "When talking about hair products.", n: "Acento en la segunda sílaba: sham-PÚ.", nEn: "Stress the second syllable: sham-POO." },
    "loc-vban06": { e: "She looked at herself in the mirror.", t: "Ella se miró en el espejo.", s: "Al hablar de arreglarse frente al espejo.", sEn: "When talking about getting ready in front of the mirror.", n: "Acento en la primera sílaba: MÍ-ror.", nEn: "Stress the first syllable: MIR-ror." },
    "loc-vban07": { e: "I'm going to take a quick shower.", t: "Voy a darme una ducha rápida.", s: "Al decir que vas a bañarte de pie.", sEn: "When saying you're going to take a shower.", n: "Se dice \"take a shower\", no \"make a shower\".", nEn: "Say \"take a shower\", not \"make a shower\"." },
    "loc-vban08": { e: "The toilet is down the hall.", t: "El inodoro está al fondo del pasillo.", s: "Al indicar dónde está el baño.", sEn: "When pointing out where the toilet is.", n: "Acento en la primera sílaba: TÓI-let.", nEn: "Stress the first syllable: TOI-let." },
    "loc-vban09": { e: "Can you buy more toilet paper?", t: "¿Puedes comprar más papel higiénico?", s: "Al pedir reponer artículos del baño.", sEn: "When asking to restock bathroom items.", n: "Son dos palabras; en hablar casual también se dice \"TP\".", nEn: "It's two words; in casual speech people also say \"TP\"." },
    "loc-vban10": { e: "I need a comb for my hair.", t: "Necesito un peine para el cabello.", s: "Al hablar de peinarte.", sEn: "When talking about combing your hair.", n: "La 'b' final es muda; suena \"kóum\", rima con \"home\".", nEn: "The final 'b' is silent; it sounds like \"comb\", rhyming with \"home\"." },
    "loc-vban11": { e: "Is there a hair dryer in the room?", t: "¿Hay secadora de pelo en la habitación?", s: "Al preguntar por servicios en un hotel.", sEn: "When asking about amenities at a hotel.", n: "Son dos palabras: hair + dryer; \"dryer\" suena DRÁI-er.", nEn: "It's two words: hair + dryer; \"dryer\" sounds like DRY-er." },
    "loc-vban12": { e: "He bought a new razor for shaving.", t: "Él compró una afeitadora nueva.", s: "Al hablar de artículos para afeitarse.", sEn: "When talking about shaving items.", n: "Acento en la primera sílaba: RÉI-sor.", nEn: "Stress the first syllable: RA-zor." },
    "loc-vban13": { e: "Please don't leave dishes in the sink.", t: "Por favor no dejes platos en el lavabo.", s: "Al referirte al lavabo del baño o de la cocina.", sEn: "When referring to a bathroom or kitchen sink.", n: "\"Sink\" rima con \"think\"; no lo confundas con \"sing\".", nEn: "\"Sink\" rhymes with \"think\"; don't confuse it with \"sing\"." },
    "loc-vban14": { e: "The kids love playing in the bathtub.", t: "A los niños les encanta jugar en la tina.", s: "Al hablar de la bañera para bañarse.", sEn: "When talking about the tub for bathing.", n: "Es una palabra: bath + tub; en casual a veces solo \"tub\".", nEn: "It's one word: bath + tub; casually just \"tub\"." },
    "loc-vban15": { e: "I forgot to put on deodorant today.", t: "Olvidé ponerme desodorante hoy.", s: "Al hablar de la higiene personal diaria.", sEn: "When talking about daily personal hygiene.", n: "Se pronuncia di-Ó-do-rant, con el acento en la segunda sílaba.", nEn: "It's pronounced de-O-dor-ant, stress on the second syllable." },
    "loc-vban16": { e: "Use this brush to clean the tiles.", t: "Usa este cepillo para limpiar los azulejos.", s: "Al referirte a un cepillo de limpieza en general.", sEn: "When referring to a cleaning brush in general.", n: "\"Brush\" sirve para cepillo y para 'cepillar' como verbo.", nEn: "\"Brush\" works as the noun and the verb 'to brush'." },
    "loc-vher01": { e: "Hand me the hammer, please.", t: "Pásame el martillo, por favor.", s: "Al pedir una herramienta mientras trabajas.", sEn: "When asking for a tool while working.", n: "La 'h' se aspira; suena JÁ-mer, acento al inicio.", nEn: "The 'h' is breathy; it sounds like HAM-mer, stress at the start." },
    "loc-vher02": { e: "I need a nail to hang this picture.", t: "Necesito un clavo para colgar este cuadro.", s: "Al colgar algo en la pared.", sEn: "When hanging something on the wall.", n: "\"Nail\" también significa 'uña'; el contexto lo aclara.", nEn: "\"Nail\" also means 'fingernail'; context makes it clear." },
    "loc-vher03": { e: "Do you have a Phillips screwdriver?", t: "¿Tienes un destornillador de cruz?", s: "Al buscar la herramienta para tornillos.", sEn: "When looking for the tool for screws.", n: "Es una palabra: screw + driver, SKRÚ-drai-ver.", nEn: "It's one word: screw + driver, SCREW-driver." },
    "loc-vher04": { e: "This screw is too loose.", t: "Este tornillo está muy flojo.", s: "Al hablar de fijar o ajustar algo.", sEn: "When talking about fastening or adjusting something.", n: "\"Screw\" suena \"skru\"; también es verbo: 'atornillar'.", nEn: "\"Screw\" sounds like \"skroo\"; it's also a verb: 'to screw'." },
    "loc-vher05": { e: "Be careful with that saw, it's sharp.", t: "Ten cuidado con esa sierra, está afilada.", s: "Al usar herramientas para cortar madera.", sEn: "When using tools to cut wood.", n: "\"Saw\" suena \"so\"; también es el pasado de \"see\".", nEn: "\"Saw\" sounds like \"saw\"; it's also the past of \"see\"." },
    "loc-vher06": { e: "I'll use the drill to make a hole.", t: "Usaré el taladro para hacer un agujero.", s: "Al perforar una pared o madera.", sEn: "When drilling into a wall or wood.", n: "\"Drill\" es taladro y también 'taladrar' como verbo.", nEn: "\"Drill\" is the noun and the verb 'to drill'." },
    "loc-vher07": { e: "Tighten the bolt with a wrench.", t: "Aprieta el perno con una llave inglesa.", s: "Al ajustar tuercas o pernos.", sEn: "When tightening nuts or bolts.", n: "La 'w' es muda; suena \"rench\".", nEn: "The 'w' is silent; it sounds like \"rench\"." },
    "loc-vher08": { e: "Grab the pliers to bend this wire.", t: "Agarra los alicates para doblar este alambre.", s: "Al sujetar o doblar cosas pequeñas.", sEn: "When gripping or bending small things.", n: "Siempre es plural: \"pliers\", como \"scissors\".", nEn: "It's always plural: \"pliers\", like \"scissors\"." },
    "loc-vher09": { e: "Use the tape measure to check the width.", t: "Usa la cinta métrica para medir el ancho.", s: "Al medir longitudes en un proyecto.", sEn: "When measuring lengths in a project.", n: "Son dos palabras: tape + measure; \"measure\" suena MÉ-zher (la 's' es sonora, como en 'visión').", nEn: "It's two words: tape + measure; \"measure\" sounds like MEH-zher." },
    "loc-vher10": { e: "Hold the ladder while I climb up.", t: "Sostén la escalera mientras subo.", s: "Al subir a un lugar alto.", sEn: "When climbing up to a high place.", n: "\"Ladder\" es escalera de mano; la fija es \"stairs\".", nEn: "\"Ladder\" is a step ladder; a fixed staircase is \"stairs\"." },
    "loc-vher11": { e: "Grab a shovel and help me dig.", t: "Agarra una pala y ayúdame a cavar.", s: "Al trabajar en el jardín o la tierra.", sEn: "When working in the garden or soil.", n: "Acento en la primera sílaba: SHÁ-vol.", nEn: "Stress the first syllable: SHOV-el." },
    "loc-vher12": { e: "We need one more can of paint.", t: "Necesitamos una lata más de pintura.", s: "Al pintar una pared o un mueble.", sEn: "When painting a wall or furniture.", n: "\"Paint\" es pintura y 'pintar' como verbo.", nEn: "\"Paint\" is the noun and the verb 'to paint'." },
    "loc-vher13": { e: "Clean the paintbrush after you finish.", t: "Limpia la brocha cuando termines.", s: "Al pintar y guardar las herramientas.", sEn: "When painting and putting away tools.", n: "Es una palabra: paint + brush, PÉINT-brash.", nEn: "It's one word: paint + brush, PAINT-brush." },
    "loc-vher14": { e: "Wrap some tape around the cable.", t: "Envuelve un poco de cinta alrededor del cable.", s: "Al pegar o sujetar cosas con cinta.", sEn: "When sticking or fastening things with tape.", n: "\"Tape\" suena \"téip\"; es incontable, di \"some tape\".", nEn: "\"Tape\" sounds like \"tape\"; it's uncountable, say \"some tape\"." },
    "loc-vher15": { e: "A little glue will fix the chair.", t: "Un poco de pegamento arreglará la silla.", s: "Al unir piezas rotas.", sEn: "When joining broken pieces.", n: "\"Glue\" suena \"glu\"; es incontable, di \"some glue\".", nEn: "\"Glue\" sounds like \"gloo\"; it's uncountable, say \"some glue\"." },
    "loc-vher16": { e: "All my tools are in the toolbox.", t: "Todas mis herramientas están en la caja de herramientas.", s: "Al guardar u organizar las herramientas.", sEn: "When storing or organizing tools.", n: "Es una palabra: tool + box, TÚL-boks.", nEn: "It's one word: tool + box, TOOL-box." },
    "loc-vmus01": { e: "This is my favorite song.", t: "Esta es mi canción favorita.", s: "Al hablar de música que te gusta.", sEn: "When talking about music you like.", n: "\"Song\" rima con \"long\"; la 'o' es abierta.", nEn: "\"Song\" rhymes with \"long\"; the 'o' is open." },
    "loc-vmus02": { e: "He plays the guitar really well.", t: "Él toca la guitarra muy bien.", s: "Al hablar de tocar un instrumento.", sEn: "When talking about playing an instrument.", n: "Acento en la segunda sílaba: gui-TAR.", nEn: "Stress the second syllable: gui-TAR." },
    "loc-vmus03": { e: "She's learning to play the piano.", t: "Ella está aprendiendo a tocar el piano.", s: "Al hablar de instrumentos de teclado.", sEn: "When talking about keyboard instruments.", n: "Se pronuncia pi-Á-nou, distinto del español.", nEn: "It's pronounced pee-AN-oh, different from Spanish." },
    "loc-vmus04": { e: "He plays the drums in a band.", t: "Él toca el tambor en una banda.", s: "Al hablar de percusión.", sEn: "When talking about percussion.", n: "\"Drum\" rima con \"sum\"; el conjunto se dice \"drums\".", nEn: "\"Drum\" rhymes with \"sum\"; the kit is \"drums\"." },
    "loc-vmus05": { e: "The flute has a soft, gentle sound.", t: "La flauta tiene un sonido suave y delicado.", s: "Al hablar de instrumentos de viento.", sEn: "When talking about wind instruments.", n: "\"Flute\" suena \"flut\", con 'u' larga.", nEn: "\"Flute\" sounds like \"floot\", with a long 'u'." },
    "loc-vmus06": { e: "She plays the violin in the orchestra.", t: "Ella toca el violín en la orquesta.", s: "Al hablar de instrumentos de cuerda.", sEn: "When talking about string instruments.", n: "Acento en la última sílaba: vai-o-LÍN.", nEn: "Stress the last syllable: vy-o-LIN." },
    "loc-vmus07": { e: "The trumpet led the whole song.", t: "La trompeta lideró toda la canción.", s: "Al hablar de instrumentos de metal.", sEn: "When talking about brass instruments.", n: "Acento en la primera sílaba: TRÁM-pet.", nEn: "Stress the first syllable: TRUM-pet." },
    "loc-vmus08": { e: "The singer has an amazing voice.", t: "El cantante tiene una voz increíble.", s: "Al hablar de quien canta en un grupo.", sEn: "When talking about the person who sings in a group.", n: "Se pronuncia \"SÍN-er\"; la \"ng\" suena nasal como en \"sing\", no con la \"g\" dura de \"finger\".", nEn: "Pronounced \"SING-er\"; the \"ng\" is the soft nasal of \"sing\", not the hard 'g' of \"finger\"." },
    "loc-vmus09": { e: "They started a rock band in college.", t: "Empezaron una banda de rock en la universidad.", s: "Al hablar de un grupo musical.", sEn: "When talking about a musical group.", n: "\"Band\" rima con \"hand\"; ojo, no es 'banda' de tela (eso es \"strip\").", nEn: "\"Band\" rhymes with \"hand\"; note it's not a strip of cloth." },
    "loc-vmus10": { e: "We're going to a concert tonight.", t: "Vamos a un concierto esta noche.", s: "Al planear ir a ver música en vivo.", sEn: "When planning to go see live music.", n: "Acento en la primera sílaba: KÓN-sert.", nEn: "Stress the first syllable: CON-cert." },
    "loc-vmus11": { e: "I love the rhythm of this song.", t: "Me encanta el ritmo de esta canción.", s: "Al hablar del compás o cadencia de la música.", sEn: "When talking about the beat or cadence of music.", n: "Ortografía difícil: r-h-y-t-h-m; suena RÍ-dam.", nEn: "Tricky spelling: r-h-y-t-h-m; it sounds like RITH-um." },
    "loc-vmus12": { e: "She has a beautiful singing voice.", t: "Ella tiene una hermosa voz para cantar.", s: "Al hablar de la voz de alguien.", sEn: "When talking about someone's voice.", n: "\"Voice\" suena \"vóis\"; rima con \"choice\".", nEn: "\"Voice\" sounds like \"voice\"; it rhymes with \"choice\"." },
    "loc-vmus13": { e: "Please speak into the microphone.", t: "Por favor habla en el micrófono.", s: "Al usar equipo de sonido en un evento.", sEn: "When using sound equipment at an event.", n: "Acento en la primera sílaba: MÁI-kro-foun; casual: \"mic\".", nEn: "Stress the first syllable: MI-cro-phone; casually: \"mic\"." },
    "loc-vmus14": { e: "He played the wrong note.", t: "Tocó la nota equivocada.", s: "Al hablar de tonos musicales.", sEn: "When talking about musical tones.", n: "\"Note\" también significa 'nota' escrita o apunte.", nEn: "\"Note\" also means a written note or memo." },
    "loc-vmus15": { e: "The band walked onto the stage.", t: "La banda subió al escenario.", s: "Al hablar de presentaciones en vivo.", sEn: "When talking about live performances.", n: "\"Stage\" suena \"stéich\"; también significa 'etapa'.", nEn: "\"Stage\" sounds like \"stage\"; it also means 'phase'." },
    "loc-vmus16": { e: "The audience cheered after the show.", t: "El público aplaudió después del espectáculo.", s: "Al hablar de la gente que asiste a un evento.", sEn: "When talking about the people attending an event.", n: "Se pronuncia Ó-di-ens; es un falso amigo parcial de 'audiencia'.", nEn: "It's pronounced AW-dee-ens; a partial false friend of 'audiencia'." },
    "loc-vfma01": { e: "Draw a big circle here and write the name inside it.", t: "Dibuja un círculo grande aquí y escribe el nombre adentro.", s: "Al describir una forma redonda en un dibujo o señal.", sEn: "When describing a round shape in a drawing or sign.", n: "\"Circle\" lleva el acento al inicio: SÉR-kol. La primera 'c' suena como 's' y la segunda como 'k'.", nEn: "\"Circle\" is stressed at the start: SER-kel. The first 'c' sounds like 's' and the second like 'k'." },
    "loc-vfma02": { e: "The room is a perfect square, four meters on each side.", t: "El cuarto es un cuadrado perfecto, cuatro metros por lado.", s: "Al hablar de una forma de cuatro lados iguales.", sEn: "When talking about a four-equal-sided shape.", n: "\"Square\" se pronuncia 'skuér', con la 'qu' como 'kw'.", nEn: "\"Square\" is pronounced 'skwair', with 'qu' like 'kw'." },
    "loc-vfma03": { e: "Cut the sandwich into a triangle, please.", t: "Corta el sándwich en triángulo, por favor.", s: "Al describir una forma de tres lados.", sEn: "When describing a three-sided shape.", n: "\"Triangle\" lleva el acento al inicio: TRÁI-an-gol.", nEn: "\"Triangle\" is stressed at the start: TRI-an-gle." },
    "loc-vfma04": { e: "The table is a long rectangle that seats eight people.", t: "La mesa es un rectángulo largo donde caben ocho personas.", s: "Al describir una forma alargada de cuatro lados.", sEn: "When describing a long four-sided shape.", n: "\"Rectangle\" lleva el acento al inicio: REK-tan-gol.", nEn: "\"Rectangle\" is stressed at the start: REC-tan-gle." },
    "loc-vfma05": { e: "The hotel has a gold star on the front door.", t: "El hotel tiene una estrella dorada en la puerta principal.", s: "Al hablar de la forma de estrella o de categorías de hotel.", sEn: "When talking about a star shape or hotel ratings.", n: "\"Star\" empieza con 'st'; evita poner una 'e' antes: no es 'estar'.", nEn: "\"Star\" starts with 'st'; don't add an 'e' before it." },
    "loc-vfma06": { e: "She drew a little heart next to her name on the card.", t: "Ella dibujó un corazoncito junto a su nombre en la tarjeta.", s: "Al hablar de la forma de corazón en notas o decoraciones.", sEn: "When talking about a heart shape on notes or decorations.", n: "\"Heart\" se pronuncia 'jart', con 'h' aspirada y sin sonar la 'ea' como 'i'.", nEn: "\"Heart\" is pronounced 'hart', rhyming with 'art', not 'heart-eat'." },
    "loc-vfma07": { e: "Please stand behind the yellow line.", t: "Por favor, párese detrás de la línea amarilla.", s: "Al indicar una marca o trazo recto en el piso o en papel.", sEn: "When pointing out a straight mark on the floor or paper.", n: "\"Line\" se pronuncia 'láin', no 'lin'; la 'i' suena como 'ai'.", nEn: "\"Line\" is pronounced 'lyne', not 'lin'." },
    "loc-vfma08": { e: "There's a small dot of sauce on the plate as decoration.", t: "Hay un puntito de salsa en el plato como decoración.", s: "Al hablar de una marca redonda y pequeña.", sEn: "When talking about a small round mark.", n: "\"Dot\" es un punto pequeño; para puntuación al final de una frase se dice 'period' o 'full stop'.", nEn: "\"Dot\" is a small mark; the sentence-ending punctuation is a 'period' or 'full stop'." },
    "loc-vfma09": { e: "The mirror has an oval shape with a wooden frame.", t: "El espejo tiene forma ovalada con marco de madera.", s: "Al describir una forma alargada y redondeada.", sEn: "When describing a long, rounded shape.", n: "\"Oval\" lleva el acento al inicio: ÓU-val.", nEn: "\"Oval\" is stressed at the start: O-val." },
    "loc-vfma10": { e: "The ring has a small diamond in the center.", t: "El anillo tiene un pequeño diamante en el centro.", s: "Al hablar de la forma de rombo o de la piedra preciosa.", sEn: "When talking about a diamond shape or the gemstone.", n: "\"Diamond\" lleva el acento al inicio: DÁI-mond, suele sonar como dos sílabas.", nEn: "\"Diamond\" is stressed at the start: DI-mond, often just two syllables." },
    "loc-vfma11": { e: "Follow the arrow to find the exit.", t: "Sigue la flecha para encontrar la salida.", s: "Al guiar a alguien con señales que apuntan una dirección.", sEn: "When guiding someone with signs pointing a direction.", n: "\"Arrow\" lleva el acento al inicio: É-rou, sin sonar fuerte la 'r' doble.", nEn: "\"Arrow\" is stressed at the start: A-rrow, with a soft double 'r'." },
    "loc-vfma12": { e: "There's a red cross on the first-aid box.", t: "Hay una cruz roja en la caja de primeros auxilios.", s: "Al hablar de la forma de cruz o del símbolo de ayuda médica.", sEn: "When talking about a cross shape or the medical symbol.", n: "\"Cross\" se pronuncia 'kros', con 'o' corta y la 'ss' marcada.", nEn: "\"Cross\" is pronounced 'kros', with a short 'o'." },
    "loc-vfma13": { e: "Be careful, there's a sharp curve in the road ahead.", t: "Ten cuidado, hay una curva cerrada más adelante en el camino.", s: "Al describir una línea que se dobla, en un camino o un dibujo.", sEn: "When describing a bending line, on a road or a drawing.", n: "\"Curve\" se pronuncia 'kerv'; la 'u' suena como una 'e' relajada.", nEn: "\"Curve\" is pronounced 'kerv', with the 'u' like a soft 'er'." },
    "loc-vfma14": { e: "The lamp is in the corner of the room.", t: "La lámpara está en la esquina del cuarto.", s: "Al indicar dónde se juntan dos paredes o bordes.", sEn: "When pointing out where two walls or edges meet.", n: "\"Corner\" lleva el acento al inicio: KÓR-ner.", nEn: "\"Corner\" is stressed at the start: COR-ner." },
    "loc-vfma15": { e: "Don't put the glass too close to the edge of the table.", t: "No pongas el vaso muy cerca del borde de la mesa.", s: "Al hablar del límite o filo de algo.", sEn: "When talking about the rim or border of something.", n: "\"Edge\" se pronuncia 'ech', con un sonido suave al final como en 'judge'.", nEn: "\"Edge\" is pronounced 'edj', with a soft ending like 'judge'." },
    "loc-vfma16": { e: "We have a nice round table for your group of six.", t: "Tenemos una linda mesa redonda para su grupo de seis.", s: "Al describir algo de forma circular, como una mesa.", sEn: "When describing something circular, like a table.", n: "\"Round\" se pronuncia 'ráund'; la 'ou' suena como 'au'.", nEn: "\"Round\" is pronounced 'rownd', with 'ou' like 'ow'." },
    "loc-vmat01": { e: "The floor is made of dark wood, so be careful when it's wet.", t: "El piso es de madera oscura, así que ten cuidado cuando esté mojado.", s: "Al hablar del material de muebles o pisos.", sEn: "When talking about the material of furniture or floors.", n: "\"Wood\" se pronuncia 'uud', con 'u' corta, igual que 'would'.", nEn: "\"Wood\" is pronounced 'wood', a short 'u', like 'would'." },
    "loc-vmat02": { e: "The chairs are made of metal, so they're light and easy to move.", t: "Las sillas son de metal, así que son ligeras y fáciles de mover.", s: "Al describir de qué está hecho un objeto.", sEn: "When describing what an object is made of.", n: "\"Metal\" lleva el acento al inicio: MÉ-tal, con la 't' suave en inglés americano.", nEn: "\"Metal\" is stressed at the start: ME-tal, with a soft 't' in US English." },
    "loc-vmat03": { e: "We use plastic cups for the pool area for safety.", t: "Usamos vasos de plástico en la zona de la piscina por seguridad.", s: "Al hablar de un material ligero y económico.", sEn: "When talking about a light, cheap material.", n: "\"Plastic\" lleva el acento al inicio: PLÁS-tik.", nEn: "\"Plastic\" is stressed at the start: PLAS-tic." },
    "loc-vmat04": { e: "Please be careful, the table is made of glass.", t: "Por favor ten cuidado, la mesa es de vidrio.", s: "Al advertir sobre un material frágil.", sEn: "When warning about a fragile material.", n: "\"Glass\" se pronuncia 'glas'; sirve también para 'vaso' o 'copa'.", nEn: "\"Glass\" is pronounced 'glas'; it also means a drinking glass." },
    "loc-vmat05": { e: "I'll bring you some paper to write down the address.", t: "Le traigo un papel para que anote la dirección.", s: "Al ofrecer algo para escribir o anotar.", sEn: "When offering something to write on.", n: "\"Paper\" lleva el acento al inicio: PÉI-per.", nEn: "\"Paper\" is stressed at the start: PAY-per." },
    "loc-vmat06": { e: "We use a clean cloth to wipe down each table.", t: "Usamos un paño limpio para limpiar cada mesa.", s: "Al hablar de tela o de un trapo para limpiar.", sEn: "When talking about fabric or a wiping rag.", n: "\"Cloth\" (tela) se pronuncia 'kloz'; el plural 'clothes' (ropa) suena distinto.", nEn: "\"Cloth\" (fabric) is 'kloth'; the plural 'clothes' (garments) sounds different." },
    "loc-vmat07": { e: "The sofa is real leather, so it lasts for years.", t: "El sofá es de cuero auténtico, así que dura muchos años.", s: "Al describir el material de zapatos, bolsos o muebles.", sEn: "When describing the material of shoes, bags, or furniture.", n: "\"Leather\" lleva el acento al inicio: LÉ-der, con 'th' suave.", nEn: "\"Leather\" is stressed at the start: LE-ther, with a soft 'th'." },
    "loc-vmat08": { e: "The frame is painted gold to match the lobby.", t: "El marco está pintado de dorado para combinar con el lobby.", s: "Al hablar del metal precioso o del color dorado.", sEn: "When talking about the precious metal or the gold color.", n: "\"Gold\" se pronuncia 'góuld'; la 'o' suena como 'ou'.", nEn: "\"Gold\" is pronounced 'gohld', with 'o' like 'oh'." },
    "loc-vmat09": { e: "The cutlery is silver, so please polish it carefully.", t: "Los cubiertos son de plata, así que pula con cuidado.", s: "Al hablar del metal precioso o del color plateado.", sEn: "When talking about the precious metal or the silver color.", n: "\"Silver\" lleva el acento al inicio: SÍL-ver.", nEn: "\"Silver\" is stressed at the start: SIL-ver." },
    "loc-vmat10": { e: "The gate is made of iron, so it's very heavy.", t: "El portón es de hierro, así que es muy pesado.", s: "Al describir un metal fuerte y pesado.", sEn: "When describing a strong, heavy metal.", n: "\"Iron\" se pronuncia 'ÁI-ern'; la 'r' casi no se oye.", nEn: "\"Iron\" is pronounced 'I-ern'; the 'r' is nearly silent." },
    "loc-vmat11": { e: "The path is made of stone, so wear good shoes.", t: "El sendero es de piedra, así que usa buen calzado.", s: "Al hablar de piedra como material de construcción.", sEn: "When talking about stone as a building material.", n: "\"Stone\" se pronuncia 'stóun'; la 'o' suena como 'ou'.", nEn: "\"Stone\" is pronounced 'stohn', with 'o' like 'oh'." },
    "loc-vmat12": { e: "The wall is made of red brick, very typical here.", t: "La pared es de ladrillo rojo, muy típico de aquí.", s: "Al describir el material de paredes o construcciones.", sEn: "When describing the material of walls or buildings.", n: "\"Brick\" se pronuncia 'brik', con 'i' corta como en 'sit'.", nEn: "\"Brick\" is pronounced 'brik', with a short 'i' like 'sit'." },
    "loc-vmat13": { e: "The floor is just cement, so it can get cold.", t: "El piso es solo de cemento, así que puede enfriarse.", s: "Al hablar del material gris de construcción.", sEn: "When talking about the gray building material.", n: "\"Cement\" lleva el acento al final: si-MÉNT.", nEn: "\"Cement\" is stressed at the end: si-MENT." },
    "loc-vmat14": { e: "The mat by the door is made of rubber, so it doesn't slip.", t: "El tapete junto a la puerta es de goma, así que no se resbala.", s: "Al describir un material flexible y antideslizante.", sEn: "When describing a flexible, non-slip material.", n: "\"Rubber\" lleva el acento al inicio: RÁ-ber.", nEn: "\"Rubber\" is stressed at the start: RUB-ber." },
    "loc-vmat15": { e: "These towels are pure cotton, soft and easy to wash.", t: "Estas toallas son de puro algodón, suaves y fáciles de lavar.", s: "Al hablar del material de toallas, ropa o sábanas.", sEn: "When talking about the material of towels, clothes, or sheets.", n: "\"Cotton\" lleva el acento al inicio: KÓ-ton, con la 'tt' suave en inglés americano.", nEn: "\"Cotton\" is stressed at the start: COT-ton, with a soft 'tt' in US English." },
    "loc-vmat16": { e: "The blankets are wool, perfect for cold nights.", t: "Las cobijas son de lana, perfectas para las noches frías.", s: "Al describir el material de cobijas o suéteres.", sEn: "When describing the material of blankets or sweaters.", n: "\"Wool\" se pronuncia 'uul', con 'u' corta, parecida a 'pull'.", nEn: "\"Wool\" is pronounced 'wool', a short 'u', like 'pull'." },
    "loc-vave01": { e: "Look, there's a little bird on the balcony.", t: "Mira, hay un pajarito en el balcón.", s: "Al señalar un ave en general.", sEn: "When pointing out a bird in general.", n: "\"Bird\" se pronuncia 'berd'; la 'i' suena como una 'e' relajada.", nEn: "\"Bird\" is pronounced 'berd', with the 'i' like a soft 'er'." },
    "loc-vave02": { e: "We get fresh eggs from the hen every morning.", t: "Recogemos huevos frescos de la gallina cada mañana.", s: "Al hablar de la gallina hembra que pone huevos.", sEn: "When talking about the female chicken that lays eggs.", n: "\"Hen\" se pronuncia 'jen', con 'h' aspirada y 'e' corta.", nEn: "\"Hen\" is pronounced 'hen', with a short 'e'." },
    "loc-vave03": { e: "The rooster wakes everyone up early on the farm.", t: "El gallo despierta a todos temprano en la granja.", s: "Al hablar del ave macho que canta al amanecer.", sEn: "When talking about the male bird that crows at dawn.", n: "\"Rooster\" lleva el acento al inicio: RÚS-ter; en el Reino Unido dicen 'cockerel'.", nEn: "\"Rooster\" is stressed at the start: ROO-ster; in the UK they say 'cockerel'." },
    "loc-vave04": { e: "The children love feeding the ducks by the pond.", t: "A los niños les encanta dar de comer a los patos junto al estanque.", s: "Al hablar del ave de agua de pico ancho.", sEn: "When talking about the broad-billed water bird.", n: "\"Duck\" se pronuncia 'dak', con 'u' corta como en 'cup'.", nEn: "\"Duck\" is pronounced 'duck', with a short 'u' like 'cup'." },
    "loc-vave05": { e: "A goose can be louder and bolder than a duck.", t: "Un ganso puede ser más ruidoso y atrevido que un pato.", s: "Al hablar del ave de agua grande de cuello largo.", sEn: "When talking about the large, long-necked water bird.", n: "\"Goose\" es singular; el plural es 'geese', no 'gooses'.", nEn: "\"Goose\" is singular; the plural is 'geese', not 'gooses'." },
    "loc-vave06": { e: "We serve turkey for the big holiday dinner.", t: "Servimos pavo en la gran cena de las fiestas.", s: "Al hablar del ave grande que se come en fiestas.", sEn: "When talking about the large bird eaten on holidays.", n: "\"Turkey\" lleva el acento al inicio: TÉR-ki.", nEn: "\"Turkey\" is stressed at the start: TUR-key." },
    "loc-vave07": { e: "You can sometimes see an eagle flying over the mountains.", t: "A veces se puede ver un águila volando sobre las montañas.", s: "Al hablar del ave grande de presa.", sEn: "When talking about the large bird of prey.", n: "\"Eagle\" lleva el acento al inicio: Í-gol, con 'ea' como 'i' larga.", nEn: "\"Eagle\" is stressed at the start: EE-gle, with 'ea' like a long 'ee'." },
    "loc-vave08": { e: "An owl hunts at night and sleeps during the day.", t: "Un búho caza de noche y duerme durante el día.", s: "Al hablar del ave nocturna de ojos grandes.", sEn: "When talking about the night bird with big eyes.", n: "\"Owl\" se pronuncia 'ául', en una sílaba, como 'how' con 'l'.", nEn: "\"Owl\" is pronounced 'owl', one syllable, like 'how' with an 'l'." },
    "loc-vave09": { e: "The hotel has a parrot that says hello to the guests.", t: "El hotel tiene un loro que les dice hola a los huéspedes.", s: "Al hablar del ave colorida que puede imitar voces.", sEn: "When talking about the colorful bird that can mimic voices.", n: "\"Parrot\" lleva el acento al inicio: PÉ-rot.", nEn: "\"Parrot\" is stressed at the start: PA-rrot." },
    "loc-vave10": { e: "There are always pigeons in the main square.", t: "Siempre hay palomas en la plaza principal.", s: "Al hablar del ave gris común de las ciudades.", sEn: "When talking about the common gray city bird.", n: "\"Pigeon\" se pronuncia 'PÍ-yon'; la 'g' suena como la 'j' inglesa (sonido de 'y' fuerte, no la 'g' de 'gato').", nEn: "\"Pigeon\" is pronounced 'PI-jun'; the 'g' is soft like 'j'." },
    "loc-vave11": { e: "The kids want to see the penguins at the aquarium.", t: "Los niños quieren ver los pingüinos en el acuario.", s: "Al hablar del ave de zonas frías que no vuela.", sEn: "When talking about the cold-climate bird that doesn't fly.", n: "\"Penguin\" lleva el acento al inicio: PÉN-guin.", nEn: "\"Penguin\" is stressed at the start: PEN-gwin." },
    "loc-vave12": { e: "There's a beautiful white swan on the lake.", t: "Hay un hermoso cisne blanco en el lago.", s: "Al hablar del ave elegante de cuello largo del agua.", sEn: "When talking about the elegant long-necked water bird.", n: "\"Swan\" se pronuncia 'suon'; la 'w' suena como 'u'.", nEn: "\"Swan\" is pronounced 'swon', with the 'w' like a soft 'w'." },
    "loc-vave13": { e: "Watch your food, the seagulls here are very bold.", t: "Cuida tu comida, las gaviotas de aquí son muy atrevidas.", s: "Al hablar del ave blanca y gris de la playa.", sEn: "When talking about the white-and-gray beach bird.", n: "\"Seagull\" lleva el acento al inicio: SÍ-gal.", nEn: "\"Seagull\" is stressed at the start: SEA-gull." },
    "loc-vave14": { e: "A tiny hummingbird visits the flowers in the garden.", t: "Un colibrí diminuto visita las flores del jardín.", s: "Al hablar del ave pequeñísima que vuela muy rápido.", sEn: "When talking about the tiny bird that flies very fast.", n: "\"Hummingbird\" lleva el acento al inicio: JÁ-ming-berd.", nEn: "\"Hummingbird\" is stressed at the start: HUM-ming-bird." },
    "loc-vave15": { e: "The ostrich is the biggest bird, but it can't fly.", t: "El avestruz es el ave más grande, pero no puede volar.", s: "Al hablar del ave enorme de patas largas.", sEn: "When talking about the huge long-legged bird.", n: "\"Ostrich\" lleva el acento al inicio: ÓS-trich.", nEn: "\"Ostrich\" is stressed at the start: OS-trich." },
    "loc-vave16": { e: "Look at the little yellow chick following the hen.", t: "Mira el pollito amarillo siguiendo a la gallina.", s: "Al hablar de la cría recién nacida de la gallina.", sEn: "When talking about the newly hatched baby chicken.", n: "\"Chick\" se pronuncia 'chik', con 'i' corta como en 'sit'.", nEn: "\"Chick\" is pronounced 'chik', with a short 'i' like 'sit'." },
    "loc-vmvi01": { e: "We serve fresh fish caught the same morning.", t: "Servimos pescado fresco capturado la misma mañana.", s: "Al hablar del animal del agua o del plato de pescado.", sEn: "When talking about the water animal or the fish dish.", n: "\"Fish\" sirve para singular y plural; no digas 'fishes' normalmente.", nEn: "\"Fish\" works for singular and plural; you usually don't say 'fishes'." },
    "loc-vmvi02": { e: "Don't worry, there are no sharks near this beach.", t: "No te preocupes, no hay tiburones cerca de esta playa.", s: "Al hablar del gran pez depredador del mar.", sEn: "When talking about the large ocean predator fish.", n: "\"Shark\" se pronuncia 'shark', con 'sh' suave al inicio.", nEn: "\"Shark\" is pronounced 'shark', with a soft 'sh' at the start." },
    "loc-vmvi03": { e: "You can sometimes see a whale from the boat tour.", t: "A veces se puede ver una ballena desde el tour en barco.", s: "Al hablar del enorme mamífero marino.", sEn: "When talking about the huge sea mammal.", n: "\"Whale\" se pronuncia 'uéil'; la 'wh' suena como una 'u' suave.", nEn: "\"Whale\" is pronounced 'wayl', with 'wh' like a soft 'w'." },
    "loc-vmvi04": { e: "The kids saw a dolphin jump right next to the boat.", t: "Los niños vieron un delfín saltar justo al lado del barco.", s: "Al hablar del mamífero marino juguetón e inteligente.", sEn: "When talking about the playful, smart sea mammal.", n: "\"Dolphin\" lleva el acento al inicio: DÓL-fin, con 'ph' como 'f'.", nEn: "\"Dolphin\" is stressed at the start: DOL-fin, with 'ph' like 'f'." },
    "loc-vmvi05": { e: "We have grilled octopus on today's special menu.", t: "Tenemos pulpo a la parrilla en el menú especial de hoy.", s: "Al hablar del animal marino de ocho brazos.", sEn: "When talking about the eight-armed sea animal.", n: "\"Octopus\" lleva el acento al inicio: ÓK-to-pus.", nEn: "\"Octopus\" is stressed at the start: OC-to-pus." },
    "loc-vmvi06": { e: "The crab soup is one of our most popular dishes.", t: "La sopa de cangrejo es uno de nuestros platos más populares.", s: "Al hablar del animal marino de caparazón y pinzas.", sEn: "When talking about the sea animal with a shell and claws.", n: "\"Crab\" se pronuncia 'krab', con 'a' corta como en 'cat'.", nEn: "\"Crab\" is pronounced 'krab', with a short 'a' like 'cat'." },
    "loc-vmvi07": { e: "Fresh lobster is a bit pricey but worth it.", t: "La langosta fresca es un poco cara pero vale la pena.", s: "Al hablar del marisco grande de pinzas, muy apreciado.", sEn: "When talking about the large prized clawed shellfish.", n: "\"Lobster\" lleva el acento al inicio: LÓBS-ter.", nEn: "\"Lobster\" is stressed at the start: LOB-ster." },
    "loc-vmvi08": { e: "Would you like the shrimp as a starter?", t: "¿Desea los camarones como entrada?", s: "Al ofrecer mariscos pequeños en el menú.", sEn: "When offering small shellfish on the menu.", n: "\"Shrimp\" se usa en EE. UU.; en el Reino Unido dicen 'prawn'.", nEn: "\"Shrimp\" is used in the US; in the UK they say 'prawn'." },
    "loc-vmvi09": { e: "Be careful swimming, there are jellyfish in the water today.", t: "Ten cuidado al nadar, hoy hay medusas en el agua.", s: "Al advertir sobre el animal marino que puede picar.", sEn: "When warning about the sea animal that can sting.", n: "\"Jellyfish\" lleva el acento al inicio: YÉ-li-fish; igual en plural.", nEn: "\"Jellyfish\" is stressed at the start: JEL-ly-fish; same in plural." },
    "loc-vmvi10": { e: "We saw a sea turtle while snorkeling near the reef.", t: "Vimos una tortuga marina mientras buceábamos cerca del arrecife.", s: "Al hablar del animal marino de caparazón duro.", sEn: "When talking about the hard-shelled sea animal.", n: "\"Turtle\" lleva el acento al inicio: TÉR-tol.", nEn: "\"Turtle\" is stressed at the start: TUR-tle." },
    "loc-vmvi11": { e: "The kids found a starfish on the sand.", t: "Los niños encontraron una estrella de mar en la arena.", s: "Al hablar del animal marino con forma de estrella.", sEn: "When talking about the star-shaped sea animal.", n: "\"Starfish\" lleva el acento al inicio: STAR-fish; igual en plural.", nEn: "\"Starfish\" is stressed at the start: STAR-fish; same in plural." },
    "loc-vmvi12": { e: "There are seals resting on the rocks by the shore.", t: "Hay focas descansando en las rocas junto a la orilla.", s: "Al hablar del mamífero marino que descansa en las rocas.", sEn: "When talking about the sea mammal that rests on rocks.", n: "\"Seal\" se pronuncia 'sil', con 'ea' como 'i' larga.", nEn: "\"Seal\" is pronounced 'seel', with 'ea' like a long 'ee'." },
    "loc-vmvi13": { e: "Please don't touch the coral when you're snorkeling.", t: "Por favor no toques el coral cuando hagas snorkel.", s: "Al hablar del organismo del arrecife marino.", sEn: "When talking about the marine reef organism.", n: "\"Coral\" lleva el acento al inicio: KÓ-ral.", nEn: "\"Coral\" is stressed at the start: CO-ral." },
    "loc-vmvi14": { e: "The oysters are very fresh, served on ice.", t: "Las ostras están muy frescas, servidas sobre hielo.", s: "Al ofrecer este marisco de concha en el menú.", sEn: "When offering this shelled shellfish on the menu.", n: "\"Oyster\" lleva el acento al inicio: ÓIS-ter, con 'oy' como en 'boy'.", nEn: "\"Oyster\" is stressed at the start: OY-ster, with 'oy' like 'boy'." },
    "loc-vmvi15": { e: "We saw a tiny seahorse holding onto the coral.", t: "Vimos un caballito de mar diminuto agarrado al coral.", s: "Al hablar del pequeño animal marino con forma de caballo.", sEn: "When talking about the small horse-shaped sea animal.", n: "\"Seahorse\" lleva el acento al inicio: SÍ-jors.", nEn: "\"Seahorse\" is stressed at the start: SEA-horse." },
    "loc-vmvi16": { e: "The fried squid is a favorite with tourists.", t: "El calamar frito es uno de los favoritos de los turistas.", s: "Al hablar del animal marino de tentáculos que se come.", sEn: "When talking about the edible tentacled sea animal.", n: "\"Squid\" se pronuncia 'skuid'; sirve para singular y plural.", nEn: "\"Squid\" is pronounced 'skwid'; it works for singular and plural." },
    "loc-vins01": { e: "There's a bee buzzing around the dessert table on the terrace.", t: "Hay una abeja zumbando alrededor de la mesa de postres en la terraza.", s: "Cuando avisas a un huésped sobre un insecto cerca de la comida al aire libre.", sEn: "When you warn a guest about an insect near the food outdoors.", n: "\"Bee\" se pronuncia con 'i' larga, como en 'see'.", nEn: "\"Bee\" has a long 'ee' sound, like in 'see'." },
    "loc-vins02": { e: "Please don't leave sugar out, or you'll get an ant problem.", t: "Por favor no dejes el azúcar afuera, o tendrás un problema de hormigas.", s: "Cuando hablas de higiene en la cocina o el almacén.", sEn: "When you talk about hygiene in the kitchen or storeroom.", n: "El plural es \"ants\", con la 's' bien marcada.", nEn: "The plural is \"ants\", with a clear 's' at the end." },
    "loc-vins03": { e: "There's a fly in the dining room; could you grab the swatter?", t: "Hay una mosca en el comedor; ¿puedes traer el matamoscas?", s: "Cuando un insecto entra al área de los clientes.", sEn: "When an insect gets into the customer area.", n: "El plural de \"fly\" es \"flies\", con 'ies'.", nEn: "The plural of \"fly\" is \"flies\", spelled with 'ies'." },
    "loc-vins04": { e: "We have mosquito repellent at the desk if you're heading outside.", t: "Tenemos repelente de mosquitos en la recepción si va a salir.", s: "Cuando ofreces repelente a un huésped que sale de noche.", sEn: "When you offer repellent to a guest going out at night.", n: "\"Mosquito\" se dice \"mos-KÍ-tou\", con la 'qu' como 'k'.", nEn: "\"Mosquito\" is said \"mos-KEE-toh\", with the 'qu' like 'k'." },
    "loc-vins05": { e: "Don't worry, that spider is harmless and keeps the bugs away.", t: "No se preocupe, esa araña es inofensiva y mantiene alejados a los bichos.", s: "Cuando tranquilizas a un huésped que vio una araña.", sEn: "When you reassure a guest who spotted a spider.", n: "El plural es \"spiders\"; la primera vocal es el diptongo 'ái', como en 'SPÁI-der'.", nEn: "The plural is \"spiders\"; the first vowel is the long 'eye' diphthong, as in \"SPY-der\"." },
    "loc-vins06": { e: "There's a beautiful butterfly in the garden the guests love to photograph.", t: "Hay una hermosa mariposa en el jardín que a los huéspedes les encanta fotografiar.", s: "Cuando hablas de la fauna del jardín con un huésped.", sEn: "When you talk about the garden's wildlife with a guest.", n: "El plural es \"butterflies\", con 'ies' al final.", nEn: "The plural is \"butterflies\", ending in 'ies'." },
    "loc-vins07": { e: "A beetle landed on the table, but it's totally harmless.", t: "Un escarabajo se posó en la mesa, pero es completamente inofensivo.", s: "Cuando calmas a un cliente que vio un insecto en la mesa.", sEn: "When you calm a customer who saw an insect on the table.", n: "\"Beetle\" suena \"BÍ-tol\", parecido a \"Beatles\".", nEn: "\"Beetle\" sounds like \"BEE-tul\", close to \"Beatles\"." },
    "loc-vins08": { e: "You'll hear a grasshopper or two out on the patio in the evening.", t: "Escuchará uno que otro saltamontes en el patio por la tarde.", s: "Cuando describes el ambiente nocturno del lugar a un huésped.", sEn: "When you describe the evening atmosphere to a guest.", n: "El acento va en la primera sílaba: GRÁS-hopper.", nEn: "The stress is on the first syllable: GRASS-hopper." },
    "loc-vins09": { e: "Look, there's a dragonfly hovering over the pool.", t: "Mire, hay una libélula volando sobre la piscina.", s: "Cuando señalas algo bonito de la naturaleza a un huésped.", sEn: "When you point out something pretty in nature to a guest.", n: "El plural es \"dragonflies\", con 'ies'.", nEn: "The plural is \"dragonflies\", ending in 'ies'." },
    "loc-vins10": { e: "Be careful, there's a wasp near the juice; it can sting.", t: "Tenga cuidado, hay una avispa cerca del jugo; puede picar.", s: "Cuando adviertes a un cliente de un insecto que pica.", sEn: "When you warn a customer about a stinging insect.", n: "\"Wasp\" se dice \"uosp\"; la 'a' suena como 'o'.", nEn: "\"Wasp\" is said \"wosp\"; the 'a' sounds like 'o'." },
    "loc-vins11": { e: "If you ever see a cockroach, let us know and we'll handle it right away.", t: "Si alguna vez ve una cucaracha, avísenos y nos encargamos enseguida.", s: "Cuando tranquilizas a un huésped sobre el control de plagas.", sEn: "When you reassure a guest about pest control.", n: "\"Cockroach\" se acorta a \"roach\" en lenguaje casual.", nEn: "\"Cockroach\" is often shortened to \"roach\" in casual speech." },
    "loc-vins12": { e: "The kids found a fuzzy caterpillar on a leaf in the garden.", t: "Los niños encontraron una oruga peluda en una hoja del jardín.", s: "Cuando comentas algo curioso del jardín a una familia.", sEn: "When you mention something curious in the garden to a family.", n: "El plural es \"caterpillars\"; el acento va al inicio: KÁ-terpillar.", nEn: "The plural is \"caterpillars\"; stress the start: CAT-erpillar." },
    "loc-vins13": { e: "After the rain, you'll see the odd worm on the path.", t: "Después de la lluvia, verá uno que otro gusano en el camino.", s: "Cuando explicas algo del entorno tras la lluvia.", sEn: "When you explain something about the grounds after rain.", n: "\"Worm\" se dice \"uerm\"; la 'w' es como 'u'.", nEn: "\"Worm\" is said \"werm\"; the 'w' is a soft 'w' sound." },
    "loc-vins14": { e: "At night the garden fills with the glow of a firefly here and there.", t: "De noche el jardín se llena con el brillo de alguna luciérnaga.", s: "Cuando describes una escena nocturna bonita a un huésped.", sEn: "When you describe a pretty nighttime scene to a guest.", n: "El plural es \"fireflies\"; también se dice \"lightning bug\" en EE. UU.", nEn: "The plural is \"fireflies\"; in the US it's also called a \"lightning bug\"." },
    "loc-vins15": { e: "There's a snail on the wall by the entrance — kind of cute, actually.", t: "Hay un caracol en el muro de la entrada; bastante simpático, la verdad.", s: "Cuando charlas de forma ligera con un huésped en la puerta.", sEn: "When you make light conversation with a guest at the door.", n: "\"Snail\" se dice \"snéil\"; rima con \"mail\".", nEn: "\"Snail\" rhymes with \"mail\"." },
    "loc-vins16": { e: "A ladybug landed on her hand and she was thrilled.", t: "Una mariquita se le posó en la mano y quedó encantada.", s: "Cuando comentas un momento simpático con una niña o huésped.", sEn: "When you mention a sweet moment with a child or guest.", n: "En el Reino Unido se dice \"ladybird\" en lugar de \"ladybug\".", nEn: "In the UK people say \"ladybird\" instead of \"ladybug\"." },
    "loc-vpos01": { e: "We baked a fresh cake this morning if you'd like a slice.", t: "Horneamos un pastel fresco esta mañana si desea una rebanada.", s: "Cuando ofreces el postre del día a un cliente.", sEn: "When you offer the dessert of the day to a customer.", n: "\"Cake\" se dice \"kéik\"; una porción es \"a slice of cake\".", nEn: "\"Cake\" sounds like \"kayk\"; a portion is \"a slice of cake\"." },
    "loc-vpos02": { e: "Would you like a cookie with your coffee?", t: "¿Desea una galleta con su café?", s: "Cuando acompañas un café con algo dulce.", sEn: "When you pair a coffee with something sweet.", n: "En el Reino Unido se dice \"biscuit\" en vez de \"cookie\".", nEn: "In the UK people say \"biscuit\" instead of \"cookie\"." },
    "loc-vpos03": { e: "For dessert we have vanilla or chocolate ice cream.", t: "De postre tenemos helado de vainilla o de chocolate.", s: "Cuando ofreces opciones de postre a la mesa.", sEn: "When you offer dessert options to the table.", n: "\"Ice cream\" son dos palabras; el acento cae en \"ice\".", nEn: "\"Ice cream\" is two words; the stress falls on \"ice\"." },
    "loc-vpos04": { e: "This dessert is made with real dark chocolate.", t: "Este postre está hecho con chocolate amargo de verdad.", s: "Cuando describes los ingredientes de un postre a un cliente.", sEn: "When you describe a dessert's ingredients to a customer.", n: "\"Chocolate\" suena \"CHÓK-lit\", solo dos sílabas en inglés.", nEn: "\"Chocolate\" sounds like \"CHOK-lit\", just two syllables in English." },
    "loc-vpos05": { e: "We leave a little candy on the pillow for our guests.", t: "Dejamos un caramelo en la almohada para nuestros huéspedes.", s: "Cuando explicas un detalle del servicio del hotel.", sEn: "When you explain a small touch of the hotel's service.", n: "\"Candy\" es incontable en general; di \"some candy\", no \"a candy\".", nEn: "\"Candy\" is usually uncountable; say \"some candy\", not \"a candy\"." },
    "loc-vpos06": { e: "The apple pie is homemade and still warm.", t: "El pay de manzana es casero y todavía está tibio.", s: "Cuando recomiendas un postre recién hecho.", sEn: "When you recommend a freshly made dessert.", n: "\"Pie\" se dice \"pái\"; rima con \"my\".", nEn: "\"Pie\" rhymes with \"my\"." },
    "loc-vpos07": { e: "We have fresh donuts with the morning coffee.", t: "Tenemos donas frescas con el café de la mañana.", s: "Cuando describes el desayuno disponible a un huésped.", sEn: "When you describe the available breakfast to a guest.", n: "También se escribe \"doughnut\"; \"donut\" es la forma corta.", nEn: "It's also spelled \"doughnut\"; \"donut\" is the short form." },
    "loc-vpos08": { e: "The custard is our most popular dessert here.", t: "El flan es nuestro postre más popular aquí.", s: "Cuando recomiendas el postre estrella de la casa.", sEn: "When you recommend the house's signature dessert.", n: "El flan latino se traduce como \"custard\" o \"flan\" en inglés.", nEn: "Latin flan is translated as \"custard\" or simply \"flan\" in English." },
    "loc-vpos09": { e: "Would you like some honey for your tea?", t: "¿Desea un poco de miel para su té?", s: "Cuando ofreces acompañamientos para una bebida caliente.", sEn: "When you offer add-ons for a hot drink.", n: "\"Honey\" se dice \"JÁ-ni\"; la 'o' suena como 'a'.", nEn: "\"Honey\" is said \"HUH-nee\"; the 'o' sounds like 'uh'." },
    "loc-vpos10": { e: "We serve toast with butter and jam for breakfast.", t: "Servimos pan tostado con mantequilla y mermelada en el desayuno.", s: "Cuando describes lo que incluye el desayuno.", sEn: "When you describe what breakfast includes.", n: "\"Jam\" se dice \"yam\"; la 'j' suena como en \"jeep\".", nEn: "\"Jam\" starts with the 'j' sound as in \"jeep\"." },
    "loc-vpos11": { e: "Would you like a pancake or two with maple syrup?", t: "¿Desea uno o dos panqueques con jarabe de maple?", s: "Cuando ofreces opciones de desayuno dulce.", sEn: "When you offer sweet breakfast options.", n: "El acento va en la primera sílaba: PÁN-cake.", nEn: "The stress is on the first syllable: PAN-cake." },
    "loc-vpos12": { e: "The kids can toast a marshmallow by the fire tonight.", t: "Los niños pueden tostar un malvavisco junto al fuego esta noche.", s: "Cuando describes una actividad nocturna a una familia.", sEn: "When you describe an evening activity to a family.", n: "\"Marshmallow\" suena \"MARSH-me-lou\", con la 'a' final relajada.", nEn: "\"Marshmallow\" sounds like \"MARSH-muh-low\", with a relaxed final vowel." },
    "loc-vpos13": { e: "We give each child a lollipop on the way out.", t: "Le damos una paleta a cada niño a la salida.", s: "Cuando explicas un detalle simpático para los niños.", sEn: "When you explain a sweet touch for children.", n: "El acento va en la primera sílaba: LÓ-li-pop.", nEn: "The stress is on the first syllable: LOL-li-pop." },
    "loc-vpos14": { e: "Sorry, please don't stick your gum under the table.", t: "Disculpe, por favor no pegue su chicle debajo de la mesa.", s: "Cuando pides amablemente a un cliente que no haga algo.", sEn: "When you politely ask a customer not to do something.", n: "\"Gum\" es incontable; di \"some gum\" o \"a piece of gum\".", nEn: "\"Gum\" is uncountable; say \"some gum\" or \"a piece of gum\"." },
    "loc-vpos15": { e: "Today's pudding is made with coconut and a touch of cinnamon.", t: "El budín de hoy está hecho con coco y un toque de canela.", s: "Cuando describes el postre del día a un cliente.", sEn: "When you describe the dessert of the day to a customer.", n: "En el Reino Unido \"pudding\" también significa \"postre\" en general.", nEn: "In the UK \"pudding\" can also mean \"dessert\" in general." },
    "loc-vpos16": { e: "We can offer fruit Jell-O if you prefer something light.", t: "Podemos ofrecer una gelatina de fruta si prefiere algo ligero.", s: "Cuando sugieres un postre suave a un cliente.", sEn: "When you suggest a light dessert to a customer.", n: "En EE. UU. \"jelly\" es una mermelada clara (sin trozos) y \"jam\" es la mermelada con trozos de fruta; el postre que tiembla se llama \"Jell-O\" o \"gelatin\".", nEn: "In the US \"jelly\" is a clear fruit spread, and \"jam\" is the fruit spread with pieces of fruit; the wobbly dessert is \"Jell-O\" or \"gelatin\"." },
    "loc-vesp01": { e: "Would you like a little more salt on your dish?", t: "¿Desea un poco más de sal en su plato?", s: "Cuando ofreces ajustar el sazón de un plato.", sEn: "When you offer to adjust the seasoning of a dish.", n: "\"Salt\" se dice \"solt\"; la 'a' suena como 'o'.", nEn: "\"Salt\" is said \"sawlt\"; the 'a' sounds like 'aw'." },
    "loc-vesp02": { e: "There's salt and pepper on every table.", t: "Hay sal y pimienta en cada mesa.", s: "Cuando indicas dónde están los condimentos.", sEn: "When you point out where the condiments are.", n: "\"Pepper\" se dice \"PÉ-per\", con doble 'p' suave.", nEn: "\"Pepper\" is said \"PEP-er\", with a soft double 'p'." },
    "loc-vesp03": { e: "This sauce has a bit of fresh garlic in it.", t: "Esta salsa tiene un poco de ajo fresco.", s: "Cuando describes los ingredientes de un plato.", sEn: "When you describe a dish's ingredients.", n: "\"Garlic\" es incontable; di \"some garlic\", no \"a garlic\".", nEn: "\"Garlic\" is uncountable; say \"some garlic\", not \"a garlic\"." },
    "loc-vesp04": { e: "We sprinkle a little cinnamon on the coffee.", t: "Espolvoreamos un poco de canela sobre el café.", s: "Cuando describes un toque especial de una bebida.", sEn: "When you describe a special touch on a drink.", n: "\"Cinnamon\" se acentúa al inicio: SÍ-na-mon.", nEn: "\"Cinnamon\" is stressed at the start: CIN-na-mon." },
    "loc-vesp05": { e: "The tea has fresh ginger, which is great for the stomach.", t: "El té lleva jengibre fresco, que es muy bueno para el estómago.", s: "Cuando recomiendas una bebida por sus beneficios.", sEn: "When you recommend a drink for its benefits.", n: "\"Ginger\" se dice \"YÍN-yer\", con la 'g' suave.", nEn: "\"Ginger\" is said \"JIN-jer\", with a soft 'g'." },
    "loc-vesp06": { e: "The beans are seasoned with a little cumin.", t: "Los frijoles están sazonados con un poco de comino.", s: "Cuando explicas el sabor de un platillo a un cliente.", sEn: "When you explain the flavor of a dish to a customer.", n: "\"Cumin\" se dice \"KIÚ-min\" o \"KÁ-min\", ambas válidas.", nEn: "\"Cumin\" can be said \"KYOO-min\" or \"KUH-min\"; both are fine." },
    "loc-vesp07": { e: "We garnish the plate with a little fresh parsley.", t: "Adornamos el plato con un poco de perejil fresco.", s: "Cuando describes la presentación de un plato.", sEn: "When you describe how a dish is presented.", n: "\"Parsley\" se acentúa al inicio: PARS-li.", nEn: "\"Parsley\" is stressed at the start: PARS-ley." },
    "loc-vesp08": { e: "Some people love cilantro and some really don't.", t: "A algunas personas les encanta el cilantro y a otras de plano no.", s: "Cuando preguntas o comentas sobre una hierba divisiva.", sEn: "When you ask about or comment on a divisive herb.", n: "En el Reino Unido la hoja se llama \"coriander\".", nEn: "In the UK the leaf is called \"coriander\"." },
    "loc-vesp09": { e: "The pizza sauce has tomato, garlic, and oregano.", t: "La salsa de la pizza lleva tomate, ajo y orégano.", s: "Cuando enumeras los ingredientes de un platillo.", sEn: "When you list a dish's ingredients.", n: "En inglés se dice \"o-RÉ-ga-nou\", distinto del español.", nEn: "In English it's \"o-REG-a-no\", with the stress in the middle." },
    "loc-vesp10": { e: "We top the pasta with a few leaves of fresh basil.", t: "Coronamos la pasta con unas hojas de albahaca fresca.", s: "Cuando describes el toque final de un plato.", sEn: "When you describe the finishing touch of a dish.", n: "En EE. UU. \"basil\" se dice \"BÉI-sol\"; en el Reino Unido \"BÁ-sol\".", nEn: "In the US \"basil\" is \"BAY-zil\"; in the UK it's \"BAZ-il\"." },
    "loc-vesp11": { e: "Would you like a sprig of mint in your lemonade?", t: "¿Desea una ramita de menta en su limonada?", s: "Cuando ofreces un detalle especial en una bebida.", sEn: "When you offer a special touch in a drink.", n: "\"Mint\" se dice tal cual; la 'i' es corta, como en \"sit\".", nEn: "\"Mint\" has a short 'i', like in \"sit\"." },
    "loc-vesp12": { e: "There's a hint of nutmeg in the sauce.", t: "Hay un toque de nuez moscada en la salsa.", s: "Cuando describes un sabor sutil de un plato.", sEn: "When you describe a subtle flavor in a dish.", n: "\"Nutmeg\" se acentúa al inicio: NÁT-meg.", nEn: "\"Nutmeg\" is stressed at the start: NUT-meg." },
    "loc-vesp13": { e: "Careful, the chili makes this dish quite spicy.", t: "Cuidado, el chile hace que este plato sea bastante picante.", s: "Cuando adviertes a un cliente sobre lo picante de un plato.", sEn: "When you warn a customer that a dish is spicy.", n: "\"Chili\" es el ají; \"chilly\" (con doble l) significa \"frío\".", nEn: "\"Chili\" is the pepper; \"chilly\" (double l) means \"cold\"." },
    "loc-vesp14": { e: "The curry is mild, so it's not too spicy.", t: "El curry es suave, así que no pica mucho.", s: "Cuando tranquilizas a un cliente sobre el nivel de picante.", sEn: "When you reassure a customer about the spice level.", n: "\"Curry\" se dice \"KÉ-ri\"; la 'u' suena como 'e'.", nEn: "\"Curry\" is said \"CUH-ree\"; the 'u' sounds like 'uh'." },
    "loc-vesp15": { e: "This ice cream is made with real vanilla.", t: "Este helado está hecho con vainilla de verdad.", s: "Cuando destacas la calidad de un ingrediente.", sEn: "When you highlight the quality of an ingredient.", n: "\"Vanilla\" se dice \"va-NÍ-la\", con el acento en medio.", nEn: "\"Vanilla\" is said \"va-NIL-a\", stressed in the middle." },
    "loc-vesp16": { e: "The rice gets its color from a pinch of saffron.", t: "El arroz toma su color de una pizca de azafrán.", s: "Cuando explicas qué le da color o sabor a un plato.", sEn: "When you explain what gives a dish its color or flavor.", n: "\"Saffron\" se acentúa al inicio: SÁ-fron.", nEn: "\"Saffron\" is stressed at the start: SAF-fron." },
    "loc-vmed01": { e: "The pool is about ten meters long.", t: "La piscina mide unos diez metros de largo.", s: "Cuando das medidas de una instalación a un huésped.", sEn: "When you give a guest the measurements of a facility.", n: "En EE. UU. se escribe \"meter\"; en el Reino Unido \"metre\".", nEn: "In the US it's spelled \"meter\"; in the UK \"metre\"." },
    "loc-vmed02": { e: "The shelf is just a few centimeters too narrow for that bag.", t: "El estante es demasiado angosto por unos pocos centímetros para esa maleta.", s: "Cuando explicas por qué algo no cabe en un espacio.", sEn: "When you explain why something doesn't fit in a space.", n: "Se abrevia \"cm\"; el acento va al inicio: SÉN-ti-meter.", nEn: "It's abbreviated \"cm\"; the stress is on the start: CEN-ti-meter." },
    "loc-vmed03": { e: "The beach is about two kilometers from the hotel.", t: "La playa está a unos dos kilómetros del hotel.", s: "Cuando indicas una distancia a un huésped.", sEn: "When you give a guest a distance.", n: "Se abrevia \"km\"; el acento puede ir en \"ki-LÓ-meter\".", nEn: "It's abbreviated \"km\"; one common stress is \"ki-LOM-eter\"." },
    "loc-vmed04": { e: "Each guest gets a free liter of water on arrival.", t: "Cada huésped recibe un litro de agua gratis al llegar.", s: "Cuando explicas una cortesía del hotel.", sEn: "When you explain a complimentary touch from the hotel.", n: "En EE. UU. se escribe \"liter\"; en el Reino Unido \"litre\".", nEn: "In the US it's spelled \"liter\"; in the UK \"litre\"." },
    "loc-vmed05": { e: "The fish was about a kilo, so it easily fed four.", t: "El pescado pesaba como un kilo, así que alcanzó para cuatro sin problema.", s: "Cuando hablas de cantidades en la cocina.", sEn: "When you talk about quantities in the kitchen.", n: "\"Kilo\" es la forma corta de \"kilogram\".", nEn: "\"Kilo\" is the short form of \"kilogram\"." },
    "loc-vmed06": { e: "The recipe needs two hundred grams of flour.", t: "La receta necesita doscientos gramos de harina.", s: "Cuando lees o explicas una receta a un compañero.", sEn: "When you read or explain a recipe to a coworker.", n: "Se abrevia \"g\"; el plural es \"grams\".", nEn: "It's abbreviated \"g\"; the plural is \"grams\"." },
    "loc-vmed07": { e: "Add about a pound of tomatoes to the sauce.", t: "Agrega como una libra de tomates a la salsa.", s: "Cuando das cantidades en medidas de EE. UU. en la cocina.", sEn: "When you give quantities in US units in the kitchen.", n: "\"Pound\" se abrevia \"lb\" y equivale a unos 454 gramos.", nEn: "\"Pound\" is abbreviated \"lb\" and is about 454 grams." },
    "loc-vmed08": { e: "The gap under the door is about an inch.", t: "El espacio debajo de la puerta es como de una pulgada.", s: "Cuando describes una medida pequeña a un huésped o técnico.", sEn: "When you describe a small measurement to a guest or repair tech.", n: "El plural es \"inches\"; una pulgada son unos 2,5 cm.", nEn: "The plural is \"inches\"; one inch is about 2.5 cm." },
    "loc-vmed09": { e: "The ceiling is about ten feet high in the lobby.", t: "El techo del lobby mide como diez pies de alto.", s: "Cuando describes el tamaño de un espacio a un huésped.", sEn: "When you describe the size of a space to a guest.", n: "El plural de \"foot\" es \"feet\", irregular.", nEn: "The plural of \"foot\" is \"feet\", an irregular form." },
    "loc-vmed10": { e: "The nearest town is just a mile down the road.", t: "El pueblo más cercano está a apenas una milla por la carretera.", s: "Cuando indicas una distancia corta a un huésped.", sEn: "When you give a guest a short distance.", n: "Una milla son unos 1,6 kilómetros; el plural es \"miles\".", nEn: "One mile is about 1.6 kilometers; the plural is \"miles\"." },
    "loc-vmed11": { e: "You can have half now and take the other half to go.", t: "Puede comer la mitad ahora y llevarse la otra mitad.", s: "Cuando ofreces partir una porción para un cliente.", sEn: "When you offer to split a portion for a customer.", n: "El plural es \"halves\"; la 'l' es muda en \"half\".", nEn: "The plural is \"halves\"; the 'l' is silent in \"half\"." },
    "loc-vmed12": { e: "We bake a fresh dozen rolls every morning.", t: "Horneamos una docena de panecillos frescos cada mañana.", s: "Cuando hablas de cantidades de panadería o cocina.", sEn: "When you talk about bakery or kitchen quantities.", n: "Tras un número, \"dozen\" no lleva 's': \"two dozen eggs\".", nEn: "After a number, \"dozen\" takes no 's': \"two dozen eggs\"." },
    "loc-vmed13": { e: "We left a fresh pair of slippers in your room.", t: "Dejamos un par de pantuflas nuevas en su habitación.", s: "Cuando explicas un detalle de cortesía de la habitación.", sEn: "When you explain a complimentary touch in the room.", n: "\"A pair of\" va con cosas de dos partes: shoes, gloves, slippers.", nEn: "\"A pair of\" goes with two-part things: shoes, gloves, slippers." },
    "loc-vmed14": { e: "There's a weight limit of twenty kilos per bag on that flight.", t: "Hay un límite de peso de veinte kilos por maleta en ese vuelo.", s: "Cuando informas a un huésped sobre reglas de equipaje.", sEn: "When you inform a guest about luggage rules.", n: "\"Weight\" se dice \"uéit\"; la 'gh' es muda.", nEn: "\"Weight\" is said \"wayt\"; the 'gh' is silent." },
    "loc-vmed15": { e: "There's a height limit on the pool slide for safety.", t: "Hay un límite de altura en el tobogán de la piscina por seguridad.", s: "Cuando explicas una regla de seguridad a un huésped.", sEn: "When you explain a safety rule to a guest.", n: "\"Height\" se dice \"jáit\", rima con \"light\"; la 'gh' es muda.", nEn: "\"Height\" is said \"hyte\", rhyming with \"light\"; the 'gh' is silent." },
    "loc-vmed16": { e: "What size bed would you prefer, a double or a queen?", t: "¿Qué tamaño de cama prefiere, matrimonial o queen?", s: "Cuando preguntas las preferencias de habitación de un huésped.", sEn: "When you ask a guest about their room preferences.", n: "\"Size\" se dice \"sáis\"; la 's' final suena como 'z'.", nEn: "\"Size\" is said \"syze\"; the final 's' sounds like 'z'." },
    "loc-vdir01": { e: "Turn left at the next corner to reach the station.", t: "Da vuelta a la izquierda en la próxima esquina para llegar a la estación.", s: "Cuando le das indicaciones a alguien que pregunta por una dirección.", sEn: "When you give directions to someone asking the way.", n: "\"Left\" se pronuncia \"left\" con una 'e' corta; no la conviertas en 'leeft'.", nEn: "\"Left\" has a short 'e'; don't stretch it into 'leeft'." },
    "loc-vdir02": { e: "The bathroom is on the right, just past the stairs.", t: "El baño está a la derecha, justo pasando las escaleras.", s: "Cuando indicas dónde queda algo dentro de un edificio.", sEn: "When you point out where something is inside a building.", n: "\"Right\" significa tanto \"derecha\" como \"correcto\"; el contexto lo aclara.", nEn: "\"Right\" means both \"the right side\" and \"correct\"; context tells them apart." },
    "loc-vdir03": { e: "Go straight for two blocks and you'll see the hotel.", t: "Siga derecho dos cuadras y verá el hotel.", s: "Cuando explicas un camino sin vueltas a un turista.", sEn: "When you explain a route with no turns to a tourist.", n: "Suele decirse \"go straight\" o \"straight ahead\"; ambas son naturales.", nEn: "People say \"go straight\" or \"straight ahead\"; both are natural." },
    "loc-vdir04": { e: "The rooms are up on the second floor.", t: "Las habitaciones están arriba, en el segundo piso.", s: "Cuando señalas que algo está en un nivel más alto.", sEn: "When you point out that something is on a higher level.", n: "\"Up\" es cortito; para subir escaleras di \"go up the stairs\".", nEn: "\"Up\" is short; to climb stairs say \"go up the stairs\"." },
    "loc-vdir05": { e: "The restrooms are down the hall on your left.", t: "Los baños están abajo por el pasillo, a su izquierda.", s: "Cuando indicas que algo está en un nivel más bajo o más adelante.", sEn: "When you point out something on a lower level or further along.", n: "\"Down\" se pronuncia \"dáun\"; rima con \"town\".", nEn: "\"Down\" is pronounced \"down\"; it rhymes with \"town\"." },
    "loc-vdir06": { e: "There's a nice café very near the hotel.", t: "Hay una cafetería muy linda cerca del hotel.", s: "Cuando recomiendas un lugar que queda a poca distancia.", sEn: "When you recommend a place that's a short distance away.", n: "\"Near\" se pronuncia \"nir\"; no agregues una 'e' al inicio.", nEn: "\"Near\" sounds like \"nir\"; don't add an 'e' at the start." },
    "loc-vdir07": { e: "The beach is a bit far, so I'd take a taxi.", t: "La playa queda un poco lejos, así que yo tomaría un taxi.", s: "Cuando adviertes que un lugar está a buena distancia.", sEn: "When you warn that a place is quite a distance away.", n: "\"Far\" es el opuesto de \"near\"; ambos son cortos y fáciles de recordar.", nEn: "\"Far\" is the opposite of \"near\"; both are short and easy to remember." },
    "loc-vdir08": { e: "Please sign here, and your room is ready.", t: "Por favor firme aquí, y su habitación está lista.", s: "Cuando señalas un lugar exacto cerca de ti.", sEn: "When you point to an exact spot close to you.", n: "\"Here\" es cerca de quien habla; \"there\" es lejos.", nEn: "\"Here\" is close to the speaker; \"there\" is farther away." },
    "loc-vdir09": { e: "The bus stop is right there, across the street.", t: "La parada del autobús está ahí mismo, cruzando la calle.", s: "Cuando señalas algo que está a la vista pero un poco lejos.", sEn: "When you point at something visible but a bit away.", n: "No confundas \"there\" (lugar) con \"their\" (de ellos); suenan igual.", nEn: "Don't mix up \"there\" (place) with \"their\" (belonging to them); they sound alike." },
    "loc-vdir10": { e: "You can wait inside where it's warm.", t: "Puede esperar adentro, donde hace calor.", s: "Cuando invitas a alguien a pasar al interior.", sEn: "When you invite someone to come into a building.", n: "\"Inside\" lleva el acento en la segunda sílaba: in-SIDE.", nEn: "\"Inside\" is stressed on the second syllable: in-SIDE." },
    "loc-vdir11": { e: "The tables outside have a great view of the sea.", t: "Las mesas de afuera tienen una vista hermosa del mar.", s: "Cuando ofreces sentarse al aire libre.", sEn: "When you offer seating in the open air.", n: "\"Outside\" es lo opuesto de \"inside\"; acento en SIDE.", nEn: "\"Outside\" is the opposite of \"inside\"; stress on SIDE." },
    "loc-vdir12": { e: "Just walk forward and the exit is on your right.", t: "Solo camine hacia adelante y la salida está a su derecha.", s: "Cuando guías a alguien a seguir avanzando.", sEn: "When you guide someone to keep moving ahead.", n: "\"Forward\" lleva el acento al inicio: FOR-ward.", nEn: "\"Forward\" is stressed at the start: FOR-ward." },
    "loc-vdir13": { e: "I'll be right back, I just need to go to the back.", t: "Ya vuelvo, solo necesito ir al fondo.", s: "Cuando te refieres a la parte trasera de un lugar.", sEn: "When you refer to the rear part of a place.", n: "\"Back\" sirve para \"atrás\", \"regresar\" y \"la espalda\"; el contexto lo define.", nEn: "\"Back\" can mean the rear, to return, or your back; context decides." },
    "loc-vdir14": { e: "The old town is to the north of the river.", t: "El casco antiguo está al norte del río.", s: "Cuando orientas a alguien con los puntos cardinales.", sEn: "When you orient someone using compass directions.", n: "\"North\" lleva el sonido 'th' suave; saca un poco la lengua.", nEn: "\"North\" has the soft 'th' sound; put your tongue out a little." },
    "loc-vdir15": { e: "The beaches in the south are warmer this time of year.", t: "Las playas del sur son más cálidas en esta época del año.", s: "Cuando describes una región usando los puntos cardinales.", sEn: "When you describe a region using compass directions.", n: "\"South\" termina en 'th'; no lo cambies por una 's' ('saus').", nEn: "\"South\" ends in 'th'; don't turn it into an 's' ('sauss')." },
    "loc-vdir16": { e: "The pharmacy is between the bank and the bakery.", t: "La farmacia está entre el banco y la panadería.", s: "Cuando ubicas algo respecto a dos puntos de referencia.", sEn: "When you locate something relative to two landmarks.", n: "\"Between\" se usa para dos cosas; para más di \"among\".", nEn: "\"Between\" is for two things; for more than two use \"among\"." },
    "loc-vprg01": { e: "What time does the bus leave?", t: "¿A qué hora sale el autobús?", s: "Cuando preguntas por información concreta sobre algo.", sEn: "When you ask for specific information about something.", n: "\"What\" se pronuncia \"uot\"; la 'h' no suena.", nEn: "\"What\" is pronounced \"wot\"; the 'h' is silent." },
    "loc-vprg02": { e: "Who is in charge here?", t: "¿Quién está a cargo aquí?", s: "Cuando preguntas por una persona.", sEn: "When you ask about a person.", n: "\"Who\" se pronuncia \"ju\"; la 'w' no suena.", nEn: "\"Who\" is pronounced \"hoo\"; the 'w' is silent." },
    "loc-vprg03": { e: "Where is the nearest ATM?", t: "¿Dónde está el cajero automático más cercano?", s: "Cuando preguntas por el lugar de algo.", sEn: "When you ask about the location of something.", n: "\"Where\" suena casi igual que \"wear\" (vestir); el contexto los separa.", nEn: "\"Where\" sounds almost like \"wear\" (clothing); context tells them apart." },
    "loc-vprg04": { e: "When does the store open?", t: "¿Cuándo abre la tienda?", s: "Cuando preguntas por el momento o la hora de algo.", sEn: "When you ask about the time of something.", n: "\"When\" se pronuncia \"uen\"; no alargues la 'e'.", nEn: "\"When\" is pronounced \"wen\"; don't stretch the 'e'." },
    "loc-vprg05": { e: "Why is the road closed today?", t: "¿Por qué está cerrada la calle hoy?", s: "Cuando preguntas por la razón de algo.", sEn: "When you ask about the reason for something.", n: "\"Why\" pide la razón; \"because\" da la respuesta.", nEn: "\"Why\" asks for the reason; \"because\" gives the answer." },
    "loc-vprg06": { e: "How do I get to the train station?", t: "¿Cómo llego a la estación de tren?", s: "Cuando preguntas de qué manera hacer o llegar a algo.", sEn: "When you ask in what way to do or reach something.", n: "\"How\" se pronuncia \"jáu\"; rima con \"now\".", nEn: "\"How\" is pronounced \"how\"; it rhymes with \"now\"." },
    "loc-vprg07": { e: "Which bus goes to the airport?", t: "¿Cuál autobús va al aeropuerto?", s: "Cuando preguntas entre opciones específicas.", sEn: "When you ask among specific options.", n: "Usa \"which\" cuando hay opciones limitadas; \"what\" es más abierto.", nEn: "Use \"which\" when the options are limited; \"what\" is more open-ended." },
    "loc-vprg08": { e: "How much does a ticket cost?", t: "¿Cuánto cuesta un boleto?", s: "Cuando preguntas por el precio o una cantidad incontable.", sEn: "When you ask about price or an uncountable amount.", n: "\"How much\" va con cosas incontables (dinero, agua); \"how many\" con contables.", nEn: "\"How much\" goes with uncountable things (money, water); \"how many\" with countable ones." },
    "loc-vprg09": { e: "How many people are in your group?", t: "¿Cuántas personas hay en su grupo?", s: "Cuando preguntas por una cantidad de cosas que se cuentan.", sEn: "When you ask about a number of countable things.", n: "\"How many\" siempre va seguido de un plural: \"how many people\".", nEn: "\"How many\" is always followed by a plural: \"how many people\"." },
    "loc-vprg10": { e: "Whose bag is this on the seat?", t: "¿De quién es esta bolsa en el asiento?", s: "Cuando preguntas a quién pertenece algo.", sEn: "When you ask who something belongs to.", n: "\"Whose\" suena igual que \"who's\" (who is); ojo al escribir.", nEn: "\"Whose\" sounds like \"who's\" (who is); watch the spelling." },
    "loc-vprg11": { e: "What time does breakfast start?", t: "¿A qué hora empieza el desayuno?", s: "Cuando preguntas por la hora exacta de un evento.", sEn: "When you ask about the exact time of an event.", n: "\"What time\" es la forma natural; evita \"at what hour\".", nEn: "\"What time\" is the natural form; avoid \"at what hour\"." },
    "loc-vprg12": { e: "How far is the beach from here?", t: "¿Qué tan lejos está la playa de aquí?", s: "Cuando preguntas por la distancia a un lugar.", sEn: "When you ask about the distance to a place.", n: "\"How far\" pregunta por distancia; la respuesta puede ir en cuadras o minutos.", nEn: "\"How far\" asks about distance; the answer can be in blocks or minutes." },
    "loc-vprg13": { e: "How often does the bus come?", t: "¿Qué tan seguido pasa el autobús?", s: "Cuando preguntas por la frecuencia de algo.", sEn: "When you ask about how frequently something happens.", n: "Se responde con \"every...\": \"every ten minutes\".", nEn: "It's answered with \"every...\": \"every ten minutes\"." },
    "loc-vprg14": { e: "How long does the tour take?", t: "¿Cuánto tiempo dura el tour?", s: "Cuando preguntas por la duración de algo.", sEn: "When you ask about the duration of something.", n: "\"How long\" también puede preguntar por largo físico; el contexto lo aclara.", nEn: "\"How long\" can also ask about physical length; context makes it clear." },
    "loc-vprg15": { e: "Where are you from?", t: "¿De dónde eres?", s: "Cuando preguntas por el origen o país de alguien.", sEn: "When you ask about someone's origin or country.", n: "El \"from\" va al final: \"where are you from?\", no \"from where are you\".", nEn: "The \"from\" goes at the end: \"where are you from?\", not \"from where are you\"." },
    "loc-vprg16": { e: "Where to? I can call you a taxi.", t: "¿Hacia dónde? Le puedo pedir un taxi.", s: "Cuando preguntas hacia qué destino va alguien.", sEn: "When you ask what destination someone is heading to.", n: "\"Where to?\" es una forma corta y natural de preguntar el destino.", nEn: "\"Where to?\" is a short, natural way to ask the destination." },
    "loc-vprn01": { e: "I can help you with that right now.", t: "Yo puedo ayudarle con eso ahora mismo.", s: "Cuando hablas de ti mismo como sujeto de la oración.", sEn: "When you talk about yourself as the subject of the sentence.", n: "\"I\" siempre se escribe con mayúscula, incluso en medio de la frase.", nEn: "\"I\" is always capitalized, even in the middle of a sentence." },
    "loc-vprn02": { e: "You can leave your bags here if you like.", t: "Tú puedes dejar tus maletas aquí si quieres.", s: "Cuando te diriges a la persona con quien hablas.", sEn: "When you address the person you're speaking to.", n: "\"You\" sirve para singular y plural; el inglés no distingue como \"tú/ustedes\".", nEn: "\"You\" works for singular and plural; English doesn't split it like \"tú/ustedes\"." },
    "loc-vprn03": { e: "He is the manager, he can help you.", t: "Él es el gerente, él puede ayudarle.", s: "Cuando hablas de un hombre o niño.", sEn: "When you talk about a man or boy.", n: "\"He\" se pronuncia \"ji\" con 'i' larga; no lo acortes a \"je\".", nEn: "\"He\" is pronounced \"hee\" with a long 'i'; don't shorten it." },
    "loc-vprn04": { e: "She works at the front desk in the mornings.", t: "Ella trabaja en la recepción por las mañanas.", s: "Cuando hablas de una mujer o niña.", sEn: "When you talk about a woman or girl.", n: "\"She\" empieza con el sonido 'sh', como pedir silencio.", nEn: "\"She\" starts with the 'sh' sound, like asking for silence." },
    "loc-vprn05": { e: "We open at eight every morning.", t: "Nosotros abrimos a las ocho cada mañana.", s: "Cuando hablas de ti y de otras personas juntas.", sEn: "When you talk about yourself together with others.", n: "\"We\" se pronuncia \"uí\" con 'i' larga; rima con \"see\".", nEn: "\"We\" is pronounced \"wee\" with a long 'i'; it rhymes with \"see\"." },
    "loc-vprn06": { e: "They are waiting for a table outside.", t: "Ellos están esperando una mesa afuera.", s: "Cuando hablas de varias personas o cosas.", sEn: "When you talk about several people or things.", n: "\"They\" sirve para personas y cosas, sin género.", nEn: "\"They\" works for people and things, with no gender." },
    "loc-vprn07": { e: "This is my first day on the job.", t: "Este es mi primer día en el trabajo.", s: "Cuando indicas que algo te pertenece.", sEn: "When you show that something belongs to you.", n: "\"My\" va antes del sustantivo: \"my room\"; \"mine\" va solo.", nEn: "\"My\" goes before the noun: \"my room\"; \"mine\" stands alone." },
    "loc-vprn08": { e: "Your room is ready, here is the key.", t: "Su habitación está lista, aquí está la llave.", s: "Cuando indicas que algo pertenece a la persona con quien hablas.", sEn: "When you show that something belongs to the person you're speaking to.", n: "No confundas \"your\" (tu) con \"you're\" (you are); suenan igual.", nEn: "Don't mix up \"your\" (belonging) with \"you're\" (you are); they sound alike." },
    "loc-vprn09": { e: "Is this his suitcase by the door?", t: "¿Es esta su maleta (de él) junto a la puerta?", s: "Cuando indicas que algo pertenece a un hombre.", sEn: "When you show that something belongs to a man.", n: "\"His\" se usa solo para hombres; para mujeres es \"her\".", nEn: "\"His\" is only for men; for women it's \"her\"." },
    "loc-vprn10": { e: "Her flight leaves early tomorrow.", t: "Su vuelo (de ella) sale temprano mañana.", s: "Cuando indicas que algo pertenece a una mujer.", sEn: "When you show that something belongs to a woman.", n: "\"Her\" es tanto \"su (de ella)\" como \"a ella\"; el contexto lo aclara.", nEn: "\"Her\" means both \"her\" (possession) and \"her\" (object); context tells them apart." },
    "loc-vprn11": { e: "Our restaurant is just around the corner.", t: "Nuestro restaurante está a la vuelta de la esquina.", s: "Cuando indicas que algo nos pertenece a un grupo que te incluye.", sEn: "When you show that something belongs to a group including you.", n: "\"Our\" se pronuncia \"áur\", parecido a \"hour\" (hora).", nEn: "\"Our\" is pronounced \"our\", like \"hour\"." },
    "loc-vprn12": { e: "This is the best table in the house.", t: "Esta es la mejor mesa del lugar.", s: "Cuando señalas algo cercano a ti.", sEn: "When you point at something close to you.", n: "\"This\" es para algo cercano; \"that\" para algo más lejano.", nEn: "\"This\" is for something near; \"that\" for something farther." },
    "loc-vprn13": { e: "That is the room with the sea view.", t: "Esa es la habitación con vista al mar.", s: "Cuando señalas algo un poco alejado de ti.", sEn: "When you point at something a bit away from you.", n: "\"That\" se pronuncia \"dat\" con 'th' suave al inicio.", nEn: "\"That\" is pronounced \"that\" with a soft 'th' at the start." },
    "loc-vprn14": { e: "These are fresh from the kitchen.", t: "Estos están recién hechos de la cocina.", s: "Cuando señalas varias cosas cercanas a ti.", sEn: "When you point at several things close to you.", n: "\"These\" es el plural de \"this\"; ambos para cosas cercanas.", nEn: "\"These\" is the plural of \"this\"; both for nearby things." },
    "loc-vprn15": { e: "Those tables by the window are reserved.", t: "Esas mesas junto a la ventana están reservadas.", s: "Cuando señalas varias cosas alejadas de ti.", sEn: "When you point at several things farther away.", n: "\"Those\" es el plural de \"that\"; ambos para cosas lejanas.", nEn: "\"Those\" is the plural of \"that\"; both for things farther away." },
    "loc-vprn16": { e: "Someone left a phone at the table.", t: "Alguien dejó un teléfono en la mesa.", s: "Cuando hablas de una persona sin saber quién es.", sEn: "When you talk about a person without knowing who it is.", n: "\"Someone\" lleva el acento al inicio: SOME-one.", nEn: "\"Someone\" is stressed at the start: SOME-one." },
    "loc-vpai01": { e: "I'm from the United States.", t: "Soy de Estados Unidos.", s: "Cuando dices de qué país vienes o eres.", sEn: "When you say which country you come from or are from.", n: "En inglés los países se escriben con mayúscula: \"United States\".", nEn: "In English country names are capitalized: \"United States\"." },
    "loc-vpai02": { e: "She was born in England.", t: "Ella nació en Inglaterra.", s: "Al hablar del lugar de nacimiento u origen de alguien.", sEn: "When talking about someone's birthplace or origin.", n: "\"England\" lleva mayúscula y no es lo mismo que el Reino Unido entero.", nEn: "\"England\" is capitalized and isn't the same as the whole United Kingdom." },
    "loc-vpai03": { e: "We're moving to Canada next year.", t: "Nos mudamos a Canadá el próximo año.", s: "Cuando hablas de viajar o mudarte a otro país.", sEn: "When you talk about traveling or moving to another country.", n: "En inglés \"Canada\" lleva mayúscula y el acento va en la primera sílaba.", nEn: "In English \"Canada\" is capitalized and stressed on the first syllable." },
    "loc-vpai04": { e: "Mexico shares a long border with the United States.", t: "México comparte una larga frontera con Estados Unidos.", s: "Al hablar de geografía o de países vecinos.", sEn: "When talking about geography or neighboring countries.", n: "En inglés se escribe \"Mexico\", sin acento y con mayúscula.", nEn: "In English it's written \"Mexico\", without an accent and capitalized." },
    "loc-vpai05": { e: "My grandparents are from Spain.", t: "Mis abuelos son de España.", s: "Cuando hablas del origen de tu familia.", sEn: "When you talk about where your family is from.", n: "En inglés \"Spain\" lleva mayúscula y suena \"spéin\".", nEn: "In English \"Spain\" is capitalized and sounds like \"spayn\"." },
    "loc-vpai06": { e: "Paris is the capital of France.", t: "París es la capital de Francia.", s: "Al mencionar países o sus capitales.", sEn: "When mentioning countries or their capitals.", n: "En inglés \"France\" lleva mayúscula y la 'a' suena como en \"cat\".", nEn: "In English \"France\" is capitalized and the 'a' sounds like in \"cat\"." },
    "loc-vpai07": { e: "He studied engineering in Germany.", t: "Él estudió ingeniería en Alemania.", s: "Cuando hablas de dónde alguien estudió o trabajó.", sEn: "When you talk about where someone studied or worked.", n: "En inglés \"Germany\" lleva mayúscula y empieza con sonido 'y' suave: YÉR-ma-ni.", nEn: "In English \"Germany\" is capitalized and starts with a soft 'j' sound: JER-ma-ni." },
    "loc-vpai08": { e: "We spent two weeks traveling around Italy.", t: "Pasamos dos semanas viajando por Italia.", s: "Cuando cuentas sobre un viaje a otro país.", sEn: "When you tell someone about a trip to another country.", n: "En inglés \"Italy\" lleva mayúscula y el acento va en la primera sílaba.", nEn: "In English \"Italy\" is capitalized and stressed on the first syllable." },
    "loc-vpai09": { e: "Brazil is famous for its beaches and soccer.", t: "Brasil es famoso por sus playas y su fútbol.", s: "Al describir o presentar un país.", sEn: "When describing or introducing a country.", n: "En inglés \"Brazil\" se escribe con 'z' y lleva mayúscula.", nEn: "In English \"Brazil\" is spelled with a 'z' and is capitalized." },
    "loc-vpai10": { e: "China has the largest population in the world.", t: "China tiene la población más grande del mundo.", s: "Cuando das un dato sobre un país.", sEn: "When you share a fact about a country.", n: "En inglés \"China\" lleva mayúscula y la 'ch' suena como en \"church\".", nEn: "In English \"China\" is capitalized and the 'ch' sounds like in \"church\"." },
    "loc-vpai11": { e: "I'd love to visit Japan someday.", t: "Me encantaría visitar Japón algún día.", s: "Cuando hablas de un país que quieres conocer.", sEn: "When you talk about a country you'd like to visit.", n: "En inglés \"Japan\" lleva mayúscula y el acento va en la segunda sílaba: ya-PÁN.", nEn: "In English \"Japan\" is capitalized and stressed on the second syllable: ja-PAN." },
    "loc-vpai12": { e: "Colombia is known for its coffee.", t: "Colombia es conocida por su café.", s: "Al hablar de productos o cultura de un país.", sEn: "When talking about a country's products or culture.", n: "En inglés \"Colombia\" lleva mayúscula y se escribe con 'o', no con 'u'.", nEn: "In English \"Colombia\" is capitalized and spelled with an 'o', not a 'u'." },
    "loc-vpai13": { e: "Argentina is in South America.", t: "Argentina está en Sudamérica.", s: "Cuando ubicas un país en un continente.", sEn: "When you locate a country on a continent.", n: "En inglés \"Argentina\" lleva mayúscula y la 'g' suena como 'y' suave.", nEn: "In English \"Argentina\" is capitalized and the 'g' sounds like a soft 'j'." },
    "loc-vpai14": { e: "My cousin lives in Australia.", t: "Mi primo vive en Australia.", s: "Cuando dices dónde vive un familiar o amigo.", sEn: "When you say where a relative or friend lives.", n: "En inglés \"Australia\" lleva mayúscula y suena os-TRÉI-lia.", nEn: "In English \"Australia\" is capitalized and sounds like aw-STRAY-lia." },
    "loc-vpai15": { e: "India is a country with many languages.", t: "India es un país con muchos idiomas.", s: "Al describir las características de un país.", sEn: "When describing a country's features.", n: "En inglés \"India\" lleva mayúscula y el acento va en la primera sílaba.", nEn: "In English \"India\" is capitalized and stressed on the first syllable." },
    "loc-vpai16": { e: "The pyramids are in Egypt.", t: "Las pirámides están en Egipto.", s: "Cuando mencionas dónde queda un lugar famoso.", sEn: "When you mention where a famous place is located.", n: "En inglés \"Egypt\" lleva mayúscula y suena Í-yipt, no \"egipto\".", nEn: "In English \"Egypt\" is capitalized and sounds like EE-jipt, not \"egipto\"." },
    "loc-vnac01": { e: "She is American.", t: "Ella es estadounidense.", s: "Cuando dices la nacionalidad de alguien.", sEn: "When you say someone's nationality.", n: "En inglés las nacionalidades se escriben con mayúscula: \"American\".", nEn: "In English nationalities are capitalized: \"American\"." },
    "loc-vnac02": { e: "He is English, from London.", t: "Él es inglés, de Londres.", s: "Al presentar de dónde es una persona.", sEn: "When introducing where a person is from.", n: "\"English\" siempre con mayúscula, ya sea la nacionalidad o el idioma.", nEn: "\"English\" is always capitalized, whether it's the nationality or the language." },
    "loc-vnac03": { e: "My boss is Canadian.", t: "Mi jefe es canadiense.", s: "Cuando hablas de la nacionalidad de alguien que conoces.", sEn: "When you mention the nationality of someone you know.", n: "En inglés \"Canadian\" lleva mayúscula y el acento va en la sílaba NÉI.", nEn: "In English \"Canadian\" is capitalized and stressed on the NAY syllable." },
    "loc-vnac04": { e: "The food here is authentic Mexican.", t: "La comida aquí es auténtica mexicana.", s: "Al describir comida, cultura o personas de un país.", sEn: "When describing food, culture, or people from a country.", n: "En inglés \"Mexican\" lleva mayúscula aunque describa comida o cosas.", nEn: "In English \"Mexican\" is capitalized even when it describes food or things." },
    "loc-vnac05": { e: "I'm learning Spanish at school.", t: "Estoy aprendiendo español en la escuela.", s: "Al hablar de un idioma o de la nacionalidad.", sEn: "When talking about a language or nationality.", n: "En inglés \"Spanish\" siempre lleva mayúscula, como idioma y como nacionalidad.", nEn: "In English \"Spanish\" is always capitalized, as a language and a nationality." },
    "loc-vnac06": { e: "She speaks French fluently.", t: "Ella habla francés con fluidez.", s: "Cuando mencionas qué idioma habla alguien.", sEn: "When you mention what language someone speaks.", n: "En inglés \"French\" lleva mayúscula y termina con sonido \"ch\".", nEn: "In English \"French\" is capitalized and ends with a \"ch\" sound." },
    "loc-vnac07": { e: "Our new neighbor is German.", t: "Nuestro nuevo vecino es alemán.", s: "Al hablar de la nacionalidad de un vecino o conocido.", sEn: "When talking about a neighbor's or acquaintance's nationality.", n: "En inglés \"German\" lleva mayúscula y empieza con 'y' suave: YÉR-man.", nEn: "In English \"German\" is capitalized and starts with a soft 'j': JER-man." },
    "loc-vnac08": { e: "He is Italian and cooks amazing pasta.", t: "Él es italiano y cocina una pasta increíble.", s: "Cuando describes a una persona y su origen.", sEn: "When describing a person and their origin.", n: "En inglés \"Italian\" lleva mayúscula y el acento va en la sílaba TÁ.", nEn: "In English \"Italian\" is capitalized and stressed on the TA syllable." },
    "loc-vnac09": { e: "The team has a Brazilian coach.", t: "El equipo tiene un entrenador brasileño.", s: "Al mencionar el origen de alguien en un grupo.", sEn: "When mentioning someone's origin within a group.", n: "En inglés \"Brazilian\" lleva mayúscula y se escribe con 'z'.", nEn: "In English \"Brazilian\" is capitalized and spelled with a 'z'." },
    "loc-vnac10": { e: "My coworker is Chinese.", t: "Mi compañero de trabajo es chino.", s: "Cuando hablas de la nacionalidad de un compañero.", sEn: "When you talk about a coworker's nationality.", n: "En inglés \"Chinese\" lleva mayúscula y el acento va al final: chai-NÍS.", nEn: "In English \"Chinese\" is capitalized and stressed at the end: chai-NEES." },
    "loc-vnac11": { e: "The chef is Japanese.", t: "El chef es japonés.", s: "Al decir de dónde viene una persona.", sEn: "When saying where a person comes from.", n: "En inglés \"Japanese\" lleva mayúscula y el acento va al final: ya-pa-NÍS.", nEn: "In English \"Japanese\" is capitalized and stressed at the end: ja-pa-NEES." },
    "loc-vnac12": { e: "She is Colombian, from Medellín.", t: "Ella es colombiana, de Medellín.", s: "Cuando presentas de dónde es alguien.", sEn: "When you introduce where someone is from.", n: "En inglés \"Colombian\" lleva mayúscula y se escribe con 'o'.", nEn: "In English \"Colombian\" is capitalized and spelled with an 'o'." },
    "loc-vnac13": { e: "My friend is Argentine.", t: "Mi amigo es argentino.", s: "Al hablar de la nacionalidad de un amigo.", sEn: "When talking about a friend's nationality.", n: "En inglés \"Argentine\" lleva mayúscula; también se usa \"Argentinian\".", nEn: "In English \"Argentine\" is capitalized; \"Argentinian\" is also used." },
    "loc-vnac14": { e: "The tourist is Australian.", t: "El turista es australiano.", s: "Cuando describes de dónde viene un visitante.", sEn: "When describing where a visitor comes from.", n: "En inglés \"Australian\" lleva mayúscula y suena os-TRÉI-lian.", nEn: "In English \"Australian\" is capitalized and sounds like aw-STRAY-lian." },
    "loc-vnac15": { e: "Our doctor is Indian.", t: "Nuestro doctor es indio.", s: "Al mencionar el origen de un profesional.", sEn: "When mentioning a professional's origin.", n: "En inglés \"Indian\" lleva mayúscula y el acento va en la primera sílaba.", nEn: "In English \"Indian\" is capitalized and stressed on the first syllable." },
    "loc-vnac16": { e: "As a foreigner, I had to show my passport.", t: "Como extranjero, tuve que mostrar mi pasaporte.", s: "Cuando hablas de alguien de otro país en un trámite o viaje.", sEn: "When talking about someone from another country in paperwork or travel.", n: "\"Foreigner\" no lleva mayúscula y la 'g' es muda: FÓ-ri-ner.", nEn: "\"Foreigner\" is not capitalized and the 'g' is silent: FOR-i-ner." },
    "loc-vbel01": { e: "She put on her makeup before the party.", t: "Ella se puso maquillaje antes de la fiesta.", s: "Al hablar de productos que se usan en la cara.", sEn: "When talking about products you use on your face.", n: "\"Makeup\" suele escribirse como una sola palabra.", nEn: "\"Makeup\" is usually written as one word." },
    "loc-vbel02": { e: "I'm looking for a red lipstick.", t: "Estoy buscando un labial rojo.", s: "Cuando compras o pides un producto de belleza.", sEn: "When buying or asking for a beauty product.", n: "\"Lipstick\" junta \"lip\" (labio) y \"stick\" (barra).", nEn: "\"Lipstick\" combines \"lip\" and \"stick\"." },
    "loc-vbel03": { e: "This perfume smells like flowers.", t: "Este perfume huele a flores.", s: "Al describir un aroma o un regalo.", sEn: "When describing a scent or a gift.", n: "\"Perfume\" se parece al español, pero el acento va en la primera sílaba: PÉR-fium.", nEn: "\"Perfume\" looks like Spanish, but the stress is on the first syllable: PER-fume." },
    "loc-vbel04": { e: "Put some cream on your hands.", t: "Ponte un poco de crema en las manos.", s: "Cuando hablas de cuidado de la piel.", sEn: "When talking about skin care.", n: "\"Cream\" suena \"krim\", con 'i' larga.", nEn: "\"Cream\" sounds like \"kreem\", with a long 'e'." },
    "loc-vbel05": { e: "She painted her nails pink.", t: "Ella se pintó las uñas de rosa.", s: "Al hablar del cuidado de las manos.", sEn: "When talking about hand care.", n: "\"Nails\" es plural; una sola uña es \"a nail\".", nEn: "\"Nails\" is plural; a single one is \"a nail\"." },
    "loc-vbel06": { e: "Her hair is long and dark.", t: "Su cabello es largo y oscuro.", s: "Cuando describes el aspecto de alguien.", sEn: "When describing someone's appearance.", n: "\"Hair\" no lleva 's' aunque hables de mucho cabello.", nEn: "\"Hair\" has no 's' even when you mean a lot of it." },
    "loc-vbel07": { e: "I need a haircut this week.", t: "Necesito un corte de pelo esta semana.", s: "Cuando pides una cita en la peluquería.", sEn: "When booking an appointment at the hair salon.", n: "\"Haircut\" es una sola palabra y el acento va al inicio.", nEn: "\"Haircut\" is one word and the stress is at the start." },
    "loc-vbel08": { e: "She works at a hair salon downtown.", t: "Ella trabaja en un salón de belleza en el centro.", s: "Al hablar de dónde se hace tratamientos de belleza.", sEn: "When talking about where beauty services are done.", n: "\"Salon\" lleva el acento al final: sa-LÓN, parecido al español.", nEn: "\"Salon\" is stressed at the end: sa-LON, close to Spanish." },
    "loc-vbel09": { e: "He gets his beard trimmed at the barber shop.", t: "Él se recorta la barba en la barbería.", s: "Cuando hablas de cortes de pelo para hombres.", sEn: "When talking about men's haircuts.", n: "\"Barber shop\" también se escribe junto: \"barbershop\".", nEn: "\"Barber shop\" is also written together: \"barbershop\"." },
    "loc-vbel10": { e: "I bought a new bottle of nail polish.", t: "Compré un nuevo frasco de esmalte de uñas.", s: "Al comprar productos para las uñas.", sEn: "When buying products for your nails.", n: "\"Nail polish\" son dos palabras; \"polish\" significa esmalte o brillo.", nEn: "\"Nail polish\" is two words; \"polish\" means the coating or shine." },
    "loc-vbel11": { e: "Use this lotion to keep your skin soft.", t: "Usa esta loción para mantener la piel suave.", s: "Cuando hablas del cuidado de la piel del cuerpo.", sEn: "When talking about body skin care.", n: "\"Lotion\" suena LÓU-shon; la 'ti' suena como \"sh\".", nEn: "\"Lotion\" sounds like LOH-shun; the 'ti' sounds like \"sh\"." },
    "loc-vbel12": { e: "She wore blue eyeshadow tonight.", t: "Ella usó sombra de ojos azul esta noche.", s: "Al describir el maquillaje de los ojos.", sEn: "When describing eye makeup.", n: "\"Eyeshadow\" junta \"eye\" (ojo) y \"shadow\" (sombra).", nEn: "\"Eyeshadow\" combines \"eye\" and \"shadow\"." },
    "loc-vbel13": { e: "Mascara makes your eyelashes look longer.", t: "El rímel hace que tus pestañas se vean más largas.", s: "Cuando hablas de maquillaje para las pestañas.", sEn: "When talking about makeup for your eyelashes.", n: "En inglés se dice \"mascara\", no \"rímel\"; el acento va en KÁ.", nEn: "In English it's \"mascara\", not \"rímel\"; the stress is on KA." },
    "loc-vbel14": { e: "A little blush gives your cheeks color.", t: "Un poco de rubor le da color a las mejillas.", s: "Al hablar del maquillaje de las mejillas.", sEn: "When talking about makeup for your cheeks.", n: "\"Blush\" también significa sonrojarse.", nEn: "\"Blush\" also means to go red in the face." },
    "loc-vbel15": { e: "She matched the foundation to her skin tone.", t: "Ella combinó la base con su tono de piel.", s: "Cuando hablas de la base del maquillaje.", sEn: "When talking about the base layer of makeup.", n: "\"Foundation\" también significa cimientos de un edificio.", nEn: "\"Foundation\" also means the base of a building." },
    "loc-vbel16": { e: "Beauty is more than just looks.", t: "La belleza es más que solo la apariencia.", s: "Al hablar de belleza en general.", sEn: "When talking about beauty in general.", n: "\"Beauty\" suena BIÚ-ti; el grupo \"eau\" suena como 'iu'.", nEn: "\"Beauty\" sounds like BYOO-ty; the 'eau' makes a 'yoo' sound." },
    "loc-vlim01": { e: "Can you sweep the floor with the broom?", t: "¿Puedes barrer el piso con la escoba?", s: "Al pedir o usar herramientas de limpieza.", sEn: "When asking for or using cleaning tools.", n: "\"Broom\" suena \"brum\", con 'u' larga.", nEn: "\"Broom\" sounds like \"broom\", with a long 'oo'." },
    "loc-vlim02": { e: "I need to mop the kitchen with the mop.", t: "Necesito trapear la cocina con el trapeador.", s: "Cuando limpias pisos mojados.", sEn: "When cleaning wet floors.", n: "\"Mop\" es el objeto y también el verbo (trapear).", nEn: "\"Mop\" is both the object and the verb (to mop)." },
    "loc-vlim03": { e: "Wipe the table with a clean rag.", t: "Limpia la mesa con un trapo limpio.", s: "Al limpiar superficies con un paño.", sEn: "When cleaning surfaces with a cloth.", n: "\"Rag\" es un trapo viejo; un paño nuevo suele ser \"cloth\".", nEn: "\"Rag\" is an old cloth; a newer one is often \"cloth\"." },
    "loc-vlim04": { e: "Fill the bucket with warm water.", t: "Llena el balde con agua tibia.", s: "Cuando preparas agua para limpiar.", sEn: "When preparing water for cleaning.", n: "\"Bucket\" suena BÁ-ket; el acento va al inicio.", nEn: "\"Bucket\" sounds like BUCK-et; the stress is at the start." },
    "loc-vlim05": { e: "Add a little detergent to the water.", t: "Agrega un poco de detergente al agua.", s: "Al hablar de productos para lavar.", sEn: "When talking about washing products.", n: "\"Detergent\" lleva el acento en TÉR y la 'g' suena como 'y'.", nEn: "\"Detergent\" is stressed on TER and the 'g' sounds like 'j'." },
    "loc-vlim06": { e: "Wash your hands with soap.", t: "Lávate las manos con jabón.", s: "Cuando hablas de higiene o limpieza.", sEn: "When talking about hygiene or cleaning.", n: "\"Soap\" suena \"sóup\"; no lo confundas con \"soup\" (sopa).", nEn: "\"Soap\" sounds like \"sohp\"; don't confuse it with \"soup\"." },
    "loc-vlim07": { e: "Please take out the trash.", t: "Por favor saca la basura.", s: "Al pedir que se bote la basura.", sEn: "When asking someone to take out the garbage.", n: "En EE. UU. se dice \"trash\"; en el Reino Unido, \"rubbish\".", nEn: "In the US it's \"trash\"; in the UK, \"rubbish\"." },
    "loc-vlim08": { e: "Throw it in the trash can.", t: "Tíralo en el bote de basura.", s: "Cuando indicas dónde botar algo.", sEn: "When pointing out where to throw something away.", n: "\"Trash can\" son dos palabras; en el Reino Unido es \"bin\".", nEn: "\"Trash can\" is two words; in the UK it's \"bin\"." },
    "loc-vlim09": { e: "I'll vacuum the carpet with the vacuum.", t: "Voy a aspirar la alfombra con la aspiradora.", s: "Al limpiar alfombras o pisos con la máquina.", sEn: "When cleaning carpets or floors with the machine.", n: "\"Vacuum\" se escribe con doble 'u' y suena VÁ-kium.", nEn: "\"Vacuum\" is spelled with a double 'u' and sounds like VAK-yoom." },
    "loc-vlim10": { e: "Use a damp sponge to clean the sink.", t: "Usa una esponja húmeda para limpiar el lavabo.", s: "Cuando limpias superficies con una esponja.", sEn: "When cleaning surfaces with a sponge.", n: "\"Sponge\" suena \"spanch\"; la 'o' suena como 'a' corta.", nEn: "\"Sponge\" sounds like \"spunj\"; the 'o' sounds like a short 'u'." },
    "loc-vlim11": { e: "Wear gloves when you use bleach.", t: "Usa guantes cuando uses cloro.", s: "Al proteger las manos durante la limpieza.", sEn: "When protecting your hands while cleaning.", n: "\"Gloves\" es plural; un solo guante es \"a glove\".", nEn: "\"Gloves\" is plural; a single one is \"a glove\"." },
    "loc-vlim12": { e: "Be careful, bleach can stain your clothes.", t: "Ten cuidado, el cloro puede manchar tu ropa.", s: "Cuando usas productos fuertes de limpieza.", sEn: "When using strong cleaning products.", n: "En inglés es \"bleach\", no \"chlorine\", para el producto de limpieza.", nEn: "In English it's \"bleach\", not \"chlorine\", for the cleaning product." },
    "loc-vlim13": { e: "There's a lot of dust on the shelves.", t: "Hay mucho polvo en los estantes.", s: "Al notar suciedad que se acumula.", sEn: "When you notice built-up dirt.", n: "\"Dust\" también es verbo: \"to dust\" significa quitar el polvo.", nEn: "\"Dust\" is also a verb: \"to dust\" means to remove the dust." },
    "loc-vlim14": { e: "There's a stain on the carpet.", t: "Hay una mancha en la alfombra.", s: "Cuando señalas una marca que hay que limpiar.", sEn: "When pointing out a mark that needs cleaning.", n: "\"Stain\" suena \"stéin\", parecido a \"Spain\".", nEn: "\"Stain\" sounds like \"stayn\", similar to \"Spain\"." },
    "loc-vlim15": { e: "The room is clean now.", t: "El cuarto ya está limpio.", s: "Al decir que algo quedó sin suciedad.", sEn: "When saying something is free of dirt.", n: "\"Clean\" es adjetivo y verbo: \"to clean\" significa limpiar.", nEn: "\"Clean\" is both adjective and verb: \"to clean\" means to clean." },
    "loc-vlim16": { e: "These dishes are still dirty.", t: "Estos platos siguen sucios.", s: "Cuando algo necesita limpiarse.", sEn: "When something needs cleaning.", n: "\"Dirty\" suena DÉR-ti; es lo opuesto de \"clean\".", nEn: "\"Dirty\" sounds like DER-ty; it's the opposite of \"clean\"." },
    "loc-vemr01": { e: "Help! Someone call an ambulance!", t: "¡Ayuda! ¡Que alguien llame a una ambulancia!", s: "Cuando necesitas asistencia urgente.", sEn: "When you need urgent assistance.", n: "\"Help\" es palabra y grito de emergencia; también verbo: \"to help\".", nEn: "\"Help\" is both a word and an emergency shout; also a verb: \"to help\"." },
    "loc-vemr02": { e: "Call the police right away.", t: "Llama a la policía de inmediato.", s: "Al reportar un delito o emergencia.", sEn: "When reporting a crime or emergency.", n: "\"Police\" lleva el acento al final: po-LÍS.", nEn: "\"Police\" is stressed at the end: po-LEES." },
    "loc-vemr03": { e: "The firefighters arrived in minutes.", t: "Los bomberos llegaron en minutos.", s: "Cuando hablas de quién apaga un incendio.", sEn: "When talking about who puts out a fire.", n: "\"Firefighters\" junta \"fire\" (fuego) y \"fighters\" (luchadores).", nEn: "\"Firefighters\" combines \"fire\" and \"fighters\"." },
    "loc-vemr04": { e: "The ambulance took him to the hospital.", t: "La ambulancia lo llevó al hospital.", s: "Al hablar de una emergencia médica.", sEn: "When talking about a medical emergency.", n: "\"Ambulance\" lleva el acento al inicio: ÁM-biu-lans.", nEn: "\"Ambulance\" is stressed at the start: AM-byoo-lans." },
    "loc-vemr05": { e: "There's a fire in the building!", t: "¡Hay un incendio en el edificio!", s: "Cuando alertas sobre un incendio.", sEn: "When warning about a fire.", n: "\"Fire\" suena \"fáir\"; también significa despedir a alguien del trabajo.", nEn: "\"Fire\" sounds like \"fire\"; it also means to dismiss someone from a job." },
    "loc-vemr06": { e: "Stay back, there's danger ahead.", t: "Quédate atrás, hay peligro adelante.", s: "Al advertir sobre una situación de riesgo.", sEn: "When warning about a risky situation.", n: "\"Danger\" suena DÉIN-yer; la 'g' suena como 'y' suave.", nEn: "\"Danger\" sounds like DAIN-jer; the 'g' is a soft 'j'." },
    "loc-vemr07": { e: "There was a car accident on the highway.", t: "Hubo un accidente de auto en la carretera.", s: "Cuando reportas un choque o suceso.", sEn: "When reporting a crash or incident.", n: "\"Accident\" lleva el acento al inicio: ÁK-si-dent.", nEn: "\"Accident\" is stressed at the start: AK-si-dent." },
    "loc-vemr08": { e: "This is an emergency, please hurry.", t: "Esto es una emergencia, por favor apúrese.", s: "Al pedir ayuda urgente.", sEn: "When asking for urgent help.", n: "\"Emergency\" lleva el acento en MÉR: i-MÉR-yen-si.", nEn: "\"Emergency\" is stressed on MER: i-MER-jen-si." },
    "loc-vemr09": { e: "She was taken to the hospital last night.", t: "La llevaron al hospital anoche.", s: "Cuando hablas de atención médica.", sEn: "When talking about medical care.", n: "\"Hospital\" se parece al español, pero la 'h' se aspira: JÓS-pi-tal.", nEn: "\"Hospital\" looks like Spanish, but the 'h' is breathed out: HOS-pi-tal." },
    "loc-vemr10": { e: "Two people were injured in the crash.", t: "Dos personas resultaron heridas en el choque.", s: "Al hablar de personas lastimadas en un accidente.", sEn: "When talking about people hurt in an accident.", n: "\"Injured\" suena ÍN-yerd; la 'j' suena como 'y' suave.", nEn: "\"Injured\" sounds like IN-jurd; the 'j' is a soft 'j'." },
    "loc-vemr11": { e: "Stop that thief!", t: "¡Detengan a ese ladrón!", s: "Cuando alguien te roba algo.", sEn: "When someone steals something from you.", n: "\"Thief\" suena \"zif\" con la 'th' suave; el plural es \"thieves\".", nEn: "\"Thief\" has a soft \"th\" sound; the plural is \"thieves\"." },
    "loc-vemr12": { e: "There was a robbery at the store.", t: "Hubo un robo en la tienda.", s: "Al reportar un delito de robo.", sEn: "When reporting a theft.", n: "\"Robbery\" lleva doble 'b' y el acento al inicio: RÓ-be-ri.", nEn: "\"Robbery\" has a double 'b' and the stress at the start: ROB-be-ry." },
    "loc-vemr13": { e: "The rescue team saved everyone.", t: "El equipo de rescate salvó a todos.", s: "Cuando hablas de salvar a alguien en peligro.", sEn: "When talking about saving someone in danger.", n: "\"Rescue\" suena RÉS-kiu; también es verbo: \"to rescue\".", nEn: "\"Rescue\" sounds like RES-kyoo; it's also a verb: \"to rescue\"." },
    "loc-vemr14": { e: "Don't worry, you're safe now.", t: "No te preocupes, ya estás a salvo.", s: "Al tranquilizar a alguien tras un peligro.", sEn: "When reassuring someone after danger.", n: "\"Safe\" suena \"séif\"; también significa una caja fuerte.", nEn: "\"Safe\" sounds like \"sayf\"; it also means a strongbox." },
    "loc-vemr15": { e: "Be careful, the floor is wet.", t: "Ten cuidado, el piso está mojado.", s: "Cuando adviertes a alguien de un riesgo.", sEn: "When warning someone of a risk.", n: "\"Careful\" junta \"care\" (cuidado) y \"-ful\"; suena KÉR-ful.", nEn: "\"Careful\" combines \"care\" and \"-ful\"; it sounds like KAIR-ful." },
    "loc-vemr16": { e: "The exit is to your left.", t: "La salida está a su izquierda.", s: "Al indicar por dónde salir de un lugar.", sEn: "When showing where to leave a place.", n: "\"Exit\" suena ÉK-sit; en emergencias busca el cartel \"EXIT\".", nEn: "\"Exit\" sounds like EK-sit; in emergencies look for the \"EXIT\" sign." },

    // ============== Núcleo esencial + Vocabulario B2 ==============
    "loc-vnu01": { e: "The hotel is right next to the beach.", t: "El hotel está justo al lado de la playa.", s: "Cuando hablas de algo específico o ya conocido.", sEn: "When you talk about something specific or already known.", n: "Se pronuncia \"da\", no \"de\"; la 'th' es suave (lengua entre los dientes).", nEn: "It sounds like \"duh\", not \"thee\"; the 'th' is soft (tongue between the teeth)." },
    "loc-vnu02": { e: "Can I get a coffee, please?", t: "¿Me das un café, por favor?", s: "Antes de un sustantivo que empieza con sonido de consonante.", sEn: "Before a noun that starts with a consonant sound.", n: "Relajado suena \"a\" (como en español); enfático suena \"ei\".", nEn: "Relaxed it sounds like \"uh\"; stressed it sounds like \"ay\"." },
    "loc-vnu03": { e: "She works as an English teacher.", t: "Ella trabaja como profesora de inglés.", s: "Antes de un sustantivo que empieza con sonido de vocal.", sEn: "Before a noun that starts with a vowel sound.", n: "Usa \"an\" por el sonido, no la letra: \"an hour\", \"a university\".", nEn: "Use \"an\" for the sound, not the letter: \"an hour\", \"a university\"." },
    "loc-vnu04": { e: "Would you like some water?", t: "¿Quieres un poco de agua?", s: "Para una cantidad indefinida en frases afirmativas y ofertas.", sEn: "For an indefinite amount in statements and offers.", n: "En ofertas se usa \"some\" aunque sea pregunta: \"Want some tea?\".", nEn: "In offers we use \"some\" even in questions: \"Want some tea?\"." },
    "loc-vnu05": { e: "Do you have any questions?", t: "¿Tienes alguna pregunta?", s: "En preguntas y frases negativas para cantidad indefinida.", sEn: "In questions and negatives for an indefinite amount.", n: "\"Some\" en afirmativas; \"any\" en preguntas y negativas.", nEn: "\"Some\" in statements; \"any\" in questions and negatives." },
    "loc-vnu06": { e: "I check my email every morning.", t: "Reviso mi correo cada mañana.", s: "Para hablar de algo que pasa siempre o sin excepción.", sEn: "To talk about something that happens always or without exception.", n: "\"Every\" va con singular: \"every day\", no \"every days\".", nEn: "\"Every\" takes a singular noun: \"every day\", not \"every days\"." },
    "loc-vnu07": { e: "Sorry, there are no rooms available tonight.", t: "Lo siento, no hay habitaciones disponibles esta noche.", s: "Para negar la existencia de algo, delante del sustantivo.", sEn: "To deny the existence of something, before the noun.", n: "\"No\" + sustantivo = \"not any\": \"no rooms\" = \"not any rooms\".", nEn: "\"No\" + noun equals \"not any\": \"no rooms\" equals \"not any rooms\"." },
    "loc-vnu08": { e: "I asked for towels, but none were left.", t: "Pedí toallas, pero no quedaba ninguna.", s: "Para decir \"ni uno\" sin repetir el sustantivo.", sEn: "To say \"not one\" without repeating the noun.", n: "Suena igual que \"nun\" (monja); rima con \"sun\".", nEn: "It sounds like \"nun\"; it rhymes with \"sun\"." },
    "loc-vnu09": { e: "Would you like another drink?", t: "¿Quieres otra bebida?", s: "Para pedir o ofrecer uno más del mismo tipo.", sEn: "To ask for or offer one more of the same kind.", n: "\"Another\" es una sola palabra: \"an\" + \"other\".", nEn: "\"Another\" is one word: \"an\" + \"other\"." },
    "loc-vnu10": { e: "The other guests are already at breakfast.", t: "Los otros huéspedes ya están en el desayuno.", s: "Para referirte a los demás o a algo distinto.", sEn: "To refer to the rest or to something different.", n: "\"Other\" con sustantivo plural; \"another\" con singular.", nEn: "\"Other\" with a plural noun; \"another\" with a singular one." },
    "loc-vnu100": { e: "Thank you for your help.", t: "Gracias por tu ayuda.", s: "Para agradecer.", sEn: "To say thanks.", n: "Informal: \"thanks\". La 'th' es suave: lengua entre dientes.", nEn: "Informal: \"thanks\". The 'th' is soft: tongue between the teeth." },
    "loc-vnu101": { e: "Sorry, I didn't hear you.", t: "Perdón, no te escuché.", s: "Para disculparse o pedir que repitan.", sEn: "To apologize or ask someone to repeat.", n: "\"Sorry?\" solo, con tono de pregunta, = ¿perdón, qué?", nEn: "\"Sorry?\" alone, with a rising tone, means \"pardon, what?\"." },
    "loc-vnu102": { e: "Hello, welcome to our hotel.", t: "Hola, bienvenido a nuestro hotel.", s: "Para saludar al recibir a alguien.", sEn: "To greet someone you receive.", n: "Informal: \"hi\". Al teléfono se usa \"hello\".", nEn: "Informal: \"hi\". On the phone use \"hello\"." },
    "loc-vnu103": { e: "Goodbye, have a nice trip!", t: "¡Adiós, buen viaje!", s: "Para despedirse.", sEn: "To say farewell.", n: "Informal y muy común: \"bye\".", nEn: "Informal and very common: \"bye\"." },
    "loc-vnu104": { e: "Okay, I'll be right there.", t: "Está bien, ya voy.", s: "Para aceptar o confirmar algo.", sEn: "To accept or confirm something.", n: "Se escribe \"okay\" u \"OK\"; significan lo mismo.", nEn: "Written \"okay\" or \"OK\"; they mean the same." },
    "loc-vnu105": { e: "You're welcome, enjoy your stay.", t: "De nada, disfrute su estadía.", s: "Para responder a un agradecimiento.", sEn: "To respond to a thank you.", n: "Más informal: \"no problem\" o \"sure\".", nEn: "More informal: \"no problem\" or \"sure\"." },
    "loc-vnu106": { e: "Excuse me, where is the restroom?", t: "Disculpe, ¿dónde está el baño?", s: "Para llamar la atención o pedir paso.", sEn: "To get attention or ask to pass.", n: "\"Excuse me\" para empezar; \"sorry\" para disculparse.", nEn: "\"Excuse me\" to start; \"sorry\" to apologize." },
    "loc-vnu107": { e: "Of course, right this way.", t: "Por supuesto, por aquí.", s: "Para aceptar con gusto una petición.", sEn: "To accept a request gladly.", n: "Suena cálido y servicial; ideal en atención al cliente.", nEn: "It sounds warm and helpful; great in customer service." },
    "loc-vnu108": { e: "There's one more thing I need to ask.", t: "Hay una cosa más que necesito preguntar.", s: "Para referirte a un objeto o asunto en general.", sEn: "To refer to an object or matter in general.", n: "La 'th' es la sorda (/θ/), como soplando: \"zink\".", nEn: "The 'th' is the voiceless one (/θ/), like a soft blow." },
    "loc-vnu109": { e: "Is this the way to the beach?", t: "¿Este es el camino a la playa?", s: "Para un camino o una manera de hacer algo.", sEn: "For a path or a way of doing something.", n: "\"This way, please\" = por aquí, por favor.", nEn: "\"This way, please\" means \"come this direction\"." },
    "loc-vnu11": { e: "It was such a nice day at the beach.", t: "Fue un día tan lindo en la playa.", s: "Para enfatizar una cualidad: \"such a + adjetivo + sustantivo\".", sEn: "To emphasize a quality: \"such a + adjective + noun\".", n: "Con sustantivo usa \"such\"; con adjetivo solo usa \"so\".", nEn: "With a noun use \"such\"; with just an adjective use \"so\"." },
    "loc-vnu110": { e: "A lot of people come here in summer.", t: "Mucha gente viene aquí en verano.", s: "Para referirte a varias personas.", sEn: "To refer to several persons.", n: "\"People\" ya es plural; no digas \"peoples\".", nEn: "\"People\" is already plural; don't say \"peoples\"." },
    "loc-vnu111": { e: "The woman at the desk can help you.", t: "La mujer en la recepción puede ayudarte.", s: "Para referirte a una mujer.", sEn: "To refer to a woman.", n: "Plural: \"women\" (WÍ-min); cambia el sonido.", nEn: "Plural: \"women\" (WIM-in); the sound changes." },
    "loc-vnu112": { e: "Is the child traveling with you?", t: "¿El niño viaja con usted?", s: "Para referirte a un niño o niña.", sEn: "To refer to a child.", n: "Plural irregular: \"children\" (CHÍL-dren).", nEn: "Irregular plural: \"children\" (CHIL-dren)." },
    "loc-vnu113": { e: "People come from all over the world.", t: "La gente viene de todo el mundo.", s: "Para hablar del planeta o de todo el mundo.", sEn: "To talk about the planet or everyone.", n: "\"All over the world\" = de todas partes.", nEn: "\"All over the world\" means from everywhere." },
    "loc-vnu114": { e: "Life here is calm and slow.", t: "La vida aquí es tranquila y lenta.", s: "Para hablar de la vida en general.", sEn: "To talk about life in general.", n: "Plural: \"lives\" (láivs), con 'v'.", nEn: "Plural: \"lives\" (lyvz), with a 'v'." },
    "loc-vnu115": { e: "This is the best part of the tour.", t: "Esta es la mejor parte del tour.", s: "Para una porción o sección de algo.", sEn: "For a portion or section of something.", n: "\"Part of\" = parte de: \"part of the team\".", nEn: "\"Part of\" means a piece of: \"part of the team\"." },
    "loc-vnu116": { e: "This is a great place to relax.", t: "Este es un buen lugar para relajarse.", s: "Para referirte a un sitio o lugar.", sEn: "To refer to a spot or location.", n: "\"Take place\" significa ocurrir/celebrarse.", nEn: "\"Take place\" means to happen/be held." },
    "loc-vnu117": { e: "That's a good point.", t: "Ese es un buen punto.", s: "Para una idea, un argumento o un lugar exacto.", sEn: "For an idea, an argument, or an exact spot.", n: "\"What's the point?\" = ¿para qué? / ¿qué sentido tiene?", nEn: "\"What's the point?\" means what's the use?" },
    "loc-vnu118": { e: "In fact, the tour is free today.", t: "De hecho, el tour es gratis hoy.", s: "Para presentar algo real o verdadero.", sEn: "To present something real or true.", n: "\"In fact\" = de hecho; conecta y aclara.", nEn: "\"In fact\" means actually; it connects and clarifies." },
    "loc-vnu119": { e: "Don't worry, that's not a problem.", t: "No te preocupes, eso no es problema.", s: "Para hablar de una dificultad.", sEn: "To talk about a difficulty.", n: "\"No problem\" es respuesta común a \"thank you\".", nEn: "\"No problem\" is a common reply to \"thank you\"." },
    "loc-vnu12": { e: "She has her own car.", t: "Ella tiene su propio carro.", s: "Para subrayar que algo pertenece a esa persona.", sEn: "To stress that something belongs to that person.", n: "Va después del posesivo: \"my own\", \"his own\".", nEn: "It comes after the possessive: \"my own\", \"his own\"." },
    "loc-vnu120": { e: "Can I have your name, please?", t: "¿Me puede dar su nombre, por favor?", s: "Para pedir o dar un nombre.", sEn: "To ask for or give a name.", n: "\"What's your name?\" = ¿cómo te llamas?", nEn: "\"What's your name?\" means what are you called?" },
    "loc-vnu13": { e: "We took the same bus every day.", t: "Tomábamos el mismo bus todos los días.", s: "Para decir que dos cosas son idénticas.", sEn: "To say that two things are identical.", n: "Casi siempre lleva \"the\" delante: \"the same\".", nEn: "It almost always takes \"the\" before it: \"the same\"." },
    "loc-vnu14": { e: "The keys are in the drawer.", t: "Las llaves están en el cajón.", s: "Para algo dentro de un espacio cerrado.", sEn: "For something inside an enclosed space.", n: "\"In\" = dentro; \"on\" = encima; \"at\" = en un punto.", nEn: "\"In\" means inside; \"on\" means on top; \"at\" means at a point." },
    "loc-vnu15": { e: "Your room is on the third floor.", t: "Tu habitación está en el tercer piso.", s: "Para algo encima de una superficie o un día concreto.", sEn: "For something on a surface or a specific day.", n: "Días y fechas llevan \"on\": \"on Monday\", \"on July 4th\".", nEn: "Days and dates take \"on\": \"on Monday\", \"on July 4th\"." },
    "loc-vnu16": { e: "Let's meet at the entrance.", t: "Nos vemos en la entrada.", s: "Para un punto exacto, lugar o una hora.", sEn: "For an exact point, place, or a time.", n: "Horas llevan \"at\": \"at 8\", \"at noon\".", nEn: "Times take \"at\": \"at 8\", \"at noon\"." },
    "loc-vnu17": { e: "I'm going to the market.", t: "Voy al mercado.", s: "Para indicar dirección o destino.", sEn: "To show direction or destination.", n: "Relajado suena \"ta\"; también va antes del infinitivo: \"to go\".", nEn: "Relaxed it sounds like \"tuh\"; it also marks the infinitive: \"to go\"." },
    "loc-vnu18": { e: "This bus goes from the airport to the city.", t: "Este bus va del aeropuerto a la ciudad.", s: "Para indicar origen o punto de partida.", sEn: "To show origin or starting point.", n: "\"From... to...\" marca de dónde a dónde.", nEn: "\"From... to...\" marks where from and where to." },
    "loc-vnu19": { e: "I'd like a room with a sea view.", t: "Quisiera una habitación con vista al mar.", s: "Para indicar compañía o algo que incluye.", sEn: "To show company or something that is included.", n: "La 'th' es suave; suena casi \"wid\" en habla rápida.", nEn: "The 'th' is soft; it almost sounds like \"wid\" in fast speech." },
    "loc-vnu20": { e: "You can pay by card.", t: "Puedes pagar con tarjeta.", s: "Para indicar medio, autor o algo al lado.", sEn: "To show means, author, or something next to.", n: "\"Pay by card\", \"a book by...\", \"sit by the window\".", nEn: "\"Pay by card\", \"a book by...\", \"sit by the window\"." },
    "loc-vnu21": { e: "This table is for two people.", t: "Esta mesa es para dos personas.", s: "Para indicar destinatario, propósito o duración.", sEn: "To show a recipient, purpose, or duration.", n: "Con tiempo significa duración: \"for two hours\".", nEn: "With time it means duration: \"for two hours\"." },
    "loc-vnu22": { e: "Let me tell you about the tour.", t: "Déjame contarte sobre el tour.", s: "Para hablar del tema de algo.", sEn: "To talk about the topic of something.", n: "También significa \"más o menos\": \"about 10 people\".", nEn: "It also means \"roughly\": \"about 10 people\"." },
    "loc-vnu23": { e: "That's the best part of the trip.", t: "Esa es la mejor parte del viaje.", s: "Para relación, posesión o cantidad.", sEn: "For relation, possession, or quantity.", n: "La 'f' suena como 'v': \"av\", no \"of\".", nEn: "The 'f' sounds like 'v': \"uhv\", not \"off\"." },
    "loc-vnu24": { e: "Please come into the room.", t: "Por favor, entra a la habitación.", s: "Para movimiento hacia el interior de algo.", sEn: "For movement to the inside of something.", n: "\"Into\" lleva movimiento; \"in\" es solo posición.", nEn: "\"Into\" has movement; \"in\" is just position." },
    "loc-vnu25": { e: "There's a bridge over the river.", t: "Hay un puente sobre el río.", s: "Para algo por encima o que cruza.", sEn: "For something above or crossing.", n: "También significa \"más de\": \"over 20 years\".", nEn: "It also means \"more than\": \"over 20 years\"." },
    "loc-vnu26": { e: "Your bag is under the table.", t: "Tu bolso está debajo de la mesa.", s: "Para algo por debajo de otra cosa.", sEn: "For something below another thing.", n: "También \"menos de\": \"under 18\".", nEn: "It also means \"less than\": \"under 18\"." },
    "loc-vnu27": { e: "We can talk after the meeting.", t: "Podemos hablar después de la reunión.", s: "Para algo posterior en el tiempo.", sEn: "For something later in time.", n: "Opuesto de \"before\"; va antes del evento: \"after lunch\".", nEn: "Opposite of \"before\"; goes before the event: \"after lunch\"." },
    "loc-vnu28": { e: "Please arrive before noon.", t: "Por favor llega antes del mediodía.", s: "Para algo anterior en el tiempo.", sEn: "For something earlier in time.", n: "Sirve de preposición y de conjunción: \"before you go\".", nEn: "It works as a preposition and a conjunction: \"before you go\"." },
    "loc-vnu29": { e: "Breakfast is served during the morning.", t: "El desayuno se sirve durante la mañana.", s: "Para algo que ocurre dentro de un período.", sEn: "For something that happens within a period.", n: "\"During\" + sustantivo; \"while\" + frase con verbo.", nEn: "\"During\" + noun; \"while\" + a clause with a verb." },
    "loc-vnu30": { e: "I'll have a coffee without sugar.", t: "Tomaré un café sin azúcar.", s: "Para indicar la ausencia de algo.", sEn: "To show the absence of something.", n: "Opuesto de \"with\"; \"with\" + \"out\".", nEn: "Opposite of \"with\"; it's \"with\" + \"out\"." },
    "loc-vnu31": { e: "Go through that door to the lobby.", t: "Pasa por esa puerta hacia el lobby.", s: "Para pasar de un lado a otro de algo.", sEn: "To go from one side of something to the other.", n: "No suena la 'g' ni la 'h': solo \"zru\".", nEn: "The 'g' and 'h' are silent: just \"throo\"." },
    "loc-vnu32": { e: "Please don't lean against the wall.", t: "Por favor no te apoyes contra la pared.", s: "Para oposición o contacto físico.", sEn: "For opposition or physical contact.", n: "También figurado: \"I'm against the idea\".", nEn: "It's also figurative: \"I'm against the idea\"." },
    "loc-vnu33": { e: "The shop is just around the corner.", t: "La tienda está a la vuelta de la esquina.", s: "Para rodear algo o una posición cercana.", sEn: "To go around something or for a nearby position.", n: "También \"aproximadamente\": \"around 5 o'clock\".", nEn: "It also means \"approximately\": \"around 5 o'clock\"." },
    "loc-vnu34": { e: "The parking is behind the hotel.", t: "El estacionamiento está detrás del hotel.", s: "Para algo en la parte de atrás de otra cosa.", sEn: "For something at the back of another thing.", n: "Opuesto de \"in front of\".", nEn: "Opposite of \"in front of\"." },
    "loc-vnu35": { e: "There's a clock above the door.", t: "Hay un reloj encima de la puerta.", s: "Para algo más alto, sin tocar.", sEn: "For something higher up, without touching.", n: "\"Above\" no toca; \"on\" sí toca la superficie.", nEn: "\"Above\" doesn't touch; \"on\" does touch the surface." },
    "loc-vnu36": { e: "The price is below twenty dollars.", t: "El precio está por debajo de veinte dólares.", s: "Para algo más bajo o menor.", sEn: "For something lower or less.", n: "Opuesto de \"above\"; útil para números y niveles.", nEn: "Opposite of \"above\"; handy for numbers and levels." },
    "loc-vnu37": { e: "This dish is popular among tourists.", t: "Este plato es popular entre los turistas.", s: "Para algo en medio de un grupo de tres o más.", sEn: "For something in the middle of a group of three or more.", n: "\"Among\" para grupos; \"between\" para dos cosas.", nEn: "\"Among\" for groups; \"between\" for two things." },
    "loc-vnu38": { e: "The bakery is across the street.", t: "La panadería está al otro lado de la calle.", s: "Para algo al otro lado o que cruza.", sEn: "For something on the other side or that crosses.", n: "\"Across the street\" = enfrente, al otro lado.", nEn: "\"Across the street\" means opposite, on the other side." },
    "loc-vnu39": { e: "He walked toward the beach.", t: "Caminó hacia la playa.", s: "Para movimiento en dirección a algo.", sEn: "For movement in the direction of something.", n: "\"Toward\" y \"towards\" son iguales; ambos valen.", nEn: "\"Toward\" and \"towards\" are the same; both are fine." },
    "loc-vnu40": { e: "We walked along the beach.", t: "Caminamos por la playa.", s: "Para movimiento siguiendo una línea o camino.", sEn: "For movement following a line or path.", n: "\"Along the road\", \"along the river\".", nEn: "\"Along the road\", \"along the river\"." },
    "loc-vnu41": { e: "Call me if you need anything.", t: "Llámame si necesitas algo.", s: "Para condiciones: algo depende de otra cosa.", sEn: "For conditions: something depends on another thing.", n: "\"If\" condición; \"when\" para algo seguro.", nEn: "\"If\" for a condition; \"when\" for something certain." },
    "loc-vnu42": { e: "You can wait here while I check.", t: "Puedes esperar aquí mientras reviso.", s: "Para dos acciones al mismo tiempo.", sEn: "For two actions at the same time.", n: "\"While\" + verbo; \"during\" + sustantivo.", nEn: "\"While\" + a verb; \"during\" + a noun." },
    "loc-vnu43": { e: "You can pay with either card.", t: "Puedes pagar con cualquiera de las dos tarjetas.", s: "Para dos opciones: una u otra.", sEn: "For two options: one or the other.", n: "\"Either... or...\" = o... o...; también \"me either\" (yo tampoco, informal).", nEn: "\"Either... or...\" means one or the other; also \"me either\" (informal)." },
    "loc-vnu44": { e: "This room is bigger than the other one.", t: "Esta habitación es más grande que la otra.", s: "Para comparar dos cosas.", sEn: "To compare two things.", n: "\"Than\" compara; \"then\" es \"luego\". ¡No los confundas!", nEn: "\"Than\" compares; \"then\" means \"after that\". Don't mix them up!" },
    "loc-vnu45": { e: "She works as a tour guide.", t: "Ella trabaja como guía de turismo.", s: "Para rol, comparación o causa.", sEn: "For a role, comparison, or reason.", n: "\"As... as...\" compara igualdad: \"as big as\".", nEn: "\"As... as...\" compares equality: \"as big as\"." },
    "loc-vnu46": { e: "It was raining, though we still went out.", t: "Estaba lloviendo, aunque igual salimos.", s: "Para contrastar dos ideas.", sEn: "To contrast two ideas.", n: "Suena \"dou\"; al final de frase = \"sin embargo\".", nEn: "It sounds like \"thoh\"; at the end of a sentence it means \"however\"." },
    "loc-vnu47": { e: "We can't start unless everyone is here.", t: "No podemos empezar a menos que todos estén aquí.", s: "Para una condición negativa (\"si no...\").", sEn: "For a negative condition (\"if not...\").", n: "\"Unless\" = \"if not\"; lleva el verbo en afirmativo.", nEn: "\"Unless\" means \"if not\"; the verb stays affirmative." },
    "loc-vnu48": { e: "The bar is open until midnight.", t: "El bar está abierto hasta la medianoche.", s: "Para indicar hasta qué momento dura algo.", sEn: "To show up to what moment something lasts.", n: "También \"till\" (más informal) significa lo mismo.", nEn: "\"Till\" (more informal) means the same thing." },
    "loc-vnu49": { e: "I've worked here since last year.", t: "He trabajado aquí desde el año pasado.", s: "Para un punto de inicio en el tiempo o una causa.", sEn: "For a starting point in time or a reason.", n: "Con \"since\" usa el present perfect: \"I've worked since...\".", nEn: "With \"since\" use the present perfect: \"I've worked since...\"." },
    "loc-vnu50": { e: "I'm not sure whether he is coming.", t: "No estoy seguro de si él va a venir.", s: "Para expresar duda entre dos opciones.", sEn: "To express doubt between two options.", n: "Suena igual que \"weather\" (clima), pero distinto significado.", nEn: "It sounds like \"weather\", but it has a different meaning." },
    "loc-vnu51": { e: "Sorry, that is not possible right now.", t: "Lo siento, eso no es posible ahora.", s: "Para negar verbos y frases.", sEn: "To make verbs and sentences negative.", n: "Se contrae: \"is not\" = \"isn't\", \"do not\" = \"don't\".", nEn: "It contracts: \"is not\" equals \"isn't\", \"do not\" equals \"don't\"." },
    "loc-vnu52": { e: "The food here is very good.", t: "La comida aquí es muy buena.", s: "Para intensificar adjetivos y adverbios.", sEn: "To intensify adjectives and adverbs.", n: "La 'v' es con labios y dientes, no como 'b' española.", nEn: "The 'v' uses lips and teeth, not like the Spanish 'b'." },
    "loc-vnu53": { e: "This coffee is too hot.", t: "Este café está demasiado caliente.", s: "Para \"en exceso\" o, al final, \"también\".", sEn: "For \"excessively\" or, at the end, \"also\".", n: "\"Too + adjetivo\" = exceso; \"..., too\" al final = también.", nEn: "\"Too + adjective\" means excess; \"..., too\" at the end means also." },
    "loc-vnu54": { e: "I just want a glass of water.", t: "Solo quiero un vaso de agua.", s: "Para \"solamente\" o algo recién ocurrido.", sEn: "For \"only\" or something that just happened.", n: "También \"recién\": \"I just arrived\" = acabo de llegar.", nEn: "It also means \"recently\": \"I just arrived\" equals I have just arrived." },
    "loc-vnu55": { e: "We only have two rooms left.", t: "Solo nos quedan dos habitaciones.", s: "Para limitar a una cantidad o cosa.", sEn: "To limit to one amount or thing.", n: "\"Only\" va junto a lo que limita: \"only two\".", nEn: "\"Only\" goes next to what it limits: \"only two\"." },
    "loc-vnu56": { e: "Are you still working here?", t: "¿Todavía trabajas aquí?", s: "Para algo que continúa sin cambiar.", sEn: "For something that continues unchanged.", n: "\"Still\" = sigue pasando; \"yet\" = aún no, en negativas.", nEn: "\"Still\" means it continues; \"yet\" means not yet, in negatives." },
    "loc-vnu57": { e: "The guests have already checked in.", t: "Los huéspedes ya hicieron el check-in.", s: "Para algo que pasó antes de lo esperado.", sEn: "For something that happened sooner than expected.", n: "\"Already\" en afirmativas; \"yet\" en preguntas y negativas.", nEn: "\"Already\" in statements; \"yet\" in questions and negatives." },
    "loc-vnu58": { e: "I always start work at eight.", t: "Siempre empiezo a trabajar a las ocho.", s: "Para algo que pasa todo el tiempo.", sEn: "For something that happens all the time.", n: "Va antes del verbo principal: \"I always go\".", nEn: "It goes before the main verb: \"I always go\"." },
    "loc-vnu59": { e: "I never drink coffee at night.", t: "Nunca tomo café de noche.", s: "Para algo que no pasa jamás.", sEn: "For something that never happens.", n: "Ya es negativo: no uses \"don't\" con \"never\".", nEn: "It is already negative: don't use \"don't\" with \"never\"." },
    "loc-vnu60": { e: "We often get tourists from Spain.", t: "A menudo recibimos turistas de España.", s: "Para algo que pasa muchas veces.", sEn: "For something that happens many times.", n: "La 't' suele ser muda: \"Ó-fen\".", nEn: "The 't' is usually silent: \"OFF-en\"." },
    "loc-vnu61": { e: "Sometimes the bus is late.", t: "A veces el bus llega tarde.", s: "Para algo que pasa de vez en cuando.", sEn: "For something that happens occasionally.", n: "Puede ir al inicio o antes del verbo.", nEn: "It can go at the start or before the verb." },
    "loc-vnu62": { e: "Could you say that again, please?", t: "¿Podría repetir eso, por favor?", s: "Para pedir o decir que algo se repite.", sEn: "To ask for or say that something repeats.", n: "Muy útil para pedir que repitan: \"Again, please?\".", nEn: "Very handy for asking someone to repeat: \"Again, please?\"." },
    "loc-vnu63": { e: "This place is really beautiful.", t: "Este lugar es realmente hermoso.", s: "Para enfatizar o mostrar interés sincero.", sEn: "To emphasize or show genuine interest.", n: "\"Really?\" solo, muestra sorpresa o interés.", nEn: "\"Really?\" on its own shows surprise or interest." },
    "loc-vnu64": { e: "We're almost ready to leave.", t: "Estamos casi listos para salir.", s: "Para algo que falta muy poco.", sEn: "For something that is nearly done.", n: "\"Almost\" va antes de lo que modifica: \"almost done\".", nEn: "\"Almost\" goes before what it modifies: \"almost done\"." },
    "loc-vnu65": { e: "Maybe we can go tomorrow.", t: "Tal vez podamos ir mañana.", s: "Para algo posible pero no seguro.", sEn: "For something possible but not certain.", n: "\"Maybe\" suele ir al inicio de la frase.", nEn: "\"Maybe\" usually goes at the start of the sentence." },
    "loc-vnu66": { e: "Well, let me check that for you.", t: "Bueno, déjame revisar eso para ti.", s: "Para ganar tiempo o decir \"bien\".", sEn: "To gain time or to say \"good/fine\".", n: "Como adverbio: \"She speaks well\" (lo hace bien).", nEn: "As an adverb: \"She speaks well\" (does it well)." },
    "loc-vnu67": { e: "It's open even on Sundays.", t: "Está abierto incluso los domingos.", s: "Para enfatizar algo sorprendente.", sEn: "To emphasize something surprising.", n: "\"Even\" va antes de la palabra que destaca.", nEn: "\"Even\" goes before the word it highlights." },
    "loc-vnu68": { e: "Let's go together.", t: "Vamos juntos.", s: "Para acciones en grupo o en compañía.", sEn: "For actions done in a group or company.", n: "\"Get together\" significa reunirse.", nEn: "\"Get together\" means to meet up." },
    "loc-vnu69": { e: "The bus will be here soon.", t: "El bus llegará pronto.", s: "Para algo que pasará en poco tiempo.", sEn: "For something that will happen shortly.", n: "\"See you soon\" es una despedida común.", nEn: "\"See you soon\" is a common goodbye." },
    "loc-vnu70": { e: "I'll call you later.", t: "Te llamo más tarde.", s: "Para algo en un momento posterior.", sEn: "For something at a later moment.", n: "\"See you later\" = nos vemos luego.", nEn: "\"See you later\" means see you afterward." },
    "loc-vnu71": { e: "Have you ever been to Mexico?", t: "¿Alguna vez has estado en México?", s: "En preguntas sobre experiencias.", sEn: "In questions about experiences.", n: "\"Ever\" en preguntas; \"never\" en respuestas negativas.", nEn: "\"Ever\" in questions; \"never\" in negative answers." },
    "loc-vnu72": { e: "Has the taxi arrived yet?", t: "¿Ya llegó el taxi?", s: "En preguntas y negativas, al final de la frase.", sEn: "In questions and negatives, at the end of the sentence.", n: "\"Not yet\" = todavía no; respuesta muy común.", nEn: "\"Not yet\" means not so far; a very common reply." },
    "loc-vnu73": { e: "The pool is closed, so we went to the beach instead.", t: "La piscina está cerrada, así que fuimos a la playa en cambio.", s: "Para reemplazar una opción por otra.", sEn: "To replace one option with another.", n: "\"Instead of\" + sustantivo: \"tea instead of coffee\".", nEn: "\"Instead of\" + noun: \"tea instead of coffee\"." },
    "loc-vnu74": { e: "It's late, but let's go anyway.", t: "Es tarde, pero vamos de todos modos.", s: "Para seguir a pesar de algo o cambiar de tema.", sEn: "To continue despite something or to change topic.", n: "Útil para cerrar un tema: \"Anyway, let's start.\"", nEn: "Handy for wrapping up a topic: \"Anyway, let's start.\"" },
    "loc-vnu75": { e: "All the rooms are clean now.", t: "Todas las habitaciones ya están limpias.", s: "Para la totalidad de algo.", sEn: "For the whole of something.", n: "\"All day\" = todo el día; \"all of us\" = todos nosotros.", nEn: "\"All day\" means the whole day; \"all of us\" means everyone of us." },
    "loc-vnu76": { e: "There are many tourists in summer.", t: "Hay muchos turistas en verano.", s: "Para cantidad grande de cosas contables.", sEn: "For a large amount of countable things.", n: "\"Many\" con contables; \"much\" con incontables.", nEn: "\"Many\" with countables; \"much\" with uncountables." },
    "loc-vnu77": { e: "There isn't much time left.", t: "No queda mucho tiempo.", s: "Para cantidad grande de algo incontable.", sEn: "For a large amount of something uncountable.", n: "Suele ir en preguntas y negativas: \"how much?\".", nEn: "It often appears in questions and negatives: \"how much?\"." },
    "loc-vnu78": { e: "Would you like some more bread?", t: "¿Quieres un poco más de pan?", s: "Para una cantidad mayor o comparar.", sEn: "For a larger amount or to compare.", n: "\"More than\" para comparar: \"more than ten\".", nEn: "\"More than\" to compare: \"more than ten\"." },
    "loc-vnu79": { e: "Most guests arrive in the afternoon.", t: "La mayoría de los huéspedes llegan en la tarde.", s: "Para la mayor parte de un grupo.", sEn: "For the largest part of a group.", n: "Superlativo: \"the most beautiful\" = el más hermoso.", nEn: "As a superlative: \"the most beautiful\" means the most beautiful." },
    "loc-vnu80": { e: "Try to use less water, please.", t: "Trata de usar menos agua, por favor.", s: "Para cantidad menor de algo incontable.", sEn: "For a smaller amount of something uncountable.", n: "\"Less\" con incontables; \"fewer\" con contables.", nEn: "\"Less\" with uncountables; \"fewer\" with countables." },
    "loc-vnu81": { e: "We have a few rooms still free.", t: "Tenemos unas pocas habitaciones libres aún.", s: "Para una cantidad pequeña de cosas contables.", sEn: "For a small amount of countable things.", n: "\"A few\" = algunos (positivo); \"few\" = pocos (escaso).", nEn: "\"A few\" means some (positive); \"few\" means hardly any." },
    "loc-vnu82": { e: "Both rooms have a sea view.", t: "Ambas habitaciones tienen vista al mar.", s: "Para referirte a dos cosas a la vez.", sEn: "To refer to two things at once.", n: "La 'th' final es suave: \"bouz\".", nEn: "The final 'th' is soft: \"bohth\"." },
    "loc-vnu83": { e: "Each guest gets a welcome drink.", t: "Cada huésped recibe una bebida de bienvenida.", s: "Para uno por uno dentro de un grupo.", sEn: "For one by one within a group.", n: "\"Each\" va con verbo y sustantivo en singular.", nEn: "\"Each\" takes a singular verb and noun." },
    "loc-vnu84": { e: "We offer several tours each week.", t: "Ofrecemos varios tours cada semana.", s: "Para más de dos pero no muchos.", sEn: "For more than two but not many.", n: "Va con sustantivo plural: \"several days\".", nEn: "It takes a plural noun: \"several days\"." },
    "loc-vnu85": { e: "Do we have enough chairs?", t: "¿Tenemos suficientes sillas?", s: "Para indicar cantidad bastante.", sEn: "To indicate a sufficient amount.", n: "Antes de sustantivo, después de adjetivo: \"big enough\".", nEn: "Before a noun, after an adjective: \"big enough\"." },
    "loc-vnu86": { e: "I can help you with that.", t: "Puedo ayudarte con eso.", s: "Para capacidad, permiso u ofrecer ayuda.", sEn: "For ability, permission, or offering help.", n: "Va seguido del verbo base: \"can help\", no \"can to help\".", nEn: "It is followed by the base verb: \"can help\", not \"can to help\"." },
    "loc-vnu87": { e: "I will bring it right away.", t: "Lo traeré enseguida.", s: "Para decisiones y promesas sobre el futuro.", sEn: "For decisions and promises about the future.", n: "Se contrae: \"I will\" = \"I'll\".", nEn: "It contracts: \"I will\" equals \"I'll\"." },
    "loc-vnu88": { e: "Would you like some coffee?", t: "¿Le gustaría un café?", s: "Para ofertas y peticiones corteses.", sEn: "For polite offers and requests.", n: "\"Would you like...?\" es la forma educada de \"do you want\".", nEn: "\"Would you like...?\" is the polite form of \"do you want\"." },
    "loc-vnu89": { e: "You should try the local fish.", t: "Deberías probar el pescado local.", s: "Para dar consejos o recomendaciones.", sEn: "To give advice or recommendations.", n: "La 'l' es muda: \"shud\". Va con verbo base.", nEn: "The 'l' is silent: \"shood\". It takes the base verb." },
    "loc-vnu90": { e: "Could you help me, please?", t: "¿Podrías ayudarme, por favor?", s: "Para pedir algo con cortesía o hablar de posibilidad.", sEn: "To ask politely or talk about possibility.", n: "La 'l' es muda: \"cud\". Más suave que \"can\".", nEn: "The 'l' is silent: \"cood\". Softer than \"can\"." },
    "loc-vnu91": { e: "Guests must check out by noon.", t: "Los huéspedes deben salir antes del mediodía.", s: "Para obligación fuerte o reglas.", sEn: "For strong obligation or rules.", n: "\"Must\" es más fuerte que \"should\".", nEn: "\"Must\" is stronger than \"should\"." },
    "loc-vnu92": { e: "May I take your order?", t: "¿Puedo tomar su orden?", s: "Para pedir permiso de forma muy educada.", sEn: "To ask permission very politely.", n: "\"May I...?\" es más formal que \"Can I...?\".", nEn: "\"May I...?\" is more formal than \"Can I...?\"." },
    "loc-vnu93": { e: "It might rain later.", t: "Podría llover más tarde.", s: "Para una posibilidad no muy segura.", sEn: "For a possibility that is not very certain.", n: "\"Might\" es menos seguro que \"may\".", nEn: "\"Might\" is less certain than \"may\"." },
    "loc-vnu94": { e: "Does the price include breakfast?", t: "¿El precio incluye el desayuno?", s: "Auxiliar para preguntas y negativas con he/she/it.", sEn: "Auxiliary for questions and negatives with he/she/it.", n: "Con \"does\", el verbo va sin 's': \"does he work?\".", nEn: "With \"does\", the verb drops the 's': \"does he work?\"." },
    "loc-vnu95": { e: "Did you enjoy the tour?", t: "¿Disfrutaste el tour?", s: "Auxiliar para preguntas y negativas en pasado.", sEn: "Auxiliary for questions and negatives in the past.", n: "Con \"did\", el verbo va en base: \"did you go?\".", nEn: "With \"did\", the verb stays in base form: \"did you go?\"." },
    "loc-vnu96": { e: "I have to leave at six.", t: "Tengo que salir a las seis.", s: "Para obligación, muy común en el día a día.", sEn: "For obligation, very common in everyday life.", n: "Con he/she usa \"has to\": \"she has to go\".", nEn: "With he/she use \"has to\": \"she has to go\"." },
    "loc-vnu97": { e: "You need to sign here.", t: "Necesitas firmar aquí.", s: "Para expresar una necesidad práctica.", sEn: "To express a practical necessity.", n: "\"Need to\" + verbo base: \"need to pay\".", nEn: "\"Need to\" + base verb: \"need to pay\"." },
    "loc-vnu98": { e: "Yes, of course.", t: "Sí, por supuesto.", s: "Para responder afirmativamente.", sEn: "To answer affirmatively.", n: "Informal: \"yeah\" (yea). Más formal: \"yes\".", nEn: "Informal: \"yeah\". More formal: \"yes\"." },
    "loc-vnu99": { e: "One coffee, please.", t: "Un café, por favor.", s: "Para pedir algo con cortesía.", sEn: "To ask for something politely.", n: "Va al inicio o al final de la petición.", nEn: "It goes at the start or the end of the request." },
    "loc-vac01": { e: "I'll get you a fresh towel.", t: "Le traigo una toalla limpia.", s: "Para conseguir, recibir o traer algo.", sEn: "To get, receive, or bring something.", n: "Muy versátil: \"get a taxi\", \"get tired\", \"get home\".", nEn: "Very versatile: \"get a taxi\", \"get tired\", \"get home\"." },
    "loc-vac02": { e: "I can make a reservation for you.", t: "Puedo hacerle una reservación.", s: "Para crear o producir algo.", sEn: "To create or produce something.", n: "\"Make\" para crear; \"do\" para acciones generales.", nEn: "\"Make\" for creating; \"do\" for general actions." },
    "loc-vac03": { e: "What did the guide say?", t: "¿Qué dijo el guía?", s: "Para reportar palabras dichas.", sEn: "To report words spoken.", n: "\"Say\" sin persona; \"tell\" sí: \"tell me\".", nEn: "\"Say\" without a person; \"tell\" with one: \"tell me\"." },
    "loc-vac04": { e: "Can you tell me the price?", t: "¿Puedes decirme el precio?", s: "Para decir algo a una persona concreta.", sEn: "To tell something to a specific person.", n: "\"Tell\" siempre lleva a quién: \"tell him\".", nEn: "\"Tell\" always needs a listener: \"tell him\"." },
    "loc-vac05": { e: "Let me ask the manager.", t: "Déjame preguntarle al gerente.", s: "Para hacer una pregunta o pedir algo.", sEn: "To ask a question or request something.", n: "\"Ask for\" = pedir: \"ask for the bill\".", nEn: "\"Ask for\" means request: \"ask for the bill\"." },
    "loc-vac06": { e: "Do you need anything else?", t: "¿Necesita algo más?", s: "Para expresar una necesidad.", sEn: "To express a need.", n: "\"Need\" + sustantivo o \"need to\" + verbo.", nEn: "\"Need\" + noun or \"need to\" + verb." },
    "loc-vac07": { e: "Can I use the Wi-Fi here?", t: "¿Puedo usar el Wi-Fi aquí?", s: "Para emplear algo.", sEn: "To employ or utilize something.", n: "Como verbo suena \"yuz\" (con z); como sustantivo \"yus\" (con s).", nEn: "As a verb it sounds \"yooz\"; as a noun \"yoos\"." },
    "loc-vac08": { e: "I can't find my key.", t: "No encuentro mi llave.", s: "Para localizar algo perdido o buscado.", sEn: "To locate something lost or searched for.", n: "Pasado irregular: \"found\".", nEn: "Irregular past: \"found\"." },
    "loc-vac09": { e: "Please keep your ticket.", t: "Por favor guarda tu boleto.", s: "Para conservar o seguir teniendo algo.", sEn: "To keep or hold on to something.", n: "Pasado irregular: \"kept\".", nEn: "Irregular past: \"kept\"." },
    "loc-vac10": { e: "Let me show you the room.", t: "Déjame mostrarte la habitación.", s: "Para permitir o proponer (\"déjame...\").", sEn: "To allow or to propose (\"let me...\").", n: "\"Let me\" + verbo base: \"let me check\".", nEn: "\"Let me\" + base verb: \"let me check\"." },
    "loc-vac11": { e: "You can put your bags here.", t: "Puedes poner tus maletas aquí.", s: "Para colocar algo en un lugar.", sEn: "To place something somewhere.", n: "Pasado igual: \"put\" (no cambia).", nEn: "Past is the same: \"put\" (no change)." },
    "loc-vac12": { e: "What does this word mean?", t: "¿Qué significa esta palabra?", s: "Para preguntar o explicar un significado.", sEn: "To ask or explain a meaning.", n: "\"I mean...\" = quiero decir...; aclara una idea.", nEn: "\"I mean...\" clarifies an idea you just said." },
    "loc-vac13": { e: "Let me show you the way.", t: "Déjame mostrarte el camino.", s: "Para enseñar o guiar a alguien.", sEn: "To display or guide someone.", n: "\"Show\" no rima con \"now\"; suena \"shou\".", nEn: "\"Show\" doesn't rhyme with \"now\"; it sounds \"shoh\"." },
    "loc-vac14": { e: "You should try the local food.", t: "Deberías probar la comida local.", s: "Para intentar algo o probar comida.", sEn: "To attempt something or taste food.", n: "\"Try to\" + verbo = intentar; \"try\" + comida = probar.", nEn: "\"Try to\" + verb means attempt; \"try\" + food means taste." },
    "loc-vac15": { e: "I'll call you a taxi.", t: "Te llamo un taxi.", s: "Para telefonear o pedir algo por nombre.", sEn: "To phone someone or summon something.", n: "\"Call back\" = devolver la llamada.", nEn: "\"Call back\" means return the call." },
    "loc-vac16": { e: "How do you feel today?", t: "¿Cómo te sientes hoy?", s: "Para emociones o sensaciones físicas.", sEn: "For emotions or physical sensations.", n: "Pasado irregular: \"felt\".", nEn: "Irregular past: \"felt\"." },
    "loc-vac17": { e: "This place became very popular.", t: "Este lugar se volvió muy popular.", s: "Para un cambio de estado o situación.", sEn: "For a change of state or situation.", n: "Pasado irregular: \"became\".", nEn: "Irregular past: \"became\"." },
    "loc-vac18": { e: "You seem tired.", t: "Pareces cansado.", s: "Para describir una impresión.", sEn: "To describe an impression.", n: "\"Seem\" + adjetivo: \"it seems easy\".", nEn: "\"Seem\" + adjective: \"it seems easy\"." },
    "loc-vac19": { e: "Can we talk for a minute?", t: "¿Podemos hablar un minuto?", s: "Para conversar con alguien.", sEn: "To converse with someone.", n: "\"Talk to\" o \"talk with\" alguien.", nEn: "\"Talk to\" or \"talk with\" someone." },
    "loc-vac20": { e: "Turn left at the corner.", t: "Gira a la izquierda en la esquina.", s: "Para cambiar de dirección o girar algo.", sEn: "To change direction or rotate something.", n: "\"Turn on/off\" = encender/apagar.", nEn: "\"Turn on/off\" means switch on/off." },
    "loc-vac21": { e: "The tour starts at nine.", t: "El tour empieza a las nueve.", s: "Para el inicio de algo.", sEn: "For the beginning of something.", n: "Sinónimo: \"begin\". \"Start\" es más común al hablar.", nEn: "Synonym: \"begin\". \"Start\" is more common in speech." },
    "loc-vac22": { e: "Could you move a little to the left?", t: "¿Podrías moverte un poco a la izquierda?", s: "Para cambiar de lugar o mudarse.", sEn: "To change place or to relocate.", n: "\"Move in/out\" = mudarse (entrar/salir de una casa).", nEn: "\"Move in/out\" means move into/out of a home." },
    "loc-vac23": { e: "I believe the bus is late.", t: "Creo que el bus viene tarde.", s: "Para expresar una creencia u opinión.", sEn: "To express a belief or opinion.", n: "\"Believe in\" = creer en algo o alguien.", nEn: "\"Believe in\" means to have faith in something." },
    "loc-vac24": { e: "Can you bring me the menu?", t: "¿Me puedes traer el menú?", s: "Para llevar algo hacia quien habla.", sEn: "To carry something toward the speaker.", n: "\"Bring\" hacia aquí; \"take\" hacia allá. Pasado: \"brought\".", nEn: "\"Bring\" toward here; \"take\" away. Past: \"brought\"." },
    "loc-vac25": { e: "What happened here?", t: "¿Qué pasó aquí?", s: "Para hablar de un suceso o evento.", sEn: "To talk about an event occurring.", n: "No lleva sujeto persona: \"it happened\".", nEn: "It doesn't take a person as subject: \"it happened\"." },
    "loc-vac26": { e: "Please sit anywhere you like.", t: "Por favor siéntate donde gustes.", s: "Para tomar asiento.", sEn: "To take a seat.", n: "\"Sit down\" es muy común; pasado: \"sat\".", nEn: "\"Sit down\" is very common; past: \"sat\"." },
    "loc-vac27": { e: "You can stand over there.", t: "Puedes pararte allá.", s: "Para estar de pie o ponerse de pie.", sEn: "To be on one's feet or stand up.", n: "\"Stand up\" = levantarse; pasado: \"stood\".", nEn: "\"Stand up\" means to rise; past: \"stood\"." },
    "loc-vac28": { e: "Nice to meet you!", t: "¡Mucho gusto en conocerte!", s: "Para conocer a alguien o reunirse.", sEn: "To meet someone or get together.", n: "Pasado irregular: \"met\".", nEn: "Irregular past: \"met\"." },
    "loc-vac29": { e: "Does the price include taxes?", t: "¿El precio incluye los impuestos?", s: "Para indicar qué viene dentro de algo.", sEn: "To indicate what comes within something.", n: "Muy útil para precios: \"breakfast included\".", nEn: "Very handy for prices: \"breakfast included\"." },
    "loc-vac30": { e: "Let's continue the tour.", t: "Continuemos el tour.", s: "Para seguir con algo que ya empezó.", sEn: "To go on with something already started.", n: "Sinónimo informal: \"keep going\".", nEn: "Informal synonym: \"keep going\"." },
    "loc-vac31": { e: "Sorry, I don't understand.", t: "Disculpa, no entiendo.", s: "Para comprender algo o a alguien.", sEn: "To comprehend something or someone.", n: "Pasado irregular: \"understood\".", nEn: "Irregular past: \"understood\"." },
    "loc-vac32": { e: "You can watch the sunset from here.", t: "Puedes ver el atardecer desde aquí.", s: "Para mirar algo con atención o por un rato.", sEn: "To look at something attentively or for a while.", n: "\"Watch\" = mirar atento; \"see\" = ver en general.", nEn: "\"Watch\" means observe; \"see\" means perceive." },
    "loc-vac33": { e: "Please follow me.", t: "Por favor sígame.", s: "Para ir detrás de alguien o seguir instrucciones.", sEn: "To go behind someone or follow instructions.", n: "\"Follow me\" es muy útil para guiar a clientes.", nEn: "\"Follow me\" is very handy for guiding customers." },
    "loc-vac34": { e: "The bus stops right here.", t: "El bus para justo aquí.", s: "Para detener o detenerse.", sEn: "To stop or to halt.", n: "\"Stop\" + -ing = dejar de hacer: \"stop talking\".", nEn: "\"Stop\" + -ing means quit doing: \"stop talking\"." },
    "loc-vac35": { e: "We want to create a nice experience.", t: "Queremos crear una linda experiencia.", s: "Para producir algo nuevo.", sEn: "To produce something new.", n: "Acento en la segunda sílaba: kri-ÉIT.", nEn: "Stress on the second syllable: cre-ATE." },
    "loc-vac36": { e: "How long will you spend here?", t: "¿Cuánto tiempo pasarás aquí?", s: "Para dinero o tiempo invertido.", sEn: "For money or time invested.", n: "\"Spend money\" y \"spend time\". Pasado: \"spent\".", nEn: "\"Spend money\" and \"spend time\". Past: \"spent\"." },
    "loc-vac37": { e: "This town is growing fast.", t: "Este pueblo está creciendo rápido.", s: "Para aumentar de tamaño o cultivar.", sEn: "To increase in size or to cultivate.", n: "Pasado irregular: \"grew\"; participio: \"grown\".", nEn: "Irregular past: \"grew\"; participle: \"grown\"." },
    "loc-vac38": { e: "What time do you open?", t: "¿A qué hora abren?", s: "Para abrir algo o un negocio.", sEn: "To open something or a business.", n: "También adjetivo: \"the shop is open\".", nEn: "Also an adjective: \"the shop is open\"." },
    "loc-vac39": { e: "We offer free breakfast.", t: "Ofrecemos desayuno gratis.", s: "Para proponer o dar algo.", sEn: "To propose or provide something.", n: "Acento en la primera sílaba: Ó-fer.", nEn: "Stress on the first syllable: OFF-er." },
    "loc-vac40": { e: "I hope you enjoy your stay.", t: "Espero que disfrutes tu estadía.", s: "Para desear que algo bueno pase.", sEn: "To wish that something good happens.", n: "\"Hope\" = esperar con deseo; \"wait\" = aguardar.", nEn: "\"Hope\" means wish; \"wait\" means await." },
    "loc-vac41": { e: "Please wait here a moment.", t: "Por favor espera aquí un momento.", s: "Para aguardar a alguien o algo.", sEn: "To await someone or something.", n: "\"Wait for\" + persona/cosa: \"wait for me\".", nEn: "\"Wait for\" + person/thing: \"wait for me\"." },
    "loc-vac42": { e: "Let me set the table for you.", t: "Déjame ponerte la mesa.", s: "Para colocar o ajustar algo.", sEn: "To place or adjust something.", n: "Pasado igual: \"set\". \"Set the table\" = poner la mesa.", nEn: "Past is the same: \"set\". \"Set the table\" means lay it." },
    "loc-vac43": { e: "You can choose any table.", t: "Puedes elegir cualquier mesa.", s: "Para seleccionar entre opciones.", sEn: "To select among options.", n: "Pasado irregular: \"chose\"; participio: \"chosen\".", nEn: "Irregular past: \"chose\"; participle: \"chosen\"." },
    "loc-vac44": { e: "Pets are not allowed inside.", t: "No se permiten mascotas adentro.", s: "Para reglas: lo que se permite o no.", sEn: "For rules: what is allowed or not.", n: "Muy usado en pasivo: \"is allowed\", \"not allowed\".", nEn: "Often used in the passive: \"is allowed\", \"not allowed\"." },
    "loc-vac45": { e: "Would you like to add a dessert?", t: "¿Quieres agregar un postre?", s: "Para sumar algo a un pedido o lista.", sEn: "To add something to an order or list.", n: "\"Add up\" = sumar (números).", nEn: "\"Add up\" means to total (numbers)." },
    "loc-vac46": { e: "Hurry, or we'll miss the bus.", t: "Apúrate, o perderemos el bus.", s: "Para no alcanzar algo o echar de menos.", sEn: "To fail to catch something or to feel its absence.", n: "\"Miss the bus\" = perderlo; \"miss you\" = extrañarte.", nEn: "\"Miss the bus\" means not catch it; \"miss you\" means long for you." },
    "loc-vac47": { e: "I can drive you to the hotel.", t: "Puedo llevarte al hotel en carro.", s: "Para conducir o llevar a alguien en vehículo.", sEn: "To drive or take someone by car.", n: "Pasado irregular: \"drove\"; participio: \"driven\".", nEn: "Irregular past: \"drove\"; participle: \"driven\"." },
    "loc-vac48": { e: "I'll pick you up at the airport.", t: "Te recojo en el aeropuerto.", s: "Para recoger a alguien o algo.", sEn: "To collect someone or something.", n: "Verbo con partícula; muy común en transporte.", nEn: "A phrasal verb; very common with transport." },
    "loc-vac49": { e: "I'd like to book a table for two.", t: "Quisiera reservar una mesa para dos.", s: "Para reservar una mesa, sala o tour.", sEn: "To reserve a table, room, or tour.", n: "\"Book\" como verbo = reservar; también \"reserve\".", nEn: "\"Book\" as a verb means reserve; also \"reserve\"." },
    "loc-vac50": { e: "I'll send you the details.", t: "Te envío los detalles.", s: "Para mandar algo a alguien.", sEn: "To send something to someone.", n: "Pasado irregular: \"sent\".", nEn: "Irregular past: \"sent\"." },
    "loc-b2op01": { e: "In my opinion, the new menu is a real improvement.", t: "En mi opinión, el nuevo menú es una verdadera mejora.", s: "Cuando das tu punto de vista en una reunión o charla.", sEn: "When you give your point of view in a meeting or chat.", n: "Va al inicio de la frase y se separa con coma; más formal que 'I think'.", nEn: "It opens the sentence with a comma; more formal than 'I think'." },
    "loc-b2op02": { e: "I reckon we should open earlier on weekends.", t: "Yo diría que deberíamos abrir más temprano los fines de semana.", s: "Al dar una opinión relajada entre compañeros.", sEn: "When giving a casual opinion among coworkers.", n: "Muy británico e informal; equivale a 'I think' o 'I guess'.", nEn: "Very British and casual; it means 'I think' or 'I guess'." },
    "loc-b2op03": { e: "As far as I'm concerned, the project is already a success.", t: "Por lo que a mí respecta, el proyecto ya es un éxito.", s: "Cuando das tu postura personal, dejando claro que es solo tuya.", sEn: "When you give your personal stance, making clear it's just yours.", n: "Marca que hablas solo por ti; útil para no imponer tu opinión.", nEn: "It signals you speak only for yourself; handy to avoid imposing your view." },
    "loc-b2op04": { e: "From a guest's point of view, the wait felt too long.", t: "Desde el punto de vista de un huésped, la espera se sintió muy larga.", s: "Al presentar cómo se ve algo desde cierta perspectiva.", sEn: "When framing how something looks from a certain perspective.", n: "Suele ir con 'from a... point of view'; abreviado 'POV' solo por escrito.", nEn: "Often used as 'from a... point of view'; the short 'POV' is written only." },
    "loc-b2op05": { e: "It seems to me that customers prefer the smaller portions.", t: "Me parece que los clientes prefieren las porciones más pequeñas.", s: "Al dar una impresión personal con cierta cautela.", sEn: "When offering a personal impression with some caution.", n: "Más suave que 'I'm sure'; deja espacio a que te equivoques.", nEn: "Softer than 'I'm sure'; it leaves room for being wrong." },
    "loc-b2op06": { e: "I'd say it's worth the extra cost.", t: "Yo diría que vale el costo extra.", s: "Al dar una opinión rápida o una estimación.", sEn: "When giving a quick opinion or an estimate.", n: "Es la forma corta de 'I would say'; muy natural al estimar.", nEn: "It's the short form of 'I would say'; very natural for estimates." },
    "loc-b2op07": { e: "From my perspective, the team handled the complaint well.", t: "Desde mi perspectiva, el equipo manejó bien la queja.", s: "Al aportar tu visión en una conversación seria o de trabajo.", sEn: "When adding your view in a serious or work conversation.", n: "Suena profesional; 'perspective' lleva el acento en la segunda sílaba.", nEn: "Sounds professional; 'perspective' is stressed on the second syllable." },
    "loc-b2op08": { e: "This is arguably the best coffee in town.", t: "Posiblemente este sea el mejor café de la ciudad.", s: "Al hacer una afirmación fuerte pero discutible.", sEn: "When making a strong but debatable claim.", n: "Admite que se puede argumentar; suaviza una opinión tajante.", nEn: "It admits the point is arguable; it softens a bold opinion." },
    "loc-b2op09": { e: "Frankly, the service today was not good enough.", t: "Francamente, el servicio de hoy no fue lo bastante bueno.", s: "Cuando vas a decir algo honesto, quizá incómodo.", sEn: "When you're about to say something honest, maybe uncomfortable.", n: "Avisa que serás directo; úsalo con tacto en el trabajo.", nEn: "It signals you'll be blunt; use it tactfully at work." },
    "loc-b2op10": { e: "To be honest, I wasn't expecting such a big crowd.", t: "Para ser honesto, no esperaba tanta gente.", s: "Al confesar algo con sinceridad en una charla.", sEn: "When admitting something sincerely in conversation.", n: "La 'h' de 'honest' es muda; se dice 'ónest'. A menudo abreviado 'TBH'.", nEn: "The 'h' in 'honest' is silent; say 'onest'. Often shortened to 'TBH'." },
    "loc-b2op11": { e: "I assume the delivery will arrive before noon.", t: "Supongo que la entrega llegará antes del mediodía.", s: "Cuando das algo por hecho sin estar seguro del todo.", sEn: "When you take something for granted without being fully sure.", n: "Marca una suposición lógica; cuidado, puede sonar tajante.", nEn: "It marks a logical assumption; careful, it can sound presumptuous." },
    "loc-b2op12": { e: "I doubt we'll finish before the rush.", t: "Dudo que terminemos antes de la hora pico.", s: "Al expresar que algo te parece poco probable.", sEn: "When expressing that something seems unlikely to you.", n: "La 'b' de 'doubt' es muda; se dice 'daut'.", nEn: "The 'b' in 'doubt' is silent; say 'daut'." },
    "loc-b2op13": { e: "It depends on how many guests show up.", t: "Depende de cuántos huéspedes lleguen.", s: "Cuando la respuesta no es fija y varía según el caso.", sEn: "When the answer isn't fixed and varies by case.", n: "Lleva 'on' antes del factor: 'it depends on...', nunca 'depends of'.", nEn: "Use 'on' before the factor: 'it depends on...', never 'depends of'." },
    "loc-b2op14": { e: "In fact, we sold out within an hour.", t: "De hecho, nos agotamos en una hora.", s: "Al añadir un dato que refuerza o corrige lo anterior.", sEn: "When adding a fact that backs up or corrects what came before.", n: "Introduce algo más fuerte o sorprendente que lo ya dicho.", nEn: "It introduces something stronger or more surprising than before." },
    "loc-b2op15": { e: "Apparently, the road is closed for repairs.", t: "Al parecer, la carretera está cerrada por reparaciones.", s: "Al repetir algo que oíste pero no confirmaste tú mismo.", sEn: "When repeating something you heard but didn't confirm yourself.", n: "Marca información de segunda mano; no garantizas que sea cierta.", nEn: "It flags second-hand info; you're not vouching it's true." },
    "loc-b2op16": { e: "The tour supposedly lasts two hours, but it often runs longer.", t: "El tour supuestamente dura dos horas, pero suele alargarse.", s: "Al citar algo oficial de lo que dudas un poco.", sEn: "When citing something official you slightly doubt.", n: "Insinúa cierta duda o ironía sobre lo dicho.", nEn: "It hints at some doubt or irony about the claim." },
    "loc-b2op17": { e: "They left early, presumably to catch the last boat.", t: "Se fueron temprano, presumiblemente para alcanzar la última lancha.", s: "Al deducir un motivo razonable de algo que ves.", sEn: "When inferring a reasonable reason from what you see.", n: "Es una suposición lógica, más segura que 'maybe'.", nEn: "It's a logical guess, more confident than 'maybe'." },
    "loc-b2op18": { e: "On the whole, the season went better than last year.", t: "En general, la temporada fue mejor que la del año pasado.", s: "Al dar una valoración global tras considerar todo.", sEn: "When giving an overall judgment after weighing everything.", n: "La 'w' de 'whole' es muda; se dice 'jóul'. Equivale a 'overall'.", nEn: "The 'w' in 'whole' is silent; say 'hole'. It means 'overall'." },
    "loc-b2de01": { e: "I agree, we should raise the price a little.", t: "Estoy de acuerdo, deberíamos subir un poco el precio.", s: "Cuando apoyas lo que alguien acaba de decir.", sEn: "When you back what someone just said.", n: "Se dice 'I agree', nunca 'I am agree'; es un verbo, no adjetivo.", nEn: "Say 'I agree', never 'I am agree'; it's a verb, not an adjective." },
    "loc-b2de02": { e: "I disagree, I think the old schedule worked better.", t: "No estoy de acuerdo, creo que el horario anterior funcionaba mejor.", s: "Al oponerte cortésmente a una idea.", sEn: "When politely opposing an idea.", n: "Para suavizar: 'I'm afraid I disagree'; suena menos brusco.", nEn: "To soften it: 'I'm afraid I disagree'; it sounds less blunt." },
    "loc-b2de03": { e: "That's a good point, I hadn't thought of the parking.", t: "Es un buen punto, no había pensado en el estacionamiento.", s: "Al reconocer que el otro dijo algo válido.", sEn: "When acknowledging the other person made a valid point.", n: "Muestra que escuchas; ideal antes de añadir tu propia idea.", nEn: "It shows you're listening; great before adding your own idea." },
    "loc-b2de04": { e: "I see your point, but we still need to cut costs.", t: "Entiendo lo que dices, pero igual hay que recortar gastos.", s: "Al admitir el argumento del otro antes de matizar.", sEn: "When granting the other's argument before pushing back.", n: "Suele ir seguido de 'but'; reconoces sin ceder del todo.", nEn: "It's often followed by 'but'; you acknowledge without fully giving in." },
    "loc-b2de05": { e: "Fair enough, we'll try it your way first.", t: "Me parece justo, lo intentaremos a tu manera primero.", s: "Al aceptar un argumento aunque no estabas convencido.", sEn: "When accepting an argument even if you weren't convinced.", n: "Acepta sin discutir más; informal y muy común al cerrar un debate.", nEn: "It accepts without arguing more; casual and common to end a debate." },
    "loc-b2de06": { e: "Absolutely, that's exactly what I had in mind.", t: "Absolutamente, eso es justo lo que tenía en mente.", s: "Para mostrar acuerdo total y entusiasta.", sEn: "To show total, enthusiastic agreement.", n: "Más fuerte que 'yes'; el acento va en la primera sílaba.", nEn: "Stronger than 'yes'; the stress falls on the first syllable." },
    "loc-b2de07": { e: "Exactly, that's the problem we keep running into.", t: "Exactamente, ese es el problema que seguimos teniendo.", s: "Al confirmar que el otro dio justo en el clavo.", sEn: "When confirming the other person nailed it.", n: "La 'x' suena 'gz'; di 'eg-zákt-li', no 'ek-sákt-li'.", nEn: "The 'x' sounds like 'gz'; say 'eg-zact-ly', not 'ek-sact-ly'." },
    "loc-b2de08": { e: "I'm not so sure that discount will bring more clients.", t: "No estoy tan seguro de que ese descuento traiga más clientes.", s: "Al dudar con cortesía de una propuesta.", sEn: "When politely doubting a proposal.", n: "Forma educada de discrepar sin decir 'no' directamente.", nEn: "A polite way to disagree without a flat 'no'." },
    "loc-b2de09": { e: "It wasn't quiet; on the contrary, we were packed.", t: "No estuvo tranquilo; al contrario, estábamos llenísimos.", s: "Al negar algo y afirmar justo lo opuesto.", sEn: "When denying something and asserting the opposite.", n: "Corrige una idea previa; va con coma y al inicio de la frase.", nEn: "It corrects a previous idea; goes with a comma, opening the sentence." },
    "loc-b2de10": { e: "Whether the new logo is better is debatable.", t: "Si el nuevo logo es mejor es discutible.", s: "Cuando un punto no está claro y admite opiniones.", sEn: "When a point isn't clear-cut and allows differing views.", n: "No te comprometes con un lado; reconoces que hay debate.", nEn: "You don't commit to a side; you admit there's room for debate." },
    "loc-b2de11": { e: "I beg to differ; the figures tell a different story.", t: "Discrepo; las cifras cuentan otra historia.", s: "Al estar en desacuerdo de forma formal o algo irónica.", sEn: "When disagreeing in a formal or slightly ironic way.", n: "Muy educado y un poco anticuado; útil en contextos formales.", nEn: "Very polite and a bit old-fashioned; handy in formal settings." },
    "loc-b2de12": { e: "You have a point, maybe we are charging too much.", t: "Tienes razón en algo, quizá estamos cobrando de más.", s: "Al conceder que el otro tiene parte de razón.", sEn: "When conceding the other person is partly right.", n: "Concesión parcial; suaviza antes de seguir con tu postura.", nEn: "A partial concession; it softens before you push your own view." },
    "loc-b2de13": { e: "You're partly right, but the timing was also an issue.", t: "En parte tienes razón, pero el momento también fue un problema.", s: "Al aceptar solo una porción de lo que se dijo.", sEn: "When accepting only part of what was said.", n: "Matiza un acuerdo; suele combinarse con 'but'.", nEn: "It qualifies an agreement; often paired with 'but'." },
    "loc-b2de14": { e: "Broadly speaking, the guests were happy this week.", t: "Hablando en general, los huéspedes quedaron contentos esta semana.", s: "Al generalizar sin entrar en excepciones.", sEn: "When generalizing without getting into exceptions.", n: "Evita comprometerte con detalles; abre una visión amplia.", nEn: "It avoids committing to details; it opens a wide-angle view." },
    "loc-b2de15": { e: "To some extent, the delay was our fault.", t: "Hasta cierto punto, la demora fue culpa nuestra.", s: "Al admitir algo solo de forma parcial.", sEn: "When admitting something only partially.", n: "Reconoce algo sin asumirlo del todo; muy útil para negociar.", nEn: "It admits something without owning it fully; great for negotiating." },
    "loc-b2de16": { e: "No doubt the summer will be busier than spring.", t: "Sin duda el verano será más movido que la primavera.", s: "Al afirmar algo con plena seguridad.", sEn: "When stating something with full confidence.", n: "La 'b' de 'doubt' es muda; se dice 'daut'. Refuerza tu certeza.", nEn: "The 'b' in 'doubt' is silent; say 'daut'. It boosts your certainty." },
    "loc-b2de17": { e: "We should definitely repeat that promotion.", t: "Definitivamente deberíamos repetir esa promoción.", s: "Para reafirmar algo con total convicción.", sEn: "To reaffirm something with full conviction.", n: "Se escribe con 'i', no 'a': 'defInitely'; error común 'definately'.", nEn: "Spelled with 'i', not 'a': 'defInitely'; common typo 'definately'." },
    "loc-b2de18": { e: "We hardly had any complaints this month.", t: "Apenas tuvimos quejas este mes.", s: "Al expresar que algo casi no ocurre.", sEn: "When expressing that something barely happens.", n: "Tiene sentido negativo; 'hardly any' significa 'casi ninguno'.", nEn: "It carries a negative meaning; 'hardly any' means 'almost none'." },
    "loc-b2cn01": { e: "The room was small; however, it was very clean.", t: "La habitación era pequeña; sin embargo, estaba muy limpia.", s: "Al introducir un contraste con lo anterior.", sEn: "When introducing a contrast with what came before.", n: "Suele ir tras punto y coma o al inicio, con coma después.", nEn: "It usually follows a semicolon or opens a sentence, with a comma after." },
    "loc-b2cn02": { e: "The flight was canceled; therefore, we rebooked the guests.", t: "El vuelo se canceló; por lo tanto, reubicamos a los huéspedes.", s: "Al señalar una consecuencia lógica.", sEn: "When signaling a logical consequence.", n: "Más formal que 'so'; típico en correos y reportes.", nEn: "More formal than 'so'; typical in emails and reports." },
    "loc-b2cn03": { e: "It was raining; nevertheless, the tour went ahead.", t: "Estaba lloviendo; no obstante, el tour siguió adelante.", s: "Al admitir algo y seguir con lo contrario igualmente.", sEn: "When conceding something yet proceeding with the opposite.", n: "Más enfático que 'however'; tono formal.", nEn: "More emphatic than 'however'; formal in tone." },
    "loc-b2cn04": { e: "Even though it was late, we served them dinner.", t: "Aunque era tarde, les servimos la cena.", s: "Al unir dos ideas que se contradicen, con énfasis.", sEn: "When linking two clashing ideas, with emphasis.", n: "Más enfático que 'although'; va seguido de sujeto y verbo.", nEn: "More emphatic than 'although'; followed by subject and verb." },
    "loc-b2cn05": { e: "Despite the noise, the guests slept well.", t: "A pesar del ruido, los huéspedes durmieron bien.", s: "Al señalar un obstáculo que no impidió algo.", sEn: "When noting an obstacle that didn't stop something.", n: "Va con sustantivo o -ing, no con verbo conjugado; sin 'of'.", nEn: "Followed by a noun or -ing, not a full clause; no 'of' after it." },
    "loc-b2cn06": { e: "The first group was quiet, whereas the second was lively.", t: "El primer grupo era callado, mientras que el segundo era animado.", s: "Al contrastar dos cosas en la misma frase.", sEn: "When contrasting two things in the same sentence.", n: "Marca contraste, no tiempo; va en medio de la frase con coma.", nEn: "It marks contrast, not time; sits mid-sentence after a comma." },
    "loc-b2cn07": { e: "The hotel is central; moreover, it has free parking.", t: "El hotel es céntrico; además, tiene estacionamiento gratis.", s: "Al añadir un argumento que refuerza el anterior.", sEn: "When adding an argument that reinforces the previous one.", n: "Formal; añade peso. Va tras punto y coma o al inicio con coma.", nEn: "Formal; it adds weight. Follows a semicolon or opens with a comma." },
    "loc-b2cn08": { e: "The price is fair; furthermore, breakfast is included.", t: "El precio es justo; es más, el desayuno está incluido.", s: "Al sumar otra razón en un texto o discurso formal.", sEn: "When piling on another reason in formal speech or writing.", n: "Casi igual que 'moreover'; tono de informe o correo serio.", nEn: "Almost the same as 'moreover'; report or formal-email tone." },
    "loc-b2cn09": { e: "In addition, we offer a late check-out on request.", t: "Además, ofrecemos salida tardía bajo petición.", s: "Al introducir información extra.", sEn: "When introducing extra information.", n: "Para añadir antes de un sustantivo usa 'in addition to'.", nEn: "To add before a noun use 'in addition to'." },
    "loc-b2cn10": { e: "It's pricier; on the other hand, the location is perfect.", t: "Es más caro; por otro lado, la ubicación es perfecta.", s: "Al presentar el otro lado de un asunto.", sEn: "When presenting the other side of an issue.", n: "Suele seguir a 'on the one hand'; introduce el contrapunto.", nEn: "It often follows 'on the one hand'; it introduces the counterpoint." },
    "loc-b2cn11": { e: "It rained all day; as a result, the beach trip was canceled.", t: "Llovió todo el día; como resultado, se canceló la salida a la playa.", s: "Al mostrar el efecto de una causa.", sEn: "When showing the effect of a cause.", n: "Para un sustantivo causante usa 'as a result of'.", nEn: "To name the cause as a noun use 'as a result of'." },
    "loc-b2cn12": { e: "The supplier was late; consequently, we changed the menu.", t: "El proveedor llegó tarde; en consecuencia, cambiamos el menú.", s: "Al indicar una consecuencia en tono formal.", sEn: "When indicating a consequence in a formal tone.", n: "Sinónimo culto de 'so'; el acento va en la primera sílaba.", nEn: "A formal synonym of 'so'; stress falls on the first syllable." },
    "loc-b2cn13": { e: "Pay the deposit now; otherwise, we can't hold the room.", t: "Pague el depósito ahora; de lo contrario, no podemos reservar la habitación.", s: "Al advertir qué pasa si no se cumple una condición.", sEn: "When warning what happens if a condition isn't met.", n: "Introduce la consecuencia negativa de no hacer algo.", nEn: "It introduces the negative outcome of not doing something." },
    "loc-b2cn14": { e: "The chef prepped the food; meanwhile, I set the tables.", t: "El chef preparó la comida; mientras tanto, yo puse las mesas.", s: "Al describir algo que ocurre a la vez que otra cosa.", sEn: "When describing something happening at the same time as another.", n: "Indica simultaneidad; equivale a 'in the meantime'.", nEn: "It marks simultaneity; it's equivalent to 'in the meantime'." },
    "loc-b2cn15": { e: "Last year was slow; in contrast, this season is fully booked.", t: "El año pasado fue flojo; en cambio, esta temporada está llena.", s: "Al resaltar una diferencia marcada entre dos casos.", sEn: "When highlighting a sharp difference between two cases.", n: "Para comparar con algo concreto: 'in contrast to/with'.", nEn: "To compare with something specific: 'in contrast to/with'." },
    "loc-b2cn16": { e: "Some guests need extras; for instance, an early breakfast.", t: "Algunos huéspedes piden extras; por ejemplo, un desayuno temprano.", s: "Al dar un ejemplo concreto.", sEn: "When giving a concrete example.", n: "Sinónimo de 'for example'; igual de natural y un poco más formal.", nEn: "A synonym of 'for example'; equally natural and a touch more formal." },
    "loc-b2cn17": { e: "It's non-refundable; in other words, you can't get your money back.", t: "No es reembolsable; en otras palabras, no puede recuperar su dinero.", s: "Al reformular algo de modo más claro.", sEn: "When rephrasing something more clearly.", n: "Introduce una explicación más simple de lo dicho.", nEn: "It introduces a simpler explanation of what was said." },
    "loc-b2cn18": { e: "The bridge was closed, thus we took a longer route.", t: "El puente estaba cerrado, así que tomamos una ruta más larga.", s: "Al expresar una consecuencia en estilo formal o escrito.", sEn: "When expressing a consequence in formal or written style.", n: "Muy formal; la 'th' es sonora, como en 'this'.", nEn: "Very formal; the 'th' is voiced, like in 'this'." },
    "loc-b2ti01": { e: "We occasionally get guests asking for a late check-out.", t: "De vez en cuando recibimos huéspedes que piden salida tardía.", s: "Al hablar de algo que pasa pocas veces.", sEn: "When talking about something that happens rarely.", n: "Frecuencia baja; suele ir antes del verbo principal.", nEn: "Low frequency; it usually goes before the main verb." },
    "loc-b2ti02": { e: "The line was long, but eventually everyone got a table.", t: "La fila era larga, pero con el tiempo todos consiguieron mesa.", s: "Al señalar que algo ocurre tras una espera o proceso.", sEn: "When noting something happens after a wait or process.", n: "No significa 'eventualmente' (a veces); es 'al final, con el tiempo'.", nEn: "It doesn't mean 'maybe'; it means 'in the end, after a while'." },
    "loc-b2ti03": { e: "Nowadays most guests book online instead of by phone.", t: "Hoy en día la mayoría reserva en línea en vez de por teléfono.", s: "Al contrastar el presente con cómo era antes.", sEn: "When contrasting the present with how things used to be.", n: "Va al inicio o al final; se refiere a la época actual en general.", nEn: "Goes at the start or end; it refers to the present era in general." },
    "loc-b2ti04": { e: "Your room isn't ready; in the meantime, enjoy a coffee.", t: "Su habitación no está lista; entretanto, disfrute un café.", s: "Al ofrecer algo durante una espera.", sEn: "When offering something during a wait.", n: "Llena el tiempo entre dos momentos; sinónimo de 'meanwhile'.", nEn: "It fills the time between two moments; a synonym of 'meanwhile'." },
    "loc-b2ti05": { e: "Guests frequently ask about the nearest beach.", t: "Los huéspedes preguntan con frecuencia por la playa más cercana.", s: "Al hablar de algo que pasa muchas veces.", sEn: "When talking about something that happens often.", n: "Más formal que 'often'; suele ir antes del verbo.", nEn: "More formal than 'often'; it usually goes before the verb." },
    "loc-b2ti06": { e: "We rarely close before midnight in high season.", t: "Rara vez cerramos antes de medianoche en temporada alta.", s: "Al decir que algo casi nunca pasa.", sEn: "When saying something almost never happens.", n: "Tiene sentido negativo; no se combina con otra negación.", nEn: "It carries a negative meaning; don't pair it with another negative." },
    "loc-b2ti07": { e: "Lately we've had a lot of last-minute cancellations.", t: "Últimamente hemos tenido muchas cancelaciones de último minuto.", s: "Al hablar de una tendencia reciente.", sEn: "When talking about a recent trend.", n: "Suele ir con present perfect ('we've had'); marca lo reciente.", nEn: "It often pairs with the present perfect; it marks recent time." },
    "loc-b2ti08": { e: "At the moment, all our tables are taken.", t: "Actualmente, todas nuestras mesas están ocupadas.", s: "Al describir la situación justo ahora.", sEn: "When describing the situation right now.", n: "Equivale a 'currently'; ojo, 'actually' significa 'en realidad'.", nEn: "It means 'currently'; note 'actually' means 'in reality'." },
    "loc-b2ti09": { e: "Please let us know about allergies beforehand.", t: "Por favor avísenos de las alergias de antemano.", s: "Al pedir que algo se haga con anticipación.", sEn: "When asking that something be done in advance.", n: "Va al final de la frase; significa 'antes, con anticipación'.", nEn: "It goes at the end of the sentence; it means 'in advance'." },
    "loc-b2ti10": { e: "We'll visit the museum and have lunch afterwards.", t: "Visitaremos el museo y luego almorzaremos.", s: "Al indicar lo que sigue tras una actividad.", sEn: "When indicating what comes after an activity.", n: "En inglés americano suele escribirse 'afterward', sin 's'.", nEn: "In American English it's often 'afterward', without the 's'." },
    "loc-b2ti11": { e: "The town gradually filled up as summer began.", t: "El pueblo se fue llenando poco a poco al empezar el verano.", s: "Al describir un cambio lento y constante.", sEn: "When describing a slow, steady change.", n: "Indica progreso paulatino; opuesto de 'suddenly'.", nEn: "It marks step-by-step progress; the opposite of 'suddenly'." },
    "loc-b2ti12": { e: "The weather changed suddenly and the tour was cut short.", t: "El clima cambió de repente y el tour se acortó.", s: "Al narrar algo inesperado y rápido.", sEn: "When narrating something unexpected and fast.", n: "Marca un cambio brusco; muy usado al contar historias.", nEn: "It marks an abrupt change; common when telling stories." },
    "loc-b2ti13": { e: "Let me know immediately if anything goes wrong.", t: "Avíseme inmediatamente si algo sale mal.", s: "Al pedir una reacción sin demora.", sEn: "When asking for a reaction without delay.", n: "Más fuerte que 'soon'; el acento va en la segunda sílaba.", nEn: "Stronger than 'soon'; stress falls on the second syllable." },
    "loc-b2ti14": { e: "We recently added vegan options to the menu.", t: "Hace poco agregamos opciones veganas al menú.", s: "Al mencionar algo que pasó no hace mucho.", sEn: "When mentioning something that happened not long ago.", n: "Funciona con pasado simple o present perfect.", nEn: "It works with the simple past or the present perfect." },
    "loc-b2ti15": { e: "The phone was ringing constantly during the storm.", t: "El teléfono sonaba constantemente durante la tormenta.", s: "Al describir algo que pasa sin parar.", sEn: "When describing something that happens non-stop.", n: "A veces da idea de molestia por la repetición continua.", nEn: "It can suggest annoyance at the non-stop repetition." },
    "loc-b2ti16": { e: "The pool is temporarily closed for cleaning.", t: "La piscina está cerrada temporalmente por limpieza.", s: "Al avisar que algo es solo por un tiempo.", sEn: "When warning that something is only for a while.", n: "Subraya que no es permanente; opuesto de 'permanently'.", nEn: "It stresses it isn't permanent; the opposite of 'permanently'." },
    "loc-b2ti17": { e: "Sooner or later, every guest asks for the Wi-Fi password.", t: "Tarde o temprano, cada huésped pide la contraseña del Wi-Fi.", s: "Al decir que algo acabará pasando sin remedio.", sEn: "When saying something is bound to happen.", n: "Expresión fija; el orden 'sooner or later' no se invierte.", nEn: "A fixed phrase; the order 'sooner or later' isn't reversed." },
    "loc-b2ti18": { e: "From now on, we'll confirm every booking by email.", t: "De ahora en adelante, confirmaremos cada reserva por correo.", s: "Al anunciar un cambio que empieza ya y sigue.", sEn: "When announcing a change that starts now and continues.", n: "Marca el inicio de una nueva costumbre o regla.", nEn: "It marks the start of a new habit or rule." },
    "loc-b2em01": { e: "By Friday I felt completely overwhelmed by the number of bookings.", t: "Para el viernes me sentía totalmente abrumado por la cantidad de reservas.", s: "Cuando tienes demasiadas tareas o emociones al mismo tiempo.", sEn: "When you have too many tasks or feelings at once.", n: "La \"h\" es muda: suena \"ou-ver-UÉLMD\"; va con \"feel/be overwhelmed\".", nEn: "Use it as 'feel/be overwhelmed'; the 'h' is silent, say 'overwelmd'." },
    "loc-b2em02": { e: "He was reluctant to change his plans, but he finally agreed.", t: "Estaba reacio a cambiar sus planes, pero al final aceptó.", s: "Cuando alguien no quiere hacer algo, aunque al final lo haga.", sEn: "When someone doesn't want to do something, even if they end up doing it.", n: "Se usa con 'to + verbo': 'reluctant to go', 'reluctant to help'.", nEn: "Use it with 'to + verb': 'reluctant to go', 'reluctant to help'." },
    "loc-b2em03": { e: "I always feel anxious before a job interview.", t: "Siempre me siento ansioso antes de una entrevista de trabajo.", s: "Cuando estás preocupado o inquieto por algo que va a pasar.", sEn: "When you feel worried or uneasy about something coming up.", n: "Se escribe con 'x' pero suena 'ank-shus'; no lo confundas con 'anxiety' (sustantivo).", nEn: "Spelled with 'x' but sounds like 'ank-shus'; the noun is 'anxiety'." },
    "loc-b2em04": { e: "She was thrilled to hear she got the promotion.", t: "Estaba emocionadísima al enterarse de que la ascendieron.", s: "Cuando algo te hace muy feliz o entusiasmado.", sEn: "When something makes you very happy or excited.", n: "Más fuerte que 'happy'; suele ir 'thrilled to' o 'thrilled about'.", nEn: "Stronger than 'happy'; usually 'thrilled to' or 'thrilled about'." },
    "loc-b2em05": { e: "I get frustrated when the wifi keeps dropping at work.", t: "Me frustro cuando el wifi se cae todo el tiempo en el trabajo.", s: "Cuando algo te molesta porque no sale como esperabas.", sEn: "When something annoys you because it isn't going as you hoped.", n: "El acento va en la segunda sílaba: frus-TRA-ted, no FRUS-tra-ted.", nEn: "Stress the second syllable: frus-TRA-ted, not FRUS-tra-ted." },
    "loc-b2em06": { e: "I was so embarrassed when I forgot the customer's name.", t: "Me dio mucha vergüenza cuando olvidé el nombre del cliente.", s: "Cuando sientes vergüenza por algo que hiciste o pasó.", sEn: "When you feel ashamed or self-conscious about something.", n: "Lleva doble 'r' y doble 's'; no significa 'embarazada' (pregnant).", nEn: "Double 'r' and double 's'; it does NOT mean 'pregnant'." },
    "loc-b2em07": { e: "We were disappointed with the hotel's poor service.", t: "Quedamos decepcionados con el mal servicio del hotel.", s: "Cuando algo no cumple tus expectativas.", sEn: "When something doesn't meet your expectations.", n: "Se dice 'disappointed with/in' algo o alguien, o 'disappointed that'.", nEn: "Say 'disappointed with/in' something or someone, or 'disappointed that'." },
    "loc-b2em08": { e: "I'm a little envious of her relaxed lifestyle.", t: "Le tengo un poco de envidia a su estilo de vida relajado.", s: "Cuando deseas algo que otra persona tiene.", sEn: "When you want something that another person has.", n: "Va con 'of': 'envious of someone'; es más formal que 'jealous'.", nEn: "Use 'of': 'envious of someone'; slightly more formal than 'jealous'." },
    "loc-b2em09": { e: "I'm thankful for everything my team did this week.", t: "Estoy agradecido por todo lo que hizo mi equipo esta semana.", s: "Cuando aprecias algo que alguien hizo por ti.", sEn: "When you appreciate something someone did for you.", n: "Va con 'for' algo y 'to' alguien; 'thankful for the help'.", nEn: "Use 'for' something and 'to' someone; 'thankful for the help'." },
    "loc-b2em10": { e: "After months of practice, she felt confident speaking English.", t: "Después de meses de práctica, se sintió segura hablando inglés.", s: "Cuando crees en tus propias capacidades.", sEn: "When you believe in your own abilities.", n: "'Confident' es el adjetivo; 'confidence' el sustantivo. Va con 'about/in'.", nEn: "'Confident' is the adjective; 'confidence' the noun. Use 'about/in'." },
    "loc-b2em11": { e: "He felt ashamed of the way he had spoken to his mother.", t: "Se sintió avergonzado por cómo le había hablado a su madre.", s: "Cuando sientes culpa o vergüenza por una conducta tuya.", sEn: "When you feel guilt or shame about your own behaviour.", n: "Va con 'of': 'ashamed of yourself'; es más profundo que 'embarrassed'.", nEn: "Use 'of': 'ashamed of yourself'; deeper than 'embarrassed'." },
    "loc-b2em12": { e: "I was so relieved when the guests finally found their passports.", t: "Sentí un gran alivio cuando los huéspedes por fin encontraron sus pasaportes.", s: "Cuando desaparece una preocupación o un problema.", sEn: "When a worry or problem finally goes away.", n: "El sustantivo es 'relief'; va con 'to' o 'that': 'relieved that it's over'.", nEn: "The noun is 'relief'; use 'to' or 'that': 'relieved that it's over'." },
    "loc-b2em13": { e: "I'm curious about how the new booking system works.", t: "Tengo curiosidad por saber cómo funciona el nuevo sistema de reservas.", s: "Cuando quieres saber o aprender más sobre algo.", sEn: "When you want to know or learn more about something.", n: "Va con 'about': 'curious about something'; el sustantivo es 'curiosity'.", nEn: "Use 'about': 'curious about something'; the noun is 'curiosity'." },
    "loc-b2em14": { e: "The manager was annoyed that the report was late again.", t: "El gerente estaba molesto porque el informe llegó tarde otra vez.", s: "Cuando algo pequeño te irrita o fastidia.", sEn: "When something small irritates or bothers you.", n: "Va con 'with' alguien y 'at/about/by' algo; el verbo es 'to annoy'.", nEn: "Use 'with' someone and 'at/about/by' something; the verb is 'to annoy'." },
    "loc-b2em15": { e: "After a long shift, she felt content just sitting quietly at home.", t: "Tras un turno largo, se sentía a gusto solo de estar sentada tranquila en casa.", s: "Cuando estás tranquilo y satisfecho con lo que tienes.", sEn: "When you feel calm and satisfied with what you have.", n: "Como adjetivo el acento va al final: con-TENT; el sustantivo CON-tent es 'contenido'.", nEn: "As an adjective stress the end: con-TENT; the noun CON-tent means 'content/material'." },
    "loc-b2em16": { e: "The new trainee is eager to learn everything about the job.", t: "El nuevo aprendiz tiene muchas ganas de aprender todo sobre el trabajo.", s: "Cuando tienes muchas ganas o entusiasmo por hacer algo.", sEn: "When you are very keen or enthusiastic to do something.", n: "Va con 'to + verbo' o 'for': 'eager to start', 'eager for feedback'.", nEn: "Use 'to + verb' or 'for': 'eager to start', 'eager for feedback'." },
    "loc-b2em17": { e: "I felt uneasy about leaving the front desk unattended.", t: "Me sentía intranquilo de dejar la recepción sin atender.", s: "Cuando algo te da una sensación de inquietud o duda.", sEn: "When something gives you a sense of worry or doubt.", n: "Va con 'about': 'uneasy about something'; suena más sutil que 'anxious'.", nEn: "Use 'about': 'uneasy about something'; subtler than 'anxious'." },
    "loc-b2em18": { e: "She was deeply moved by the guest's kind thank-you note.", t: "Quedó profundamente conmovida por la amable nota de agradecimiento del huésped.", s: "Cuando algo te toca el corazón o te emociona.", sEn: "When something touches your heart or stirs your feelings.", n: "Va con 'by': 'moved by something'; 'deeply moved' suena natural.", nEn: "Use 'by': 'moved by something'; 'deeply moved' sounds natural." },
    "loc-b2pe01": { e: "She's the most reliable person on the team — she never misses a shift.", t: "Es la persona más confiable del equipo; nunca falta a un turno.", s: "Cuando describes a alguien en quien se puede confiar.", sEn: "When you describe someone you can depend on.", n: "El sustantivo es 'reliability'; el contrario es 'unreliable'.", nEn: "The noun is 'reliability'; the opposite is 'unreliable'." },
    "loc-b2pe02": { e: "He's too stubborn to admit he made a mistake.", t: "Es demasiado terco para admitir que cometió un error.", s: "Cuando alguien no cambia de opinión por nada.", sEn: "When someone refuses to change their mind.", n: "La 'u' suena como 'a' corta: 'STA-born', no 'STU-born'.", nEn: "The 'u' sounds like a short 'a': 'STA-born', not 'STU-born'." },
    "loc-b2pe03": { e: "Our boss is very generous with bonuses at the end of the year.", t: "Nuestro jefe es muy generoso con los bonos a fin de año.", s: "Cuando alguien da o comparte con gusto.", sEn: "When someone gives or shares willingly.", n: "Va con 'with': 'generous with'; el sustantivo es 'generosity'.", nEn: "Use 'with': 'generous with'; the noun is 'generosity'." },
    "loc-b2pe04": { e: "She's ambitious and wants to manage her own hotel one day.", t: "Es ambiciosa y quiere dirigir su propio hotel algún día.", s: "Cuando alguien tiene grandes metas y trabaja por ellas.", sEn: "When someone has big goals and works toward them.", n: "La 't' suena 'sh': 'am-BI-shus'; el sustantivo es 'ambition'.", nEn: "The 't' sounds like 'sh': 'am-BI-shus'; the noun is 'ambition'." },
    "loc-b2pe05": { e: "I'd rather work with an honest colleague than a clever one.", t: "Prefiero trabajar con un colega honesto que con uno astuto.", s: "Cuando alguien dice la verdad y no engaña.", sEn: "When someone tells the truth and doesn't cheat.", n: "La 'h' es muda: suena 'ONest'; el sustantivo es 'honesty'.", nEn: "The 'h' is silent: say 'ONest'; the noun is 'honesty'." },
    "loc-b2pe06": { e: "He's a bit thin-skinned, so choose your words carefully with him.", t: "Es un poco susceptible, así que elige bien tus palabras con él.", s: "Cuando alguien se ofende o se hiere con facilidad.", sEn: "When someone is easily offended or hurt.", n: "Lleva guion; el contrario es 'thick-skinned' (de piel dura, que aguanta críticas).", nEn: "Hyphenated; the opposite is 'thick-skinned' (able to take criticism)." },
    "loc-b2pe07": { e: "My new manager is easy-going and rarely gets stressed.", t: "Mi nuevo gerente es relajado y casi nunca se estresa.", s: "Cuando alguien es tranquilo y poco exigente.", sEn: "When someone is relaxed and not demanding.", n: "Lleva guion como adjetivo; describe a personas, no a situaciones.", nEn: "Hyphenated as an adjective; describes people, not situations." },
    "loc-b2pe08": { e: "You need to be outgoing to work at the reception desk.", t: "Necesitas ser sociable para trabajar en la recepción.", s: "Cuando alguien disfruta conocer gente y socializar.", sEn: "When someone enjoys meeting people and socialising.", n: "Es lo contrario de 'shy'; 'extroverted' es más formal.", nEn: "It's the opposite of 'shy'; 'extroverted' is more formal." },
    "loc-b2pe09": { e: "He was too shy to ask the customer for feedback.", t: "Era demasiado tímido para pedirle opinión al cliente.", s: "Cuando alguien se siente incómodo al hablar con otros.", sEn: "When someone feels uncomfortable talking to others.", n: "Suena 'shái', rima con 'my'; el sustantivo es 'shyness'.", nEn: "Sounds like 'shy', rhymes with 'my'; the noun is 'shyness'." },
    "loc-b2pe10": { e: "She's a hardworking waitress who never complains about long shifts.", t: "Es una mesera trabajadora que nunca se queja de los turnos largos.", s: "Cuando alguien se esfuerza mucho en su trabajo.", sEn: "When someone puts a lot of effort into their work.", n: "Se escribe junto o con guion: 'hard-working'; no digas 'hard worker' como adjetivo.", nEn: "Written as one word or hyphenated: 'hard-working'; not 'hard worker' as an adjective." },
    "loc-b2pe11": { e: "It was selfish of him to take the last day off without asking.", t: "Fue egoísta de su parte tomarse el último día libre sin preguntar.", s: "Cuando alguien solo piensa en sí mismo.", sEn: "When someone only thinks about themselves.", n: "Construcción: 'It was selfish of someone to...'; el contrario es 'selfless'.", nEn: "Pattern: 'It was selfish of someone to...'; the opposite is 'selfless'." },
    "loc-b2pe12": { e: "It was very thoughtful of you to remember my birthday.", t: "Fue muy considerado de tu parte acordarte de mi cumpleaños.", s: "Cuando alguien piensa en cómo cuidar a los demás.", sEn: "When someone thinks about how to look after others.", n: "La 'gh' es muda: suena 'ZOT-ful'; también significa 'pensativo'.", nEn: "The 'gh' is silent: say 'THOT-ful'; it can also mean 'pensive'." },
    "loc-b2pe13": { e: "It was brave of her to speak up during the meeting.", t: "Fue valiente de su parte alzar la voz durante la reunión.", s: "Cuando alguien enfrenta el miedo o el peligro.", sEn: "When someone faces fear or danger.", n: "El sustantivo es 'bravery'; 'courageous' es un sinónimo más formal.", nEn: "The noun is 'bravery'; 'courageous' is a more formal synonym." },
    "loc-b2pe14": { e: "Despite his success, he stayed modest about his achievements.", t: "A pesar de su éxito, se mantuvo modesto sobre sus logros.", s: "Cuando alguien no presume de sus logros.", sEn: "When someone doesn't boast about their achievements.", n: "El sustantivo es 'modesty'; va con 'about': 'modest about'.", nEn: "The noun is 'modesty'; use 'about': 'modest about'." },
    "loc-b2pe15": { e: "Our most loyal customers come back every summer.", t: "Nuestros clientes más leales vuelven cada verano.", s: "Cuando alguien apoya o es fiel a otros con constancia.", sEn: "When someone stays faithful and supportive over time.", n: "El sustantivo es 'loyalty'; común en 'loyalty card' (tarjeta de fidelidad).", nEn: "The noun is 'loyalty'; common in 'loyalty card'." },
    "loc-b2pe16": { e: "The tour guide was so witty that the whole group kept laughing.", t: "El guía era tan ingenioso que todo el grupo se reía sin parar.", s: "Cuando alguien es gracioso de forma inteligente y rápida.", sEn: "When someone is funny in a clever, quick way.", n: "El sustantivo es 'wit'; no es lo mismo que 'funny', es más agudo.", nEn: "The noun is 'wit'; not the same as 'funny', it's sharper." },
    "loc-b2pe17": { e: "You have to be patient when you train new staff.", t: "Hay que ser paciente cuando capacitas a personal nuevo.", s: "Cuando alguien sabe esperar con calma sin enojarse.", sEn: "When someone can wait calmly without getting upset.", n: "El sustantivo es 'patience'; ojo, 'patient' también significa 'paciente' médico.", nEn: "The noun is 'patience'; note 'patient' also means a medical 'patient'." },
    "loc-b2pe18": { e: "He came across as arrogant when he ignored the staff's ideas.", t: "Pareció arrogante cuando ignoró las ideas del personal.", s: "Cuando alguien se cree superior a los demás.", sEn: "When someone thinks they are better than everyone else.", n: "El sustantivo es 'arrogance'; el contrario es 'humble' o 'modest'.", nEn: "The noun is 'arrogance'; the opposite is 'humble' or 'modest'." },
    "loc-b2ab01": { e: "Working freelance gave her the freedom to choose her own hours.", t: "Trabajar por cuenta propia le dio la libertad de elegir sus horarios.", s: "Cuando hablas del derecho o la posibilidad de actuar libremente.", sEn: "When you talk about the right or chance to act freely.", n: "Va con 'of' o 'to': 'freedom of speech', 'freedom to choose'.", nEn: "Use 'of' or 'to': 'freedom of speech', 'freedom to choose'." },
    "loc-b2ab02": { e: "Finishing the course was a real achievement for her.", t: "Terminar el curso fue un verdadero logro para ella.", s: "Cuando algo que se consigue con esfuerzo te enorgullece.", sEn: "When something earned through effort makes you proud.", n: "El verbo es 'to achieve'; 'sense of achievement' es muy común.", nEn: "The verb is 'to achieve'; 'sense of achievement' is very common." },
    "loc-b2ab03": { e: "He learned more from his failures than from his wins.", t: "Aprendió más de sus fracasos que de sus triunfos.", s: "Cuando algo no sale o no funciona como esperabas.", sEn: "When something doesn't work out as hoped.", n: "El verbo es 'to fail'; 'fear of failure' es una colocación común.", nEn: "The verb is 'to fail'; 'fear of failure' is a common collocation." },
    "loc-b2ab04": { e: "Sometimes it's hard to tell the truth to a difficult customer.", t: "A veces es difícil decir la verdad a un cliente difícil.", s: "Cuando hablas de lo que es real o cierto.", sEn: "When you talk about what is real or correct.", n: "Va con 'tell': 'tell the truth'; el adjetivo es 'true'.", nEn: "Use 'tell': 'tell the truth'; the adjective is 'true'." },
    "loc-b2ab05": { e: "Her belief that hard work pays off keeps her motivated.", t: "Su creencia de que el esfuerzo vale la pena la mantiene motivada.", s: "Cuando hablas de algo que alguien considera verdadero.", sEn: "When you talk about something someone holds to be true.", n: "El verbo es 'to believe'; va con 'in': 'belief in something'.", nEn: "The verb is 'to believe'; use 'in': 'belief in something'." },
    "loc-b2ab06": { e: "The main purpose of the meeting was to review the budget.", t: "El propósito principal de la reunión era revisar el presupuesto.", s: "Cuando hablas de la razón o el fin de algo.", sEn: "When you talk about the reason or aim of something.", n: "'On purpose' significa 'a propósito', adrede; ojo con ese giro.", nEn: "'On purpose' means 'deliberately'; watch that phrase." },
    "loc-b2ab07": { e: "Her knowledge of local history impressed the whole tour group.", t: "Su conocimiento de la historia local impresionó a todo el grupo.", s: "Cuando hablas de lo que alguien sabe o ha aprendido.", sEn: "When you talk about what someone knows or has learned.", n: "La 'k' es muda: suena 'NOlech'; es incontable, sin plural.", nEn: "The 'k' is silent: say 'NOlij'; it's uncountable, no plural." },
    "loc-b2ab08": { e: "Years of experience in tourism made him a calm problem-solver.", t: "Años de experiencia en turismo lo hicieron un solucionador tranquilo.", s: "Cuando hablas de lo vivido o aprendido con el tiempo.", sEn: "When you talk about what someone has done or learned over time.", n: "Incontable cuando es 'práctica'; contable cuando es 'una vivencia'.", nEn: "Uncountable as 'know-how'; countable as 'an event you lived'." },
    "loc-b2ab09": { e: "This job is a great opportunity to improve your English.", t: "Este trabajo es una gran oportunidad para mejorar tu inglés.", s: "Cuando hablas de una buena ocasión para hacer algo.", sEn: "When you talk about a good chance to do something.", n: "Va con 'to + verbo' o 'for': 'opportunity to grow', 'opportunity for change'.", nEn: "Use 'to + verb' or 'for': 'opportunity to grow', 'opportunity for change'." },
    "loc-b2ab10": { e: "Closing the bar safely is the manager's responsibility.", t: "Cerrar el bar de forma segura es responsabilidad del gerente.", s: "Cuando hablas de un deber o una tarea que te corresponde.", sEn: "When you talk about a duty or task that is yours.", n: "Va con 'for': 'responsibility for'; el adjetivo es 'responsible'.", nEn: "Use 'for': 'responsibility for'; the adjective is 'responsible'." },
    "loc-b2ab11": { e: "Speaking two languages is a big advantage in this industry.", t: "Hablar dos idiomas es una gran ventaja en este sector.", s: "Cuando hablas de algo que te pone en mejor posición.", sEn: "When you talk about something that puts you ahead.", n: "Va con 'over': 'advantage over'; 'take advantage of' es 'aprovechar'.", nEn: "Use 'over': 'advantage over'; 'take advantage of' means 'to make use of'." },
    "loc-b2ab12": { e: "The main disadvantage of the night shift is the lack of sleep.", t: "La principal desventaja del turno nocturno es la falta de sueño.", s: "Cuando hablas de algo negativo o un punto en contra.", sEn: "When you talk about a downside or a drawback.", n: "Es el contrario de 'advantage'; 'at a disadvantage' es 'en desventaja'.", nEn: "It's the opposite of 'advantage'; 'at a disadvantage' means 'worse off'." },
    "loc-b2ab13": { e: "The hotel has clear rules about staff behaviour with guests.", t: "El hotel tiene reglas claras sobre el comportamiento del personal con los huéspedes.", s: "Cuando hablas de cómo actúa una persona.", sEn: "When you talk about how a person acts.", n: "En EE. UU. se escribe 'behavior' sin 'u'; el verbo es 'to behave'.", nEn: "In the US it's spelled 'behavior' without the 'u'; the verb is 'to behave'." },
    "loc-b2ab14": { e: "A positive attitude makes a huge difference with customers.", t: "Una actitud positiva hace una gran diferencia con los clientes.", s: "Cuando hablas de la disposición o forma de pensar de alguien.", sEn: "When you talk about someone's mindset or outlook.", n: "Va con 'towards': 'attitude towards work'; ojo, no es 'aptitude' (capacidad).", nEn: "Use 'towards': 'attitude towards work'; don't confuse it with 'aptitude' (skill)." },
    "loc-b2ab15": { e: "Her ability to stay calm under pressure is impressive.", t: "Su capacidad para mantener la calma bajo presión es impresionante.", s: "Cuando hablas de lo que alguien es capaz de hacer.", sEn: "When you talk about what someone is able to do.", n: "Va con 'to + verbo': 'ability to do'; el adjetivo es 'able'.", nEn: "Use 'to + verb': 'ability to do'; the adjective is 'able'." },
    "loc-b2ab16": { e: "It takes a lot of effort to keep every guest happy.", t: "Cuesta mucho esfuerzo mantener contento a cada huésped.", s: "Cuando hablas del trabajo o la energía que pones en algo.", sEn: "When you talk about the work or energy you put in.", n: "Va con 'make' o 'put in': 'make an effort', 'put in effort'.", nEn: "Use 'make' or 'put in': 'make an effort', 'put in effort'." },
    "loc-b2ab17": { e: "We've made good progress with the new training programme.", t: "Hemos hecho un buen avance con el nuevo programa de capacitación.", s: "Cuando hablas de mejorar o avanzar hacia una meta.", sEn: "When you talk about improving or moving toward a goal.", n: "Incontable: 'much progress', no 'progresses'; va con 'make'.", nEn: "Uncountable: 'much progress', not 'progresses'; use 'make'." },
    "loc-b2ab18": { e: "I didn't understand the real meaning of his comment at first.", t: "Al principio no entendí el verdadero significado de su comentario.", s: "Cuando hablas de lo que algo quiere decir o representa.", sEn: "When you talk about what something stands for or expresses.", n: "El verbo es 'to mean'; 'meaningful' es 'significativo'.", nEn: "The verb is 'to mean'; 'meaningful' means 'significant'." },
    "loc-b2co01": { e: "We need to make a decision about the new supplier today.", t: "Tenemos que tomar una decisión sobre el nuevo proveedor hoy.", s: "Cuando hay que elegir entre opciones.", sEn: "When you have to choose between options.", n: "En inglés se dice 'make' una decisión, nunca 'take a decision' (salvo UK formal).", nEn: "In English you 'make' a decision, not 'take' one (except formal UK)." },
    "loc-b2co02": { e: "A good manager takes responsibility when something goes wrong.", t: "Un buen gerente asume la responsabilidad cuando algo sale mal.", s: "Cuando alguien acepta la culpa o el deber de algo.", sEn: "When someone accepts the blame or duty for something.", n: "Va con 'for': 'take responsibility for'; usa 'take', no 'make'.", nEn: "Use 'for': 'take responsibility for'; use 'take', not 'make'." },
    "loc-b2co03": { e: "Please pay attention to the safety briefing before the dive.", t: "Por favor presta atención a la charla de seguridad antes del buceo.", s: "Cuando pides concentración o cuidado en algo.", sEn: "When you ask for focus or care about something.", n: "Va con 'to': 'pay attention to'; se usa 'pay', no 'put'.", nEn: "Use 'to': 'pay attention to'; the verb is 'pay', not 'put'." },
    "loc-b2co04": { e: "It was great working with you — let's keep in touch.", t: "Fue genial trabajar contigo; mantengámonos en contacto.", s: "Cuando te despides y quieres seguir en comunicación.", sEn: "When you say goodbye but want to stay in contact.", n: "También 'stay in touch'; va con 'with': 'keep in touch with'.", nEn: "Also 'stay in touch'; use 'with': 'keep in touch with'." },
    "loc-b2co05": { e: "The students are making good progress with their pronunciation.", t: "Los estudiantes están haciendo buenos progresos con su pronunciación.", s: "Cuando avanzas o mejoras hacia una meta.", sEn: "When you move forward or improve toward a goal.", n: "Va con 'make', nunca 'do'; 'make progress with/on something'.", nEn: "Use 'make', never 'do'; 'make progress with/on something'." },
    "loc-b2co06": { e: "All the staff will take part in the fire drill on Friday.", t: "Todo el personal participará en el simulacro de incendio el viernes.", s: "Cuando te unes o participas en una actividad.", sEn: "When you join or participate in an activity.", n: "Va con 'in': 'take part in'; equivale a 'participate in'.", nEn: "Use 'in': 'take part in'; equivalent to 'participate in'." },
    "loc-b2co07": { e: "We've been doing business with that agency for ten years.", t: "Llevamos diez años haciendo negocios con esa agencia.", s: "Cuando comercias o trabajas con otra empresa.", sEn: "When you trade or work with another company.", n: "Va con 'do', no 'make'; 'do business with someone'.", nEn: "Use 'do', not 'make'; 'do business with someone'." },
    "loc-b2co08": { e: "He broke his promise to cover my shift on Saturday.", t: "Rompió su promesa de cubrir mi turno el sábado.", s: "Cuando alguien no cumple lo que prometió.", sEn: "When someone fails to do what they promised.", n: "El contrario es 'keep a promise' (cumplir una promesa).", nEn: "The opposite is 'keep a promise'." },
    "loc-b2co09": { e: "You run a risk of losing customers if the service is slow.", t: "Corres el riesgo de perder clientes si el servicio es lento.", s: "Cuando te expones a un posible problema o peligro.", sEn: "When you expose yourself to a possible problem.", n: "También 'take a risk'; 'run the risk of + -ing' es muy común.", nEn: "Also 'take a risk'; 'run the risk of + -ing' is very common." },
    "loc-b2co10": { e: "The team worked late to meet the deadline for the report.", t: "El equipo trabajó hasta tarde para cumplir el plazo del informe.", s: "Cuando terminas algo a tiempo, antes de la fecha límite.", sEn: "When you finish something on time, before the due date.", n: "Va con 'meet'; 'miss a deadline' es 'no cumplir el plazo'.", nEn: "Use 'meet'; 'miss a deadline' means to fail to finish in time." },
    "loc-b2co11": { e: "The campaign aims to raise awareness about plastic on the beach.", t: "La campaña busca crear conciencia sobre el plástico en la playa.", s: "Cuando informas para que la gente entienda un tema.", sEn: "When you inform people so they understand an issue.", n: "Va con 'raise' y 'of/about': 'raise awareness of/about'.", nEn: "Use 'raise' and 'of/about': 'raise awareness of/about'." },
    "loc-b2co12": { e: "It's too early to draw a conclusion from just one review.", t: "Es muy pronto para sacar una conclusión de una sola reseña.", s: "Cuando llegas a una idea final tras analizar algo.", sEn: "When you reach a final idea after looking at something.", n: "Va con 'draw', no 'take'; 'draw a conclusion from something'.", nEn: "Use 'draw', not 'take'; 'draw a conclusion from something'." },
    "loc-b2co13": { e: "His explanation didn't really make sense to the new staff.", t: "Su explicación no tenía mucho sentido para el personal nuevo.", s: "Cuando algo es lógico y se entiende.", sEn: "When something is logical and easy to understand.", n: "Va con 'make'; 'make sense of something' es 'entender algo'.", nEn: "Use 'make'; 'make sense of something' means to understand it." },
    "loc-b2co14": { e: "You should take advantage of the free training while it lasts.", t: "Deberías aprovechar la capacitación gratis mientras dure.", s: "Cuando usas una oportunidad a tu favor.", sEn: "When you use an opportunity to your benefit.", n: "Va con 'of': 'take advantage of'; puede ser positivo o aprovecharse de alguien.", nEn: "Use 'of': 'take advantage of'; can be positive or mean exploiting someone." },
    "loc-b2co15": { e: "Good reviews have a real impact on our bookings.", t: "Las buenas reseñas tienen un impacto real en nuestras reservas.", s: "Cuando algo influye o afecta a algo más.", sEn: "When something influences or affects something else.", n: "Va con 'on': 'have an impact on'; 'impact' como sustantivo lleva el acento al inicio.", nEn: "Use 'on': 'have an impact on'; the noun 'impact' is stressed at the start." },
    "loc-b2co16": { e: "At the start of the season we set a goal to raise our ratings.", t: "Al inicio de la temporada fijamos una meta de subir nuestras calificaciones.", s: "Cuando defines un objetivo que quieres alcanzar.", sEn: "When you define an objective you want to reach.", n: "Va con 'set'; 'reach/achieve a goal' es 'alcanzar la meta'.", nEn: "Use 'set'; 'reach/achieve a goal' means to attain it." },
    "loc-b2co17": { e: "After a long talk, both sides reached an agreement on the price.", t: "Tras una larga charla, ambas partes llegaron a un acuerdo sobre el precio.", s: "Cuando dos partes resuelven una negociación.", sEn: "When two sides settle a negotiation.", n: "Va con 'reach' o 'come to'; 'reach an agreement on/about something'.", nEn: "Use 'reach' or 'come to'; 'reach an agreement on/about something'." },
    "loc-b2co18": { e: "Could you give me some feedback on how I handled that complaint?", t: "¿Podrías darme retroalimentación sobre cómo manejé esa queja?", s: "Cuando comentas a alguien cómo lo hizo para que mejore.", sEn: "When you tell someone how they did so they can improve.", n: "Va con 'give' y 'on': 'give feedback on'; 'feedback' es incontable.", nEn: "Use 'give' and 'on': 'give feedback on'; 'feedback' is uncountable." },
    "loc-b2tj01": { e: "We have a tight deadline, so the report has to be ready by Friday.", t: "Tenemos un plazo muy ajustado, así que el reporte debe estar listo el viernes.", s: "Cuando hablas de la fecha límite de un proyecto en el trabajo.", sEn: "When talking about the cut-off date for a project at work.", n: "Se usa con \"meet a deadline\" (cumplir) o \"miss a deadline\" (incumplir).", nEn: "Use it with \"meet a deadline\" or \"miss a deadline\"." },
    "loc-b2tj02": { e: "My workload has doubled since two people left the team.", t: "Mi carga de trabajo se duplicó desde que dos personas dejaron el equipo.", s: "Cuando describes cuánto trabajo tienes acumulado.", sEn: "When describing how much work you have piled up.", n: "\"Heavy workload\" es mucho trabajo; \"light workload\", poco.", nEn: "\"Heavy workload\" is a lot of work; \"light workload\" is little." },
    "loc-b2tj03": { e: "Finishing the project on time was a real achievement for the whole team.", t: "Terminar el proyecto a tiempo fue un verdadero logro para todo el equipo.", s: "Cuando destacas algo que lograste, por ejemplo en una entrevista.", sEn: "When highlighting something you accomplished, e.g. in an interview.", n: "En el CV, lista \"key achievements\" para destacar resultados.", nEn: "On a CV, list \"key achievements\" to highlight results." },
    "loc-b2tj04": { e: "She got a promotion after three years as a team leader.", t: "Ella consiguió un ascenso tras tres años como líder de equipo.", s: "Cuando subes a un puesto mejor dentro de la empresa.", sEn: "When you move up to a better position in the company.", n: "Falso amigo: aquí no significa \"promoción\" de ventas, sino ascenso laboral.", nEn: "False friend: here it's a job promotion, not a sales \"promotion\"." },
    "loc-b2tj05": { e: "I asked a colleague to cover my shift while I was sick.", t: "Le pedí a un colega que cubriera mi turno mientras estuve enfermo.", s: "Cuando te refieres a alguien que trabaja contigo.", sEn: "When referring to someone you work with.", n: "\"Colleague\" suena más formal que \"coworker\"; la \"-ue\" final es muda (termina en sonido /g/).", nEn: "\"Colleague\" sounds more formal than \"coworker\"; the final \"-ue\" is silent (it ends in a /g/ sound)." },
    "loc-b2tj06": { e: "Communication is a key skill in any customer-facing job.", t: "La comunicación es una habilidad clave en cualquier trabajo de cara al cliente.", s: "Cuando hablas de lo que sabes hacer profesionalmente.", sEn: "When talking about what you can do professionally.", n: "\"Soft skills\" son sociales; \"hard skills\", técnicas.", nEn: "\"Soft skills\" are social; \"hard skills\" are technical." },
    "loc-b2tj07": { e: "I have three tasks to finish before the end of the day.", t: "Tengo tres tareas que terminar antes de que acabe el día.", s: "Cuando hablas de una actividad concreta del trabajo.", sEn: "When talking about a specific work activity.", n: "\"To carry out a task\" significa realizar una tarea.", nEn: "\"To carry out a task\" means to complete a task." },
    "loc-b2tj08": { e: "We have a team meeting every Monday to plan the week.", t: "Tenemos una reunión de equipo cada lunes para planear la semana.", s: "Cuando te juntas con tus compañeros para coordinar.", sEn: "When you get together with coworkers to coordinate.", n: "\"To hold a meeting\" es convocarla; \"to attend\" es asistir.", nEn: "\"To hold a meeting\" is to call it; \"to attend\" is to go." },
    "loc-b2tj09": { e: "I worked overtime all week to finish the launch.", t: "Trabajé horas extra toda la semana para terminar el lanzamiento.", s: "Cuando trabajas más horas de las normales.", sEn: "When you work more hours than usual.", n: "Es incontable: di \"a lot of overtime\", nunca \"overtimes\".", nEn: "It's uncountable: say \"a lot of overtime\", never \"overtimes\"." },
    "loc-b2tj10": { e: "Good teamwork made the difference on this project.", t: "El buen trabajo en equipo marcó la diferencia en este proyecto.", s: "Cuando valoras la colaboración entre compañeros.", sEn: "When you value collaboration between coworkers.", n: "Es incontable; no se dice \"a teamwork\".", nEn: "It's uncountable; you don't say \"a teamwork\"." },
    "loc-b2tj11": { e: "Training new staff is part of my responsibilities.", t: "Capacitar al personal nuevo es parte de mis responsabilidades.", s: "Cuando describes tus deberes en el puesto.", sEn: "When describing your duties in a role.", n: "\"To take responsibility for\" es asumir la responsabilidad de algo.", nEn: "\"To take responsibility for\" means to own something." },
    "loc-b2tj12": { e: "My manager was happy with my performance this quarter.", t: "Mi jefe quedó contento con mi desempeño este trimestre.", s: "En una evaluación de cómo haces tu trabajo.", sEn: "In a review of how you do your job.", n: "\"Performance review\" es la evaluación de desempeño anual.", nEn: "\"Performance review\" is the annual appraisal." },
    "loc-b2tj13": { e: "I sent my application for the marketing position yesterday.", t: "Envié mi solicitud para el puesto de marketing ayer.", s: "Cuando postulas formalmente a un trabajo.", sEn: "When you formally apply for a job.", n: "\"To submit an application\" es enviarla; \"applicant\" es quien postula.", nEn: "\"To submit an application\" is to send it; \"applicant\" is the person." },
    "loc-b2tj14": { e: "I have a job interview on Thursday, so I'm a bit nervous.", t: "Tengo una entrevista de trabajo el jueves, así que estoy un poco nervioso.", s: "Cuando te citan para evaluarte para un puesto.", sEn: "When you're called to be assessed for a role.", n: "\"Interviewer\" es quien entrevista; \"interviewee\", el candidato.", nEn: "\"Interviewer\" asks; \"interviewee\" is the candidate." },
    "loc-b2tj15": { e: "They interviewed five candidates for the same role.", t: "Entrevistaron a cinco candidatos para el mismo puesto.", s: "Cuando hablas de las personas que postulan a un puesto.", sEn: "When talking about the people applying for a role.", n: "\"The ideal candidate\" es el candidato ideal en los anuncios.", nEn: "\"The ideal candidate\" appears in job ads." },
    "loc-b2tj16": { e: "I'm hoping to ask for a salary raise at my next review.", t: "Espero pedir un aumento de sueldo en mi próxima evaluación.", s: "Cuando quieres ganar más en el mismo puesto.", sEn: "When you want to earn more in the same role.", n: "En el Reino Unido se dice \"pay rise\"; en EE. UU., \"raise\".", nEn: "In the UK it's \"pay rise\"; in the US, \"raise\"." },
    "loc-b2tj17": { e: "She decided to resign after finding a better job.", t: "Ella decidió renunciar tras encontrar un trabajo mejor.", s: "Cuando dejas tu trabajo voluntariamente.", sEn: "When you voluntarily leave your job.", n: "La \"g\" es muda: \"ri-SAIN\". \"To quit\" es más informal.", nEn: "The \"g\" is silent: \"ri-SAIN\". \"To quit\" is more informal." },
    "loc-b2tj18": { e: "The company plans to hire ten more people this year.", t: "La empresa planea contratar a diez personas más este año.", s: "Cuando una empresa toma a alguien para un puesto.", sEn: "When a company takes someone on for a role.", n: "Lo contrario es \"to fire\" (despedir) o \"to lay off\" (despido por recorte).", nEn: "The opposite is \"to fire\" or \"to lay off\" (downsizing)." },
    "loc-b2ng01": { e: "Let's stick to the agenda so the meeting doesn't run late.", t: "Sigamos la agenda para que la reunión no se alargue.", s: "En una reunión, para referirte a los temas a tratar.", sEn: "In a meeting, to refer to the topics to cover.", n: "Falso amigo: aquí es el orden del día, no una agenda de citas.", nEn: "False friend: here it's the list of topics, not a diary." },
    "loc-b2ng02": { e: "I'll send you a detailed proposal by the end of the week.", t: "Le enviaré una propuesta detallada al final de la semana.", s: "Cuando ofreces formalmente una idea o plan a un cliente.", sEn: "When you formally offer an idea or plan to a client.", n: "\"To put forward a proposal\" es presentar una propuesta.", nEn: "\"To put forward a proposal\" means to present one." },
    "loc-b2ng03": { e: "Our biggest client renewed the contract for another year.", t: "Nuestro cliente más grande renovó el contrato por un año más.", s: "Cuando hablas de empresas o personas que contratan tus servicios.", sEn: "When talking about firms or people who hire your services.", n: "\"Client\" es de servicios; \"customer\", de compras en tienda.", nEn: "\"Client\" is for services; \"customer\" for shop purchases." },
    "loc-b2ng04": { e: "The company made a good profit in the last quarter.", t: "La empresa obtuvo una buena ganancia en el último trimestre.", s: "Cuando hablas del dinero que gana un negocio.", sEn: "When talking about the money a business earns.", n: "Lo contrario es \"loss\" (pérdida); \"profitable\" es rentable.", nEn: "The opposite is \"loss\"; \"profitable\" means it makes money." },
    "loc-b2ng05": { e: "They reported a heavy loss after the bad investment.", t: "Reportaron una pérdida fuerte tras la mala inversión.", s: "Cuando un negocio gasta más de lo que gana.", sEn: "When a business spends more than it earns.", n: "\"To make a loss\" es tener pérdidas; \"at a loss\", con pérdida.", nEn: "\"To make a loss\" means to lose money on something." },
    "loc-b2ng06": { e: "We hit our sales target two weeks early this month.", t: "Alcanzamos nuestra meta de ventas dos semanas antes este mes.", s: "Cuando hablas de una cifra u objetivo a alcanzar.", sEn: "When talking about a figure or goal to reach.", n: "\"To meet/hit a target\" es alcanzarlo; \"to miss\", no lograrlo.", nEn: "\"To meet/hit a target\" is to reach it; \"to miss\" is to fail." },
    "loc-b2ng07": { e: "We closed a deal with a new supplier this morning.", t: "Cerramos un trato con un nuevo proveedor esta mañana.", s: "Cuando llegas a un acuerdo comercial.", sEn: "When you reach a business agreement.", n: "\"To close a deal\" es cerrar el trato; \"a good deal\" es una ganga.", nEn: "\"To close a deal\" seals it; \"a good deal\" is a bargain." },
    "loc-b2ng08": { e: "Our marketing strategy focuses on younger customers.", t: "Nuestra estrategia de marketing se centra en clientes más jóvenes.", s: "Cuando hablas del plan general de un negocio.", sEn: "When talking about a business's overall plan.", n: "El adjetivo es \"strategic\" (estratégico).", nEn: "The adjective is \"strategic\"." },
    "loc-b2ng09": { e: "The annual budget for advertising was cut by half.", t: "El presupuesto anual de publicidad se redujo a la mitad.", s: "Cuando hablas del dinero asignado para un período.", sEn: "When talking about money allocated for a period.", n: "\"To be on budget\" es ir dentro del presupuesto.", nEn: "\"To be on budget\" means within the planned amount." },
    "loc-b2ng10": { e: "We're looking for a cheaper supplier for the packaging.", t: "Estamos buscando un proveedor más barato para el empaque.", s: "Cuando hablas de quien te abastece de productos.", sEn: "When talking about who provides you with goods.", n: "El verbo es \"to supply\" (suministrar).", nEn: "The verb is \"to supply\"." },
    "loc-b2ng11": { e: "Please send the invoice to our accounts department.", t: "Por favor envíe la factura a nuestro departamento de cuentas.", s: "Cuando pides o emites un documento de cobro.", sEn: "When you request or issue a billing document.", n: "\"To issue an invoice\" es emitir; \"to settle\", pagar.", nEn: "\"To issue an invoice\" is to send it; \"to settle\", to pay." },
    "loc-b2ng12": { e: "We can't start the work without a signed contract.", t: "No podemos empezar el trabajo sin un contrato firmado.", s: "Cuando formalizas un acuerdo por escrito.", sEn: "When you formalize an agreement in writing.", n: "\"To sign a contract\" es firmarlo; \"to breach\", incumplirlo.", nEn: "\"To sign a contract\" is to sign; \"to breach\" is to break it." },
    "loc-b2ng13": { e: "The two firms formed a partnership to enter new markets.", t: "Las dos empresas formaron una asociación para entrar a nuevos mercados.", s: "Cuando dos empresas colaboran formalmente.", sEn: "When two firms collaborate formally.", n: "\"Partner\" es el socio; \"to partner with\", asociarse con.", nEn: "\"Partner\" is the associate; \"to partner with\" means to team up." },
    "loc-b2ng14": { e: "The product launch is scheduled for next month.", t: "El lanzamiento del producto está programado para el próximo mes.", s: "Cuando una empresa saca algo nuevo al mercado.", sEn: "When a company brings something new to market.", n: "El verbo \"to launch\" rima con \"lunch\" pero con \"o\": \"lonch\".", nEn: "The verb \"to launch\" rhymes with \"lonch\", not \"lunch\"." },
    "loc-b2ng15": { e: "They gained market share after lowering their prices.", t: "Ganaron cuota de mercado tras bajar sus precios.", s: "Cuando hablas de qué parte del mercado controla una empresa.", sEn: "When talking about a firm's slice of the market.", n: "Es incontable; di \"more market share\", no \"market shares\".", nEn: "It's uncountable; say \"more market share\", not \"shares\"." },
    "loc-b2ng16": { e: "We need to keep all the stakeholders informed about the changes.", t: "Necesitamos mantener informadas a todas las partes interesadas sobre los cambios.", s: "Cuando hablas de quienes tienen interés en un proyecto.", sEn: "When talking about those with an interest in a project.", n: "Incluye clientes, empleados, inversores; no solo accionistas.", nEn: "It includes clients, staff, investors, not just shareholders." },
    "loc-b2ng17": { e: "The company's revenue grew by ten percent last year.", t: "Los ingresos de la empresa crecieron un diez por ciento el año pasado.", s: "Cuando hablas del dinero total que entra a un negocio.", sEn: "When talking about a business's total income.", n: "\"Revenue\" es el ingreso bruto; \"profit\" es lo que queda.", nEn: "\"Revenue\" is gross income; \"profit\" is what's left." },
    "loc-b2ng18": { e: "After a long negotiation, both sides agreed on the price.", t: "Tras una larga negociación, ambas partes acordaron el precio.", s: "Cuando dos partes discuten para llegar a un acuerdo.", sEn: "When two sides discuss to reach an agreement.", n: "El verbo es \"to negotiate\"; \"under negotiation\" es en negociación.", nEn: "The verb is \"to negotiate\"; \"under negotiation\" means in progress." },
    "loc-b2di01": { e: "I set a personal budget so I don't overspend.", t: "Fijo un presupuesto personal para no gastar de más.", s: "Cuando planeas cuánto gastar cada mes.", sEn: "When planning how much to spend each month.", n: "\"To stick to a budget\" es ceñirse al presupuesto.", nEn: "\"To stick to a budget\" means not to overspend." },
    "loc-b2di02": { e: "I'm using my savings to pay for the trip.", t: "Estoy usando mis ahorros para pagar el viaje.", s: "Cuando hablas del dinero que has guardado.", sEn: "When talking about money you've put aside.", n: "Casi siempre en plural; \"a savings account\" es cuenta de ahorros.", nEn: "Almost always plural; \"a savings account\" holds them." },
    "loc-b2di03": { e: "She decided to invest part of her salary in stocks.", t: "Ella decidió invertir parte de su sueldo en acciones.", s: "Cuando pones dinero para que crezca con el tiempo.", sEn: "When you put money in to grow it over time.", n: "El sustantivo es \"investment\" (inversión).", nEn: "The noun is \"investment\"." },
    "loc-b2di04": { e: "It took me two years to pay off all my debt.", t: "Me tomó dos años pagar toda mi deuda.", s: "Cuando debes dinero a alguien o a un banco.", sEn: "When you owe money to someone or a bank.", n: "La \"b\" es muda: se dice \"det\". \"In debt\" es endeudado.", nEn: "The \"b\" is silent: say \"det\". \"In debt\" means you owe." },
    "loc-b2di05": { e: "I can't afford a new car right now.", t: "No puedo permitirme un carro nuevo ahora mismo.", s: "Cuando hablas de si tienes dinero para algo.", sEn: "When talking about whether you can pay for something.", n: "Casi siempre con \"can/can't\": \"I can't afford it\".", nEn: "Almost always with \"can/can't\": \"I can't afford it\"." },
    "loc-b2di06": { e: "I took out a loan to start my small business.", t: "Saqué un préstamo para empezar mi pequeño negocio.", s: "Cuando un banco te presta dinero a devolver.", sEn: "When a bank lends you money to pay back.", n: "\"To take out a loan\" es sacar; \"to pay off\", terminar de pagar.", nEn: "\"To take out a loan\" is to get one; \"to pay off\" is to finish it." },
    "loc-b2di07": { e: "The bank raised the interest rate on the loan.", t: "El banco subió la tasa de interés del préstamo.", s: "Cuando hablas de lo que cobra o paga un banco.", sEn: "When talking about what a bank charges or pays.", n: "Falso amigo: \"interest\" aquí es financiero, no curiosidad.", nEn: "False friend: here \"interest\" is financial, not curiosity." },
    "loc-b2di08": { e: "We're still paying off the mortgage on our house.", t: "Todavía estamos pagando la hipoteca de nuestra casa.", s: "Cuando pides un préstamo grande para comprar vivienda.", sEn: "When you take a big loan to buy a home.", n: "La \"t\" es muda: se dice \"MÓR-guech\".", nEn: "The \"t\" is silent: say \"MOR-gage\"." },
    "loc-b2di09": { e: "My monthly expenses went up after I moved downtown.", t: "Mis gastos mensuales subieron después de mudarme al centro.", s: "Cuando hablas de en qué se va tu dinero.", sEn: "When talking about where your money goes.", n: "\"To cut expenses\" es reducir gastos; suele ir en plural.", nEn: "\"To cut expenses\" means to reduce them; usually plural." },
    "loc-b2di10": { e: "A second job gives me extra income each month.", t: "Un segundo empleo me da ingresos extra cada mes.", s: "Cuando hablas del dinero que recibes regularmente.", sEn: "When talking about the money you receive regularly.", n: "Es incontable; di \"a higher income\", no \"incomes\".", nEn: "It's uncountable; say \"a higher income\", not \"incomes\"." },
    "loc-b2di11": { e: "You have to pay tax on everything you earn.", t: "Tienes que pagar impuestos sobre todo lo que ganas.", s: "Cuando hablas del dinero que se paga al Estado.", sEn: "When talking about money paid to the government.", n: "\"Income tax\" es impuesto sobre la renta; plural \"taxes\".", nEn: "\"Income tax\" is on earnings; plural is \"taxes\"." },
    "loc-b2di12": { e: "The bank charges a small fee for international transfers.", t: "El banco cobra una pequeña comisión por transferencias internacionales.", s: "Cuando un servicio te cobra un cargo fijo.", sEn: "When a service charges you a set amount.", n: "\"Fee\" es por servicio; \"fine\" es multa por infracción.", nEn: "\"Fee\" is for a service; \"fine\" is a penalty." },
    "loc-b2di13": { e: "I asked for a refund because the item was broken.", t: "Pedí un reembolso porque el artículo estaba roto.", s: "Cuando te devuelven el dinero de una compra.", sEn: "When you get your money back on a purchase.", n: "El verbo es \"to refund\"; \"to get a refund\" es recibirlo.", nEn: "The verb is \"to refund\"; \"to get a refund\" is to receive it." },
    "loc-b2di14": { e: "The euro is a strong currency compared to many others.", t: "El euro es una moneda fuerte comparada con muchas otras.", s: "Cuando hablas del dinero de un país.", sEn: "When talking about a country's money.", n: "\"Currency\" es la divisa; \"coin\" es la moneda física.", nEn: "\"Currency\" is the money system; \"coin\" is the physical piece." },
    "loc-b2di15": { e: "The exchange rate is bad, so I'll change my money later.", t: "El tipo de cambio está malo, así que cambiaré mi dinero después.", s: "Cuando comparas el valor de dos monedas.", sEn: "When comparing the value of two currencies.", n: "\"Rate\" rima con \"late\"; no lo digas \"rat\".", nEn: "\"Rate\" rhymes with \"late\"; don't say \"rat\"." },
    "loc-b2di16": { e: "I opened a bank account to receive my salary.", t: "Abrí una cuenta bancaria para recibir mi sueldo.", s: "Cuando guardas tu dinero en un banco.", sEn: "When you keep your money in a bank.", n: "\"To open an account\" es abrirla; \"balance\" es el saldo.", nEn: "\"To open an account\" is to start one; \"balance\" is what's in it." },
    "loc-b2di17": { e: "I need to withdraw some cash from the ATM.", t: "Necesito retirar algo de efectivo del cajero.", s: "Cuando sacas dinero de tu cuenta.", sEn: "When you take money out of your account.", n: "Lo contrario es \"to deposit\" (depositar).", nEn: "The opposite is \"to deposit\"." },
    "loc-b2di18": { e: "I still owe my friend twenty dollars from last week.", t: "Todavía le debo veinte dólares a mi amigo de la semana pasada.", s: "Cuando tienes que devolverle dinero a alguien.", sEn: "When you have to pay money back to someone.", n: "La \"w\" es muda: se dice \"ou\", como \"oh\".", nEn: "The \"w\" is silent: say \"oh\"." },
    "loc-b2ed01": { e: "She has a degree in business administration.", t: "Ella tiene un título en administración de empresas.", s: "Cuando hablas de los estudios universitarios terminados.", sEn: "When talking about a completed university qualification.", n: "Falso amigo: \"career\" es trayectoria laboral, no \"carrera\" universitaria.", nEn: "False friend: \"career\" is your work path, not a university course." },
    "loc-b2ed02": { e: "He's doing research on renewable energy at university.", t: "Está haciendo investigación sobre energía renovable en la universidad.", s: "Cuando hablas de estudiar un tema a fondo.", sEn: "When talking about studying a topic in depth.", n: "Es incontable: di \"a lot of research\", nunca \"researches\".", nEn: "It's uncountable: say \"a lot of research\", never \"researches\"." },
    "loc-b2ed03": { e: "The course gave me a good knowledge of accounting.", t: "El curso me dio un buen conocimiento de contabilidad.", s: "Cuando hablas de lo que sabes sobre un tema.", sEn: "When talking about what you know about a topic.", n: "Es incontable; la \"k\" inicial es muda: \"NÓ-lij\".", nEn: "It's uncountable; the initial \"k\" is silent: \"NOL-ej\"." },
    "loc-b2ed04": { e: "I have to hand in this assignment by Monday.", t: "Tengo que entregar este trabajo el lunes.", s: "Cuando un profesor te pone una tarea para entregar.", sEn: "When a teacher sets you a piece of work to hand in.", n: "\"To hand in an assignment\" es entregarlo.", nEn: "\"To hand in an assignment\" is to submit it." },
    "loc-b2ed05": { e: "The professor gave a lecture on modern history.", t: "El profesor dio una clase magistral sobre historia moderna.", s: "Cuando un experto da una charla larga a muchos estudiantes.", sEn: "When an expert gives a long talk to many students.", n: "Falso amigo: \"lecture\" es una clase, no \"lectura\".", nEn: "False friend: \"lecture\" is a class, not a reading." },
    "loc-b2ed06": { e: "He won a scholarship to study abroad.", t: "Ganó una beca para estudiar en el extranjero.", s: "Cuando te dan dinero para estudiar por tus méritos.", sEn: "When you're given money to study based on merit.", n: "\"To win/get a scholarship\" es conseguir una beca.", nEn: "\"To win/get a scholarship\" means to be awarded one." },
    "loc-b2ed07": { e: "University tuition has gone up a lot in recent years.", t: "La matrícula universitaria ha subido mucho en los últimos años.", s: "Cuando hablas del costo de estudiar.", sEn: "When talking about the cost of studying.", n: "\"Tuition fees\" es lo que pagas por estudiar.", nEn: "\"Tuition fees\" is what you pay to study." },
    "loc-b2ed08": { e: "The submission deadline for the essay is next Friday.", t: "La fecha de entrega del ensayo es el próximo viernes.", s: "Cuando hablas del último día para entregar un trabajo.", sEn: "When talking about the last day to hand in work.", n: "\"To extend a deadline\" es ampliar el plazo.", nEn: "\"To extend a deadline\" means to give more time." },
    "loc-b2ed09": { e: "I'm taking five courses this semester.", t: "Estoy tomando cinco cursos este semestre.", s: "Cuando hablas de medio año académico.", sEn: "When talking about half an academic year.", n: "En el Reino Unido suelen usar \"term\" en lugar de \"semester\".", nEn: "In the UK they often say \"term\" instead of \"semester\"." },
    "loc-b2ed10": { e: "She'll graduate from university next summer.", t: "Ella se graduará de la universidad el próximo verano.", s: "Cuando terminas tus estudios y recibes el título.", sEn: "When you finish your studies and get the degree.", n: "\"To graduate from\" lleva \"from\", no \"of\".", nEn: "\"To graduate from\" takes \"from\", not \"of\"." },
    "loc-b2ed11": { e: "As an undergraduate, I shared a flat with three friends.", t: "Como estudiante de pregrado, compartía un piso con tres amigos.", s: "Cuando hablas de quien estudia su primer título.", sEn: "When talking about someone doing a first degree.", n: "\"Postgraduate\" es de posgrado, después del primer título.", nEn: "\"Postgraduate\" is after the first degree." },
    "loc-b2ed12": { e: "He spent a year writing his master's thesis.", t: "Pasó un año escribiendo su tesis de maestría.", s: "Cuando hablas del trabajo final de una carrera o posgrado.", sEn: "When talking about the final paper of a degree.", n: "El plural es \"theses\" (ZÍ-sis → ZÍ-siis).", nEn: "The plural is \"theses\"." },
    "loc-b2ed13": { e: "The syllabus lists all the topics we'll cover this term.", t: "El temario lista todos los temas que veremos este periodo.", s: "Cuando hablas del plan de contenidos de un curso.", sEn: "When talking about the content plan of a course.", n: "El plural es \"syllabuses\" o \"syllabi\".", nEn: "The plural is \"syllabuses\" or \"syllabi\"." },
    "loc-b2ed14": { e: "This job requires a teaching qualification.", t: "Este trabajo requiere una titulación docente.", s: "Cuando hablas de un título o certificado que te habilita.", sEn: "When talking about a credential that qualifies you.", n: "En plural, \"qualifications\" son tus títulos en el CV.", nEn: "In plural, \"qualifications\" are your credentials on a CV." },
    "loc-b2ed15": { e: "Attendance is compulsory for all the seminars.", t: "La asistencia es obligatoria para todos los seminarios.", s: "Cuando hablas de presentarte a clase.", sEn: "When talking about showing up to class.", n: "El verbo es \"to attend\" (asistir), sin \"to\" después.", nEn: "The verb is \"to attend\" something, with no \"to\" after." },
    "loc-b2ed16": { e: "The school updated its curriculum to include coding.", t: "La escuela actualizó su currículo para incluir programación.", s: "Cuando hablas del conjunto de materias de un programa.", sEn: "When talking about the whole set of subjects in a program.", n: "Ojo: \"curriculum\" es el plan; el CV en inglés se llama \"CV\" o \"résumé\".", nEn: "Note: \"curriculum\" is the study plan; the document is a \"CV\" or \"résumé\"." },
    "loc-b2ed17": { e: "I have to study hard for my final exam next week.", t: "Tengo que estudiar mucho para mi examen final la próxima semana.", s: "Cuando hablas de la prueba al término de un curso.", sEn: "When talking about the test at the end of a course.", n: "\"To sit/take an exam\" es presentarlo; \"to pass\", aprobarlo.", nEn: "\"To sit/take an exam\" is to do it; \"to pass\" is to succeed." },
    "loc-b2ed18": { e: "I need to review my notes before the test tomorrow.", t: "Necesito repasar mis apuntes antes de la prueba de mañana.", s: "Cuando estudias de nuevo lo ya visto antes de un examen.", sEn: "When you study material again before a test.", n: "Falso amigo: en el Reino Unido \"to revise\" es repasar, no solo \"revisar\".", nEn: "False friend: in the UK \"to revise\" means to study, not just to check." },
    "loc-b2ph01": { e: "Don't give up now; you're almost finished with the course.", t: "No te rindas ahora; ya casi terminas el curso.", s: "Cuando alguien quiere abandonar algo difícil y lo animas a seguir.", sEn: "When someone wants to quit something hard and you encourage them.", n: "Separable: \"give it up\". Para dejar un hábito usa \"give up smoking\" (+ -ing).", nEn: "Separable: \"give it up\". For quitting a habit use \"give up smoking\" (+ -ing)." },
    "loc-b2ph02": { e: "I'm really looking forward to the trip next weekend.", t: "Tengo muchas ganas del viaje el próximo fin de semana.", s: "Cuando esperas con ilusión algo que va a pasar.", sEn: "When you eagerly await something that's coming.", n: "Inseparable; siempre + sustantivo o -ing: \"looking forward to seeing you\".", nEn: "Inseparable; always + noun or -ing: \"looking forward to seeing you\"." },
    "loc-b2ph03": { e: "We ran out of milk, so I'll buy some on the way home.", t: "Se nos acabó la leche, así que compraré en el camino a casa.", s: "Cuando algo se agota y ya no queda.", sEn: "When something is used up and there's none left.", n: "Inseparable; siempre + \"of\" + sustantivo: \"run out of time\".", nEn: "Inseparable; always + \"of\" + noun: \"run out of time\"." },
    "loc-b2ph04": { e: "I just found out that the meeting was moved to Friday.", t: "Acabo de enterarme de que la reunión se pasó al viernes.", s: "Cuando descubres o te enteras de una información.", sEn: "When you discover or learn a piece of information.", n: "Separable: \"find it out\". A menudo seguido de \"that\" o una pregunta indirecta.", nEn: "Separable: \"find it out\". Often followed by \"that\" or an indirect question." },
    "loc-b2ph05": { e: "They had to put off the wedding because of the storm.", t: "Tuvieron que posponer la boda por la tormenta.", s: "Cuando aplazas algo para más tarde.", sEn: "When you postpone something to a later time.", n: "Separable: \"put it off\". Con verbo usa + -ing: \"put off calling\".", nEn: "Separable: \"put it off\". With a verb use + -ing: \"put off calling\"." },
    "loc-b2ph06": { e: "Please carry on with your work; I didn't mean to interrupt.", t: "Por favor continúa con tu trabajo; no quise interrumpir.", s: "Cuando le pides a alguien que siga haciendo algo.", sEn: "When you tell someone to keep doing something.", n: "Inseparable; suele ir + \"with\" + sustantivo o + -ing: \"carry on working\".", nEn: "Inseparable; often + \"with\" + noun or + -ing: \"carry on working\"." },
    "loc-b2ph07": { e: "Our team can deal with any complaints from the guests.", t: "Nuestro equipo puede lidiar con cualquier queja de los huéspedes.", s: "Cuando manejas un problema o una situación difícil.", sEn: "When you handle a problem or difficult situation.", n: "Inseparable; siempre + \"with\" + sustantivo.", nEn: "Inseparable; always + \"with\" + noun." },
    "loc-b2ph08": { e: "She came up with a great idea to save the company money.", t: "Se le ocurrió una gran idea para ahorrarle dinero a la empresa.", s: "Cuando inventas o propones una idea o solución.", sEn: "When you invent or propose an idea or solution.", n: "Inseparable de tres partes; siempre + \"with\" + sustantivo.", nEn: "Inseparable three-part verb; always + \"with\" + noun." },
    "loc-b2ph09": { e: "I get along really well with my new coworkers.", t: "Me llevo muy bien con mis nuevos compañeros.", s: "Cuando tienes una buena relación con alguien.", sEn: "When you have a good relationship with someone.", n: "Inseparable; usa \"with\" antes de la persona: \"get along with him\".", nEn: "Inseparable; use \"with\" before the person: \"get along with him\"." },
    "loc-b2ph10": { e: "Could you look after the front desk while I take a break?", t: "¿Podrías cuidar la recepción mientras tomo un descanso?", s: "Cuando te encargas o cuidas de alguien o algo.", sEn: "When you take care of someone or something.", n: "Inseparable; siempre + sustantivo: \"look after the kids\".", nEn: "Inseparable; always + noun: \"look after the kids\"." },
    "loc-b2ph11": { e: "The guide pointed out the oldest building in the square.", t: "El guía señaló el edificio más antiguo de la plaza.", s: "Cuando llamas la atención sobre algo o lo mencionas.", sEn: "When you draw attention to something or mention it.", n: "Separable: \"point it out\". A menudo + \"that\": \"point out that...\".", nEn: "Separable: \"point it out\". Often + \"that\": \"point out that...\"." },
    "loc-b2ph12": { e: "He turned down the job offer because the pay was too low.", t: "Rechazó la oferta de trabajo porque el sueldo era muy bajo.", s: "Cuando rechazas una oferta o invitación.", sEn: "When you reject an offer or invitation.", n: "Separable: \"turn it down\". También significa bajar el volumen.", nEn: "Separable: \"turn it down\". Also means to lower the volume." },
    "loc-b2ph13": { e: "Don't bring up the price until they've seen the room.", t: "No menciones el precio hasta que hayan visto la habitación.", s: "Cuando introduces un tema en una conversación.", sEn: "When you introduce a topic in a conversation.", n: "Separable: \"bring it up\". También significa criar a un niño.", nEn: "Separable: \"bring it up\". Also means to raise a child." },
    "loc-b2ph14": { e: "Let me work out how much each person owes for dinner.", t: "Déjame calcular cuánto debe cada persona por la cena.", s: "Cuando resuelves un problema o calculas algo.", sEn: "When you solve a problem or calculate something.", n: "Separable: \"work it out\". También significa entrenar en el gimnasio.", nEn: "Separable: \"work it out\". Also means to exercise at the gym." },
    "loc-b2ph15": { e: "They set up a new café right next to the station.", t: "Montaron una cafetería nueva justo al lado de la estación.", s: "Cuando estableces o creas algo nuevo.", sEn: "When you establish or create something new.", n: "Separable: \"set it up\". Sustantivo: \"setup\" (junto).", nEn: "Separable: \"set it up\". Noun form: \"setup\" (one word)." },
    "loc-b2ph16": { e: "A larger company took over the hotel last year.", t: "Una empresa más grande se hizo cargo del hotel el año pasado.", s: "Cuando alguien asume el control de algo.", sEn: "When someone takes control of something.", n: "Separable: \"take it over\". Sustantivo: \"takeover\" (junto).", nEn: "Separable: \"take it over\". Noun form: \"takeover\" (one word)." },
    "loc-b2ph17": { e: "It took me a while to figure out how the machine works.", t: "Me tomó un rato entender cómo funciona la máquina.", s: "Cuando logras entender algo después de pensarlo.", sEn: "When you manage to understand something after thinking.", n: "Separable: \"figure it out\". A menudo + pregunta indirecta.", nEn: "Separable: \"figure it out\". Often + indirect question." },
    "loc-b2ph18": { e: "We need to get rid of these old chairs before the renovation.", t: "Tenemos que deshacernos de estas sillas viejas antes de la renovación.", s: "Cuando eliminas o te desprendes de algo.", sEn: "When you remove or dispose of something.", n: "Inseparable; siempre + \"of\" + sustantivo. No es separable.", nEn: "Inseparable; always + \"of\" + noun. Not separable." },
    "loc-b2ph19": { e: "I'll look into the problem and get back to you tomorrow.", t: "Investigaré el problema y te respondo mañana.", s: "Cuando examinas o investigas un asunto.", sEn: "When you examine or investigate a matter.", n: "Inseparable; siempre + \"into\" + sustantivo.", nEn: "Inseparable; always + \"into\" + noun." },
    "loc-b2ph20": { e: "Don't worry, we'll sort out the booking mistake right away.", t: "No te preocupes, resolveremos el error de la reserva enseguida.", s: "Cuando arreglas un problema o pones algo en orden.", sEn: "When you fix a problem or put something in order.", n: "Separable: \"sort it out\". Muy común en inglés británico.", nEn: "Separable: \"sort it out\". Very common in British English." },
    "loc-b2ve01": { e: "With hard work, you can achieve almost any goal you set.", t: "Con esfuerzo, puedes lograr casi cualquier meta que te propongas.", s: "Cuando alcanzas un objetivo tras esfuerzo.", sEn: "When you reach a goal after effort.", n: "Transitivo: \"achieve a goal\". El sustantivo es \"achievement\".", nEn: "Transitive: \"achieve a goal\". The noun is \"achievement\"." },
    "loc-b2ve02": { e: "We can't afford a new car right now, so we'll wait.", t: "No podemos permitirnos un carro nuevo ahora, así que esperaremos.", s: "Cuando hablas de tener dinero suficiente para algo.", sEn: "When you talk about having enough money for something.", n: "Casi siempre con \"can/could\": \"can afford to + verbo\".", nEn: "Almost always with \"can/could\": \"can afford to + verb\"." },
    "loc-b2ve03": { e: "I suggest booking the tour early to get a better price.", t: "Sugiero reservar el tour temprano para conseguir un mejor precio.", s: "Cuando propones una idea o recomendación.", sEn: "When you propose an idea or recommendation.", n: "Estructura: \"suggest + -ing\" o \"suggest that...\"; nunca \"suggest to do\".", nEn: "Structure: \"suggest + -ing\" or \"suggest that...\"; never \"suggest to do\"." },
    "loc-b2ve04": { e: "Try to avoid driving downtown during rush hour.", t: "Trata de evitar manejar por el centro en hora pico.", s: "Cuando previenes o esquivas algo no deseado.", sEn: "When you prevent or stay away from something unwanted.", n: "Estructura: \"avoid + -ing\"; nunca \"avoid to do\".", nEn: "Structure: \"avoid + -ing\"; never \"avoid to do\"." },
    "loc-b2ve05": { e: "After all that work, you really deserve a holiday.", t: "Después de tanto trabajo, de verdad mereces unas vacaciones.", s: "Cuando algo es justo o ganado por alguien.", sEn: "When something is fair or earned by someone.", n: "Transitivo: \"deserve a break\" o \"deserve to + verbo\".", nEn: "Transitive: \"deserve a break\" or \"deserve to + verb\"." },
    "loc-b2ve06": { e: "Somehow she managed to finish the report before noon.", t: "De algún modo logró terminar el informe antes del mediodía.", s: "Cuando consigues hacer algo difícil.", sEn: "When you succeed in doing something difficult.", n: "Para logros: \"manage to + verbo\". También significa dirigir un equipo.", nEn: "For achievements: \"manage to + verb\". Also means to run a team." },
    "loc-b2ve07": { e: "His English has improved a lot since he moved abroad.", t: "Su inglés ha mejorado mucho desde que se mudó al extranjero.", s: "Cuando algo se vuelve mejor con el tiempo.", sEn: "When something gets better over time.", n: "Puede ser transitivo o intransitivo: \"improve\" o \"improve it\".", nEn: "Can be transitive or intransitive: \"improve\" or \"improve it\"." },
    "loc-b2ve08": { e: "The hotel wants to reduce its energy costs this year.", t: "El hotel quiere reducir sus costos de energía este año.", s: "Cuando algo se hace más pequeño en cantidad.", sEn: "When something is made smaller in amount.", n: "Transitivo: \"reduce costs\". Estructura: \"reduce X by 20%\".", nEn: "Transitive: \"reduce costs\". Structure: \"reduce X by 20%\"." },
    "loc-b2ve09": { e: "They plan to increase the staff during the summer season.", t: "Planean aumentar el personal durante la temporada de verano.", s: "Cuando algo se hace más grande en cantidad.", sEn: "When something is made larger in amount.", n: "Verbo: \"in-CRIS\"; sustantivo: \"IN-cris\". El acento cambia.", nEn: "Verb: \"in-CREASE\"; noun: \"IN-crease\". The stress shifts." },
    "loc-b2ve10": { e: "This position requires at least two years of experience.", t: "Este puesto requiere al menos dos años de experiencia.", s: "Cuando algo es obligatorio o necesario.", sEn: "When something is mandatory or needed.", n: "Transitivo: \"require X\" o \"require that...\". Más formal que \"need\".", nEn: "Transitive: \"require X\" or \"require that...\". More formal than \"need\"." },
    "loc-b2ve11": { e: "The hotel provides towels and toiletries in every room.", t: "El hotel proporciona toallas y artículos de aseo en cada habitación.", s: "Cuando das o suministras algo a alguien.", sEn: "When you give or supply something to someone.", n: "Estructura: \"provide X\" o \"provide somebody with X\".", nEn: "Structure: \"provide X\" or \"provide somebody with X\"." },
    "loc-b2ve12": { e: "Good signs help prevent guests from getting lost.", t: "Buenos letreros ayudan a impedir que los huéspedes se pierdan.", s: "Cuando evitas que algo malo ocurra.", sEn: "When you stop something bad from happening.", n: "Estructura: \"prevent somebody from + -ing\".", nEn: "Structure: \"prevent somebody from + -ing\"." },
    "loc-b2ve13": { e: "We don't allow pets in the dining area, sorry.", t: "No permitimos mascotas en el área del comedor, lo siento.", s: "Cuando das permiso para algo.", sEn: "When you give permission for something.", n: "Estructura: \"allow somebody to + verbo\". Voz pasiva: \"are not allowed\".", nEn: "Structure: \"allow somebody to + verb\". Passive: \"are not allowed\"." },
    "loc-b2ve14": { e: "We encourage guests to try the local food nearby.", t: "Animamos a los huéspedes a probar la comida local de la zona.", s: "Cuando motivas a alguien a hacer algo.", sEn: "When you motivate someone to do something.", n: "Estructura: \"encourage somebody to + verbo\".", nEn: "Structure: \"encourage somebody to + verb\"." },
    "loc-b2ve15": { e: "A guest complained about the noise from the street.", t: "Un huésped se quejó del ruido de la calle.", s: "Cuando expresas insatisfacción por algo.", sEn: "When you express dissatisfaction about something.", n: "Estructura: \"complain about X\" o \"complain to somebody\".", nEn: "Structure: \"complain about X\" or \"complain to somebody\"." },
    "loc-b2ve16": { e: "He admitted making a mistake with the reservation.", t: "Admitió haber cometido un error con la reserva.", s: "Cuando reconoces que algo es cierto, a menudo a regañadientes.", sEn: "When you accept something is true, often reluctantly.", n: "Estructura: \"admit + -ing\" o \"admit that...\".", nEn: "Structure: \"admit + -ing\" or \"admit that...\"." },
    "loc-b2ve17": { e: "She denied taking the money from the cash register.", t: "Negó haber tomado el dinero de la caja.", s: "Cuando dices que algo no es cierto.", sEn: "When you say something is not true.", n: "Estructura: \"deny + -ing\" o \"deny that...\"; nunca \"deny to do\".", nEn: "Structure: \"deny + -ing\" or \"deny that...\"; never \"deny to do\"." },
    "loc-b2ve18": { e: "The customer refused to pay the extra service charge.", t: "El cliente se negó a pagar el cargo extra por el servicio.", s: "Cuando alguien no acepta hacer algo.", sEn: "When someone won't accept doing something.", n: "Estructura: \"refuse to + verbo\". Más fuerte que \"don't want to\".", nEn: "Structure: \"refuse to + verb\". Stronger than \"don't want to\"." },
    "loc-b2ve19": { e: "They finally succeeded in opening their own restaurant.", t: "Finalmente lograron abrir su propio restaurante.", s: "Cuando consigues lo que te propones.", sEn: "When you achieve what you set out to do.", n: "Estructura: \"succeed in + -ing\". El sustantivo es \"success\".", nEn: "Structure: \"succeed in + -ing\". The noun is \"success\"." },
    "loc-b2ve20": { e: "Many tourists struggle to understand the local accent.", t: "Muchos turistas batallan para entender el acento local.", s: "Cuando algo te cuesta mucho trabajo.", sEn: "When you find something very hard to do.", n: "Estructura: \"struggle to + verbo\" o \"struggle with X\".", nEn: "Structure: \"struggle to + verb\" or \"struggle with X\"." },
    "loc-b2aj01": { e: "She's a reliable worker who always arrives on time.", t: "Es una trabajadora confiable que siempre llega a tiempo.", s: "Cuando alguien o algo es de fiar.", sEn: "When someone or something can be trusted.", n: "Lo contrario es \"unreliable\". El verbo relacionado es \"rely on\".", nEn: "The opposite is \"unreliable\". The related verb is \"rely on\"." },
    "loc-b2aj02": { e: "Please make sure the bill is accurate before the guest pays.", t: "Por favor asegúrate de que la cuenta sea exacta antes de que el huésped pague.", s: "Cuando algo es correcto y sin errores.", sEn: "When something is correct and free of errors.", n: "Lo contrario es \"inaccurate\". El sustantivo es \"accuracy\".", nEn: "The opposite is \"inaccurate\". The noun is \"accuracy\"." },
    "loc-b2aj03": { e: "The new system is much more efficient than the old one.", t: "El sistema nuevo es mucho más eficiente que el anterior.", s: "Cuando algo funciona bien sin desperdiciar tiempo ni recursos.", sEn: "When something works well without wasting time or resources.", n: "No confundir con \"effective\" (que da resultado). Sustantivo: \"efficiency\".", nEn: "Don't confuse with \"effective\" (gets results). Noun: \"efficiency\"." },
    "loc-b2aj04": { e: "There was a significant rise in bookings this summer.", t: "Hubo un aumento significativo de reservas este verano.", s: "Cuando algo es notable o importante.", sEn: "When something is notable or important.", n: "El adverbio es \"significantly\": \"significantly higher\".", nEn: "The adverb is \"significantly\": \"significantly higher\"." },
    "loc-b2aj05": { e: "The prices here are reasonable for such a good location.", t: "Los precios aquí son razonables para tan buena ubicación.", s: "Cuando algo es justo, sensato o no muy caro.", sEn: "When something is fair, sensible, or not too expensive.", n: "Lo contrario es \"unreasonable\". También significa sensato.", nEn: "The opposite is \"unreasonable\". Also means sensible." },
    "loc-b2aj06": { e: "This hotel is suitable for families with small children.", t: "Este hotel es adecuado para familias con niños pequeños.", s: "Cuando algo es apropiado para un fin o persona.", sEn: "When something is appropriate for a purpose or person.", n: "Estructura: \"suitable for X\". Lo contrario es \"unsuitable\".", nEn: "Structure: \"suitable for X\". The opposite is \"unsuitable\"." },
    "loc-b2aj07": { e: "Are you aware that the pool closes early today?", t: "¿Estás al tanto de que la piscina cierra temprano hoy?", s: "Cuando sabes o te das cuenta de algo.", sEn: "When you know or notice something.", n: "Estructura: \"aware of X\" o \"aware that...\". Sustantivo: \"awareness\".", nEn: "Structure: \"aware of X\" or \"aware that...\". Noun: \"awareness\"." },
    "loc-b2aj08": { e: "I'm willing to stay late if the team needs help.", t: "Estoy dispuesto a quedarme tarde si el equipo necesita ayuda.", s: "Cuando estás listo o de buena gana para hacer algo.", sEn: "When you're ready and happy to do something.", n: "Estructura: \"willing to + verbo\". Lo contrario es \"unwilling\".", nEn: "Structure: \"willing to + verb\". The opposite is \"unwilling\"." },
    "loc-b2aj09": { e: "It's likely to rain this afternoon, so bring an umbrella.", t: "Es probable que llueva esta tarde, así que lleva un paraguas.", s: "Cuando algo tiene buena probabilidad de pasar.", sEn: "When something has a good chance of happening.", n: "Estructura: \"likely to + verbo\" o \"It's likely that...\".", nEn: "Structure: \"likely to + verb\" or \"It's likely that...\"." },
    "loc-b2aj10": { e: "The museum is definitely worth visiting while you're here.", t: "El museo definitivamente vale la pena visitarlo mientras estás aquí.", s: "Cuando algo merece el esfuerzo, tiempo o dinero.", sEn: "When something deserves the effort, time, or money.", n: "Estructura: \"worth + -ing\" o \"worth + sustantivo\"; nunca \"worth to do\".", nEn: "Structure: \"worth + -ing\" or \"worth + noun\"; never \"worth to do\"." },
    "loc-b2aj11": { e: "Too much sun can be harmful, so use sunscreen.", t: "Demasiado sol puede ser dañino, así que usa protector solar.", s: "Cuando algo puede causar daño.", sEn: "When something can cause damage or injury.", n: "Estructura: \"harmful to X\". Lo contrario es \"harmless\".", nEn: "Structure: \"harmful to X\". The opposite is \"harmless\"." },
    "loc-b2aj12": { e: "Please keep your valuable items in the room safe.", t: "Por favor guarda tus objetos valiosos en la caja fuerte de la habitación.", s: "Cuando algo vale mucho o es muy útil.", sEn: "When something is worth a lot or very useful.", n: "No confundir con \"invaluable\" (= inestimable, aún más valioso).", nEn: "Don't confuse with \"invaluable\" (= priceless, even more valuable)." },
    "loc-b2aj13": { e: "There are no rooms available for tonight, I'm afraid.", t: "No hay habitaciones disponibles para esta noche, me temo.", s: "Cuando algo se puede obtener o usar.", sEn: "When something can be obtained or used.", n: "Lo contrario es \"unavailable\". También para personas: \"I'm available\".", nEn: "The opposite is \"unavailable\". Also for people: \"I'm available\"." },
    "loc-b2aj14": { e: "The booking system is more complex than it looks.", t: "El sistema de reservas es más complejo de lo que parece.", s: "Cuando algo tiene muchas partes y no es simple.", sEn: "When something has many parts and isn't simple.", n: "Como adjetivo \"COM-pleks\"; como sustantivo también. Lo opuesto: \"simple\".", nEn: "As an adjective \"COM-plex\"; as a noun too. The opposite: \"simple\"." },
    "loc-b2aj15": { e: "It was obvious that the guest was unhappy with the room.", t: "Era obvio que el huésped no estaba contento con la habitación.", s: "Cuando algo es claro y fácil de ver.", sEn: "When something is clear and easy to see.", n: "El adverbio \"obviously\" se usa mucho al inicio de frase.", nEn: "The adverb \"obviously\" is often used at the start of a sentence." },
    "loc-b2aj16": { e: "Good communication is crucial in this kind of job.", t: "La buena comunicación es crucial en este tipo de trabajo.", s: "Cuando algo es extremadamente importante.", sEn: "When something is extremely important.", n: "Estructura: \"crucial to X\" o \"crucial for X\". Más fuerte que \"important\".", nEn: "Structure: \"crucial to X\" or \"crucial for X\". Stronger than \"important\"." },
    "loc-b2aj17": { e: "Our check-in times are flexible if you let us know early.", t: "Nuestros horarios de registro son flexibles si nos avisas con tiempo.", s: "Cuando algo o alguien se adapta con facilidad.", sEn: "When something or someone adapts easily.", n: "Lo contrario es \"inflexible\". El sustantivo es \"flexibility\".", nEn: "The opposite is \"inflexible\". The noun is \"flexibility\"." },
    "loc-b2aj18": { e: "Working at reception can be demanding during peak season.", t: "Trabajar en recepción puede ser exigente en temporada alta.", s: "Cuando algo requiere mucho esfuerzo, tiempo o atención.", sEn: "When something needs a lot of effort, time, or attention.", n: "Viene del verbo \"demand\". También para personas exigentes.", nEn: "Comes from the verb \"demand\". Also for demanding people." },
    "loc-b2aj19": { e: "Teaching tourists about our city is a rewarding job.", t: "Enseñar a los turistas sobre nuestra ciudad es un trabajo gratificante.", s: "Cuando algo da satisfacción aunque cueste esfuerzo.", sEn: "When something gives satisfaction despite the effort.", n: "Viene de \"reward\" (recompensa). A menudo contrasta con \"demanding\".", nEn: "Comes from \"reward\". Often contrasts with \"demanding\"." },
    "loc-b2aj20": { e: "What is the current price for a double room?", t: "¿Cuál es el precio actual de una habitación doble?", s: "Cuando hablas de lo que existe o aplica ahora.", sEn: "When you talk about what exists or applies now.", n: "\"Current\" = actual; ojo, \"actual\" en inglés significa \"real, verdadero\".", nEn: "\"Current\" = present-day; note \"actual\" in English means \"real, true\"." },
    "loc-b2so01": { e: "The government promised to reduce poverty in the poorest regions of the country.", t: "El gobierno prometió reducir la pobreza en las regiones más pobres del país.", s: "Al hablar de problemas sociales o leer noticias sobre desigualdad.", sEn: "When discussing social problems or reading news about inequality.", n: "\"Poverty\" lleva el acento en la primera sílaba; el adjetivo es \"poor\".", nEn: "\"Poverty\" is stressed on the first syllable; the adjective is \"poor\"." },
    "loc-b2so02": { e: "The new law aims to guarantee equality between men and women at work.", t: "La nueva ley busca garantizar la igualdad entre hombres y mujeres en el trabajo.", s: "Cuando se debaten derechos o políticas contra la discriminación.", sEn: "When debating rights or anti-discrimination policies.", n: "El opuesto es \"inequality\" (desigualdad); ambos llevan el acento en \"KUO\".", nEn: "The opposite is \"inequality\"; both stress the \"qual\" syllable." },
    "loc-b2so03": { e: "The government announced new measures to support small businesses.", t: "El gobierno anunció nuevas medidas para apoyar a las pequeñas empresas.", s: "Al leer noticias políticas o comentar decisiones oficiales.", sEn: "When reading political news or commenting on official decisions.", n: "La primera \"n\" de \"government\" suele tragarse; suena \"GÁ-ver-ment\".", nEn: "The first \"n\" in \"government\" is often dropped; say \"GUV-er-ment\"." },
    "loc-b2so04": { e: "Every citizen has the right to vote in the national election.", t: "Todo ciudadano tiene derecho a votar en la elección nacional.", s: "Al hablar de derechos, deberes o nacionalidad.", sEn: "When talking about rights, duties or nationality.", n: "La 'z' suena suave (como zumbido); no la digas como la 's' española.", nEn: "The 'z' is a soft buzzing sound, not the Spanish 's'." },
    "loc-b2so05": { e: "Technology has changed the way our society communicates.", t: "La tecnología ha cambiado la forma en que se comunica nuestra sociedad.", s: "En discusiones sobre cultura, valores o cambios sociales.", sEn: "In discussions about culture, values or social change.", n: "Se pronuncia \"so-SAI-e-ti\", con la segunda sílaba como \"sigh\".", nEn: "Say \"so-SY-e-ty\", with the stressed syllable like \"sigh\"." },
    "loc-b2so06": { e: "Workers fought for years to protect their basic rights.", t: "Los trabajadores lucharon durante años para proteger sus derechos básicos.", s: "Al hablar de leyes, libertades o justicia social.", sEn: "When talking about laws, freedoms or social justice.", n: "\"Human rights\" (derechos humanos) es una colocación muy frecuente.", nEn: "\"Human rights\" is a very common collocation." },
    "loc-b2so07": { e: "The new law makes it illegal to use a phone while driving.", t: "La nueva ley prohíbe usar el teléfono mientras se maneja.", s: "Al comentar normas, prohibiciones o reformas legales.", sEn: "When commenting on rules, bans or legal reforms.", n: "Suena \"lo\", con vocal larga; el plural \"laws\" añade una 'z' suave.", nEn: "It sounds like \"law\" with a long vowel; the plural \"laws\" ends in a soft 'z'." },
    "loc-b2so08": { e: "The police are working hard to reduce crime in the city center.", t: "La policía trabaja duro para reducir el delito en el centro de la ciudad.", s: "Al leer noticias policiales o hablar de seguridad.", sEn: "When reading crime news or talking about safety.", n: "\"Crime\" es a menudo incontable; \"a crime\" es un delito concreto.", nEn: "\"Crime\" is often uncountable; \"a crime\" means one specific offense." },
    "loc-b2so09": { e: "The victims' families are still waiting for justice after ten years.", t: "Las familias de las víctimas todavía esperan justicia después de diez años.", s: "Al hablar de tribunales, derechos o equidad.", sEn: "When talking about courts, rights or fairness.", n: "La 'j' inicial suena como en \"jam\", no como la 'j' española.", nEn: "The initial 'j' sounds like in \"jam\", not the Spanish 'j'." },
    "loc-b2so10": { e: "Freedom of speech is protected by the constitution.", t: "La libertad de expresión está protegida por la constitución.", s: "En debates sobre derechos civiles o democracia.", sEn: "In debates about civil rights or democracy.", n: "\"Freedom of speech\" (libertad de expresión) es la colocación clave.", nEn: "\"Freedom of speech\" is the key collocation." },
    "loc-b2so11": { e: "Millions of people voted in the presidential election last week.", t: "Millones de personas votaron en la elección presidencial la semana pasada.", s: "Al hablar de política o procesos de votación.", sEn: "When talking about politics or voting processes.", n: "\"Election\" es el proceso; \"to elect\" es el verbo elegir.", nEn: "\"Election\" is the process; \"to elect\" is the verb." },
    "loc-b2so12": { e: "Thousands joined the protest against the rise in fuel prices.", t: "Miles se unieron a la protesta contra la subida del precio del combustible.", s: "Al describir manifestaciones o descontento social.", sEn: "When describing demonstrations or social unrest.", n: "El sustantivo \"PRO-test\" lleva el acento delante; el verbo \"pro-TEST\" atrás.", nEn: "The noun \"PRO-test\" stresses the front; the verb \"pro-TEST\" the end." },
    "loc-b2so13": { e: "The whole community came together to rebuild the school.", t: "Toda la comunidad se unió para reconstruir la escuela.", s: "Al hablar de barrios, grupos o proyectos locales.", sEn: "When talking about neighborhoods, groups or local projects.", n: "Se pronuncia \"co-MIU-ni-ti\", con el acento en la segunda sílaba.", nEn: "Say \"co-MEW-ni-ty\", stressed on the second syllable." },
    "loc-b2so14": { e: "Immigration has shaped the culture of many large cities.", t: "La inmigración ha moldeado la cultura de muchas ciudades grandes.", s: "En debates sobre fronteras, trabajo o diversidad.", sEn: "In debates about borders, work or diversity.", n: "\"Immigration\" (llegar) vs \"emigration\" (salir); cuida la primera vocal.", nEn: "\"Immigration\" (coming in) vs \"emigration\" (going out); mind the first vowel." },
    "loc-b2so15": { e: "Unemployment has fallen for the third month in a row.", t: "El desempleo ha bajado por tercer mes consecutivo.", s: "Al leer noticias económicas o de empleo.", sEn: "When reading economic or job-market news.", n: "El opuesto es \"employment\"; el prefijo \"un-\" indica falta de.", nEn: "The opposite is \"employment\"; the prefix \"un-\" means lack of." },
    "loc-b2so16": { e: "The state provides welfare to families who lose their income.", t: "El estado ofrece ayudas sociales a las familias que pierden sus ingresos.", s: "Al hablar de ayudas estatales o protección social.", sEn: "When talking about state aid or social protection.", n: "En EE. UU. \"welfare\" suele referirse a las ayudas económicas.", nEn: "In the US \"welfare\" often refers to financial benefits." },
    "loc-b2so17": { e: "The company changed its policy on working from home.", t: "La empresa cambió su política sobre el trabajo desde casa.", s: "Al hablar de normas, planes o estrategias oficiales.", sEn: "When talking about rules, plans or official strategies.", n: "\"Policy\" es una medida o norma; \"politics\" es la actividad política.", nEn: "\"Policy\" is a measure or rule; \"politics\" is the political activity." },
    "loc-b2so18": { e: "The population of the city has doubled in twenty years.", t: "La población de la ciudad se ha duplicado en veinte años.", s: "Al hablar de estadísticas, ciudades o demografía.", sEn: "When talking about statistics, cities or demographics.", n: "\"Population\" es la gente; \"people\" es el plural genérico de persona.", nEn: "\"Population\" is the total number of people; \"people\" is the general plural." },
    "loc-b2ma01": { e: "Air pollution in the city has reached dangerous levels this summer.", t: "La contaminación del aire en la ciudad alcanzó niveles peligrosos este verano.", s: "Al hablar de la calidad del aire, agua o medio ambiente.", sEn: "When talking about air, water or environmental quality.", n: "\"Air/water pollution\" son las colocaciones más comunes.", nEn: "\"Air/water pollution\" are the most common collocations." },
    "loc-b2ma02": { e: "Scientists warn that climate change is happening faster than expected.", t: "Los científicos advierten que el cambio climático ocurre más rápido de lo esperado.", s: "En noticias o debates sobre el calentamiento global.", sEn: "In news or debates about global warming.", n: "\"Climate\" suena \"KLAI-met\", con la primera sílaba como \"sky\".", nEn: "\"Climate\" sounds \"KLY-met\", with the first syllable like \"sky\"." },
    "loc-b2ma03": { e: "Recycling helps reduce the amount of waste sent to landfills.", t: "El reciclaje ayuda a reducir la cantidad de basura que va a los vertederos.", s: "Al hablar de residuos o hábitos sostenibles en casa.", sEn: "When talking about waste or sustainable habits at home.", n: "El verbo es \"to recycle\"; la 'c' suena como 's' suave.", nEn: "The verb is \"to recycle\"; the 'c' sounds like a soft 's'." },
    "loc-b2ma04": { e: "The company is switching to more sustainable packaging.", t: "La empresa está cambiando a un empaque más sostenible.", s: "Al describir productos, energía o desarrollo responsables.", sEn: "When describing responsible products, energy or development.", n: "El sustantivo es \"sustainability\"; el acento va en \"TEI\".", nEn: "The noun is \"sustainability\"; the stress falls on \"tain\"." },
    "loc-b2ma05": { e: "We all have a responsibility to protect the environment.", t: "Todos tenemos la responsabilidad de proteger el medio ambiente.", s: "En cualquier conversación sobre naturaleza o ecología.", sEn: "In any conversation about nature or ecology.", n: "La 'n' de \"enviroNment\" suele tragarse; di \"in-VAI-ron-ment\".", nEn: "The 'n' in \"environment\" is often dropped; say \"en-VY-ron-ment\"." },
    "loc-b2ma06": { e: "The factory was fined for dumping waste into the river.", t: "La fábrica fue multada por verter residuos en el río.", s: "Al hablar de basura, reciclaje o contaminación.", sEn: "When talking about garbage, recycling or pollution.", n: "\"Waste\" es también verbo: \"to waste water\" (malgastar agua).", nEn: "\"Waste\" is also a verb: \"to waste water\" means to use it carelessly." },
    "loc-b2ma07": { e: "Solar panels let homes produce their own clean energy.", t: "Los paneles solares permiten que los hogares produzcan su propia energía limpia.", s: "Al hablar de electricidad, recursos o sostenibilidad.", sEn: "When talking about electricity, resources or sustainability.", n: "La 'g' suena suave como en \"gel\"; el acento va al inicio.", nEn: "The 'g' is soft like in \"gel\"; the stress is on the first syllable." },
    "loc-b2ma08": { e: "More and more countries are investing in renewable energy.", t: "Cada vez más países invierten en energía renovable.", s: "Al hablar de fuentes de energía limpias y sostenibles.", sEn: "When talking about clean, sustainable energy sources.", n: "\"Renewable energy\" suele referirse a solar, eólica o hidráulica.", nEn: "\"Renewable energy\" usually means solar, wind or hydropower." },
    "loc-b2ma09": { e: "Global warming is causing sea levels to rise around the world.", t: "El calentamiento global está provocando que suba el nivel del mar en todo el mundo.", s: "En noticias o conversaciones sobre el clima del planeta.", sEn: "In news or conversations about the planet's climate.", n: "La 'w' de \"warming\" se pronuncia; suena \"UOR-ming\".", nEn: "The 'w' in \"warming\" is pronounced; it sounds \"WOR-ming\"." },
    "loc-b2ma10": { e: "The government wants to cut carbon emissions by half before 2030.", t: "El gobierno quiere reducir a la mitad las emisiones de carbono antes de 2030.", s: "Al hablar de gases contaminantes o políticas climáticas.", sEn: "When talking about polluting gases or climate policy.", n: "Casi siempre se usa en plural: \"emissions\".", nEn: "It is almost always used in the plural: \"emissions\"." },
    "loc-b2ma11": { e: "The new park was created to protect local wildlife.", t: "El nuevo parque se creó para proteger la fauna silvestre local.", s: "Al hablar de animales salvajes y su conservación.", sEn: "When talking about wild animals and their conservation.", n: "\"Wildlife\" es incontable; nunca digas \"wildlifes\".", nEn: "\"Wildlife\" is uncountable; never say \"wildlifes\"." },
    "loc-b2ma12": { e: "The long drought has destroyed most of the region's crops.", t: "La larga sequía ha destruido la mayoría de los cultivos de la región.", s: "Al hablar del clima extremo o la falta de agua.", sEn: "When talking about extreme weather or water shortages.", n: "\"Drought\" se pronuncia \"draut\", rima con \"out\"; la 'gh' es muda.", nEn: "\"Drought\" sounds \"drowt\", rhyming with \"out\"; the 'gh' is silent." },
    "loc-b2ma13": { e: "Heavy rain caused a flood that forced hundreds to leave their homes.", t: "Las fuertes lluvias provocaron una inundación que obligó a cientos a dejar sus casas.", s: "Al hablar de desastres naturales o clima extremo.", sEn: "When talking about natural disasters or extreme weather.", n: "\"Flood\" rima con \"blood\"; la 'oo' suena como una 'a' corta.", nEn: "\"Flood\" rhymes with \"blood\"; the 'oo' sounds like a short 'u'." },
    "loc-b2ma14": { e: "Greenhouse gases trap heat and warm the planet.", t: "Los gases de efecto invernadero atrapan el calor y calientan el planeta.", s: "Al explicar las causas del calentamiento global.", sEn: "When explaining the causes of global warming.", n: "\"Greenhouse gases\" (gases de efecto invernadero) es la colocación clave.", nEn: "\"Greenhouse gases\" is the key collocation." },
    "loc-b2ma15": { e: "Conservation efforts have helped save several endangered species.", t: "Los esfuerzos de conservación han ayudado a salvar varias especies en peligro.", s: "Al hablar de proteger la naturaleza o los recursos.", sEn: "When talking about protecting nature or resources.", n: "El verbo es \"to conserve\"; el acento del sustantivo va en \"VEI\".", nEn: "The verb is \"to conserve\"; the noun is stressed on \"va\"." },
    "loc-b2ma16": { e: "Deforestation in the rainforest threatens thousands of species.", t: "La deforestación en la selva tropical amenaza a miles de especies.", s: "Al hablar de la tala de bosques y sus consecuencias.", sEn: "When talking about cutting down forests and its effects.", n: "Es una palabra larga; el acento principal cae en \"TEI\".", nEn: "It's a long word; the main stress falls on \"ta\"." },
    "loc-b2ma17": { e: "Flying less is one way to reduce your carbon footprint.", t: "Volar menos es una forma de reducir tu huella de carbono.", s: "Al hablar del impacto ambiental de las acciones diarias.", sEn: "When talking about the environmental impact of daily actions.", n: "\"Footprint\" significa literalmente \"huella\"; aquí es la marca ambiental.", nEn: "\"Footprint\" literally means a track; here it's your environmental mark." },
    "loc-b2ma18": { e: "The sea turtle is an endangered species in this part of the coast.", t: "La tortuga marina es una especie en peligro de extinción en esta parte de la costa.", s: "Al hablar de animales o plantas amenazados.", sEn: "When talking about threatened animals or plants.", n: "\"Endangered species\" (especie en peligro) es la colocación habitual.", nEn: "\"Endangered species\" is the usual collocation." },
    "loc-b2te01": { e: "You can use the same account on all your devices.", t: "Puedes usar la misma cuenta en todos tus dispositivos.", s: "Al hablar de teléfonos, tabletas o computadoras.", sEn: "When talking about phones, tablets or computers.", n: "\"Device\" suena \"di-VAIS\", con el acento en la segunda sílaba.", nEn: "\"Device\" sounds \"di-VICE\", stressed on the second syllable." },
    "loc-b2te02": { e: "Please install the latest software update to fix the bug.", t: "Por favor, instala la última actualización de software para corregir el error.", s: "Cuando el sistema pide instalar una nueva versión.", sEn: "When the system asks you to install a newer version.", n: "\"Update\" como sustantivo lleva acento delante: \"AP-deit\".", nEn: "\"Update\" as a noun is stressed at the front: \"UP-date\"." },
    "loc-b2te03": { e: "The app collects too much personal data about its users.", t: "La aplicación recopila demasiados datos personales de sus usuarios.", s: "Al hablar de información digital o privacidad.", sEn: "When talking about digital information or privacy.", n: "Se acepta \"DEI-ta\" y \"DA-ta\"; el primero es más común en inglés.", nEn: "Both \"DAY-ta\" and \"DA-ta\" are accepted; the first is more common." },
    "loc-b2te04": { e: "Streaming a film in high quality uses a lot of data.", t: "Transmitir una película en alta calidad consume muchos datos.", s: "Al hablar de ver vídeos o escuchar música por internet.", sEn: "When talking about watching videos or listening to music online.", n: "El verbo es \"to stream\"; \"streaming service\" es una plataforma.", nEn: "The verb is \"to stream\"; a \"streaming service\" is a platform." },
    "loc-b2te05": { e: "You need to download the app before you can log in.", t: "Necesitas descargar la aplicación antes de poder iniciar sesión.", s: "Al instalar archivos, aplicaciones o documentos de internet.", sEn: "When installing files, apps or documents from the internet.", n: "\"Download\" (bajar) es lo contrario de \"upload\" (subir).", nEn: "\"Download\" (get from the net) is the opposite of \"upload\" (send up)." },
    "loc-b2te06": { e: "It only takes a minute to upload your photos to the cloud.", t: "Solo toma un minuto subir tus fotos a la nube.", s: "Al enviar archivos desde tu equipo a internet.", sEn: "When sending files from your device to the internet.", n: "Como sustantivo el acento va delante: \"AP-loud\".", nEn: "As a noun the stress is at the front: \"UP-load\"." },
    "loc-b2te07": { e: "You can change the language in the settings menu.", t: "Puedes cambiar el idioma en el menú de ajustes.", s: "Al configurar una aplicación o dispositivo.", sEn: "When configuring an app or device.", n: "Casi siempre va en plural: \"settings\".", nEn: "It is almost always plural: \"settings\"." },
    "loc-b2te08": { e: "I forgot the password to my email account.", t: "Olvidé la contraseña de mi cuenta de correo.", s: "Al iniciar sesión en un servicio o registrarse.", sEn: "When logging into a service or signing up.", n: "\"To create an account\" (crear una cuenta) es la colocación típica.", nEn: "\"To create an account\" is the typical collocation." },
    "loc-b2te09": { e: "This website works better on a different browser.", t: "Este sitio web funciona mejor en otro navegador.", s: "Al hablar de navegar por internet.", sEn: "When talking about browsing the internet.", n: "El verbo \"to browse\" significa navegar u ojear; la 's' suena como 'z'.", nEn: "The verb \"to browse\" means to surf or look around; the 's' sounds like 'z'." },
    "loc-b2te10": { e: "The new headphones are wireless, so there are no cables.", t: "Los nuevos audífonos son inalámbricos, así que no hay cables.", s: "Al hablar de conexiones, redes o dispositivos sin cable.", sEn: "When talking about connections, networks or cable-free devices.", n: "\"Wireless\" se forma de \"wire\" (cable) + \"-less\" (sin).", nEn: "\"Wireless\" comes from \"wire\" + \"-less\" (without)." },
    "loc-b2te11": { e: "My phone keeps telling me the storage is full.", t: "Mi teléfono me sigue avisando que el almacenamiento está lleno.", s: "Al hablar del espacio para archivos en un dispositivo.", sEn: "When talking about file space on a device.", n: "El verbo es \"to store\"; la 'g' final suena suave como en \"age\".", nEn: "The verb is \"to store\"; the final 'g' is soft like in \"age\"." },
    "loc-b2te12": { e: "Always make a backup of your files before updating the system.", t: "Siempre haz una copia de seguridad de tus archivos antes de actualizar el sistema.", s: "Al hablar de proteger datos contra pérdidas.", sEn: "When talking about protecting data against loss.", n: "Como verbo se escribe separado: \"to back up your files\".", nEn: "As a verb it is written apart: \"to back up your files\"." },
    "loc-b2te13": { e: "Artificial intelligence is now used to translate text in seconds.", t: "La inteligencia artificial ahora se usa para traducir texto en segundos.", s: "Al hablar de tecnología avanzada o automatización.", sEn: "When talking about advanced technology or automation.", n: "Se abrevia \"AI\", que se deletrea \"ei ai\".", nEn: "It is shortened to \"AI\", spelled out as \"ay-eye\"." },
    "loc-b2te14": { e: "She spends hours on social media every evening.", t: "Ella pasa horas en las redes sociales cada noche.", s: "Al hablar de plataformas como Instagram o Facebook.", sEn: "When talking about platforms like Instagram or Facebook.", n: "\"Social media\" se trata como singular: \"social media is...\".", nEn: "\"Social media\" is treated as singular: \"social media is...\"." },
    "loc-b2te15": { e: "Many users worry about their privacy when using free apps.", t: "Muchos usuarios se preocupan por su privacidad al usar aplicaciones gratuitas.", s: "Al hablar de protección de datos personales.", sEn: "When talking about protecting personal data.", n: "En inglés americano suena \"PRAI-va-si\", con la primera sílaba como \"pry\".", nEn: "In American English it sounds \"PRY-va-cy\", with the first syllable like \"pry\"." },
    "loc-b2te16": { e: "I turned off notifications so my phone would stop buzzing.", t: "Apagué las notificaciones para que mi teléfono dejara de vibrar.", s: "Al hablar de avisos o alertas en el celular.", sEn: "When talking about alerts or pop-ups on your phone.", n: "El verbo es \"to notify\"; el acento del sustantivo va en \"KEI\".", nEn: "The verb is \"to notify\"; the noun is stressed on \"ca\"." },
    "loc-b2te17": { e: "I cancelled my subscription because I never used the service.", t: "Cancelé mi suscripción porque nunca usé el servicio.", s: "Al hablar de pagos mensuales por una app o plataforma.", sEn: "When talking about monthly payments for an app or platform.", n: "El verbo es \"to subscribe\"; \"a monthly subscription\" es la colocación.", nEn: "The verb is \"to subscribe\"; \"a monthly subscription\" is the collocation." },
    "loc-b2te18": { e: "You can pay your bills online without going to the bank.", t: "Puedes pagar tus facturas en línea sin ir al banco.", s: "Al hablar de hacer cosas a través de internet.", sEn: "When talking about doing things over the internet.", n: "Lo contrario es \"offline\" (sin conexión); ambos sin guion.", nEn: "The opposite is \"offline\"; both are written without a hyphen." },
    "loc-b2sa01": { e: "Too much stress at work can really affect your sleep.", t: "Demasiado estrés en el trabajo puede afectar mucho tu sueño.", s: "Cuando hablas de cómo el trabajo o la vida te tensiona.", sEn: "When talking about how work or life makes you tense.", n: "'Stress' es incontable: di 'a lot of stress', no 'many stresses'.", nEn: "'Stress' is uncountable: say 'a lot of stress', not 'many stresses'." },
    "loc-b2sa02": { e: "A balanced diet gives you more energy throughout the day.", t: "Una alimentación equilibrada te da más energía durante el día.", s: "Cuando hablas de lo que comes habitualmente, no solo para adelgazar.", sEn: "When talking about what you usually eat, not just to lose weight.", n: "'Diet' también significa alimentación en general, no solo 'régimen'.", nEn: "'Diet' also means your overall eating, not only a weight-loss plan." },
    "loc-b2sa03": { e: "Washing your hands often helps prevent infections.", t: "Lavarte las manos seguido ayuda a prevenir infecciones.", s: "Cuando explicas cómo evitar una enfermedad antes de que ocurra.", sEn: "When explaining how to avoid an illness before it happens.", n: "Se usa 'prevent something' o 'prevent someone from doing'; no 'prevent to do'.", nEn: "Use 'prevent something' or 'prevent someone from doing'; not 'prevent to do'." },
    "loc-b2sa04": { e: "It took her two weeks to fully recover from the flu.", t: "Le tomó dos semanas recuperarse del todo de la gripe.", s: "Cuando alguien vuelve a estar bien después de estar enfermo.", sEn: "When someone gets well again after being sick.", n: "Se dice 'recover from an illness'; lleva la preposición 'from'.", nEn: "Say 'recover from an illness'; it takes the preposition 'from'." },
    "loc-b2sa05": { e: "A high fever is a common symptom of the flu.", t: "La fiebre alta es un síntoma común de la gripe.", s: "Cuando describes una señal de que estás enfermo.", sEn: "When describing a sign that you are ill.", n: "La 'p' en 'symptom' casi no se oye: suena 'SIM-tom'.", nEn: "The 'p' in 'symptom' is barely heard: it sounds like 'SIM-tom'." },
    "loc-b2sa06": { e: "The doctor started her on a new treatment last month.", t: "El médico le empezó un nuevo tratamiento el mes pasado.", s: "Cuando hablas del plan médico para curar una enfermedad.", sEn: "When talking about the medical plan to cure an illness.", n: "Se dice 'treatment for' una condición: 'treatment for asthma'.", nEn: "Say 'treatment for' a condition: 'treatment for asthma'." },
    "loc-b2sa07": { e: "You'll need a prescription to get these pills at the pharmacy.", t: "Necesitarás una receta para conseguir estas pastillas en la farmacia.", s: "Cuando el médico te autoriza un medicamento por escrito.", sEn: "When the doctor authorizes a medicine for you in writing.", n: "'Prescription' es receta médica; la receta de cocina es 'recipe'.", nEn: "'Prescription' is a medical script; a cooking recipe is 'recipe'." },
    "loc-b2sa08": { e: "I made an appointment with the dentist for next Tuesday.", t: "Hice una cita con el dentista para el próximo martes.", s: "Cuando reservas una hora con un médico o profesional.", sEn: "When you book a time with a doctor or professional.", n: "'Appointment' es cita formal; una cita romántica es 'a date'.", nEn: "'Appointment' is a formal meeting; a romantic one is 'a date'." },
    "loc-b2sa09": { e: "He missed the whole season because of a knee injury.", t: "Se perdió toda la temporada por una lesión de rodilla.", s: "Cuando hablas de un daño físico, como en el deporte.", sEn: "When talking about physical harm, such as in sport.", n: "'Injury' es daño físico; un insulto u ofensa no es 'injury'.", nEn: "'Injury' is physical harm; an insult or offense is not an 'injury'." },
    "loc-b2sa10": { e: "More companies now take their workers' mental health seriously.", t: "Cada vez más empresas toman en serio la salud mental de sus trabajadores.", s: "Cuando hablas del bienestar emocional y psicológico.", sEn: "When talking about emotional and psychological wellbeing.", n: "'Health' lleva el sonido /θ/ al final; suena 'jelz', con la lengua entre los dientes.", nEn: "'Health' ends in the /θ/ sound; place your tongue between your teeth." },
    "loc-b2sa11": { e: "Regular exercise is great for both body and wellbeing.", t: "El ejercicio regular es muy bueno para el cuerpo y el bienestar.", s: "Cuando hablas de sentirse bien en general, en cuerpo y mente.", sEn: "When talking about feeling good overall, in body and mind.", n: "También se escribe 'well-being' con guion; ambas formas son correctas.", nEn: "It is also written 'well-being' with a hyphen; both are correct." },
    "loc-b2sa12": { e: "After the night shift I was completely exhausted.", t: "Después del turno de noche estaba completamente agotado.", s: "Cuando estás muy cansado, más que solo 'tired'.", sEn: "When you are very tired, more than just 'tired'.", n: "'Exhausted' ya es extremo: no digas 'very exhausted', usa 'absolutely'.", nEn: "'Exhausted' is already extreme: not 'very exhausted', use 'absolutely'." },
    "loc-b2sa13": { e: "She tries to keep a balanced life between work and family.", t: "Ella intenta mantener una vida equilibrada entre el trabajo y la familia.", s: "Cuando describes algo sano y bien repartido, como la dieta o la vida.", sEn: "When describing something healthy and well shared out, like diet or life.", n: "Colocaciones útiles: 'a balanced diet', 'a balanced lifestyle'.", nEn: "Useful collocations: 'a balanced diet', 'a balanced lifestyle'." },
    "loc-b2sa14": { e: "He goes to the gym three times a week to improve his fitness.", t: "Va al gimnasio tres veces por semana para mejorar su estado físico.", s: "Cuando hablas de tu condición física o forma.", sEn: "When talking about your physical condition or shape.", n: "'Fitness' es incontable; no lleva 's' de plural ('fitnesses').", nEn: "'Fitness' is uncountable; it takes no plural 's' ('fitnesses')." },
    "loc-b2sa15": { e: "Sleeping well keeps your immune system strong.", t: "Dormir bien mantiene fuerte tu sistema inmune.", s: "Cuando hablas de las defensas del cuerpo contra enfermedades.", sEn: "When talking about the body's defenses against illness.", n: "'Immune' suena 'i-MIÚN', con el acento en la segunda sílaba.", nEn: "'Immune' sounds like 'i-MYOON', stressed on the second syllable." },
    "loc-b2sa16": { e: "Drowsiness is a common side effect of this medication.", t: "La somnolencia es un efecto secundario común de este medicamento.", s: "Cuando hablas de un efecto no deseado de un medicamento.", sEn: "When talking about an unwanted effect of a medicine.", n: "Casi siempre va en plural: 'the side effects of the drug'.", nEn: "It usually appears plural: 'the side effects of the drug'." },
    "loc-b2sa17": { e: "I go for a checkup with my doctor once a year.", t: "Voy a un chequeo con mi médico una vez al año.", s: "Cuando vas al médico de forma rutinaria, sin estar enfermo.", sEn: "When you visit the doctor routinely, without being sick.", n: "También se escribe 'check-up'; el verbo es 'to check up on'.", nEn: "It is also spelled 'check-up'; the verb is 'to check up on'." },
    "loc-b2sa18": { e: "Try to breathe slowly and deeply to calm down.", t: "Intenta respirar lento y profundo para calmarte.", s: "Cuando aconsejas a alguien que se relaje o controle la ansiedad.", sEn: "When advising someone to relax or manage anxiety.", n: "'Breathe' (verbo) lleva /ð/ y suena 'brid'; 'breath' (sustantivo) suena 'brez'.", nEn: "'Breathe' (verb) has /ð/ and sounds 'breedh'; 'breath' (noun) sounds 'breth'." },
    "loc-b2vj01": { e: "Our itinerary includes three cities in five days.", t: "Nuestro itinerario incluye tres ciudades en cinco días.", s: "Cuando hablas del plan detallado de un viaje.", sEn: "When talking about the detailed plan of a trip.", n: "'Itinerary' es difícil: practica 'ai-TÍ-ne-re-ri', con el acento al inicio del medio.", nEn: "'Itinerary' is tricky: practice 'eye-TIN-er-er-y'." },
    "loc-b2vj02": { e: "There was a two-hour delay because of the bad weather.", t: "Hubo un retraso de dos horas por el mal tiempo.", s: "Cuando un vuelo o tren sale más tarde de lo previsto.", sEn: "When a flight or train leaves later than planned.", n: "Como verbo: 'the flight was delayed'; el acento va en 'LÉI'.", nEn: "As a verb: 'the flight was delayed'; stress falls on 'LAY'." },
    "loc-b2vj03": { e: "The price includes flights and accommodation for a week.", t: "El precio incluye vuelos y alojamiento por una semana.", s: "Cuando hablas del lugar donde te hospedas en un viaje.", sEn: "When talking about the place you stay during a trip.", n: "Lleva doble 'c' y doble 'm'; error común es escribir 'acomodation'.", nEn: "It has double 'c' and double 'm'; a common error is 'acomodation'." },
    "loc-b2vj04": { e: "We spent the whole afternoon sightseeing in the old town.", t: "Pasamos toda la tarde haciendo turismo en el casco antiguo.", s: "Cuando visitas los lugares famosos de un sitio como turista.", sEn: "When visiting the famous places of a spot as a tourist.", n: "Se usa con 'go': 'go sightseeing', como 'go shopping'.", nEn: "It is used with 'go': 'go sightseeing', like 'go shopping'." },
    "loc-b2vj05": { e: "Please check the departure time on your boarding pass.", t: "Por favor revise la hora de salida en su tarjeta de embarque.", s: "Cuando hablas de cuándo sale un vuelo, tren o autobús.", sEn: "When talking about when a flight, train or bus leaves.", n: "En aeropuertos: 'departures' (salidas) frente a 'arrivals' (llegadas).", nEn: "At airports: 'departures' versus 'arrivals'." },
    "loc-b2vj06": { e: "On arrival, a guide will be waiting for you at the airport.", t: "A la llegada, un guía estará esperándote en el aeropuerto.", s: "Cuando hablas del momento de llegar a un destino.", sEn: "When talking about the moment of reaching a destination.", n: "'On arrival' significa 'al llegar'; es una expresión muy útil.", nEn: "'On arrival' means 'when you arrive'; a very handy phrase." },
    "loc-b2vj07": { e: "You can show your boarding pass on your phone at the gate.", t: "Puedes mostrar tu tarjeta de embarque en el teléfono en la puerta.", s: "Cuando hablas del documento para subir al avión.", sEn: "When talking about the document to board the plane.", n: "'Boarding pass' es para el avión; el 'ticket' es la compra del vuelo.", nEn: "'Boarding pass' is for the plane; the 'ticket' is the flight purchase." },
    "loc-b2vj08": { e: "We had to open our bags at customs when we landed.", t: "Tuvimos que abrir las maletas en la aduana al aterrizar.", s: "Cuando pasas el control de un país al entrar desde el extranjero.", sEn: "When you pass a country's control on entering from abroad.", n: "'Customs' (aduana) siempre lleva 's'; 'custom' (costumbre) es distinto.", nEn: "'Customs' (border control) always has 's'; 'custom' (a tradition) differs." },
    "loc-b2vj09": { e: "Make sure your travel insurance covers medical costs.", t: "Asegúrate de que tu seguro de viaje cubra los gastos médicos.", s: "Cuando hablas de protección contra problemas en el viaje.", sEn: "When talking about protection against trip problems.", n: "'Insurance' (sustantivo) suena 'in-SHÚ-rans'; el verbo es 'insure'.", nEn: "'Insurance' (noun) sounds 'in-SHOOR-ance'; the verb is 'insure'." },
    "loc-b2vj10": { e: "Lisbon has become a very popular travel destination.", t: "Lisboa se ha vuelto un destino de viaje muy popular.", s: "Cuando hablas del lugar al que viajas.", sEn: "When talking about the place you travel to.", n: "El acento va en 'NÉI': 'des-ti-NÉI-shon'.", nEn: "The stress falls on 'NA': 'des-ti-NAY-shon'." },
    "loc-b2vj11": { e: "The journey from the airport to the hotel takes an hour.", t: "El viaje del aeropuerto al hotel toma una hora.", s: "Cuando hablas del trayecto en sí, no del viaje completo.", sEn: "When talking about the trip itself, not the whole holiday.", n: "'Journey' es el trayecto; 'trip' es la salida completa (ida y vuelta).", nEn: "'Journey' is the travel itself; 'trip' is the whole outing there and back." },
    "loc-b2vj12": { e: "She's been studying abroad in Germany for two years.", t: "Ha estado estudiando en el extranjero, en Alemania, por dos años.", s: "Cuando hablas de estar o ir a otro país.", sEn: "When talking about being in or going to another country.", n: "'Abroad' no lleva preposición: di 'go abroad', no 'go to abroad'.", nEn: "'Abroad' takes no preposition: say 'go abroad', not 'go to abroad'." },
    "loc-b2vj13": { e: "You should change some currency before you arrive.", t: "Deberías cambiar algo de moneda antes de llegar.", s: "Cuando hablas del dinero de un país para cambiarlo.", sEn: "When talking about a country's money to exchange it.", n: "'Currency' es la divisa; las monedas físicas son 'coins'.", nEn: "'Currency' is the money system; physical coins are 'coins'." },
    "loc-b2vj14": { e: "The Eiffel Tower is the most famous landmark in Paris.", t: "La Torre Eiffel es el lugar emblemático más famoso de París.", s: "Cuando hablas de un sitio famoso y reconocible de una ciudad.", sEn: "When talking about a famous, recognizable site of a city.", n: "'Landmark' es un punto de referencia famoso, no cualquier monumento.", nEn: "'Landmark' is a famous reference point, not just any monument." },
    "loc-b2vj15": { e: "I had terrible jet lag for three days after the flight.", t: "Tuve un desfase horario terrible por tres días después del vuelo.", s: "Cuando estás cansado tras un vuelo largo entre husos horarios.", sEn: "When you are tired after a long flight across time zones.", n: "Se dice 'have jet lag' o 'be jet-lagged'; no 'feel jet lag bad'.", nEn: "Say 'have jet lag' or 'be jet-lagged'; not 'feel jet lag bad'." },
    "loc-b2vj16": { e: "They offered a full refund after the cancellation of the tour.", t: "Ofrecieron un reembolso completo tras la cancelación del tour.", s: "Cuando un vuelo, hotel o tour se cancela.", sEn: "When a flight, hotel or tour is cancelled.", n: "'Cancellation' lleva doble 'l'; el verbo 'cancel' lleva una sola.", nEn: "'Cancellation' has double 'l'; the verb 'cancel' has one." },
    "loc-b2vj17": { e: "We had a three-hour layover in Madrid on the way home.", t: "Tuvimos una escala de tres horas en Madrid de regreso a casa.", s: "Cuando esperas en un aeropuerto entre dos vuelos.", sEn: "When you wait at an airport between two flights.", n: "'Layover' (EE. UU.) y 'stopover' significan lo mismo: una escala.", nEn: "'Layover' (US) and 'stopover' mean the same: a connecting stop." },
    "loc-b2vj18": { e: "It's cheaper if you book your tickets well in advance.", t: "Sale más barato si reservas los boletos con buena antelación.", s: "Cuando recomiendas reservar antes de viajar para ahorrar.", sEn: "When recommending to reserve before traveling to save money.", n: "'Book' (verbo) es reservar; no confundir con 'book' (libro).", nEn: "'Book' (verb) means to reserve; don't confuse it with 'book' (the object)." },

    // ===================== Lernpfad-Erweiterung (Batch 2) =====================
    // --- saludos-en ---
    "loc-sal15": { e: "Hey, how's it going? Busy day today?", t: "Oye, ¿qué tal? ¿Día ocupado hoy?", s: "Saludo informal a un compañero o cliente habitual.", sEn: "An informal greeting to a coworker or regular customer.", n: "Más casual que \"How are you?\"; se responde \"Good, you?\".", nEn: "More casual than \"How are you?\"; reply \"Good, you?\"." },
    "loc-sal16": { e: "Welcome! Come on in, make yourself at home.", t: "¡Bienvenido! Pase, está en su casa.", s: "Al recibir a alguien que llega.", sEn: "When welcoming someone who arrives.", n: "\"Welcome\" se dice \"UÉL-com\", con la 'w' suave.", nEn: "\"Welcome\" is said \"WEL-cum\", with a soft 'w'." },
    "loc-sal17": { e: "Take care, and see you soon!", t: "Cuídate, ¡y nos vemos pronto!", s: "Despedida cálida con alguien que volverás a ver.", sEn: "A warm goodbye to someone you'll see again.", n: "\"Soon\" suena a una \"u\" larga: \"suun\".", nEn: "\"Soon\" has a long \"oo\": \"suun\"." },
    "loc-sal18": { e: "Long time! How have you been?", t: "¡Cuánto tiempo! ¿Cómo te ha ido?", s: "Al reencontrarte con alguien tras un tiempo.", sEn: "When you meet someone again after a while.", n: "Present perfect: pregunta por el periodo hasta ahora.", nEn: "Present perfect: it asks about the time up to now." },
    "loc-sal19": { e: "Long time no see — you look great!", t: "Cuánto tiempo sin verte, ¡te ves muy bien!", s: "Saludo informal a alguien que no veías hace mucho.", sEn: "An informal greeting to someone you haven't seen in ages.", n: "Frase hecha; su gramática \"rota\" es a propósito y muy común.", nEn: "A set phrase; the \"broken\" grammar is intentional and very common." },
    "loc-sal20": { e: "Say hi to your family for me!", t: "¡Saluda a tu familia de mi parte!", s: "Al despedirte de un conocido cercano.", sEn: "When saying goodbye to a close acquaintance.", n: "Agregar \"for me\" lo hace más cálido.", nEn: "Adding \"for me\" makes it warmer." },
    "loc-sal21": { e: "You look tired — get some rest tonight.", t: "Te ves cansado, descansa esta noche.", s: "Al despedirte de alguien cansado.", sEn: "When saying goodbye to someone who's tired.", n: "\"Get some rest\" es más natural que \"rest yourself\".", nEn: "\"Get some rest\" is more natural than \"rest yourself\"." },
    "loc-sal22": { e: "Good to see you again! How's everything?", t: "¡Qué gusto verte de nuevo! ¿Cómo va todo?", s: "Al encontrarte con un conocido.", sEn: "When running into someone you know.", n: "\"Good to see you\" (ya conocido) vs \"nice to meet you\" (primera vez).", nEn: "\"Good to see you\" (already known) vs \"nice to meet you\" (first time)." },
    // --- telefono ---
    "loc-tel15": { e: "Sorry, could you speak up? It's a bit noisy here.", t: "Perdón, ¿podría hablar más fuerte? Hay ruido aquí.", s: "Cuando oyes muy bajo a quien llama.", sEn: "When the caller sounds too quiet.", n: "\"Speak up\" = hablar más fuerte; phrasal verb.", nEn: "\"Speak up\" means to talk louder; a phrasal verb." },
    "loc-tel16": { e: "Sorry, the signal is bad — let me move to another room.", t: "Disculpe, la señal está mala; me cambio de cuarto.", s: "Cuando se corta o se oye mal durante la llamada.", sEn: "When the call breaks up or sounds bad.", n: "\"Signal\" lleva el acento al inicio: SÍG-nal.", nEn: "\"Signal\" is stressed at the start: SIG-nal." },
    "loc-tel17": { e: "One moment, I'll put you through to the right department.", t: "Un momento, le paso con el área correcta.", s: "Al transferir una llamada en recepción u oficina.", sEn: "When transferring a call at a front desk or office.", n: "\"Put you through\" = pasar/transferir la llamada.", nEn: "\"Put you through\" means to transfer the call." },
    "loc-tel18": { e: "Who may I say is calling, please?", t: "¿De parte de quién, por favor?", s: "Al contestar y necesitar el nombre de quien llama.", sEn: "When answering and needing the caller's name.", n: "Más cortés que \"Who is this?\".", nEn: "More polite than \"Who is this?\"." },
    "loc-tel19": { e: "I'm with a client right now — I'll call you later.", t: "Estoy con un cliente ahora; lo llamo más tarde.", s: "Cuando no puedes hablar y prometes devolver la llamada.", sEn: "When you can't talk and promise to call back.", n: "\"Call you later\" o \"call you back\" valen igual.", nEn: "\"Call you later\" or \"call you back\" both work." },
    "loc-tel20": { e: "Please stay on the line, I'm transferring you now.", t: "No cuelgue, le transfiero ahora.", s: "Justo antes de pasar la llamada.", sEn: "Right before passing the call on.", n: "\"Transfer\" para llamadas; el acento va al inicio.", nEn: "\"Transfer\" for calls; the stress is at the start." },
    // --- direcciones ---
    "loc-dir15": { e: "The office is on the second floor, take the stairs.", t: "La oficina está en el segundo piso, suba por las escaleras.", s: "Al indicar el piso de un lugar.", sEn: "When telling someone which floor a place is on.", n: "En EE. UU. \"second floor\" es un piso arriba del nivel de calle.", nEn: "In the US the \"second floor\" is one up from street level." },
    "loc-dir16": { e: "Just follow the signs to the exit.", t: "Solo siga las señales hacia la salida.", s: "Al guiar por señalización.", sEn: "When guiding someone by the signage.", n: "\"Signs\" lleva la 'g' muda y la 's' suena como 'z': \"sainz\".", nEn: "\"Signs\" has a silent 'g': \"sainz\"." },
    "loc-dir17": { e: "The pharmacy is just past the traffic light.", t: "La farmacia está justo pasando el semáforo.", s: "Al ubicar algo después de un punto.", sEn: "When locating something beyond a landmark.", n: "\"Traffic light\" = semáforo; \"past\" = pasando/más allá.", nEn: "\"Traffic light\" is the semáforo; \"past\" means beyond." },
    "loc-dir18": { e: "Go around the corner and you'll see the entrance.", t: "Dé la vuelta en la esquina y verá la entrada.", s: "Al indicar que rodee la esquina.", sEn: "When telling someone to round the corner.", n: "\"Around the corner\" = a la vuelta de la esquina.", nEn: "\"Around the corner\" means just past the corner." },
    "loc-dir19": { e: "It's between the bank and the pharmacy, you can't miss it.", t: "Está entre el banco y la farmacia, no tiene pierde.", s: "Al ubicar algo entre dos referencias.", sEn: "When placing something between two landmarks.", n: "\"Between\" para dos cosas; \"among\" para tres o más.", nEn: "\"Between\" for two things; \"among\" for three or more." },
    "loc-dir20": { e: "Excuse me, am I going the right way to the station?", t: "Disculpe, ¿voy en la dirección correcta a la estación?", s: "Al confirmar el rumbo con alguien.", sEn: "When checking your direction with someone.", n: "\"The right way\" = el camino correcto.", nEn: "\"The right way\" means the correct route." },
    // --- compras-en ---
    "loc-com15": { e: "Do you have this in another size?", t: "¿Tienen esto en otra talla?", s: "Al probarte algo que no te queda.", sEn: "When something you try on doesn't fit.", n: "\"Size\" sirve para ropa y zapatos.", nEn: "\"Size\" works for clothes and shoes." },
    "loc-com16": { e: "It's a gift — can you wrap it for me?", t: "Es un regalo, ¿me lo puede envolver?", s: "Al comprar un regalo.", sEn: "When buying a gift.", n: "\"Wrap\" tiene la 'w' muda: \"rap\".", nEn: "\"Wrap\" has a silent 'w': \"rap\"." },
    "loc-com17": { e: "Do you have this in stock, or is it sold out?", t: "¿Tienen este en stock, o está agotado?", s: "Al preguntar por disponibilidad.", sEn: "When asking about availability.", n: "\"In stock\" = disponible; \"out of stock\" = agotado.", nEn: "\"In stock\" means available; \"out of stock\" means sold out." },
    "loc-com18": { e: "There are so many — which one do you recommend?", t: "Hay tantos, ¿cuál me recomienda?", s: "Al pedir consejo de compra.", sEn: "When asking for a buying recommendation.", n: "\"Recommend\" lleva doble 'm'; acento en \"-MEND\".", nEn: "\"Recommend\" has a double 'm'; stress on \"-MEND\"." },
    "loc-com19": { e: "Great, I'll take this one.", t: "Perfecto, me llevo este.", s: "Al decidirte por un producto en la caja.", sEn: "When deciding on a product at the till.", n: "\"I'll take it\" es la forma típica de \"me lo llevo\".", nEn: "\"I'll take it\" is the typical way to say you'll buy it." },
    "loc-com20": { e: "It's pricey — can I pay in installments?", t: "Es caro, ¿puedo pagar a plazos?", s: "Al pagar algo costoso.", sEn: "When paying for something expensive.", n: "\"Installments\" = plazos/cuotas.", nEn: "\"Installments\" are the monthly payments." },
    // --- dinero-en ---
    "loc-din15": { e: "Do you have change for fifty? I only have a big bill.", t: "¿Tiene cambio de cincuenta? Solo tengo un billete grande.", s: "Al pagar con un billete grande.", sEn: "When paying with a large bill.", n: "\"Change\" aquí = vuelto/sencillo (incontable).", nEn: "\"Change\" here means coins/small money (uncountable)." },
    "loc-din16": { e: "What's the withdrawal fee at this ATM?", t: "¿Cuánto cobran por retirar en este cajero?", s: "Antes de sacar dinero de un cajero.", sEn: "Before taking money out at an ATM.", n: "\"Withdrawal\" es el sustantivo de \"withdraw\".", nEn: "\"Withdrawal\" is the noun of \"withdraw\"." },
    "loc-din17": { e: "My card has expired, I need a new one.", t: "Se me venció la tarjeta, necesito una nueva.", s: "Al avisar que la tarjeta caducó.", sEn: "When reporting that a card is out of date.", n: "\"Expired\" = vencido/caducado.", nEn: "\"Expired\" means out of date." },
    "loc-din18": { e: "How much do I owe you for the transfer?", t: "¿Cuánto debo pagar por la transferencia?", s: "En el banco, al preguntar el monto a pagar.", sEn: "At the bank, when asking the amount due.", n: "\"Owe\" se pronuncia \"OU\", como \"oh\".", nEn: "\"Owe\" is pronounced \"oh\"." },
    "loc-din19": { e: "I'd like to open an account, what do I need?", t: "Quiero abrir una cuenta, ¿qué necesito?", s: "En el banco al iniciar un trámite.", sEn: "At the bank when starting a process.", n: "\"Account\" lleva el acento en la segunda sílaba: a-CÁUNT.", nEn: "\"Account\" is stressed on the second syllable: a-COUNT." },
    "loc-din20": { e: "I'd like to deposit money into my account.", t: "Quisiera depositar dinero en mi cuenta.", s: "En el banco para ingresar dinero.", sEn: "At the bank to pay money in.", n: "\"Deposit\" = ingresar; lo opuesto de \"withdraw\".", nEn: "\"Deposit\" means to pay in; the opposite of \"withdraw\"." },
    // --- numeros-en ---
    "loc-num15": { e: "The city has over one million people.", t: "La ciudad tiene más de un millón de personas.", s: "Al decir cifras muy grandes.", sEn: "When saying very large numbers.", n: "\"Million\" no lleva 's' tras un número: \"two million\".", nEn: "\"Million\" takes no 's' after a number: \"two million\"." },
    "loc-num16": { e: "Take the first door, then the second on the right.", t: "Tome la primera puerta, luego la segunda a la derecha.", s: "Al dar indicaciones con ordinales.", sEn: "When giving directions with ordinals.", n: "Ordinales: first, second, third llevan terminaciones especiales.", nEn: "Ordinals: first, second, third have special endings." },
    "loc-num17": { e: "I'll be there in a quarter of an hour.", t: "Llego en un cuarto de hora.", s: "Al hablar de fracciones o tiempo.", sEn: "When talking about fractions or time.", n: "\"A quarter\" = un cuarto (1/4).", nEn: "\"A quarter\" means one fourth (1/4)." },
    "loc-num18": { e: "On weekends the price is double.", t: "Los fines de semana el precio es el doble.", s: "Al explicar un recargo o tarifa más alta.", sEn: "When explaining a surcharge or higher rate.", n: "\"Double\" se dice \"DÓ-bol\", no \"du-ble\".", nEn: "\"Double\" is said \"DUH-bul\", not \"doo-blay\"." },
    "loc-num19": { e: "The meeting starts at a quarter to five.", t: "La reunión empieza a cuarto para las cinco.", s: "Al decir la hora con \"para\".", sEn: "When telling time with \"to\".", n: "\"Quarter to five\" = 4:45; \"quarter past five\" = 5:15.", nEn: "\"Quarter to five\" is 4:45; \"quarter past five\" is 5:15." },
    "loc-num20": { e: "Your reservation is for the thirtieth of June.", t: "Su reserva es para el treinta de junio.", s: "Al confirmar una fecha con un cliente.", sEn: "When confirming a date with a customer.", n: "Las fechas usan ordinales: \"the thirtieth of June\".", nEn: "Dates use ordinals: \"the thirtieth of June\"." },
    // --- conectores-en ---
    "loc-con15": { e: "The flight was canceled; therefore, we stayed one more night.", t: "Cancelaron el vuelo; por lo tanto, nos quedamos una noche más.", s: "Al expresar una conclusión formal.", sEn: "When stating a formal conclusion.", n: "\"Therefore\" es formal; \"so\" es la versión informal.", nEn: "\"Therefore\" is formal; \"so\" is the informal version." },
    "loc-con16": { e: "We open late, that is to say, after ten.", t: "Abrimos tarde, es decir, después de las diez.", s: "Al aclarar o reformular una idea.", sEn: "When clarifying or rephrasing an idea.", n: "\"That is to say\" introduce una aclaración; \"i.e.\" por escrito.", nEn: "\"That is to say\" introduces a clarification; \"i.e.\" in writing." },
    "loc-con17": { e: "It's not far; in fact, it's just around the corner.", t: "No queda lejos; de hecho, está a la vuelta.", s: "Al reforzar o corregir lo dicho.", sEn: "When reinforcing or correcting what was said.", n: "\"In fact\" añade énfasis o corrige una idea previa.", nEn: "\"In fact\" adds emphasis or corrects a previous idea." },
    "loc-con18": { e: "We'll go ahead unless you tell us otherwise.", t: "Seguimos adelante a menos que nos digas lo contrario.", s: "Al poner una condición negativa.", sEn: "When setting a negative condition.", n: "\"Unless\" = si no / a menos que; ya es negativo.", nEn: "\"Unless\" means \"if not\"; it's already negative." },
    "loc-con19": { e: "Please wait here while I check the system.", t: "Espere aquí mientras reviso el sistema.", s: "Al pedir que alguien aguarde durante una acción.", sEn: "When asking someone to wait during a task.", n: "\"While\" va con un verbo; \"during\" con un sustantivo.", nEn: "\"While\" is used with a verb; \"during\" with a noun." },
    "loc-con20": { e: "Some prefer tea; on the other hand, others love coffee.", t: "Algunos prefieren té; en cambio, otros aman el café.", s: "Al presentar el otro lado de una idea.", sEn: "When presenting the other side of an idea.", n: "\"On the other hand\" contrasta dos opciones.", nEn: "\"On the other hand\" contrasts two options." },
    "loc-con21": { e: "First, log in; then, open the report.", t: "Primero, inicia sesión; luego, abre el reporte.", s: "Al explicar pasos en orden.", sEn: "When explaining steps in order.", n: "\"First… then…\" ordena instrucciones con claridad.", nEn: "\"First… then…\" orders instructions clearly." },
    "loc-con22": { e: "Finally, we signed the contract.", t: "Finalmente, firmamos el contrato.", s: "Al cerrar una secuencia o un relato.", sEn: "When closing a sequence or a story.", n: "\"Finally\" al inicio resume el último paso.", nEn: "\"Finally\" at the start sums up the last step." },
    // --- preguntas-en ---
    "loc-prg13": { e: "I'm not sure what to order — can you recommend something?", t: "No sé qué pedir, ¿me puede recomendar algo?", s: "Al pedir una sugerencia.", sEn: "When asking for a suggestion.", n: "\"Recommend\" rige objeto directo: \"recommend something\".", nEn: "\"Recommend\" takes a direct object: \"recommend something\"." },
    "loc-prg14": { e: "May I ask you a question about the schedule?", t: "¿Le puedo hacer una pregunta sobre el horario?", s: "Al pedir permiso para preguntar algo.", sEn: "When asking permission to ask something.", n: "\"May I ask...\" es una forma muy cortés de iniciar una pregunta.", nEn: "\"May I ask...\" is a very polite way to start a question." },
    "loc-prg15": { e: "Sorry, what does this word mean?", t: "Perdón, ¿qué significa esta palabra?", s: "Al no entender un término en inglés.", sEn: "When you don't understand an English term.", n: "\"What does … mean?\" pide el significado.", nEn: "\"What does … mean?\" asks for the meaning." },
    "loc-prg16": { e: "When does the shop open tomorrow?", t: "¿Cuándo abre la tienda mañana?", s: "Al preguntar por horarios de atención.", sEn: "When asking about opening hours.", n: "\"Does it open\" en presente para horarios habituales.", nEn: "\"Does it open\" in the present for regular hours." },
    "loc-prg17": { e: "Is there Wi-Fi here, and what's the password?", t: "¿Hay wifi aquí, y cuál es la contraseña?", s: "Al llegar a un café u hotel.", sEn: "When arriving at a café or hotel.", n: "\"Is there…?\" pregunta por disponibilidad.", nEn: "\"Is there…?\" asks about availability." },
    "loc-prg18": { e: "How do I get there from here?", t: "¿Cómo llego allá desde aquí?", s: "Al pedir indicaciones de ruta.", sEn: "When asking for directions to a place.", n: "\"Get there\" = llegar; muy natural en preguntas de ruta.", nEn: "\"Get there\" means to arrive; very natural for directions." },
    "loc-prg19": { e: "Sorry, can you say that again, more slowly?", t: "Perdón, ¿puede repetir, más despacio?", s: "Cuando no entendiste lo que dijeron.", sEn: "When you didn't catch what was said.", n: "\"Say that again\" suena más suave que \"repeat\".", nEn: "\"Say that again\" sounds softer than \"repeat\"." },
    "loc-prg20": { e: "Is it okay if I pay later?", t: "¿Está bien si pago después?", s: "Al pedir permiso o flexibilidad.", sEn: "When asking permission or flexibility.", n: "\"Is it okay if I…?\" pide permiso de forma cortés.", nEn: "\"Is it okay if I…?\" politely asks permission." },
    // --- cliente-en ---
    "loc-cli15": { e: "I'd be glad to take care of that for you right now.", t: "Con gusto me encargo de eso ahora mismo.", s: "Cuando el cliente pide algo y quieres mostrar buena disposición.", sEn: "When the customer asks for something and you want to sound willing.", n: "\"Take care of that\" = ocuparme de eso.", nEn: "\"Take care of that\" means to handle it." },
    "loc-cli16": { e: "Could you give me more details about the problem?", t: "¿Podría darme más detalles del problema?", s: "Al necesitar más información para resolver.", sEn: "When you need more information to resolve an issue.", n: "\"Could you…?\" es más cortés que \"Can you…?\".", nEn: "\"Could you…?\" is more polite than \"Can you…?\"." },
    "loc-cli17": { e: "I'll look into it right away and call you back.", t: "Reviso su caso de inmediato y le devuelvo la llamada.", s: "Al comprometerte a investigar un problema.", sEn: "When committing to investigate a problem.", n: "\"Look into\" = investigar/revisar a fondo.", nEn: "\"Look into\" means to investigate something." },
    "loc-cli18": { e: "I understand your concern, let's fix this together.", t: "Entiendo su preocupación, resolvámoslo juntos.", s: "Al mostrar empatía con un cliente molesto.", sEn: "When showing empathy with an upset customer.", n: "Validar la preocupación calma al cliente.", nEn: "Acknowledging the concern calms the customer." },
    "loc-cli19": { e: "I'll confirm everything by email today.", t: "Le confirmo todo por correo hoy.", s: "Al cerrar dejando constancia escrita.", sEn: "When closing with a written record.", n: "\"By email\" = por correo; sin artículo.", nEn: "\"By email\" needs no article." },
    "loc-cli20": { e: "I'll wait to hear from you before we proceed.", t: "Quedo pendiente de su respuesta antes de continuar.", s: "Al esperar la decisión del cliente.", sEn: "When awaiting the customer's decision.", n: "\"Hear from you\" = tener noticias tuyas.", nEn: "\"Hear from you\" means to get a reply from you." },
    // --- bpo-en ---
    "loc-bpo17": { e: "May I put you on hold for a moment?", t: "¿Me permite ponerlo en espera un momento?", s: "Antes de poner en espera al cliente en un call center.", sEn: "Before putting a caller on hold in a call center.", n: "Pedir permiso primero es buena práctica de call center.", nEn: "Asking permission first is good call-center practice." },
    "loc-bpo18": { e: "Let me update your details on the account.", t: "Permítame actualizar sus datos en la cuenta.", s: "Al corregir información del cliente.", sEn: "When correcting the customer's information.", n: "\"Details\" = datos/detalles; acento al inicio.", nEn: "\"Details\" means the data; stress at the start." },
    "loc-bpo19": { e: "For your security, let me verify your identity first.", t: "Por su seguridad, permítame verificar su identidad primero.", s: "Antes de dar información sensible de la cuenta.", sEn: "Before sharing sensitive account information.", n: "\"Verify\" se acentúa al inicio: VÉ-ri-fai.", nEn: "\"Verify\" is stressed at the start: VE-ri-fy." },
    "loc-bpo20": { e: "I'll send a confirmation email with the details.", t: "Le enviaré un correo de confirmación con los detalles.", s: "Al cerrar un trámite por teléfono.", sEn: "When wrapping up a process over the phone.", n: "\"Confirmation\" tiene cuatro sílabas: con-fir-MÉI-shon.", nEn: "\"Confirmation\" has four syllables: con-fir-MAY-shun." },
    "loc-bpo21": { e: "Is there anything else I can do for you today?", t: "¿Hay algo más en que pueda ayudarle hoy?", s: "Antes de finalizar la llamada.", sEn: "Before ending the call.", n: "Frase de cierre estándar en call center.", nEn: "A standard call-center closing line." },
    "loc-bpo22": { e: "Have a great day, and thanks for calling!", t: "Que tenga un buen día, ¡y gracias por llamar!", s: "Al despedirte de quien llamó.", sEn: "When saying goodbye to the caller.", n: "Cierre cálido que deja buena impresión.", nEn: "A warm closing that leaves a good impression." },
    // --- reunion-en ---
    "loc-reu15": { e: "We have a lot to cover, so let's get through the agenda.", t: "Tenemos mucho que ver, así que avancemos con la agenda.", s: "Al mantener el ritmo de la reunión.", sEn: "When keeping the meeting on pace.", n: "\"Get through\" = terminar/recorrer algo.", nEn: "\"Get through\" means to work all the way through something." },
    "loc-reu16": { e: "Before we close, anything to add?", t: "Antes de cerrar, ¿quieren añadir algo?", s: "Al invitar aportes finales.", sEn: "When inviting final input.", n: "Forma breve de \"is there anything to add?\".", nEn: "Short form of \"is there anything to add?\"." },
    "loc-reu17": { e: "We're out of time, so let's cover it next meeting.", t: "Se nos acabó el tiempo, lo vemos en la próxima reunión.", s: "Al posponer un punto a otra sesión.", sEn: "When deferring a point to another session.", n: "\"Cover\" aquí = tratar/abordar un tema.", nEn: "\"Cover\" here means to deal with a topic." },
    "loc-reu18": { e: "Good point, let's add that to the plan.", t: "Buen punto, agreguémoslo al plan.", s: "Cuando alguien dice algo acertado en una reunión.", sEn: "When someone makes a fair point in a meeting.", n: "\"Good point\" reconoce la idea sin comprometerte del todo.", nEn: "\"Good point\" acknowledges the idea without fully committing." },
    "loc-reu19": { e: "We're short on time, so let's wrap up.", t: "Vamos cortos de tiempo, así que vayamos cerrando.", s: "Al acercarse el final de la reunión.", sEn: "When the meeting is nearly over.", n: "\"Wrap up\" = cerrar/terminar; phrasal verb muy útil.", nEn: "\"Wrap up\" means to finish; a very useful phrasal verb." },
    "loc-reu20": { e: "I'll share the notes after the meeting.", t: "Comparto las notas después de la reunión.", s: "Al ofrecer enviar el resumen al equipo.", sEn: "When offering to send the team a summary.", n: "\"Share\" para archivos o pantallas; muy común en trabajo.", nEn: "\"Share\" for files or screens; very common at work." },
    // --- oficina ---
    "loc-ofi15": { e: "Can you forward me that email when you get a chance?", t: "¿Puede reenviarme ese correo cuando pueda?", s: "Al pedir que te reenvíen un mensaje.", sEn: "When asking someone to forward a message.", n: "\"Forward\" para correos; \"transfer\" para llamadas.", nEn: "\"Forward\" for emails; \"transfer\" for calls." },
    "loc-ofi16": { e: "I'm on the cc, so I've seen the thread.", t: "Estoy en copia, así que vi la conversación.", s: "Al confirmar que estás al tanto de un correo.", sEn: "When confirming you're aware of an email.", n: "\"cc\" se deletrea \"si-si\"; \"thread\" = hilo del correo.", nEn: "\"cc\" is spelled out \"see-see\"; \"thread\" is the email chain." },
    "loc-ofi17": { e: "I'll reply before noon with the figures.", t: "Le respondo antes del mediodía con las cifras.", s: "Al comprometerte a un plazo concreto.", sEn: "When committing to a specific deadline.", n: "\"Noon\" = mediodía (12:00).", nEn: "\"Noon\" means midday (12:00)." },
    "loc-ofi18": { e: "I need an extension on the deadline, please.", t: "Necesito una prórroga en la fecha límite, por favor.", s: "Al pedir más tiempo para una entrega.", sEn: "When asking for more time on a task.", n: "\"Extension\" = prórroga/ampliación de plazo.", nEn: "\"Extension\" means more time on a deadline." },
    "loc-ofi19": { e: "I'm working from home today, but I'm online.", t: "Hoy trabajo desde casa, pero estoy conectado.", s: "Al avisar que trabajas en remoto.", sEn: "When letting others know you're working remotely.", n: "\"Working from home\" (WFH) = teletrabajo.", nEn: "\"Working from home\" (WFH) means remote work." },
    "loc-ofi20": { e: "I'm on leave next week, so please reach out to my colleague.", t: "La próxima semana estoy de permiso, así que escríbale a mi colega.", s: "Al informar de una ausencia planeada.", sEn: "When announcing a planned absence.", n: "\"On leave\" = de permiso/vacaciones; formal y claro.", nEn: "\"On leave\" means away on time off; formal and clear." },
    // --- tech-en ---
    "loc-tech17": { e: "We need to fix this bug before the release.", t: "Hay que arreglar este bug antes del lanzamiento.", s: "Al priorizar un error en el equipo.", sEn: "When prioritizing an error with the team.", n: "\"Bug\" = error; \"release\" = lanzamiento/versión.", nEn: "\"Bug\" is an error; \"release\" is a version launch." },
    "loc-tech18": { e: "Can you merge the PR when the tests pass?", t: "¿Puedes hacer merge del PR cuando pasen las pruebas?", s: "En un flujo de trabajo con control de versiones.", sEn: "In a version-control workflow.", n: "\"PR\" = pull request; se deletrea \"pi-ar\".", nEn: "\"PR\" is pull request; spelled out \"pee-arr\"." },
    "loc-tech19": { e: "It's in testing now; I'll update you soon.", t: "Está en pruebas ahora; te aviso pronto.", s: "Al reportar el estado de una tarea.", sEn: "When reporting the status of a task.", n: "\"In testing\" = en fase de pruebas.", nEn: "\"In testing\" means in the testing phase." },
    "loc-tech20": { e: "The server is down, the team is looking into it.", t: "El servidor está caído, el equipo lo está revisando.", s: "Al comunicar una caída del sistema.", sEn: "When reporting a system outage.", n: "\"Down\" = caído/fuera de servicio; \"up\" = funcionando.", nEn: "\"Down\" means offline; \"up\" means running." },
    "loc-tech21": { e: "Try to restart the service and see if it helps.", t: "Intenta reiniciar el servicio a ver si ayuda.", s: "Al sugerir un primer paso de solución.", sEn: "When suggesting a first troubleshooting step.", n: "\"Restart\" = reiniciar; \"reset\" es restablecer.", nEn: "\"Restart\" means reboot; \"reset\" means restore defaults." },
    "loc-tech22": { e: "I'll give you access to the repo this afternoon.", t: "Te paso el acceso al repositorio esta tarde.", s: "Al conceder permisos a un compañero.", sEn: "When granting a teammate permissions.", n: "\"Access\" lleva el acento al inicio: ÁK-ses.", nEn: "\"Access\" is stressed at the start: AK-ses." },
    // --- entrevista ---
    "loc-ent15": { e: "I have experience leading small teams under pressure.", t: "Tengo experiencia liderando equipos pequeños bajo presión.", s: "En la entrevista, al describir tu experiencia de liderazgo.", sEn: "In the interview, when describing your leadership experience.", n: "\"Leading\" + sustantivo: dirigiendo/al frente de.", nEn: "\"Leading\" + noun: being in charge of." },
    "loc-ent16": { e: "I work well in a team and under pressure.", t: "Trabajo bien en equipo y bajo presión.", s: "Al describir tus fortalezas.", sEn: "When describing your strengths.", n: "\"In a team\" lleva artículo; no \"in team\".", nEn: "\"In a team\" needs the article; not \"in team\"." },
    "loc-ent17": { e: "Is the role remote or on-site, or a mix?", t: "¿El puesto es remoto o presencial, o mixto?", s: "Al preguntar la modalidad de trabajo.", sEn: "When asking about the work arrangement.", n: "\"On-site\" = presencial; \"remote\" = a distancia.", nEn: "\"On-site\" means in person; \"remote\" means from home." },
    "loc-ent18": { e: "I handle pressure well and stay calm.", t: "Manejo bien la presión y mantengo la calma.", s: "Al describir tu temperamento laboral.", sEn: "When describing your work temperament.", n: "\"Handle\" tiene la 'h' aspirada suave: \"JÁN-dol\".", nEn: "\"Handle\" has a soft aspirated 'h': \"HAN-dl\"." },
    "loc-ent19": { e: "What would my duties be on a typical day?", t: "¿Cuáles serían mis funciones en un día normal?", s: "Al preguntar por las responsabilidades del puesto.", sEn: "When asking about the role's responsibilities.", n: "\"Duties\" = funciones/responsabilidades.", nEn: "\"Duties\" means responsibilities or tasks." },
    "loc-ent20": { e: "I'm available to start right away.", t: "Estoy disponible para empezar de inmediato.", s: "Al indicar tu disponibilidad inmediata.", sEn: "When stating your immediate availability.", n: "\"Available\" se acentúa: a-VÉI-la-bol.", nEn: "\"Available\" is stressed: a-VAY-la-bul." },
    // --- modales-en ---
    "loc-mod13": { e: "Could you give me a hand with these boxes?", t: "¿Podrías echarme una mano con estas cajas?", s: "Al pedir ayuda de forma amable.", sEn: "When asking for help in a friendly way.", n: "\"Give me a hand\" = echar una mano (ayudar).", nEn: "\"Give me a hand\" means to help out." },
    "loc-mod14": { e: "It's okay, you don't have to apologize.", t: "Está bien, no tienes que disculparte.", s: "Al tranquilizar a quien se disculpa.", sEn: "When reassuring someone who apologizes.", n: "\"Don't have to\" = no es necesario (sin obligación).", nEn: "\"Don't have to\" means it isn't necessary." },
    "loc-mod15": { e: "You may be right, let's check the data.", t: "Podría tener razón, revisemos los datos.", s: "Al admitir una posibilidad con cortesía.", sEn: "When politely admitting a possibility.", n: "\"May be\" (dos palabras) = posibilidad; \"maybe\" = quizás.", nEn: "\"May be\" (two words) is possibility; \"maybe\" is perhaps." },
    "loc-mod16": { e: "We must finish today, the client is waiting.", t: "Debemos terminar hoy, el cliente espera.", s: "Al expresar una obligación fuerte.", sEn: "When expressing a strong obligation.", n: "\"Must\" es obligación más fuerte que \"have to\".", nEn: "\"Must\" is a stronger obligation than \"have to\"." },
    "loc-mod17": { e: "Excuse me, can I use the restroom?", t: "Disculpe, ¿puedo usar el baño?", s: "Al pedir permiso de forma cotidiana.", sEn: "When asking permission in everyday situations.", n: "\"Can I…?\" para permiso informal; \"may I…?\" formal.", nEn: "\"Can I…?\" for casual permission; \"may I…?\" formal." },
    "loc-mod18": { e: "May I ask a question before we start?", t: "¿Me permites una pregunta antes de empezar?", s: "Al pedir turno para preguntar.", sEn: "When asking for the floor to question.", n: "\"May I\" es muy cortés para pedir permiso.", nEn: "\"May I\" is very polite for asking permission." },
    // --- pronunciacion-en ---
    "loc-pron15": { e: "Say \"think\" with your tongue between your teeth.", t: "Di \"think\" con la lengua entre los dientes.", s: "Al practicar la \"th\" sorda (zeta inglesa).", sEn: "When practicing the unvoiced \"th\".", n: "La \"th\" de think no es \"t\" ni \"s\"; lengua entre dientes.", nEn: "The \"th\" in think is neither \"t\" nor \"s\"; tongue between teeth." },
    "loc-pron16": { e: "\"This\" uses a soft, voiced \"th\".", t: "\"This\" usa una \"th\" suave y sonora.", s: "Al distinguir la \"th\" sonora de la sorda.", sEn: "When telling the voiced \"th\" from the unvoiced one.", n: "En think la \"th\" es sorda; en this es sonora (suena a \"d\").", nEn: "In think the \"th\" is unvoiced; in this it's voiced (like a \"d\")." },
    "loc-pron17": { e: "\"Beach\" has a long \"ee\"; keep it clear.", t: "\"Beach\" tiene una \"i\" larga; pronúnciala clara.", s: "Al evitar confundir beach con una mala palabra.", sEn: "When avoiding confusing beach with a rude word.", n: "Alarga la \"i\": \"biich\", no \"bich\".", nEn: "Lengthen the \"ee\": \"beech\", not \"bitch\"." },
    "loc-pron18": { e: "\"Work\" has a soft American \"r\".", t: "\"Work\" tiene una \"r\" suave a la americana.", s: "Al pulir la \"r\" inglesa.", sEn: "When polishing the English \"r\".", n: "No la hagas vibrante como en español; \"uérk\".", nEn: "Don't roll it like in Spanish; \"werk\"." },
    "loc-pron19": { e: "\"Comfortable\" sounds like \"COMF-ta-bul\".", t: "\"Comfortable\" suena \"COMF-ta-bol\".", s: "Al reducir sílabas en palabras largas.", sEn: "When reducing syllables in long words.", n: "Los nativos comen sílabas: tres, no cuatro.", nEn: "Natives drop a syllable: three, not four." },
    "loc-pron20": { e: "\"Wednesday\" sounds like \"WENS-day\".", t: "\"Wednesday\" suena \"UÉNS-dei\".", s: "Al pronunciar días con letras mudas.", sEn: "When pronouncing days with silent letters.", n: "La primera \"d\" es muda.", nEn: "The first \"d\" is silent." },
    // --- falsos-amigos ---
    "loc-fa17": { e: "Insert the card into the machine.", t: "Introduce la tarjeta en la máquina.", s: "Al usar \"introducir\" en sentido físico.", sEn: "When using \"introduce\" in the physical sense.", n: "\"Introduce\" en inglés es presentar a alguien; meter algo es \"insert\".", nEn: "\"Introduce\" means to present a person; to put something in is \"insert\"." },
    "loc-fa18": { e: "I can't put up with the noise anymore.", t: "Ya no soporto el ruido.", s: "Al hablar de tolerar algo molesto.", sEn: "When talking about tolerating something annoying.", n: "\"Support\" es apoyar; tolerar es \"put up with\".", nEn: "\"Support\" means to back someone; to tolerate is \"put up with\"." },
    "loc-fa19": { e: "We'll carry out the plan next week.", t: "Realizaremos el plan la próxima semana.", s: "Al hablar de ejecutar/llevar a cabo algo.", sEn: "When talking about executing a plan.", n: "\"Realize\" es darse cuenta; hacer/ejecutar es \"carry out\".", nEn: "\"Realize\" means to become aware; to do/execute is \"carry out\"." },
    "loc-fa20": { e: "They always argue about money.", t: "Siempre discuten por dinero.", s: "Al referirte a una disputa.", sEn: "When referring to a quarrel.", n: "\"Argue\" suele ser pelear; \"discuss\" es debatir con calma.", nEn: "\"Argue\" usually means to quarrel; \"discuss\" is to talk it over calmly." },
    "loc-fa21": { e: "We spent the weekend in the countryside.", t: "Pasamos el fin de semana en el campo.", s: "Al hablar del campo (zona rural).", sEn: "When talking about the rural countryside.", n: "\"Camp\" es campamento; zona rural es \"countryside\".", nEn: "\"Camp\" is a campsite; rural land is \"countryside\"." },
    "loc-fa22": { e: "My kids go to school nearby.", t: "Mis hijos van al colegio aquí cerca.", s: "Al hablar de la escuela de niños.", sEn: "When talking about children's school.", n: "\"College\" es universidad; el colegio es \"school\".", nEn: "\"College\" means university; primary/secondary is \"school\"." },
    // --- feedback-en ---
    "loc-fb11": { e: "I have a suggestion that might help the team.", t: "Tengo una sugerencia que podría ayudar al equipo.", s: "Al proponer una mejora de forma constructiva.", sEn: "When proposing an improvement constructively.", n: "\"Suggestion\" se dice \"so-YÉS-chon\".", nEn: "\"Suggestion\" is said \"suh-JES-chun\"." },
    "loc-fb12": { e: "Can I give you some feedback on the report?", t: "¿Puedo darte feedback sobre el reporte?", s: "Al pedir permiso antes de comentar el trabajo.", sEn: "When asking permission before commenting on work.", n: "Pedir permiso primero suena más respetuoso.", nEn: "Asking permission first sounds more respectful." },
    "loc-fb13": { e: "You did really well on this project.", t: "Lo hiciste muy bien en este proyecto.", s: "Al reconocer un buen desempeño.", sEn: "When recognizing good performance.", n: "\"Well\" (adverbio), no \"good\", tras un verbo de acción.", nEn: "Use \"well\" (adverb), not \"good\", after an action verb." },
    "loc-fb14": { e: "Let's work on this together next week.", t: "Trabajemos en esto juntos la próxima semana.", s: "Al ofrecer apoyo tras dar feedback.", sEn: "When offering support after giving feedback.", n: "\"Work on\" = trabajar en/mejorar algo.", nEn: "\"Work on\" means to improve something." },
    "loc-fb15": { e: "What can I improve for next time?", t: "¿Qué puedo mejorar para la próxima?", s: "Al pedir retroalimentación sobre tu trabajo.", sEn: "When asking for feedback on your own work.", n: "\"Improve\" lleva el acento en la segunda sílaba.", nEn: "\"Improve\" is stressed on the second syllable." },
    "loc-fb16": { e: "How can I support you better next month?", t: "¿Cómo puedo apoyarte mejor el próximo mes?", s: "Al ofrecer ayuda en una evaluación.", sEn: "When offering help in a review.", n: "Pregunta abierta que muestra liderazgo cercano.", nEn: "An open question that shows supportive leadership." },
    // --- networking-en ---
    "loc-net11": { e: "What field are you in? I work in logistics myself.", t: "¿En qué área trabajas? Yo trabajo en logística.", s: "Al conocer a alguien en un evento de networking.", sEn: "When meeting someone at a networking event.", n: "\"Field\" = área o sector profesional.", nEn: "\"Field\" means your professional area or sector." },
    "loc-net12": { e: "Tell me more about your project.", t: "Cuéntame más de tu proyecto.", s: "Al mostrar interés en lo que hace alguien.", sEn: "When showing interest in what someone does.", n: "\"Tell me about…\" invita a seguir hablando.", nEn: "\"Tell me about…\" invites them to keep talking." },
    "loc-net13": { e: "Can you introduce me to someone in that team?", t: "¿Me presentas a alguien de ese equipo?", s: "Al pedir una presentación en un evento.", sEn: "When asking for an introduction at an event.", n: "\"Introduce me to\" = presentarme a (una persona).", nEn: "\"Introduce me to\" means to present me to a person." },
    "loc-net14": { e: "I'll reach out this week to set something up.", t: "Te escribo esta semana para coordinar algo.", s: "Al prometer contacto tras conocer a alguien.", sEn: "When promising to follow up after meeting.", n: "\"Reach out\" = contactar/escribir; muy usado.", nEn: "\"Reach out\" means to get in touch; very common." },
    "loc-net15": { e: "It was great meeting you today.", t: "Fue un gusto conocerte hoy.", s: "Al despedirte tras una buena charla.", sEn: "When saying goodbye after a good chat.", n: "Tras \"great\" va verbo en -ing: \"meeting you\".", nEn: "After \"great\" use the -ing form: \"meeting you\"." },
    "loc-net16": { e: "Do you have a card? Let's stay in touch.", t: "¿Tienes una tarjeta? Sigamos en contacto.", s: "Al intercambiar datos de contacto.", sEn: "When exchanging contact details.", n: "\"Stay in touch\" = seguir en contacto.", nEn: "\"Stay in touch\" means to keep in contact." },
    // --- resenas-en ---
    "loc-res15": { e: "The service was excellent from start to finish.", t: "El servicio fue excelente de principio a fin.", s: "Al escribir una reseña positiva.", sEn: "When writing a positive review.", n: "\"Excellent\" se acentúa al inicio: ÉK-se-lent.", nEn: "\"Excellent\" is stressed at the start: EK-se-lent." },
    "loc-res16": { e: "I highly recommend this place to everyone.", t: "Recomiendo mucho este lugar a todos.", s: "Al cerrar una reseña recomendando.", sEn: "When closing a review with a recommendation.", n: "\"Highly recommend\" es la fórmula natural.", nEn: "\"Highly recommend\" is the natural phrasing." },
    "loc-res17": { e: "I'd come back for sure next time.", t: "Volvería sin dudarlo la próxima vez.", s: "Al expresar que repetirías la experiencia.", sEn: "When expressing you'd repeat the experience.", n: "\"For sure\" = sin duda; informal y positivo.", nEn: "\"For sure\" means definitely; casual and positive." },
    "loc-res18": { e: "The food was delicious and well presented.", t: "La comida estaba deliciosa y bien presentada.", s: "Al elogiar la comida en una reseña.", sEn: "When praising the food in a review.", n: "\"Delicious\" ya es intenso; no necesita \"very\".", nEn: "\"Delicious\" is already strong; no need for \"very\"." },
    "loc-res19": { e: "The staff was very friendly and helpful.", t: "El personal fue muy amable y servicial.", s: "Al valorar la atención recibida.", sEn: "When rating the service you received.", n: "\"Staff\" es colectivo; suele ir en singular.", nEn: "\"Staff\" is collective; usually takes a singular verb." },
    "loc-res20": { e: "Thanks for your review, it means a lot to us.", t: "Gracias por tu reseña, significa mucho para nosotros.", s: "Al responder a un cliente que dejó reseña.", sEn: "When replying to a customer who left a review.", n: "Responder reseñas mejora la reputación del negocio.", nEn: "Replying to reviews improves a business's reputation." },
    // --- finanzas-en ---
    "loc-fin13": { e: "When is the billing date for this account?", t: "¿Cuándo es la fecha de corte de esta cuenta?", s: "Al preguntar cuándo se factura.", sEn: "When asking when billing happens.", n: "\"Billing date\" = fecha de corte/facturación.", nEn: "\"Billing date\" is when the bill is issued." },
    "loc-fin14": { e: "I need a quote before we move forward.", t: "Necesito una cotización antes de avanzar.", s: "Al pedir un presupuesto a un proveedor.", sEn: "When asking a supplier for a price estimate.", n: "\"Quote\" = cotización; \"quotation\" es más formal.", nEn: "\"Quote\" is an estimate; \"quotation\" is more formal." },
    "loc-fin15": { e: "The total includes tax and shipping.", t: "El total incluye impuesto y envío.", s: "Al aclarar qué cubre un precio.", sEn: "When clarifying what a price covers.", n: "\"Tax\" suele ir sin artículo al hablar en general.", nEn: "\"Tax\" usually has no article when speaking in general." },
    "loc-fin16": { e: "Can you bill the company directly?", t: "¿Pueden facturar a la empresa directamente?", s: "Al pedir factura a nombre de la empresa.", sEn: "When asking to invoice the company.", n: "\"Bill\" como verbo = facturar/cobrar.", nEn: "\"Bill\" as a verb means to invoice/charge." },
    "loc-fin17": { e: "The refund takes about five business days.", t: "El reembolso tarda unos cinco días hábiles.", s: "Al explicar plazos de devolución de dinero.", sEn: "When explaining refund timelines.", n: "\"Business days\" = días hábiles, sin fines de semana.", nEn: "\"Business days\" are weekdays, excluding weekends." },
    "loc-fin18": { e: "Good news — the budget was approved.", t: "Buenas noticias: el presupuesto fue aprobado.", s: "Al comunicar la aprobación de fondos.", sEn: "When announcing that funds were approved.", n: "\"Approved\" se dice \"a-PRÚVD\".", nEn: "\"Approved\" is said \"uh-PROOVD\"." },
    // --- negociacion ---
    "loc-neg13": { e: "What's your best price if I order today?", t: "¿Cuál es su mejor precio si pido hoy?", s: "Al negociar antes de cerrar una compra.", sEn: "When negotiating before closing a purchase.", n: "\"Best price\" invita a un descuento sin presionar.", nEn: "\"Best price\" invites a discount without pressure." },
    "loc-neg14": { e: "Is there any room to negotiate on the bulk order?", t: "¿Hay margen para negociar en el pedido grande?", s: "Al tantear si el precio o las condiciones son flexibles.", sEn: "When testing whether the price or terms are flexible.", n: "\"Room to negotiate\" = margen/espacio para negociar.", nEn: "\"Room to negotiate\" means flexibility to negotiate." },
    "loc-neg15": { e: "It's a bit pricey for me — any flexibility?", t: "Es un poco caro para mí, ¿hay flexibilidad?", s: "Al pedir un mejor precio con cortesía.", sEn: "When politely asking for a better price.", n: "\"Pricey\" es informal para \"caro\".", nEn: "\"Pricey\" is an informal word for \"expensive\"." },
    "loc-neg16": { e: "Is there a bulk discount for large orders?", t: "¿Hay descuento por volumen para pedidos grandes?", s: "Al preguntar por rebajas por cantidad.", sEn: "When asking about quantity discounts.", n: "\"Bulk\" = al por mayor/en volumen.", nEn: "\"Bulk\" means in large quantity/wholesale." },
    "loc-neg17": { e: "Great, let's close the deal.", t: "Perfecto, cerremos el trato.", s: "Al confirmar un acuerdo.", sEn: "When confirming an agreement.", n: "\"Close the deal\" = cerrar/finalizar el trato.", nEn: "\"Close the deal\" means to finalize the agreement." },
    "loc-neg18": { e: "I'll think about it and get back to you.", t: "Lo pensaré y te aviso.", s: "Al no decidir de inmediato.", sEn: "When not deciding right away.", n: "\"Get back to you\" = darte una respuesta luego.", nEn: "\"Get back to you\" means to reply later." },
    // --- videocall-en ---
    "loc-vc13": { e: "I can barely hear you — turn the volume up a bit.", t: "Apenas te oigo, sube un poco el volumen.", s: "Cuando el audio se oye bajo.", sEn: "When the audio is too quiet.", n: "\"Turn up\" = subir; \"turn down\" = bajar.", nEn: "\"Turn up\" means raise; \"turn down\" means lower." },
    "loc-vc14": { e: "Can you turn on your camera, please?", t: "¿Puedes activar la cámara, por favor?", s: "Al pedir que enciendan el video.", sEn: "When asking someone to turn their video on.", n: "\"Turn on/off\" para cámara, micrófono y luces.", nEn: "\"Turn on/off\" for camera, mic and lights." },
    "loc-vc15": { e: "Could you share your screen so we can see it?", t: "¿Podrías compartir tu pantalla para verla?", s: "Al pedir que muestren algo en la llamada.", sEn: "When asking someone to show something on the call.", n: "\"Share your screen\" es la frase estándar.", nEn: "\"Share your screen\" is the standard phrase." },
    "loc-vc16": { e: "Your video froze for a second there.", t: "Tu video se congeló por un momento.", s: "Cuando la imagen se queda fija por mala conexión.", sEn: "When the picture freezes due to a bad connection.", n: "\"Froze\" es el pasado de \"freeze\" (congelar).", nEn: "\"Froze\" is the past of \"freeze\"." },
    "loc-vc17": { e: "Can you see the slides okay, or should I zoom in?", t: "¿Se ven bien las diapositivas, o las acerco?", s: "Al compartir una presentación.", sEn: "When sharing a presentation.", n: "\"Slides\" = diapositivas.", nEn: "\"Slides\" are the presentation pages." },
    "loc-vc18": { e: "I'll record the meeting and share it later.", t: "Voy a grabar la reunión y la comparto después.", s: "Al avisar que se grabará la sesión.", sEn: "When letting people know the session is recorded.", n: "Avisar antes de grabar es buena práctica.", nEn: "Telling people before recording is good practice." },
    // ===================== Thema-Erweiterung (EXP_CARDS) =====================
    // --- meseros ---
    "loc-mes17": { e: "If you'd like, I can recommend something light before the main course.", t: "Si gusta, puedo recomendarle algo ligero antes del plato fuerte.", s: "Cuando el cliente no sabe qué pedir de entrada.", sEn: "When the guest isn't sure what to order to start.", n: "\"Main course\" es el plato principal; \"starter\" o \"appetizer\" es la entrada.", nEn: "\"Main course\" is the main dish; \"starter\" or \"appetizer\" is the first course." },
    "loc-mes18": { e: "I would have brought your dish sooner, but the kitchen was swamped.", t: "Le habría traído el plato antes, pero la cocina estaba llena.", s: "Cuando te disculpas por una demora con la comida.", sEn: "When you apologize for a delay with the food.", n: "\"Swamped\" significa muy ocupado; suena natural y amable.", nEn: "\"Swamped\" means very busy; it sounds natural and friendly." },
    "loc-mes19": { e: "If you're in a hurry, I can ask the kitchen to prepare something quick.", t: "Si tiene prisa, puedo pedir que le preparen algo rápido.", s: "Cuando el cliente parece tener prisa.", sEn: "When the guest seems to be in a hurry.", n: "\"In a hurry\" se dice mucho más que \"with hurry\".", nEn: "\"In a hurry\" is used much more than \"with hurry\"." },
    "loc-mes20": { e: "Since it's your first time with us, the appetizer is on the house.", t: "Como es la primera vez que nos visita, le invito un aperitivo.", s: "Cuando quieres dar la bienvenida a un cliente nuevo.", sEn: "When you want to welcome a new guest.", n: "\"On the house\" significa que es cortesía, gratis.", nEn: "\"On the house\" means it's complimentary, free." },
    "loc-mes21": { e: "Would you like more bread while you wait?", t: "¿Le sirvo más pan mientras espera?", s: "Cuando la comida se está demorando.", sEn: "When the food is taking a while.", n: "Ofrecer algo durante la espera mejora la experiencia.", nEn: "Offering something during the wait improves the experience." },
    "loc-mes22": { e: "Would you like me to split the bill?", t: "¿Prefiere que le separe la cuenta?", s: "Cuando varias personas pagan por separado.", sEn: "When several people are paying separately.", n: "\"Split the bill\" es la frase normal para dividir la cuenta.", nEn: "\"Split the bill\" is the normal phrase for dividing the check." },
    "loc-mes23": { e: "Here are your utensils.", t: "Aquí tiene sus cubiertos.", s: "Al poner cubiertos en la mesa.", sEn: "When setting cutlery on the table.", n: "\"Utensils\" o \"cutlery\"; en EE. UU. se usa más \"silverware\".", nEn: "\"Utensils\" or \"cutlery\"; in the US \"silverware\" is common." },
    "loc-mes24": { e: "Can I take your plate?", t: "¿Le retiro el plato?", s: "Cuando el cliente terminó de comer.", sEn: "When the guest has finished eating.", n: "Es más cortés preguntar antes de retirar el plato.", nEn: "It's more polite to ask before clearing the plate." },
    // --- recepcion ---
    "loc-rec17": { e: "If your flight arrives late, we can hold your room until midnight.", t: "Si su vuelo llega tarde, podemos guardarle la habitación hasta medianoche.", s: "Cuando un huésped avisa que llegará tarde.", sEn: "When a guest says they'll arrive late.", n: "\"Hold your room\" significa reservarla sin darla a otro.", nEn: "\"Hold your room\" means keep it reserved for them." },
    "loc-rec18": { e: "I've noted that you'd prefer a quiet room away from the elevator.", t: "He anotado que prefiere una habitación tranquila lejos del ascensor.", s: "Cuando registras una preferencia del huésped.", sEn: "When you record a guest's preference.", n: "\"I've noted\" muestra atención al detalle.", nEn: "\"I've noted\" shows attention to detail." },
    "loc-rec19": { e: "Should you need anything during the night, just dial zero.", t: "En caso de que necesite algo durante la noche, marque el cero.", s: "Al explicar cómo pedir ayuda de noche.", sEn: "When explaining how to get help at night.", n: "\"Should you need\" es una forma formal y elegante de \"if you need\".", nEn: "\"Should you need\" is a formal, elegant way to say \"if you need\"." },
    "loc-rec20": { e: "We would have given you a room with a view, but they were already booked.", t: "Le habríamos dado una habitación con vista, pero ya estaban reservadas.", s: "Cuando no puedes cumplir una solicitud por falta de disponibilidad.", sEn: "When you can't meet a request due to availability.", n: "\"Already booked\" significa que ya estaban reservadas.", nEn: "\"Already booked\" means they were already reserved." },
    "loc-rec21": { e: "Would you like a wake-up call?", t: "¿Le gustaría que le despierten por teléfono?", s: "Al ofrecer un servicio de despertar.", sEn: "When offering a wake-up service.", n: "\"Wake-up call\" es la llamada del hotel para despertar.", nEn: "\"Wake-up call\" is the hotel's call to wake you up." },
    "loc-rec22": { e: "You can set the safe with your own code.", t: "Puede dejar la caja fuerte con su propia clave.", s: "Al explicar la caja fuerte de la habitación.", sEn: "When explaining the in-room safe.", n: "\"Safe\" es la caja fuerte; \"code\" es la clave.", nEn: "\"Safe\" is the strongbox; \"code\" is the PIN." },
    "loc-rec23": { e: "Your room is ready.", t: "Su habitación ya está lista.", s: "Cuando la habitación queda lista para entrar.", sEn: "When the room is ready to check in.", n: "Frase corta y muy útil al recibir huéspedes.", nEn: "Short, very useful phrase when receiving guests." },
    "loc-rec24": { e: "Here's a map of the city.", t: "Aquí tiene el mapa de la ciudad.", s: "Al orientar a un huésped que sale a pasear.", sEn: "When helping a guest heading out to explore.", n: "Acompáñalo señalando el hotel en el mapa.", nEn: "Point out the hotel on the map as you hand it over." },
    // --- guias ---
    "loc-gui17": { e: "If you look up, you'll see that the ceiling was painted by hand centuries ago.", t: "Si miran hacia arriba, verán que el techo fue pintado a mano hace siglos.", s: "Al señalar un detalle del techo de un edificio histórico.", sEn: "When pointing out a ceiling detail in a historic building.", n: "\"Centuries ago\" significa hace siglos.", nEn: "\"Centuries ago\" means hundreds of years in the past." },
    "loc-gui18": { e: "Even though it looks far, we'll get there on foot in about ten minutes.", t: "Aunque parezca lejos, llegaremos caminando en unos diez minutos.", s: "Cuando el grupo cree que el destino está lejos.", sEn: "When the group thinks the destination is far.", n: "\"On foot\" significa caminando.", nEn: "\"On foot\" means walking." },
    "loc-gui19": { e: "Anyone who wants to stay longer can catch up with us at the square.", t: "Quien quiera quedarse más tiempo aquí puede alcanzarnos en la plaza.", s: "Al dar libertad para detenerse y luego reunirse.", sEn: "When letting people linger and rejoin later.", n: "\"Catch up with us\" significa alcanzarnos.", nEn: "\"Catch up with us\" means to rejoin the group." },
    "loc-gui20": { e: "This church has been restored several times after the earthquakes.", t: "Esta iglesia ha sido restaurada varias veces después de los terremotos.", s: "Al contar la historia de un edificio.", sEn: "When telling the history of a building.", n: "\"Has been restored\" es presente perfecto pasivo.", nEn: "\"Has been restored\" is the present perfect passive." },
    "loc-gui21": { e: "Please turn off your flash inside the temple.", t: "Por favor, apaguen el flash dentro del templo.", s: "Al entrar a un lugar donde no se permite flash.", sEn: "When entering a place where flash isn't allowed.", n: "\"Turn off\" significa apagar.", nEn: "\"Turn off\" means to switch off." },
    "loc-gui22": { e: "The next stop is just around the corner.", t: "El próximo punto está justo a la vuelta.", s: "Al avanzar hacia la siguiente parada.", sEn: "When moving to the next stop.", n: "\"Around the corner\" significa a la vuelta, muy cerca.", nEn: "\"Around the corner\" means very close by." },
    "loc-gui23": { e: "This is the oldest part of the city.", t: "Esto es lo más antiguo de la ciudad.", s: "Al llegar al casco histórico.", sEn: "When arriving at the historic center.", n: "\"Oldest\" es el superlativo de \"old\".", nEn: "\"Oldest\" is the superlative of \"old\"." },
    "loc-gui24": { e: "Let's start the tour.", t: "Vamos a empezar el recorrido.", s: "Al iniciar la visita con el grupo.", sEn: "When beginning the visit with the group.", n: "\"Let's\" es la forma corta de \"let us\", para invitar a hacer algo juntos.", nEn: "\"Let's\" is short for \"let us\", inviting the group to act together." },
    // --- taxi-en ---
    "loc-tax15": { e: "If you don't mind, I can take a shortcut to avoid the traffic.", t: "Si no le importa, puedo tomar un atajo para evitar el tráfico.", s: "Cuando hay tráfico y conoces una ruta más rápida.", sEn: "When there's traffic and you know a faster route.", n: "\"Shortcut\" es un atajo.", nEn: "\"Shortcut\" is a quicker alternate route." },
    "loc-tax16": { e: "I would have charged you less, but the night rate is higher.", t: "Le habría cobrado menos, pero la tarifa nocturna es más alta.", s: "Al explicar por qué la tarifa es mayor de noche.", sEn: "When explaining a higher night fare.", n: "\"Night rate\" es la tarifa nocturna.", nEn: "\"Night rate\" is the nighttime fare." },
    "loc-tax17": { e: "As soon as we cross the bridge, the road clears up.", t: "En cuanto pasemos el puente, el camino se despeja.", s: "Al tranquilizar al pasajero sobre el tráfico.", sEn: "When reassuring the passenger about traffic.", n: "\"Clears up\" significa que el tráfico disminuye.", nEn: "\"Clears up\" means traffic eases." },
    "loc-tax18": { e: "If you want, I can wait for you and drive you back to the hotel.", t: "Si quiere, puedo esperarlo y llevarlo de vuelta al hotel.", s: "Cuando el pasajero hará una parada corta.", sEn: "When the passenger will make a quick stop.", n: "\"Drive you back\" significa llevarlo de regreso.", nEn: "\"Drive you back\" means take you back." },
    "loc-tax19": { e: "Do you mind if I take the highway?", t: "¿Le importa si tomo la autopista?", s: "Antes de elegir una ruta más rápida.", sEn: "Before choosing a faster route.", n: "\"Do you mind if...\" es una forma cortés de pedir permiso.", nEn: "\"Do you mind if...\" is a polite way to ask permission." },
    "loc-tax20": { e: "Would you like me to put on some music?", t: "¿Quiere que ponga música?", s: "Para hacer el viaje más agradable.", sEn: "To make the ride more pleasant.", n: "\"Put on\" significa poner o encender.", nEn: "\"Put on\" means to play or turn on." },
    "loc-tax21": { e: "The airport is half an hour from here.", t: "El aeropuerto queda a media hora de aquí.", s: "Al informar el tiempo del viaje.", sEn: "When telling the travel time.", n: "\"Half an hour\" significa media hora.", nEn: "\"Half an hour\" means thirty minutes." },
    "loc-tax22": { e: "What's the address?", t: "¿Cuál es la dirección?", s: "Al pedir el destino exacto.", sEn: "When asking for the exact destination.", n: "\"Address\" se pronuncia con el acento variable; aquí \"a-DRES\".", nEn: "\"Address\" stress can vary; here \"a-DRES\"." },
    "loc-tax23": { e: "Right here is fine.", t: "Aquí está bien.", s: "Cuando el pasajero indica dónde bajarse.", sEn: "When the passenger indicates where to get off.", n: "Lo dice el pasajero, pero el taxista debe entenderlo.", nEn: "The passenger says this; the driver should understand it." },
    "loc-tax24": { e: "Do you need a receipt?", t: "¿Necesita un recibo?", s: "Al terminar el viaje y cobrar.", sEn: "When finishing the ride and charging.", n: "\"Receipt\" tiene la \"p\" muda: \"ri-SÍT\".", nEn: "\"Receipt\" has a silent \"p\": \"ri-SÍT\"." },
    // --- ventas ---
    "loc-ven15": { e: "If you take two, I can give you the third one at half price.", t: "Si lleva dos, le puedo dejar el tercero a mitad de precio.", s: "Al ofrecer una promoción por cantidad.", sEn: "When offering a bulk deal.", n: "\"Half price\" significa a mitad de precio.", nEn: "\"Half price\" means fifty percent off." },
    "loc-ven16": { e: "I would have given you a better price, but it's already on sale.", t: "Le habría hecho un mejor precio, pero ya está rebajado.", s: "Cuando el cliente pide más descuento.", sEn: "When the customer asks for a bigger discount.", n: "\"On sale\" significa en oferta o rebajado.", nEn: "\"On sale\" means discounted." },
    "loc-ven17": { e: "If it doesn't fit, you can exchange it within the next three days.", t: "Si no le queda bien, puede cambiarlo en los próximos tres días.", s: "Al explicar la política de cambios.", sEn: "When explaining the exchange policy.", n: "\"Exchange\" es cambiar el producto; \"refund\" es devolver el dinero.", nEn: "\"Exchange\" swaps the item; \"refund\" returns the money." },
    "loc-ven18": { e: "This one is woven by the women in the village, that's what makes it special.", t: "Este lo tejen las mujeres del pueblo, por eso es tan especial.", s: "Al destacar el valor de un producto artesanal.", sEn: "When highlighting a handmade product's value.", n: "\"Woven\" es el participio de \"weave\" (tejer).", nEn: "\"Woven\" is the past participle of \"weave\"." },
    "loc-ven19": { e: "Would you like me to hold it while you keep looking?", t: "¿Quiere que se lo aparte mientras sigue mirando?", s: "Cuando el cliente quiere seguir mirando.", sEn: "When the customer wants to keep browsing.", n: "\"Hold it\" aquí significa apartarlo, no sujetarlo.", nEn: "\"Hold it\" here means set it aside for them." },
    "loc-ven20": { e: "I take cards too.", t: "Acepto tarjeta también.", s: "Cuando el cliente pregunta cómo pagar.", sEn: "When the customer asks how to pay.", n: "\"I take cards\" significa que acepta tarjetas.", nEn: "\"I take cards\" means cards are accepted." },
    "loc-ven21": { e: "I'll give you a bag to carry it.", t: "Le doy una bolsa para que lo lleve.", s: "Al entregar la compra.", sEn: "When handing over the purchase.", n: "\"Carry\" significa cargar o llevar.", nEn: "\"Carry\" means to take or hold while moving." },
    "loc-ven22": { e: "How much do you want to spend?", t: "¿Cuánto quiere gastar?", s: "Para ayudar al cliente según su presupuesto.", sEn: "To help the customer based on their budget.", n: "\"Spend\" significa gastar dinero.", nEn: "\"Spend\" means to use money." },
    "loc-ven23": { e: "It's very cheap.", t: "Es muy barato.", s: "Al resaltar un buen precio.", sEn: "When emphasizing a good price.", n: "\"Cheap\" es barato; \"affordable\" suena más fino.", nEn: "\"Cheap\" is inexpensive; \"affordable\" sounds nicer." },
    "loc-ven24": { e: "Look, feel the fabric.", t: "Mire, toque la tela.", s: "Al invitar al cliente a probar la calidad.", sEn: "When inviting the customer to feel the quality.", n: "\"Fabric\" es la tela o el material.", nEn: "\"Fabric\" is the cloth or material." },
    // --- bar-en ---
    "loc-bar15": { e: "If you tell me what flavors you like, I'll mix something just for you.", t: "Si me dice qué sabores le gustan, le preparo algo a su medida.", s: "Cuando el cliente no sabe qué cóctel pedir.", sEn: "When the guest isn't sure which cocktail to order.", n: "\"Mix\" se usa para preparar tragos.", nEn: "\"Mix\" is used for preparing drinks." },
    "loc-bar16": { e: "I would have poured you another, but we've already closed the bar.", t: "Le habría servido otra, pero ya cerramos la barra.", s: "Al final de la noche, cuando ya no se sirve.", sEn: "At the end of the night, when service has ended.", n: "\"Poured\" es el pasado de \"pour\" (servir).", nEn: "\"Poured\" is the past of \"pour\"." },
    "loc-bar17": { e: "If you're going to drive, I'd recommend something non-alcoholic.", t: "Si va a manejar, le recomiendo algo sin alcohol.", s: "Cuando el cliente va a conducir luego.", sEn: "When the guest will be driving later.", n: "\"Non-alcoholic\" significa sin alcohol.", nEn: "\"Non-alcoholic\" means without alcohol." },
    "loc-bar18": { e: "This rum is from the region, you should try it neat first.", t: "Este ron es de la región, deberías probarlo solo primero.", s: "Al recomendar un licor local.", sEn: "When recommending a local spirit.", n: "\"Neat\" significa solo, sin hielo ni mezcla.", nEn: "\"Neat\" means straight, no ice or mixer." },
    "loc-bar19": { e: "Do you want it strong or light?", t: "¿Lo quiere fuerte o suave?", s: "Al preparar un trago a gusto del cliente.", sEn: "When making a drink to the guest's taste.", n: "\"Strong\" es cargado; \"light\" es suave.", nEn: "\"Strong\" is potent; \"light\" is mild." },
    "loc-bar20": { e: "Shall I add a slice of lime?", t: "¿Le pongo una rodaja de limón?", s: "Al servir un trago o agua.", sEn: "When serving a drink or water.", n: "\"Slice\" es una rodaja; \"lime\" es limón verde.", nEn: "\"Slice\" is a thin round piece; \"lime\" is the green citrus." },
    "loc-bar21": { e: "The tip isn't included.", t: "La propina no está incluida.", s: "Al entregar la cuenta.", sEn: "When handing over the bill.", n: "\"Tip\" es la propina; en muchos países es opcional.", nEn: "\"Tip\" is the gratuity; in many countries it's optional." },
    "loc-bar22": { e: "Which beer would you like?", t: "¿Qué cerveza prefiere?", s: "Cuando el cliente quiere una cerveza.", sEn: "When the guest wants a beer.", n: "\"Which\" se usa al elegir entre opciones.", nEn: "\"Which\" is used when choosing among options." },
    "loc-bar23": { e: "Coming right up.", t: "Ya se la traigo.", s: "Justo después de tomar un pedido.", sEn: "Right after taking an order.", n: "\"Coming right up\" es muy común en bares y restaurantes.", nEn: "\"Coming right up\" is very common in bars and restaurants." },
    "loc-bar24": { e: "Is it good?", t: "¿Está bueno?", s: "Al confirmar que el cliente disfruta su bebida.", sEn: "When checking the guest likes their drink.", n: "Pregunta sencilla para mostrar atención.", nEn: "A simple question to show you care." },
    // --- playa-en ---
    "loc-pla15": { e: "If you want to stay until sunset, I'll hold the chair for you all day.", t: "Si quiere quedarse hasta el atardecer, le guardo la silla todo el día.", s: "Al alquilar una silla por el día.", sEn: "When renting out a chair for the day.", n: "\"Sunset\" es el atardecer.", nEn: "\"Sunset\" is when the sun goes down." },
    "loc-pla16": { e: "I would have set the umbrella closer, but the wind is strong.", t: "Le habría puesto la sombrilla más cerca, pero el viento está fuerte.", s: "Al acomodar la sombrilla con viento.", sEn: "When setting up the umbrella in the wind.", n: "\"Set\" aquí significa colocar.", nEn: "\"Set\" here means to place." },
    "loc-pla17": { e: "If the flag is red, you shouldn't go in the water.", t: "Si la bandera está roja, no debería meterse al agua.", s: "Al advertir sobre las banderas de seguridad.", sEn: "When warning about safety flags.", n: "\"Shouldn't\" expresa una recomendación, no una orden.", nEn: "\"Shouldn't\" expresses advice, not a command." },
    "loc-pla18": { e: "Even though it looks calm, the current here can be dangerous.", t: "Aunque parezca tranquila, la corriente aquí puede ser peligrosa.", s: "Al advertir sobre corrientes marinas.", sEn: "When warning about sea currents.", n: "\"Current\" es la corriente del mar.", nEn: "\"Current\" is the flow of the sea." },
    "loc-pla19": { e: "Can I help you carry your things to the sand?", t: "¿Le ayudo a cargar las cosas hasta la arena?", s: "Al recibir a un cliente que llega con cosas.", sEn: "When greeting a guest arriving with belongings.", n: "\"Sand\" es la arena.", nEn: "\"Sand\" is the beach ground." },
    "loc-pla20": { e: "The beach restaurant stays open late.", t: "El restaurante de la playa abre hasta tarde.", s: "Al informar sobre opciones para comer.", sEn: "When informing about dining options.", n: "\"Stays open late\" significa que cierra tarde.", nEn: "\"Stays open late\" means it closes late." },
    "loc-pla21": { e: "Would you like to rent a board?", t: "¿Quiere alquilar una tabla?", s: "Al ofrecer alquiler de tabla de surf.", sEn: "When offering surfboard rental.", n: "\"Board\" puede ser tabla de surf o bodyboard.", nEn: "\"Board\" can be a surfboard or bodyboard." },
    "loc-pla22": { e: "The water is warm.", t: "El agua está tibia.", s: "Al invitar a meterse al mar.", sEn: "When inviting someone into the sea.", n: "\"Warm\" es tibio; \"hot\" es muy caliente.", nEn: "\"Warm\" is mildly warm; \"hot\" is very hot." },
    "loc-pla23": { e: "There's shade here.", t: "Aquí hay sombra.", s: "Al ofrecer un lugar fresco.", sEn: "When offering a cool spot.", n: "\"Shade\" es la sombra; \"shadow\" es la silueta.", nEn: "\"Shade\" is shelter from sun; \"shadow\" is the outline." },
    "loc-pla24": { e: "Enjoy the beach.", t: "Disfrute la playa.", s: "Al despedir a un cliente.", sEn: "When saying goodbye to a guest.", n: "\"Enjoy\" se pronuncia \"en-LLÓI\".", nEn: "\"Enjoy\" is pronounced \"en-LLÓI\"." },
    // --- quejas-en ---
    "loc-que15": { e: "I'm really sorry about what happened; let me see how I can fix it.", t: "Lamento mucho lo ocurrido; permítame ver cómo puedo arreglarlo.", s: "Al responder a una queja seria.", sEn: "When responding to a serious complaint.", n: "Reconocer y ofrecer solución calma al cliente.", nEn: "Acknowledging and offering a fix calms the guest." },
    "loc-que16": { e: "If you had told us earlier, we would have sorted it out right away.", t: "Si me hubiera avisado antes, lo habríamos solucionado de inmediato.", s: "Cuando el cliente se queja tarde de algo.", sEn: "When the guest complains late about something.", n: "Es un condicional del pasado (third conditional).", nEn: "This is a third conditional (past)." },
    "loc-que17": { e: "I understand you're upset, and I assure you we'll take it seriously.", t: "Entiendo que esté molesto y le aseguro que lo tomaremos en serio.", s: "Al calmar a un cliente enojado.", sEn: "When calming an angry guest.", n: "\"Upset\" es molesto o disgustado.", nEn: "\"Upset\" means annoyed or distressed." },
    "loc-que18": { e: "To make up for it, I'd like to offer you a free night.", t: "Para compensarlo, me gustaría ofrecerle una noche gratis.", s: "Al ofrecer una compensación.", sEn: "When offering compensation.", n: "\"Make up for it\" significa compensar.", nEn: "\"Make up for it\" means to compensate." },
    "loc-que19": { e: "I'll speak with the kitchen right now.", t: "Voy a hablar con la cocina ahora mismo.", s: "Cuando hay un problema con la comida.", sEn: "When there's an issue with the food.", n: "Mostrar acción inmediata genera confianza.", nEn: "Showing immediate action builds trust." },
    "loc-que20": { e: "I can move you to another room if you prefer.", t: "Le cambio la habitación si lo prefiere.", s: "Cuando hay un problema con la habitación.", sEn: "When there's a problem with the room.", n: "\"Move you\" significa cambiarlo de habitación.", nEn: "\"Move you\" means relocate you to another room." },
    "loc-que21": { e: "You're absolutely right.", t: "Tiene toda la razón.", s: "Al reconocer que el cliente tiene razón.", sEn: "When acknowledging the guest is right.", n: "\"Absolutely\" refuerza el acuerdo.", nEn: "\"Absolutely\" strongly reinforces agreement." },
    "loc-que22": { e: "Sorry for the trouble.", t: "Disculpe la molestia.", s: "Al disculparse por una incomodidad menor.", sEn: "When apologizing for a minor inconvenience.", n: "\"Trouble\" aquí significa molestia o inconveniente.", nEn: "\"Trouble\" here means inconvenience." },
    "loc-que23": { e: "I'll fix it now.", t: "Lo arreglo ya.", s: "Al resolver un problema de inmediato.", sEn: "When resolving a problem immediately.", n: "Frase corta que transmite acción rápida.", nEn: "A short phrase that conveys quick action." },
    "loc-que24": { e: "I'm sorry about that — let me make it up to you.", t: "Lamento eso; permítame compensarlo.", s: "Cuando quieres reparar un error con el cliente.", sEn: "When you want to make up for a mistake to the customer.", n: "\"Make it up to you\" = compensarte por un error.", nEn: "\"Make it up to you\" means to compensate someone for a mistake." },
    // --- platos-en ---
    "loc-pla-t15": { e: "If you've never tried it, I suggest starting with a small portion.", t: "Si nunca lo ha probado, le sugiero empezar con una porción pequeña.", s: "Al recomendar un plato nuevo para el cliente.", sEn: "When recommending a dish new to the guest.", n: "\"Portion\" es porción.", nEn: "\"Portion\" is a serving size." },
    "loc-pla-t16": { e: "This dish is slow-cooked for several hours.", t: "Este plato se cocina a fuego lento durante varias horas.", s: "Al describir cómo se prepara el plato.", sEn: "When describing how the dish is prepared.", n: "\"Slow-cooked\" significa cocido a fuego lento.", nEn: "\"Slow-cooked\" means cooked slowly over low heat." },
    "loc-pla-t17": { e: "Even though it looks simple, the recipe has been passed down for generations.", t: "Aunque se vea sencillo, la receta ha pasado de generación en generación.", s: "Al destacar la tradición de un plato.", sEn: "When highlighting a dish's tradition.", n: "\"Passed down\" significa transmitido de generación en generación.", nEn: "\"Passed down\" means handed from one generation to the next." },
    "loc-pla-t18": { e: "If you're allergic to peanuts, I should warn you the sauce has some.", t: "Si es alérgico al maní, le aviso que la salsa lleva un poco.", s: "Al avisar sobre un ingrediente alérgeno.", sEn: "When warning about an allergen.", n: "\"Peanuts\" es maní o cacahuate.", nEn: "\"Peanuts\" are groundnuts." },
    "loc-pla-t19": { e: "It's served piping hot.", t: "Se sirve bien caliente.", s: "Al advertir que el plato está muy caliente.", sEn: "When noting the dish is very hot.", n: "\"Piping hot\" significa muy caliente.", nEn: "\"Piping hot\" means very hot." },
    "loc-pla-t20": { e: "The dessert has raw cane sugar and cheese.", t: "El postre lleva panela y queso.", s: "Al describir un postre local.", sEn: "When describing a local dessert.", n: "\"Raw cane sugar\" es lo más cercano a \"panela\".", nEn: "\"Raw cane sugar\" is the closest to \"panela\"." },
    "loc-pla-t21": { e: "You can order it without spice if you prefer.", t: "Puede pedirlo sin picante si prefiere.", s: "Cuando el cliente no tolera el picante.", sEn: "When the guest can't handle spice.", n: "\"Spice\" aquí se refiere al picante.", nEn: "\"Spice\" here refers to heat/hotness." },
    "loc-pla-t22": { e: "It's made fresh today.", t: "Está hecho hoy.", s: "Al resaltar la frescura del plato.", sEn: "When highlighting the dish's freshness.", n: "\"Made fresh\" enfatiza que es del día.", nEn: "\"Made fresh\" emphasizes it's made the same day." },
    "loc-pla-t23": { e: "It's sweet.", t: "Es dulce.", s: "Al describir el sabor de un plato o postre.", sEn: "When describing the flavor of a dish or dessert.", n: "\"Sweet\" es dulce; \"savory\" es salado.", nEn: "\"Sweet\" is sugary; \"savory\" is salty/non-sweet." },
    "loc-pla-t24": { e: "Would you like the sauce on the side?", t: "¿Quiere salsa aparte?", s: "Al ofrecer la salsa por separado.", sEn: "When offering the sauce separately.", n: "\"On the side\" significa aparte, no encima.", nEn: "\"On the side\" means served separately." },
    // --- limpieza ---
    "loc-lim13": { e: "If you'd rather I didn't come in today, just let me know and I'll come back tomorrow.", t: "Si prefiere que no entre hoy, déjeme saber y vuelvo mañana.", s: "Al respetar la privacidad del huésped.", sEn: "When respecting the guest's privacy.", n: "\"I'd rather\" expresa preferencia educadamente.", nEn: "\"I'd rather\" expresses preference politely." },
    "loc-lim14": { e: "I would have finished sooner, but the room next door took longer.", t: "Habría terminado antes, pero el cuarto de al lado tardó más.", s: "Al disculparse por una demora.", sEn: "When apologizing for a delay.", n: "\"Next door\" significa de al lado.", nEn: "\"Next door\" means the adjacent room." },
    "loc-lim15": { e: "If you find anything out of place, please let me know.", t: "Si encuentra algo fuera de lugar, por favor avíseme.", s: "Tras limpiar, al ofrecer atención.", sEn: "After cleaning, offering to help further.", n: "\"Out of place\" significa fuera de su sitio.", nEn: "\"Out of place\" means not where it should be." },
    "loc-lim16": { e: "I've left extra towels in case you need them later.", t: "He dejado toallas extra por si las necesita más tarde.", s: "Al dejar artículos de más para el huésped.", sEn: "When leaving extra items for the guest.", n: "\"In case\" significa por si acaso.", nEn: "\"In case\" means just in case." },
    "loc-lim17": { e: "Would you like me to change the sheets today?", t: "¿Quiere que cambie las sábanas hoy?", s: "Al ofrecer cambio de ropa de cama.", sEn: "When offering to change the bedding.", n: "\"Sheets\" son las sábanas.", nEn: "\"Sheets\" are the bed linens." },
    "loc-lim18": { e: "I'll vacuum the carpet quickly.", t: "Voy a aspirar la alfombra rápido.", s: "Al limpiar la habitación.", sEn: "When cleaning the room.", n: "\"Vacuum\" es aspirar; \"carpet\" es la alfombra.", nEn: "\"Vacuum\" is to hoover; \"carpet\" is the rug/floor covering." },
    "loc-lim19": { e: "Shall I take out the trash?", t: "¿Le saco la basura?", s: "Al ofrecer retirar la basura.", sEn: "When offering to remove the trash.", n: "\"Trash\" (EE. UU.) o \"rubbish\" (UK).", nEn: "\"Trash\" (US) or \"rubbish\" (UK)." },
    "loc-lim20": { e: "I've made up the room for you.", t: "Dejé el cuarto listo para usted.", s: "Al terminar de arreglar la habitación.", sEn: "When finishing tidying the room.", n: "\"Make up the room\" significa arreglar y dejar lista la habitación.", nEn: "\"Make up the room\" means tidy and ready the room." },
    "loc-lim21": { e: "Shall I open the curtains?", t: "¿Le abro las cortinas?", s: "Al arreglar la habitación por la mañana.", sEn: "When tidying the room in the morning.", n: "\"Curtains\" son las cortinas.", nEn: "\"Curtains\" are the window drapes." },
    "loc-lim22": { e: "Here are more pillows.", t: "Aquí hay más almohadas.", s: "Al traer artículos extra solicitados.", sEn: "When bringing extra requested items.", n: "\"Pillows\" son las almohadas.", nEn: "\"Pillows\" are the cushions for the head." },
    "loc-lim23": { e: "The room is clean.", t: "El cuarto está limpio.", s: "Al confirmar que terminó la limpieza.", sEn: "When confirming the cleaning is done.", n: "Frase simple y útil para reportar el trabajo.", nEn: "A simple, useful phrase to report the work." },
    "loc-lim24": { e: "Do you need anything else?", t: "¿Necesita algo más?", s: "Antes de salir de la habitación.", sEn: "Before leaving the room.", n: "\"Anything else\" cierra la atención cortésmente.", nEn: "\"Anything else\" closes the service politely." },
    // --- spa-en ---
    "loc-spa13": { e: "If you feel too much pressure at any point, tell me and I'll ease off.", t: "Si siente demasiada presión en algún momento, dígame y la bajo.", s: "Durante el masaje, para ajustar la fuerza.", sEn: "During the massage, to adjust the pressure.", n: "\"Ease off\" significa bajar la intensidad.", nEn: "\"Ease off\" means reduce the intensity." },
    "loc-spa14": { e: "I'd recommend taking a few minutes before you get up.", t: "Le recomendaría tomarse unos minutos antes de levantarse.", s: "Al terminar el masaje.", sEn: "When the massage ends.", n: "\"Get up\" significa levantarse.", nEn: "\"Get up\" means to stand/rise." },
    "loc-spa15": { e: "Since you've got tension in your back, I'll focus there.", t: "Como tiene tensión en la espalda, me enfocaré ahí.", s: "Al detectar tensión en una zona.", sEn: "When noticing tension in an area.", n: "\"Tension\" es la tensión muscular.", nEn: "\"Tension\" is muscle tightness." },
    "loc-spa16": { e: "If I had known about your injury, I would have used less force.", t: "Si hubiera sabido de su lesión, habría usado menos fuerza.", s: "Si el cliente menciona una lesión después.", sEn: "If the guest mentions an injury afterward.", n: "Condicional del pasado para algo que ya no se puede cambiar.", nEn: "Past conditional for something that can't be changed now." },
    "loc-spa17": { e: "Would you like warm towels?", t: "¿Le caliento las toallas?", s: "Al ofrecer un servicio extra durante el spa.", sEn: "When offering an extra during the spa.", n: "\"Warm towels\" son toallas calientes.", nEn: "\"Warm towels\" are heated towels." },
    "loc-spa18": { e: "I'll be using almond oil.", t: "Voy a usar aceite de almendras.", s: "Antes de empezar el masaje.", sEn: "Before starting the massage.", n: "La \"l\" de \"almond\" suele ser muda: \"Á-mond\".", nEn: "The \"l\" in \"almond\" is often silent: \"Á-mond\"." },
    "loc-spa19": { e: "Take off your shoes and put on the robe.", t: "Quítese los zapatos y póngase la bata.", s: "Al preparar al cliente para el tratamiento.", sEn: "When preparing the guest for the treatment.", n: "\"Robe\" es la bata.", nEn: "\"Robe\" is the bathrobe." },
    "loc-spa20": { e: "Would you prefer soft music?", t: "¿Prefiere música suave?", s: "Al ambientar la sala.", sEn: "When setting the mood in the room.", n: "\"Soft music\" es música suave o relajante.", nEn: "\"Soft music\" is gentle, relaxing music." },
    "loc-spa21": { e: "Close your eyes.", t: "Cierre los ojos.", s: "Para ayudar al cliente a relajarse.", sEn: "To help the guest relax.", n: "\"Eyes\" se pronuncia \"ais\".", nEn: "\"Eyes\" is pronounced \"ais\"." },
    "loc-spa22": { e: "How do you feel?", t: "¿Cómo se siente?", s: "Durante o después del tratamiento.", sEn: "During or after the treatment.", n: "\"Feel\" significa sentirse.", nEn: "\"Feel\" means to feel/sense." },
    "loc-spa23": { e: "Here is some water.", t: "Aquí tiene agua.", s: "Al ofrecer agua tras el masaje.", sEn: "When offering water after the massage.", n: "Beber agua ayuda tras un masaje.", nEn: "Drinking water helps after a massage." },
    "loc-spa24": { e: "We're almost done.", t: "Ya casi terminamos.", s: "Cerca del final del tratamiento.", sEn: "Near the end of the treatment.", n: "\"Almost done\" significa casi terminado.", nEn: "\"Almost done\" means nearly finished." },
    // --- lancha-en ---
    "loc-lan13": { e: "If anyone gets seasick, let me know and we'll head to shore.", t: "Si alguien se marea, avíseme y nos acercamos a la orilla.", s: "Al inicio del paseo en lancha.", sEn: "At the start of the boat trip.", n: "\"Seasick\" es mareado por el mar.", nEn: "\"Seasick\" means nauseous from the sea." },
    "loc-lan14": { e: "We would have left earlier, but we had to wait for the coast guard.", t: "Habríamos salido antes, pero tuvimos que esperar a la guardia costera.", s: "Al explicar una demora en la salida.", sEn: "When explaining a delayed departure.", n: "\"Coast guard\" es la guardia costera.", nEn: "\"Coast guard\" is the maritime authority." },
    "loc-lan15": { e: "Since the sea is calm, we'll reach the island faster.", t: "Como el mar está calmado, llegaremos a la isla más rápido.", s: "Cuando el mar está tranquilo.", sEn: "When the sea is calm.", n: "\"Calm\" se pronuncia \"cam\", con la \"l\" muda.", nEn: "\"Calm\" is pronounced \"cam\", with a silent \"l\"." },
    "loc-lan16": { e: "If you want to take photos, this is the best spot for it.", t: "Si quieren tomar fotos, este es el mejor lugar para hacerlo.", s: "Al pasar por un punto panorámico.", sEn: "When passing a scenic point.", n: "\"Spot\" significa lugar o punto.", nEn: "\"Spot\" means a place or point." },
    "loc-lan17": { e: "Keep your hands inside the boat.", t: "Mantengan las manos dentro del bote.", s: "Por seguridad durante el paseo.", sEn: "For safety during the ride.", n: "\"Inside\" significa adentro.", nEn: "\"Inside\" means within." },
    "loc-lan18": { e: "We're going to stop to watch dolphins.", t: "Vamos a parar a ver delfines.", s: "Al avistar fauna marina.", sEn: "When spotting marine wildlife.", n: "\"Dolphins\" son los delfines.", nEn: "\"Dolphins\" are the sea mammals." },
    "loc-lan19": { e: "Put your phones away safely.", t: "Guarden bien sus celulares.", s: "Antes de un tramo con olas.", sEn: "Before a rough stretch.", n: "\"Put away\" significa guardar.", nEn: "\"Put away\" means to store/stow." },
    "loc-lan20": { e: "The trip takes about forty minutes.", t: "El viaje dura unos cuarenta minutos.", s: "Al informar la duración del trayecto.", sEn: "When telling the trip's duration.", n: "\"Takes about\" significa dura aproximadamente.", nEn: "\"Takes about\" means lasts roughly." },
    "loc-lan21": { e: "Get on carefully.", t: "Suban con cuidado.", s: "Al abordar la lancha.", sEn: "When boarding the boat.", n: "\"Get on\" significa subir a un bote o vehículo.", nEn: "\"Get on\" means to board a boat or vehicle." },
    "loc-lan22": { e: "The water is clear.", t: "El agua es clara.", s: "Al destacar la belleza del lugar.", sEn: "When highlighting the spot's beauty.", n: "\"Clear\" significa transparente o cristalina.", nEn: "\"Clear\" means transparent." },
    "loc-lan23": { e: "Is everyone ready?", t: "¿Todos listos?", s: "Antes de zarpar.", sEn: "Before setting off.", n: "\"Everyone\" se pronuncia \"É-vri-uan\".", nEn: "\"Everyone\" is pronounced \"É-vri-uan\"." },
    "loc-lan24": { e: "Hold on tight.", t: "Agárrense fuerte.", s: "Antes de acelerar o pasar olas.", sEn: "Before speeding up or hitting waves.", n: "\"Hold on tight\" significa sujetarse fuerte.", nEn: "\"Hold on tight\" means grip firmly." },
    // --- checkout-en ---
    "loc-cko13": { e: "If you need to leave later, I can request a late check-out.", t: "Si necesita salir más tarde, puedo solicitar un check-out tardío.", s: "Cuando el huésped quiere salir más tarde.", sEn: "When the guest wants to leave later.", n: "\"Late check-out\" es salida tardía, a veces con costo.", nEn: "\"Late check-out\" is a later departure, sometimes for a fee." },
    "loc-cko14": { e: "I would have charged you for the extra night, but I see you're leaving on time.", t: "Le habría cobrado la noche extra, pero veo que se va a tiempo.", s: "Al revisar la cuenta de salida.", sEn: "When reviewing the checkout bill.", n: "\"On time\" significa a tiempo.", nEn: "\"On time\" means punctually." },
    "loc-cko15": { e: "Once I check the charge, I'll email you the receipt.", t: "Una vez que revise el cargo, le envío el recibo por correo.", s: "Al procesar el pago final.", sEn: "When processing the final payment.", n: "\"Charge\" es el cargo; \"receipt\" es el recibo.", nEn: "\"Charge\" is the amount billed; \"receipt\" is the proof." },
    "loc-cko16": { e: "If we find anything in your room, where should we send it?", t: "Si encontramos algo en su cuarto, ¿a dónde se lo enviamos?", s: "Cuando el huésped pudo olvidar algo.", sEn: "When the guest may have left something.", n: "Es buena práctica pedir una dirección de contacto.", nEn: "It's good practice to ask for a contact address." },
    "loc-cko17": { e: "Would you like me to add the tip to the bill?", t: "¿Quiere que le sume la propina a la cuenta?", s: "Al cerrar la cuenta.", sEn: "When closing out the bill.", n: "\"Add to the bill\" significa cargar a la cuenta.", nEn: "\"Add to the bill\" means charge to the account." },
    "loc-cko18": { e: "I'll check that nothing's missing.", t: "Voy a revisar que no falte nada.", s: "Antes de cerrar el check-out.", sEn: "Before finalizing the checkout.", n: "\"Missing\" significa que falta.", nEn: "\"Missing\" means absent/not there." },
    "loc-cko19": { e: "What time should I order the taxi for?", t: "¿Le pido el taxi para qué hora?", s: "Al organizar el transporte de salida.", sEn: "When arranging departure transport.", n: "\"Order the taxi for\" indica la hora deseada.", nEn: "\"Order the taxi for\" indicates the desired time." },
    "loc-cko20": { e: "The charge will appear on your card in a few days.", t: "El cargo aparecerá en su tarjeta en unos días.", s: "Al explicar el cobro con tarjeta.", sEn: "When explaining a card charge.", n: "\"Appear on your card\" significa reflejarse en el estado de cuenta.", nEn: "\"Appear on your card\" means show on your statement." },
    "loc-cko21": { e: "May I have the key back?", t: "¿Me devuelve la llave?", s: "Al pedir la llave de la habitación.", sEn: "When asking for the room key back.", n: "\"May I have\" es muy cortés.", nEn: "\"May I have\" is very polite." },
    "loc-cko22": { e: "Here is your receipt.", t: "Aquí tiene su recibo.", s: "Al entregar el comprobante de pago.", sEn: "When handing over the payment receipt.", n: "\"Receipt\" tiene la \"p\" muda.", nEn: "\"Receipt\" has a silent \"p\"." },
    "loc-cko23": { e: "Is everything in order?", t: "¿Todo en orden?", s: "Al confirmar que todo está correcto.", sEn: "When confirming everything is correct.", n: "\"In order\" significa en orden, correcto.", nEn: "\"In order\" means correct/settled." },
    "loc-cko24": { e: "It was a pleasure having you — safe travels!", t: "Fue un placer atenderle, ¡buen viaje!", s: "Al despedir al huésped en el check-out.", sEn: "When saying goodbye to the guest at check-out.", n: "\"Having you\" aquí significa tenerle como huésped.", nEn: "\"Having you\" here means hosting you as a guest." },
    // --- buceo-en ---
    "loc-buc13": { e: "If you feel pressure in your ears, go up a little and equalize again.", t: "Si sienten presión en los oídos, suban un poco y vuelvan a igualar.", s: "Durante el descenso bajo el agua.", sEn: "During the descent underwater.", n: "\"Equalize\" es igualar la presión de los oídos.", nEn: "\"Equalize\" means balance the pressure in your ears." },
    "loc-buc14": { e: "Before we get in the water, we'll check all the gear together.", t: "Antes de entrar al agua, revisaremos todo el equipo juntos.", s: "En el briefing antes de bucear.", sEn: "In the briefing before diving.", n: "\"Gear\" es el equipo de buceo.", nEn: "\"Gear\" is the diving equipment." },
    "loc-buc15": { e: "If your mask fills with water, don't worry, I'll show you how to clear it.", t: "Si se les llena la máscara de agua, no se preocupen, les enseño a vaciarla.", s: "Al enseñar a los principiantes.", sEn: "When teaching beginners.", n: "\"Clear it\" significa vaciar la máscara.", nEn: "\"Clear it\" means empty the water from the mask." },
    "loc-buc16": { e: "Remember you have to ascend slowly to avoid problems.", t: "Recuerden que deben subir despacio para evitar problemas.", s: "Al recordar reglas de seguridad.", sEn: "When reminding of safety rules.", n: "\"Ascend\" es subir o ascender.", nEn: "\"Ascend\" means to go up." },
    "loc-buc17": { e: "Let's swim slowly to save air.", t: "Nademos despacio para ahorrar aire.", s: "Para que el aire dure más.", sEn: "So the air lasts longer.", n: "\"Save air\" significa ahorrar aire.", nEn: "\"Save air\" means conserve your air supply." },
    "loc-buc18": { e: "Check how much air you have left.", t: "Revisen cuánto aire les queda.", s: "Durante la inmersión, para controlar el tanque.", sEn: "During the dive, to monitor the tank.", n: "\"Have left\" significa lo que queda.", nEn: "\"Have left\" means what remains." },
    "loc-buc19": { e: "If you see me do this, it means you're okay.", t: "Si me ven hacer esto, significa que están bien.", s: "Al enseñar señales de mano.", sEn: "When teaching hand signals.", n: "Bajo el agua se usan señas, no la voz.", nEn: "Underwater you use signals, not your voice." },
    "loc-buc20": { e: "Don't go up faster than your bubbles.", t: "No suban más rápido que sus burbujas.", s: "Regla clave de seguridad al ascender.", sEn: "A key safety rule when ascending.", n: "\"Bubbles\" son las burbujas; subir lento es vital.", nEn: "\"Bubbles\" are the air bubbles; ascending slowly is vital." },
    "loc-buc21": { e: "Stay close to me.", t: "Manténganse cerca de mí.", s: "Para mantener al grupo unido.", sEn: "To keep the group together.", n: "\"Stay close\" significa quedarse cerca.", nEn: "\"Stay close\" means remain near." },
    "loc-buc22": { e: "Don't be afraid, I'm right next to you.", t: "No tengan miedo, estoy junto a ustedes.", s: "Al tranquilizar a un buzo nervioso.", sEn: "When reassuring a nervous diver.", n: "\"Afraid\" se pronuncia \"a-FRÉID\".", nEn: "\"Afraid\" is pronounced \"a-FRÉID\"." },
    "loc-buc23": { e: "Look down.", t: "Miren hacia abajo.", s: "Al señalar algo bajo el agua.", sEn: "When pointing to something underwater.", n: "\"Look down\" significa mirar hacia abajo.", nEn: "\"Look down\" means direct your eyes downward." },
    "loc-buc24": { e: "Ready to get in?", t: "¿Listos para entrar?", s: "Justo antes de meterse al agua.", sEn: "Right before entering the water.", n: "\"Get in\" significa entrar al agua.", nEn: "\"Get in\" means to enter the water." },
    // --- trekking-en ---
    "loc-trk13": { e: "If anyone gets tired, we can take a longer break here.", t: "Si alguien se cansa, podemos hacer una pausa más larga aquí.", s: "Cuando el grupo necesita descansar.", sEn: "When the group needs to rest.", n: "\"Break\" es una pausa o descanso.", nEn: "\"Break\" is a rest or pause." },
    "loc-trk14": { e: "We would have arrived faster, but the rain slowed us down.", t: "Habríamos llegado más rápido, pero la lluvia nos retrasó.", s: "Al explicar un retraso en la caminata.", sEn: "When explaining a delay on the hike.", n: "\"Slowed us down\" significa nos retrasó.", nEn: "\"Slowed us down\" means it delayed us." },
    "loc-trk15": { e: "As we climb, try to breathe steadily.", t: "Mientras subimos, traten de respirar de forma pausada.", s: "En la subida, para controlar el ritmo.", sEn: "On the ascent, to control the pace.", n: "\"Steadily\" significa de forma constante.", nEn: "\"Steadily\" means at a constant rate." },
    "loc-trk16": { e: "If the weather gets worse, we'll turn back for safety.", t: "Si el clima empeora, daremos la vuelta por seguridad.", s: "Al advertir sobre condiciones cambiantes.", sEn: "When warning about changing conditions.", n: "\"Turn back\" significa devolverse.", nEn: "\"Turn back\" means to go back." },
    "loc-trk17": { e: "Place one foot in front of the other carefully.", t: "Pongan un pie delante del otro con cuidado.", s: "En un tramo difícil del sendero.", sEn: "On a tricky stretch of trail.", n: "\"In front of\" significa delante de.", nEn: "\"In front of\" means ahead of." },
    "loc-trk18": { e: "Save your energy for the climb.", t: "Guarden energía para la subida.", s: "Antes del tramo más exigente.", sEn: "Before the toughest stretch.", n: "\"Climb\" es la subida o ascenso.", nEn: "\"Climb\" is the ascent." },
    "loc-trk19": { e: "Follow the trail markers.", t: "Sigan las marcas del sendero.", s: "Para no perder el camino.", sEn: "To stay on the right path.", n: "\"Trail markers\" son las señales del sendero.", nEn: "\"Trail markers\" are the path signs." },
    "loc-trk20": { e: "Let me know if you need to stop.", t: "Avísenme si necesitan parar.", s: "Para que el grupo avise si se cansa.", sEn: "So the group tells you if they tire.", n: "\"Let me know\" significa avíseme.", nEn: "\"Let me know\" means inform me." },
    "loc-trk21": { e: "Take a break.", t: "Tomen un descanso.", s: "Al hacer una pausa.", sEn: "When taking a pause.", n: "\"Take a break\" significa descansar.", nEn: "\"Take a break\" means to rest." },
    "loc-trk22": { e: "We're nearly at the top.", t: "Ya falta poco.", s: "Al acercarse a la cima.", sEn: "When nearing the summit.", n: "\"Nearly\" significa casi, igual que \"almost\".", nEn: "\"Nearly\" means almost." },
    "loc-trk23": { e: "Step here.", t: "Pisen aquí.", s: "Al indicar dónde pisar con seguridad.", sEn: "When showing where to step safely.", n: "\"Step\" significa pisar o dar un paso.", nEn: "\"Step\" means to place your foot." },
    "loc-trk24": { e: "You did great!", t: "¡Lo hicieron muy bien!", s: "Al terminar la caminata.", sEn: "When finishing the hike.", n: "\"You did great\" felicita el esfuerzo.", nEn: "\"You did great\" praises the effort." },
    // --- aeropuerto-en ---
    "loc-air13": { e: "If your bag is overweight, you'll have to pay an extra fee.", t: "Si su maleta pesa de más, tendrá que pagar un cargo adicional.", s: "En el mostrador de facturación.", sEn: "At the check-in counter.", n: "\"Overweight\" significa que pesa de más.", nEn: "\"Overweight\" means over the weight limit." },
    "loc-air14": { e: "I would have given you a window seat, but they're all taken.", t: "Le habría dado un asiento de ventana, pero ya están todos ocupados.", s: "Al asignar asientos.", sEn: "When assigning seats.", n: "\"Taken\" significa ocupado.", nEn: "\"Taken\" means occupied." },
    "loc-air15": { e: "Once you've cleared security, your gate is at the end of the hall.", t: "Una vez que pase seguridad, su puerta está al final del pasillo.", s: "Al dar indicaciones a la puerta.", sEn: "When directing to the gate.", n: "\"Cleared security\" significa haber pasado el control.", nEn: "\"Cleared security\" means passed the checkpoint." },
    "loc-air16": { e: "If you miss your connection, go to your airline's counter.", t: "Si pierde su conexión, acérquese al mostrador de su aerolínea.", s: "Al orientar sobre vuelos de conexión.", sEn: "When advising about connecting flights.", n: "\"Miss your connection\" significa perder el vuelo de conexión.", nEn: "\"Miss your connection\" means lose your connecting flight." },
    "loc-air17": { e: "Are you carrying any liquids in your hand luggage?", t: "¿Lleva algún líquido en el equipaje de mano?", s: "En el control de seguridad.", sEn: "At the security check.", n: "\"Hand luggage\" es el equipaje de mano.", nEn: "\"Hand luggage\" is carry-on baggage." },
    "loc-air18": { e: "Your luggage will come out on belt four.", t: "Su equipaje saldrá por la banda cuatro.", s: "Al indicar dónde recoger las maletas.", sEn: "When showing where to collect bags.", n: "\"Belt\" es la banda de equipaje.", nEn: "\"Belt\" is the baggage carousel." },
    "loc-air19": { e: "Please remove your belt and shoes.", t: "Quítese el cinturón y los zapatos, por favor.", s: "En el control de seguridad.", sEn: "At the security checkpoint.", n: "\"Remove\" significa quitar.", nEn: "\"Remove\" means to take off." },
    "loc-air20": { e: "Priority boarding goes first.", t: "El abordaje preferencial es primero.", s: "Al organizar el embarque.", sEn: "When organizing boarding.", n: "\"Priority boarding\" es el abordaje preferencial.", nEn: "\"Priority boarding\" is the preferred boarding group." },
    "loc-air21": { e: "Your flight is on time.", t: "Su vuelo está a tiempo.", s: "Al confirmar el estado del vuelo.", sEn: "When confirming flight status.", n: "\"On time\" significa a tiempo, sin retraso.", nEn: "\"On time\" means punctual, no delay." },
    "loc-air22": { e: "Are you traveling alone?", t: "¿Viaja solo?", s: "Al hacer preguntas de seguridad.", sEn: "When asking security questions.", n: "\"Alone\" significa solo.", nEn: "\"Alone\" means by yourself." },
    "loc-air23": { e: "This way to the gate.", t: "Por aquí a la puerta.", s: "Al guiar al pasajero.", sEn: "When guiding the passenger.", n: "\"Gate\" es la puerta de embarque.", nEn: "\"Gate\" is the boarding gate." },
    "loc-air24": { e: "What's your destination?", t: "¿Cuál es su destino?", s: "Al registrar al pasajero.", sEn: "When checking in the passenger.", n: "\"Destination\" se pronuncia \"des-ti-NÉI-shon\".", nEn: "\"Destination\" is pronounced \"des-ti-NÉI-shon\"." },
    // --- alquiler-auto-en ---
    "loc-aut11": { e: "If you return the car late, you'll be charged for an extra day.", t: "Si devuelve el auto tarde, se le cobrará un día adicional.", s: "Al explicar la política de devolución.", sEn: "When explaining the return policy.", n: "\"Charged\" significa que se le cobra.", nEn: "\"Charged\" means billed." },
    "loc-aut12": { e: "I would have given you a bigger car, but this is the only one left.", t: "Le habría dado un auto más grande, pero solo queda este.", s: "Cuando hay poca disponibilidad.", sEn: "When availability is low.", n: "\"The only one left\" significa el único que queda.", nEn: "\"The only one left\" means the last one available." },
    "loc-aut13": { e: "In case of an accident, call the number on the contract.", t: "En caso de accidente, llame al número que aparece en el contrato.", s: "Al dar instrucciones de emergencia.", sEn: "When giving emergency instructions.", n: "\"In case of\" significa en caso de.", nEn: "\"In case of\" means in the event of." },
    "loc-aut14": { e: "If you take full coverage, you won't have to worry about minor scratches.", t: "Si toma el seguro completo, no se preocupe por rayones menores.", s: "Al ofrecer el seguro completo.", sEn: "When offering full insurance.", n: "\"Full coverage\" es el seguro completo.", nEn: "\"Full coverage\" is comprehensive insurance." },
    "loc-aut15": { e: "Once you sign here, I'll hand you the keys.", t: "Una vez que firme aquí, le entrego las llaves.", s: "Al cerrar el contrato de alquiler.", sEn: "When finalizing the rental contract.", n: "\"Hand you\" significa entregarle en mano.", nEn: "\"Hand you\" means give to you directly." },
    "loc-aut16": { e: "The GPS is included in the price.", t: "El GPS está incluido en el precio.", s: "Al describir lo que incluye el alquiler.", sEn: "When describing what the rental includes.", n: "\"GPS\" se deletrea \"lli-pi-ES\".", nEn: "\"GPS\" is spelled out \"lli-pi-ES\"." },
    "loc-aut17": { e: "Would you like to add a second driver?", t: "¿Quiere agregar un segundo conductor?", s: "Al ofrecer opciones adicionales.", sEn: "When offering add-ons.", n: "\"Second driver\" suele tener un costo extra.", nEn: "\"Second driver\" usually costs extra." },
    "loc-aut18": { e: "The tank is full now.", t: "El tanque está lleno ahora.", s: "Al entregar el auto.", sEn: "When handing over the car.", n: "\"Tank\" es el tanque de gasolina.", nEn: "\"Tank\" is the fuel tank." },
    "loc-aut19": { e: "Take photos of the car before you leave.", t: "Tome fotos del auto antes de salir.", s: "Para registrar el estado del auto.", sEn: "To document the car's condition.", n: "Las fotos protegen al cliente de cobros injustos.", nEn: "Photos protect the customer from unfair charges." },
    "loc-aut20": { e: "Tolls aren't included.", t: "El peaje no está incluido.", s: "Al aclarar costos adicionales.", sEn: "When clarifying extra costs.", n: "\"Tolls\" son los peajes.", nEn: "\"Tolls\" are road charges." },
    "loc-aut21": { e: "Can you drive a manual?", t: "¿Sabe manejar manual?", s: "Al ofrecer un auto de cambios.", sEn: "When offering a stick-shift car.", n: "\"Manual\" es de cambios; \"automatic\" es automático.", nEn: "\"Manual\" is stick-shift; \"automatic\" is automatic." },
    "loc-aut22": { e: "Here's the key.", t: "Aquí está la llave.", s: "Al entregar la llave del auto.", sEn: "When handing over the car key.", n: "\"Key\" es la llave.", nEn: "\"Key\" is the key." },
    "loc-aut23": { e: "The car is red.", t: "El auto es rojo.", s: "Al ayudar a identificar el auto.", sEn: "When helping identify the car.", n: "Útil para que el cliente lo encuentre.", nEn: "Useful so the customer can find it." },
    "loc-aut24": { e: "It's parked outside.", t: "Está estacionado afuera.", s: "Al indicar dónde está el auto.", sEn: "When showing where the car is.", n: "\"Parked\" significa estacionado.", nEn: "\"Parked\" means parked/stationary." },
    // --- museo-en ---
    "loc-mus11": { e: "If you buy your ticket online, you'll skip the line at the box office.", t: "Si compra la entrada en línea, evitará la fila de la taquilla.", s: "Al recomendar comprar en línea.", sEn: "When recommending buying online.", n: "\"Skip the line\" significa evitar la fila.", nEn: "\"Skip the line\" means avoid the queue." },
    "loc-mus12": { e: "I would have given you an audio guide, but they're all lent out.", t: "Le habría dado la audioguía, pero ya las prestamos todas.", s: "Cuando no quedan audioguías.", sEn: "When no audio guides are left.", n: "\"Lent out\" significa prestadas todas.", nEn: "\"Lent out\" means all loaned out." },
    "loc-mus13": { e: "The back room will remain closed until further notice.", t: "La sala del fondo permanecerá cerrada hasta nuevo aviso.", s: "Al informar de una sala cerrada.", sEn: "When informing of a closed room.", n: "\"Until further notice\" significa hasta nuevo aviso.", nEn: "\"Until further notice\" means indefinitely for now." },
    "loc-mus14": { e: "If you're interested in modern art, don't miss the second floor.", t: "Si le interesa el arte moderno, no se pierda la segunda planta.", s: "Al recomendar una sección del museo.", sEn: "When recommending a museum section.", n: "\"Don't miss\" significa no se pierda.", nEn: "\"Don't miss\" means be sure to see." },
    "loc-mus15": { e: "This painting has been under restoration for months.", t: "Esta pintura ha estado en restauración durante meses.", s: "Al explicar por qué una obra no está visible.", sEn: "When explaining why a work isn't on view.", n: "\"Under restoration\" significa en restauración.", nEn: "\"Under restoration\" means being restored." },
    "loc-mus16": { e: "The last entry is half an hour before closing.", t: "La última entrada es media hora antes de cerrar.", s: "Al informar el horario de cierre.", sEn: "When informing about closing time.", n: "\"Last entry\" es la última hora de ingreso.", nEn: "\"Last entry\" is the final admission time." },
    "loc-mus17": { e: "Would you like a guided tour in English?", t: "¿Le interesa una visita guiada en inglés?", s: "Al ofrecer un recorrido guiado.", sEn: "When offering a guided tour.", n: "\"Guided tour\" es la visita guiada.", nEn: "\"Guided tour\" is a tour with a guide." },
    "loc-mus18": { e: "Please leave your backpacks at the cloakroom.", t: "Deje las mochilas en el guardarropa.", s: "Al pedir dejar las mochilas.", sEn: "When asking to leave backpacks.", n: "\"Cloakroom\" es el guardarropa.", nEn: "\"Cloakroom\" is the coat/bag check." },
    "loc-mus19": { e: "The gift shop is by the exit.", t: "La tienda del museo está a la salida.", s: "Al indicar dónde está la tienda.", sEn: "When showing where the shop is.", n: "\"Gift shop\" es la tienda de regalos.", nEn: "\"Gift shop\" is the souvenir shop." },
    "loc-mus20": { e: "Children get in for free.", t: "Los niños entran gratis.", s: "Al informar sobre entradas gratuitas.", sEn: "When informing about free admission.", n: "\"For free\" significa gratis.", nEn: "\"For free\" means at no cost." },
    "loc-mus21": { e: "How many tickets?", t: "¿Cuántas entradas?", s: "En la taquilla, al vender entradas.", sEn: "At the ticket booth, when selling tickets.", n: "\"Tickets\" son las entradas.", nEn: "\"Tickets\" are the admission tickets." },
    "loc-mus22": { e: "This way, please.", t: "Por aquí, por favor.", s: "Al guiar al visitante.", sEn: "When guiding the visitor.", n: "Frase corta y cortés para orientar.", nEn: "A short, polite phrase to direct people." },
    "loc-mus23": { e: "The restroom is over there.", t: "El baño está allá.", s: "Al indicar dónde está el baño.", sEn: "When showing where the restroom is.", n: "\"Restroom\" (EE. UU.) o \"toilet\" (UK).", nEn: "\"Restroom\" (US) or \"toilet\" (UK)." },
    "loc-mus24": { e: "Here's your ticket.", t: "Aquí tiene su entrada.", s: "Al entregar la entrada.", sEn: "When handing over the ticket.", n: "\"Ticket\" se pronuncia \"TÍ-ket\".", nEn: "\"Ticket\" is pronounced \"TÍ-ket\"." },
    // --- saludos-en ---
    "loc-sal23": { e: "If you have a minute, I'd love to catch up with you.", t: "Si tienes un momento, me encantaría ponerme al día contigo.", s: "Cuando te reencuentras con alguien y quieres conversar un rato.", sEn: "When you run into someone and want to chat for a bit.", n: "\"Catch up\" significa ponerse al día sobre lo que ha pasado.", nEn: "\"Catch up\" means to share news about what's been going on." },
    "loc-sal24": { e: "We haven't seen each other since the party, how's life treating you?", t: "No nos veíamos desde la fiesta, ¿cómo te ha tratado la vida?", s: "Al saludar a un viejo conocido después de mucho tiempo.", sEn: "When greeting an old acquaintance after a long time.", n: "\"How's life treating you?\" es una forma cálida y casual de preguntar cómo estás.", nEn: "\"How's life treating you?\" is a warm, casual way to ask how someone is." },
    // --- telefono ---
    "loc-tel21": { e: "If I don't pick up, leave me a voicemail and I'll get back to you.", t: "Si no le contesto, déjeme un mensaje de voz y le devuelvo la llamada.", s: "Cuando explicas qué hacer si no respondes el teléfono.", sEn: "When explaining what to do if you don't answer the phone.", n: "\"Pick up\" es contestar; \"hang up\" es colgar.", nEn: "\"Pick up\" means to answer; \"hang up\" means to end the call." },
    "loc-tel22": { e: "Sorry, you're breaking up, can you repeat that when you have a better signal?", t: "Disculpe, se está cortando, ¿me lo puede repetir cuando tenga mejor señal?", s: "Cuando la llamada se entrecorta y no escuchas bien.", sEn: "When the call keeps cutting out and you can't hear well.", n: "\"You're breaking up\" se dice cuando la voz se corta en la llamada.", nEn: "\"You're breaking up\" is what you say when the voice keeps cutting out." },
    "loc-tel23": { e: "I'm afraid he's in a meeting right now, would you like me to tell him you called?", t: "Me temo que en este momento está reunido, ¿quiere que le diga que llamó?", s: "Cuando contestas por alguien que no está disponible.", sEn: "When you answer for someone who isn't available.", n: "\"I'm afraid\" suaviza una mala noticia de forma educada.", nEn: "\"I'm afraid\" softens bad news politely." },
    "loc-tel24": { e: "Sorry, I have to hang up, my battery's dying.", t: "Lo siento, tengo que colgar, se me está acabando la batería.", s: "Cuando necesitas terminar la llamada de repente.", sEn: "When you need to end the call suddenly.", n: "\"Hang up\" es colgar el teléfono.", nEn: "\"Hang up\" means to end the phone call." },
    // --- direcciones ---
    "loc-dir21": { e: "When you reach a roundabout, take the third exit and follow the directions.", t: "Si llega a una rotonda, tome la tercera salida y siga las indicaciones.", s: "Cuando le explicas a alguien una ruta con rotondas.", sEn: "When explaining a route with roundabouts to someone.", n: "En EE. UU. también dicen \"traffic circle\" por \"roundabout\".", nEn: "In the US people also say \"traffic circle\" for \"roundabout\"." },
    "loc-dir22": { e: "If you pass the bridge, you've gone too far and you'll have to turn back.", t: "Si se pasa del puente, se fue demasiado lejos y tendrá que regresar.", s: "Cuando adviertes a alguien sobre una referencia que indica que se pasó.", sEn: "When warning someone about a landmark that means they went too far.", n: "\"Turn back\" es devolverse por donde vino.", nEn: "\"Turn back\" means to go back the way you came." },
    "loc-dir23": { e: "The easiest way to get there is to take the main avenue down to the park.", t: "La forma más fácil de llegar es tomar la avenida principal hasta el parque.", s: "Cuando recomiendas la ruta más sencilla a un destino.", sEn: "When recommending the simplest route to a destination.", n: "\"Down to\" aquí indica dirección, no que sea cuesta abajo.", nEn: "\"Down to\" here means direction, not literally downhill." },
    "loc-dir24": { e: "Don't worry, it's just around the corner.", t: "No se preocupe, está justo a la vuelta de la esquina.", s: "Cuando un lugar está muy cerca, casi al lado.", sEn: "When a place is very close, almost right there.", n: "\"Around the corner\" también significa figuradamente \"muy pronto\".", nEn: "\"Around the corner\" can also figuratively mean \"very soon\"." },
    // --- compras-en ---
    "loc-com21": { e: "If it doesn't fit, can I bring it back and exchange it for another size?", t: "Si no me queda bien, ¿puedo traerlo de vuelta y cambiarlo por otra talla?", s: "Antes de comprar ropa, cuando preguntas por cambios.", sEn: "Before buying clothes, when asking about exchanges.", n: "\"Exchange\" es cambiar por otro; \"return\" es devolver por dinero.", nEn: "\"Exchange\" means swap for another; \"return\" means give it back for money." },
    "loc-com22": { e: "I'd take it, but I'd like to think about it a bit before I decide.", t: "Me lo llevaría, pero quisiera pensarlo un poco antes de decidirme.", s: "Cuando algo te gusta pero no estás listo para comprar.", sEn: "When you like something but aren't ready to buy.", n: "\"Think about it\" es una forma educada de no comprometerte aún.", nEn: "\"Think about it\" is a polite way to avoid committing yet." },
    "loc-com23": { e: "Could you let me know if you get more stock in next week?", t: "¿Me podría avisar si les llega más mercancía la próxima semana?", s: "Cuando el producto está agotado y quieres saber cuándo llega.", sEn: "When the item is sold out and you want to know when more arrives.", n: "\"Stock\" es la mercancía disponible; \"out of stock\" es agotado.", nEn: "\"Stock\" is available merchandise; \"out of stock\" means sold out." },
    "loc-com24": { e: "I love it, can you hold it for me until tomorrow?", t: "Me encanta, ¿me lo puede apartar hasta mañana?", s: "Cuando quieres reservar algo y volver a comprarlo después.", sEn: "When you want to reserve something and come back to buy it later.", n: "\"Hold it for me\" es apartar o reservar un producto.", nEn: "\"Hold it for me\" means to set aside or reserve an item." },
    // --- salud-en ---
    "loc-med15": { e: "I have a sore throat and it hurts to swallow.", t: "Me duele la garganta y me duele al tragar.", s: "En la farmacia o con el médico, describiendo dolor de garganta.", sEn: "At the pharmacy or doctor, describing a sore throat.", n: "\"Throat\" lleva el sonido /θ/, como \"z\" suave: \"zrout\".", nEn: "\"Throat\" has the /θ/ sound, like a soft \"th\"." },
    "loc-med16": { e: "I have a cold, so I've been sneezing all day.", t: "Estoy resfriado, así que he estado estornudando todo el día.", s: "Cuando explicas que tienes gripa o resfriado.", sEn: "When explaining that you have a cold.", n: "Se dice \"I have a cold\", no \"I am cold\" (eso es tener frío).", nEn: "Say \"I have a cold\", not \"I am cold\" (that means feeling cold)." },
    "loc-med17": { e: "It's allergy season, do you have something for allergies?", t: "Es temporada de alergias, ¿tiene algo para la alergia?", s: "En la farmacia, pidiendo algo para las alergias.", sEn: "At the pharmacy, asking for something for allergies.", n: "\"Allergies\" se pronuncia \"Á-ler-yis\", con la g suave.", nEn: "\"Allergies\" is pronounced \"AL-er-jees\", with a soft g." },
    "loc-med18": { e: "Do I take it before or after meals?", t: "¿Lo tomo antes o después de comer?", s: "Cuando preguntas cómo tomar un medicamento.", sEn: "When asking how to take a medication.", n: "\"Meals\" son las comidas; \"on an empty stomach\" es en ayunas.", nEn: "\"Meals\" are the meals; \"on an empty stomach\" means fasting." },
    "loc-med19": { e: "I need to make an appointment with the doctor.", t: "Necesito sacar una cita con el médico.", s: "Cuando llamas o vas a la clínica para agendar.", sEn: "When you call or go to the clinic to schedule.", n: "\"Make an appointment\" es sacar o agendar una cita.", nEn: "\"Make an appointment\" means to schedule a visit." },
    "loc-med20": { e: "I've been taking this for a week and I don't feel any better.", t: "He estado tomando esto por una semana y no me siento mejor.", s: "Cuando un tratamiento no está funcionando.", sEn: "When a treatment isn't working.", n: "\"I've been taking\" (presente perfecto continuo) marca algo que sigue ocurriendo.", nEn: "\"I've been taking\" (present perfect continuous) marks something ongoing." },
    "loc-med21": { e: "If the fever doesn't go down by tomorrow, you should see a doctor.", t: "Si la fiebre no baja para mañana, debería ver a un médico.", s: "Cuando aconsejas a alguien sobre cuándo buscar atención.", sEn: "When advising someone about when to seek care.", n: "\"Go down\" para la fiebre significa bajar.", nEn: "\"Go down\" for a fever means to drop." },
    "loc-med22": { e: "Are there any side effects I should be aware of?", t: "¿Hay algún efecto secundario que deba tener en cuenta?", s: "Cuando el médico o farmacéutico te receta algo nuevo.", sEn: "When the doctor or pharmacist prescribes something new.", n: "\"Side effects\" son los efectos secundarios.", nEn: "\"Side effects\" are the secondary effects of a medicine." },
    "loc-med23": { e: "I've had a pain in my back for a few days that won't go away.", t: "Llevo varios días con un dolor de espalda que no se me quita.", s: "Cuando describes un dolor persistente al médico.", sEn: "When describing a persistent pain to the doctor.", n: "\"Won't go away\" significa que algo no desaparece.", nEn: "\"Won't go away\" means something doesn't disappear." },
    "loc-med24": { e: "Is this available over the counter, or do I need a prescription?", t: "¿Esto se vende sin receta, o necesito una?", s: "Al preguntar si un medicamento requiere receta.", sEn: "When asking if a medicine needs a prescription.", n: "\"Over the counter\" significa sin receta; \"prescription\" es receta.", nEn: "\"Over the counter\" means no prescription needed." },
    // --- dinero-en ---
    "loc-din21": { e: "If I withdraw from another bank, do they charge me an extra fee?", t: "Si retiro de otro banco, ¿me cobran una comisión adicional?", s: "Antes de sacar dinero en un cajero que no es de tu banco.", sEn: "Before withdrawing from an ATM not run by your bank.", n: "\"Fee\" es comisión; \"withdraw\" es retirar dinero.", nEn: "\"Fee\" means a charge; \"withdraw\" means to take out money." },
    "loc-din22": { e: "I'd like to transfer money abroad, how long does it take to arrive?", t: "Me gustaría transferir dinero al exterior, ¿cuánto se demora en llegar?", s: "En el banco, al enviar dinero a otro país.", sEn: "At the bank, when sending money to another country.", n: "\"Abroad\" significa al extranjero o al exterior.", nEn: "\"Abroad\" means to another country." },
    "loc-din23": { e: "I think I was overcharged, could you check my account?", t: "Creo que me cobraron de más, ¿podría revisar mi cuenta?", s: "Cuando notas un cobro incorrecto en tu cuenta.", sEn: "When you notice an incorrect charge on your account.", n: "\"Overcharged\" significa que te cobraron de más.", nEn: "\"Overcharged\" means you were charged too much." },
    "loc-din24": { e: "Can I pay by bank transfer instead of card?", t: "¿Puedo pagar con transferencia en vez de tarjeta?", s: "Al pagar y preferir una transferencia bancaria.", sEn: "When paying and preferring a bank transfer.", n: "\"Bank transfer\" es una transferencia entre cuentas.", nEn: "\"Bank transfer\" is a transfer between accounts." },
    // --- transporte-en ---
    "loc-tra15": { e: "Excuse me, where's the bus stop?", t: "Disculpe, ¿dónde está la parada?", s: "Cuando buscas dónde tomar el bus.", sEn: "When looking for where to catch the bus.", n: "\"Bus stop\" es la parada; \"station\" es la estación más grande.", nEn: "\"Bus stop\" is the stop; \"station\" is the larger terminal." },
    "loc-tra16": { e: "One ticket, please.", t: "Un boleto, por favor.", s: "En la taquilla o con el conductor al comprar pasaje.", sEn: "At the ticket window or with the driver when buying a fare.", n: "\"Ticket\" es boleto, tiquete o pasaje.", nEn: "\"Ticket\" covers fare, pass, or boarding ticket." },
    "loc-tra17": { e: "To get downtown, do I have to change lines?", t: "Para ir al centro, ¿tengo que hacer transbordo?", s: "Cuando preguntas si debes cambiar de tren o bus.", sEn: "When asking if you must switch trains or buses.", n: "\"Change lines\" o \"transfer\" es hacer transbordo.", nEn: "\"Change lines\" or \"transfer\" means to switch routes." },
    "loc-tra18": { e: "Does this train stop at my station?", t: "¿Este tren para en mi estación?", s: "Antes de subir, para asegurarte de que el tren para donde necesitas.", sEn: "Before boarding, to make sure the train stops where you need.", n: "Algunos trenes expresos no paran en todas las estaciones.", nEn: "Some express trains skip certain stations." },
    "loc-tra19": { e: "Sorry I'm late, I missed my connection.", t: "Perdón por la demora, perdí mi conexión.", s: "Cuando explicas por qué llegaste tarde en transporte.", sEn: "When explaining why you arrived late by transit.", n: "\"Missed my connection\" es perder el siguiente tren o bus de enlace.", nEn: "\"Missed my connection\" means missing your next connecting service." },
    "loc-tra20": { e: "If I miss the last bus, is there another way to get home?", t: "Si no alcanzo el último bus, ¿hay otra forma de llegar a casa?", s: "De noche, planeando cómo volver si pierdes el transporte.", sEn: "At night, planning how to get back if you miss transit.", n: "\"The last bus\" es el último servicio de la noche.", nEn: "\"The last bus\" is the final service of the night." },
    "loc-tra21": { e: "Could you let me know when we get to the central station?", t: "¿Me podría avisar cuando lleguemos a la estación central?", s: "Cuando no conoces la ruta y pides ayuda para no pasarte.", sEn: "When you don't know the route and ask not to miss your stop.", n: "Pedir esto a otro pasajero o al conductor es muy común y educado.", nEn: "Asking this of a passenger or driver is common and polite." },
    "loc-tra22": { e: "It would be cheaper to buy a monthly pass if you travel every day.", t: "Saldría más barato comprar un pase mensual si viajas todos los días.", s: "Al aconsejar a alguien que usa mucho el transporte.", sEn: "When advising someone who uses transit a lot.", n: "\"Monthly pass\" es un abono mensual de transporte.", nEn: "\"Monthly pass\" is a monthly transit subscription." },
    "loc-tra23": { e: "The train was delayed, so I'm going to be late for the meeting.", t: "El tren se retrasó, así que voy a llegar tarde a la reunión.", s: "Cuando avisas que llegarás tarde por culpa del transporte.", sEn: "When warning you'll be late because of transit.", n: "\"Delayed\" es retrasado; \"on time\" es a tiempo.", nEn: "\"Delayed\" means late; \"on time\" means punctual." },
    "loc-tra24": { e: "What's the best route to the airport?", t: "¿Cuál es la mejor ruta al aeropuerto?", s: "Cuando planeas tu viaje y quieres el camino más eficiente.", sEn: "When planning your trip and wanting the most efficient way.", n: "\"Route\" se puede decir \"ruut\" o \"raut\", ambas valen.", nEn: "\"Route\" can be said \"root\" or \"rout\"; both are fine." },
    // --- emergencias-en ---
    "loc-eme15": { e: "Fire! Everybody get out!", t: "¡Fuego! ¡Todos afuera!", s: "Para alertar a otros de un incendio.", sEn: "To alert others of a fire.", n: "Gritar \"Fire!\" es la forma estándar de alertar de un incendio.", nEn: "Shouting \"Fire!\" is the standard way to warn of a fire." },
    "loc-eme16": { e: "Watch out, there's a car coming!", t: "¡Cuidado, viene un carro!", s: "Para advertir a alguien de un peligro inmediato.", sEn: "To warn someone of immediate danger.", n: "\"Watch out!\" es una advertencia urgente, como \"¡cuidado!\".", nEn: "\"Watch out!\" is an urgent warning, like \"look out!\"." },
    "loc-eme17": { e: "Quick, call the emergency number!", t: "¡Rápido, llamen al número de emergencias!", s: "Cuando necesitas ayuda urgente y pides que llamen.", sEn: "When you need urgent help and ask someone to call.", n: "En EE. UU. el número es el 911; en otros países varía.", nEn: "In the US the number is 911; it varies by country." },
    "loc-eme18": { e: "Someone needs a doctor over here!", t: "¡Alguien necesita un médico aquí!", s: "Cuando alguien se desmaya o se enferma de repente.", sEn: "When someone faints or suddenly falls ill.", n: "\"Someone\" se pronuncia \"SÓM-won\".", nEn: "\"Someone\" is pronounced \"SUM-won\"." },
    "loc-eme19": { e: "Please help, I can't find my son!", t: "Por favor ayuden, ¡no encuentro a mi hijo!", s: "Cuando se te pierde un niño en un lugar lleno de gente.", sEn: "When you lose a child in a crowded place.", n: "\"I can't find\" es no poder encontrar a alguien o algo.", nEn: "\"I can't find\" means you're unable to locate someone or something." },
    "loc-eme20": { e: "If you see anything suspicious, tell security right away.", t: "Si ve algo sospechoso, avise a seguridad de inmediato.", s: "Cuando adviertes a alguien que reporte cosas extrañas.", sEn: "When telling someone to report anything strange.", n: "\"Suspicious\" se pronuncia \"sos-PÍ-shos\".", nEn: "\"Suspicious\" is pronounced \"suss-PISH-us\"." },
    "loc-eme21": { e: "I think someone followed me, I don't feel safe walking alone.", t: "Creo que alguien me siguió, no me siento seguro caminando solo.", s: "Cuando sientes que tu seguridad está en riesgo.", sEn: "When you feel your safety is at risk.", n: "\"I don't feel safe\" expresa que no te sientes seguro.", nEn: "\"I don't feel safe\" expresses feeling unsafe." },
    "loc-eme22": { e: "Stay calm and follow the emergency exits out to the street.", t: "Mantenga la calma y siga las salidas de emergencia hasta la calle.", s: "Durante una evacuación, guiando a la gente a la salida.", sEn: "During an evacuation, guiding people to the exit.", n: "\"Emergency exits\" son las salidas de emergencia.", nEn: "\"Emergency exits\" are the marked escape routes." },
    "loc-eme23": { e: "If you don't feel better soon, we should go to the emergency room.", t: "Si no se siente mejor pronto, deberíamos ir a urgencias.", s: "Cuando alguien está enfermo y consideras llevarlo a urgencias.", sEn: "When someone is ill and you consider taking them to the ER.", n: "\"Emergency room\" (o \"ER\") es la sala de urgencias.", nEn: "\"Emergency room\" (or \"ER\") is the urgent-care hospital ward." },
    "loc-eme24": { e: "Can you help me, please? I'm a bit lost.", t: "¿Me puede ayudar, por favor? Estoy un poco perdido.", s: "Cuando necesitas ayuda de un desconocido amablemente.", sEn: "When you need help from a stranger politely.", n: "Agregar \"please\" hace la petición más cortés.", nEn: "Adding \"please\" makes the request more polite." },
    // --- peluqueria ---
    "loc-pel13": { e: "Just the ends, please, not too much off.", t: "Solo las puntas, por favor, no mucho.", s: "Cuando solo quieres recortar las puntas del cabello.", sEn: "When you only want a light trim of the ends.", n: "\"The ends\" son las puntas del cabello.", nEn: "\"The ends\" are the tips of the hair." },
    "loc-pel14": { e: "I want my usual cut, the same as last time.", t: "Quiero el mismo corte de siempre, igual que la última vez.", s: "Cuando vuelves al mismo peluquero y quieres lo de siempre.", sEn: "When you return to the same barber and want your usual.", n: "\"Usual\" se pronuncia \"IÚ-shual\".", nEn: "\"Usual\" is pronounced \"YOO-zhoo-al\"." },
    "loc-pel15": { e: "Don't make it too short on top, please.", t: "No me lo deje muy corto arriba, por favor.", s: "Cuando das indicaciones precisas sobre el corte.", sEn: "When giving precise instructions about the cut.", n: "\"On top\" es la parte de arriba; \"on the sides\" los lados.", nEn: "\"On top\" is the top; \"on the sides\" is the sides." },
    "loc-pel16": { e: "Can you cover the gray hairs while you're at it?", t: "¿Me puede teñir las canas de paso?", s: "Cuando quieres ocultar las canas con tinte.", sEn: "When you want to hide gray hairs with color.", n: "\"Gray\" (US) o \"grey\" (UK); \"canas\" son \"gray hairs\".", nEn: "\"Gray\" (US) or \"grey\" (UK); both spellings are correct." },
    "loc-pel17": { e: "How long does the haircut take?", t: "¿Cuánto se demora el corte?", s: "Cuando tienes prisa y quieres saber cuánto tardará.", sEn: "When you're in a hurry and want to know how long it'll take.", n: "\"Haircut\" se pronuncia \"JER-cot\".", nEn: "\"Haircut\" is pronounced \"HAIR-cut\"." },
    "loc-pel18": { e: "I like the part on the side, not in the middle.", t: "Me gusta la raya a un lado, no en el medio.", s: "Cuando indicas dónde quieres la raya del cabello.", sEn: "When indicating where you want your hair parted.", n: "\"Part\" es la raya del cabello; \"in the middle\" es al medio.", nEn: "\"Part\" is the hair parting; \"in the middle\" is centered." },
    "loc-pel19": { e: "Last time they cut it too short, this time leave it a bit longer.", t: "La última vez me lo dejaron demasiado corto, esta vez déjelo más largo.", s: "Cuando corriges el resultado de un corte anterior.", sEn: "When correcting the result of a previous cut.", n: "\"Leave it longer\" es pedir que dejen el cabello más largo.", nEn: "\"Leave it longer\" asks them to keep the hair longer." },
    "loc-pel20": { e: "Could you recommend a cut that's easy to maintain?", t: "¿Me podría recomendar un corte que sea fácil de mantener?", s: "Cuando quieres un estilo práctico y poco exigente.", sEn: "When you want a practical, low-effort style.", n: "\"Easy to maintain\" significa fácil de mantener en el día a día.", nEn: "\"Easy to maintain\" means low daily upkeep." },
    "loc-pel21": { e: "If you're going to dye it, I'd rather have a shade that doesn't show too much.", t: "Si me lo va a teñir, prefiero un tono que no se note tanto.", s: "Cuando aceptas un tinte pero quieres algo discreto.", sEn: "When agreeing to color but wanting something subtle.", n: "\"Dye\" es teñir; \"shade\" es el tono o matiz.", nEn: "\"Dye\" means to color; \"shade\" is the tone or hue." },
    "loc-pel22": { e: "I'd like something different, but still manageable for work.", t: "Me gustaría algo distinto, pero que siga siendo manejable para el trabajo.", s: "Cuando quieres un cambio sin complicarte el arreglo diario.", sEn: "When wanting a change without complicating your daily routine.", n: "\"Manageable\" significa fácil de manejar o peinar.", nEn: "\"Manageable\" means easy to handle or style." },
    "loc-pel23": { e: "Tidy it up a little more, please, around the neck.", t: "Me lo arregla un poco más, por favor, en el cuello.", s: "Cuando pides retoques finales al corte.", sEn: "When asking for final touch-ups to the cut.", n: "\"Tidy it up\" es arreglar o emparejar los detalles.", nEn: "\"Tidy it up\" means to neaten the details." },
    "loc-pel24": { e: "It looks perfect, thank you so much.", t: "Quedó perfecto, muchas gracias.", s: "Al final, cuando estás contento con el resultado.", sEn: "At the end, when you're happy with the result.", n: "\"Thank you\" suena \"ZENK yu\", con el sonido /θ/.", nEn: "\"Thank you\" has the soft /θ/ sound at the start." },
    // --- vivienda ---
    "loc-viv13": { e: "How much is the rent per month?", t: "¿Cuánto es el arriendo al mes?", s: "Al preguntar el precio mensual de un lugar.", sEn: "When asking the monthly price of a place.", n: "\"Rent\" es el arriendo; \"per month\" es al mes.", nEn: "\"Rent\" is the monthly payment; \"per month\" means monthly." },
    "loc-viv14": { e: "Are the utilities included in the rent?", t: "¿Las cuentas están incluidas en el arriendo?", s: "Antes de alquilar, al preguntar por luz, agua y gas.", sEn: "Before renting, when asking about electricity, water and gas.", n: "\"Utilities\" son los servicios: luz, agua, gas.", nEn: "\"Utilities\" are services like electricity, water, and gas." },
    "loc-viv15": { e: "Can I bring my pet? I have a small dog.", t: "¿Puedo traer mi mascota? Tengo un perro pequeño.", s: "Al preguntar si el lugar acepta animales.", sEn: "When asking whether pets are allowed.", n: "\"Pet\" es mascota; \"pet-friendly\" es que acepta mascotas.", nEn: "\"Pet\" is a pet; \"pet-friendly\" means pets are welcome." },
    "loc-viv16": { e: "The lease is for one year, with the option to renew.", t: "El contrato es por un año, con opción a renovar.", s: "Cuando el dueño explica la duración del contrato.", sEn: "When the landlord explains the contract length.", n: "\"Lease\" es el contrato de arriendo.", nEn: "\"Lease\" is the rental contract." },
    "loc-viv17": { e: "There's a leak in the bathroom, can you send someone?", t: "Hay una fuga en el baño, ¿puede enviar a alguien?", s: "Al reportar un problema al dueño o administrador.", sEn: "When reporting a problem to the landlord or manager.", n: "\"Leak\" es una fuga de agua.", nEn: "\"Leak\" is a water leak." },
    "loc-viv18": { e: "Before I sign the lease, I'd like to look the apartment over carefully.", t: "Antes de firmar el contrato, me gustaría revisar bien el apartamento.", s: "Cuando quieres inspeccionar antes de comprometerte.", sEn: "When you want to inspect before committing.", n: "\"Look it over\" es revisar algo con cuidado.", nEn: "\"Look it over\" means to inspect carefully." },
    "loc-viv19": { e: "If I decide to renew, would the rent go up next year?", t: "Si decido renovar, ¿el arriendo subiría el próximo año?", s: "Al hablar de renovar el contrato con el dueño.", sEn: "When discussing renewing the contract with the landlord.", n: "\"Go up\" significa subir o aumentar.", nEn: "\"Go up\" means to increase." },
    "loc-viv20": { e: "I've been without hot water for a week and no one has come to fix it.", t: "Llevo una semana sin agua caliente y nadie ha venido a arreglarlo.", s: "Al quejarte de un problema que el dueño no ha resuelto.", sEn: "When complaining about an unresolved problem.", n: "El presente perfecto \"has come\" marca algo aún sin resolverse.", nEn: "Present perfect \"has come\" marks something still unresolved." },
    "loc-viv21": { e: "Would I get the deposit back if I leave the place clean?", t: "¿Me devolverían el depósito si dejo el lugar limpio?", s: "Al mudarte, preguntando por la devolución del depósito.", sEn: "When moving out, asking about the deposit return.", n: "\"Deposit\" es el depósito de garantía.", nEn: "\"Deposit\" is the security deposit." },
    "loc-viv22": { e: "Who pays for repairs, you or me?", t: "¿Quién paga las reparaciones, usted o yo?", s: "Al aclarar las responsabilidades del contrato.", sEn: "When clarifying responsibilities in the contract.", n: "\"Repairs\" son las reparaciones del inmueble.", nEn: "\"Repairs\" are property fixes." },
    "loc-viv23": { e: "I need to give a month's notice before I move out.", t: "Necesito avisar con un mes de anticipación antes de mudarme.", s: "Al informar que dejarás el lugar.", sEn: "When notifying that you'll be leaving.", n: "\"Give notice\" es avisar con anticipación que te vas.", nEn: "\"Give notice\" means to warn in advance that you're leaving." },
    "loc-viv24": { e: "I really like the apartment, it feels like home.", t: "El apartamento me gusta mucho, se siente como un hogar.", s: "Al expresar que te gusta el lugar.", sEn: "When expressing that you like the place.", n: "\"Apartment\" (US) o \"flat\" (UK).", nEn: "\"Apartment\" (US) or \"flat\" (UK)." },
    // --- clima-en ---
    "loc-clm13": { e: "Take a jacket, it's raining.", t: "Lleva una chaqueta, está lloviendo.", s: "Cuando describes que está cayendo lluvia.", sEn: "When describing that it's raining.", n: "\"It's raining\" usa \"it\" impersonal para el clima.", nEn: "\"It's raining\" uses impersonal \"it\" for weather." },
    "loc-clm14": { e: "It's cold outside, bundle up.", t: "Hace frío afuera, abrígate.", s: "Cuando avisas que hace frío antes de salir.", sEn: "When warning it's cold before going out.", n: "\"It's cold\" para el clima; \"I'm cold\" para tu cuerpo.", nEn: "\"It's cold\" for weather; \"I'm cold\" for your body." },
    "loc-clm15": { e: "The sky is getting gray, looks like a storm.", t: "El cielo se está poniendo gris, parece tormenta.", s: "Cuando notas que el clima va a empeorar.", sEn: "When you notice the weather is about to turn.", n: "\"Getting gray\" describe un cambio en curso.", nEn: "\"Getting gray\" describes an ongoing change." },
    "loc-clm16": { e: "It's going to be sunny tomorrow, perfect for the beach.", t: "Mañana va a estar soleado, perfecto para la playa.", s: "Al hablar del pronóstico para el día siguiente.", sEn: "When talking about tomorrow's forecast.", n: "\"Sunny\" es soleado; \"sun\" es el sol.", nEn: "\"Sunny\" means sunny; \"sun\" is the sun." },
    "loc-clm17": { e: "There was a storm last night, did you hear it?", t: "Hubo una tormenta anoche, ¿la escuchaste?", s: "Al comentar el clima del día anterior.", sEn: "When commenting on the previous day's weather.", n: "\"Storm\" es tormenta; \"thunderstorm\" lleva truenos.", nEn: "\"Storm\" is a storm; \"thunderstorm\" has thunder." },
    "loc-clm18": { e: "It's freezing this morning, I can see my breath.", t: "Está helado esta mañana, se me ve el aliento.", s: "En un día muy frío, exagerando lo helado que está.", sEn: "On a very cold day, emphasizing how cold it is.", n: "\"Freezing\" es helado, mucho más que \"cold\".", nEn: "\"Freezing\" means icy cold, much more than \"cold\"." },
    "loc-clm19": { e: "If the weather stays like this, we'll have to cancel the trip.", t: "Si el clima sigue así, tendremos que cancelar el paseo.", s: "Al planear según las condiciones del tiempo.", sEn: "When planning based on the weather conditions.", n: "\"Stays like this\" significa que el clima sigue igual.", nEn: "\"Stays like this\" means the weather stays the same." },
    "loc-clm20": { e: "They said it's supposed to clear up by the weekend.", t: "Dijeron que va a mejorar para el fin de semana.", s: "Al repetir lo que dice el pronóstico.", sEn: "When repeating what the forecast says.", n: "\"Clear up\" es despejarse o mejorar el clima.", nEn: "\"Clear up\" means the weather improves or clears." },
    "loc-clm21": { e: "You should bring a coat because it'll get colder at night.", t: "Deberías llevar abrigo porque va a refrescar en la noche.", s: "Al aconsejar abrigarse para más tarde.", sEn: "When advising to dress warmly for later.", n: "\"Get colder\" es ponerse más frío.", nEn: "\"Get colder\" means to become colder." },
    "loc-clm22": { e: "Even though it's sunny now, it looks like it'll rain later.", t: "Aunque ahora hace sol, parece que va a llover más tarde.", s: "Al advertir que el buen clima no durará.", sEn: "When warning the good weather won't last.", n: "\"Even though\" significa \"aunque\", contrastando dos ideas.", nEn: "\"Even though\" means \"although\", contrasting two ideas." },
    "loc-clm23": { e: "The forecast says it'll be cloudy all day.", t: "El pronóstico dice que estará nublado todo el día.", s: "Al citar el pronóstico del tiempo.", sEn: "When quoting the weather forecast.", n: "\"Forecast\" es el pronóstico del clima.", nEn: "\"Forecast\" is the weather prediction." },
    "loc-clm24": { e: "It's so hot, I need some water.", t: "Qué calor hace, necesito agua.", s: "En un día muy caluroso.", sEn: "On a very hot day.", n: "\"It's so hot\" enfatiza el calor con \"so\".", nEn: "\"It's so hot\" emphasizes the heat with \"so\"." },
    // --- delivery-en ---
    "loc-del11": { e: "Hi, are you {name}? I have a delivery.", t: "Hola, ¿es usted {name}? Traigo una entrega.", s: "Cuando llegas a entregar y confirmas con quién hablas.", sEn: "When you arrive to deliver and confirm who you're talking to.", n: "Confirmar el nombre evita entregar al destinatario equivocado.", nEn: "Confirming the name avoids delivering to the wrong person." },
    "loc-del12": { e: "Here's your package, it's a bit heavy.", t: "Aquí tiene su paquete, está un poco pesado.", s: "Al entregar un paquete en mano.", sEn: "When handing over a package in person.", n: "\"Package\" (US) o \"parcel\" (UK).", nEn: "\"Package\" (US) or \"parcel\" (UK)." },
    "loc-del13": { e: "Where would you like me to leave it?", t: "¿Dónde quiere que lo deje?", s: "Cuando el cliente no puede recibirlo en mano.", sEn: "When the customer can't take it in person.", n: "Preguntar esto es cortés y evita malentendidos.", nEn: "Asking this is polite and avoids confusion." },
    "loc-del14": { e: "I need your signature to drop it off.", t: "Necesito su firma para entregarlo.", s: "Cuando la entrega requiere confirmación firmada.", sEn: "When the delivery requires a signed confirmation.", n: "\"Signature\" se pronuncia \"SÍG-na-cher\".", nEn: "\"Signature\" is pronounced \"SIG-nuh-chur\"." },
    "loc-del15": { e: "The restaurant took a while, sorry about the wait.", t: "El restaurante se demoró un poco, disculpe la espera.", s: "Al disculparte por una entrega de comida demorada.", sEn: "When apologizing for a late food delivery.", n: "\"Took a while\" significa que tomó tiempo.", nEn: "\"Took a while\" means it took some time." },
    "loc-del16": { e: "Can you confirm the address before I head over?", t: "¿Me confirma la dirección antes de ir?", s: "Cuando quieres asegurarte de la dirección correcta.", sEn: "When you want to make sure of the right address.", n: "\"Confirm\" se pronuncia \"con-FÉRM\".", nEn: "\"Confirm\" is pronounced \"kun-FURM\"." },
    "loc-del17": { e: "I can't find the building, could you send me the exact location?", t: "No encuentro el edificio, ¿me podría enviar la ubicación exacta?", s: "Cuando estás perdido buscando la dirección de entrega.", sEn: "When you're lost looking for the delivery address.", n: "\"Exact location\" puede ser un pin de mapa compartido.", nEn: "\"Exact location\" can be a shared map pin." },
    "loc-del18": { e: "If you don't answer when I arrive, I'll leave the order with the doorman.", t: "Si no contesta cuando llegue, dejaré el pedido con el portero.", s: "Al explicar tu plan si el cliente no abre.", sEn: "When explaining your plan if the customer doesn't answer.", n: "\"Doorman\" es el portero del edificio.", nEn: "\"Doorman\" is the building's door attendant." },
    "loc-del19": { e: "Your order is on the way, it should arrive in about fifteen minutes.", t: "Su pedido viene en camino, debería llegar en unos quince minutos.", s: "Al actualizar al cliente sobre su entrega.", sEn: "When updating the customer about their delivery.", n: "\"On the way\" significa en camino.", nEn: "\"On the way\" means en route." },
    "loc-del20": { e: "If anything in the order is wrong, let me know and I'll sort it out right away.", t: "Si algo del pedido está mal, avíseme y lo soluciono enseguida.", s: "Al entregar, ofreciendo resolver cualquier error.", sEn: "When delivering, offering to fix any mistake.", n: "\"Sort it out\" es resolver un problema (más británico, también común en US).", nEn: "\"Sort it out\" means to resolve a problem." },
    "loc-del21": { e: "Could you leave me a good review? It really helps.", t: "¿Me puede dejar una buena reseña? Ayuda mucho.", s: "Al pedir amablemente una buena calificación.", sEn: "When kindly asking for a good rating.", n: "\"Review\" es una reseña o valoración.", nEn: "\"Review\" is a rating or evaluation." },
    "loc-del22": { e: "The bell isn't working, I'm knocking on the door.", t: "El timbre no funciona, estoy tocando la puerta.", s: "Cuando el timbre falla y avisas que tocas.", sEn: "When the bell fails and you tell them you're knocking.", n: "\"Knock\" es tocar la puerta con los nudillos.", nEn: "\"Knock\" means to rap on the door." },
    "loc-del23": { e: "Have a good one, take care!", t: "Que tenga buen día, ¡cuídese!", s: "Despedida casual al terminar la entrega.", sEn: "A casual goodbye after finishing the delivery.", n: "\"Have a good one\" es una despedida casual y amistosa.", nEn: "\"Have a good one\" is a casual, friendly goodbye." },
    "loc-del24": { e: "I'm here for the pickup, the order's under {name}.", t: "Vengo por la recogida, el pedido está a nombre de {name}.", s: "Cuando llegas al local a recoger un pedido.", sEn: "When you arrive at the shop to collect an order.", n: "\"Pickup\" es la recogida; \"drop-off\" es la entrega.", nEn: "\"Pickup\" is collection; \"drop-off\" is delivery." },
    // --- gym-en ---
    "loc-gym11": { e: "Tighten your core to protect your back.", t: "Apriete el abdomen para proteger la espalda.", s: "Cuando el entrenador corrige tu técnica en un ejercicio.", sEn: "When the trainer corrects your form on an exercise.", n: "\"Core\" es la zona del abdomen y la cintura.", nEn: "\"Core\" is the abdominal and trunk area." },
    "loc-gym12": { e: "Look straight ahead, not down.", t: "Mire al frente, no hacia abajo.", s: "Al corregir la postura de la cabeza durante un ejercicio.", sEn: "When correcting head posture during an exercise.", n: "\"Straight ahead\" es justo hacia el frente.", nEn: "\"Straight ahead\" means directly forward." },
    "loc-gym13": { e: "How many sets should I do?", t: "¿Cuántas series hago?", s: "Al preguntar el plan de entrenamiento.", sEn: "When asking about the workout plan.", n: "\"Set\" es una serie; \"rep\" es una repetición.", nEn: "\"Set\" is a set; \"rep\" is a repetition." },
    "loc-gym14": { e: "Add a little more weight on the next set.", t: "Sube un poco el peso en la siguiente serie.", s: "Cuando el ejercicio se siente fácil y subes carga.", sEn: "When the exercise feels easy and you add load.", n: "\"Weight\" se pronuncia \"weit\", la gh es muda.", nEn: "\"Weight\" is pronounced \"wayt\", the gh is silent." },
    "loc-gym15": { e: "Don't lock your knees at the top.", t: "No bloquee las rodillas arriba.", s: "Al corregir una postura que puede causar lesión.", sEn: "When correcting a stance that could cause injury.", n: "\"Lock your knees\" es estirarlas por completo y trabarlas.", nEn: "\"Lock your knees\" means fully straightening and locking them." },
    "loc-gym16": { e: "Can you spot me on the last rep?", t: "¿Me cuida la última repetición?", s: "Al pedir ayuda para no fallar con el peso.", sEn: "When asking for help so you don't fail under the weight.", n: "\"Spot me\" es pedir que te asistan por seguridad.", nEn: "\"Spot me\" means to ask someone to assist you for safety." },
    "loc-gym17": { e: "If you feel pain in the joint, stop right away and let me know.", t: "Si sientes dolor en la articulación, para de inmediato y avísame.", s: "Cuando el entrenador advierte sobre lesiones.", sEn: "When the trainer warns about injuries.", n: "\"Joint\" es la articulación; \"muscle\" es el músculo.", nEn: "\"Joint\" is a joint; \"muscle\" is a muscle." },
    "loc-gym18": { e: "You'll see results if you stay consistent for a few weeks.", t: "Vas a ver resultados si te mantienes constante durante unas semanas.", s: "Al motivar a alguien que recién empieza.", sEn: "When motivating someone who's just starting.", n: "\"Stay consistent\" es mantenerse constante.", nEn: "\"Stay consistent\" means to keep at it regularly." },
    "loc-gym19": { e: "Focus on your form before you worry about adding weight.", t: "Concéntrate en la técnica antes de preocuparte por subir el peso.", s: "Al aconsejar a un principiante sobre prioridades.", sEn: "When advising a beginner about priorities.", n: "\"Form\" en el gimnasio es la técnica del movimiento.", nEn: "\"Form\" at the gym means movement technique." },
    "loc-gym20": { e: "If you're struggling to finish the set, it's fine to use less weight.", t: "Si te cuesta terminar la serie, está bien usar menos peso.", s: "Al tranquilizar a alguien que no puede con la carga.", sEn: "When reassuring someone who can't handle the load.", n: "\"Struggling\" significa batallar o costar mucho.", nEn: "\"Struggling\" means having a hard time." },
    "loc-gym21": { e: "Hold it at the top for two seconds.", t: "Aguanta arriba dos segundos.", s: "Al dar una instrucción de tiempo en el ejercicio.", sEn: "When giving a timing cue during the exercise.", n: "\"Hold it\" es mantener la posición.", nEn: "\"Hold it\" means to keep the position." },
    "loc-gym22": { e: "Let's cool down now with some stretching.", t: "Vamos a enfriar ahora con estiramientos.", s: "Al final del entrenamiento, para relajar el cuerpo.", sEn: "At the end of the workout, to relax the body.", n: "\"Cool down\" es enfriar; lo opuesto de \"warm up\".", nEn: "\"Cool down\" is the opposite of \"warm up\"." },
    "loc-gym23": { e: "Good posture, keep it just like that.", t: "Buena postura, mantenla así.", s: "Al felicitar a alguien por su técnica.", sEn: "When praising someone's technique.", n: "\"Posture\" se pronuncia \"PÓS-cher\".", nEn: "\"Posture\" is pronounced \"POS-chur\"." },
    "loc-gym24": { e: "Don't skip the warm-up or you could easily get hurt.", t: "No te saltes el calentamiento o te puedes lesionar fácilmente.", s: "Al recordar la importancia de calentar.", sEn: "When reminding about the importance of warming up.", n: "\"Get hurt\" es lesionarse o hacerse daño.", nEn: "\"Get hurt\" means to injure yourself." },
    // --- hogar-en ---
    "loc-hog13": { e: "I'll sweep the floor before I leave.", t: "Voy a barrer el piso antes de irme.", s: "Cuando ofreces hacer una tarea de limpieza.", sEn: "When offering to do a cleaning task.", n: "\"Sweep\" es barrer; \"mop\" es trapear.", nEn: "\"Sweep\" means to sweep; \"mop\" means to mop." },
    "loc-hog14": { e: "Should I wash the dishes now?", t: "¿Lavo los platos ahora?", s: "Al preguntar si haces una tarea doméstica.", sEn: "When asking whether to do a household chore.", n: "\"Dishes\" son los platos; \"do the dishes\" es lavarlos.", nEn: "\"Dishes\" are the dishes; \"do the dishes\" means wash them." },
    "loc-hog15": { e: "The washing machine broke, it won't turn on.", t: "Se dañó la lavadora, no enciende.", s: "Al reportar un electrodoméstico averiado.", sEn: "When reporting a broken appliance.", n: "\"Washing machine\" es la lavadora.", nEn: "\"Washing machine\" is the clothes washer." },
    "loc-hog16": { e: "Do you need anything from the store?", t: "¿Necesita algo del mercado?", s: "Antes de salir a comprar, ofreciéndote a traer algo.", sEn: "Before going out shopping, offering to bring something.", n: "\"Store\" es la tienda o el mercado.", nEn: "\"Store\" is the shop or market." },
    "loc-hog17": { e: "I'll hang the laundry out to dry.", t: "Voy a tender la ropa para que se seque.", s: "Al hacer la tarea de lavar y tender ropa.", sEn: "When doing the laundry and hanging it.", n: "\"Laundry\" es la ropa para lavar o ya lavada.", nEn: "\"Laundry\" is the clothes to wash or just washed." },
    "loc-hog18": { e: "The sink is clogged, the water won't drain.", t: "El fregadero está tapado, el agua no baja.", s: "Al reportar un fregadero o lavabo tapado.", sEn: "When reporting a blocked sink.", n: "\"Clogged\" es tapado u obstruido.", nEn: "\"Clogged\" means blocked or obstructed." },
    "loc-hog19": { e: "If you don't mind, I'd finish earlier today and come in earlier tomorrow.", t: "Si no le importa, terminaría más temprano hoy y vendría antes mañana.", s: "Al proponer un cambio de horario de forma educada.", sEn: "When politely proposing a schedule change.", n: "\"If you don't mind\" es una forma cortés de pedir algo.", nEn: "\"If you don't mind\" is a polite way to request something." },
    "loc-hog20": { e: "I've already vacuumed, but I still need to clean the bathrooms.", t: "Ya pasé la aspiradora, pero todavía me falta limpiar los baños.", s: "Al reportar lo que ya hiciste y lo que falta.", sEn: "When reporting what's done and what's left.", n: "\"Vacuum\" es pasar la aspiradora; se dice \"VÁ-kium\".", nEn: "\"Vacuum\" means to use the vacuum cleaner." },
    "loc-hog21": { e: "If you leave me a list, I'll buy whatever's missing on the way.", t: "Si me deja una lista, compro todo lo que haga falta de camino.", s: "Al ofrecer hacer las compras de regreso.", sEn: "When offering to do the shopping on your way.", n: "\"Whatever's missing\" significa lo que falte.", nEn: "\"Whatever's missing\" means whatever is needed." },
    "loc-hog22": { e: "I've been cooking all morning, so dinner is almost ready.", t: "Llevo toda la mañana cocinando, así que la cena ya casi está lista.", s: "Al avisar el progreso de la comida.", sEn: "When updating on the meal's progress.", n: "\"I've been cooking\" marca una acción que ha durado un rato.", nEn: "\"I've been cooking\" marks an ongoing action over time." },
    "loc-hog23": { e: "The trash needs taking out, it's full.", t: "Hay que sacar la basura, está llena.", s: "Al notar que la basura debe sacarse.", sEn: "When noticing the trash needs to go out.", n: "\"Take out the trash\" es sacar la basura.", nEn: "\"Take out the trash\" means to remove the garbage." },
    "loc-hog24": { e: "I'm done for today, see you tomorrow.", t: "Ya terminé por hoy, nos vemos mañana.", s: "Al despedirte después de terminar el trabajo.", sEn: "When saying goodbye after finishing work.", n: "\"Done for today\" es haber terminado por el día.", nEn: "\"Done for today\" means finished for the day." },
    // --- entrevista ---
    "loc-ent21": { e: "In my previous job, I led a team of five people for two years.", t: "En mi trabajo anterior, lideré un equipo de cinco personas por dos años.", s: "Al describir tu experiencia de liderazgo en una entrevista.", sEn: "When describing your leadership experience in an interview.", n: "\"Led\" se pronuncia como \"led\", igual que el pasado de \"lead\".", nEn: "\"Led\" is pronounced like \"led\", the past tense of \"lead\"." },
    "loc-ent22": { e: "If you give me the chance, I'd give it my all every single day.", t: "Si me dan la oportunidad, daría lo mejor de mí cada día.", s: "Al cerrar una entrevista mostrando motivación.", sEn: "When closing an interview to show motivation.", n: "\"Give it my all\" suena más natural que \"give my best\".", nEn: "\"Give it my all\" sounds more natural than \"give my best\"." },
    "loc-ent23": { e: "I've improved my English a lot over the past year by practicing daily.", t: "He mejorado mucho mi inglés en el último año practicando a diario.", s: "Cuando te preguntan por tu nivel de inglés.", sEn: "When asked about your English level.", n: "Usa el present perfect \"I've improved\" para logros recientes.", nEn: "Use the present perfect \"I've improved\" for recent achievements." },
    "loc-ent24": { e: "I see myself as someone who's always looking to learn more and grow.", t: "Me considero alguien que siempre busca aprender más y crecer.", s: "Al hablar de tus cualidades personales.", sEn: "When talking about your personal qualities.", n: "\"I see myself as\" es una forma elegante de describirte.", nEn: "\"I see myself as\" is an elegant way to describe yourself." },
    // --- oficina ---
    "loc-ofi21": { e: "If you don't mind, I'll send you the draft before it goes out to everyone.", t: "Si no le molesta, le envío el borrador antes de enviarlo a todos.", s: "Antes de mandar un correo importante a todo el equipo.", sEn: "Before sending an important email to the whole team.", n: "\"If you don't mind\" suaviza la petición y suena cortés.", nEn: "\"If you don't mind\" softens the request and sounds polite." },
    "loc-ofi22": { e: "I haven't had time to go over the report yet, but I'll do it today.", t: "Aún no he tenido tiempo de revisar el reporte, pero lo haré hoy.", s: "Cuando te preguntan por algo pendiente.", sEn: "When someone asks about something still pending.", n: "\"Go over\" significa revisar con detalle.", nEn: "\"Go over\" means to review in detail." },
    "loc-ofi23": { e: "I just wanted to make sure we're on the same page before moving on.", t: "Quería confirmar que estamos alineados antes de seguir.", s: "Antes de avanzar en un proyecto compartido.", sEn: "Before moving ahead on a shared project.", n: "\"On the same page\" significa estar de acuerdo o alineados.", nEn: "\"On the same page\" means to be aligned or in agreement." },
    "loc-ofi24": { e: "Can you let me know when it's ready? No rush.", t: "¿Me avisas cuando lo tengas listo? Sin prisa.", s: "Al delegar una tarea y pedir aviso al terminar.", sEn: "When delegating a task and asking for an update.", n: "\"Let me know\" es la forma estándar de pedir que te avisen.", nEn: "\"Let me know\" is the standard way to ask for an update." },
    // --- cliente-en ---
    "loc-cli21": { e: "I'm really sorry about that; let me see how I can fix it for you.", t: "Lamento mucho lo ocurrido; déjeme ver cómo puedo solucionarlo.", s: "Cuando un cliente reporta un problema y quieres resolverlo.", sEn: "When a customer reports a problem and you want to solve it.", n: "\"Fix it for you\" muestra disposición a ayudar.", nEn: "\"Fix it for you\" shows willingness to help." },
    "loc-cli22": { e: "If you give me a few minutes, I'll check your account and confirm everything.", t: "Si me da unos minutos, reviso su cuenta y le confirmo todo.", s: "Antes de poner al cliente en breve espera para revisar.", sEn: "Before placing the customer on a brief hold to check.", n: "\"A few minutes\" suena más cálido que \"a moment\".", nEn: "\"A few minutes\" sounds warmer than \"a moment\"." },
    "loc-cli23": { e: "I completely understand your frustration, and I'll do everything I can to help.", t: "Entiendo perfectamente su frustración y haré todo lo posible por ayudarle.", s: "Con un cliente molesto que necesita sentirse escuchado.", sEn: "With an upset customer who needs to feel heard.", n: "Validar la emoción del cliente baja la tensión.", nEn: "Validating the customer's emotion lowers tension." },
    "loc-cli24": { e: "Once the refund is processed, you'll get a confirmation email.", t: "Una vez que reciba el reembolso, le llegará un correo de confirmación.", s: "Al explicar los pasos siguientes de un reembolso.", sEn: "When explaining the next steps of a refund.", n: "\"Once... you'll...\" es ideal para explicar procesos.", nEn: "\"Once... you'll...\" is great for explaining processes." },
    // --- reunion-en ---
    "loc-reu21": { e: "Before we wrap up, I want to make sure everyone's on board.", t: "Antes de cerrar, quiero asegurarme de que todos estén de acuerdo.", s: "Al final de una reunión, antes de tomar una decisión.", sEn: "At the end of a meeting, before making a decision.", n: "\"On board\" significa estar de acuerdo con el plan.", nEn: "\"On board\" means to agree with the plan." },
    "loc-reu22": { e: "If there are no objections, let's go ahead with that proposal.", t: "Si no hay objeciones, sigamos adelante con esa propuesta.", s: "Cuando quieres aprobar algo y avanzar.", sEn: "When you want to approve something and move on.", n: "\"Go ahead with\" significa proceder con algo.", nEn: "\"Go ahead with\" means to proceed with something." },
    "loc-reu23": { e: "I'd like to hear everyone's thoughts before we decide.", t: "Me gustaría escuchar la opinión de todos antes de decidir.", s: "Para abrir la discusión antes de cerrar un tema.", sEn: "To open the discussion before closing a topic.", n: "\"Thoughts\" es una forma natural de decir \"opiniones\".", nEn: "\"Thoughts\" is a natural way to say \"opinions\"." },
    "loc-reu24": { e: "I've taken notes on the key points and I'll send them after the meeting.", t: "Tomé nota de los puntos y se los enviaré después de la reunión.", s: "Cuando eres quien toma notas en la reunión.", sEn: "When you're the one taking notes in the meeting.", n: "\"Key points\" significa los puntos más importantes.", nEn: "\"Key points\" means the most important points." },
    // --- resenas-en ---
    "loc-res21": { e: "If you had a good experience, we'd love it if you left us a review.", t: "Si tuviste una buena experiencia, nos encantaría que dejaras una reseña.", s: "Al pedirle a un cliente satisfecho que reseñe.", sEn: "When asking a happy customer to leave a review.", n: "\"We'd love it if you...\" es una petición amable.", nEn: "\"We'd love it if you...\" is a friendly request." },
    "loc-res22": { e: "I'd come back in a heartbeat because the service was amazing.", t: "Volvería sin pensarlo porque la atención fue increíble.", s: "Al escribir una reseña muy positiva.", sEn: "When writing a very positive review.", n: "\"In a heartbeat\" significa sin dudarlo, al instante.", nEn: "\"In a heartbeat\" means without hesitation, instantly." },
    "loc-res23": { e: "What I liked most was how friendly the whole staff was.", t: "Lo que más me gustó fue lo amable que fue todo el personal.", s: "Al destacar lo mejor de tu experiencia en una reseña.", sEn: "When highlighting the best part of your experience in a review.", n: "\"What I liked most was...\" es una estructura típica de reseñas.", nEn: "\"What I liked most was...\" is a typical review structure." },
    "loc-res24": { e: "We appreciate every comment, as it helps us improve our service.", t: "Apreciamos cada comentario, ya que nos ayuda a mejorar el servicio.", s: "Al responder comentarios en redes como negocio.", sEn: "When replying to comments on social media as a business.", n: "\"As it helps us\" conecta dos ideas de forma profesional.", nEn: "\"As it helps us\" links two ideas professionally." },
    // --- cv-en ---
    "loc-cv13": { e: "I'm attaching my cover letter along with my resume.", t: "Adjunto mi carta de presentación junto con mi currículum.", s: "Al postularte por correo a un puesto.", sEn: "When applying for a job by email.", n: "\"Cover letter\" es la carta de presentación; \"resume\" el CV en EE. UU.", nEn: "\"Cover letter\" is the intro letter; \"resume\" is the CV in the US." },
    "loc-cv14": { e: "I'm proficient in Excel and other office tools.", t: "Manejo Excel a nivel avanzado y otras herramientas de oficina.", s: "Al listar tus habilidades técnicas en el CV.", sEn: "When listing your technical skills on your CV.", n: "\"Proficient in\" suena más profesional que \"good at\".", nEn: "\"Proficient in\" sounds more professional than \"good at\"." },
    "loc-cv15": { e: "I'm available for an interview anytime this week.", t: "Estoy disponible para una entrevista cuando gusten esta semana.", s: "Al cerrar tu carta o correo de postulación.", sEn: "When closing your cover letter or application email.", n: "\"Anytime\" se escribe junto cuando significa \"cuando sea\".", nEn: "\"Anytime\" is one word when it means \"whenever\"." },
    "loc-cv16": { e: "I worked as an administrative assistant for three years.", t: "Trabajé como asistente administrativa durante tres años.", s: "Al describir tu puesto anterior.", sEn: "When describing your previous role.", n: "\"Administrative\" lleva el acento en la segunda sílaba.", nEn: "\"Administrative\" is stressed on the second syllable." },
    "loc-cv17": { e: "I have a certificate in sales from a recognized institute.", t: "Tengo un certificado en ventas de un instituto reconocido.", s: "Al mencionar tu formación o certificaciones.", sEn: "When mentioning your training or certifications.", n: "\"Certificate\" (documento) suena distinto a \"certification\".", nEn: "\"Certificate\" (document) sounds different from \"certification\"." },
    "loc-cv18": { e: "I found your job posting on LinkedIn and I'm very interested.", t: "Encontré su vacante en LinkedIn y estoy muy interesado.", s: "Al iniciar tu correo explicando cómo viste el puesto.", sEn: "When starting your email explaining how you saw the job.", n: "\"Job posting\" es el anuncio de la vacante.", nEn: "\"Job posting\" is the job advertisement." },
    "loc-cv19": { e: "I believe my experience is a great fit for what you're looking for.", t: "Creo que mi experiencia encaja muy bien con lo que buscan.", s: "Al argumentar por qué eres buen candidato.", sEn: "When arguing why you're a good candidate.", n: "\"A great fit\" significa que encajas perfectamente.", nEn: "\"A great fit\" means you match perfectly." },
    "loc-cv20": { e: "Throughout my career, I've developed strong communication skills.", t: "A lo largo de mi carrera he desarrollado fuertes habilidades de comunicación.", s: "Al resaltar competencias clave en tu carta.", sEn: "When highlighting key competencies in your letter.", n: "\"Throughout\" significa \"a lo largo de todo\".", nEn: "\"Throughout\" means \"all the way through\"." },
    "loc-cv21": { e: "I'm really excited about the chance to bring value to your team.", t: "Me motiva mucho la oportunidad de aportar valor a su equipo.", s: "Para cerrar tu carta con entusiasmo.", sEn: "To close your letter with enthusiasm.", n: "\"Bring value\" suena más profesional que \"help\".", nEn: "\"Bring value\" sounds more professional than \"help\"." },
    "loc-cv22": { e: "While I'm new to this field, I learn quickly and I'm fully committed.", t: "Si bien soy nuevo en este sector, aprendo con rapidez y compromiso.", s: "Cuando postulas a algo sin experiencia directa.", sEn: "When applying for something without direct experience.", n: "\"While\" aquí significa \"aunque\".", nEn: "\"While\" here means \"although\"." },
    "loc-cv23": { e: "I'm open to relocating if needed for the position.", t: "Estoy abierto a reubicarme si es necesario para el puesto.", s: "Cuando el trabajo podría requerir mudarte.", sEn: "When the job might require you to move.", n: "\"Open to\" significa estar dispuesto a algo.", nEn: "\"Open to\" means willing to do something." },
    "loc-cv24": { e: "Here's my contact number in case you have any questions.", t: "Aquí está mi número de contacto por si tienen preguntas.", s: "Al dejar tus datos al final del CV o correo.", sEn: "When leaving your details at the end of your CV or email.", n: "\"Here's\" es la contracción de \"here is\".", nEn: "\"Here's\" is the contraction of \"here is\"." },
    // --- negociacion ---
    "loc-neg19": { e: "If we could adjust the payment terms, we'd close today.", t: "Si pudiéramos ajustar el plazo de pago, cerraríamos hoy mismo.", s: "Al negociar condiciones para cerrar un trato.", sEn: "When negotiating terms to close a deal.", n: "\"Payment terms\" son las condiciones de pago.", nEn: "\"Payment terms\" are the payment conditions." },
    "loc-neg20": { e: "I understand where you're coming from, but that price is out of our budget.", t: "Entiendo su punto, pero ese precio queda fuera de nuestro presupuesto.", s: "Al rechazar un precio sin sonar grosero.", sEn: "When rejecting a price without sounding rude.", n: "\"Where you're coming from\" significa entender el punto de vista.", nEn: "\"Where you're coming from\" means understanding their point of view." },
    "loc-neg21": { e: "I'm willing to give on this if you give on that.", t: "Estoy dispuesto a ceder en esto si usted cede en aquello.", s: "Al proponer un intercambio de concesiones.", sEn: "When proposing a trade of concessions.", n: "\"Give on\" aquí significa ceder en un punto.", nEn: "\"Give on\" here means to concede on a point." },
    "loc-neg22": { e: "How about we meet in the middle and split the difference?", t: "¿Qué tal si lo dividimos a la mitad y partimos la diferencia?", s: "Cuando ambos están cerca de un acuerdo.", sEn: "When both sides are close to a deal.", n: "\"Meet in the middle\" significa llegar a un punto medio.", nEn: "\"Meet in the middle\" means to reach a compromise." },
    "loc-neg23": { e: "I need to see the numbers before I commit to anything.", t: "Necesito ver los números antes de comprometerme.", s: "Cuando no quieres aceptar sin revisar datos.", sEn: "When you don't want to accept without reviewing data.", n: "\"The numbers\" se refiere a las cifras del trato.", nEn: "\"The numbers\" refers to the figures of the deal." },
    "loc-neg24": { e: "Can we go over the terms one more time before signing?", t: "¿Podemos revisar las condiciones una vez más antes de firmar?", s: "Antes de cerrar para confirmar todo.", sEn: "Before closing, to confirm everything.", n: "\"Go over the terms\" significa repasar las condiciones.", nEn: "\"Go over the terms\" means to review the conditions." },
    // --- bpo-en ---
    "loc-bpo23": { e: "To protect your account, I'll need to ask you a couple of security questions.", t: "Para proteger su cuenta, necesito hacerle un par de preguntas de seguridad.", s: "Antes de dar acceso a información sensible en una llamada.", sEn: "Before giving access to sensitive information on a call.", n: "\"A couple of\" significa \"un par de\".", nEn: "\"A couple of\" means \"a pair of / two\"." },
    "loc-bpo24": { e: "If the call drops, I'll call you back on this number.", t: "Si la llamada se corta, le devolveré la llamada a este número.", s: "Al inicio de la llamada, por si se pierde la conexión.", sEn: "At the start of the call, in case the connection is lost.", n: "\"The call drops\" significa que la llamada se corta.", nEn: "\"The call drops\" means the call gets cut off." },
    // --- tech-en ---
    "loc-tech23": { e: "Once you approve the PR, I'll merge it and kick off the deploy.", t: "Una vez que apruebes el PR, lo fusiono y lanzo el despliegue.", s: "Coordinando el flujo de trabajo de código con tu equipo.", sEn: "Coordinating the code workflow with your team.", n: "\"Kick off\" significa iniciar o lanzar algo.", nEn: "\"Kick off\" means to start or launch something." },
    "loc-tech24": { e: "It looks like the bug only shows up when the user isn't logged in.", t: "Parece que el bug solo aparece cuando el usuario no ha iniciado sesión.", s: "Al describir cómo reproducir un error.", sEn: "When describing how to reproduce a bug.", n: "\"Shows up\" significa aparecer; \"logged in\", con sesión iniciada.", nEn: "\"Shows up\" means to appear; \"logged in\" means signed in." },
    // --- videocall-en ---
    "loc-vc19": { e: "If you can't hear me, drop it in the chat and I'll rejoin.", t: "Si no logran oírme, escríbanlo en el chat y vuelvo a conectarme.", s: "Cuando temes tener problemas de audio en la llamada.", sEn: "When you fear audio issues on the call.", n: "\"Rejoin\" significa volver a entrar a la reunión.", nEn: "\"Rejoin\" means to join the meeting again." },
    "loc-vc20": { e: "Sorry, I think we talked over each other; go ahead, you first.", t: "Perdón, creo que hablamos al mismo tiempo; adelante, tú primero.", s: "Cuando dos personas hablan a la vez en una videollamada.", sEn: "When two people speak at the same time on a video call.", n: "\"Talk over each other\" es hablar encima del otro.", nEn: "\"Talk over each other\" means to speak at the same time." },
    "loc-vc21": { e: "Before we start, let me put the agenda up on the screen.", t: "Antes de empezar, déjenme compartir la agenda en pantalla.", s: "Al abrir una videollamada mostrando los temas.", sEn: "When opening a video call by showing the topics.", n: "\"Put up on the screen\" es mostrar en pantalla.", nEn: "\"Put up on the screen\" means to display on screen." },
    "loc-vc22": { e: "If my video freezes, carry on without me and I'll catch up.", t: "Si se me congela el video, sigan sin mí y me reincorporo.", s: "Cuando tu conexión es inestable durante la llamada.", sEn: "When your connection is unstable during the call.", n: "\"Catch up\" significa ponerse al día.", nEn: "\"Catch up\" means to get back up to speed." },
    "loc-vc23": { e: "Let me give you control of my screen so you can navigate.", t: "Déjame compartir el control con ustedes para que naveguen.", s: "Al pasar el control remoto en una herramienta compartida.", sEn: "When handing over remote control in a shared tool.", n: "\"Give control\" es ceder el control de la pantalla.", nEn: "\"Give control\" means to hand over screen control." },
    "loc-vc24": { e: "Do I sound better if I get closer to the mic?", t: "¿Me escuchan mejor si me acerco al micrófono?", s: "Cuando crees que el audio no se oye bien.", sEn: "When you think your audio isn't coming through well.", n: "\"Mic\" es la forma corta y común de \"microphone\".", nEn: "\"Mic\" is the short, common form of \"microphone\"." },
    // --- ventas-pro ---
    "loc-vp13": { e: "Let me walk you through how it works step by step.", t: "Permítame mostrarle cómo funciona paso a paso.", s: "Al iniciar una demostración del producto.", sEn: "When starting a product demonstration.", n: "\"Walk you through\" significa guiarte paso a paso.", nEn: "\"Walk you through\" means to guide you step by step." },
    "loc-vp14": { e: "Most clients start with the basic plan and upgrade later.", t: "Muchos clientes empiezan con el plan básico y luego mejoran.", s: "Al recomendar un plan inicial al cliente.", sEn: "When recommending a starter plan to the customer.", n: "\"Upgrade\" significa pasar a un plan superior.", nEn: "\"Upgrade\" means to move to a higher plan." },
    "loc-vp15": { e: "The first week is free, no credit card required.", t: "La primera semana es gratis, sin tarjeta de crédito.", s: "Al ofrecer una prueba gratuita.", sEn: "When offering a free trial.", n: "\"Free\" se pronuncia con la \"i\" larga: \"frii\".", nEn: "\"Free\" is pronounced with a long \"i\": \"frii\"." },
    "loc-vp16": { e: "You can cancel anytime, no questions asked.", t: "Puede cancelar cuando quiera, sin preguntas.", s: "Para reducir el miedo del cliente a comprometerse.", sEn: "To ease the customer's fear of commitment.", n: "\"No questions asked\" significa sin complicaciones.", nEn: "\"No questions asked\" means without any hassle." },
    "loc-vp17": { e: "What's holding you back from deciding today?", t: "¿Qué le impide tomar la decisión hoy?", s: "Para descubrir las objeciones del cliente.", sEn: "To uncover the customer's objections.", n: "\"Holding you back\" significa lo que te frena.", nEn: "\"Holding you back\" means what's stopping you." },
    "loc-vp18": { e: "I'll give you a welcome discount on your first order.", t: "Le ofrezco un descuento de bienvenida en su primer pedido.", s: "Para incentivar la primera compra.", sEn: "To encourage the first purchase.", n: "\"Discount\" lleva el acento en la primera sílaba.", nEn: "\"Discount\" is stressed on the first syllable." },
    "loc-vp19": { e: "If you try it this week, I'll throw in the setup at no cost.", t: "Si lo prueba esta semana, le incluyo la instalación sin costo.", s: "Para cerrar la venta con un incentivo extra.", sEn: "To close the sale with an extra incentive.", n: "\"Throw in\" significa incluir algo gratis.", nEn: "\"Throw in\" means to include something for free." },
    "loc-vp20": { e: "I get your hesitation; many clients felt the same until they tried it.", t: "Entiendo su duda; muchos clientes sentían lo mismo hasta que lo probaron.", s: "Al manejar una objeción de un cliente dudoso.", sEn: "When handling an objection from a hesitant client.", n: "Esta técnica (felt-felt-found) suaviza las objeciones.", nEn: "This technique (felt-felt-found) softens objections." },
    "loc-vp21": { e: "What sets our product apart is the support that comes with it.", t: "Lo que diferencia a nuestro producto es el soporte que viene incluido.", s: "Al explicar tu ventaja frente a la competencia.", sEn: "When explaining your edge over competitors.", n: "\"Sets it apart\" significa lo que lo hace diferente.", nEn: "\"Sets it apart\" means what makes it different." },
    "loc-vp22": { e: "If you give me ten minutes, I'll show you exactly how this would save you money.", t: "Si me da diez minutos, le muestro exactamente cómo le ahorraría dinero.", s: "Para conseguir tiempo del cliente con una promesa de valor.", sEn: "To get the customer's time with a value promise.", n: "\"Would save you\" usa el condicional para proyectar el beneficio.", nEn: "\"Would save you\" uses the conditional to project the benefit." },
    "loc-vp23": { e: "Let me send you a success story similar to yours.", t: "Déjeme enviarle un caso de éxito parecido al suyo.", s: "Para generar confianza con un ejemplo real.", sEn: "To build trust with a real example.", n: "\"Success story\" es un caso de éxito o testimonio.", nEn: "\"Success story\" is a case study or testimonial." },
    "loc-vp24": { e: "There's no long-term commitment, so it's risk-free.", t: "No hay compromiso de permanencia, así que no hay riesgo.", s: "Para tranquilizar a un cliente indeciso.", sEn: "To reassure an undecided customer.", n: "\"Long-term commitment\" es compromiso a largo plazo.", nEn: "\"Long-term commitment\" is a long-term obligation." },
    // --- finanzas-en ---
    "loc-fin19": { e: "If the payment doesn't come in by Friday, a late fee will apply.", t: "Si el pago no entra antes del viernes, se aplicará un recargo.", s: "Al recordar a un cliente una fecha de pago.", sEn: "When reminding a client of a payment date.", n: "\"Late fee\" es el recargo por pago tardío.", nEn: "\"Late fee\" is the charge for a late payment." },
    "loc-fin20": { e: "Once they approve the quote, we'll issue the formal invoice.", t: "Una vez que aprueben la cotización, emitimos la factura formal.", s: "Al explicar el proceso de facturación.", sEn: "When explaining the billing process.", n: "\"Issue an invoice\" significa emitir una factura.", nEn: "\"Issue an invoice\" means to send out an invoice." },
    "loc-fin21": { e: "We've spent more than planned, so we need to adjust the budget.", t: "Hemos gastado más de lo previsto, así que debemos ajustar el presupuesto.", s: "En una revisión de gastos del mes.", sEn: "During a monthly expense review.", n: "\"More than planned\" significa más de lo presupuestado.", nEn: "\"More than planned\" means over what was budgeted." },
    "loc-fin22": { e: "Can you confirm which account I should transfer to?", t: "¿Me confirma a qué cuenta hago la transferencia?", s: "Antes de hacer un pago por transferencia.", sEn: "Before making a bank transfer payment.", n: "\"Transfer to\" siempre lleva la preposición \"to\".", nEn: "\"Transfer to\" always takes the preposition \"to\"." },
    "loc-fin23": { e: "The payment was split into three installments.", t: "El pago se dividió en tres cuotas.", s: "Al acordar pagos a plazos con un cliente.", sEn: "When agreeing on installment payments with a client.", n: "\"Installments\" son las cuotas o pagos parciales.", nEn: "\"Installments\" are the partial payments." },
    "loc-fin24": { e: "We're still waiting on the manager's approval to proceed.", t: "Todavía estamos esperando la aprobación del gerente para seguir.", s: "Cuando un pago o gasto está detenido por autorización.", sEn: "When a payment or expense is held up by authorization.", n: "\"Waiting on\" significa esperar a que algo ocurra.", nEn: "\"Waiting on\" means waiting for something to happen." },
    // --- logistica-en ---
    "loc-log13": { e: "The order is packed and ready for pickup.", t: "El pedido está empacado y listo para recoger.", s: "Cuando confirmas que un pedido está listo.", sEn: "When confirming an order is ready.", n: "\"Packed\" significa empacado o embalado.", nEn: "\"Packed\" means packed up or boxed." },
    "loc-log14": { e: "The truck leaves at six in the morning sharp.", t: "El camión sale a las seis de la mañana en punto.", s: "Al informar el horario de salida del transporte.", sEn: "When informing the transport departure time.", n: "\"Sharp\" después de la hora significa \"en punto\".", nEn: "\"Sharp\" after a time means \"exactly / on the dot\"." },
    "loc-log15": { e: "I'll email you the tracking link in a minute.", t: "Le envío la guía de rastreo por correo en un minuto.", s: "Al compartir el seguimiento del envío.", sEn: "When sharing the shipment tracking.", n: "\"Tracking link\" es el enlace para rastrear el envío.", nEn: "\"Tracking link\" is the link to track the shipment." },
    "loc-log16": { e: "One box is missing from the shipment we received.", t: "Falta una caja en el envío que recibimos.", s: "Al reportar un faltante en una entrega.", sEn: "When reporting a missing item in a delivery.", n: "\"Missing\" significa que falta algo.", nEn: "\"Missing\" means something is absent." },
    "loc-log17": { e: "The package arrived damaged, so we need a replacement.", t: "El paquete llegó dañado, así que necesitamos un reemplazo.", s: "Al reclamar por un producto dañado en tránsito.", sEn: "When claiming for a product damaged in transit.", n: "\"Damaged\" se pronuncia \"DA-mecht\", no \"da-meich\".", nEn: "\"Damaged\" is pronounced \"DA-mecht\", not \"da-meich\"." },
    "loc-log18": { e: "I need to reschedule the delivery for next week.", t: "Necesito reprogramar la entrega para la próxima semana.", s: "Cuando no podrás recibir el envío en la fecha original.", sEn: "When you can't receive the shipment on the original date.", n: "\"Reschedule\" significa cambiar la fecha programada.", nEn: "\"Reschedule\" means to change the scheduled date." },
    "loc-log19": { e: "If the shipment gets held at customs, we'll let you know right away.", t: "Si el envío se retiene en aduana, le avisaremos de inmediato.", s: "Al advertir a un cliente sobre posibles retrasos aduaneros.", sEn: "When warning a client about possible customs delays.", n: "\"Held at customs\" significa retenido en la aduana.", nEn: "\"Held at customs\" means held up at customs." },
    "loc-log20": { e: "The supplier confirmed the order will ship as soon as payment clears.", t: "El proveedor confirmó que el pedido saldrá en cuanto reciba el pago.", s: "Al coordinar el envío con un proveedor.", sEn: "When coordinating shipment with a supplier.", n: "\"Payment clears\" significa que el pago se acredita.", nEn: "\"Payment clears\" means the payment goes through." },
    "loc-log21": { e: "Since the container was delayed, we need to update the client on the new timeline.", t: "Dado que el contenedor se retrasó, debemos avisar al cliente del nuevo plazo.", s: "Cuando un retraso afecta la fecha prometida.", sEn: "When a delay affects the promised date.", n: "\"Timeline\" se refiere al cronograma o plazos.", nEn: "\"Timeline\" refers to the schedule or deadlines." },
    "loc-log22": { e: "Before dispatching, make sure the packaging meets the requirements.", t: "Antes de despachar, asegúrese de que el embalaje cumpla con los requisitos.", s: "Al dar instrucciones de preparación de un envío.", sEn: "When giving instructions to prepare a shipment.", n: "\"Dispatching\" significa despachar o enviar mercancía.", nEn: "\"Dispatching\" means sending out goods." },
    "loc-log23": { e: "The courier tried to deliver twice but no one was home.", t: "El courier intentó entregar dos veces pero no había nadie.", s: "Al explicar por qué un paquete no se entregó.", sEn: "When explaining why a package wasn't delivered.", n: "\"Courier\" es el mensajero o servicio de paquetería.", nEn: "\"Courier\" is the delivery person or service." },
    "loc-log24": { e: "The warehouse closes at five, so send it before then.", t: "La bodega cierra a las cinco, así que envíalo antes.", s: "Al coordinar horarios con el almacén.", sEn: "When coordinating timing with the warehouse.", n: "\"Warehouse\" es la bodega o almacén.", nEn: "\"Warehouse\" is the storage facility." },
    // --- feedback-en ---
    "loc-fb17": { e: "You've improved a lot, but I think you can still polish your follow-up.", t: "Has mejorado mucho, pero creo que aún puedes pulir tu seguimiento.", s: "En una evaluación de desempeño con un empleado.", sEn: "In a performance review with an employee.", n: "\"Polish\" aquí significa pulir o perfeccionar algo.", nEn: "\"Polish\" here means to refine or perfect something." },
    "loc-fb18": { e: "Next time, I'd appreciate a heads-up if something falls behind.", t: "Me gustaría que la próxima vez me avisaras antes si algo se atrasa.", s: "Al pedir mejor comunicación sobre retrasos.", sEn: "When asking for better communication about delays.", n: "\"Heads-up\" es un aviso anticipado.", nEn: "\"Heads-up\" is an advance warning." },
    "loc-fb19": { e: "When you deliver on time, you make everyone's job easier.", t: "Cuando entregas a tiempo, le facilitas el trabajo a todo el equipo.", s: "Al reconocer el impacto positivo de un empleado.", sEn: "When recognizing an employee's positive impact.", n: "\"Make someone's job easier\" es facilitar el trabajo de alguien.", nEn: "\"Make someone's job easier\" means to ease their work." },
    "loc-fb20": { e: "If you could focus on one thing this month, what would it be?", t: "Si pudieras enfocarte en una cosa este mes, ¿cuál sería?", s: "Para ayudar a un empleado a fijar una prioridad.", sEn: "To help an employee set a priority.", n: "Esta pregunta invita a la reflexión sin presionar.", nEn: "This question invites reflection without pressure." },
    "loc-fb21": { e: "I loved how you handled that difficult customer yesterday.", t: "Me encantó cómo manejaste a ese cliente difícil ayer.", s: "Al dar reconocimiento específico y positivo.", sEn: "When giving specific, positive recognition.", n: "\"Handled\" significa manejar o gestionar una situación.", nEn: "\"Handled\" means to manage or deal with a situation." },
    "loc-fb22": { e: "Let's take this as a chance to grow together.", t: "Tomemos esto como una oportunidad para crecer juntos.", s: "Al reencuadrar un error como aprendizaje.", sEn: "When reframing a mistake as a learning opportunity.", n: "\"Take this as a chance\" suaviza una crítica.", nEn: "\"Take this as a chance\" softens criticism." },
    "loc-fb23": { e: "I'm really proud of you and the progress you've made.", t: "Estoy muy orgulloso de ti y del progreso que has hecho.", s: "Al felicitar a un miembro del equipo.", sEn: "When praising a team member.", n: "\"Proud of you\" expresa orgullo de forma cálida.", nEn: "\"Proud of you\" expresses pride warmly." },
    "loc-fb24": { e: "My door is always open if you need to talk about anything.", t: "Mi puerta siempre está abierta si necesitas hablar de algo.", s: "Para mostrarte disponible como líder o jefe.", sEn: "To show you're approachable as a leader or manager.", n: "\"My door is always open\" es una expresión de cercanía.", nEn: "\"My door is always open\" is an expression of openness." },
    // --- networking-en ---
    "loc-net17": { e: "I've heard great things about your company; I'd love to learn more.", t: "He oído cosas muy buenas de tu empresa; me encantaría saber más.", s: "Al iniciar una conversación en un evento profesional.", sEn: "When starting a conversation at a professional event.", n: "\"Heard great things\" es un cumplido natural para romper el hielo.", nEn: "\"Heard great things\" is a natural ice-breaking compliment." },
    "loc-net18": { e: "If you ever need anything from my side, don't hesitate to reach out.", t: "Si alguna vez necesitas algo de mi área, no dudes en escribirme.", s: "Al ofrecer ayuda y cerrar una conversación.", sEn: "When offering help and closing a conversation.", n: "\"Reach out\" significa contactar o escribir.", nEn: "\"Reach out\" means to get in touch." },
    "loc-net19": { e: "I was actually just thinking of someone with your background for a project.", t: "Justo estaba pensando en alguien con tu perfil para un proyecto.", s: "Cuando ves una oportunidad de colaboración.", sEn: "When you spot a collaboration opportunity.", n: "\"Background\" significa perfil, formación o trayectoria.", nEn: "\"Background\" means profile, training or experience." },
    "loc-net20": { e: "I'd love to grab a coffee and hear more about what you do.", t: "Me encantaría tomarnos un café y conocer mejor lo que haces.", s: "Al proponer una reunión informal para seguir conversando.", sEn: "When proposing an informal meeting to keep talking.", n: "\"Grab a coffee\" es una forma casual de invitar a charlar.", nEn: "\"Grab a coffee\" is a casual way to invite a chat." },
    "loc-net21": { e: "Is there anyone on your team I should meet?", t: "¿Trabajas con alguien que yo deba conocer?", s: "Para pedir una presentación a otros contactos.", sEn: "To ask for an introduction to other contacts.", n: "Es una forma sutil de pedir referidos.", nEn: "It's a subtle way to ask for referrals." },
    "loc-net22": { e: "Follow me and I'll tag you at the event later.", t: "Sígueme y te etiqueto en el evento.", s: "Al intercambiar redes sociales en un evento.", sEn: "When exchanging social media at an event.", n: "\"Tag\" significa etiquetar a alguien en una publicación.", nEn: "\"Tag\" means to mention someone in a post." },
    "loc-net23": { e: "How did you hear about this event?", t: "¿Cómo te llegó la invitación a este evento?", s: "Para iniciar una charla casual con un desconocido.", sEn: "To start casual small talk with a stranger.", n: "\"Hear about\" significa enterarse de algo.", nEn: "\"Hear about\" means to find out about something." },
    "loc-net24": { e: "I'll send you my profile so we stay connected.", t: "Te envío mi perfil para que estemos conectados.", s: "Al cerrar el intercambio de contactos.", sEn: "When closing the exchange of contacts.", n: "\"Stay connected\" significa mantenerse en contacto.", nEn: "\"Stay connected\" means to keep in touch." },
    // --- salud-pro-en ---
    "loc-hc15": { e: "Step on the scale, please, so I can check your weight.", t: "Súbase a la báscula, por favor, para revisar su peso.", s: "Durante la toma de signos vitales de un paciente.", sEn: "During a patient's vital signs check.", n: "\"Scale\" es la báscula; \"step on\" es subirse.", nEn: "\"Scale\" is the weighing scale; \"step on\" is to get on it." },
    "loc-hc16": { e: "I'm going to draw some blood; you'll feel a small pinch.", t: "Voy a sacarle una muestra de sangre; sentirá un pequeño pinchazo.", s: "Antes de tomar una muestra de sangre.", sEn: "Before taking a blood sample.", n: "\"Draw blood\" es la expresión médica para sacar sangre.", nEn: "\"Draw blood\" is the medical term for taking a blood sample." },
    "loc-hc17": { e: "Please lie down here while I examine you.", t: "Recuéstese aquí, por favor, mientras lo examino.", s: "Al preparar al paciente para una revisión.", sEn: "When preparing the patient for an examination.", n: "\"Lie down\" es recostarse; no confundir con \"lay\".", nEn: "\"Lie down\" means to recline; don't confuse with \"lay\"." },
    "loc-hc18": { e: "Take the medication with food to avoid an upset stomach.", t: "Tómese el medicamento con comida para evitar malestar estomacal.", s: "Al dar indicaciones sobre un medicamento.", sEn: "When giving instructions about a medication.", n: "\"With food\" significa junto con la comida.", nEn: "\"With food\" means along with a meal." },
    "loc-hc19": { e: "The doctor will see you shortly, please have a seat.", t: "El doctor lo verá en unos minutos, tome asiento por favor.", s: "En recepción o sala de espera de una clínica.", sEn: "At the reception or waiting room of a clinic.", n: "\"Shortly\" significa en poco tiempo, pronto.", nEn: "\"Shortly\" means in a short while, soon." },
    "loc-hc20": { e: "Does it hurt when I press here?", t: "¿Le duele cuando presiono aquí?", s: "Durante una exploración física del paciente.", sEn: "During a physical examination of the patient.", n: "\"Press\" significa presionar; \"hurt\", doler.", nEn: "\"Press\" means to push down; \"hurt\" means to ache." },
    "loc-hc21": { e: "We need to schedule a follow-up appointment in two weeks.", t: "Necesitamos programar un control de seguimiento en dos semanas.", s: "Al cerrar una consulta y planear el seguimiento.", sEn: "When closing a consultation and planning follow-up.", n: "\"Follow-up appointment\" es una cita de seguimiento.", nEn: "\"Follow-up appointment\" is a check-up visit." },
    "loc-hc22": { e: "If the fever doesn't go down in two days, you'll need to come back for a check-up.", t: "Si la fiebre no baja en dos días, debe regresar para una revisión.", s: "Al dar instrucciones de alta a un paciente.", sEn: "When giving discharge instructions to a patient.", n: "\"Go down\" aquí significa bajar la fiebre.", nEn: "\"Go down\" here means for the fever to drop." },
    "loc-hc23": { e: "Before we operate, we'll need you to sign the consent form.", t: "Antes de operarlo, necesitamos que firme el consentimiento.", s: "Antes de un procedimiento quirúrgico.", sEn: "Before a surgical procedure.", n: "\"Consent form\" es el formulario de consentimiento.", nEn: "\"Consent form\" is the consent document." },
    "loc-hc24": { e: "Keep the wound clean and dry for the next few days.", t: "Mantenga la herida limpia y seca por unos días.", s: "Al dar cuidados posteriores a una herida.", sEn: "When giving aftercare instructions for a wound.", n: "\"Wound\" se pronuncia \"uund\", no \"uaund\".", nEn: "\"Wound\" (injury) is pronounced \"woond\", not \"wownd\"." },
    // --- gramatica-en ---
    "loc-gra15": { e: "They are my friends from school.", t: "Ellos son mis amigos de la escuela.", s: "Cuando hablas de varias personas con el verbo \"to be\".", sEn: "When you talk about several people with the verb \"to be\".", n: "\"They are\" se usa para plural; se contrae como \"they're\".", nEn: "\"They are\" is used for plurals; it contracts to \"they're\"." },
    "loc-gra16": { e: "I'm not hungry, I just ate.", t: "No tengo hambre, acabo de comer.", s: "Para negar con el verbo \"to be\" en presente.", sEn: "To make a negative with the verb \"to be\" in the present.", n: "En inglés \"tener hambre\" se dice \"to be hungry\", no \"to have hunger\".", nEn: "In English you \"are hungry\", you don't \"have hunger\"." },
    "loc-gra17": { e: "Do you have any siblings, or are you an only child?", t: "¿Tienes hermanos, o eres hijo único?", s: "Para hacer una pregunta en presente simple con \"do\".", sEn: "To ask a present simple question with \"do\".", n: "Las preguntas en presente simple usan \"do/does\" + verbo base.", nEn: "Present simple questions use \"do/does\" + base verb." },
    "loc-gra18": { e: "She doesn't work on Sundays, so she sleeps in.", t: "Ella no trabaja los domingos, así que duerme hasta tarde.", s: "Para negar en presente simple en tercera persona.", sEn: "To make a third-person present simple negative.", n: "Con \"he/she/it\" se usa \"doesn't\" y el verbo va sin \"-s\".", nEn: "With \"he/she/it\" use \"doesn't\" and the verb drops the \"-s\"." },
    "loc-gra19": { e: "There are a lot of people at the party tonight.", t: "Hay mucha gente en la fiesta esta noche.", s: "Para decir que algo existe en plural: \"there are\".", sEn: "To say something exists in the plural: \"there are\".", n: "\"There is\" para singular, \"there are\" para plural.", nEn: "\"There is\" for singular, \"there are\" for plural." },
    "loc-gra20": { e: "If I had more time, I would learn to play the piano.", t: "Si tuviera más tiempo, aprendería a tocar el piano.", s: "Para hablar de algo hipotético o poco probable.", sEn: "To talk about something hypothetical or unlikely.", n: "Segundo condicional: \"if\" + pasado, \"would\" + verbo base.", nEn: "Second conditional: \"if\" + past, \"would\" + base verb." },
    "loc-gra21": { e: "The book I'm reading is very interesting.", t: "El libro que estoy leyendo es muy interesante.", s: "Para describir algo con una cláusula relativa.", sEn: "To describe something with a relative clause.", n: "El \"that/which\" se puede omitir cuando es objeto de la frase.", nEn: "\"That/which\" can be dropped when it's the object of the clause." },
    "loc-gra22": { e: "Although he was tired, he finished the work.", t: "Aunque estaba cansado, terminó el trabajo.", s: "Para conectar dos ideas con contraste.", sEn: "To connect two ideas with a contrast.", n: "\"Although\" introduce una idea contraria, como \"aunque\".", nEn: "\"Although\" introduces a contrasting idea, like \"aunque\"." },
    "loc-gra23": { e: "I know the woman who lives next door.", t: "Conozco a la mujer que vive al lado.", s: "Para identificar a una persona con \"who\".", sEn: "To identify a person with \"who\".", n: "Usa \"who\" para personas y \"which\" para cosas.", nEn: "Use \"who\" for people and \"which\" for things." },
    "loc-gra24": { e: "I don't know what to say, this is amazing.", t: "No sé qué decir, esto es increíble.", s: "Para expresar duda con \"what to + verbo\".", sEn: "To express uncertainty with \"what to + verb\".", n: "\"What to say\" = qué decir; el infinitivo no cambia.", nEn: "\"What to say\" means \"qué decir\"; the infinitive stays the same." },
    // --- examen ---
    "loc-exa15": { e: "Close your books and listen carefully.", t: "Cierren el libro y escuchen con atención.", s: "Instrucción del profesor en clase.", sEn: "A teacher's instruction in class.", n: "El imperativo en inglés usa el verbo base sin sujeto.", nEn: "The imperative in English uses the base verb with no subject." },
    "loc-exa16": { e: "Sit down, please, and we'll begin.", t: "Siéntense, por favor, y empezamos.", s: "Para pedir a alguien que se siente cortésmente.", sEn: "To politely ask someone to sit.", n: "\"Sit down\" es un phrasal verb; \"please\" lo hace cortés.", nEn: "\"Sit down\" is a phrasal verb; \"please\" makes it polite." },
    "loc-exa17": { e: "Can you explain it again? I missed that part.", t: "¿Puede explicarlo otra vez? Me perdí esa parte.", s: "Cuando no entendiste algo en clase.", sEn: "When you didn't understand something in class.", n: "\"Again\" significa \"otra vez\" y va al final de la frase.", nEn: "\"Again\" means \"otra vez\" and goes at the end of the sentence." },
    "loc-exa18": { e: "I forgot my notebook at home today.", t: "Olvidé mi cuaderno en casa hoy.", s: "Para disculparte por olvidar algo.", sEn: "To apologize for forgetting something.", n: "\"Forgot\" es el pasado irregular de \"forget\".", nEn: "\"Forgot\" is the irregular past of \"forget\"." },
    "loc-exa19": { e: "How much time do we have for the test?", t: "¿Cuánto tiempo tenemos para el examen?", s: "Para preguntar sobre la duración del examen.", sEn: "To ask about the length of the test.", n: "\"Time\" es incontable, por eso usamos \"how much\".", nEn: "\"Time\" is uncountable, so we use \"how much\"." },
    "loc-exa20": { e: "If you don't understand something, raise your hand.", t: "Si no entiende algo, levante la mano.", s: "Instrucción condicional del profesor.", sEn: "A conditional instruction from the teacher.", n: "Primer condicional: \"if\" + presente, imperativo o \"will\".", nEn: "First conditional: \"if\" + present, then imperative or \"will\"." },
    "loc-exa21": { e: "I haven't finished checking my answers yet.", t: "Todavía no he terminado de revisar mis respuestas.", s: "Para decir que aún no completas algo.", sEn: "To say you haven't completed something yet.", n: "Tras \"finish\" se usa el gerundio: \"finish checking\".", nEn: "After \"finish\" you use the gerund: \"finish checking\"." },
    "loc-exa22": { e: "Could you repeat the question more slowly?", t: "¿Podría repetir la pregunta más despacio?", s: "Petición cortés cuando algo va muy rápido.", sEn: "A polite request when something is too fast.", n: "\"Could you\" es más cortés que \"can you\".", nEn: "\"Could you\" is more polite than \"can you\"." },
    "loc-exa23": { e: "I'd like you to explain this exercise to me.", t: "Me gustaría que me explicara este ejercicio.", s: "Para pedir ayuda de forma educada.", sEn: "To ask for help politely.", n: "\"I'd like you to + verbo\" = me gustaría que tú...", nEn: "\"I'd like you to + verb\" means \"me gustaría que tú...\"." },
    "loc-exa24": { e: "Although I studied a lot, the exam was difficult.", t: "Aunque estudié mucho, el examen fue difícil.", s: "Para reconocer un resultado inesperado.", sEn: "To acknowledge an unexpected result.", n: "\"Although\" contrasta dos ideas dentro de una sola oración.", nEn: "\"Although\" contrasts two ideas within one sentence." },
    // --- numeros-en ---
    "loc-num21": { e: "If you buy three, they cost twenty-five dollars in total.", t: "Si compras tres, te cuestan veinticinco dólares en total.", s: "Para calcular un precio total al comprar varios.", sEn: "To work out a total price when buying several.", n: "Los números compuestos llevan guion: \"twenty-five\".", nEn: "Compound numbers take a hyphen: \"twenty-five\"." },
    "loc-num22": { e: "I was born on March eighth, nineteen ninety.", t: "Nací el ocho de marzo de mil novecientos noventa.", s: "Para decir tu fecha de nacimiento.", sEn: "To say your date of birth.", n: "Los años se leen en pares: 1990 = \"nineteen ninety\".", nEn: "Years are read in pairs: 1990 = \"nineteen ninety\"." },
    "loc-num23": { e: "The concert starts at a quarter past seven.", t: "El concierto empieza a las siete y cuarto.", s: "Para decir la hora con \"y cuarto\".", sEn: "To tell the time with \"a quarter past\".", n: "\"Quarter past\" = y cuarto; \"quarter to\" = cuarto para.", nEn: "\"Quarter past\" means \"y cuarto\"; \"quarter to\" means \"cuarto para\"." },
    "loc-num24": { e: "Almost two-thirds of the class passed the exam.", t: "Casi dos tercios de la clase aprobaron el examen.", s: "Para expresar fracciones de un grupo.", sEn: "To express fractions of a group.", n: "Las fracciones plurales llevan \"-s\": \"two-thirds\".", nEn: "Plural fractions take \"-s\": \"two-thirds\"." },
    // --- conectores-en ---
    "loc-con23": { e: "I'll call you as soon as I arrive.", t: "Te llamo tan pronto como llegue.", s: "Para indicar que algo pasa inmediatamente después.", sEn: "To indicate something happens right after.", n: "Tras \"as soon as\" se usa presente para hablar del futuro.", nEn: "After \"as soon as\" use the present to talk about the future." },
    "loc-con24": { e: "It was raining; even so, we went out.", t: "Estaba lloviendo; aun así, salimos.", s: "Para indicar que algo ocurre a pesar de lo anterior.", sEn: "To show something happens despite the previous point.", n: "\"Even so\" = a pesar de eso.", nEn: "\"Even so\" means despite that." },
    // --- tiempos-en ---
    "loc-tie13": { e: "She lives in Mexico with her family.", t: "Ella vive en México con su familia.", s: "Para hablar de un hecho habitual en presente.", sEn: "To talk about a habitual fact in the present.", n: "Con \"she\" el verbo lleva \"-s\": \"lives\".", nEn: "With \"she\" the verb takes \"-s\": \"lives\"." },
    "loc-tie14": { e: "We play soccer every weekend.", t: "Jugamos fútbol cada fin de semana.", s: "Para hablar de una rutina con \"we\".", sEn: "To talk about a routine with \"we\".", n: "Con \"we\" el verbo no cambia: \"we play\".", nEn: "With \"we\" the verb doesn't change: \"we play\"." },
    "loc-tie15": { e: "What are you doing now? You look busy.", t: "¿Qué estás haciendo ahora? Te ves ocupado.", s: "Para preguntar por una acción en progreso.", sEn: "To ask about an action in progress.", n: "Presente continuo: \"to be\" + verbo con \"-ing\".", nEn: "Present continuous: \"to be\" + verb with \"-ing\"." },
    "loc-tie16": { e: "Last night I slept very well.", t: "Anoche dormí muy bien.", s: "Para hablar de algo terminado en el pasado.", sEn: "To talk about something completed in the past.", n: "\"Slept\" es el pasado irregular de \"sleep\".", nEn: "\"Slept\" is the irregular past of \"sleep\"." },
    "loc-tie17": { e: "Next week we're going to travel to the coast.", t: "La próxima semana vamos a viajar a la costa.", s: "Para hablar de un plan futuro.", sEn: "To talk about a future plan.", n: "\"Going to\" expresa planes e intenciones futuras.", nEn: "\"Going to\" expresses future plans and intentions." },
    "loc-tie18": { e: "I always drink coffee in the morning.", t: "Siempre tomo café por la mañana.", s: "Para describir un hábito con un adverbio de frecuencia.", sEn: "To describe a habit with a frequency adverb.", n: "\"Always\" va antes del verbo principal.", nEn: "\"Always\" goes before the main verb." },
    "loc-tie19": { e: "When I arrived, they had already left.", t: "Cuando llegué, ellos ya se habían ido.", s: "Para mostrar que una acción pasó antes que otra.", sEn: "To show one action happened before another.", n: "Pasado perfecto: \"had\" + participio, para lo anterior.", nEn: "Past perfect: \"had\" + participle, for the earlier action." },
    "loc-tie20": { e: "This time tomorrow I'll be flying to New York.", t: "Mañana a esta hora estaré volando a Nueva York.", s: "Para una acción en progreso en un momento futuro.", sEn: "For an action in progress at a future moment.", n: "Futuro continuo: \"will be\" + verbo con \"-ing\".", nEn: "Future continuous: \"will be\" + verb with \"-ing\"." },
    "loc-tie21": { e: "I've been studying English since January.", t: "He estado estudiando inglés desde enero.", s: "Para una acción que empezó antes y sigue.", sEn: "For an action that started earlier and continues.", n: "Presente perfecto continuo: \"have been\" + \"-ing\".", nEn: "Present perfect continuous: \"have been\" + \"-ing\"." },
    "loc-tie22": { e: "If you call me, I'll explain it to you.", t: "Si me llamas, te lo explicaré.", s: "Para una condición real en el futuro.", sEn: "For a real condition in the future.", n: "Primer condicional: \"if\" + presente, \"will\" + verbo.", nEn: "First conditional: \"if\" + present, \"will\" + verb." },
    "loc-tie23": { e: "While I was cooking, I was listening to music.", t: "Mientras cocinaba, escuchaba música.", s: "Para dos acciones simultáneas en el pasado.", sEn: "For two simultaneous actions in the past.", n: "Pasado continuo: \"was/were\" + verbo con \"-ing\".", nEn: "Past continuous: \"was/were\" + verb with \"-ing\"." },
    "loc-tie24": { e: "By Friday I'll have finished the project.", t: "Para el viernes ya habré terminado el proyecto.", s: "Para algo que se completará antes de cierto momento.", sEn: "For something that will be done before a point.", n: "Futuro perfecto: \"will have\" + participio.", nEn: "Future perfect: \"will have\" + participle." },
    // --- preposiciones ---
    "loc-pre13": { e: "I don't like driving at night.", t: "No me gusta manejar en la noche.", s: "Para hablar de un momento del día.", sEn: "To talk about a time of day.", n: "Se dice \"at night\", pero \"in the morning/afternoon\".", nEn: "We say \"at night\", but \"in the morning/afternoon\"." },
    "loc-pre14": { e: "There's a painting on the wall.", t: "Hay un cuadro en la pared.", s: "Para indicar contacto con una superficie.", sEn: "To indicate contact with a surface.", n: "\"On\" se usa para superficies: en la pared, en la mesa.", nEn: "\"On\" is used for surfaces: on the wall, on the table." },
    "loc-pre15": { e: "Let's meet in front of the store.", t: "Veámonos frente a la tienda.", s: "Para indicar una posición delante de algo.", sEn: "To indicate a position in front of something.", n: "\"In front of\" = frente a; lo opuesto es \"behind\".", nEn: "\"In front of\" means \"frente a\"; the opposite is \"behind\"." },
    "loc-pre16": { e: "The cat is hiding behind the door.", t: "El gato se esconde detrás de la puerta.", s: "Para indicar una posición detrás de algo.", sEn: "To indicate a position behind something.", n: "\"Behind\" = detrás de; no necesita \"of\".", nEn: "\"Behind\" means \"detrás de\"; it doesn't need \"of\"." },
    "loc-pre17": { e: "I'll be there in five minutes.", t: "Llego en cinco minutos.", s: "Para indicar cuánto falta para algo.", sEn: "To indicate how long until something.", n: "\"In\" + tiempo expresa cuándo pasará algo en el futuro.", nEn: "\"In\" + time expresses when something will happen." },
    "loc-pre18": { e: "I'm going from Lima to Cusco by bus.", t: "Voy de Lima a Cusco en bus.", s: "Para indicar origen y destino de un viaje.", sEn: "To indicate the origin and destination of a trip.", n: "\"From... to...\" marca el punto de partida y llegada.", nEn: "\"From... to...\" marks the starting and ending points." },
    "loc-pre19": { e: "It depends on you, not on me.", t: "Depende de ti, no de mí.", s: "Para decir que algo está condicionado a otra cosa.", sEn: "To say something is conditioned by another thing.", n: "El verbo \"depend\" siempre va con la preposición \"on\".", nEn: "The verb \"depend\" always goes with the preposition \"on\"." },
    "loc-pre20": { e: "I'm looking for my keys everywhere.", t: "Estoy buscando mis llaves por todas partes.", s: "Para decir que buscas algo.", sEn: "To say you're searching for something.", n: "\"Look for\" = buscar; no se traduce \"for\" por separado.", nEn: "\"Look for\" means \"buscar\"; don't translate \"for\" separately." },
    "loc-pre21": { e: "I agree with you on that point.", t: "Estoy de acuerdo contigo en eso.", s: "Para expresar acuerdo sobre un tema.", sEn: "To express agreement on a topic.", n: "\"Agree with\" (persona) y \"agree on\" (tema).", nEn: "\"Agree with\" (a person) and \"agree on\" (a topic)." },
    "loc-pre22": { e: "I've been afraid of spiders since I was a child.", t: "Tengo miedo a las arañas desde niño.", s: "Para hablar de un miedo que tienes hace tiempo.", sEn: "To talk about a long-standing fear.", n: "\"Afraid of\" = tener miedo a; siempre con \"of\".", nEn: "\"Afraid of\" means \"tener miedo a\"; always with \"of\"." },
    "loc-pre23": { e: "I thought about you all day.", t: "Pensé en ti todo el día.", s: "Para decir que algo o alguien estuvo en tu mente.", sEn: "To say something or someone was on your mind.", n: "\"Think about\" = pensar en; no uses \"think in\".", nEn: "\"Think about\" means \"pensar en\"; don't say \"think in\"." },
    "loc-pre24": { e: "I work from nine to five every day.", t: "Trabajo desde las nueve hasta las cinco todos los días.", s: "Para indicar un rango de horas.", sEn: "To indicate a range of hours.", n: "\"From... to...\" también sirve para rangos de tiempo.", nEn: "\"From... to...\" also works for time ranges." },
    // --- preguntas-en ---
    "loc-prg21": { e: "Would you mind if I opened the window?", t: "¿Te importaría si abro la ventana?", s: "Petición muy cortés para hacer algo.", sEn: "A very polite request to do something.", n: "Tras \"would you mind if\" se usa el pasado: \"if I opened\".", nEn: "After \"would you mind if\" use the past: \"if I opened\"." },
    "loc-prg22": { e: "Do you know what time the train leaves?", t: "¿Sabes a qué hora sale el tren?", s: "Pregunta indirecta y cortés sobre un horario.", sEn: "An indirect, polite question about a schedule.", n: "En preguntas indirectas el orden es normal: \"the train leaves\".", nEn: "In indirect questions the word order is normal: \"the train leaves\"." },
    "loc-prg23": { e: "How long have you been waiting?", t: "¿Cuánto tiempo llevas esperando?", s: "Para preguntar por la duración de una acción.", sEn: "To ask about the duration of an action.", n: "\"How long have you been + -ing\" para duración.", nEn: "\"How long have you been + -ing\" asks about duration." },
    "loc-prg24": { e: "Could you tell me how to get to the station?", t: "¿Me podrías decir cómo llegar a la estación?", s: "Para pedir indicaciones cortésmente.", sEn: "To politely ask for directions.", n: "\"Could you tell me...\" suaviza la pregunta.", nEn: "\"Could you tell me...\" softens the question." },
    // --- falsos-amigos ---
    "loc-fa23": { e: "Put on warm clothes; \"clothes\" is not \"rope\".", t: "Ponte ropa abrigada; \"clothes\" no es \"rope\".", s: "Cuando confundes \"ropa\" con \"rope\" (cuerda).", sEn: "When you confuse \"clothes\" with \"rope\".", n: "\"Clothes\" = ropa; \"rope\" = cuerda, un falso amigo.", nEn: "\"Clothes\" means ropa; \"rope\" means cuerda, a false friend." },
    "loc-fa24": { e: "A \"tuna\" in English is a fish, not the cactus fruit.", t: "Una \"tuna\" en inglés es un pez, no la fruta del cactus.", s: "Cuando confundes \"tuna\" (atún) con la fruta \"tuna\".", sEn: "When you confuse English \"tuna\" with the cactus fruit.", n: "El atún es \"tuna\"; la fruta del nopal es \"prickly pear\".", nEn: "The fish is \"tuna\"; the cactus fruit is \"prickly pear\"." },
    // --- pronunciacion-en ---
    "loc-pron21": { e: "I thought about it for a long time.", t: "Lo pensé durante mucho tiempo.", s: "Para practicar la \"th\" fuerte con vocal larga.", sEn: "To practice the hard \"th\" with a long vowel.", n: "\"Thought\" suena \"zot\"; el grupo \"-ough\" suena \"o\".", nEn: "\"Thought\" sounds like \"zot\"; the \"-ough\" sounds like \"o\"." },
    "loc-pron22": { e: "I'll be back in a month.", t: "Regreso en un mes.", s: "Para practicar la \"th\" fuerte al final de palabra.", sEn: "To practice the hard \"th\" at the end of a word.", n: "\"Month\" suena \"manz\"; el plural es \"months\".", nEn: "\"Month\" sounds like \"manz\"; the plural is \"months\"." },
    "loc-pron23": { e: "Eat your vegetables, they're good for you.", t: "Cómete tus verduras, son buenas para ti.", s: "Para practicar una palabra que parece más larga.", sEn: "To practice a word that looks longer than it sounds.", n: "\"Vegetable\" tiene 3 sílabas: \"VECH-ta-bol\".", nEn: "\"Vegetable\" has 3 syllables: \"VECH-ta-bol\"." },
    "loc-pron24": { e: "We spent a week on a small island.", t: "Pasamos una semana en una isla pequeña.", s: "Para practicar la \"s\" muda.", sEn: "To practice the silent \"s\".", n: "En \"island\" la \"s\" es muda: \"ÁI-land\".", nEn: "In \"island\" the \"s\" is silent: \"ÁI-land\"." },
    // --- perfecto-en ---
    "loc-perf13": { e: "It has rained all morning, so we stayed inside.", t: "Ha llovido toda la mañana, así que nos quedamos adentro.", s: "Para una acción del pasado con efecto en el presente.", sEn: "For a past action with a present effect.", n: "Presente perfecto: \"has\" + participio con \"it\".", nEn: "Present perfect: \"has\" + participle with \"it\"." },
    "loc-perf14": { e: "We have seen that movie twice already.", t: "Hemos visto esa película dos veces ya.", s: "Para una experiencia sin decir cuándo exactamente.", sEn: "For an experience without saying exactly when.", n: "\"Seen\" es el participio de \"see\".", nEn: "\"Seen\" is the past participle of \"see\"." },
    "loc-perf15": { e: "Have you talked to her today?", t: "¿Has hablado con ella hoy?", s: "Para preguntar por algo dentro de un periodo no terminado.", sEn: "To ask about something within an unfinished period.", n: "\"Today\" no ha terminado, por eso usamos presente perfecto.", nEn: "\"Today\" isn't over, so we use the present perfect." },
    "loc-perf16": { e: "My brother has lost his keys again.", t: "Mi hermano ha perdido las llaves otra vez.", s: "Para un resultado presente de algo pasado.", sEn: "For a present result of a past event.", n: "\"Lost\" es el participio irregular de \"lose\".", nEn: "\"Lost\" is the irregular participle of \"lose\"." },
    "loc-perf17": { e: "They haven't arrived yet, let's wait.", t: "Todavía no han llegado, esperemos.", s: "Para algo que aún no ha pasado.", sEn: "For something that hasn't happened yet.", n: "\"Yet\" va al final en frases negativas.", nEn: "\"Yet\" goes at the end in negative sentences." },
    "loc-perf18": { e: "I have just spoken to the boss about it.", t: "Acabo de hablar con el jefe sobre eso.", s: "Para algo que pasó hace muy poco.", sEn: "For something that happened a moment ago.", n: "\"Just\" + presente perfecto = acabar de hacer algo.", nEn: "\"Just\" + present perfect means \"to have just done something\"." },
    "loc-perf19": { e: "It's the best book I've ever read.", t: "Es el mejor libro que he leído nunca.", s: "Para hablar de una experiencia máxima hasta ahora.", sEn: "To talk about a top experience so far.", n: "\"Ever\" acompaña al presente perfecto en superlativos.", nEn: "\"Ever\" goes with the present perfect in superlatives." },
    "loc-perf20": { e: "I've been thinking about changing jobs.", t: "He estado pensando en cambiar de trabajo.", s: "Para una actividad reciente y continua.", sEn: "For a recent and ongoing activity.", n: "\"Have been + -ing\" resalta la duración de la acción.", nEn: "\"Have been + -ing\" emphasizes the duration of the action." },
    "loc-perf21": { e: "I had never seen anything like that before.", t: "Nunca había visto algo así antes.", s: "Para algo anterior a otro momento del pasado.", sEn: "For something prior to another past moment.", n: "Pasado perfecto: \"had\" + participio.", nEn: "Past perfect: \"had\" + participle." },
    "loc-perf22": { e: "We have lived here since we got married.", t: "Hemos vivido aquí desde que nos casamos.", s: "Para una situación que empezó en el pasado y sigue.", sEn: "For a situation that started in the past and continues.", n: "\"Since\" marca el inicio; \"for\" marca la duración.", nEn: "\"Since\" marks the start; \"for\" marks the duration." },
    "loc-perf23": { e: "How many times have you been to London?", t: "¿Cuántas veces has estado en Londres?", s: "Para preguntar por experiencias repetidas.", sEn: "To ask about repeated experiences.", n: "\"Have been to\" = haber estado en (y ya volvió).", nEn: "\"Have been to\" means \"haber estado en\" (and come back)." },
    "loc-perf24": { e: "They have been working here for hours.", t: "Han estado trabajando aquí por horas.", s: "Para una acción que sigue en curso desde hace rato.", sEn: "For an action still going on for a while.", n: "\"For + periodo\" indica cuánto dura la acción.", nEn: "\"For + period\" indicates how long the action lasts." },
    // --- articulos-en ---
    "loc-art13": { e: "I eat an apple every day.", t: "Como una manzana todos los días.", s: "Para usar \"an\" antes de sonido vocálico.", sEn: "To use \"an\" before a vowel sound.", n: "Se usa \"an\" antes de sonido de vocal: \"an apple\".", nEn: "Use \"an\" before a vowel sound: \"an apple\"." },
    "loc-art14": { e: "I'm reading a book about history.", t: "Estoy leyendo un libro de historia.", s: "Para usar \"a\" antes de sonido consonántico.", sEn: "To use \"a\" before a consonant sound.", n: "Se usa \"a\" antes de sonido de consonante: \"a book\".", nEn: "Use \"a\" before a consonant sound: \"a book\"." },
    "loc-art15": { e: "Look, the moon is full tonight.", t: "Mira, la luna está llena esta noche.", s: "Para algo único que todos conocen.", sEn: "For something unique that everyone knows.", n: "Usa \"the\" con cosas únicas: the moon, the sun.", nEn: "Use \"the\" with unique things: the moon, the sun." },
    "loc-art16": { e: "I go to bed early on weekdays.", t: "Voy a la cama temprano entre semana.", s: "Expresión fija sin artículo.", sEn: "A fixed expression with no article.", n: "\"Go to bed\" no lleva \"the\"; es una expresión fija.", nEn: "\"Go to bed\" takes no \"the\"; it's a fixed expression." },
    "loc-art17": { e: "Breakfast is important; don't skip it.", t: "El desayuno es importante; no te lo saltes.", s: "Para hablar de comidas en general.", sEn: "To talk about meals in general.", n: "Los nombres de comidas no llevan artículo: \"breakfast\".", nEn: "Meal names take no article: \"breakfast\"." },
    "loc-art18": { e: "Take an umbrella, it might rain.", t: "Lleva un paraguas, podría llover.", s: "Para usar \"an\" antes de vocal.", sEn: "To use \"an\" before a vowel.", n: "\"Umbrella\" empieza con sonido vocálico: \"an umbrella\".", nEn: "\"Umbrella\" starts with a vowel sound: \"an umbrella\"." },
    "loc-art19": { e: "Money can't buy happiness, they say.", t: "El dinero no compra la felicidad, dicen.", s: "Para hablar de conceptos en general.", sEn: "To talk about concepts in general.", n: "Los incontables generales no llevan \"the\": \"money\".", nEn: "General uncountable nouns take no \"the\": \"money\"." },
    "loc-art20": { e: "I play the guitar, but I don't play chess.", t: "Toco la guitarra, pero no juego al ajedrez.", s: "Para contrastar instrumentos y juegos.", sEn: "To contrast instruments and games.", n: "Instrumentos llevan \"the\"; los juegos no.", nEn: "Instruments take \"the\"; games don't." },
    "loc-art21": { e: "Dogs are more loyal than cats, in my opinion.", t: "Los perros son más leales que los gatos, en mi opinión.", s: "Para hablar de un grupo en general.", sEn: "To talk about a group in general.", n: "Sin artículo cuando hablas de algo en general en plural.", nEn: "No article when speaking of something general in the plural." },
    "loc-art22": { e: "The woman I met yesterday is an engineer.", t: "La mujer que conocí ayer es ingeniera.", s: "Para usar \"the\" con algo específico y \"an\" con profesión.", sEn: "To use \"the\" for something specific and \"an\" for a job.", n: "Profesiones llevan \"a/an\": \"she is an engineer\".", nEn: "Jobs take \"a/an\": \"she is an engineer\"." },
    "loc-art23": { e: "It's the biggest city in the country.", t: "Es la ciudad más grande del país.", s: "Para usar \"the\" con superlativos.", sEn: "To use \"the\" with superlatives.", n: "Los superlativos siempre llevan \"the\": \"the biggest\".", nEn: "Superlatives always take \"the\": \"the biggest\"." },
    "loc-art24": { e: "Love is more important than money.", t: "El amor es más importante que el dinero.", s: "Para comparar dos conceptos generales.", sEn: "To compare two general concepts.", n: "\"Love\" y \"money\" en general no llevan artículo.", nEn: "\"Love\" and \"money\" in general take no article." },
    // --- cantidades-en ---
    "loc-cant13": { e: "I have many books at home.", t: "Tengo muchos libros en casa.", s: "Para contar sustantivos contables en plural.", sEn: "To count countable nouns in the plural.", n: "\"Many\" se usa con contables: \"many books\".", nEn: "\"Many\" is used with countable nouns: \"many books\"." },
    "loc-cant14": { e: "I'd like a little bread, please.", t: "Quisiera un poco de pan, por favor.", s: "Para pedir una cantidad pequeña de algo incontable.", sEn: "To ask for a small amount of something uncountable.", n: "\"A little\" se usa con incontables: \"a little bread\".", nEn: "\"A little\" is used with uncountable nouns: \"a little bread\"." },
    "loc-cant15": { e: "There isn't much milk left in the fridge.", t: "No queda mucha leche en el refri.", s: "Para una cantidad pequeña de algo incontable.", sEn: "For a small amount of something uncountable.", n: "\"Much\" se usa con incontables, sobre todo en negativo.", nEn: "\"Much\" is used with uncountable nouns, especially in negatives." },
    "loc-cant16": { e: "How many eggs do you need for the cake?", t: "¿Cuántos huevos necesitas para el pastel?", s: "Para preguntar la cantidad de algo contable.", sEn: "To ask the quantity of something countable.", n: "\"How many\" con contables; \"how much\" con incontables.", nEn: "\"How many\" with countable; \"how much\" with uncountable." },
    "loc-cant17": { e: "I have some friends in Canada.", t: "Tengo algunos amigos en Canadá.", s: "Para una cantidad indefinida en afirmativo.", sEn: "For an indefinite quantity in the affirmative.", n: "\"Some\" se usa en frases afirmativas.", nEn: "\"Some\" is used in affirmative sentences." },
    "loc-cant18": { e: "There were few people at the meeting.", t: "Había poca gente en la reunión.", s: "Para indicar escasez de algo contable.", sEn: "To indicate a shortage of something countable.", n: "\"Few\" (contable) y \"little\" (incontable) = poco/pocos.", nEn: "\"Few\" (countable) and \"little\" (uncountable) mean \"few/little\"." },
    "loc-cant19": { e: "I don't have enough money to buy it.", t: "No tengo suficiente dinero para comprarlo.", s: "Para decir que algo no alcanza.", sEn: "To say there isn't enough of something.", n: "\"Enough\" va antes del sustantivo: \"enough money\".", nEn: "\"Enough\" goes before the noun: \"enough money\"." },
    "loc-cant20": { e: "There's too much homework this week.", t: "Hay demasiada tarea esta semana.", s: "Para quejarte de un exceso de algo incontable.", sEn: "To complain about an excess of something uncountable.", n: "\"Too much\" (incontable) y \"too many\" (contable) = demasiado.", nEn: "\"Too much\" (uncountable) and \"too many\" (countable) mean \"too much/many\"." },
    "loc-cant21": { e: "Most of my friends speak English.", t: "La mayoría de mis amigos hablan inglés.", s: "Para hablar de la mayor parte de un grupo.", sEn: "To talk about most of a group.", n: "\"Most of\" + grupo específico; el verbo va en plural.", nEn: "\"Most of\" + a specific group; the verb is plural." },
    "loc-cant22": { e: "There are only a few tickets left.", t: "Solo quedan unas pocas entradas.", s: "Para indicar que queda poco de algo contable.", sEn: "To indicate little is left of something countable.", n: "\"A few\" tiene un matiz más positivo que \"few\".", nEn: "\"A few\" has a more positive nuance than \"few\"." },
    "loc-cant23": { e: "I bought several fruits at the market.", t: "Compré varias frutas en el mercado.", s: "Para una cantidad media de algo contable.", sEn: "For a medium quantity of something countable.", n: "\"Several\" = varios; siempre con contables en plural.", nEn: "\"Several\" means \"varios\"; always with plural countable nouns." },
    "loc-cant24": { e: "None of them came to the party.", t: "Ninguno de ellos vino a la fiesta.", s: "Para decir que cero personas o cosas.", sEn: "To say zero people or things.", n: "\"None of them\" = ninguno de ellos; expresa cantidad cero.", nEn: "\"None of them\" means \"ninguno de ellos\"; it expresses zero." },
    // --- modales-en ---
    "loc-mod19": { e: "You mustn't be late for the exam.", t: "No debes llegar tarde al examen.", s: "Para una prohibición fuerte.", sEn: "For a strong prohibition.", n: "\"Mustn't\" = prohibición; \"don't have to\" = no es necesario.", nEn: "\"Mustn't\" is prohibition; \"don't have to\" means not necessary." },
    "loc-mod20": { e: "She can swim very well.", t: "Sabe nadar muy bien.", s: "Para expresar una habilidad.", sEn: "To express an ability.", n: "\"Can\" expresa capacidad; el verbo va en base sin \"to\".", nEn: "\"Can\" expresses ability; the verb is in the base form, no \"to\"." },
    "loc-mod21": { e: "You should have told me the truth.", t: "Deberías haberme dicho la verdad.", s: "Para reprochar algo que no se hizo.", sEn: "To reproach something that wasn't done.", n: "\"Should have + participio\" = lo correcto en el pasado.", nEn: "\"Should have + participle\" describes the right past action." },
    "loc-mod22": { e: "He must be tired after the trip.", t: "Debe de estar cansado después del viaje.", s: "Para una deducción casi segura.", sEn: "For an almost certain deduction.", n: "\"Must\" también expresa deducción lógica, no solo obligación.", nEn: "\"Must\" can also express logical deduction, not only obligation." },
    "loc-mod23": { e: "If you want, we could meet tomorrow.", t: "Si quieres, podríamos vernos mañana.", s: "Para una sugerencia amable.", sEn: "For a gentle suggestion.", n: "\"Could\" suaviza una propuesta; es menos directo que \"can\".", nEn: "\"Could\" softens a suggestion; it's less direct than \"can\"." },
    "loc-mod24": { e: "You didn't have to wait so long for me.", t: "No tuviste que esperarme tanto tiempo.", s: "Para decir que algo no era necesario.", sEn: "To say something wasn't necessary.", n: "\"Didn't have to\" = no fue necesario (y quizás no se hizo).", nEn: "\"Didn't have to\" means it wasn't necessary (and maybe wasn't done)." },
    // --- phrasal-en ---
    "loc-phr15": { e: "Please sit down and relax.", t: "Por favor siéntate y relájate.", s: "Para pedir a alguien que se siente.", sEn: "To ask someone to sit.", n: "\"Sit down\" es intransitivo (no lleva objeto), así que no se separa: se dice \"sit down\", nunca \"sit it down\".", nEn: "\"Sit down\" is a phrasal verb." },
    "loc-phr16": { e: "Come in, the door is open.", t: "Entra, la puerta está abierta.", s: "Para invitar a alguien a pasar.", sEn: "To invite someone to enter.", n: "\"Come in\" = entrar (hacia el hablante).", nEn: "\"Come in\" means \"entrar\" (toward the speaker)." },
    "loc-phr17": { e: "I have to look after my sister this weekend.", t: "Tengo que cuidar a mi hermana este fin de semana.", s: "Para hablar de cuidar a alguien.", sEn: "To talk about caring for someone.", n: "\"Look after\" = cuidar de alguien o algo.", nEn: "\"Look after\" means to take care of someone or something." },
    "loc-phr18": { e: "We're going to go out tonight.", t: "Vamos a salir esta noche.", s: "Para hablar de salir a divertirse.", sEn: "To talk about going out to have fun.", n: "\"Go out\" = salir (de la casa, a divertirse).", nEn: "\"Go out\" means to leave home, to go out for fun." },
    "loc-phr19": { e: "I ran out of gas on the highway.", t: "Me quedé sin gasolina en la carretera.", s: "Para decir que algo se agotó.", sEn: "To say something ran out.", n: "\"Run out of\" = quedarse sin (agotarse algo).", nEn: "\"Run out of\" means to run out of something." },
    "loc-phr20": { e: "We had to call off the meeting because of the storm.", t: "Tuvimos que cancelar la reunión por la tormenta.", s: "Para hablar de cancelar un evento.", sEn: "To talk about canceling an event.", n: "\"Call off\" = cancelar; es separable: \"call it off\".", nEn: "\"Call off\" means to cancel; it's separable: \"call it off\"." },
    "loc-phr21": { e: "Don't give up, you almost made it.", t: "No te rindas, casi lo logras.", s: "Para animar a alguien a no rendirse.", sEn: "To encourage someone not to quit.", n: "\"Give up\" = rendirse o dejar de intentar.", nEn: "\"Give up\" means to surrender or stop trying." },
    "loc-phr22": { e: "I need to find out what happened.", t: "Necesito averiguar qué pasó.", s: "Para hablar de descubrir información.", sEn: "To talk about discovering information.", n: "\"Find out\" = averiguar, descubrir un dato.", nEn: "\"Find out\" means to find out or discover a fact." },
    "loc-phr23": { e: "I get along well with my coworkers.", t: "Me llevo bien con mis compañeros.", s: "Para hablar de buenas relaciones.", sEn: "To talk about good relationships.", n: "\"Get along with\" = llevarse bien con alguien.", nEn: "\"Get along with\" means to get on well with someone." },
    "loc-phr24": { e: "You have to look after your things in crowded places.", t: "Tienes que cuidar tus cosas en lugares concurridos.", s: "Para recordar cuidar las pertenencias.", sEn: "To remind someone to mind their belongings.", n: "\"Look after\" también sirve para objetos: cuidar cosas.", nEn: "\"Look after\" also works for objects: to mind your things." },
    // --- comparar-en ---
    "loc-comp11": { e: "My brother is taller than me.", t: "Mi hermano es más alto que yo.", s: "Para comparar estatura.", sEn: "To compare height.", n: "Adjetivos cortos forman el comparativo con \"-er\".", nEn: "Short adjectives form the comparative with \"-er\"." },
    "loc-comp12": { e: "She is older than her sister.", t: "Ella es mayor que su hermana.", s: "Para comparar edad.", sEn: "To compare age.", n: "\"Older\" es el comparativo de \"old\".", nEn: "\"Older\" is the comparative of \"old\"." },
    "loc-comp13": { e: "This movie is more interesting than the book.", t: "Esta película es más interesante que el libro.", s: "Para comparar con adjetivos largos.", sEn: "To compare with long adjectives.", n: "Adjetivos largos usan \"more\" + adjetivo.", nEn: "Long adjectives use \"more\" + adjective." },
    "loc-comp14": { e: "He can run as fast as me.", t: "Él corre tan rápido como yo.", s: "Para indicar igualdad entre dos cosas.", sEn: "To indicate equality between two things.", n: "\"As + adjetivo + as\" expresa igualdad.", nEn: "\"As + adjective + as\" expresses equality." },
    "loc-comp15": { e: "It was the hottest day of the year.", t: "Fue el día más caluroso del año.", s: "Para destacar lo máximo de un grupo.", sEn: "To highlight the maximum in a group.", n: "Superlativo de adjetivos cortos: \"the\" + \"-est\".", nEn: "Superlative of short adjectives: \"the\" + \"-est\"." },
    "loc-comp16": { e: "This house is more expensive than the other one.", t: "Esta casa es más cara que la otra.", s: "Para comparar precios.", sEn: "To compare prices.", n: "\"More expensive than\" = más caro que.", nEn: "\"More expensive than\" means \"más caro que\"." },
    "loc-comp17": { e: "The more you practice, the better you get.", t: "Cuanto más practicas, mejor te vuelves.", s: "Para mostrar que dos cosas crecen juntas.", sEn: "To show two things increasing together.", n: "Estructura \"the more..., the better...\" = cuanto más..., mejor...", nEn: "Structure \"the more..., the better...\" means \"cuanto más..., mejor...\"." },
    "loc-comp18": { e: "My phone is less expensive than yours.", t: "Mi celular es menos caro que el tuyo.", s: "Para comparar a la baja.", sEn: "To compare downward.", n: "\"Less + adjetivo + than\" = menos... que.", nEn: "\"Less + adjective + than\" means \"menos... que\"." },
    "loc-comp19": { e: "It's not as difficult as I thought.", t: "No es tan difícil como pensaba.", s: "Para decir que algo es menos de lo esperado.", sEn: "To say something is less than expected.", n: "\"Not as... as\" niega la igualdad entre dos cosas.", nEn: "\"Not as... as\" denies equality between two things." },
    "loc-comp20": { e: "She's the kindest person I know.", t: "Es la persona más amable que conozco.", s: "Para elogiar destacando entre todos.", sEn: "To praise by singling out from all.", n: "Superlativo: \"the\" + adjetivo con \"-est\".", nEn: "Superlative: \"the\" + adjective with \"-est\"." },
    "loc-comp21": { e: "I feel stronger than before.", t: "Me siento más fuerte que antes.", s: "Para comparar con un estado anterior.", sEn: "To compare with a previous state.", n: "\"Stronger\" es el comparativo de \"strong\": se forma con \"-er\" (no se duplica ninguna letra).", nEn: "\"Stronger\" is the comparative of \"strong\": formed with \"-er\" (no letter is doubled)." },
    "loc-comp22": { e: "That was the easiest exam of all.", t: "Ese fue el examen más fácil de todos.", s: "Para destacar lo más fácil.", sEn: "To highlight the easiest.", n: "Adjetivos en \"-y\" cambian a \"-iest\": \"easiest\".", nEn: "Adjectives ending in \"-y\" change to \"-iest\": \"easiest\"." },
    "loc-comp23": { e: "I have less money than last month.", t: "Tengo menos dinero que el mes pasado.", s: "Para comparar cantidades incontables a la baja.", sEn: "To compare uncountable quantities downward.", n: "\"Less\" se usa con incontables; \"fewer\" con contables.", nEn: "\"Less\" is for uncountable; \"fewer\" is for countable." },
    "loc-comp24": { e: "It's getting hotter and hotter in summer.", t: "Cada vez hace más calor en verano.", s: "Para describir un cambio gradual.", sEn: "To describe a gradual change.", n: "Repetir el comparativo (\"hotter and hotter\") = cada vez más.", nEn: "Repeating the comparative (\"hotter and hotter\") means \"more and more\"." },
  };

  var SC = window.SC || (window.SC = {});
  SC.contextDataLocals = C;
})();
